/**
 * Colony Name Modal
 *
 * Simple naming prompt shown during NUX (after Fleet Manifesto).
 * Asks the player to name their colony.
 */

import { COLONY_NAME_MAX_LENGTH } from '../sim/culture';
import { trapFocus } from './focusTrap';
import { safeHtml } from './utils/safeHtml';

let overlay: HTMLDivElement | null = null;
let removeFocusTrap: (() => void) | null = null;
let prompted = false;

/** Whether the colony name prompt has been shown this session. */
export function hasColonyNameBeenPrompted(): boolean {
  return prompted;
}

/** Reset state (for save/load). */
export function resetColonyNameModalState(): void {
  prompted = false;
}

export function showColonyNameModal(
  onSubmit: (name: string) => void,
): void {
  if (overlay) return;
  prompted = true;

  overlay = document.createElement('div');
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.85);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 2000;
    font-family: 'Courier New', monospace;
    opacity: 0;
    transition: opacity 0.5s ease;
  `;
  document.body.appendChild(overlay);
  requestAnimationFrame(() => {
    if (overlay) overlay.style.opacity = '1';
  });

  const modal = document.createElement('div');
  modal.setAttribute('role', 'dialog');
  modal.setAttribute('aria-label', 'Name Your Colony');
  modal.setAttribute('aria-modal', 'true');
  modal.setAttribute('tabindex', '-1');
  modal.style.cssText = `
    background: rgba(0, 4, 12, 0.98);
    border: 1px solid #06b6d4;
    box-shadow: 0 0 60px rgba(6,182,212,0.15), inset 0 0 40px rgba(0,0,0,0.6);
    color: #e2e8f0;
    max-width: 460px;
    width: 90vw;
    padding: 36px 32px;
    border-radius: 2px;
    position: relative;
  `;

  modal.innerHTML = safeHtml`
    <div style="font-size:9px; color:#06b6d4; opacity:0.7; text-transform:uppercase; letter-spacing:3px; margin-bottom:6px;">
      ARIA — COLONY FOUNDING
    </div>
    <div style="font-size:18px; font-weight:bold; color:#06b6d4; margin-bottom:16px; letter-spacing:1px;">
      Name Your Colony
    </div>
    <p style="margin:0 0 20px; line-height:1.7; color:#94a3b8; font-size:12px;">
      Every civilization needs an identity. What will your outpost in the asteroid belt be called?
    </p>
    <input id="colony-name-input" type="text" maxlength="${COLONY_NAME_MAX_LENGTH}" placeholder="Enter colony name..." style="
      width: 100%;
      background: rgba(0,0,0,0.4);
      border: 1px solid #06b6d444;
      border-radius: 2px;
      color: #e2e8f0;
      font-family: 'Courier New', monospace;
      font-size: 14px;
      padding: 12px;
      outline: none;
      box-sizing: border-box;
      letter-spacing: 0.5px;
    " />
    <div style="display:flex; justify-content:space-between; align-items:center; margin-top:12px;">
      <span id="colony-name-count" style="font-size:10px; color:#475569;">0/${COLONY_NAME_MAX_LENGTH}</span>
      <div style="display:flex; gap:12px;">
        <button id="colony-name-skip" style="
          background:none; border:none; color:#475569; cursor:pointer;
          font-family:'Courier New',monospace; font-size:10px; text-transform:uppercase; letter-spacing:1px;
        ">Skip</button>
        <button id="colony-name-submit" style="
          background: transparent;
          border: 1px solid #06b6d488;
          color: #06b6d4;
          font-family: 'Courier New', monospace;
          font-size: 11px;
          padding: 6px 18px;
          cursor: pointer;
          border-radius: 2px;
          letter-spacing: 1px;
          text-transform: uppercase;
          transition: background 0.2s;
        ">Found Colony</button>
      </div>
    </div>
  `;

  overlay.appendChild(modal);
  removeFocusTrap = trapFocus(modal);

  const input = modal.querySelector<HTMLInputElement>('#colony-name-input')!;
  const charCount = modal.querySelector<HTMLSpanElement>('#colony-name-count')!;
  const submitBtn = modal.querySelector<HTMLButtonElement>('#colony-name-submit')!;
  const skipBtn = modal.querySelector<HTMLButtonElement>('#colony-name-skip')!;

  input.addEventListener('input', () => {
    charCount.textContent = `${input.value.length}/${COLONY_NAME_MAX_LENGTH}`;
  });

  submitBtn.addEventListener('click', () => {
    const name = input.value.trim();
    if (name.length > 0) {
      onSubmit(name);
    }
    closeModal();
  });

  submitBtn.addEventListener('mouseover', () => {
    submitBtn.style.background = 'rgba(6,182,212,0.15)';
  });
  submitBtn.addEventListener('mouseout', () => {
    submitBtn.style.background = 'transparent';
  });

  skipBtn.addEventListener('click', closeModal);

  input.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') {
      const name = input.value.trim();
      if (name.length > 0) {
        onSubmit(name);
      }
      closeModal();
    }
  });

  // Auto-focus the input
  requestAnimationFrame(() => input.focus());
}

function closeModal(): void {
  if (!overlay) return;
  removeFocusTrap?.();
  removeFocusTrap = null;
  overlay.style.opacity = '0';
  const ref = overlay;
  setTimeout(() => ref.remove(), 500);
  overlay = null;
}
