/**
 * Build Panel UI
 *
 * Shows available robot constructions with their mineral costs.
 * Integrates with the tech tree to show what is unlocked.
 * Press C to toggle.
 */

import { ROBOT_RECIPES } from '../sim/robotFactory';
import type { SimEnqueueBuildMessage } from '../sim/messages';
import { techBitmask } from '../sim/techTree';
import { attachTooltip } from './tooltip';
import { ROBOT_TYPES } from '../sim/robotProfiles';
import { registerHudButton } from './hudButtonBar';
import { showHint } from './hints';

const ROBOT_DESCRIPTIONS: Record<number, string> = {
  [ROBOT_TYPES.SCOUT]:
    'Explores the asteroid belt\nReveals new asteroids and anomalies\nFast but low cargo capacity',
  [ROBOT_TYPES.MINER]:
    'Extracts raw ore from asteroids\nCore mining unit — build many\nSlower movement, high yield',
  [ROBOT_TYPES.HAULER]:
    'Transports ore from asteroids to base\nHigh cargo capacity, no mining\nAim for ~1 hauler per 3 miners',
  [ROBOT_TYPES.RESEARCHER]:
    'Generates research points over time\nRequired to progress the tech tree\nRequires researcher_bots tech',
  [ROBOT_TYPES.REFINER]:
    'Converts raw ore into refined materials\nRefined materials unlock advanced builds\nRequires ore_refining tech',
  [ROBOT_TYPES.DEFENDER]:
    'Secures sector perimeter against inbound threats\nPatrols and intercepts kinetic hazards\nRequires defense_systems tech',
  [ROBOT_TYPES.ENGINEER]:
    'Constructs and upgrades base buildings\nNeeded for infrastructure expansion\nRequires constructor_bots tech',
};

type WorkerSend = (msg: SimEnqueueBuildMessage) => void;

let panel: HTMLDivElement | null = null;
let isOpen = false;
let workerSend: WorkerSend | null = null;

// Latest state from SimTechStateMessage
let _refined: Record<string, number> = {};
let _rawStorage: Record<string, number> = {};
let _unlockedMask = 0n;
let _queueLength = 0;
let _factoryProgress: number | null = null;
let _factoryRemainingSeconds: number | null = null;
let _renderScheduled = false;
let _lastRenderFingerprint = '';

// Robot type unlock requirements (from ROBOT_RECIPES)
const UNLOCK_MAP = new Map(ROBOT_RECIPES.map((r) => [r.robotType, r.unlockTechId]));

function formatEta(seconds: number): string {
  if (seconds < 10) return '< 10s';
  if (seconds < 60) return `~${Math.round(seconds)}s`;
  const m = Math.floor(seconds / 60);
  const s = Math.round(seconds % 60);
  return s > 0 ? `~${m}m ${s}s` : `~${m}m`;
}

function isUnlocked(robotType: number): boolean {
  const techId = UNLOCK_MAP.get(robotType);
  if (!techId) return true; // no tech required
  return (_unlockedMask & techBitmask(techId)) !== 0n;
}

/** Returns 'refined' if affordable with refined mats, 'raw' if with raw ore, or null if can't afford. */
function getAffordMode(recipe: (typeof ROBOT_RECIPES)[0]): 'refined' | 'raw' | null {
  const canAffordRefined = Object.entries(recipe.refinedCost).every(
    ([mat, amt]) => (_refined[mat] ?? 0) >= (amt ?? 0),
  );
  if (canAffordRefined) return 'refined';

  const canAffordRaw = Object.entries(recipe.rawCost).every(
    ([mat, amt]) => (_rawStorage[mat] ?? 0) >= (amt ?? 0),
  );
  if (canAffordRaw) return 'raw';

  return null;
}

function formatCost(recipe: (typeof ROBOT_RECIPES)[0]): string {
  const mode = getAffordMode(recipe);
  // Show refined cost if player has refined materials, otherwise show raw ore cost
  const useRefined = mode === 'refined' || Object.keys(_refined).length > 0;
  if (useRefined) {
    const parts = Object.entries(recipe.refinedCost).map(([mat, amt]) => {
      const have = Math.floor(_refined[mat] ?? 0);
      const need = amt ?? 0;
      const ok = have >= need;
      const label = mat.replace(/_/g, ' ');
      return `<span style="color:${ok ? '#4aff4a' : '#ff4444'}">${need} ${label} (${have})</span>`;
    });
    const rawParts = Object.entries(recipe.rawCost).map(([mat, amt]) => {
      const have = Math.floor(_rawStorage[mat] ?? 0);
      const need = amt ?? 0;
      const ok = have >= need;
      const label = mat.replace(/_/g, ' ');
      return `<span style="color:${ok ? '#88cc88' : '#cc4444'}">${need} ${label} (${have})</span>`;
    });
    return parts.join(', ') + `<br><span style="color:#556;font-size:10px;">or raw: </span>` + rawParts.join(', ');
  } else {
    // No refined materials yet — show raw cost prominently
    return Object.entries(recipe.rawCost).map(([mat, amt]) => {
      const have = Math.floor(_rawStorage[mat] ?? 0);
      const need = amt ?? 0;
      const ok = have >= need;
      const label = mat.replace(/_/g, ' ');
      return `<span style="color:${ok ? '#4aff4a' : '#ff4444'}">${need} ${label} (${have})</span>`;
    }).join(', ');
  }
}

export function initBuildPanel(send: WorkerSend): void {
  workerSend = send;
  injectBuildPulseStyle();
  createToggleButton();
}

export function updateBuildState(
  refined: Record<string, number>,
  unlockedMask: bigint,
  queueLength: number,
  factoryProgress: number | null,
  factoryRemainingSeconds: number | null = null,
  rawStorage?: Record<string, number>,
): void {
  _refined = refined;
  if (rawStorage) _rawStorage = rawStorage;
  _unlockedMask = unlockedMask;
  _queueLength = queueLength;
  _factoryProgress = factoryProgress;
  _factoryRemainingSeconds = factoryRemainingSeconds;
  if (isOpen && !_renderScheduled) {
    _renderScheduled = true;
    requestAnimationFrame(() => {
      _renderScheduled = false;
      renderPanel();
    });
  }
}

export function toggleBuildPanel(): void {
  if (isOpen) {
    isOpen = false;
    if (panel) {
      const p = panel;
      panel = null;
      p.style.opacity = '0';
      p.style.transform = 'translateX(-50%) translateY(-8px)';
      setTimeout(() => p.remove(), 250);
    }
  } else {
    openPanel();
  }
}

const BUILD_HINT_SEEN_KEY = 'asteroid_miner_build_hint_seen';

function createToggleButton(): void {
  const btn = registerHudButton('🤖 Build', toggleBuildPanel, 'Build robots (C key)');

  // Pulse the button for 30s on first session to guide new players
  try {
    if (!localStorage.getItem(BUILD_HINT_SEEN_KEY)) {
      injectBuildPulseStyle();
      btn.classList.add('build-btn-pulse');
      setTimeout(() => {
        btn.classList.remove('build-btn-pulse');
        try { localStorage.setItem(BUILD_HINT_SEEN_KEY, '1'); } catch { /* ignore */ }
      }, 30_000);
    }
  } catch { /* ignore */ }
}

function injectBuildPulseStyle(): void {
  if (document.getElementById('build-pulse-style')) return;
  const style = document.createElement('style');
  style.id = 'build-pulse-style';
  style.textContent = `
    @keyframes buildBtnPulse {
      0%   { box-shadow: 0 0 4px rgba(136,204,255,0.4); }
      50%  { box-shadow: 0 0 12px rgba(136,204,255,0.9), 0 0 20px rgba(136,204,255,0.5); }
      100% { box-shadow: 0 0 4px rgba(136,204,255,0.4); }
    }
    .build-btn-pulse {
      animation: buildBtnPulse 1.4s ease-in-out infinite;
    }
    @keyframes factoryBarGlow {
      0%, 100% { box-shadow: 0 0 4px rgba(34,211,238,0.3); }
      50%      { box-shadow: 0 0 10px rgba(34,211,238,0.7), 0 0 20px rgba(34,211,238,0.3); }
    }
    .factory-bar-active {
      animation: factoryBarGlow 2s ease-in-out infinite;
      position: relative;
      overflow: hidden;
    }
    .factory-bar-active::after {
      content: '';
      position: absolute;
      top: 0; left: -50%; width: 30%; height: 100%;
      background: linear-gradient(90deg, transparent, rgba(255,255,255,0.25), transparent);
      animation: barShimmer 2.2s ease-in-out infinite;
    }
    @keyframes barShimmer {
      0%   { left: -50%; }
      100% { left: 150%; }
    }
    @keyframes factoryComplete {
      0%   { box-shadow: 0 0 20px rgba(74,255,74,0.9), 0 0 40px rgba(74,255,74,0.4); }
      100% { box-shadow: 0 0 4px rgba(34,211,238,0.2); }
    }
    .factory-bar-complete {
      animation: factoryComplete 0.8s ease-out forwards;
    }
  `;
  document.head.appendChild(style);
}

function openPanel(): void {
  isOpen = true;
  _lastRenderFingerprint = ''; // force fresh render
  panel = document.createElement('div');
  panel.id = 'build-panel';
  panel.setAttribute('role', 'complementary');
  panel.setAttribute('aria-label', 'Robot construction bay');
  panel.style.cssText = `
    position: absolute;
    top: 40px;
    left: 50%;
    transform: translateX(-50%) translateY(-8px);
    width: 720px;
    max-height: 75vh;
    overflow-y: auto;
    background: rgba(5,10,20,0.97);
    border: 1px solid #22d3ee55;
    border-radius: 8px;
    padding: 16px;
    font-family: 'Courier New', monospace;
    font-size: 12px;
    color: #ccc;
    z-index: 200;
    pointer-events: auto;
    box-shadow: 0 0 40px rgba(0,0,0,0.9);
    opacity: 0;
    transition: opacity 0.25s ease-out, transform 0.25s ease-out;
  `;
  renderPanel();
  document.getElementById('hud-overlay')?.appendChild(panel);
  requestAnimationFrame(() => {
    if (panel) {
      panel.style.opacity = '1';
      panel.style.transform = 'translateX(-50%) translateY(0)';
    }
  });
}

function buildRenderFingerprint(): string {
  const progressPct = _factoryProgress !== null ? Math.round(_factoryProgress * 100) : null;
  const etaStr = _factoryRemainingSeconds !== null ? formatEta(_factoryRemainingSeconds) : '';
  let fp = `q${_queueLength}|p${progressPct}|m${_unlockedMask}|e${etaStr}`;
  for (const recipe of ROBOT_RECIPES) {
    fp += `|${recipe.robotType}:${getAffordMode(recipe) ?? 'n'}`;
  }
  for (const key of Object.keys(_refined).sort()) {
    fp += `|r${key}${Math.floor(_refined[key])}`;
  }
  for (const key of Object.keys(_rawStorage).sort()) {
    fp += `|s${key}${Math.floor(_rawStorage[key])}`;
  }
  return fp;
}

function renderPanel(): void {
  if (!panel) return;

  // Skip re-render if nothing visible has changed — prevents DOM
  // replacement at frame rate which causes button flashing and click loss.
  const fp = buildRenderFingerprint();
  if (fp === _lastRenderFingerprint) return;
  _lastRenderFingerprint = fp;

  const progressPct = _factoryProgress !== null ? Math.round(_factoryProgress * 100) : null;

  let html = `
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;border-bottom:1px solid #22d3ee33;padding-bottom:8px;">
      <h2 style="margin:0;color:#22d3ee;font-size:14px;letter-spacing:2px;">⚙ CONSTRUCTION BAY</h2>
      <button id="build-close-btn" aria-label="Close build panel" style="background:none;border:1px solid #666;color:#aaa;padding:2px 8px;cursor:pointer;border-radius:3px;font-family:monospace;">✕ close</button>
    </div>`;

  // Factory status
  if (_queueLength > 0 || progressPct !== null) {
    html += `<div style="margin-bottom:12px;padding:8px;background:rgba(34,211,238,0.08);border:1px solid #22d3ee33;border-radius:4px;">`;
    html += `<span style="color:#22d3ee">Factory queue:</span> ${_queueLength} order${_queueLength !== 1 ? 's' : ''}`;
    if (progressPct !== null) {
      const etaStr =
        _factoryRemainingSeconds !== null
          ? ` · ${formatEta(_factoryRemainingSeconds)} remaining`
          : '';
      html += ` &nbsp;|&nbsp; <span style="color:#4aff4a">Building: ${progressPct}%${etaStr}</span>`;
      const barClass = progressPct >= 100 ? 'factory-bar-complete' : 'factory-bar-active';
      html += `<div class="${barClass}" style="margin-top:6px;background:#1a1a1a;border-radius:3px;height:6px;overflow:hidden;">
        <div style="width:${progressPct}%;height:100%;background:${progressPct >= 100 ? '#4aff4a' : '#22d3ee'};transition:width 0.5s;"></div>
      </div>`;
    }
    html += `</div>`;
  } else {
    html += `<div style="margin-bottom:12px;padding:6px 8px;color:#555;font-style:italic;">Factory idle — no builds queued</div>`;
  }

  // Robot recipes grid
  html += `<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;">`;
  for (const recipe of ROBOT_RECIPES) {
    const unlocked = isUnlocked(recipe.robotType);
    const affordMode = unlocked ? getAffordMode(recipe) : null;
    const affordable = affordMode !== null;
    const cardColor = !unlocked ? '#333' : affordable ? '#0a2a1a' : '#1a0a0a';
    const borderColor = !unlocked ? '#333' : affordable ? '#22d3ee44' : '#66333344';

    html += `<div data-recipe-robot-type="${recipe.robotType}" style="background:${cardColor};border:1px solid ${borderColor};border-radius:6px;padding:10px;">`;
    html += `<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px;">`;
    html += `<span style="color:${unlocked ? '#22d3ee' : '#555'};font-weight:bold;">${recipe.name}</span>`;
    html += `<span style="color:#888;font-size:11px;">${recipe.duration}s</span>`;
    html += `</div>`;

    const shortDesc = ROBOT_DESCRIPTIONS[recipe.robotType]?.split('\n')[0] ?? '';
    if (shortDesc) {
      html += `<div style="color:${unlocked ? '#6a8a9a' : '#444'};font-size:10px;margin-bottom:6px;">${shortDesc}</div>`;
    }

    if (!unlocked) {
      const techId = UNLOCK_MAP.get(recipe.robotType);
      html += `<div style="color:#555;font-style:italic;font-size:11px;">🔒 Requires: ${techId?.replace(/_/g, ' ') ?? 'unknown tech'}</div>`;
    } else {
      html += `<div style="margin-bottom:8px;font-size:11px;line-height:1.6;">${formatCost(recipe)}</div>`;
      const btnLabel = affordable
        ? `Queue build: ${recipe.name}${affordMode === 'raw' ? ' (raw ore)' : ''}`
        : `Insufficient resources to build ${recipe.name}`;
      const btnText = affordable
        ? `+ Queue Build${affordMode === 'raw' ? ' (raw ore)' : ''}`
        : 'Insufficient resources';
      html += `<button data-robot-type="${recipe.robotType}" class="build-btn" aria-label="${btnLabel}" style="
        width:100%;padding:4px 0;
        background:${affordable ? 'rgba(34,211,238,0.15)' : 'rgba(80,40,40,0.15)'};
        border:1px solid ${affordable ? '#22d3ee' : '#555'};
        color:${affordable ? '#22d3ee' : '#666'};
        border-radius:3px;cursor:${affordable ? 'pointer' : 'not-allowed'};
        font-family:monospace;font-size:11px;
      " ${affordable ? '' : 'disabled'}>
        ${btnText}
      </button>`;
    }
    html += `</div>`;
  }
  html += `</div>`;

  panel.innerHTML = html;

  // Attach tooltips to recipe cards
  panel.querySelectorAll<HTMLDivElement>('[data-recipe-robot-type]').forEach((card) => {
    const robotType = parseInt(card.dataset['recipeRobotType'] ?? '-1', 10);
    const desc = ROBOT_DESCRIPTIONS[robotType];
    if (!desc) return;
    const techId = UNLOCK_MAP.get(robotType);
    const unlocked = isUnlocked(robotType);
    const tip = unlocked
      ? desc
      : `${desc}\n\n🔒 Requires: ${techId?.replace(/_/g, ' ') ?? 'unknown tech'}`;
    attachTooltip(card, tip);
  });

  // Bind events
  panel.querySelector('#build-close-btn')?.addEventListener('click', toggleBuildPanel);
  panel.querySelectorAll('.build-btn').forEach((btn) => {
    btn.addEventListener('click', () => {
      const robotType = parseInt((btn as HTMLElement).dataset['robotType'] ?? '-1', 10);
      if (robotType >= 0 && workerSend) {
        workerSend({ type: 'sim:enqueue_build', payload: { robotType } });
        showHint('first_robot_queued', 'Your new robot will spawn at base when construction is complete.');
      }
    });
  });
}
