/**
 * Habitat Panel (K key)
 *
 * Displays human colonist population, morale, political capital,
 * active demands with deadlines, and resource drain rates.
 * Follows the same modal overlay pattern as the Culture panel.
 */

import type { HumanDemand } from '../shared/habitatTypes';
import type { SimHabitatStateMessage } from '../shared/habitatTypes';
import type { SimHabitatDemandResponseMessage } from '../sim/messages';
import { registerHudButton } from './hudButtonBar';

// ── State ──────────────────────────────────────────────────────────────────────

let panel: HTMLDivElement | null = null;
let visible = false;
let latestState: SimHabitatStateMessage['payload'] | null = null;
let workerSend: ((msg: SimHabitatDemandResponseMessage) => void) | null = null;
let pendingRender = false;
let hudButtonRegistered = false;

// ── Public API ─────────────────────────────────────────────────────────────────

export function initHabitatPanel(send: (msg: SimHabitatDemandResponseMessage) => void): void {
  workerSend = send;
  // Button is NOT registered here — it appears only after the habitat is built.
  // Call revealHabitatHudButton() when the first sim:habitat_state message arrives.
}

/** Show the Habitat HUD button. Idempotent — safe to call multiple times. */
export function revealHabitatHudButton(): void {
  if (hudButtonRegistered) return;
  hudButtonRegistered = true;
  registerHudButton('\u{1F3D8} Habitat', toggleHabitatPanel, 'Human habitat (K key)');
}

export function updateHabitatPanel(state: SimHabitatStateMessage['payload']): void {
  latestState = state;
  if (visible && !pendingRender) {
    pendingRender = true;
    requestAnimationFrame(() => {
      pendingRender = false;
      renderPanel();
    });
  }
}

export function toggleHabitatPanel(): void {
  if (visible) hidePanel();
  else showPanel();
}

export function hideHabitatPanel(): void {
  hidePanel();
}

// ── Panel lifecycle ────────────────────────────────────────────────────────────

function showPanel(): void {
  visible = true;
  if (!panel) buildPanel();
  renderPanel();
  panel!.style.display = 'flex';
}

function hidePanel(): void {
  visible = false;
  if (panel) panel.style.display = 'none';
}

function buildPanel(): void {
  panel = document.createElement('div');
  panel.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(4,6,14,0.82);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 180;
    backdrop-filter: blur(3px);
  `;
  panel.addEventListener('click', (e) => {
    if (e.target === panel) hidePanel();
  });
  document.body.appendChild(panel);
}

// ── Rendering ──────────────────────────────────────────────────────────────────

function moraleColor(morale: number): string {
  if (morale < 30) return '#ef4444';
  if (morale < 70) return '#f59e0b';
  return '#22c55e';
}

function statusLabel(state: SimHabitatStateMessage['payload']): { text: string; color: string } {
  if (state.dormant) return { text: 'DORMANT — Evacuated', color: '#ef4444' };
  if (state.growthPaused) return { text: 'CRISIS — Growth Paused', color: '#f59e0b' };
  return { text: 'OPERATIONAL', color: '#22c55e' };
}

const DEMAND_TYPE_LABELS: Record<HumanDemand['type'], string> = {
  resource_allocation: 'Resource Allocation',
  priority_shift: 'Priority Shift',
  safety_concern: 'Safety Concern',
  expansion_request: 'Expansion Request',
};

const DEMAND_TYPE_COLORS: Record<HumanDemand['type'], string> = {
  resource_allocation: '#3b82f6',
  priority_shift: '#f59e0b',
  safety_concern: '#ef4444',
  expansion_request: '#8b5cf6',
};

function renderPanel(): void {
  if (!panel) return;
  panel.innerHTML = '';

  const card = document.createElement('div');
  card.style.cssText = `
    background: rgba(8,12,24,0.97);
    border: 1px solid rgba(100,140,255,0.3);
    border-radius: 10px;
    padding: 24px 28px;
    width: 500px;
    max-height: 85vh;
    overflow-y: auto;
    font-family: 'Courier New', monospace;
    color: #c0d0f0;
    box-shadow: 0 8px 40px rgba(0,0,0,0.7);
  `;

  // Header
  const header = document.createElement('div');
  header.style.cssText = `
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 16px;
    padding-bottom: 10px;
    border-bottom: 1px solid rgba(100,140,255,0.2);
  `;
  header.innerHTML = `<span style="font-size:14px;color:#7090e0;letter-spacing:0.1em;text-transform:uppercase;">&#127961; Human Habitat</span>`;
  const closeBtn = document.createElement('button');
  closeBtn.textContent = '\u00d7';
  closeBtn.style.cssText = 'background:none;border:none;color:#666;cursor:pointer;font-size:18px;';
  closeBtn.onclick = () => hidePanel();
  header.appendChild(closeBtn);
  card.appendChild(header);

  if (!latestState) {
    const empty = document.createElement('div');
    empty.style.cssText = 'color:#4a5568;font-size:12px;text-align:center;padding:20px;';
    empty.textContent = 'Habitat not constructed yet \u2014 research the Habitat Module tech to begin.';
    card.appendChild(empty);
  } else {
    const s = latestState;
    const status = statusLabel(s);

    // Status badge
    const statusEl = document.createElement('div');
    statusEl.style.cssText = `
      font-size: 10px;
      color: ${status.color};
      text-transform: uppercase;
      letter-spacing: 0.08em;
      margin-bottom: 14px;
      padding: 4px 8px;
      border: 1px solid ${status.color}44;
      border-radius: 4px;
      display: inline-block;
    `;
    statusEl.textContent = status.text;
    card.appendChild(statusEl);

    // Population
    const popRow = document.createElement('div');
    popRow.style.cssText = 'display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;';
    const popLabel = document.createElement('span');
    popLabel.style.cssText = 'font-size:11px;color:#6070a0;';
    popLabel.textContent = 'Population';
    const popValue = document.createElement('span');
    popValue.style.cssText = 'font-size:13px;color:#c0d0f0;';
    const growthIndicator = s.dormant ? ' (evacuated)' : s.growthPaused ? ' (stalled)' : '';
    popValue.textContent = `${s.population} / 500${growthIndicator}`;
    popRow.appendChild(popLabel);
    popRow.appendChild(popValue);
    card.appendChild(popRow);

    // Morale bar
    card.appendChild(buildMoraleBar(s.morale));

    // Political Capital
    const pcRow = document.createElement('div');
    pcRow.style.cssText = 'display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;';
    pcRow.title = 'Political Capital — earned from high morale and resolved demands. Spent on diplomatic actions and research bonuses.';
    const pcLabel = document.createElement('span');
    pcLabel.style.cssText = 'font-size:11px;color:#6070a0;';
    pcLabel.textContent = 'Political Capital';
    const pcValue = document.createElement('span');
    pcValue.style.cssText = 'font-size:12px;color:#a78bfa;';
    pcValue.textContent = String(Math.floor(s.politicalCapital));
    pcRow.appendChild(pcLabel);
    pcRow.appendChild(pcValue);
    card.appendChild(pcRow);

    // Resource drain rates
    card.appendChild(buildDrainSection(s.population));

    // Active demands
    card.appendChild(buildDemandsSection(s.demands, s.tick));
  }

  panel.appendChild(card);
}

function buildMoraleBar(morale: number): HTMLDivElement {
  const wrap = document.createElement('div');
  wrap.style.cssText = 'margin-bottom: 14px;';

  const labelRow = document.createElement('div');
  labelRow.style.cssText = 'display:flex;justify-content:space-between;align-items:center;margin-bottom:4px;';

  const nameEl = document.createElement('span');
  nameEl.style.cssText = `font-size:11px;color:${moraleColor(morale)};`;
  nameEl.textContent = 'Morale';

  const valueEl = document.createElement('span');
  valueEl.style.cssText = 'font-size:11px;color:#6070a0;';
  const label = morale < 30 ? ' (crisis)' : morale > 70 ? ' (thriving)' : '';
  valueEl.textContent = `${Math.round(morale)}/100${label}`;

  labelRow.appendChild(nameEl);
  labelRow.appendChild(valueEl);
  wrap.appendChild(labelRow);

  const barBg = document.createElement('div');
  barBg.style.cssText = `
    width: 100%;
    height: 8px;
    background: rgba(40,50,80,0.8);
    border-radius: 4px;
    overflow: hidden;
  `;

  const bar = document.createElement('div');
  const color = moraleColor(morale);
  bar.style.cssText = `
    height: 100%;
    width: ${Math.max(0, Math.min(100, morale))}%;
    background: ${color};
    border-radius: 4px;
    transition: width 0.3s;
    box-shadow: 0 0 8px ${color}44;
  `;
  barBg.appendChild(bar);
  wrap.appendChild(barBg);

  return wrap;
}

function buildDrainSection(population: number): HTMLDivElement {
  const section = document.createElement('div');
  section.style.cssText = 'margin-bottom: 16px;';

  const header = document.createElement('div');
  header.style.cssText = `
    font-size: 10px;
    color: #4a5568;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    margin-bottom: 8px;
  `;
  header.textContent = 'Resource Drain (per interval)';
  section.appendChild(header);

  // Each 50 colonists: +1 water, +0.5 oxygen, +0.5 electronics
  const factor = population / 50;
  const drains: Array<{ resource: string; rate: number; color: string }> = [
    { resource: 'Water', rate: factor * 1, color: '#3b82f6' },
    { resource: 'Oxygen', rate: factor * 0.5, color: '#22d3ee' },
    { resource: 'Electronics', rate: factor * 0.5, color: '#f59e0b' },
  ];

  for (const d of drains) {
    const row = document.createElement('div');
    row.style.cssText = 'display:flex;justify-content:space-between;margin-bottom:4px;';

    const name = document.createElement('span');
    name.style.cssText = `font-size:11px;color:${d.color};`;
    name.textContent = d.resource;

    const rate = document.createElement('span');
    rate.style.cssText = 'font-size:11px;color:#6070a0;';
    rate.textContent = `-${d.rate.toFixed(1)} / interval`;

    row.appendChild(name);
    row.appendChild(rate);
    section.appendChild(row);
  }

  return section;
}

function buildDemandsSection(demands: HumanDemand[], currentTick: number): HTMLDivElement {
  const section = document.createElement('div');

  const header = document.createElement('div');
  header.style.cssText = `
    font-size: 10px;
    color: #4a5568;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    margin-bottom: 8px;
  `;
  header.textContent = 'Active Demands';
  section.appendChild(header);

  const activeDemands = demands.filter((d) => !d.resolved);

  if (activeDemands.length === 0) {
    const empty = document.createElement('div');
    empty.style.cssText = 'font-size:11px;color:#3a4568;padding:6px 0;';
    empty.textContent = 'No active demands from colonists.';
    section.appendChild(empty);
  } else {
    for (const demand of activeDemands) {
      section.appendChild(buildDemandCard(demand, currentTick));
    }
  }

  return section;
}

function buildDemandCard(demand: HumanDemand, currentTick: number): HTMLDivElement {
  const color = DEMAND_TYPE_COLORS[demand.type];
  const wrap = document.createElement('div');
  wrap.style.cssText = `
    border: 1px solid ${color}33;
    border-radius: 6px;
    padding: 10px 12px;
    margin-bottom: 8px;
    background: rgba(0,0,0,0.3);
  `;

  // Type label + deadline
  const topRow = document.createElement('div');
  topRow.style.cssText = 'display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;';

  const typeLabel = document.createElement('span');
  typeLabel.style.cssText = `font-size:10px;color:${color};text-transform:uppercase;letter-spacing:0.05em;`;
  typeLabel.textContent = DEMAND_TYPE_LABELS[demand.type];

  const ticksRemaining = Math.max(0, demand.deadlineTick - currentTick);
  const secondsRemaining = Math.round(ticksRemaining / 60);
  const deadlineEl = document.createElement('span');
  const deadlineColor = secondsRemaining < 30 ? '#ef4444' : secondsRemaining < 120 ? '#f59e0b' : '#6070a0';
  deadlineEl.style.cssText = `font-size:10px;color:${deadlineColor};`;
  deadlineEl.textContent = ticksRemaining > 0 ? `${formatTime(secondsRemaining)} remaining` : 'OVERDUE';

  topRow.appendChild(typeLabel);
  topRow.appendChild(deadlineEl);
  wrap.appendChild(topRow);

  // Description
  const desc = document.createElement('div');
  desc.style.cssText = 'font-size:11px;color:#a0b0d0;line-height:1.4;margin-bottom:8px;';
  desc.textContent = demand.description;
  wrap.appendChild(desc);

  // Stakes
  const stakes = document.createElement('div');
  stakes.style.cssText = 'font-size:10px;color:#4a5568;margin-bottom:8px;';
  stakes.textContent = `Morale risk: -${demand.moralePenalty} | Reward: +${demand.politicalReward} PC`;
  wrap.appendChild(stakes);

  // Action buttons
  if (workerSend) {
    const btnRow = document.createElement('div');
    btnRow.style.cssText = 'display:flex;gap:6px;';

    const actions: Array<{ label: string; action: 'accept' | 'reject' | 'negotiate'; style: string }> = [
      {
        label: 'Accept',
        action: 'accept',
        style: `padding:3px 10px;background:rgba(34,197,94,0.2);border:1px solid rgba(34,197,94,0.4);border-radius:3px;color:#22c55e;cursor:pointer;font-family:'Courier New',monospace;font-size:10px;`,
      },
      {
        label: 'Reject',
        action: 'reject',
        style: `padding:3px 10px;background:rgba(239,68,68,0.15);border:1px solid rgba(239,68,68,0.3);border-radius:3px;color:#ef4444;cursor:pointer;font-family:'Courier New',monospace;font-size:10px;`,
      },
      {
        label: 'Negotiate',
        action: 'negotiate',
        style: `padding:3px 10px;background:rgba(245,158,11,0.15);border:1px solid rgba(245,158,11,0.3);border-radius:3px;color:#f59e0b;cursor:pointer;font-family:'Courier New',monospace;font-size:10px;`,
      },
    ];

    for (const a of actions) {
      const btn = document.createElement('button');
      btn.textContent = a.label;
      btn.style.cssText = a.style;
      btn.onclick = () => {
        workerSend!({
          type: 'sim:habitat_demand_response',
          payload: { demandId: demand.id, action: a.action },
        });
      };
      btnRow.appendChild(btn);
    }

    wrap.appendChild(btnRow);
  }

  return wrap;
}

function formatTime(seconds: number): string {
  if (seconds < 60) return `${seconds}s`;
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return s > 0 ? `${m}m ${s}s` : `${m}m`;
}
