import {
  ACESFilmicToneMapping,
  AmbientLight,
  Color,
  DirectionalLight,
  PerspectiveCamera,
  Scene,
  Vector2,
  WebGLRenderer,
} from 'three';
import { EffectComposer } from 'three/examples/jsm/postprocessing/EffectComposer.js';
import { RenderPass } from 'three/examples/jsm/postprocessing/RenderPass.js';
import { UnrealBloomPass } from 'three/examples/jsm/postprocessing/UnrealBloomPass.js';
import { OutputPass } from 'three/examples/jsm/postprocessing/OutputPass.js';

export interface RendererState {
  renderer: WebGLRenderer;
  scene: Scene;
  camera: PerspectiveCamera;
  composer: EffectComposer;
  bloomPass: UnrealBloomPass;
  ambientLight: AmbientLight;
  sunLight: DirectionalLight;
}

export interface RendererOptions {
  onContextLost?: () => void;
  onContextRestored?: () => void;
}

function createContextLostOverlay(): HTMLDivElement {
  const overlay = document.createElement('div');
  overlay.id = 'webgl-context-lost-overlay';
  Object.assign(overlay.style, {
    position: 'fixed',
    inset: '0',
    display: 'none',
    alignItems: 'center',
    justifyContent: 'center',
    flexDirection: 'column',
    background: 'rgba(0,0,0,0.88)',
    color: '#e2e8f0',
    fontFamily: 'monospace',
    fontSize: '1rem',
    zIndex: '9999',
    gap: '1rem',
    textAlign: 'center',
    padding: '2rem',
  });
  return overlay;
}

export async function initRenderer(
  canvas: HTMLCanvasElement,
  options: RendererOptions = {},
): Promise<RendererState> {
  // For now, use WebGL2. WebGPU support can be added when Three.js stabilizes it.
  const renderer = new WebGLRenderer({
    canvas,
    antialias: true,
    powerPreference: 'high-performance',
  });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.setSize(window.innerWidth, window.innerHeight);
  renderer.toneMapping = ACESFilmicToneMapping;
  renderer.toneMappingExposure = 1.0;

  const scene = new Scene();
  scene.background = new Color(0x000008);

  const camera = new PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 500000);
  camera.position.set(0, 50, 50);
  camera.lookAt(0, 0, 0);

  // Post-processing
  const composer = new EffectComposer(renderer);

  const renderPass = new RenderPass(scene, camera);
  composer.addPass(renderPass);

  const bloomPass = new UnrealBloomPass(
    new Vector2(window.innerWidth, window.innerHeight),
    0.8, // strength
    0.4, // radius
    0.6, // threshold - lower so lit asteroid surfaces catch bloom
  );
  composer.addPass(bloomPass);

  const outputPass = new OutputPass();
  composer.addPass(outputPass);

  // Lighting
  const sunLight = new DirectionalLight(0xfff4e0, 2.5);
  sunLight.position.set(1, 0.5, 0.3).normalize();
  scene.add(sunLight);

  // Subtle fill light from opposite side to prevent pure-black silhouettes
  const fillLight = new DirectionalLight(0x4466cc, 0.6);
  fillLight.position.set(-1, -0.3, -0.5).normalize();
  scene.add(fillLight);

  const ambientLight = new AmbientLight(0x334466, 0.8);
  scene.add(ambientLight);

  // Resize handler
  const onResize = (): void => {
    const w = window.innerWidth;
    const h = window.innerHeight;
    camera.aspect = w / h;
    camera.updateProjectionMatrix();
    renderer.setSize(w, h);
    composer.setSize(w, h);
    bloomPass.resolution.set(w, h);
  };
  window.addEventListener('resize', onResize);

  // WebGL context loss/restore handlers
  const overlay = createContextLostOverlay();
  document.body.appendChild(overlay);
  let restoreTimeout: ReturnType<typeof setTimeout> | null = null;

  canvas.addEventListener('webglcontextlost', (event: Event) => {
    event.preventDefault(); // Required so browser will attempt to restore the context
    options.onContextLost?.();
    overlay.innerHTML = `
      <div style="font-size:1.5rem;margin-bottom:0.5rem">&#9888; Graphics context lost</div>
      <div style="color:#94a3b8">Attempting to restore rendering&hellip;</div>
    `;
    overlay.style.display = 'flex';
    restoreTimeout = setTimeout(() => {
      overlay.innerHTML = `
        <div style="font-size:1.5rem;margin-bottom:0.5rem">&#9888; Graphics context lost</div>
        <div style="color:#f87171;margin-bottom:1rem">Restore failed &mdash; please reload the page.</div>
        <button onclick="location.reload()" style="padding:0.5rem 1.25rem;background:#1e40af;color:#fff;border:none;border-radius:0.375rem;font-family:monospace;font-size:1rem;cursor:pointer">Reload</button>
      `;
    }, 5000);
  });

  canvas.addEventListener('webglcontextrestored', () => {
    if (restoreTimeout !== null) {
      clearTimeout(restoreTimeout);
      restoreTimeout = null;
    }
    overlay.style.display = 'none';
    options.onContextRestored?.();
  });

  return { renderer, scene, camera, composer, bloomPass, ambientLight, sunLight };
}
