/**
 * Solar system body positions for the canonical in-game date 2089-03-22.
 *
 * Positions are pre-computed from simplified Keplerian orbital elements
 * (J2000 epoch) propagated forward to 2089-03-22 using mean anomaly +
 * first-order eccentric anomaly (Newton iteration). All coordinates are
 * heliocentric, in the ecliptic x-z plane (y = 0).
 *
 * Scale: 1 AU = 30,000 game units.
 *
 * Sources: JPL Solar System Dynamics — approximate Keplerian elements
 * https://ssd.jpl.nasa.gov/planets/approx_pos.html
 */

export const GAME_DATE = '2089-03-22';
export const AU_TO_GAME_UNITS = 30_000;

// ── Keplerian element derivation ────────────────────────────────────────────
//
// Julian date of 2089-03-22 12:00 TT:
//   JD = 2478088.0
//   T  = (JD - 2451545.0) / 36525 = 0.72653  (centuries since J2000)
//
// For each planet we use the J2000 elements (a, e, I, L, longPeri, longNode)
// plus their century rates to propagate to T = 0.72653.
//
// Mean anomaly M = L - longPeri  (mod 360)
// Eccentric anomaly E solved via Newton: E_{n+1} = E_n - (E_n - e*sin(E_n) - M) / (1 - e*cos(E_n))
// Heliocentric distance r = a * (1 - e*cos(E))
// True anomaly v = atan2(sqrt(1-e^2)*sin(E), cos(E) - e)
// Position in orbital plane, then rotated by longPeri + longNode to ecliptic x-z.
//
// For simplicity we project onto the ecliptic (y=0) ignoring inclination
// (< 3.4° for all planets except Mercury at 7°). The visual error at
// asteroid-belt distances is negligible.
//
// Below are the final heliocentric (x, z) positions in AU, converted to game units.

interface KeplerElements {
  a: number;       // semi-major axis (AU)
  e: number;       // eccentricity
  L0: number;      // mean longitude at J2000 (deg)
  Ldot: number;    // mean longitude rate (deg/century)
  wbar0: number;   // longitude of perihelion at J2000 (deg)
  wbarDot: number; // longitude of perihelion rate (deg/century)
}

const DEG = Math.PI / 180;

// J2000 Keplerian elements (JPL approximate, 3000 BC – 3000 AD table)
const ELEMENTS: Record<string, KeplerElements> = {
  Mercury:  { a: 0.38710, e: 0.20563, L0: 252.251, Ldot: 149472.675, wbar0: 77.456,  wbarDot: 0.160 },
  Venus:    { a: 0.72333, e: 0.00677, L0: 181.980, Ldot: 58517.816,  wbar0: 131.564, wbarDot: 0.009 },
  Earth:    { a: 1.00000, e: 0.01671, L0: 100.464, Ldot: 35999.372,  wbar0: 102.937, wbarDot: 0.320 },
  Mars:     { a: 1.52368, e: 0.09340, L0: 355.453, Ldot: 19140.299,  wbar0: 336.060, wbarDot: 0.445 },
  Jupiter:  { a: 5.20260, e: 0.04849, L0: 34.351,  Ldot: 3034.906,   wbar0: 14.331,  wbarDot: 0.252 },
  Saturn:   { a: 9.55491, e: 0.05551, L0: 50.077,  Ldot: 1222.114,   wbar0: 93.057,  wbarDot: 0.555 },
  Uranus:   { a: 19.1882, e: 0.04630, L0: 314.055, Ldot: 428.467,    wbar0: 173.005, wbarDot: 0.013 },
  Neptune:  { a: 30.0699, e: 0.00899, L0: 304.349, Ldot: 218.486,    wbar0: 48.120,  wbarDot: 0.010 },
};

// T in Julian centuries since J2000 for 2089-03-22
const T = 0.72653;

function solveKepler(M: number, e: number): number {
  let E = M;
  for (let i = 0; i < 15; i++) {
    const dE = (E - e * Math.sin(E) - M) / (1 - e * Math.cos(E));
    E -= dE;
    if (Math.abs(dE) < 1e-12) break;
  }
  return E;
}

function computePosition(el: KeplerElements): { x: number; z: number } {
  const L = (el.L0 + el.Ldot * T) * DEG;
  const wbar = (el.wbar0 + el.wbarDot * T) * DEG;
  const M = ((L - wbar) % (2 * Math.PI) + 2 * Math.PI) % (2 * Math.PI);
  const E = solveKepler(M, el.e);
  const cosE = Math.cos(E);
  const sinE = Math.sin(E);
  const v = Math.atan2(Math.sqrt(1 - el.e * el.e) * sinE, cosE - el.e);
  const r = el.a * (1 - el.e * cosE);
  // Heliocentric position in ecliptic plane, rotated by longitude of perihelion
  const angle = v + wbar;
  return {
    x: r * Math.cos(angle),
    z: r * Math.sin(angle),
  };
}

// ── Body definitions ────────────────────────────────────────────────────────

export interface SolarBody {
  name: string;
  x: number;          // game units
  z: number;          // game units
  radiusKm: number;
  color: string;
  hasRings?: boolean;
  isMoon?: boolean;
  parentName?: string;
}

function au(v: number): number {
  return v * AU_TO_GAME_UNITS;
}

function buildBodies(): SolarBody[] {
  const bodies: SolarBody[] = [];

  // Sun at origin
  bodies.push({ name: 'Sun', x: 0, z: 0, radiusKm: 696_340, color: '#ffee88' });

  // Planets
  const planetData: Array<{ name: string; radiusKm: number; color: string; hasRings?: boolean }> = [
    { name: 'Mercury',  radiusKm: 2_440,  color: '#b0a090' },
    { name: 'Venus',    radiusKm: 6_052,  color: '#e8d8a0' },
    { name: 'Earth',    radiusKm: 6_371,  color: '#4488cc' },
    { name: 'Mars',     radiusKm: 3_390,  color: '#cc6644' },
    { name: 'Jupiter',  radiusKm: 69_911, color: '#d4a860' },
    { name: 'Saturn',   radiusKm: 58_232, color: '#c8b080', hasRings: true },
    { name: 'Uranus',   radiusKm: 25_362, color: '#88cccc' },
    { name: 'Neptune',  radiusKm: 24_622, color: '#4466cc' },
  ];

  const planetPositions: Record<string, { x: number; z: number }> = {};

  for (const p of planetData) {
    const pos = computePosition(ELEMENTS[p.name]);
    const gameX = au(pos.x);
    const gameZ = au(pos.z);
    planetPositions[p.name] = { x: gameX, z: gameZ };
    bodies.push({
      name: p.name,
      x: gameX,
      z: gameZ,
      radiusKm: p.radiusKm,
      color: p.color,
      hasRings: p.hasRings,
    });
  }

  // Major moons (small offsets from parent planet)
  const moonOffset = 0.003; // ~90 game units — visually close to parent
  const moons: Array<{ name: string; parent: string; radiusKm: number; offsetAngle: number }> = [
    { name: 'Phobos',   parent: 'Mars',    radiusKm: 11,   offsetAngle: 0 },
    { name: 'Deimos',   parent: 'Mars',    radiusKm: 6,    offsetAngle: Math.PI * 0.6 },
    { name: 'Io',       parent: 'Jupiter', radiusKm: 1_822, offsetAngle: 0 },
    { name: 'Europa',   parent: 'Jupiter', radiusKm: 1_561, offsetAngle: Math.PI * 0.5 },
    { name: 'Ganymede', parent: 'Jupiter', radiusKm: 2_634, offsetAngle: Math.PI },
    { name: 'Callisto', parent: 'Jupiter', radiusKm: 2_410, offsetAngle: Math.PI * 1.5 },
    { name: 'Titan',    parent: 'Saturn',  radiusKm: 2_575, offsetAngle: Math.PI * 0.3 },
  ];

  for (const m of moons) {
    const pp = planetPositions[m.parent];
    if (!pp) continue;
    const dist = au(moonOffset) * (1 + moons.indexOf(m) * 0.3);
    bodies.push({
      name: m.name,
      x: pp.x + Math.cos(m.offsetAngle) * dist,
      z: pp.z + Math.sin(m.offsetAngle) * dist,
      radiusKm: m.radiusKm,
      color: '#aaaaaa',
      isMoon: true,
      parentName: m.parent,
    });
  }

  return bodies;
}

/** All solar system bodies with pre-computed positions for 2089-03-22. */
export const SOLAR_BODIES: readonly SolarBody[] = buildBodies();

/** Only planets (no Sun, no moons) — useful for minimap rendering. */
export const PLANETS: readonly SolarBody[] = SOLAR_BODIES.filter(
  (b) => !b.isMoon && b.name !== 'Sun',
);
