/**
 * Build handlers: sim:building_built, sim:build_state, sim:base_built,
 * sim:logistics_state, sim:automation_state.
 */
import type {
  WorkerToMainMessage,
  SimBuildingBuiltMessage,
  SimBaseBuiltMessage,
  SimBuildStateMessage,
  SimLogisticsStateMessage,
  SimAutomationStateMessage,
  SimBlueprintStateMessage,
  SimRobotProducedMessage,
} from '../sim/messages';
import { storageValues } from '../gameRuntimeState';
import { showNotification } from '../ui/notifications';
import { isAway, recordAwayEvent } from '../advisor/awayEvents';
import { showBaseBuiltNotification, updateLogisticsState } from '../ui/logisticsPanel';
import { updateBuildingsState } from '../ui/baseBuildingsPanel';
import { updateAutomationState } from '../ui/automationPanel';
import { updateBlueprintState } from '../ui/blueprintPanel';
import { updateMinimapBases } from '../ui/minimap';
import { playSfx } from '../audio/sfxEngine';
import { BaseStationRenderer } from '../render/BaseStationRenderer';
import type { HandlerContext, HandlerMap } from './types';

export function registerBuildHandlers(ctx: HandlerContext): HandlerMap {
  const { refs, renderers } = ctx;
  const { scene, extraBaseRenderers } = renderers;

  return {
    'sim:building_built': (msg: WorkerToMainMessage) => {
      const bMsg = msg as SimBuildingBuiltMessage;
      if (bMsg.payload.success) {
        const buildingNames: Record<number, string> = { 0: 'Robot Factory', 1: 'Defense Turret', 2: 'Comm Relay' };
        const name = buildingNames[bMsg.payload.buildingType] ?? 'Building';
        if (isAway()) {
          recordAwayEvent({ type: 'building_built', name, timestamp: Date.now() });
        }
        showNotification(`⚙ ${name} construction started!`, '#f59e0b', 'build');
        playSfx('game.build_deploy');
        refs.latestBuildings = bMsg.payload.buildings.buildings;
        updateBuildingsState(
          { iron: storageValues[0], nickel: storageValues[1], cobalt: storageValues[2],
            platinum: storageValues[3], ice: storageValues[4], carbon: storageValues[5], silicate: storageValues[6] },
          refs.latestUnlockedMask,
          bMsg.payload.buildings.buildings,
        );
      } else {
        showNotification('Cannot build: insufficient resources or tech not unlocked', '#ef4444', 'danger');
      }
    },

    'sim:base_built': (msg: WorkerToMainMessage) => {
      const builtMsg = msg as SimBaseBuiltMessage;
      showBaseBuiltNotification(builtMsg.payload.ok, builtMsg.payload.error);
      if (builtMsg.payload.ok) {
        updateLogisticsState(builtMsg.payload.bases, []);
        const nonPrimary = builtMsg.payload.bases.filter((b) => !b.isPrimary);
        while (extraBaseRenderers.length < nonPrimary.length) {
          const b = nonPrimary[extraBaseRenderers.length];
          extraBaseRenderers.push(new BaseStationRenderer(scene, b.x, b.y, b.z));
        }
      }
    },

    'sim:logistics_state': (msg: WorkerToMainMessage) => {
      const logMsg = msg as SimLogisticsStateMessage;
      updateLogisticsState(logMsg.payload.bases, logMsg.payload.routes);
      updateMinimapBases(logMsg.payload.bases);
      const nonPrimary = logMsg.payload.bases.filter((b) => !b.isPrimary);
      while (extraBaseRenderers.length < nonPrimary.length) {
        const b = nonPrimary[extraBaseRenderers.length];
        extraBaseRenderers.push(new BaseStationRenderer(scene, b.x, b.y, b.z));
      }
    },

    'sim:automation_state': (msg: WorkerToMainMessage) => {
      const autoMsg = msg as SimAutomationStateMessage;
      updateAutomationState(autoMsg.payload);
    },

    'sim:blueprint_state': (msg: WorkerToMainMessage) => {
      const bpMsg = msg as SimBlueprintStateMessage;
      updateBlueprintState(bpMsg.payload);
    },

    'sim:build_state': (msg: WorkerToMainMessage) => {
      const bsMsg = msg as SimBuildStateMessage;
      refs.latestBuildings = bsMsg.payload.buildings;
      updateBuildingsState(
        { iron: storageValues[0], nickel: storageValues[1], cobalt: storageValues[2],
          platinum: storageValues[3], ice: storageValues[4], carbon: storageValues[5], silicate: storageValues[6] },
        refs.latestUnlockedMask,
        bsMsg.payload.buildings,
      );
    },

    'sim:robot_produced': (msg: WorkerToMainMessage) => {
      const rMsg = msg as SimRobotProducedMessage;
      const name = rMsg.payload.robotTypeName;
      if (isAway()) {
        recordAwayEvent({ type: 'robot_built', name, timestamp: Date.now() });
      }
      showNotification(`⚙ ${name} deployed!`, '#3b82f6', 'build');
      playSfx('game.robot_deploy');
    },
  };
}
