const STORAGE_KEY = 'soundEventMap';

// ── Buffer cache ──────────────────────────────────────────────────────────────

const bufferCache = new Map<string, AudioBuffer>();

// ── Map persistence ───────────────────────────────────────────────────────────

let _cachedMap: SfxEventMap | null = null;

export function loadSfxMap(): SfxEventMap {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) {
      const parsed = JSON.parse(raw) as Partial<SfxEventMap>;
      return { ...DEFAULT_SFX_MAP, ...parsed };
    }
  } catch {
    // ignore
  }
  return { ...DEFAULT_SFX_MAP };
}

export function saveSfxMap(map: SfxEventMap): void {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(map));
    _cachedMap = null;
  } catch {
    // ignore
  }
}

export function resetSfxMap(): SfxEventMap {
  try {
    localStorage.removeItem(STORAGE_KEY);
    _cachedMap = null;
  } catch {
    // ignore
  }
  return { ...DEFAULT_SFX_MAP };
}

// ── Playback ──────────────────────────────────────────────────────────────────

/**
 * Load a WAV file into a Web Audio API AudioBuffer.
 * Returns null if loading fails or audio is not initialized.
 */
async function loadBuffer(filename: string): Promise<AudioBuffer | null> {
  const cached = bufferCache.get(filename);
  if (cached) return cached;

  const ctx = audioEngine.getAudioContext();
  if (!ctx) return null;

  try {
    const url = `${import.meta.env.BASE_URL}assets/sounds/${encodeURIComponent(filename)}`;
    const response = await fetch(url);
    if (!response.ok) return null;
    const arrayBuffer = await response.arrayBuffer();
    const audioBuffer = await ctx.decodeAudioData(arrayBuffer);
    bufferCache.set(filename, audioBuffer);
    return audioBuffer;
  } catch {
    return null;
  }
}

/**
 * Play a sound for the given game event.
 * Uses a cached mapping; cache is invalidated when saveSfxMap/resetSfxMap are called.
 */
export function playSfx(event: SfxEvent): void {
  if (!_cachedMap) _cachedMap = loadSfxMap();
  const filename = _cachedMap[event];
  if (!filename) return;

  void (async () => {
    const ctx = audioEngine.getAudioContext();
    if (!ctx) return;

    const buffer = await loadBuffer(filename);
    if (!buffer) return;

    const sfxGain = audioEngine.getSfxGain();
    if (!sfxGain) return;

    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(sfxGain);
    source.start();
  })();
}

/**
 * Preview a specific sound file by filename. Used by the Sound Designer panel.
 */
export function previewSfx(filename: string): void {
  void (async () => {
    const ctx = audioEngine.getAudioContext();
    if (!ctx) return;

    const buffer = await loadBuffer(filename);
    if (!buffer) return;

    const sfxGain = audioEngine.getSfxGain();
    if (!sfxGain) return;

    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(sfxGain);
    source.start();
  })();
}
