import { playSfx } from '../audio/sfxEngine';

export function makeButton(text: string, color: string, onClick: () => void): HTMLButtonElement {
  const btn = document.createElement('button');
  btn.textContent = text;
  btn.style.cssText = `
    width: 100%;
    padding: 12px;
    background: transparent;
    border: 1px solid ${color};
    color: ${color};
    font-family: 'Courier New', monospace;
    font-size: 14px;
    letter-spacing: 2px;
    cursor: pointer;
    border-radius: 4px;
    margin-top: 4px;
  `;
  btn.addEventListener('click', () => { playSfx('ui.button_press'); onClick(); });
  return btn;
}

export function makeSmallButton(text: string, onClick: () => void): HTMLButtonElement {
  const btn = document.createElement('button');
  btn.textContent = text;
  btn.style.cssText = `
    padding: 4px 10px;
    background: transparent;
    border: 1px solid #4aff4a;
    color: #4aff4a;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    cursor: pointer;
    border-radius: 3px;
  `;
  btn.addEventListener('click', onClick);
  return btn;
}

export function showToast(msg: string): void {
  const toast = document.createElement('div');
  toast.style.cssText = `
    position: fixed;
    bottom: 40px;
    left: 50%;
    transform: translateX(-50%);
    background: rgba(0,0,0,0.9);
    color: #aaffaa;
    font-family: 'Courier New', monospace;
    font-size: 14px;
    padding: 10px 20px;
    border: 1px solid #4aff4a;
    border-radius: 4px;
    z-index: 2000;
  `;
  toast.textContent = msg;
  document.body.appendChild(toast);
  setTimeout(() => toast.remove(), 2500);
}
