import {
  AdditiveBlending,
  BufferAttribute,
  BufferGeometry,
  CanvasTexture,
  DoubleSide,
  Group,
  Material,
  Mesh,
  PlaneGeometry,
  Points,
  Scene,
  ShaderMaterial,
  Vector3,
} from 'three';
import type { DustCell } from '../../sim/dustGrid';
import { DUST_CELL_SIZE } from '../../sim/dustGrid';

/** Resolution of the dynamic dust overlay texture. */
const DUST_TEX_SIZE = 64;

/**
 * Creates a starfield and dust background using layered planes with parallax.
 * Rendered before the scene with depth write disabled.
 */
export class ParallaxSkybox {
  private starField: Points;
  private dustPlane: Mesh;
  private group: Group;

  // Dynamic dust haze overlay
  private dustCanvas: OffscreenCanvas | HTMLCanvasElement;
  private dustCtx: OffscreenCanvasRenderingContext2D | CanvasRenderingContext2D;
  private dustTexture: CanvasTexture;
  private dustOverlay: Mesh;

  constructor(scene: Scene) {
    this.group = new Group();
    this.group.renderOrder = -1;

    // Star field - thousands of point sprites
    const starCount = 3000;
    const starPositions = new Float32Array(starCount * 3);
    const starSizes = new Float32Array(starCount);
    const starColors = new Float32Array(starCount * 3);

    for (let i = 0; i < starCount; i++) {
      // Distribute on a large sphere
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);
      const r = 200000 + Math.random() * 100000;

      starPositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      starPositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
      starPositions[i * 3 + 2] = r * Math.cos(phi);

      starSizes[i] = 1.0 + Math.random() * 2.5;

      // Color variation: mostly white with hints of blue, yellow, red
      const colorRoll = Math.random();
      if (colorRoll < 0.7) {
        starColors[i * 3] = 0.9 + Math.random() * 0.1;
        starColors[i * 3 + 1] = 0.9 + Math.random() * 0.1;
        starColors[i * 3 + 2] = 1.0;
      } else if (colorRoll < 0.85) {
        starColors[i * 3] = 1.0;
        starColors[i * 3 + 1] = 0.8 + Math.random() * 0.2;
        starColors[i * 3 + 2] = 0.6 + Math.random() * 0.2;
      } else {
        starColors[i * 3] = 0.6 + Math.random() * 0.2;
        starColors[i * 3 + 1] = 0.7 + Math.random() * 0.2;
        starColors[i * 3 + 2] = 1.0;
      }
    }

    const starGeo = new BufferGeometry();
    starGeo.setAttribute('position', new BufferAttribute(starPositions, 3));
    starGeo.setAttribute('size', new BufferAttribute(starSizes, 1));
    starGeo.setAttribute('color', new BufferAttribute(starColors, 3));

    const starMat = new ShaderMaterial({
      vertexShader: `
        attribute float size;
        attribute vec3 color;
        varying vec3 vColor;
        varying float vSize;
        void main() {
          vColor = color;
          vec4 mvPos = modelViewMatrix * vec4(position, 1.0);
          float rawSize = size * (300.0 / -mvPos.z);
          // Minimum 1.5px to prevent sub-pixel aliasing / moire patterns
          gl_PointSize = clamp(rawSize, 1.5, 5.0);
          vSize = gl_PointSize;
          gl_Position = projectionMatrix * mvPos;
        }
      `,
      fragmentShader: `
        varying vec3 vColor;
        varying float vSize;
        void main() {
          float d = length(gl_PointCoord - vec2(0.5));
          if (d > 0.5) discard;
          // Softer falloff for small stars to reduce aliasing
          float softness = mix(0.35, 0.5, clamp((vSize - 1.5) / 3.0, 0.0, 1.0));
          float alpha = 1.0 - smoothstep(0.0, softness, d);
          gl_FragColor = vec4(vColor, alpha * 0.9);
        }
      `,
      transparent: true,
      depthWrite: false,
      blending: AdditiveBlending,
    });

    this.starField = new Points(starGeo, starMat);
    this.group.add(this.starField);

    // Dust layer - subtle nebula-like effect
    const dustGeo = new PlaneGeometry(400000, 400000);
    const dustMat = new ShaderMaterial({
      vertexShader: `
        varying vec2 vUv;
        void main() {
          vUv = uv;
          gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
        }
      `,
      fragmentShader: `
        varying vec2 vUv;
        uniform float uTime;

        // Simple noise for dust
        float hash(vec2 p) {
          return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
        }

        float noise(vec2 p) {
          vec2 i = floor(p);
          vec2 f = fract(p);
          f = f * f * (3.0 - 2.0 * f);
          float a = hash(i);
          float b = hash(i + vec2(1.0, 0.0));
          float c = hash(i + vec2(0.0, 1.0));
          float d = hash(i + vec2(1.0, 1.0));
          return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
        }

        float fbm(vec2 p) {
          float v = 0.0;
          float a = 0.5;
          // 2 octaves instead of 4 — halves GPU sin() cost with negligible visual difference
          for (int i = 0; i < 2; i++) {
            v += a * noise(p);
            p *= 2.0;
            a *= 0.5;
          }
          return v;
        }

        uniform vec3 uNebulaTint;
        uniform float uNebulaTintStrength;

        void main() {
          vec2 p = vUv * 3.0;
          float n = fbm(p + uTime * 0.01);
          // Base nebula color blended with per-region tint
          vec3 baseDark = vec3(0.02, 0.01, 0.04);
          vec3 baseBright = vec3(0.06, 0.03, 0.08);
          vec3 nebula = mix(baseDark, baseBright, n);
          // Apply region tint on top
          vec3 tinted = mix(nebula, uNebulaTint, uNebulaTintStrength * 0.6);
          float alpha = n * (0.12 + uNebulaTintStrength * 0.08);
          gl_FragColor = vec4(tinted, alpha);
        }
      `,
      uniforms: {
        uTime: { value: 0 },
        uNebulaTint: { value: [0.06, 0.03, 0.08] },
        uNebulaTintStrength: { value: 0.0 },
      },
      transparent: true,
      depthWrite: false,
      side: DoubleSide,
    });

    this.dustPlane = new Mesh(dustGeo, dustMat);
    this.dustPlane.position.y = -5000;
    this.dustPlane.rotation.x = -Math.PI / 2;
    this.group.add(this.dustPlane);

    // Dynamic dust hazard overlay — driven by sim DustGrid state
    const useOffscreen = typeof OffscreenCanvas !== 'undefined';
    this.dustCanvas = useOffscreen
      ? new OffscreenCanvas(DUST_TEX_SIZE, DUST_TEX_SIZE)
      : document.createElement('canvas');
    if (!useOffscreen) {
      (this.dustCanvas as HTMLCanvasElement).width = DUST_TEX_SIZE;
      (this.dustCanvas as HTMLCanvasElement).height = DUST_TEX_SIZE;
    }
    this.dustCtx = this.dustCanvas.getContext('2d')! as
      OffscreenCanvasRenderingContext2D | CanvasRenderingContext2D;
    this.dustTexture = new CanvasTexture(this.dustCanvas as HTMLCanvasElement);

    const overlayGeo = new PlaneGeometry(400000, 400000);
    const overlayMat = new ShaderMaterial({
      vertexShader: `
        varying vec2 vUv;
        void main() {
          vUv = uv;
          gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
        }
      `,
      fragmentShader: `
        varying vec2 vUv;
        uniform sampler2D uDustMap;
        uniform float uDustIntensity;
        void main() {
          float d = texture2D(uDustMap, vUv).r;
          // Orange-brown tint for dust, opacity scales with density
          vec3 dustColor = vec3(0.6, 0.35, 0.1);
          float alpha = d * uDustIntensity * 0.6;
          gl_FragColor = vec4(dustColor, alpha);
        }
      `,
      uniforms: {
        uDustMap: { value: this.dustTexture },
        uDustIntensity: { value: 1.0 },
      },
      transparent: true,
      depthWrite: false,
      side: DoubleSide,
    });

    this.dustOverlay = new Mesh(overlayGeo, overlayMat);
    this.dustOverlay.position.y = -4900; // slightly above main dust plane
    this.dustOverlay.rotation.x = -Math.PI / 2;
    this.group.add(this.dustOverlay);

    scene.add(this.group);
  }

  /** Set the region-specific nebula tint. Called by BeltRegionRenderer. */
  setNebulaTint(r: number, g: number, b: number, strength: number): void {
    const mat = this.dustPlane.material as ShaderMaterial;
    const tint = mat.uniforms.uNebulaTint.value as number[];
    tint[0] = r;
    tint[1] = g;
    tint[2] = b;
    mat.uniforms.uNebulaTintStrength.value = strength;
  }

  /**
   * Update the dynamic dust hazard overlay from DustGrid state.
   * Called when sim:dust_state message is received.
   */
  updateDustMap(dustCells: DustCell[]): void {
    const ctx = this.dustCtx;
    const size = DUST_TEX_SIZE;

    // Clear to fully transparent
    ctx.clearRect(0, 0, size, size);

    if (dustCells.length === 0) {
      this.dustTexture.needsUpdate = true;
      return;
    }

    // Use world bounds: belt extends roughly -50000 to +50000 on each axis
    // Map grid coords to texture pixels
    const worldMin = -50000 / DUST_CELL_SIZE;
    const worldMax = 50000 / DUST_CELL_SIZE;
    const worldRange = worldMax - worldMin;

    // Use ImageData for direct pixel writes — avoids per-cell fillStyle string allocation
    const imageData = ctx.createImageData(size, size);
    const data = imageData.data;

    for (const cell of dustCells) {
      const px = Math.floor(((cell.gx - worldMin) / worldRange) * size);
      const py = Math.floor(((cell.gz - worldMin) / worldRange) * size);
      if (px < 0 || px >= size - 1 || py < 0 || py >= size - 1) continue;

      const brightness = Math.min(255, Math.round(Math.min(1.0, cell.density) * 255));
      // Paint a 2x2 area for visibility at this resolution
      for (let dy = 0; dy < 2; dy++) {
        for (let dx = 0; dx < 2; dx++) {
          const idx = ((py + dy) * size + (px + dx)) * 4;
          data[idx] = brightness;
          data[idx + 1] = brightness;
          data[idx + 2] = brightness;
          data[idx + 3] = 255;
        }
      }
    }

    ctx.putImageData(imageData, 0, 0);
    this.dustTexture.needsUpdate = true;
  }

  update(cameraPosition: Vector3, time: number): void {
    // Near-zero parallax for stars
    this.starField.position.set(
      cameraPosition.x * 0.001,
      cameraPosition.y * 0.001,
      cameraPosition.z * 0.001,
    );

    // Slightly more parallax for dust
    this.dustPlane.position.x = cameraPosition.x * 0.05;
    this.dustPlane.position.z = cameraPosition.z * 0.05;

    // Dust overlay follows same parallax as base dust
    this.dustOverlay.position.x = cameraPosition.x * 0.05;
    this.dustOverlay.position.z = cameraPosition.z * 0.05;

    // Animate dust
    const mat = this.dustPlane.material as ShaderMaterial;
    mat.uniforms.uTime.value = time;
  }

  dispose(): void {
    this.starField.geometry.dispose();
    (this.starField.material as Material).dispose();
    this.dustPlane.geometry.dispose();
    (this.dustPlane.material as Material).dispose();
    this.dustOverlay.geometry.dispose();
    (this.dustOverlay.material as Material).dispose();
    this.dustTexture.dispose();
  }
}
