/**
 * System Map Panel — press O to toggle.
 *
 * A zoomed-out schematic of the solar system showing:
 * - Planets at approximate orbital distances
 * - Active cargo shipments in transit as moving dots
 * - Demand indicators per destination (green/yellow/gray)
 * - Click a planet to see info + dispatch option
 * - Belt indicator showing the player's zone
 */

import { registerHudButton } from './hudButtonBar';
import type { TransitSnapshot, TransitShipment } from '../sim/transit';
import { DESTINATIONS, TICKS_PER_GAME_DAY } from '../sim/transit';
import type { MineralField } from '../sim/minerals';
import { MINERAL_FIELDS } from '../sim/minerals';

// ── Planet layout data ──────────────────────────────────────────────────────

interface MapPlanet {
  id: string;
  name: string;
  /** Schematic distance from Sun in map units (0-1 range, logarithmic). */
  mapRadius: number;
  /** Current angle in radians for cosmetic orbit. */
  angle: number;
  /** Angular speed in radians per real-second. */
  angularSpeed: number;
  color: string;
  size: number;
  /** Is this a trade destination? */
  isDestination: boolean;
}

// Logarithmic mapping of AU distances for schematic view
// Real AU: Mercury 0.39, Venus 0.72, Earth 1.0, Mars 1.52, Belt ~2.7,
//          Jupiter 5.2, Saturn 9.5
function auToMapRadius(au: number): number {
  return 0.12 + 0.18 * Math.log2(au + 0.5);
}

const MAP_PLANETS: MapPlanet[] = [
  { id: 'mercury', name: 'Mercury', mapRadius: auToMapRadius(0.39), angle: 0.8, angularSpeed: 0.04, color: '#b0a090', size: 3, isDestination: false },
  { id: 'venus',   name: 'Venus',   mapRadius: auToMapRadius(0.72), angle: 2.1, angularSpeed: 0.025, color: '#e8d8a0', size: 4, isDestination: false },
  { id: 'earth',   name: 'Earth',   mapRadius: auToMapRadius(1.0),  angle: 3.5, angularSpeed: 0.02, color: '#4488cc', size: 5, isDestination: true },
  { id: 'luna',    name: 'Luna',    mapRadius: auToMapRadius(1.0),  angle: 3.7, angularSpeed: 0.02, color: '#aaaaaa', size: 3, isDestination: true },
  { id: 'mars',    name: 'Mars',    mapRadius: auToMapRadius(1.52), angle: 5.0, angularSpeed: 0.015, color: '#cc6644', size: 4, isDestination: false },
  { id: 'jupiter', name: 'Jupiter', mapRadius: auToMapRadius(5.2),  angle: 1.2, angularSpeed: 0.005, color: '#d4a860', size: 8, isDestination: false },
  { id: 'saturn',  name: 'Saturn',  mapRadius: auToMapRadius(9.5),  angle: 4.0, angularSpeed: 0.003, color: '#c8b080', size: 7, isDestination: false },
];

const BELT_MAP_RADIUS = auToMapRadius(2.7);

// ── State ───────────────────────────────────────────────────────────────────

let panel: HTMLDivElement | null = null;
let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;
let infoBox: HTMLDivElement | null = null;
let visible = false;
let hudBtn: HTMLButtonElement | null = null;
let snapshot: (TransitSnapshot & { tick: number }) | null = null;
let selectedPlanetId: string | null = null;
let animFrameId: number | null = null;
let lastAnimTime = 0;
let dispatchCallback: ((destinationId: string) => void) | null = null;

const CANVAS_SIZE = 480;
const CENTER = CANVAS_SIZE / 2;
const MAP_SCALE = CANVAS_SIZE * 0.45; // radius of outermost orbit in pixels

// ── Public API ──────────────────────────────────────────────────────────────

export function initSystemMapPanel(
  onDispatch: (destinationId: string) => void,
): void {
  dispatchCallback = onDispatch;
  hudBtn = registerHudButton('🗺 SYSTEM MAP', toggleSystemMapPanel, 'System Map (O)');
}

export function toggleSystemMapPanel(): void {
  if (visible) hidePanel(); else showPanel();
}

export function hideSystemMapPanel(): void {
  hidePanel();
}

export function isSystemMapPanelVisible(): boolean {
  return visible;
}

export function updateTransitSnapshot(snap: TransitSnapshot & { tick: number }): void {
  snapshot = snap;
}

// ── Lifecycle ───────────────────────────────────────────────────────────────

function showPanel(): void {
  visible = true;
  if (!panel) buildPanel();
  panel!.style.display = 'flex';
  if (hudBtn) hudBtn.style.background = 'rgba(20,50,110,0.9)';
  lastAnimTime = performance.now();
  animLoop();
}

function hidePanel(): void {
  visible = false;
  if (panel) panel.style.display = 'none';
  if (hudBtn) hudBtn.style.background = 'rgba(0,0,0,0.75)';
  if (animFrameId !== null) {
    cancelAnimationFrame(animFrameId);
    animFrameId = null;
  }
  selectedPlanetId = null;
  if (infoBox) infoBox.style.display = 'none';
}

function buildPanel(): void {
  panel = document.createElement('div');
  panel.setAttribute('role', 'dialog');
  panel.setAttribute('aria-label', 'System Map');
  panel.style.cssText = `
    position: fixed;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: ${CANVAS_SIZE + 40}px;
    background: rgba(4,8,18,0.96);
    border: 1px solid rgba(100,150,255,0.25);
    border-radius: 8px;
    box-shadow: 0 8px 40px rgba(0,0,0,0.7);
    color: #c0d0f0;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    z-index: 200;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    pointer-events: auto;
  `;

  // Header
  const header = document.createElement('div');
  header.style.cssText = `
    padding: 10px 14px;
    border-bottom: 1px solid rgba(100,140,255,0.15);
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-shrink: 0;
  `;
  const titleEl = document.createElement('span');
  titleEl.style.cssText = 'font-size: 10px; color: #7090e0; letter-spacing: 2px; text-transform: uppercase;';
  titleEl.textContent = 'System Map';
  header.appendChild(titleEl);

  const creditsEl = document.createElement('span');
  creditsEl.id = 'sysmap-credits';
  creditsEl.style.cssText = 'font-size: 10px; color: #4ade80;';
  header.appendChild(creditsEl);

  const closeBtn = document.createElement('button');
  closeBtn.setAttribute('aria-label', 'Close system map');
  closeBtn.textContent = '\u00d7';
  closeBtn.style.cssText = 'background:none;border:none;color:#64748b;cursor:pointer;font-size:16px;padding:0;line-height:1;';
  closeBtn.addEventListener('click', hidePanel);
  header.appendChild(closeBtn);
  panel.appendChild(header);

  // Canvas
  canvas = document.createElement('canvas');
  canvas.width = CANVAS_SIZE;
  canvas.height = CANVAS_SIZE;
  canvas.style.cssText = `
    display: block;
    margin: 10px auto;
    cursor: crosshair;
  `;
  canvas.addEventListener('click', onCanvasClick);
  canvas.addEventListener('mousemove', onCanvasHover);
  ctx = canvas.getContext('2d')!;
  panel.appendChild(canvas);

  // Info box (shown on planet click)
  infoBox = document.createElement('div');
  infoBox.style.cssText = `
    margin: 0 14px 10px;
    padding: 10px 12px;
    background: rgba(10,15,30,0.9);
    border: 1px solid rgba(100,150,255,0.2);
    border-radius: 4px;
    display: none;
    font-size: 11px;
    line-height: 1.6;
  `;
  panel.appendChild(infoBox);

  // Footer
  const footer = document.createElement('div');
  footer.style.cssText = `
    padding: 6px 14px;
    border-top: 1px solid rgba(100,140,255,0.1);
    font-size: 9px;
    color: #475569;
    text-align: center;
    flex-shrink: 0;
  `;
  footer.textContent = 'Click planet for details \u00b7 Press O or ESC to close';
  panel.appendChild(footer);

  document.body.appendChild(panel);
}

// ── Rendering ───────────────────────────────────────────────────────────────

function animLoop(): void {
  if (!visible) return;
  const now = performance.now();
  const dt = (now - lastAnimTime) / 1000;
  lastAnimTime = now;

  // Advance cosmetic orbits
  for (const p of MAP_PLANETS) {
    p.angle += p.angularSpeed * dt;
  }

  renderMap();
  animFrameId = requestAnimationFrame(animLoop);
}

function planetScreenPos(p: MapPlanet): { x: number; y: number } {
  const r = p.mapRadius * MAP_SCALE;
  return {
    x: CENTER + Math.cos(p.angle) * r,
    y: CENTER + Math.sin(p.angle) * r,
  };
}

function renderMap(): void {
  if (!ctx) return;
  const c = ctx;
  c.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

  // Update credits display
  const creditsEl = document.getElementById('sysmap-credits');
  if (creditsEl && snapshot) {
    creditsEl.textContent = `\u00a2 ${snapshot.credits.toFixed(1)}`;
  }

  // Draw orbital rings
  c.strokeStyle = 'rgba(60,80,120,0.25)';
  c.lineWidth = 0.5;
  for (const p of MAP_PLANETS) {
    if (p.id === 'luna') continue; // co-orbital with Earth
    c.beginPath();
    c.arc(CENTER, CENTER, p.mapRadius * MAP_SCALE, 0, Math.PI * 2);
    c.stroke();
  }

  // Draw belt zone
  const beltR = BELT_MAP_RADIUS * MAP_SCALE;
  c.fillStyle = 'rgba(100,80,50,0.12)';
  c.beginPath();
  c.arc(CENTER, CENTER, beltR + 12, 0, Math.PI * 2);
  c.arc(CENTER, CENTER, beltR - 12, 0, Math.PI * 2, true);
  c.fill();
  // Belt label
  c.fillStyle = 'rgba(180,150,100,0.5)';
  c.font = '8px "Courier New", monospace';
  c.textAlign = 'center';
  c.fillText('BELT', CENTER, CENTER - beltR + 4);

  // Draw Sun
  c.fillStyle = '#ffee88';
  c.shadowColor = '#ffee44';
  c.shadowBlur = 12;
  c.beginPath();
  c.arc(CENTER, CENTER, 6, 0, Math.PI * 2);
  c.fill();
  c.shadowBlur = 0;

  // Draw planets
  for (const p of MAP_PLANETS) {
    const pos = planetScreenPos(p);
    const dest = DESTINATIONS.find(d => d.id === p.id);
    const isLocked = dest?.locked && !(snapshot?.progression.lunaUnlocked && p.id === 'luna');
    const isAvailable = dest && !isLocked;

    // Demand indicator ring for destinations
    if (p.isDestination) {
      const demandColor = getDemandColor(p.id, isLocked ?? false);
      c.strokeStyle = demandColor;
      c.lineWidth = 2;
      c.beginPath();
      c.arc(pos.x, pos.y, p.size + 4, 0, Math.PI * 2);
      c.stroke();
    }

    // Planet body
    c.fillStyle = isLocked ? '#333' : p.color;
    c.globalAlpha = isLocked ? 0.4 : 1;
    c.beginPath();
    c.arc(pos.x, pos.y, p.size, 0, Math.PI * 2);
    c.fill();
    c.globalAlpha = 1;

    // Saturn rings
    if (p.id === 'saturn') {
      c.strokeStyle = 'rgba(200,176,128,0.4)';
      c.lineWidth = 1.5;
      c.beginPath();
      c.ellipse(pos.x, pos.y, p.size + 5, 2, -0.3, 0, Math.PI * 2);
      c.stroke();
    }

    // Label
    c.fillStyle = isLocked ? '#555' : '#8099cc';
    c.font = '9px "Courier New", monospace';
    c.textAlign = 'center';
    const label = isLocked ? '???' : p.name;
    c.fillText(label, pos.x, pos.y + p.size + 12);

    // Selection highlight
    if (selectedPlanetId === p.id && isAvailable) {
      c.strokeStyle = '#88ccff';
      c.lineWidth = 1;
      c.setLineDash([3, 3]);
      c.beginPath();
      c.arc(pos.x, pos.y, p.size + 8, 0, Math.PI * 2);
      c.stroke();
      c.setLineDash([]);
    }
  }

  // Draw cargo shipments in transit
  if (snapshot) {
    for (const shipment of snapshot.shipments) {
      if (shipment.status !== 'in_transit') continue;
      drawShipment(c, shipment);
    }
  }
}

function drawShipment(c: CanvasRenderingContext2D, shipment: TransitShipment): void {
  const dest = MAP_PLANETS.find(p => p.id === shipment.destinationId);
  if (!dest) return;

  const destPos = planetScreenPos(dest);
  const beltAngle = Math.atan2(destPos.y - CENTER, destPos.x - CENTER) + Math.PI; // opposite side
  const beltX = CENTER + Math.cos(beltAngle) * BELT_MAP_RADIUS * MAP_SCALE;
  const beltY = CENTER + Math.sin(beltAngle) * BELT_MAP_RADIUS * MAP_SCALE;

  // Compute progress 0-1
  const totalTicks = shipment.arrivalTick - shipment.departureTick;
  const tickNow = snapshot?.tick ?? 0;
  const progress = totalTicks > 0
    ? Math.min(1, Math.max(0, (tickNow - shipment.departureTick) / totalTicks))
    : 1;

  // Lerp position along arc from belt to destination
  const x = beltX + (destPos.x - beltX) * progress;
  const y = beltY + (destPos.y - beltY) * progress;

  // Draw trail
  c.strokeStyle = 'rgba(100,200,255,0.15)';
  c.lineWidth = 1;
  c.setLineDash([2, 4]);
  c.beginPath();
  c.moveTo(beltX, beltY);
  c.lineTo(destPos.x, destPos.y);
  c.stroke();
  c.setLineDash([]);

  // Draw cargo dot
  c.fillStyle = '#22d3ee';
  c.shadowColor = '#22d3ee';
  c.shadowBlur = 6;
  c.beginPath();
  c.arc(x, y, 3, 0, Math.PI * 2);
  c.fill();
  c.shadowBlur = 0;

  // ETA label
  const etaDays = Math.max(0, Math.round((shipment.arrivalTick - tickNow) / TICKS_PER_GAME_DAY));
  c.fillStyle = '#88ccff';
  c.font = '8px "Courier New", monospace';
  c.textAlign = 'center';
  c.fillText(`${etaDays}d`, x, y - 7);
}

function getDemandColor(destId: string, isLocked: boolean): string {
  if (isLocked) return 'rgba(80,80,80,0.5)';
  if (!snapshot) return 'rgba(80,80,80,0.5)';

  const destSnap = snapshot.destinations.find(d => d.id === destId);
  if (!destSnap) return 'rgba(80,80,80,0.5)';

  // Average effective price as demand indicator
  let avgPrice = 0;
  let count = 0;
  for (const f of MINERAL_FIELDS) {
    avgPrice += destSnap.pricing[f];
    count++;
  }
  avgPrice /= count;

  // Map average price to color: >1.5 = green (high demand), 0.8-1.5 = yellow, <0.8 = gray
  if (avgPrice >= 1.5) return '#4ade80';
  if (avgPrice >= 0.8) return '#facc15';
  return '#64748b';
}

// ── Interaction ─────────────────────────────────────────────────────────────

function hitTestPlanet(mx: number, my: number): MapPlanet | null {
  for (const p of MAP_PLANETS) {
    const pos = planetScreenPos(p);
    const dx = mx - pos.x;
    const dy = my - pos.y;
    if (dx * dx + dy * dy <= (p.size + 8) * (p.size + 8)) {
      return p;
    }
  }
  return null;
}

function onCanvasHover(e: MouseEvent): void {
  if (!canvas) return;
  const rect = canvas.getBoundingClientRect();
  const mx = (e.clientX - rect.left) * (CANVAS_SIZE / rect.width);
  const my = (e.clientY - rect.top) * (CANVAS_SIZE / rect.height);
  const hit = hitTestPlanet(mx, my);
  canvas.style.cursor = hit ? 'pointer' : 'crosshair';
}

function onCanvasClick(e: MouseEvent): void {
  if (!canvas) return;
  const rect = canvas.getBoundingClientRect();
  const mx = (e.clientX - rect.left) * (CANVAS_SIZE / rect.width);
  const my = (e.clientY - rect.top) * (CANVAS_SIZE / rect.height);
  const hit = hitTestPlanet(mx, my);

  if (!hit) {
    selectedPlanetId = null;
    if (infoBox) infoBox.style.display = 'none';
    return;
  }

  // Check if it's a destination
  const dest = DESTINATIONS.find(d => d.id === hit.id);
  const isLocked = dest?.locked && !(snapshot?.progression.lunaUnlocked && hit.id === 'luna');

  if (isLocked) {
    selectedPlanetId = null;
    if (infoBox) {
      infoBox.style.display = 'block';
      infoBox.innerHTML = `
        <div style="color:#64748b;text-align:center;">
          <span style="font-size:16px;">&#x1f512;</span><br>
          <b>${hit.name}</b> — destination locked<br>
          <span style="font-size:9px;color:#475569;">Complete first Earth delivery + mine 10,000 iron to unlock</span>
        </div>
      `;
    }
    return;
  }

  if (!dest) {
    // Non-destination planet — show basic info
    selectedPlanetId = hit.id;
    if (infoBox) {
      infoBox.style.display = 'block';
      infoBox.innerHTML = `
        <div style="color:#8099cc;">
          <b>${hit.name}</b><br>
          <span style="font-size:9px;color:#475569;">Not available for trade (future expansion)</span>
        </div>
      `;
    }
    return;
  }

  // Destination planet — show trade info
  selectedPlanetId = hit.id;
  showDestinationInfo(dest, hit);
}

function showDestinationInfo(dest: typeof DESTINATIONS[number], planet: MapPlanet): void {
  if (!infoBox || !snapshot) return;

  const destSnap = snapshot.destinations.find(d => d.id === dest.id);
  if (!destSnap) return;

  // Build pricing table
  const priceRows = MINERAL_FIELDS.map((f: MineralField) => {
    const price = destSnap.pricing[f];
    const color = price >= 1.5 ? '#4ade80' : price >= 1.0 ? '#facc15' : '#64748b';
    return `<span style="color:${color}">${f}: ${price.toFixed(2)}</span>`;
  }).join(' &middot; ');

  // Count in-transit shipments to this destination
  const inTransit = snapshot.shipments.filter(
    s => s.destinationId === dest.id && s.status === 'in_transit'
  );
  const transitInfo = inTransit.length > 0
    ? `<div style="margin-top:4px;color:#22d3ee;">${inTransit.length} shipment${inTransit.length > 1 ? 's' : ''} in transit</div>`
    : '';

  infoBox.style.display = 'block';
  infoBox.innerHTML = `
    <div>
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;">
        <b style="color:${planet.color};font-size:12px;">${dest.name}</b>
        <span style="color:#475569;font-size:9px;">Transit: ~${destSnap.currentTransitDays} days</span>
      </div>
      <div style="font-size:10px;color:#7090b0;margin-bottom:6px;">Prices: ${priceRows}</div>
      ${transitInfo}
      <button id="sysmap-dispatch-btn" style="
        margin-top:8px;
        padding:6px 16px;
        background:rgba(34,211,238,0.15);
        border:1px solid rgba(34,211,238,0.4);
        border-radius:4px;
        color:#22d3ee;
        font-family:'Courier New',monospace;
        font-size:10px;
        cursor:pointer;
        transition:background 0.15s;
      ">DISPATCH CARGO \u2192 ${dest.name.toUpperCase()}</button>
    </div>
  `;

  const dispatchBtn = document.getElementById('sysmap-dispatch-btn');
  if (dispatchBtn) {
    dispatchBtn.addEventListener('mouseenter', () => {
      dispatchBtn.style.background = 'rgba(34,211,238,0.3)';
    });
    dispatchBtn.addEventListener('mouseleave', () => {
      dispatchBtn.style.background = 'rgba(34,211,238,0.15)';
    });
    dispatchBtn.addEventListener('click', () => {
      if (dispatchCallback) dispatchCallback(dest.id);
    });
  }
}
