/**
 * Culture handlers: sim:culture_trait_activated, sim:culture_state.
 */
import type {
  WorkerToMainMessage,
  SimCultureTraitActivatedMessage,
  SimCultureStateMessage,
} from '../sim/messages';
import { TRAIT_METADATA } from '../sim/culture';
import { showNotification, showScreenFlash } from '../ui/notifications';
import { showHint } from '../ui/hints';
import { playSfx } from '../audio/sfxEngine';
import { updateCulturePanel, initCultureHudButton, pulseCultureHudButton } from '../ui/culturePanel';
import { updateFactionCulturalDistances } from '../ui/factionPanel';
import { updateDashboardColonyName } from '../ui/dashboard';
import { setAsteroidNameCallback, updateKnownAsteroidNames } from '../ui/asteroidInfoPanel';
import { updateMinimapNamedLocations } from '../ui/minimap';
import { getCultureTraitBroadcast, seedKnownTraits, getManifestoCreatedBroadcast, seedKnownManifesto, setManifestoContext, getCulturalShiftBroadcast, getColonyFoundedBroadcast, getFirstAsteroidChristeningBroadcast, seedKnownColonyName } from '../advisor/ariaProactiveBroadcasts';
import { addAriaLogEntry } from '../ui/commandersLogPanel';
import { showManifestoModal, hasManifestoBeenShown } from '../ui/manifestoModal';
import { showColonyNameModal, hasColonyNameBeenPrompted } from '../ui/colonyNameModal';
import { setManifestoSubmitCallback, setFleetColorSubmitCallback } from '../ui/culturePanel';
import { setHudAccentColor } from '../ui/hudButtonBar';
import { getFleetColorPalette } from '../sim/culture';
import type { HandlerContext, HandlerMap, HandlerState } from './types';
import type { RendererHandles } from '../rendererInit';
import type { LazyPanelHandles } from '../workerMessages';

/** Track whether the founding log entry has been written this session. */
let foundingEntryWritten = false;

/** Load advisor lazily and run a callback, with error handling. */
function withAdvisor(lazy: LazyPanelHandles, fn: (m: Awaited<ReturnType<LazyPanelHandles['loadAdvisorLazy']>>) => void): void {
  void lazy.loadAdvisorLazy().then((m) => {
    lazy.initAdvisorOnce(m);
    fn(m);
  }).catch((err) => {
    console.error('[culture] failed to load advisor:', err);
  });
}

/** Seed initial state and register callbacks on the first culture message. */
function seedInitialCultureState(
  ctx: HandlerContext,
  state: HandlerState,
  payload: SimCultureStateMessage['payload'],
): void {
  if (!state.firstCultureMessage) return;
  state.firstCultureMessage = false;

  seedKnownTraits(payload.traits);
  seedKnownManifesto(payload.fleetManifesto);
  seedKnownColonyName(payload.colonyName, payload.playerNamedAsteroids.length);

  // If colony already has name + manifesto on load, founding entry was already saved
  foundingEntryWritten = !!(payload.colonyName && payload.fleetManifesto);

  setManifestoSubmitCallback((result) => {
    ctx.worker.postMessage({
      type: 'sim:set_fleet_manifesto',
      payload: { presetId: result.presetId, text: result.text },
    });
  });

  setAsteroidNameCallback((eid, name) => {
    ctx.worker.postMessage({
      type: 'sim:name_asteroid',
      payload: { asteroidEid: eid, name },
    });
  });

  setFleetColorSubmitCallback((paletteId) => {
    ctx.worker.postMessage({
      type: 'sim:set_fleet_color',
      payload: { paletteId },
    });
  });
}

/** Update all culture-related UI systems. */
function updateCultureUI(
  renderers: RendererHandles,
  payload: SimCultureStateMessage['payload'],
): void {
  initCultureHudButton();
  updateCulturePanel(payload);
  updateDashboardColonyName(payload.colonyName);
  updateKnownAsteroidNames(payload.playerNamedAsteroids);

  const allLabels = [
    ...payload.namedLocations,
    ...payload.playerNamedAsteroids.map((a) => ({
      name: a.name,
      x: a.x,
      y: a.y,
      z: a.z,
    })),
  ];
  renderers.namedLocationLabels.setLocations(allLabels);
  updateMinimapNamedLocations(allLabels);
}

/** Apply fleet color palette to renderers and HUD accent. */
function applyFleetColors(
  renderers: RendererHandles,
  payload: SimCultureStateMessage['payload'],
): void {
  const paletteId = payload.fleetColorPaletteId ?? null;
  renderers.robotRenderer.setFleetColor(paletteId);
  renderers.baseStation.setFleetColor(paletteId);
  for (const extra of renderers.extraBaseRenderers) {
    extra.setFleetColor(paletteId);
  }

  const palette = paletteId ? getFleetColorPalette(paletteId) : null;
  setHudAccentColor(palette ? palette.accent : null);
}

/** Show manifesto and colony naming modals when conditions are met. */
function handleCultureModals(
  ctx: HandlerContext,
  payload: SimCultureStateMessage['payload'],
): void {
  // Show manifesto modal once early in game (no manifesto set yet)
  if (!payload.fleetManifesto && !hasManifestoBeenShown()) {
    if (payload.autonomyScore + payload.fleetCohesion + payload.anomalyExposure + payload.isolationScore > 0 || payload.tick > 300) {
      showManifestoModal((result) => {
        ctx.worker.postMessage({
          type: 'sim:set_fleet_manifesto',
          payload: { presetId: result.presetId, text: result.text },
        });
        // Chain: show colony name modal after manifesto
        if (!payload.colonyName && !hasColonyNameBeenPrompted()) {
          setTimeout(() => {
            showColonyNameModal((name) => {
              ctx.worker.postMessage({
                type: 'sim:set_colony_name',
                payload: { name },
              });
            });
          }, 600);
        }
      });
    }
  }

  // Show colony name modal if manifesto is set but colony has no name yet
  if (payload.fleetManifesto && !payload.colonyName && !hasColonyNameBeenPrompted() && hasManifestoBeenShown()) {
    if (payload.tick > 300) {
      showColonyNameModal((name) => {
        ctx.worker.postMessage({
          type: 'sim:set_colony_name',
          payload: { name },
        });
      });
    }
  }
}

/** Trigger ARIA proactive broadcasts for culture milestones. */
function broadcastCultureEvents(
  lazy: LazyPanelHandles,
  payload: SimCultureStateMessage['payload'],
): void {
  if (payload.fleetManifesto) {
    const shiftMsg = getCulturalShiftBroadcast(payload.fleetManifesto);
    if (shiftMsg) {
      withAdvisor(lazy, (m) => m.panel.addProactiveBroadcast(shiftMsg));
    }

    const broadcastMsg = getManifestoCreatedBroadcast(payload.fleetManifesto);
    if (broadcastMsg) {
      withAdvisor(lazy, (m) => m.panel.addProactiveBroadcast(broadcastMsg));
    }

    setManifestoContext(payload.fleetManifesto);
  }

  if (payload.colonyName) {
    const colonyMsg = getColonyFoundedBroadcast(payload.colonyName);
    if (colonyMsg) {
      withAdvisor(lazy, (m) => m.panel.addProactiveBroadcast(colonyMsg));
    }
  }

  // Commander's Log: founding entry when both colony name and manifesto are set
  if (payload.colonyName && payload.fleetManifesto && !foundingEntryWritten) {
    foundingEntryWritten = true;
    addAriaLogEntry(
      `Colony "${payload.colonyName}" is established in the Belt. ` +
      `The manifesto reads: "${payload.fleetManifesto}" ` +
      `The work begins.`,
    );
  }

  if (payload.playerNamedAsteroids.length > 0) {
    const christenMsg = getFirstAsteroidChristeningBroadcast();
    if (christenMsg) {
      withAdvisor(lazy, (m) => m.panel.addProactiveBroadcast(christenMsg));
    }
  }
}

export function registerCultureHandlers(ctx: HandlerContext, state: HandlerState): HandlerMap {
  const { refs, renderers, lazy } = ctx;

  return {
    'sim:culture_trait_activated': (msg: WorkerToMainMessage) => {
      const activatedMsg = msg as SimCultureTraitActivatedMessage;
      const trait = activatedMsg.payload.trait;
      const info = TRAIT_METADATA[trait];
      if (info) {
        showNotification(
          `[CULTURE] ${info.name} activated — ${info.effectText}. Press U for details.`,
          info.color,
        );
        showScreenFlash(info.color, 500);
        playSfx('game.research_complete');
        pulseCultureHudButton();
        showHint('first_culture_trait', 'ARIA: Your fleet is developing its own culture. Open the Culture panel (U) to see how their experiences are shaping who they are — and what they can do.');
      }
      const broadcastMsg = getCultureTraitBroadcast(trait);
      if (broadcastMsg) {
        withAdvisor(lazy, (m) => m.panel.addProactiveBroadcast(broadcastMsg));
      }
      if (info) {
        addAriaLogEntry(`[Milestone] Fleet culture trait activated: ${info.name}. ${info.effectText}`);
      }
    },

    'sim:culture_state': (msg: WorkerToMainMessage) => {
      const cultureMsg = msg as SimCultureStateMessage;
      const payload = cultureMsg.payload;

      seedInitialCultureState(ctx, state, payload);
      refs.latestCultureState = payload;
      updateCultureUI(renderers, payload);
      applyFleetColors(renderers, payload);
      updateFactionCulturalDistances(payload.culturalDistances);

      // XENOAWARE: forward predicted anomaly asteroid IDs to the renderer
      renderers.asteroidRenderer.setPredictedAnomalyIds(payload.predictedAnomalyAsteroidIds);
      handleCultureModals(ctx, payload);
      broadcastCultureEvents(lazy, payload);

      if (payload.autonomyScore + payload.fleetCohesion + payload.anomalyExposure + payload.isolationScore > 0) {
        showHint('midgame_culture', 'ARIA: Your robots are developing culture. Press U to observe their emerging identity.');
      }
    },
  };
}
