import * as Sentry from '@sentry/browser';

const FIXED_DT = 1000 / 60; // 16.667ms
let onRenderError: ((err: unknown) => void) | null = null;

export function setRenderErrorHandler(handler: (err: unknown) => void): void {
  onRenderError = handler;
}
const MAX_ACCUMULATOR = 200; // cap to prevent spiral of death
const ROLLING_WINDOW = 60;

export interface GameLoopCallbacks {
  onFixedUpdate: (dt: number) => void;
  onRender: (alpha: number) => void;
}

export interface GameLoopDiagnostics {
  fps: number;
  frameTimeMs: number;
  simTicksThisFrame: number;
  avgFrameTimeMs: number;
  p95FrameTimeMs: number;
  p99FrameTimeMs: number;
}

let running = false;
let paused = false;
let accumulator = 0;
let lastTime = 0;
let rafId = 0;
let callbacks: GameLoopCallbacks | null = null;

// Diagnostics
let frameTimeMs = 0;
let simTicksThisFrame = 0;
const frameTimes: number[] = [];
let frameTimeIndex = 0;
let frameTimeSum = 0;

// Scratch array for percentile computation (avoids allocation in getDiagnostics)
const sortedScratch: number[] = [];

export function getDiagnostics(): GameLoopDiagnostics {
  const n = frameTimes.length;
  const avg = n > 0 ? frameTimeSum / n : 0;

  // Compute p95/p99 from rolling window
  let p95 = 0;
  let p99 = 0;
  if (n >= 2) {
    sortedScratch.length = n;
    for (let i = 0; i < n; i++) sortedScratch[i] = frameTimes[i];
    sortedScratch.sort((a, b) => a - b);
    p95 = sortedScratch[Math.floor(n * 0.95)];
    p99 = sortedScratch[Math.floor(n * 0.99)];
  }

  return {
    fps: avg > 0 ? 1000 / avg : 0,
    frameTimeMs,
    simTicksThisFrame,
    avgFrameTimeMs: avg,
    p95FrameTimeMs: p95,
    p99FrameTimeMs: p99,
  };
}

function tick(time: number): void {
  if (!running) return;
  rafId = requestAnimationFrame(tick);

  if (lastTime === 0) {
    lastTime = time;
    return;
  }

  const elapsed = time - lastTime;
  lastTime = time;
  frameTimeMs = elapsed;

  // Rolling average
  if (frameTimes.length < ROLLING_WINDOW) {
    frameTimes.push(elapsed);
    frameTimeSum += elapsed;
  } else {
    frameTimeSum -= frameTimes[frameTimeIndex];
    frameTimes[frameTimeIndex] = elapsed;
    frameTimeSum += elapsed;
    frameTimeIndex = (frameTimeIndex + 1) % ROLLING_WINDOW;
  }

  if (paused || !callbacks) return;

  accumulator += Math.min(elapsed, MAX_ACCUMULATOR);
  simTicksThisFrame = 0;

  while (accumulator >= FIXED_DT) {
    try {
      callbacks.onFixedUpdate(FIXED_DT / 1000); // pass seconds
    } catch (err) {
      console.error('[gameLoop] onFixedUpdate threw:', err);
      Sentry.captureException(err);
    }
    accumulator -= FIXED_DT;
    simTicksThisFrame++;
  }

  const alpha = accumulator / FIXED_DT;
  try {
    callbacks.onRender(alpha);
  } catch (err) {
    console.error('[gameLoop] onRender threw:', err);
    Sentry.captureException(err);
    if (onRenderError) onRenderError(err);
  }
}

export function start(cbs: GameLoopCallbacks): void {
  callbacks = cbs;
  running = true;
  paused = false;
  accumulator = 0;
  lastTime = 0;
  frameTimes.length = 0;
  frameTimeIndex = 0;
  frameTimeSum = 0;
  rafId = requestAnimationFrame(tick);
}

export function stop(): void {
  running = false;
  paused = false;
  if (rafId) cancelAnimationFrame(rafId);
  rafId = 0;
  callbacks = null;
  accumulator = 0;
  lastTime = 0;
}

export function pause(): void {
  paused = true;
}

export function resume(): void {
  paused = false;
  lastTime = 0;
  accumulator = 0;
}

export function isRunning(): boolean {
  return running;
}

export function isPaused(): boolean {
  return paused;
}
