/**
 * Shared types and mutable state for main-thread message handlers.
 */
import type { WorkerToMainMessage } from '../sim/messages';
import type { RendererHandles } from '../rendererInit';
import type { GameRefs } from '../gameRuntimeState';
import type { LazyPanelHandles, WorkerMessageCallbacks } from '../workerMessages';

/** Dependencies passed to every handler group. */
export interface HandlerContext {
  worker: Worker;
  refs: GameRefs;
  renderers: RendererHandles;
  lazy: LazyPanelHandles;
  cbs: WorkerMessageCallbacks;
}

/** A single message handler keyed by its message type. */
export type MessageHandler = (msg: WorkerToMainMessage) => void;

/** Map of message type → handler function. */
export type HandlerMap = Partial<Record<string, MessageHandler>>;

/**
 * Module-private mutable state shared across handler groups.
 * Reset on sim:loaded to handle save/load correctly.
 */
export interface HandlerState {
  seenEntityIds: Set<number>;
  firstCultureMessage: boolean;
  firstFactionMessage: boolean;
  firstMegastructureMessage: boolean;
  /** Set on sim:loaded; consumed on next sim:frame to seed milestones. */
  needsMilestoneSeed: boolean;
  /** Prevents duplicate first-ore notification within a session. */
  firstOreNotified: boolean;
  /** Previous threat count for detecting new threats. */
  prevThreatCount: number;
}

export function createHandlerState(): HandlerState {
  return {
    seenEntityIds: new Set<number>(),
    firstCultureMessage: true,
    firstFactionMessage: true,
    firstMegastructureMessage: true,
    needsMilestoneSeed: false,
    firstOreNotified: false,
    prevThreatCount: 0,
  };
}
