/**
 * Event log handlers — captures relevant worker messages and feeds them
 * into the game event log panel. Runs as a parallel handler layer
 * (like achievement handlers).
 */
import type { WorkerToMainMessage } from '../sim/messages';
import type {
  SimBuildingBuiltMessage,
  SimRobotProducedMessage,
  SimTechStateMessage,
  SimEventMessage,
  SimLoreFragmentMessage,
  SimNarrativeEventMessage,
  SimCultureTraitActivatedMessage,
  SimTradeWindowEventMessage,
  SimTransientClusterSpawnedMessage,
  SimTransientClusterExpiredMessage,
  SimBaseBuiltMessage,
  SimResearchDeadEndMessage,
} from '../sim/messages';
import type { HandlerMap } from './types';
import { addGameEvent } from '../ui/eventLogPanel';

const BUILDING_NAMES: Record<number, string> = {
  0: 'Robot Factory',
  1: 'Defense Turret',
  2: 'Comm Relay',
};

export function registerEventLogHandlers(): HandlerMap {
  return {
    'sim:building_built': (msg: WorkerToMainMessage) => {
      const { payload } = msg as SimBuildingBuiltMessage;
      if (payload.success) {
        const name = BUILDING_NAMES[payload.buildingType] ?? `Building #${payload.buildingType}`;
        addGameEvent('building', `${name} constructed`, 0);
      }
    },

    'sim:robot_produced': (msg: WorkerToMainMessage) => {
      const { payload } = msg as SimRobotProducedMessage;
      addGameEvent('production', `${payload.robotTypeName} produced`, 0);
    },

    'sim:tech_state': (msg: WorkerToMainMessage) => {
      const { payload } = msg as SimTechStateMessage;
      if (payload.justUnlocked) {
        addGameEvent('research', `Research complete: ${payload.justUnlocked}`, payload.tick);
      }
    },

    'sim:event': (msg: WorkerToMainMessage) => {
      const { payload } = msg as SimEventMessage;
      if (payload.kind === 'anomaly_discovered') {
        addGameEvent('anomaly', `Anomaly discovered on asteroid #${payload.asteroidEid}`, payload.tick);
      }
    },

    'sim:lore_fragment': (msg: WorkerToMainMessage) => {
      const { payload } = msg as SimLoreFragmentMessage;
      if (payload.revelation) {
        addGameEvent('anomaly', 'Anomaly chain revelation unlocked', payload.tick);
      }
    },

    'sim:narrative_event': (msg: WorkerToMainMessage) => {
      const { payload } = msg as SimNarrativeEventMessage;
      const typeLabel = payload.event.type === 'threat' ? 'threat' : 'general';
      const category = payload.event.type === 'threat' ? 'threat' as const : 'general' as const;
      addGameEvent(category, payload.event.title, payload.tick);
    },

    'sim:culture_trait_activated': (msg: WorkerToMainMessage) => {
      const { payload } = msg as SimCultureTraitActivatedMessage;
      addGameEvent('general', `Culture trait activated: ${payload.trait}`, payload.tick);
    },

    'sim:trade_window_event': (msg: WorkerToMainMessage) => {
      const { payload } = msg as SimTradeWindowEventMessage;
      if (payload.type === 'opened') {
        addGameEvent('faction', `Trade window opened with ${payload.factionName}`, payload.tick);
      } else if (payload.type === 'expired') {
        addGameEvent('faction', `Trade window with ${payload.factionName} expired`, payload.tick);
      }
    },

    'sim:transient_cluster_spawned': (msg: WorkerToMainMessage) => {
      const { payload } = msg as SimTransientClusterSpawnedMessage;
      addGameEvent('resource', `Rich asteroid cluster appeared (${payload.asteroidCount} asteroids)`, payload.tick);
    },

    'sim:transient_cluster_expired': (msg: WorkerToMainMessage) => {
      const { payload } = msg as SimTransientClusterExpiredMessage;
      if (payload.capturingFactionName) {
        addGameEvent('faction', `Cluster captured by ${payload.capturingFactionName}`, payload.tick);
      } else {
        addGameEvent('resource', 'Transient cluster dispersed', payload.tick);
      }
    },

    'sim:base_built': (msg: WorkerToMainMessage) => {
      const { payload } = msg as SimBaseBuiltMessage;
      if (payload.ok) {
        addGameEvent('building', 'New base station established', 0);
      }
    },

    'sim:research_dead_end': (msg: WorkerToMainMessage) => {
      const { payload } = msg as SimResearchDeadEndMessage;
      addGameEvent('research', `Research dead end: ${payload.nodeId}`, 0);
    },
  };
}
