/**
 * Entity Renderer
 *
 * Renders ancient entities:
 * - Drifters: massive translucent spheres with vertex displacement and heavy bloom
 * - Resonants: instanced crystalline icosahedra with pulsing emissive
 */

import {
  DoubleSide,
  DynamicDrawUsage,
  Group,
  IcosahedronGeometry,
  InstancedMesh,
  Material,
  Mesh,
  MeshStandardMaterial,
  Object3D,
  OctahedronGeometry,
  RingGeometry,
  Scene,
  SphereGeometry,
  TorusGeometry,
} from 'three';
import type { EntityState } from '../shared/entityTypes';
import { ENTITY_TYPES } from '../shared/entityTypes';

// ── Drifter renderer ──────────────────────────────────────────────────────────

class DrifterMesh {
  readonly id: number;
  private group: Group;
  private outerSphere: Mesh;
  private innerSphere: Mesh;
  private coronaRing: Mesh;

  constructor(scene: Scene, entity: EntityState) {
    this.id = entity.id;
    this.group = new Group();

    // Outer shell: large translucent sphere
    const outerGeo = new SphereGeometry(entity.radius, 32, 24);
    const outerMat = new MeshStandardMaterial({
      color: 0x8866ff,
      emissive: 0x4422aa,
      emissiveIntensity: 0.4,
      transparent: true,
      opacity: 0.12,
      side: DoubleSide,
      depthWrite: false,
    });
    this.outerSphere = new Mesh(outerGeo, outerMat);
    this.group.add(this.outerSphere);

    // Inner core: brighter, denser
    const innerGeo = new SphereGeometry(entity.radius * 0.3, 24, 16);
    const innerMat = new MeshStandardMaterial({
      color: 0xccaaff,
      emissive: 0x9966ff,
      emissiveIntensity: 1.2,
      transparent: true,
      opacity: 0.35,
      depthWrite: false,
    });
    this.innerSphere = new Mesh(innerGeo, innerMat);
    this.group.add(this.innerSphere);

    // Corona ring — a faint torus orbiting the entity
    const coronaGeo = new TorusGeometry(entity.radius * 0.7, entity.radius * 0.04, 8, 64);
    const coronaMat = new MeshStandardMaterial({
      color: 0xaabbff,
      emissive: 0x6688ff,
      emissiveIntensity: 0.8,
      transparent: true,
      opacity: 0.5,
      depthWrite: false,
    });
    this.coronaRing = new Mesh(coronaGeo, coronaMat);
    this.coronaRing.rotation.x = Math.PI * 0.3;
    this.group.add(this.coronaRing);

    this.group.position.set(entity.x, entity.y, entity.z);
    scene.add(this.group);
  }

  update(entity: EntityState): void {
    this.group.position.set(entity.x, entity.y, entity.z);

    // Slow rotation
    this.outerSphere.rotation.y += 0.001;
    this.outerSphere.rotation.x += 0.0005;
    this.innerSphere.rotation.y -= 0.002;
    this.coronaRing.rotation.z += 0.003;

    // Pulse opacity and emissive intensity
    const pulse = 0.5 + 0.5 * Math.sin(entity.phase);
    (this.outerSphere.material as MeshStandardMaterial).opacity = 0.08 + 0.06 * pulse;
    (this.innerSphere.material as MeshStandardMaterial).emissiveIntensity = 0.8 + 0.6 * pulse;
    (this.coronaRing.material as MeshStandardMaterial).opacity = 0.35 + 0.2 * pulse;
  }

  dispose(scene: Scene): void {
    scene.remove(this.group);
    this.outerSphere.geometry.dispose();
    (this.outerSphere.material as Material).dispose();
    this.innerSphere.geometry.dispose();
    (this.innerSphere.material as Material).dispose();
    this.coronaRing.geometry.dispose();
    (this.coronaRing.material as Material).dispose();
  }
}

// ── Alien Fleet renderer ──────────────────────────────────────────────────────

class AlienFleetMesh {
  readonly id: number;
  private group: Group;
  private hull: Mesh;
  private innerGlow: Mesh;
  private ring: Mesh;

  constructor(scene: Scene, entity: EntityState) {
    this.id = entity.id;
    this.group = new Group();

    // Dark geometric hull — large octahedron with emissive edges
    const hullGeo = new OctahedronGeometry(entity.radius, 1);
    const hullMat = new MeshStandardMaterial({
      color: 0x111122,
      emissive: 0x3344aa,
      emissiveIntensity: 0.6,
      transparent: true,
      opacity: 0.25,
      wireframe: true,
      depthWrite: false,
    });
    this.hull = new Mesh(hullGeo, hullMat);
    this.group.add(this.hull);

    // Inner glow core — smaller, brighter
    const innerGeo = new OctahedronGeometry(entity.radius * 0.35, 0);
    const innerMat = new MeshStandardMaterial({
      color: 0x4466ff,
      emissive: 0x2244cc,
      emissiveIntensity: 1.5,
      transparent: true,
      opacity: 0.4,
      depthWrite: false,
    });
    this.innerGlow = new Mesh(innerGeo, innerMat);
    this.group.add(this.innerGlow);

    // Horizontal scanning ring
    const ringGeo = new RingGeometry(entity.radius * 0.6, entity.radius * 0.65, 64);
    const ringMat = new MeshStandardMaterial({
      color: 0x6688ff,
      emissive: 0x4466dd,
      emissiveIntensity: 1.0,
      transparent: true,
      opacity: 0.5,
      side: DoubleSide,
      depthWrite: false,
    });
    this.ring = new Mesh(ringGeo, ringMat);
    this.ring.rotation.x = Math.PI * 0.5;
    this.group.add(this.ring);

    this.group.position.set(entity.x, entity.y, entity.z);
    scene.add(this.group);
  }

  update(entity: EntityState): void {
    this.group.position.set(entity.x, entity.y, entity.z);

    // Slow, deliberate rotation
    this.hull.rotation.y += 0.0008;
    this.hull.rotation.x += 0.0003;
    this.innerGlow.rotation.y -= 0.0015;
    this.innerGlow.rotation.z += 0.001;
    this.ring.rotation.z += 0.002;

    // Pulse — slower than drifters, more deliberate
    const pulse = 0.5 + 0.5 * Math.sin(entity.phase);
    (this.hull.material as MeshStandardMaterial).emissiveIntensity = 0.4 + 0.4 * pulse;
    (this.innerGlow.material as MeshStandardMaterial).emissiveIntensity = 1.0 + 1.0 * pulse;
    (this.ring.material as MeshStandardMaterial).opacity = 0.3 + 0.3 * pulse;
  }

  dispose(scene: Scene): void {
    scene.remove(this.group);
    this.hull.geometry.dispose();
    (this.hull.material as Material).dispose();
    this.innerGlow.geometry.dispose();
    (this.innerGlow.material as Material).dispose();
    this.ring.geometry.dispose();
    (this.ring.material as Material).dispose();
  }
}

// ── Resonant renderer (instanced) ─────────────────────────────────────────────

const MAX_RESONANTS = 64;

class ResonantInstancedMesh {
  private mesh: InstancedMesh;
  private scene: Scene;

  constructor(scene: Scene) {
    this.scene = scene;
    const geo = new IcosahedronGeometry(1, 1);
    const mat = new MeshStandardMaterial({
      color: 0x44ffcc,
      emissive: 0x00ffaa,
      emissiveIntensity: 1.5,
      transparent: true,
      opacity: 0.75,
      wireframe: false,
      depthWrite: false,
    });
    this.mesh = new InstancedMesh(geo, mat, MAX_RESONANTS);
    this.mesh.count = 0;
    this.mesh.instanceMatrix.setUsage(DynamicDrawUsage);
    scene.add(this.mesh);
  }

  update(entities: EntityState[]): void {
    const dummy = new Object3D();
    let idx = 0;

    for (const e of entities) {
      if (e.type !== ENTITY_TYPES.RESONANT) continue;
      if (idx >= MAX_RESONANTS) break;

      const pulse = 0.5 + 0.5 * Math.sin(e.phase);
      const scale = e.radius * (0.8 + 0.4 * pulse);

      dummy.position.set(e.x, e.y, e.z);
      dummy.rotation.set(e.phase * 0.3, e.phase * 0.7, e.phase * 0.5);
      dummy.scale.setScalar(scale);
      dummy.updateMatrix();
      this.mesh.setMatrixAt(idx, dummy.matrix);
      idx++;
    }

    this.mesh.count = idx;
    this.mesh.instanceMatrix.needsUpdate = true;

    // Pulse emissive intensity
    const avgPhase =
      entities
        .filter((e) => e.type === ENTITY_TYPES.RESONANT)
        .reduce((acc, e) => acc + e.phase, 0) / Math.max(1, idx);
    (this.mesh.material as MeshStandardMaterial).emissiveIntensity = 1.2 + 0.8 * Math.sin(avgPhase);
  }

  dispose(): void {
    this.scene.remove(this.mesh);
    this.mesh.geometry.dispose();
    (this.mesh.material as Material).dispose();
  }
}

// ── EntityRenderer (main export) ─────────────────────────────────────────────

export class EntityRenderer {
  private scene: Scene;
  private drifters: Map<number, DrifterMesh> = new Map();
  private alienFleets: Map<number, AlienFleetMesh> = new Map();
  private resonants: ResonantInstancedMesh;

  // Visual interference effects
  private interferenceOverlay: HTMLDivElement | null = null;

  constructor(scene: Scene) {
    this.scene = scene;
    this.resonants = new ResonantInstancedMesh(scene);
  }

  update(
    entities: EntityState[],
    drifterProximity: boolean,
    resonantInterference: boolean,
    _time: number,
    alienFleetProximity = false,
  ): void {
    const liveIds = new Set(entities.map((e) => e.id));

    // Remove drifter meshes that no longer exist
    for (const [id, mesh] of this.drifters) {
      if (!liveIds.has(id)) {
        mesh.dispose(this.scene);
        this.drifters.delete(id);
      }
    }

    // Remove alien fleet meshes that no longer exist
    for (const [id, mesh] of this.alienFleets) {
      if (!liveIds.has(id)) {
        mesh.dispose(this.scene);
        this.alienFleets.delete(id);
      }
    }

    // Update/create drifter meshes
    for (const entity of entities) {
      if (entity.type === ENTITY_TYPES.DRIFTER) {
        if (!this.drifters.has(entity.id)) {
          this.drifters.set(entity.id, new DrifterMesh(this.scene, entity));
        }
        this.drifters.get(entity.id)!.update(entity);
      } else if (entity.type === ENTITY_TYPES.ALIEN_FLEET) {
        if (!this.alienFleets.has(entity.id)) {
          this.alienFleets.set(entity.id, new AlienFleetMesh(this.scene, entity));
        }
        this.alienFleets.get(entity.id)!.update(entity);
      }
    }

    // Update resonants (instanced)
    this.resonants.update(entities);

    // Interference visual overlay
    this.updateInterferenceOverlay(drifterProximity, resonantInterference, alienFleetProximity);
  }

  private updateInterferenceOverlay(
    drifterProximity: boolean,
    resonantInterference: boolean,
    alienFleetProximity: boolean,
  ): void {
    const active = drifterProximity || resonantInterference || alienFleetProximity;
    if (!active) {
      if (this.interferenceOverlay) {
        this.interferenceOverlay.style.opacity = '0';
      }
      return;
    }

    if (!this.interferenceOverlay) {
      this.interferenceOverlay = document.createElement('div');
      this.interferenceOverlay.style.cssText = `
        position: fixed;
        inset: 0;
        pointer-events: none;
        z-index: 50;
        transition: opacity 2s ease;
        opacity: 0;
      `;
      document.body.appendChild(this.interferenceOverlay);
    }

    // Alien fleet takes priority — strongest visual effect
    if (alienFleetProximity) {
      this.interferenceOverlay.style.background = 'rgba(40, 60, 200, 0.08)';
      this.interferenceOverlay.style.boxShadow = 'inset 0 0 150px rgba(50, 70, 220, 0.20)';
    } else if (drifterProximity) {
      this.interferenceOverlay.style.background = 'rgba(120, 80, 255, 0.06)';
      this.interferenceOverlay.style.boxShadow = 'inset 0 0 120px rgba(120, 80, 255, 0.15)';
    } else {
      this.interferenceOverlay.style.background = 'rgba(0, 255, 170, 0.04)';
      this.interferenceOverlay.style.boxShadow = 'inset 0 0 80px rgba(0, 255, 170, 0.10)';
    }
    this.interferenceOverlay.style.opacity = '1';
  }

  dispose(): void {
    for (const [, mesh] of this.drifters) {
      mesh.dispose(this.scene);
    }
    this.drifters.clear();
    for (const [, mesh] of this.alienFleets) {
      mesh.dispose(this.scene);
    }
    this.alienFleets.clear();
    this.resonants.dispose();
    this.interferenceOverlay?.remove();
  }
}
