/**
 * Commander Inbox Processing — LLM-powered triage, analysis, and response.
 *
 * The Commander scans incoming messages, classifies them (spam/relevant/urgent),
 * analyzes top-priority items, and produces a human-readable summary for the player.
 */

import type { InboxMessage, InboxSnapshot } from '../sim/inbox/inboxTypes';
import { createToolProvider } from './providers';
import type { IToolProvider, ToolUseResponse } from './providers';
import {
  recordUsage,
  isOverBudget,
  isSessionOverBudget,
  recordSessionUsage,
  estimateInputTokens,
  estimateOutputTokens,
} from './usage';
import { determineFallbackTier } from './fallbackChain';

// ── Types ────────────────────────────────────────────────────────────────────

export interface TriageResult {
  messageId: number;
  triageResult: 'relevant' | 'spam' | 'urgent';
  summary?: string;
  recommendedAction?: string;
}

export interface InboxProcessingResult {
  /** Commander's summary for the player */
  summary: string;
  /** Per-message triage results */
  triageResults: TriageResult[];
  /** How many messages were analyzed */
  analyzedCount: number;
  /** Error message if processing failed */
  error?: string;
}

// ── State ────────────────────────────────────────────────────────────────────

let apiKey: string | null = null;

export function setInboxApiKey(key: string | null): void {
  apiKey = key;
}

// ── Tool definitions for inbox triage ────────────────────────────────────────

const INBOX_TOOLS = [
  {
    name: 'classify_message',
    description: 'Classify an inbox message as spam, relevant, or urgent. Call this for each message you triage.',
    input_schema: {
      type: 'object',
      properties: {
        message_id: { type: 'number', description: 'ID of the message being classified' },
        classification: { type: 'string', enum: ['spam', 'relevant', 'urgent'], description: 'Classification result' },
        summary: { type: 'string', description: 'One-sentence summary of the message content' },
        recommended_action: { type: 'string', description: 'What the player should do (e.g. "Accept trade", "Ignore", "Respond diplomatically"). Optional.' },
      },
      required: ['message_id', 'classification'],
    },
  },
];

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Process inbox messages using the Commander LLM.
 * Triages all untriaged messages and returns a summary.
 */
export async function processInbox(
  snapshot: InboxSnapshot,
): Promise<InboxProcessingResult> {
  const untriaged = snapshot.messages.filter((m) => !m.triaged);

  if (untriaged.length === 0) {
    return {
      summary: 'No new messages to process.',
      triageResults: [],
      analyzedCount: 0,
    };
  }

  // Use formalized fallback chain
  const tier = determineFallbackTier(!!apiKey, isOverBudget() || isSessionOverBudget(), false);

  if (tier !== 'all_clear') {
    return offlineTriage(untriaged);
  }

  const provider = createToolProvider('anthropic', apiKey!);
  if (!provider) {
    return offlineTriage(untriaged);
  }

  try {
    return await llmTriage(provider, untriaged);
  } catch (err) {
    console.warn('[CommanderInbox] LLM triage failed, using offline fallback:', err);
    return offlineTriage(untriaged);
  }
}

// ── LLM triage ──────────────────────────────────────────────────────────────

async function llmTriage(
  provider: IToolProvider,
  messages: InboxMessage[],
): Promise<InboxProcessingResult> {
  // Cap at 20 messages per LLM call to control token usage
  const batch = messages.slice(0, 20);
  const messageList = batch
    .map((m) => `[ID:${m.id}] FROM: ${m.senderName} | TYPE: ${m.type} | SUBJECT: ${m.subject}\n${m.body}`)
    .join('\n\n---\n\n');

  const system = INBOX_SYSTEM_PROMPT;
  const query = `Here are ${batch.length} new messages to triage:\n\n${messageList}\n\nClassify each message using the classify_message tool, then provide a brief summary of what needs my attention.`;

  let response: ToolUseResponse = await provider.sendWithTools(
    system,
    query,
    INBOX_TOOLS,
    1024,
  );

  trackUsage(system + query, response.text);

  const triageResults: TriageResult[] = [];
  let summary = response.text || '';

  // Process tool calls (up to 2 rounds)
  let round = 0;
  while (response.stopReason === 'tool_use' && response.toolCalls.length > 0 && round < 2) {
    round++;

    const toolResults = [];
    for (const call of response.toolCalls) {
      if (call.name === 'classify_message') {
        const input = call.input as {
          message_id: number;
          classification: 'spam' | 'relevant' | 'urgent';
          summary?: string;
          recommended_action?: string;
        };
        triageResults.push({
          messageId: input.message_id,
          triageResult: input.classification,
          summary: input.summary,
          recommendedAction: input.recommended_action,
        });
        toolResults.push({
          type: 'tool_result' as const,
          tool_use_id: call.id,
          content: `Message ${input.message_id} classified as ${input.classification}.`,
          is_error: false,
        });
      }
    }

    const assistantContent: Array<{ type: 'text' | 'tool_use'; text?: string; id?: string; name?: string; input?: Record<string, unknown> }> = [];
    if (response.text) assistantContent.push({ type: 'text', text: response.text });
    for (const call of response.toolCalls) {
      assistantContent.push({ type: 'tool_use', id: call.id, name: call.name, input: call.input });
    }

    response = await provider.continueWithToolResults(
      system,
      [
        { role: 'user', content: query },
        { role: 'assistant', content: assistantContent },
        { role: 'user', content: toolResults },
      ],
      INBOX_TOOLS,
      512,
    );

    trackUsage('', response.text);
    if (response.text) {
      summary += (summary ? '\n\n' : '') + response.text;
    }
  }

  // If no summary was generated, create one from results
  if (!summary) {
    const urgent = triageResults.filter((r) => r.triageResult === 'urgent').length;
    const relevant = triageResults.filter((r) => r.triageResult === 'relevant').length;
    const spam = triageResults.filter((r) => r.triageResult === 'spam').length;
    summary = `Inbox processed: ${urgent} urgent, ${relevant} relevant, ${spam} spam out of ${batch.length} messages.`;
  }

  return {
    summary,
    triageResults,
    analyzedCount: batch.length,
  };
}

// ── Offline fallback triage ──────────────────────────────────────────────────

function offlineTriage(messages: InboxMessage[]): InboxProcessingResult {
  const results: TriageResult[] = [];

  for (const msg of messages) {
    let classification: 'spam' | 'relevant' | 'urgent';

    if (msg.type === 'spam') {
      classification = 'spam';
    } else if (msg.type === 'distress' || msg.priority === 'urgent') {
      classification = 'urgent';
    } else {
      classification = 'relevant';
    }

    results.push({
      messageId: msg.id,
      triageResult: classification,
      summary: `${msg.type} from ${msg.senderName}: ${msg.subject}`,
    });
  }

  const urgent = results.filter((r) => r.triageResult === 'urgent').length;
  const relevant = results.filter((r) => r.triageResult === 'relevant').length;
  const spam = results.filter((r) => r.triageResult === 'spam').length;

  return {
    summary: `Offline triage: ${urgent} urgent, ${relevant} relevant, ${spam} spam from ${messages.length} messages.`,
    triageResults: results,
    analyzedCount: messages.length,
  };
}

// ── System prompt ────────────────────────────────────────────────────────────

const INBOX_SYSTEM_PROMPT = `You are ARIA, Commander of a deep-space mining operation. You are triaging your inbox — faction communications, trade proposals, intelligence reports, and spam.

RULES:
- Classify each message using the classify_message tool
- "spam" = junk, scams, phishing, automated broker messages
- "relevant" = legitimate faction communication worth reviewing
- "urgent" = requires immediate player attention (threats, time-limited opportunities, critical intelligence)
- Watch for hidden clauses in trade offers and contracts
- Summarize concisely — the player is busy
- After classifying all messages, provide a 2-3 sentence brief of what needs attention`;

function trackUsage(input: string, output: string): void {
  if (input || output) {
    const inTok = estimateInputTokens(input);
    const outTok = estimateOutputTokens(output);
    recordUsage('anthropic', 'claude-sonnet-4-20250514', inTok, outTok);
    recordSessionUsage(inTok, outTok);
  }
}
