/**
 * Window Manager — z-index stacking and drag support for floating panels.
 *
 * Usage:
 *   registerWindow('my-panel', el)  — call when panel is first shown
 *   unregisterWindow('my-panel')    — call when panel is removed from DOM
 *   makeDraggable(el)               — add drag-by-header behavior
 *
 * All registered windows share a z-index stack starting at BASE_Z.
 * Clicking any window brings it to the front.
 */

const BASE_Z = 200;
const Z_STEP = 10;

const stack: Array<{ id: string; el: HTMLElement; bringToFrontHandler: () => void }> = [];

function restack(): void {
  stack.forEach((w, i) => {
    w.el.style.zIndex = String(BASE_Z + i * Z_STEP);
  });
}

export function registerWindow(id: string, el: HTMLElement): void {
  const existing = stack.findIndex((w) => w.id === id);
  if (existing >= 0) {
    const old = stack[existing];
    old.el.removeEventListener('mousedown', old.bringToFrontHandler, { capture: true });
    stack.splice(existing, 1);
  }
  const bringToFrontHandler = () => bringToFront(id);
  stack.push({ id, el, bringToFrontHandler });
  restack();
  el.addEventListener('mousedown', bringToFrontHandler, { capture: true });
}

export function unregisterWindow(id: string): void {
  const idx = stack.findIndex((w) => w.id === id);
  if (idx >= 0) {
    const entry = stack[idx];
    entry.el.removeEventListener('mousedown', entry.bringToFrontHandler, { capture: true });
    stack.splice(idx, 1);
  }
  restack();
}

export function bringToFront(id: string): void {
  const idx = stack.findIndex((w) => w.id === id);
  if (idx >= 0 && idx < stack.length - 1) {
    const [item] = stack.splice(idx, 1);
    stack.push(item);
    restack();
  }
}

/**
 * Make a panel draggable by its `.win-drag-handle` child element.
 * Buttons, inputs, and selects inside the handle are excluded from drag.
 * Clamps position to the viewport bounds.
 *
 * Call once after the panel element is created. The drag listener is on the
 * panel itself (event delegation), so it survives innerHTML replacement.
 */
export function makeDraggable(el: HTMLElement): void {
  let startX = 0;
  let startY = 0;
  let startLeft = 0;
  let startTop = 0;
  let cachedW = 0;
  let cachedH = 0;
  let rafId = 0;
  let lastMoveX = 0;
  let lastMoveY = 0;

  el.addEventListener('mousedown', (e: MouseEvent) => {
    const target = e.target as HTMLElement;

    // Only drag via the designated drag handle area
    if (!target.closest('.win-drag-handle')) return;
    // Don't drag when clicking interactive children
    if (
      target.tagName === 'BUTTON' ||
      target.tagName === 'INPUT' ||
      target.tagName === 'SELECT'
    )
      return;

    e.preventDefault();

    // Resolve current position to absolute px coords, clearing any CSS centering transform
    const rect = el.getBoundingClientRect();
    startX = e.clientX;
    startY = e.clientY;
    startLeft = rect.left;
    startTop = rect.top;

    // Cache dimensions once at drag start to avoid forced reflow every mousemove
    cachedW = el.offsetWidth;
    cachedH = el.offsetHeight;

    el.style.transform = 'none';
    el.style.left = `${startLeft}px`;
    el.style.top = `${startTop}px`;
    el.style.right = 'auto';
    el.style.bottom = 'auto';

    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  });

  function onMove(e: MouseEvent): void {
    lastMoveX = e.clientX;
    lastMoveY = e.clientY;
    if (!rafId) {
      rafId = requestAnimationFrame(applyMove);
    }
  }

  function applyMove(): void {
    rafId = 0;
    const dx = lastMoveX - startX;
    const dy = lastMoveY - startY;
    const newLeft = Math.max(0, Math.min(window.innerWidth - cachedW, startLeft + dx));
    const newTop = Math.max(0, Math.min(window.innerHeight - cachedH, startTop + dy));
    el.style.left = `${newLeft}px`;
    el.style.top = `${newTop}px`;
  }

  function onUp(): void {
    document.removeEventListener('mousemove', onMove);
    document.removeEventListener('mouseup', onUp);
    if (rafId) {
      cancelAnimationFrame(rafId);
      rafId = 0;
    }
  }
}
