/**
 * ARIA Away-Events — accumulates game events while the player's tab is hidden,
 * then posts an ARIA inbox summary when the player returns.
 *
 * No LLM calls — all summaries are deterministic heuristics.
 */

import type { MainToWorkerMessage } from '../sim/messages';
import type { InboxMessage } from '../sim/inbox/inboxTypes';

// ── Types ────────────────────────────────────────────────────────────────────

export interface AwayEvent {
  type: 'research_complete' | 'building_built' | 'robot_built';
  name: string;
  timestamp: number;
}

// ── State ────────────────────────────────────────────────────────────────────

let away = false;
const pendingEvents: AwayEvent[] = [];

let workerSendFn: ((msg: MainToWorkerMessage) => void) | null = null;
let nextAwayMsgId = 20_000_000;

// ── Public API ───────────────────────────────────────────────────────────────

export function setAwaySendFn(fn: (msg: MainToWorkerMessage) => void): void {
  workerSendFn = fn;
}

/** Returns true when the player's tab is hidden. */
export function isAway(): boolean {
  return away;
}

/** Record an event that occurred while the player is away. */
export function recordAwayEvent(event: AwayEvent): void {
  pendingEvents.push(event);
}

/** Start listening for tab visibility changes. */
export function startAwayTracking(): void {
  if (typeof document !== 'undefined') {
    document.addEventListener('visibilitychange', handleVisibilityChange);
  }
}

/** Stop listening and clear state. */
export function stopAwayTracking(): void {
  if (typeof document !== 'undefined') {
    document.removeEventListener('visibilitychange', handleVisibilityChange);
  }
  away = false;
  pendingEvents.length = 0;
}

/** Reset all state (for tests). */
export function resetAwayEvents(): void {
  stopAwayTracking();
  workerSendFn = null;
  nextAwayMsgId = 20_000_000;
}

/** Simulate the player going away (for tests). */
export function setAwayForTest(value: boolean): void {
  if (!value && away && pendingEvents.length > 0) {
    flushAwayEvents();
  }
  away = value;
}

// ── Internal ─────────────────────────────────────────────────────────────────

function handleVisibilityChange(): void {
  if (document.hidden) {
    away = true;
  } else {
    if (away && pendingEvents.length > 0) {
      flushAwayEvents();
    }
    away = false;
  }
}

function flushAwayEvents(): void {
  const summary = buildSummary(pendingEvents);
  pendingEvents.length = 0;

  if (!workerSendFn || !summary) return;

  const msg: InboxMessage = {
    id: nextAwayMsgId++,
    factionId: null,
    senderName: 'ARIA',
    type: 'aria_auto',
    subject: '[Welcome Back] Operations Summary',
    body: summary,
    priority: 'normal',
    tick: 0,
    triaged: true,
    triageResult: 'relevant',
    read: false,
  };

  workerSendFn({
    type: 'sim:inbox_inject',
    payload: { message: msg },
  });
}

function buildSummary(events: AwayEvent[]): string | null {
  if (events.length === 0) return null;

  const research: string[] = [];
  const buildings: string[] = [];
  const robots: string[] = [];

  for (const e of events) {
    switch (e.type) {
      case 'research_complete':
        research.push(e.name);
        break;
      case 'building_built':
        buildings.push(e.name);
        break;
      case 'robot_built':
        robots.push(e.name);
        break;
    }
  }

  const lines: string[] = [
    'Commander, while you were away your operation continued autonomously. Here is what happened:',
    '',
  ];

  if (research.length > 0) {
    lines.push(`Research completed: ${research.join(', ')}.`);
  }
  if (buildings.length > 0) {
    const counts = countNames(buildings);
    const parts = Object.entries(counts).map(([name, count]) =>
      count > 1 ? `${count}x ${name}` : name,
    );
    lines.push(`Construction completed: ${parts.join(', ')}.`);
  }
  if (robots.length > 0) {
    const counts = countNames(robots);
    const parts = Object.entries(counts).map(([name, count]) =>
      count > 1 ? `${count}x ${name}` : name,
    );
    lines.push(`Robots produced: ${parts.join(', ')}.`);
  }

  lines.push('', 'All systems nominal. Awaiting your orders.');

  return lines.join('\n');
}

function countNames(names: string[]): Record<string, number> {
  const counts: Record<string, number> = {};
  for (const n of names) {
    counts[n] = (counts[n] ?? 0) + 1;
  }
  return counts;
}
