import {
  BoxGeometry,
  Color,
  InstancedMesh,
  Material,
  MeshStandardMaterial,
  Object3D,
  OctahedronGeometry,
  Scene,
  Sphere,
  Vector3,
} from 'three';
import {
  getRobotEid,
  getRobotX,
  getRobotY,
  getRobotZ,
  getRobotRotation,
  getRobotType,
  getRobotState,
  getRobotEnergyPct,
} from '../sim/bufferLayout';
import { getFleetColorPalette } from '../shared/fleetColors';

// Default robot type visuals (used when no fleet color palette is active)
const DEFAULT_ROBOT_COLORS: Record<number, Color> = {
  0: new Color(0.2, 0.8, 0.3), // Scout - green
  1: new Color(0.9, 0.6, 0.1), // Miner - orange
  2: new Color(0.3, 0.5, 0.9), // Hauler - blue
};

// Hue offsets per robot type to keep them distinguishable within a palette
const TYPE_HUE_OFFSETS: Record<number, number> = {
  0: -0.05, // Scout - slightly shifted left
  1: 0.0,   // Miner - palette primary as-is
  2: 0.05,  // Hauler - slightly shifted right
};

const MAX_ROBOTS = 500;

export class RobotRenderer {
  private scene: Scene;
  private meshes: Map<number, InstancedMesh> = new Map();
  private dummy = new Object3D();
  private counts: Map<number, number> = new Map();
  // Maps (type → instance slot → EID) for robot picking
  private instanceEids: Map<number, number[]> = new Map();
  // Active per-type colors (palette-derived or defaults)
  private activeColors: Record<number, Color> = {
    0: DEFAULT_ROBOT_COLORS[0].clone(),
    1: DEFAULT_ROBOT_COLORS[1].clone(),
    2: DEFAULT_ROBOT_COLORS[2].clone(),
  };
  private currentPaletteId: string | null = null;
  // Pre-allocated Color objects to avoid per-frame GC pressure
  private readonly brokenColor = new Color(1, 0.1, 0.1);
  private readonly tempColor = new Color();

  constructor(scene: Scene) {
    this.scene = scene;
    this.createMeshes();
  }

  private createMeshes(): void {
    // Scout: small octahedron
    const scoutGeo = new OctahedronGeometry(3, 0);
    // Miner: box shape
    const minerGeo = new BoxGeometry(5, 3, 5);
    // Hauler: larger box
    const haulerGeo = new BoxGeometry(7, 4, 9);

    const geos = [scoutGeo, minerGeo, haulerGeo];

    for (let type = 0; type < 3; type++) {
      const color = DEFAULT_ROBOT_COLORS[type] || new Color(1, 1, 1);
      const mat = new MeshStandardMaterial({
        color,
        emissive: color.clone().multiplyScalar(0.3),
        emissiveIntensity: 0.3,
        metalness: 0.6,
        roughness: 0.3,
      });

      const mesh = new InstancedMesh(geos[type], mat, MAX_ROBOTS);
      mesh.count = 0;
      mesh.frustumCulled = false;
      // Set a large bounding sphere so InstancedMesh.raycast() doesn't
      // skip per-instance checks when instances are far from origin.
      mesh.boundingSphere = new Sphere(new Vector3(0, 0, 0), 1e6);
      this.scene.add(mesh);
      this.meshes.set(type, mesh);
    }
  }

  /**
   * Update robot visuals from simulation buffer.
   * robotBuffer: Float32Array with stride ROBOT_STRIDE: [eid, x, y, z, rotation, typeEnum, stateEnum, energyPct]
   */
  updateFromBuffer(robotBuffer: Float32Array, robotCount: number): void {
    // Reset counts and EID maps
    for (const [type] of this.meshes) {
      this.counts.set(type, 0);
      this.instanceEids.set(type, []);
    }

    for (let i = 0; i < robotCount; i++) {
      const eid = getRobotEid(robotBuffer, i);
      const x = getRobotX(robotBuffer, i);
      const y = getRobotY(robotBuffer, i);
      const z = getRobotZ(robotBuffer, i);
      const rotation = getRobotRotation(robotBuffer, i);
      const type = getRobotType(robotBuffer, i);
      const state = getRobotState(robotBuffer, i);
      const _energyPct = getRobotEnergyPct(robotBuffer, i);

      const mesh = this.meshes.get(type);
      if (!mesh) continue;

      const count = this.counts.get(type) || 0;
      if (count >= MAX_ROBOTS) continue;

      this.dummy.position.set(x, y, z);
      this.dummy.rotation.set(0, rotation, 0);
      this.dummy.updateMatrix();
      mesh.setMatrixAt(count, this.dummy.matrix);

      // Track EID for this instance slot
      const eids = this.instanceEids.get(type)!;
      eids[count] = eid;

      // Color based on state — reuse pre-allocated Color objects
      const baseColor = this.activeColors[type] || this.tempColor.set(1, 1, 1);
      if (state === 6) {
        // Broken - red
        mesh.setColorAt(count, this.brokenColor);
      } else if (state === 5) {
        // Charging - dim (reuse tempColor to avoid allocation)
        this.tempColor.copy(baseColor).multiplyScalar(0.5);
        mesh.setColorAt(count, this.tempColor);
      } else {
        mesh.setColorAt(count, baseColor);
      }

      this.counts.set(type, count + 1);
    }

    // Update mesh instance counts
    for (const [type, mesh] of this.meshes) {
      const count = this.counts.get(type) || 0;
      mesh.count = count;
      if (count > 0) {
        mesh.instanceMatrix.needsUpdate = true;
        if (mesh.instanceColor) mesh.instanceColor.needsUpdate = true;
      }
    }
  }

  /** Expose meshes for raycasting robot picking. */
  getMeshes(): ReadonlyMap<number, InstancedMesh> {
    return this.meshes;
  }

  /** Get the EID of the robot at the given instance slot for robot type. Returns -1 if not found. */
  getInstanceEid(type: number, instanceId: number): number {
    return this.instanceEids.get(type)?.[instanceId] ?? -1;
  }

  /**
   * Apply fleet color palette to robot type colors. Pass null to revert to defaults.
   * Recalculates per-type colors from the palette's primary with hue offsets.
   */
  setFleetColor(paletteId: string | null): void {
    if (paletteId === this.currentPaletteId) return;
    this.currentPaletteId = paletteId;

    if (!paletteId) {
      // Revert to defaults
      for (let type = 0; type < 3; type++) {
        this.activeColors[type].copy(DEFAULT_ROBOT_COLORS[type]);
      }
    } else {
      const palette = getFleetColorPalette(paletteId);
      if (!palette) return;

      const base = new Color(palette.primary);
      const hsl = { h: 0, s: 0, l: 0 };
      base.getHSL(hsl);

      for (let type = 0; type < 3; type++) {
        const hue = (hsl.h + (TYPE_HUE_OFFSETS[type] || 0) + 1) % 1;
        this.activeColors[type].setHSL(hue, hsl.s, hsl.l);
      }
    }

    // Update material base colors on the instanced meshes
    for (let type = 0; type < 3; type++) {
      const mesh = this.meshes.get(type);
      if (!mesh) continue;
      const mat = mesh.material as MeshStandardMaterial;
      mat.color.copy(this.activeColors[type]);
      mat.emissive.copy(this.activeColors[type]).multiplyScalar(0.3);
    }
  }

  dispose(): void {
    for (const mesh of this.meshes.values()) {
      this.scene.remove(mesh);
      mesh.geometry.dispose();
      (mesh.material as Material).dispose();
      mesh.dispose();
    }
  }
}
