/**
 * Faction handlers: sim:faction_state.
 */
import type {
  WorkerToMainMessage,
  SimFactionStateMessage,
  SimTradeWindowEventMessage,
} from '../sim/messages';
import { updateMinimapFactions } from '../ui/minimap';
import { updateMarketFactions } from '../ui/marketPanel';
import { showHint } from '../ui/hints';
import { showNotification } from '../ui/notifications';
import {
  getFactionThresholdBroadcast,
  seedKnownFactionDispositions,
} from '../advisor/ariaProactiveBroadcasts';
import { trackFirstFactionContact } from '../analytics';
import type { HandlerContext, HandlerMap, HandlerState } from './types';

export function registerFactionHandlers(
  ctx: HandlerContext,
  state: HandlerState,
): HandlerMap {
  const { lazy, refs } = ctx;

  return {
    'sim:faction_state': (msg: WorkerToMainMessage) => {
      const fMsg = msg as SimFactionStateMessage;
      refs.latestFactionSnapshots = fMsg.payload.factions;
      lazy.getFactionPanel()?.updateFactionPanel(fMsg.payload.factions);
      // Update faction claim markers for territory visualization
      refs.factionClaims = fMsg.payload.factions
        .filter((f) => f.contestingAsteroid >= 0)
        .map((f) => ({ factionId: f.id, asteroidEid: f.contestingAsteroid, color: f.color }));
      refs.factionTerritories = fMsg.payload.factions.map((f) => ({
        x: f.base.x,
        z: f.base.z,
        radius: f.territoryRadius,
        color: f.color,
      }));
      updateMarketFactions(fMsg.payload.factions);
      updateMinimapFactions(
        fMsg.payload.factions.map((f) => ({
          x: f.base.x,
          z: f.base.z,
          color: f.color,
          name: f.name,
          territoryRadius: f.territoryRadius,
        })),
      );
      if (state.firstFactionMessage) {
        state.firstFactionMessage = false;
        seedKnownFactionDispositions(fMsg.payload.factions);
        trackFirstFactionContact();
      } else {
        for (const f of fMsg.payload.factions) {
          const broadcastMsg = getFactionThresholdBroadcast(f.id, f.name, f.disposition);
          if (broadcastMsg) {
            void lazy.loadAdvisorLazy().then((m) => {
              lazy.initAdvisorOnce(m);
              m.panel.addProactiveBroadcast(broadcastMsg);
            });
          }
        }
      }
      if (fMsg.payload.factions.some((f) => f.disposition <= -60)) {
        showHint('lategame_faction_tension', 'ARIA: A rival faction has turned hostile. Press F to review faction standings and consider diplomacy before tensions escalate further.');
      }
      if (fMsg.payload.factions.length >= 3 && fMsg.payload.factions.every((f) => Math.abs(f.disposition) > 20)) {
        showHint('faction_relationships_active', 'ARIA: You now have active relationships with every faction in the belt. Open the Faction panel (F) to review your standing and plan your diplomacy.');
      }
    },

    'sim:trade_window_event': (msg: WorkerToMainMessage) => {
      const twMsg = msg as SimTradeWindowEventMessage;
      const p = twMsg.payload;

      if (p.type === 'opened') {
        const label = p.resourceLabel ?? p.resource ?? 'resources';
        showNotification(
          `${p.factionName} is offering a ${label} bonus — ${p.ticksRemaining} ticks remaining`,
          '#22c55e',
          'success',
        );
        // Surface inline trade offer in ARIA with accept/decline buttons
        const factionColor = refs.latestFactionSnapshots?.find((f) => f.id === p.factionId)?.color ?? '#22c55e';
        void lazy.loadAdvisorLazy().then((m) => {
          lazy.initAdvisorOnce(m);
          const shown = m.panel.addTradeOfferMessage({
            factionId: p.factionId,
            factionName: p.factionName,
            factionColor,
            resource: p.resource ?? 'resources',
            resourceLabel: label,
            rateMultiplier: p.rateMultiplier ?? 1,
            ticksRemaining: p.ticksRemaining ?? 0,
          });
          // Fallback to broadcast if inline offer was suppressed (e.g. grace period)
          if (!shown) {
            m.panel.addProactiveBroadcast(
              `${p.factionName} is offering a ${label} bonus (${p.rateMultiplier}\u00d7) \u2014 ${p.ticksRemaining} ticks remaining. Open the Faction panel (F) to see the deal.`,
            );
          }
        });
      } else if (p.type === 'warning') {
        showNotification(
          `${p.factionName} trade window closes in ${p.ticksRemaining} ticks`,
          '#f59e0b',
          'warning',
        );
      } else if (p.type === 'expired') {
        showNotification(
          `${p.factionName} trade window has closed`,
          '#6b7280',
          'info',
        );
      }
    },
  };
}
