/**
 * DOM-based achievement unlock toast.
 *
 * Queues notifications so only one shows at a time.
 * Rarity-coded border colour, positioned bottom-right above the HUD.
 */
import { ACHIEVEMENT_META } from './definitions';
import type { AchievementId } from './definitions';

const RARITY_COLOUR: Record<string, string> = {
  common:    'rgba(160, 165, 190, 0.9)',
  uncommon:  'rgba(61, 252, 224, 0.9)',
  rare:      'rgba(100, 160, 255, 0.9)',
  epic:      'rgba(180, 100, 255, 0.9)',
  legendary: 'rgba(255, 200, 60, 0.9)',
};

const DISPLAY_MS = 4500;
const FADE_MS = 600;

let styleInjected = false;

function injectStyles(): void {
  if (styleInjected) return;
  styleInjected = true;

  const style = document.createElement('style');
  style.textContent = `
    .ach-notif {
      position: fixed;
      bottom: 80px;
      right: 20px;
      z-index: 9999;
      pointer-events: none;
      opacity: 0;
      transform: translateX(40px);
      transition: opacity ${FADE_MS}ms ease, transform ${FADE_MS}ms ease;
    }
    .ach-notif--visible {
      opacity: 1;
      transform: translateX(0);
    }
    .ach-notif__inner {
      background: rgba(10, 12, 20, 0.92);
      border: 1px solid rgba(61, 252, 224, 0.3);
      border-left-width: 3px;
      border-radius: 4px;
      padding: 12px 16px;
      min-width: 260px;
      max-width: 340px;
      font-family: monospace;
      box-shadow: 0 0 20px rgba(61, 252, 224, 0.15);
    }
    .ach-notif__header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-bottom: 4px;
    }
    .ach-notif__label {
      font-size: 10px;
      letter-spacing: 2px;
      color: rgba(61, 252, 224, 0.8);
      text-transform: uppercase;
    }
    .ach-notif__rarity {
      font-size: 9px;
      letter-spacing: 1px;
      text-transform: uppercase;
      padding: 1px 6px;
      border-radius: 2px;
      background: rgba(255,255,255,0.08);
    }
    .ach-notif__title {
      font-size: 14px;
      font-weight: bold;
      color: #e2e8f0;
      margin-bottom: 2px;
    }
    .ach-notif__desc {
      font-size: 11px;
      color: rgba(160, 165, 190, 0.8);
    }
  `;
  document.head.appendChild(style);
}

export class AchievementNotification {
  private queue: AchievementId[] = [];
  private showing = false;

  show(achievementId: AchievementId): void {
    injectStyles();
    this.queue.push(achievementId);
    if (!this.showing) this._next();
  }

  private _next(): void {
    const id = this.queue.shift();
    if (!id) { this.showing = false; return; }
    this.showing = true;

    const meta = ACHIEVEMENT_META[id] ?? { title: 'Achievement Unlocked', description: '', rarity: 'common' };
    const borderColour = RARITY_COLOUR[meta.rarity] ?? RARITY_COLOUR.common;
    const rarityColour = RARITY_COLOUR[meta.rarity] ?? RARITY_COLOUR.common;

    const el = document.createElement('div');
    el.className = 'ach-notif';
    el.innerHTML = `
      <div class="ach-notif__inner" style="border-left-color:${borderColour}">
        <div class="ach-notif__header">
          <span class="ach-notif__label">Achievement Unlocked</span>
          <span class="ach-notif__rarity" style="color:${rarityColour}">${meta.rarity.toUpperCase()}</span>
        </div>
        <div class="ach-notif__title">${meta.title}</div>
        <div class="ach-notif__desc">${meta.description}</div>
      </div>
    `;
    document.body.appendChild(el);

    requestAnimationFrame(() => el.classList.add('ach-notif--visible'));

    setTimeout(() => {
      el.classList.remove('ach-notif--visible');
      setTimeout(() => {
        el.remove();
        this._next();
      }, FADE_MS);
    }, DISPLAY_MS);
  }
}
