import { attachTooltip } from './tooltip';
import { showNotification } from './notifications';
import { readLegacy } from '../sim/legacy';
import { isTutorialActive } from './tutorial';

const fpsEl = document.getElementById('fps-counter');
const entityEl = document.getElementById('entity-counter');
let resourceEl: HTMLDivElement | null = null;
let clockEl: HTMLDivElement | null = null;

// In-game time: 1 tick = 1 game minute (60 ticks/s real-time → 1 hour/s game-time)
const TICKS_PER_HOUR = 60;
const TICKS_PER_DAY = TICKS_PER_HOUR * 24;

/** Cached expedition number (read once from localStorage at init). */
let expeditionNumber: number | null = null;

function getExpeditionNumber(): number {
  if (expeditionNumber === null) {
    const legacy = readLegacy();
    expeditionNumber = legacy ? legacy.expeditionCount + 1 : 1;
  }
  return expeditionNumber;
}

function getClockEl(): HTMLDivElement {
  if (!clockEl) {
    clockEl = document.createElement('div');
    clockEl.style.cssText = `
      position: fixed;
      top: 8px;
      right: 176px;
      font-size: 12px;
      font-family: 'Courier New', monospace;
      color: #88ccff;
      opacity: 0.85;
      text-align: right;
    `;
    attachTooltip(clockEl, 'In-game elapsed time\n1 real second = 1 game hour');
    document.body.appendChild(clockEl);

    // Show expedition number for legacy players (expedition 2+)
    const expNum = getExpeditionNumber();
    if (expNum > 1) {
      const expEl = document.createElement('div');
      expEl.style.cssText = `
        font-size: 9px;
        color: #a855f7;
        opacity: 0.7;
        letter-spacing: 1px;
        text-transform: uppercase;
        margin-top: 2px;
      `;
      expEl.textContent = `Expedition ${expNum}`;
      attachTooltip(expEl, `You are on expedition ${expNum}.\nLegacy bonuses are active.`);
      clockEl.appendChild(expEl);
    }
  }
  return clockEl;
}

// Attach tooltips to static HUD elements
if (fpsEl) attachTooltip(fpsEl as HTMLElement, 'Frames per second — target 60');
if (entityEl)
  attachTooltip(
    entityEl as HTMLElement,
    'Total entities in simulation\n(asteroids + robots + anomalous entities)',
  );

function getResourceEl(): HTMLDivElement {
  if (!resourceEl) {
    resourceEl = document.createElement('div');
    resourceEl.style.cssText = `
      position: fixed;
      top: 40px;
      left: 8px;
      font-size: 11px;
      opacity: 0.8;
      font-family: 'Courier New', monospace;
      color: #aaffaa;
      line-height: 1.4;
    `;
    attachTooltip(
      resourceEl,
      'Raw ore in base storage\nFe=Iron · C=Carbon · Si=Silicon · H₂O=Water\nPress D to open the full dashboard',
    );
    document.body.appendChild(resourceEl);
  }
  return resourceEl;
}

/** Creates and attaches a Home button to the HUD. Calls onHome when clicked. */
export function initHomeButton(onHome: () => void): void {
  const btn = document.createElement('button');
  btn.id = 'home-btn';
  btn.title = 'Return to base (Home key)';
  btn.setAttribute('aria-label', 'Return camera to base station');
  btn.textContent = '⌂';
  btn.style.cssText = `
    position: fixed;
    top: 180px;
    right: 8px;
    width: ${160}px;
    height: 28px;
    background: rgba(0,20,0,0.75);
    color: #4aff4a;
    border: 1px solid #4aff4a55;
    border-radius: 4px;
    font-size: 13px;
    cursor: pointer;
    z-index: 20;
    pointer-events: auto;
    transition: background 0.15s;
    font-family: 'Courier New', monospace;
  `;
  btn.addEventListener('mouseenter', () => {
    btn.style.background = 'rgba(0,60,0,0.85)';
  });
  btn.addEventListener('mouseleave', () => {
    btn.style.background = 'rgba(0,20,0,0.75)';
  });
  btn.addEventListener('click', onHome);
  attachTooltip(btn, 'Return camera to base (Home key)');
  document.body.appendChild(btn);
}

export function updateHUD(
  fps: number,
  entityCount: number,
  asteroidCount: number,
  robotCount: number,
): void {
  if (fpsEl) fpsEl.textContent = `FPS: ${Math.round(fps)}`;
  if (entityEl)
    entityEl.textContent = `Asteroids: ${asteroidCount} | Robots: ${robotCount} | Total: ${entityCount}`;
}

export function updateGameClock(tick: number): void {
  const el = getClockEl();
  const day = Math.floor(tick / TICKS_PER_DAY) + 1;
  const hourOfDay = Math.floor((tick % TICKS_PER_DAY) / TICKS_PER_HOUR);
  const minute = tick % TICKS_PER_HOUR;
  const hh = String(hourOfDay).padStart(2, '0');
  const mm = String(minute).padStart(2, '0');
  el.textContent = `Day ${day}  ${hh}:${mm}`;
}

export function updateResourceHUD(
  iron: number,
  carbon: number,
  silicon: number,
  water: number,
): void {
  const el = getResourceEl();
  if (isTutorialActive()) {
    el.textContent = `Iron: ${Math.floor(iron || 0)} | Carbon: ${Math.floor(carbon || 0)} | Silicon: ${Math.floor(silicon || 0)} | Water: ${Math.floor(water || 0)}`;
  } else {
    el.textContent = `Fe: ${Math.floor(iron || 0)} | C: ${Math.floor(carbon || 0)} | Si: ${Math.floor(silicon || 0)} | H₂O: ${Math.floor(water || 0)}`;
  }
}

/** Adds or removes a pulsing glow highlight on the resource HUD counters. */
export function highlightResourceHUD(on: boolean): void {
  const el = getResourceEl();
  if (on) {
    el.style.animation = 'hud-pulse 1.2s ease-in-out infinite';
    el.style.textShadow = '0 0 8px rgba(170,255,170,0.7)';
    // Inject keyframes if not already present
    if (!document.getElementById('hud-pulse-style')) {
      const style = document.createElement('style');
      style.id = 'hud-pulse-style';
      style.textContent = `@keyframes hud-pulse {
        0%, 100% { opacity: 0.85; }
        50% { opacity: 1; }
      }`;
      document.head.appendChild(style);
    }
  } else {
    el.style.animation = '';
    el.style.textShadow = '';
  }
}

// ── Speed control ─────────────────────────────────────────────────────────────

const SPEED_STEPS = [1, 2, 4] as const;
let speedEl: HTMLButtonElement | null = null;
let onSpeedChangeCb: ((multiplier: number) => void) | null = null;
let currentSpeedIndex = 0;

function getSpeedEl(): HTMLButtonElement {
  if (speedEl) return speedEl;
  speedEl = document.createElement('button');
  speedEl.id = 'speed-control';
  speedEl.style.cssText = `
    position: fixed;
    top: 8px;
    right: 280px;
    font-size: 12px;
    font-family: 'Courier New', monospace;
    color: #4ade80;
    background: rgba(0,20,0,0.75);
    border: 1px solid rgba(74,222,128,0.3);
    border-radius: 4px;
    padding: 2px 8px;
    cursor: pointer;
    z-index: 20;
    pointer-events: auto;
    transition: background 0.15s;
  `;
  speedEl.addEventListener('mouseenter', () => {
    speedEl!.style.background = 'rgba(0,60,0,0.85)';
  });
  speedEl.addEventListener('mouseleave', () => {
    speedEl!.style.background = 'rgba(0,20,0,0.75)';
  });
  speedEl.addEventListener('click', () => cycleSpeed());
  speedEl.setAttribute('role', 'button');
  speedEl.setAttribute('aria-live', 'polite');
  attachTooltip(speedEl, 'Game speed — click, press 1/2/3, or , / . to change');
  updateSpeedDisplay();
  document.body.appendChild(speedEl);
  return speedEl;
}

function updateSpeedDisplay(): void {
  if (!speedEl) return;
  const m = SPEED_STEPS[currentSpeedIndex];
  speedEl.textContent = `▶ ${m}×`;
  speedEl.setAttribute('aria-label', `Game speed: ${m}x`);
  speedEl.style.color = m === 1 ? '#88ccff' : m === 2 ? '#4ade80' : '#f59e0b';
  speedEl.style.borderColor = m === 1 ? 'rgba(100,150,255,0.3)' : m === 2 ? 'rgba(74,222,128,0.3)' : 'rgba(245,158,11,0.3)';
}

function cycleSpeed(): void {
  currentSpeedIndex = (currentSpeedIndex + 1) % SPEED_STEPS.length;
  updateSpeedDisplay();
  if (onSpeedChangeCb) onSpeedChangeCb(SPEED_STEPS[currentSpeedIndex]);
}

export function initSpeedControl(onChange: (multiplier: number) => void): void {
  onSpeedChangeCb = onChange;
  getSpeedEl();
}

export function setSpeed(multiplier: number): void {
  const idx = SPEED_STEPS.indexOf(multiplier as 1 | 2 | 4);
  if (idx >= 0 && idx !== currentSpeedIndex) {
    currentSpeedIndex = idx;
    updateSpeedDisplay();
    if (onSpeedChangeCb) onSpeedChangeCb(SPEED_STEPS[currentSpeedIndex]);
  }
}

export function speedUp(): void {
  if (currentSpeedIndex < SPEED_STEPS.length - 1) {
    currentSpeedIndex++;
    updateSpeedDisplay();
    if (onSpeedChangeCb) onSpeedChangeCb(SPEED_STEPS[currentSpeedIndex]);
  }
}

export function speedDown(): void {
  if (currentSpeedIndex > 0) {
    currentSpeedIndex--;
    updateSpeedDisplay();
    if (onSpeedChangeCb) onSpeedChangeCb(SPEED_STEPS[currentSpeedIndex]);
  }
}

export function resetSpeed(): void {
  currentSpeedIndex = 0;
  updateSpeedDisplay();
}

// ── Transient Cluster Countdown HUD ──────────────────────────────────────────

let clusterCountdownEl: HTMLDivElement | null = null;

function getClusterCountdownEl(): HTMLDivElement {
  if (!clusterCountdownEl) {
    clusterCountdownEl = document.createElement('div');
    clusterCountdownEl.style.cssText = `
      position: absolute;
      bottom: 60px;
      left: 50%;
      transform: translateX(-50%);
      background: rgba(40,20,0,0.88);
      border: 1px solid rgba(245,158,11,0.6);
      border-radius: 6px;
      padding: 6px 14px;
      font-family: 'Courier New', monospace;
      font-size: 12px;
      color: #f59e0b;
      z-index: 60;
      pointer-events: none;
      white-space: nowrap;
      text-align: center;
      animation: cluster-pulse 1.5s ease-in-out infinite;
      display: none;
    `;
    // Inject pulsing keyframes
    if (!document.getElementById('cluster-pulse-style')) {
      const style = document.createElement('style');
      style.id = 'cluster-pulse-style';
      style.textContent = `@keyframes cluster-pulse {
        0%, 100% { border-color: rgba(245,158,11,0.6); box-shadow: 0 0 6px rgba(245,158,11,0.2); }
        50% { border-color: rgba(245,158,11,1); box-shadow: 0 0 12px rgba(245,158,11,0.5); }
      }`;
      document.head.appendChild(style);
    }
    const hudOverlay = document.getElementById('hud-overlay');
    if (hudOverlay) hudOverlay.appendChild(clusterCountdownEl);
    else document.body.appendChild(clusterCountdownEl);
  }
  return clusterCountdownEl;
}

export function updateClusterCountdownHUD(
  clusters: Array<{ clusterId: number; ticksRemaining: number }>,
): void {
  const el = getClusterCountdownEl();
  if (clusters.length === 0) {
    el.style.display = 'none';
    return;
  }

  const lines = clusters.map((c) => {
    const totalSec = Math.ceil(c.ticksRemaining / 60);
    const urgent = totalSec <= 60; // last minute is urgent
    const color = urgent ? '#ef4444' : '#f59e0b';
    const minutes = Math.floor(totalSec / 60);
    const seconds = totalSec % 60;
    const timeStr = minutes > 0
      ? (seconds > 0 ? `${minutes} min ${seconds}s` : `${minutes} min`)
      : `${totalSec}s`;
    return `<span style="color:${color}">CLUSTER #${c.clusterId}: ${timeStr}</span>`;
  });

  el.innerHTML =
    '<span style="opacity:0.6;text-transform:uppercase;letter-spacing:1px;font-size:9px">TRANSIENT CLUSTER</span><br>' +
    lines.join('<br>');
  el.style.display = 'block';

  // Urgent animation when ≤1 minute remaining
  if (clusters.some((c) => c.ticksRemaining <= 60 * 60)) {
    el.style.borderColor = 'rgba(239,68,68,0.8)';
    el.style.animationDuration = '0.6s';
  } else {
    el.style.borderColor = 'rgba(245,158,11,0.6)';
    el.style.animationDuration = '1.5s';
  }
}

export function hideClusterCountdownHUD(): void {
  if (clusterCountdownEl) clusterCountdownEl.style.display = 'none';
}

// ── Megastructure Crisis Countdown HUD ────────────────────────────────────────

let megaCrisisCountdownEl: HTMLDivElement | null = null;

function getMegaCrisisCountdownEl(): HTMLDivElement {
  if (!megaCrisisCountdownEl) {
    megaCrisisCountdownEl = document.createElement('div');
    megaCrisisCountdownEl.style.cssText = `
      position: absolute;
      bottom: 100px;
      left: 50%;
      transform: translateX(-50%);
      background: rgba(60,10,10,0.92);
      border: 1px solid rgba(239,68,68,0.6);
      border-radius: 6px;
      padding: 6px 14px;
      font-family: 'Courier New', monospace;
      font-size: 12px;
      color: #ef4444;
      z-index: 60;
      pointer-events: none;
      white-space: nowrap;
      text-align: center;
      animation: mega-crisis-pulse 1.2s ease-in-out infinite;
      display: none;
    `;
    if (!document.getElementById('mega-crisis-pulse-style')) {
      const style = document.createElement('style');
      style.id = 'mega-crisis-pulse-style';
      style.textContent = `@keyframes mega-crisis-pulse {
        0%, 100% { border-color: rgba(239,68,68,0.6); box-shadow: 0 0 8px rgba(239,68,68,0.2); }
        50% { border-color: rgba(239,68,68,1); box-shadow: 0 0 16px rgba(239,68,68,0.6); }
      }`;
      document.head.appendChild(style);
    }
    const hudOverlay = document.getElementById('hud-overlay');
    if (hudOverlay) hudOverlay.appendChild(megaCrisisCountdownEl);
    else document.body.appendChild(megaCrisisCountdownEl);
  }
  return megaCrisisCountdownEl;
}

export function updateMegaCrisisCountdownHUD(
  items: Array<{ structureName: string; stageName: string; ticksRemaining: number }>,
): void {
  const el = getMegaCrisisCountdownEl();
  if (items.length === 0) {
    el.style.display = 'none';
    return;
  }

  const lines = items.map((item) => {
    const urgent = item.ticksRemaining <= 5;
    const color = urgent ? '#fbbf24' : '#ef4444';
    return `<span style="color:${color}">${item.structureName} — ${item.stageName}: ${item.ticksRemaining} ticks</span>`;
  });

  el.innerHTML =
    '<span style="opacity:0.7;text-transform:uppercase;letter-spacing:1px;font-size:9px;color:#f87171">⚠ STAGE CRISIS</span><br>' +
    lines.join('<br>');
  el.style.display = 'block';

  if (items.some((i) => i.ticksRemaining <= 5)) {
    el.style.borderColor = 'rgba(251,191,36,0.8)';
    el.style.animationDuration = '0.4s';
  } else {
    el.style.borderColor = 'rgba(239,68,68,0.6)';
    el.style.animationDuration = '1.2s';
  }
}

export function hideMegaCrisisCountdownHUD(): void {
  if (megaCrisisCountdownEl) megaCrisisCountdownEl.style.display = 'none';
}

// ── Follow mode indicator ─────────────────────────────────────────────────────

let followIndicatorEl: HTMLDivElement | null = null;

/**
 * Show a persistent banner at the top when following a robot.
 * Provides a visible "Return to Base" button so players know how to get back.
 */
export function showFollowIndicator(robotEid: number, onReturnToBase: () => void): void {
  if (!followIndicatorEl) {
    followIndicatorEl = document.createElement('div');
    followIndicatorEl.style.cssText = `
      position: absolute;
      top: 8px;
      left: 50%;
      transform: translateX(-50%);
      background: rgba(5,20,40,0.88);
      border: 1px solid rgba(34,211,238,0.4);
      border-radius: 4px;
      padding: 4px 8px 4px 10px;
      font-family: 'Courier New', monospace;
      font-size: 11px;
      color: #22d3ee;
      z-index: 60;
      display: flex;
      align-items: center;
      gap: 10px;
      white-space: nowrap;
      pointer-events: auto;
    `;
    const hudOverlay = document.getElementById('hud-overlay');
    if (hudOverlay) hudOverlay.appendChild(followIndicatorEl);
  }

  const returnBtn = document.createElement('button');
  returnBtn.textContent = '⌂ Return to Base';
  returnBtn.style.cssText = `
    background: rgba(0,40,20,0.8);
    border: 1px solid rgba(74,222,128,0.4);
    border-radius: 3px;
    color: #4ade80;
    cursor: pointer;
    font-family: 'Courier New', monospace;
    font-size: 10px;
    padding: 2px 7px;
  `;
  returnBtn.addEventListener('click', onReturnToBase);

  followIndicatorEl.innerHTML = '';
  const label = document.createElement('span');
  label.textContent = `Following Robot #${robotEid}`;
  followIndicatorEl.appendChild(label);
  followIndicatorEl.appendChild(returnBtn);
  followIndicatorEl.style.display = 'flex';
}

export function hideFollowIndicator(): void {
  if (followIndicatorEl) followIndicatorEl.style.display = 'none';
}

// ── Objective widget ──────────────────────────────────────────────────────────

const OBJECTIVE_DISMISSED_KEY = 'asteroid_miner_obj_dismissed';

let objectiveEl: HTMLDivElement | null = null;

/**
 * Shows a persistent mission objective banner at the top-center of the HUD.
 * Dismissed by clicking ✕. Dismissed state persists via localStorage.
 */
export function initObjectiveWidget(): void {
  try {
    if (localStorage.getItem(OBJECTIVE_DISMISSED_KEY)) return;
  } catch {
    /* ignore */
  }

  const el = document.createElement('div');
  objectiveEl = el;
  el.style.cssText = `
    position: absolute;
    top: 8px;
    left: 50%;
    transform: translateX(-50%);
    background: rgba(5,10,25,0.82);
    border: 1px solid rgba(100,180,255,0.25);
    border-radius: 4px;
    padding: 4px 10px 4px 12px;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    color: rgba(160,200,255,0.8);
    z-index: 50;
    display: flex;
    align-items: center;
    gap: 10px;
    white-space: nowrap;
    pointer-events: auto;
  `;

  const text = document.createElement('span');
  text.innerHTML =
    '<span style="opacity:0.5;text-transform:uppercase;letter-spacing:1px;font-size:9px;margin-right:6px;">MISSION</span>' +
    'Mine resources · Research technology · Build the Orbital Platform';
  el.appendChild(text);

  const closeBtn = document.createElement('button');
  closeBtn.textContent = '✕';
  closeBtn.setAttribute('aria-label', 'Dismiss mission objective');
  closeBtn.style.cssText = `
    background: none;
    border: none;
    color: rgba(120,150,200,0.5);
    cursor: pointer;
    font-size: 10px;
    padding: 0 2px;
    font-family: 'Courier New', monospace;
    line-height: 1;
  `;
  closeBtn.addEventListener('click', () => {
    el.style.opacity = '0';
    el.style.transition = 'opacity 0.3s';
    setTimeout(() => el.remove(), 300);
    objectiveEl = null;
    try {
      localStorage.setItem(OBJECTIVE_DISMISSED_KEY, '1');
    } catch {
      /* ignore */
    }
  });
  el.appendChild(closeBtn);

  attachTooltip(
    el,
    'Your long-term goal: accumulate resources, research the tech tree,\nand construct the Orbital Platform megastructure.\nPress G to view megastructure progress.',
  );

  const hudOverlay = document.getElementById('hud-overlay');
  if (hudOverlay) hudOverlay.appendChild(el);
}

// ── Build guidance hint ───────────────────────────────────────────────────────

const BUILD_TOAST_SEEN_KEY = 'asteroid_miner_build_toast_seen';

/**
 * Shows a one-time toast 10s after game start reminding new players to press C
 * to open the Build panel. Only fires once (tracked via localStorage).
 */
export function initBuildGuidanceHint(): void {
  try {
    if (localStorage.getItem(BUILD_TOAST_SEEN_KEY)) return;
  } catch { /* ignore */ }

  setTimeout(() => {
    showNotification('Press [C] to open the Build panel and construct your first robot 🤖', '#88ccff');
    try { localStorage.setItem(BUILD_TOAST_SEEN_KEY, '1'); } catch { /* ignore */ }
  }, 10_000);
}
