/**
 * Polls /version.json every 60s and shows a non-blocking toast when the
 * build ID changes mid-session, prompting the player to refresh.
 */

import { showNotification } from './ui/notifications';

const POLL_INTERVAL_MS = 60_000;
let initialBuildId: string | null = null;
let timer: ReturnType<typeof setInterval> | null = null;

async function fetchBuildId(): Promise<string | null> {
  try {
    const res = await fetch('/version.json', { cache: 'no-store' });
    if (!res.ok) return null;
    const data = await res.json();
    return data.buildId ?? null;
  } catch {
    return null;
  }
}

async function check(): Promise<void> {
  const current = await fetchBuildId();
  if (!current) return;

  if (initialBuildId === null) {
    initialBuildId = current;
    return;
  }

  if (current !== initialBuildId) {
    // Stop polling once we've detected a change
    if (timer !== null) {
      clearInterval(timer);
      timer = null;
    }
    showNotification(
      '⚡ New version available — please refresh to avoid errors',
      '#f59e0b',
      'warning',
    );
  }
}

export function startVersionCheck(): void {
  // Seed the initial build ID immediately
  check();
  timer = setInterval(check, POLL_INTERVAL_MS);
}
