import type { DifficultyMode } from '../sim/difficulty';
import { DIFFICULTY_LABELS } from '../sim/difficulty';
import { makeButton } from './menuHelpers';

/** Show the title screen (always shown on first load, new-game path). */
export function showTitleScreen(onNewGame: (customSeed?: number, difficulty?: DifficultyMode) => void, onSettings?: () => void): void {
  const overlay = document.createElement('div');
  overlay.setAttribute('role', 'dialog');
  overlay.setAttribute('aria-label', 'Asteroid Miner title screen');
  overlay.setAttribute('aria-modal', 'true');
  overlay.style.cssText = `
    position: fixed;
    top: 0; left: 0;
    width: 100%; height: 100%;
    background: rgba(0,2,8,0.98);
    z-index: 2000;
    display: flex;
    align-items: center;
    justify-content: center;
    font-family: 'Courier New', monospace;
    color: #aaffaa;
  `;

  // Animated star field canvas
  const starCanvas = document.createElement('canvas');
  starCanvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;opacity:0.4;';
  starCanvas.width = window.innerWidth;
  starCanvas.height = window.innerHeight;
  overlay.appendChild(starCanvas);
  const sCtx = starCanvas.getContext('2d');
  if (sCtx) {
    const stars = Array.from({ length: 180 }, () => ({
      x: Math.random() * starCanvas.width,
      y: Math.random() * starCanvas.height,
      r: Math.random() * 1.4 + 0.3,
      speed: Math.random() * 0.15 + 0.03,
    }));
    let frameId = 0;
    function animStars(): void {
      if (!sCtx) return;
      sCtx.clearRect(0, 0, starCanvas.width, starCanvas.height);
      for (const s of stars) {
        sCtx.beginPath();
        sCtx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
        sCtx.fillStyle = 'rgba(180,200,255,0.8)';
        sCtx.fill();
        s.y += s.speed;
        if (s.y > starCanvas.height) {
          s.y = 0;
          s.x = Math.random() * starCanvas.width;
        }
      }
      frameId = requestAnimationFrame(animStars);
    }
    animStars();
    overlay.addEventListener('remove', () => cancelAnimationFrame(frameId), { once: true });
  }

  const panel = document.createElement('div');
  panel.style.cssText = `
    position: relative;
    background: rgba(0,8,0,0.92);
    border: 1px solid #4aff4a;
    border-radius: 10px;
    padding: 40px 48px;
    min-width: 400px;
    text-align: center;
    box-shadow: 0 0 60px rgba(74,255,74,0.08);
  `;

  // Logo
  const logo = document.createElement('div');
  logo.style.cssText = `
    font-size: 24px;
    color: #4aff4a;
    letter-spacing: 5px;
    text-transform: uppercase;
    margin-bottom: 4px;
    text-shadow: 0 0 16px rgba(74,255,74,0.6);
  `;
  logo.textContent = '★ CULTURES OF THE BELT ★';
  panel.appendChild(logo);

  const tagline = document.createElement('div');
  tagline.style.cssText =
    'font-size:10px;color:#4a9a4a;letter-spacing:2px;margin-bottom:8px;text-transform:uppercase;';
  tagline.textContent = 'Hard Sci-Fi 4X Mining Sim';
  panel.appendChild(tagline);

  const lore = document.createElement('div');
  lore.style.cssText =
    'font-size:9px;color:#2a5a3a;letter-spacing:1px;margin-bottom:28px;font-style:italic;';
  lore.textContent = 'Belt Sector 7  ·  2387 CE  ·  ARIA-CORE ONLINE';
  panel.appendChild(lore);

  // Seed input
  const seedRow = document.createElement('div');
  seedRow.style.cssText = 'display:flex;align-items:center;justify-content:center;gap:8px;margin-bottom:16px;';

  const seedLabel = document.createElement('label');
  seedLabel.style.cssText = 'font-size:10px;color:#556655;letter-spacing:1px;';
  seedLabel.textContent = 'SEED';
  seedRow.appendChild(seedLabel);

  const seedInput = document.createElement('input');
  seedInput.type = 'text';
  seedInput.placeholder = 'Random';
  seedInput.maxLength = 9;
  seedInput.style.cssText = `
    width: 100px;
    padding: 4px 8px;
    background: rgba(0,20,0,0.8);
    border: 1px solid #2a5a2a;
    color: #aaffaa;
    font-family: 'Courier New', monospace;
    font-size: 12px;
    border-radius: 3px;
    text-align: center;
    outline: none;
  `;
  seedInput.addEventListener('focus', () => { seedInput.style.borderColor = '#4aff4a'; });
  seedInput.addEventListener('blur', () => { seedInput.style.borderColor = '#2a5a2a'; });
  seedRow.appendChild(seedInput);
  panel.appendChild(seedRow);

  function parseSeedInput(): number | undefined {
    const val = seedInput.value.trim();
    if (!val) return undefined;
    const num = parseInt(val, 10);
    return isFinite(num) ? num : undefined;
  }

  // Difficulty picker
  let selectedDifficulty: DifficultyMode = 'normal';
  const modes: DifficultyMode[] = ['easy', 'normal', 'hard'];
  const diffRow = document.createElement('div');
  diffRow.style.cssText = 'display:flex;align-items:center;justify-content:center;gap:6px;margin-bottom:20px;';

  const diffLabel = document.createElement('span');
  diffLabel.style.cssText = 'font-size:10px;color:#556655;letter-spacing:1px;margin-right:4px;';
  diffLabel.textContent = 'DIFFICULTY';
  diffRow.appendChild(diffLabel);

  const diffBtns: HTMLButtonElement[] = [];
  for (const mode of modes) {
    const btn = document.createElement('button');
    btn.textContent = DIFFICULTY_LABELS[mode];
    btn.dataset.mode = mode;
    btn.style.cssText = `
      padding: 4px 14px;
      font-family: 'Courier New', monospace;
      font-size: 11px;
      border-radius: 3px;
      cursor: pointer;
      transition: background 0.15s, border-color 0.15s;
    `;
    diffBtns.push(btn);

    btn.addEventListener('click', () => {
      selectedDifficulty = mode;
      updateDiffSelection();
    });
    diffRow.appendChild(btn);
  }

  function updateDiffSelection(): void {
    for (const b of diffBtns) {
      const isActive = b.dataset.mode === selectedDifficulty;
      b.style.background = isActive ? 'rgba(74,255,74,0.2)' : 'rgba(0,20,0,0.6)';
      b.style.color = isActive ? '#4aff4a' : '#556655';
      b.style.border = isActive ? '1px solid #4aff4a' : '1px solid #2a4a2a';
      b.style.fontWeight = isActive ? 'bold' : 'normal';
    }
  }
  updateDiffSelection();
  panel.appendChild(diffRow);

  const newBtn = makeButton('NEW GAME', '#4aff4a', () => {
    overlay.dispatchEvent(new Event('remove'));
    overlay.remove();
    onNewGame(parseSeedInput(), selectedDifficulty);
  });
  newBtn.style.marginBottom = '10px';
  panel.appendChild(newBtn);

  if (onSettings) {
    const settingsBtn = makeButton('SETTINGS', '#8090c0', () => {
      overlay.dispatchEvent(new Event('remove'));
      overlay.remove();
      onSettings();
    });
    settingsBtn.style.marginBottom = '0';
    panel.appendChild(settingsBtn);
  }

  // Version
  const ver = document.createElement('div');
  ver.style.cssText = 'font-size:9px;color:#2a4a2a;margin-top:24px;';
  ver.textContent = `v${__APP_VERSION__}`;
  panel.appendChild(ver);

  overlay.appendChild(panel);
  document.body.appendChild(overlay);
}
