/**
 * Event Log Panel — press E to toggle.
 *
 * A scrollable, collapsible panel showing a history of important game events:
 * building/research completions, threat events, faction interactions,
 * resource milestones, anomaly discoveries. Max 100 entries.
 */

import { registerHudButton } from './hudButtonBar';

// ── Data model ──────────────────────────────────────────────────────────────

export type GameEventCategory =
  | 'building'
  | 'research'
  | 'threat'
  | 'faction'
  | 'resource'
  | 'anomaly'
  | 'production'
  | 'general';

export interface GameEventEntry {
  /** Game tick when the event occurred */
  tick: number;
  /** Event category for icon/color */
  category: GameEventCategory;
  /** One-line description */
  text: string;
}

export interface SerializedEventLog {
  entries: GameEventEntry[];
}

const MAX_ENTRIES = 100;

const CATEGORY_ICON: Record<GameEventCategory, string> = {
  building: '🏗',
  research: '🔬',
  threat: '⚠',
  faction: '🤝',
  resource: '📦',
  anomaly: '✦',
  production: '⚙',
  general: '●',
};

const CATEGORY_COLOR: Record<GameEventCategory, string> = {
  building: '#4ade80',
  research: '#60a5fa',
  threat: '#ef4444',
  faction: '#f59e0b',
  resource: '#22d3ee',
  anomaly: '#a855f7',
  production: '#88ccff',
  general: '#94a3b8',
};

// ── Internal state ──────────────────────────────────────────────────────────

let panel: HTMLDivElement | null = null;
let contentEl: HTMLDivElement | null = null;
let countEl: HTMLSpanElement | null = null;
let visible = false;
let entries: GameEventEntry[] = [];
let hudBtn: HTMLButtonElement | null = null;

// ── Tick → game time formatting ─────────────────────────────────────────────

const TICKS_PER_HOUR = 60;
const TICKS_PER_DAY = TICKS_PER_HOUR * 24;

function formatGameTime(tick: number): string {
  const day = Math.floor(tick / TICKS_PER_DAY) + 1;
  const hour = Math.floor((tick % TICKS_PER_DAY) / TICKS_PER_HOUR);
  const min = tick % TICKS_PER_HOUR;
  return `D${day} ${String(hour).padStart(2, '0')}:${String(min).padStart(2, '0')}`;
}

// ── Public API ──────────────────────────────────────────────────────────────

export function initEventLogPanel(): void {
  hudBtn = registerHudButton('📋 EVENTS', toggleEventLogPanel, 'Event Log (E)');
}

export function toggleEventLogPanel(): void {
  if (visible) hidePanel(); else showPanel();
}

export function hideEventLogPanel(): void {
  hidePanel();
}

export function isEventLogPanelVisible(): boolean {
  return visible;
}

/** Add a game event entry. Trims to MAX_ENTRIES. */
export function addGameEvent(category: GameEventCategory, text: string, tick: number): void {
  entries.push({ tick, category, text });
  if (entries.length > MAX_ENTRIES) {
    entries = entries.slice(entries.length - MAX_ENTRIES);
  }
  if (visible) renderEntries();
}

/** Serialize for save. */
export function serializeEventLog(): SerializedEventLog {
  return { entries: [...entries] };
}

/** Restore from save. */
export function restoreEventLog(data: SerializedEventLog): void {
  entries = Array.isArray(data.entries) ? [...data.entries].slice(-MAX_ENTRIES) : [];
  if (visible) renderEntries();
}

/** Reset state (new game). */
export function resetEventLog(): void {
  entries = [];
  if (visible) renderEntries();
}

// ── Lifecycle ───────────────────────────────────────────────────────────────

function showPanel(): void {
  visible = true;
  if (!panel) buildPanel();
  renderEntries();
  panel!.style.display = 'flex';
  if (hudBtn) hudBtn.style.background = 'rgba(20,50,110,0.9)';
}

function hidePanel(): void {
  visible = false;
  if (panel) panel.style.display = 'none';
  if (hudBtn) hudBtn.style.background = 'rgba(0,0,0,0.75)';
}

function buildPanel(): void {
  panel = document.createElement('div');
  panel.setAttribute('role', 'dialog');
  panel.setAttribute('aria-label', 'Game Event Log');
  panel.style.cssText = `
    position: fixed;
    top: 60px;
    right: 12px;
    width: min(380px, 90vw);
    max-height: 60vh;
    background: rgba(4,8,18,0.95);
    border: 1px solid rgba(100,150,255,0.25);
    border-radius: 6px;
    box-shadow: 0 4px 24px rgba(0,0,0,0.6);
    color: #c0d0f0;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    z-index: 180;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    pointer-events: auto;
  `;

  // Header
  const header = document.createElement('div');
  header.style.cssText = `
    padding: 10px 14px;
    border-bottom: 1px solid rgba(100,140,255,0.15);
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-shrink: 0;
  `;
  const titleEl = document.createElement('span');
  titleEl.style.cssText = 'font-size: 10px; color: #7090e0; letter-spacing: 2px; text-transform: uppercase;';
  titleEl.textContent = 'Event Log';
  header.appendChild(titleEl);

  const rightGroup = document.createElement('div');
  rightGroup.style.cssText = 'display: flex; gap: 12px; align-items: center;';
  countEl = document.createElement('span');
  countEl.style.cssText = 'font-size: 9px; color: #475569;';
  rightGroup.appendChild(countEl);

  const closeBtn = document.createElement('button');
  closeBtn.setAttribute('aria-label', 'Close event log');
  closeBtn.textContent = '×';
  closeBtn.style.cssText = 'background:none;border:none;color:#64748b;cursor:pointer;font-size:16px;padding:0;line-height:1;';
  closeBtn.addEventListener('click', hidePanel);
  rightGroup.appendChild(closeBtn);
  header.appendChild(rightGroup);
  panel.appendChild(header);

  // Scrollable content
  contentEl = document.createElement('div');
  contentEl.style.cssText = 'overflow-y: auto; flex: 1; padding: 4px 0;';
  panel.appendChild(contentEl);

  // Footer
  const footer = document.createElement('div');
  footer.style.cssText = `
    padding: 6px 14px;
    border-top: 1px solid rgba(100,140,255,0.1);
    font-size: 9px;
    color: #475569;
    text-align: center;
    flex-shrink: 0;
  `;
  footer.textContent = 'Press E or ESC to close';
  panel.appendChild(footer);

  document.body.appendChild(panel);
}

function renderEntries(): void {
  if (!contentEl || !countEl) return;

  countEl.textContent = `${entries.length} event${entries.length !== 1 ? 's' : ''}`;

  contentEl.innerHTML = '';

  if (entries.length === 0) {
    const empty = document.createElement('div');
    empty.style.cssText = 'text-align: center; padding: 24px 0; color: #475569; font-size: 10px;';
    empty.textContent = 'No events recorded yet.';
    contentEl.appendChild(empty);
    return;
  }

  // Show newest first
  for (let i = entries.length - 1; i >= 0; i--) {
    const entry = entries[i];
    const color = CATEGORY_COLOR[entry.category];
    const icon = CATEGORY_ICON[entry.category];

    const row = document.createElement('div');
    row.style.cssText = `
      padding: 6px 14px;
      border-bottom: 1px solid rgba(15,23,42,0.8);
      display: flex;
      gap: 8px;
      align-items: flex-start;
      line-height: 1.5;
    `;
    row.addEventListener('mouseenter', () => { row.style.background = 'rgba(15,23,42,0.6)'; });
    row.addEventListener('mouseleave', () => { row.style.background = ''; });

    const timeEl = document.createElement('span');
    timeEl.style.cssText = 'color: #475569; font-size: 9px; white-space: nowrap; min-width: 62px; padding-top: 1px;';
    timeEl.textContent = formatGameTime(entry.tick);

    const iconEl = document.createElement('span');
    iconEl.style.cssText = `font-size: 10px; min-width: 16px; text-align: center; padding-top: 1px;`;
    iconEl.textContent = icon;

    const textEl = document.createElement('span');
    textEl.style.cssText = `color: ${color}; font-size: 11px;`;
    textEl.textContent = entry.text;

    row.appendChild(timeEl);
    row.appendChild(iconEl);
    row.appendChild(textEl);
    contentEl.appendChild(row);
  }

  // Scroll to top (newest)
  contentEl.scrollTop = 0;
}
