/**
 * Named Location Labels — CSS overlay for robot-named asteroids.
 *
 * Projects named location 3D positions to screen space and renders
 * floating labels. Updated each frame from the render loop.
 */
import { Vector3, PerspectiveCamera } from 'three';

interface NamedLocationEntry {
  name: string;
  x: number;
  y: number;
  z: number;
}

const MAX_VISIBLE_DISTANCE = 5000;
const MAX_LABELS = 30;

export class NamedLocationLabels {
  private container: HTMLDivElement;
  private labelPool: HTMLDivElement[] = [];
  private locations: NamedLocationEntry[] = [];
  private readonly tmpVec = new Vector3();

  constructor() {
    this.container = document.createElement('div');
    this.container.id = 'named-location-labels';
    this.container.style.cssText = `
      position: fixed;
      inset: 0;
      pointer-events: none;
      z-index: 10;
      overflow: hidden;
    `;
    document.body.appendChild(this.container);
  }

  setLocations(locations: NamedLocationEntry[]): void {
    this.locations = locations;
  }

  update(camera: PerspectiveCamera): void {
    const locs = this.locations;
    const count = Math.min(locs.length, MAX_LABELS);

    // Grow pool if needed
    while (this.labelPool.length < count) {
      const el = document.createElement('div');
      el.style.cssText = `
        position: absolute;
        font-family: 'Courier New', monospace;
        font-size: 9px;
        color: rgba(160,200,255,0.7);
        text-transform: uppercase;
        letter-spacing: 1px;
        white-space: nowrap;
        pointer-events: none;
        text-shadow: 0 0 4px rgba(0,0,0,0.8);
        transform: translate(-50%, -100%);
      `;
      this.container.appendChild(el);
      this.labelPool.push(el);
    }

    const w2 = window.innerWidth / 2;
    const h2 = window.innerHeight / 2;

    for (let i = 0; i < this.labelPool.length; i++) {
      const el = this.labelPool[i];
      if (i >= count) {
        el.style.display = 'none';
        continue;
      }

      const loc = locs[i];
      this.tmpVec.set(loc.x, loc.y + 20, loc.z);

      const dist = camera.position.distanceTo(this.tmpVec);
      if (dist > MAX_VISIBLE_DISTANCE) {
        el.style.display = 'none';
        continue;
      }

      // Project to screen
      this.tmpVec.project(camera);

      // Behind camera check
      if (this.tmpVec.z > 1) {
        el.style.display = 'none';
        continue;
      }

      const sx = this.tmpVec.x * w2 + w2;
      const sy = -this.tmpVec.y * h2 + h2;

      // Off-screen check
      if (sx < -100 || sx > window.innerWidth + 100 || sy < -50 || sy > window.innerHeight + 50) {
        el.style.display = 'none';
        continue;
      }

      // Fade by distance
      const opacity = Math.max(0.3, 1 - dist / MAX_VISIBLE_DISTANCE);

      el.style.display = 'block';
      el.style.left = `${sx}px`;
      el.style.top = `${sy}px`;
      el.style.opacity = String(opacity);
      el.textContent = `\u2726 ${loc.name}`;
    }
  }

  dispose(): void {
    this.container.remove();
  }
}
