/**
 * Meridian Event lore handlers: state broadcast, commentary, and unlock notifications.
 */
import type {
  WorkerToMainMessage,
  SimMeridianLoreStateMessage,
  SimMeridianCommentaryMessage,
  SimMeridianUnlockMessage,
} from '../sim/messages';
import { updateArchivesPanel } from '../ui/archivesPanel';
import { showNotification } from '../ui/notifications';
import type { HandlerContext, HandlerMap } from './types';
import type { LazyPanelHandles } from '../workerMessages';

/** Load advisor lazily and run a callback. */
function withAdvisor(lazy: LazyPanelHandles, fn: (m: Awaited<ReturnType<LazyPanelHandles['loadAdvisorLazy']>>) => void): void {
  void lazy.loadAdvisorLazy().then((m) => {
    lazy.initAdvisorOnce(m);
    fn(m);
  }).catch((err) => {
    console.error('[meridian] failed to load advisor:', err);
  });
}

export function registerMeridianHandlers(ctx: HandlerContext): HandlerMap {
  return {
    'sim:meridian_lore_state': (msg: WorkerToMainMessage) => {
      const payload = (msg as SimMeridianLoreStateMessage).payload;
      updateArchivesPanel(payload);
    },

    'sim:meridian_commentary': (msg: WorkerToMainMessage) => {
      const payload = (msg as SimMeridianCommentaryMessage).payload;
      // Display as ARIA proactive broadcast
      withAdvisor(ctx.lazy, (m) => {
        m.panel.addProactiveBroadcast(payload.text);
      });
    },

    'sim:meridian_unlock': (msg: WorkerToMainMessage) => {
      const payload = (msg as SimMeridianUnlockMessage).payload;
      for (const series of payload.newArchiveSeries) {
        const seriesNames: Record<string, string> = {
          A: 'Early Operations',
          B: 'Middle Period',
          C: 'Final Days',
        };
        showNotification(
          `ARCHIVES UNLOCKED: Series ${series} — ${seriesNames[series] ?? 'Unknown'}`,
          'info',
        );
      }
      for (const artifact of payload.newArtifacts) {
        const artifactNames: Record<string, string> = {
          directive_log: 'ARIA-7 Directive Log',
          board_memo: 'CCR Board Memo',
        };
        showNotification(
          `HISTORICAL DATABASE: ${artifactNames[artifact] ?? artifact} now available`,
          'info',
        );
      }
    },
  };
}
