/**
 * Music Manager
 *
 * Contextual music playback using 20 Suno-licensed MP3 tracks.
 * Replaces procedural pad music; ambient drone is kept.
 *
 * - Loads tracks lazily via fetch + Web Audio API decodeAudioData
 * - Smooth crossfades (~2.5s) between states
 * - Sequences "You Make Progress Over Time" variants with alt endings
 * - Session timer: shifts to long-session tracks at 60min / 90min
 * - Respects musicVolume from AudioEngine
 */

// ── Types ─────────────────────────────────────────────────────────────────────

export type MusicGameState =
  | 'loading'        // game start
  | 'idle'           // calm, low activity
  | 'exploring'      // drifting / exploration
  | 'mining'         // quiet solo mining
  | 'focus'          // active mining focus
  | 'progress'       // steady resource / tech progress
  | 'industrial'     // building / infrastructure expansion
  | 'alert'          // infrastructure warning / tense
  | 'combat'         // combat started
  | 'mid_combat'     // mid-combat
  | 'casualties'     // high casualties
  | 'unhappy'        // low morale / crisis
  | 'post_combat'    // post-combat recovery
  | 'recovery'       // rebuilding after loss
  | 'long_session'   // >60 min
  | 'very_long';     // >90 min

// ── Track definitions ─────────────────────────────────────────────────────────

const TRACK_BASE = `${import.meta.env.BASE_URL}assets/music/`;

/** All 20 track filenames */
const TRACKS = {
  beginSlowly: 'Begin Slowly.mp3',
  spaceIsDeep: 'Space is Deep.mp3',
  cosmosIsPeaceful: 'The Cosmos is Peaceful.mp3',
  mineQuietly: 'Mine Quietly.mp3',
  focusAndMine: 'Focus and Mine.mp3',
  progressBase: 'You Make Progress Over Time.mp3',
  progressLonger: 'You Make Progress Over Time (longer).mp3',
  progressAlt1: 'You Make Progress Over Time (longer) (alt ending 1).mp3',
  progressAlt2: 'You Make Progress Over Time (longer) (alt ending 2).mp3',
  progressAlt3: 'You Make Progress Over Time (longer) (alt ending 3).mp3',
  industrialProgress: 'You make Industrial Progress.mp3',
  infraFocus: 'Your infrastructure needs your focus.mp3',
  combatStart: 'ok the attack is underway, focus now.mp3',
  midCombat: 'combat in space is almost silent but people still die.mp3',
  peopleDying: 'Your people are dying.mp3',
  peopleUnhappy: 'Your people are unhappy.mp3',
  postCombat: 'so many people died but the attack is now over and you need to clean up.mp3',
  recovery: 'We Are All In This Together.mp3',
  keepGoing: "keep going but also it's late it's a long playsession already.mp3",
  bedtime: 'Quiet and chill, maybe it is time to go to bed you have been playing a long time.mp3',
} as const;

type TrackKey = keyof typeof TRACKS;

/** Map from game state to primary track key */
const STATE_TRACK: Record<MusicGameState, TrackKey> = {
  loading: 'beginSlowly',
  idle: 'cosmosIsPeaceful',
  exploring: 'spaceIsDeep',
  mining: 'mineQuietly',
  focus: 'focusAndMine',
  progress: 'progressBase',
  industrial: 'industrialProgress',
  alert: 'infraFocus',
  combat: 'combatStart',
  mid_combat: 'midCombat',
  casualties: 'peopleDying',
  unhappy: 'peopleUnhappy',
  post_combat: 'postCombat',
  recovery: 'recovery',
  long_session: 'keepGoing',
  very_long: 'bedtime',
};

const CROSSFADE_DURATION = 2.5; // seconds
const LONG_SESSION_MS = 60 * 60 * 1000; // 60 minutes
const VERY_LONG_SESSION_MS = 90 * 60 * 1000; // 90 minutes

// Late-night (10pm–6am): transition to calmer tracks sooner
const LATE_NIGHT_LONG_MS = 15 * 60 * 1000; // 15 minutes
const LATE_NIGHT_VERY_LONG_MS = 30 * 60 * 1000; // 30 minutes
const LATE_NIGHT_START_HOUR = 22; // 10pm
const LATE_NIGHT_END_HOUR = 6;   // 6am

// ── MusicManager ──────────────────────────────────────────────────────────────

export class MusicManager {
  private ctx: AudioContext | null = null;
  private musicGain: GainNode | null = null;
  private initialized = false;

  private bufferCache = new Map<string, AudioBuffer>();
  private currentSource: AudioBufferSourceNode | null = null;
  private currentFadeGain: GainNode | null = null;
  private currentState: MusicGameState = 'loading';

  // Progress sequence: monotonically increasing ID; incrementing cancels any
  // running sequence. Exposed for testing.
  progressSequenceId = 0;

  // Crossfade generation: incremented on each crossfadeTo call so that a stale
  // async crossfade (still loading its buffer) does not start after a newer one.
  private crossfadeGeneration = 0;
  private progressAltKeys: TrackKey[] = ['progressAlt1', 'progressAlt2', 'progressAlt3'];

  private sessionStartMs = 0;
  private sessionTimer: ReturnType<typeof setInterval> | null = null;

  /** Initialize with AudioContext and the music GainNode from AudioEngine. */
  init(ctx: AudioContext, musicGain: GainNode): void {
    if (this.initialized) return;
    this.initialized = true;

    this.ctx = ctx;
    this.musicGain = musicGain;
    this.sessionStartMs = Date.now();

    // Session timer: check every minute
    this.sessionTimer = setInterval(() => this.checkSessionTimer(), 60_000);

    // Eagerly preload the two most-needed tracks into the buffer cache so
    // playback starts immediately without waiting on a fetch round-trip.
    // Only play the initial track if the game hasn't set a specific state yet —
    // if setState was called while the preload was in flight, that track wins.
    void this.preloadTracks(['beginSlowly', 'cosmosIsPeaceful']).then(() => {
      if (this.currentState === 'loading') {
        void this.playTrack('beginSlowly', false);
      }
    });
  }

  /** Preload a set of tracks into the buffer cache without playing them. */
  private async preloadTracks(keys: TrackKey[]): Promise<void> {
    await Promise.all(keys.map((k) => this.loadBuffer(k)));
  }

  /**
   * Update the music state. Call this whenever game state changes.
   * Ignores redundant transitions to the same state.
   */
  setState(state: MusicGameState): void {
    if (state === this.currentState) return;

    // Session-time overrides: long session tracks take precedence once active
    if (this.currentState === 'very_long') return;
    if (this.currentState === 'long_session' && state !== 'very_long' && state !== 'combat' &&
        state !== 'mid_combat' && state !== 'casualties') return;

    this.currentState = state;
    const trackKey = STATE_TRACK[state];
    // Invalidate any in-flight progress sequence
    this.progressSequenceId++;
    void this.crossfadeTo(trackKey, state === 'progress');
  }

  getState(): MusicGameState {
    return this.currentState;
  }

  /**
   * Skip to the next ambient track in a fixed rotation.
   * Works regardless of current game state — useful for a manual skip button.
   */
  skipTrack(): void {
    const ambientCycle: TrackKey[] = [
      'beginSlowly', 'cosmosIsPeaceful', 'spaceIsDeep',
      'mineQuietly', 'focusAndMine', 'industrialProgress',
    ];
    this._ambientCycleIdx = (this._ambientCycleIdx + 1) % ambientCycle.length;
    this.progressSequenceId++; // cancel any running progress sequence
    void this.crossfadeTo(ambientCycle[this._ambientCycleIdx], false);
  }

  private _ambientCycleIdx = 0;

  dispose(): void {
    if (this.sessionTimer !== null) {
      clearInterval(this.sessionTimer);
      this.sessionTimer = null;
    }
    this.fadeOutCurrent(0.5);
    this.ctx = null;
    this.musicGain = null;
    this.initialized = false;
  }

  // ── Private ───────────────────────────────────────────────────────────────

  /** Returns true when local time is between 10pm and 6am. */
  private isLateNight(): boolean {
    const hour = new Date().getHours();
    return hour >= LATE_NIGHT_START_HOUR || hour < LATE_NIGHT_END_HOUR;
  }

  private checkSessionTimer(): void {
    const elapsed = Date.now() - this.sessionStartMs;
    const lateNight = this.isLateNight();
    const veryLongThreshold = lateNight ? LATE_NIGHT_VERY_LONG_MS : VERY_LONG_SESSION_MS;
    const longThreshold = lateNight ? LATE_NIGHT_LONG_MS : LONG_SESSION_MS;

    if (elapsed >= veryLongThreshold && this.currentState !== 'very_long') {
      this.setState('very_long');
    } else if (elapsed >= longThreshold && this.currentState !== 'long_session' &&
               this.currentState !== 'very_long') {
      this.setState('long_session');
    }
  }

  private async loadBuffer(key: TrackKey): Promise<AudioBuffer | null> {
    const filename = TRACKS[key];
    const cached = this.bufferCache.get(filename);
    if (cached) return cached;

    if (!this.ctx) return null;
    try {
      const url = TRACK_BASE + encodeURIComponent(filename);
      const res = await fetch(url);
      if (!res.ok) return null;
      const raw = await res.arrayBuffer();
      const buf = await this.ctx.decodeAudioData(raw);
      this.bufferCache.set(filename, buf);
      return buf;
    } catch {
      return null;
    }
  }

  private async playTrack(key: TrackKey, loop: boolean): Promise<void> {
    if (!this.ctx || !this.musicGain) return;

    const buf = await this.loadBuffer(key);
    if (!buf) return;

    const fadeGain = this.ctx.createGain();
    fadeGain.gain.value = 1;
    fadeGain.connect(this.musicGain);

    const source = this.ctx.createBufferSource();
    source.buffer = buf;
    source.loop = loop;
    source.connect(fadeGain);

    this.currentSource = source;
    this.currentFadeGain = fadeGain;

    source.start();
  }

  /**
   * Play a track and return a Promise that resolves when the track ends.
   * For looping tracks, resolves immediately (they never end naturally).
   * Updates currentSource / currentFadeGain so fadeOutCurrent works.
   */
  async playTrackAwaitable(key: TrackKey, loop: boolean): Promise<void> {
    if (!this.ctx || !this.musicGain) return;

    const buf = await this.loadBuffer(key);
    if (!buf || !this.ctx || !this.musicGain) return;

    const fadeGain = this.ctx.createGain();
    fadeGain.gain.value = 1;
    fadeGain.connect(this.musicGain);

    const source = this.ctx.createBufferSource();
    source.buffer = buf;
    source.loop = loop;
    source.connect(fadeGain);

    this.currentSource = source;
    this.currentFadeGain = fadeGain;
    source.start();

    if (!loop) {
      await new Promise<void>((resolve) => {
        source.onended = () => resolve();
      });
    }
  }

  /**
   * Drive the progress music sequence using async/await so the state machine
   * is linear and easy to follow.
   *
   * Called after crossfadeTo plays the initial progressBase track. Sequences:
   *   longer → altX → base → longer → altX → base → …
   *
   * seqId guards against stale sequences: if progressSequenceId has advanced
   * (because the game state changed), the sequence exits cleanly.
   */
  async runProgressSequence(seqId: number): Promise<void> {
    const active = () =>
      seqId === this.progressSequenceId && this.currentState === 'progress';

    if (!active()) return;

    // First leg: progressLonger (progressBase was played by crossfadeTo)
    await this.playTrackAwaitable('progressLonger', false);

    while (active()) {
      // Random alt ending
      const idx = Math.floor(Math.random() * this.progressAltKeys.length);
      await this.playTrackAwaitable(this.progressAltKeys[idx], false);
      if (!active()) return;

      // Loop back through base then longer
      await this.playTrackAwaitable('progressBase', false);
      if (!active()) return;

      await this.playTrackAwaitable('progressLonger', false);
    }
  }

  private fadeOutCurrent(duration: number): void {
    if (!this.ctx || !this.currentFadeGain || !this.currentSource) return;
    const now = this.ctx.currentTime;
    const gain = this.currentFadeGain;
    const src = this.currentSource;
    gain.gain.linearRampToValueAtTime(0, now + duration);
    setTimeout(() => {
      try { src.stop(); } catch { /* already stopped */ }
      try { gain.disconnect(); } catch { /* already disconnected */ }
    }, duration * 1000 + 100);
    this.currentSource = null;
    this.currentFadeGain = null;
  }

  private async crossfadeTo(key: TrackKey, sequenced: boolean): Promise<void> {
    if (!this.ctx || !this.musicGain) return;

    const gen = ++this.crossfadeGeneration;

    // Fade out current
    this.fadeOutCurrent(CROSSFADE_DURATION);

    // Load new track
    const buf = await this.loadBuffer(key);
    if (!buf) return;

    // A newer crossfade was requested while we were loading — bail out
    if (gen !== this.crossfadeGeneration) return;

    // Fade in new track
    const fadeGain = this.ctx.createGain();
    fadeGain.gain.setValueAtTime(0, this.ctx.currentTime);
    fadeGain.gain.linearRampToValueAtTime(1, this.ctx.currentTime + CROSSFADE_DURATION);
    fadeGain.connect(this.musicGain);

    const source = this.ctx.createBufferSource();
    source.buffer = buf;
    source.loop = !sequenced;
    source.connect(fadeGain);

    this.currentSource = source;
    this.currentFadeGain = fadeGain;

    source.start();

    if (sequenced && !source.loop) {
      const seqId = this.progressSequenceId;
      source.onended = () => {
        if (source === this.currentSource && this.currentState === 'progress') {
          void this.runProgressSequence(seqId);
        }
      };
    }
  }
}

// ── Singleton ─────────────────────────────────────────────────────────────────

export const musicManager = new MusicManager();
