/**
 * Culture Panel (U key)
 *
 * Displays the fleet's cultural dimensions (autonomy, isolation, anomaly
 * exposure, cohesion) as score bars and lists active cultural traits.
 */

import { TRAIT_THRESHOLDS, TRAIT_METADATA, FLEET_COLOR_PALETTES } from '../sim/culture';
import type { CultureScores, CultureTrait } from '../shared/cultureTypes';
import type { SimCultureStateMessage } from '../sim/messages';
import type { IsolationTrait, DialectWord } from '../sim/colonyDialect';
import { getBarrierLabel } from '../sim/colonyDialect';
import { registerHudButton } from './hudButtonBar';
import { safeHtml } from './utils/safeHtml';

// ── State ──────────────────────────────────────────────────────────────────────

let panel: HTMLDivElement | null = null;
let visible = false;
let latestState: SimCultureStateMessage['payload'] | null = null;
let hudBtn: HTMLButtonElement | null = null;
let manifestoSubmitCallback: ((result: { presetId: string | null; text: string }) => void) | null = null;
let fleetColorSubmitCallback: ((paletteId: string) => void) | null = null;

// ── Trait progress helper (exported for testing) ───────────────────────────────

/** Returns trait progress data for a given dimension key, or null if no trait maps to it. */
export function getTraitProgressForDimension(
  dimKey: keyof CultureScores,
  score: number,
  activeTraits: CultureTrait[],
): { trait: CultureTrait; threshold: number; isActive: boolean } | null {
  for (const [trait, { dimension, min }] of Object.entries(TRAIT_THRESHOLDS) as [CultureTrait, { dimension: keyof CultureScores; min: number }][]) {
    if (dimension === dimKey) {
      return { trait, threshold: min, isActive: activeTraits.includes(trait) };
    }
  }
  return null;
}

// ── Public API ─────────────────────────────────────────────────────────────────

export function initCultureHudButton(): void {
  if (hudBtn) return;
  hudBtn = registerHudButton('\u{1F9EC} Culture', toggleCulturePanel, 'Fleet culture (U key)');
}

export function updateCulturePanel(state: SimCultureStateMessage['payload']): void {
  latestState = state;
  if (visible) renderPanel();
  updateHudButtonLabel(state);
}

/** Pulse the HUD button briefly to signal a new trait activation. */
export function pulseCultureHudButton(): void {
  if (!hudBtn) return;
  hudBtn.style.boxShadow = '0 0 8px 2px rgba(160,120,255,0.8)';
  hudBtn.style.borderColor = 'rgba(160,120,255,0.9)';
  setTimeout(() => {
    if (!hudBtn) return;
    hudBtn.style.boxShadow = '';
    hudBtn.style.borderColor = 'rgba(100,150,255,0.55)';
  }, 1500);
}

export function toggleCulturePanel(): void {
  if (visible) hidePanel();
  else showPanel();
}

export function hideCulturePanel(): void {
  hidePanel();
}

/** Register a callback for manifesto edits from the culture panel. */
export function setManifestoSubmitCallback(cb: (result: { presetId: string | null; text: string }) => void): void {
  manifestoSubmitCallback = cb;
}

/** Register a callback for fleet color palette selection. */
export function setFleetColorSubmitCallback(cb: (paletteId: string) => void): void {
  fleetColorSubmitCallback = cb;
}

// ── Panel lifecycle ────────────────────────────────────────────────────────────

function showPanel(): void {
  visible = true;
  if (!panel) buildPanel();
  renderPanel();
  panel!.style.display = 'flex';
  showCultureIntroOnce();
}

function hidePanel(): void {
  visible = false;
  if (panel) panel.style.display = 'none';
}

function buildPanel(): void {
  panel = document.createElement('div');
  panel.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(4,6,14,0.82);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 180;
    backdrop-filter: blur(3px);
  `;
  panel.addEventListener('click', (e) => {
    if (e.target === panel) hidePanel();
  });
  document.body.appendChild(panel);
}

// ── First-open intro modal ──────────────────────────────────────────────────────

const CULTURE_INTRO_KEY = 'asteroid_miner_culture_intro_shown';

function showCultureIntroOnce(): void {
  try {
    if (sessionStorage.getItem(CULTURE_INTRO_KEY)) return;
    sessionStorage.setItem(CULTURE_INTRO_KEY, '1');
  } catch {
    // sessionStorage unavailable — show anyway
  }

  const overlay = document.createElement('div');
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.7);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 200;
    backdrop-filter: blur(2px);
  `;

  const modal = document.createElement('div');
  modal.style.cssText = `
    background: rgba(8,12,24,0.98);
    border: 1px solid rgba(100,140,255,0.35);
    border-radius: 10px;
    padding: 28px 32px;
    max-width: 420px;
    font-family: 'Courier New', monospace;
    color: #c0d0f0;
    box-shadow: 0 8px 40px rgba(0,0,0,0.8);
    text-align: center;
  `;

  const title = document.createElement('div');
  title.style.cssText = 'font-size:13px;color:#7090e0;letter-spacing:0.1em;text-transform:uppercase;margin-bottom:16px;';
  title.textContent = 'Why Culture Matters';
  modal.appendChild(title);

  const body = document.createElement('div');
  body.style.cssText = 'font-size:11px;color:#8a9aba;line-height:1.7;margin-bottom:20px;text-align:left;';
  body.textContent = "Your mining robots are autonomous AIs. The way you deploy them \u2014 where they go, what they study, how they work together \u2014 shapes who they become. This is their culture. Factions notice. Your fleet's identity opens doors\u2026 and closes others.";
  modal.appendChild(body);

  const dismissBtn = document.createElement('button');
  dismissBtn.textContent = 'Understood';
  dismissBtn.style.cssText = `
    background: rgba(30,50,90,0.6);
    border: 1px solid rgba(100,140,255,0.4);
    border-radius: 4px;
    color: #7090e0;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    padding: 6px 20px;
    cursor: pointer;
    letter-spacing: 0.05em;
  `;
  dismissBtn.addEventListener('click', () => overlay.remove());
  modal.appendChild(dismissBtn);

  overlay.appendChild(modal);
  overlay.addEventListener('click', (e) => {
    if (e.target === overlay) overlay.remove();
  });
  document.body.appendChild(overlay);
}

// ── Rendering ──────────────────────────────────────────────────────────────────


