import { getUsageSummary, getSessionUsageSummary, tokensToDollars } from '../../advisor/usage';
import { state } from './state';
import { safeHtml } from '../utils/safeHtml';

export function updateUsageSummaryEl(): void {
  if (!state.usageSummaryEl) return;
  const summary = getUsageSummary();
  const usedK = (summary.tokensUsed / 1000).toFixed(1);
  const capK = (summary.budgetCapTokens / 1000).toFixed(0);
  const costStr = summary.estimatedCostUsd < 0.01
    ? `<$0.01`
    : `$${summary.estimatedCostUsd.toFixed(2)}`;
  const color = summary.isOverBudget
    ? '#ef4444'
    : summary.tokensUsed / summary.budgetCapTokens > 0.8
      ? '#f59e0b'
      : 'rgba(158, 207, 223, 0.6)';
  state.usageSummaryEl.style.color = color;
  const remainingUsd = tokensToDollars(summary.budgetRemainingTokens);
  const remainingStr = remainingUsd < 0.01
    ? '<$0.01'
    : `$${remainingUsd.toFixed(2)}`;
  state.usageSummaryEl.innerHTML = safeHtml`
    <span>${usedK}k / ${capK}k tok</span>
    <span>~${costStr} today · ${remainingStr} remaining</span>
  `;
}

export function updateSessionUsageEl(): void {
  if (!state.sessionUsageEl || !state.sessionCapNoticeEl) return;
  const session = getSessionUsageSummary();
  const totalK = session.totalTokens >= 1000
    ? `${(session.totalTokens / 1000).toFixed(1)}k`
    : String(session.totalTokens);
  state.sessionUsageEl.textContent = `ARIA \u00b7 ${totalK} tokens used this session`;

  // Show/hide the soft-cap notice
  if (session.isOverBudget && !session.playerOptedIn) {
    state.sessionCapNoticeEl.style.display = 'flex';
    state.sessionUsageEl.style.color = '#f59e0b';
  } else {
    state.sessionCapNoticeEl.style.display = 'none';
    state.sessionUsageEl.style.color = 'rgba(158, 207, 223, 0.6)';
  }
}

export function refreshUsageSummary(): void {
  updateUsageSummaryEl();
  updateSessionUsageEl();
}
