/**
 * Transient cluster handlers: sim:transient_cluster_spawned, update, expired.
 *
 * Design decision (MUL-3262): transient cluster events are NOT surfaced as
 * notifications or ARIA broadcasts. They are transient background mechanics —
 * the player sees them via the HUD countdown only. Previous attempts to
 * throttle cluster broadcasts failed 3 times; the correct fix is to remove
 * them from the notification path entirely.
 */
import type {
  WorkerToMainMessage,
  SimTransientClusterUpdateMessage,
  SimTransientClusterExpiredMessage,
} from '../sim/messages';
import { updateClusterCountdownHUD, hideClusterCountdownHUD } from '../ui/hud';
import type { HandlerMap } from './types';

export function registerTransientClusterHandlers(): HandlerMap {
  return {
    'sim:transient_cluster_spawned': (_msg: WorkerToMainMessage) => {
      // No notification, no ARIA broadcast — HUD countdown is sufficient.
      // Cluster position is visible on the minimap via entity rendering.
    },

    'sim:transient_cluster_update': (msg: WorkerToMainMessage) => {
      const m = msg as SimTransientClusterUpdateMessage;
      updateClusterCountdownHUD(
        m.payload.clusters.map((c) => ({ clusterId: c.clusterId, ticksRemaining: c.ticksRemaining })),
      );
    },

    'sim:transient_cluster_expired': (_msg: WorkerToMainMessage) => {
      hideClusterCountdownHUD();
    },
  };
}
