/**
 * Faction System
 *
 * Three AI-controlled rival mining factions compete with the player.
 * Faction AI decisions use a simple utility function (not LLM).
 * LLM diplomacy is handled on the main thread when the player contacts a faction.
 *
 * Each faction:
 *  - Has a fixed home base somewhere in the belt
 *  - Mines nearby asteroids at a fixed rate (simulated, not full ECS)
 *  - Tracks disposition toward the player (-100 Hostile → +100 Allied)
 *  - Reacts to player actions (nearby mining, resource trades, threats)
 */

import {
  FACTION_DEFS,
  FACTION_IDS,
  factionPairKey,
  DECISION_INTERVAL_TICKS,
  MINING_RATE,
  TERRITORY_VIOLATION_THRESHOLD,
  TERRITORY_HOSTILITY_DELTA,
  SHARED_ANOMALY_BONUS,
  TRADE_BONUS,
  INTER_FACTION_TERRITORY_DELTA,
  DISPUTE_MESSAGE_COOLDOWN,
  WAR_DISPOSITION_THRESHOLD,
  SILENCE_PROTOCOL_DETECTION_MULT,
} from './factionDefs.js';
import type {
  FactionId,
  FactionState,
  FactionSystemState,
  FactionTickParams,
  BorderDispute,
} from './factionDefs.js';

export { WAR_DISPOSITION_THRESHOLD };

// ── Tick ───────────────────────────────────────────────────────────────────────

export function tickFactions(state: FactionSystemState, params: FactionTickParams): BorderDispute[] {
  if (!state.initialized) return [];

  for (const faction of state.factions) {
    tickOneFaction(faction, params);
  }

  return tickInterFactionTerritoryDisputes(state, params);
}

function tickOneFaction(faction: FactionState, params: FactionTickParams): void {
  const def = FACTION_DEFS[faction.id];
  const { getAsteroidHealth, damageAsteroid, playerRobotPositions, rng } = params;

  // Check for player robots inside our territory
  let violatorCount = 0;
  for (const rp of playerRobotPositions) {
    const dx = rp.x - faction.base.x;
    const dz = rp.z - faction.base.z;
    const dist = Math.sqrt(dx * dx + dz * dz);
    if (dist < TERRITORY_VIOLATION_THRESHOLD) {
      violatorCount++;
    }
  }

  // Apply disposition penalty for territory violations (capped at -100)
  if (violatorCount > 0 && def.territorialness > 0.5) {
    const aggMult = params.aggressionMultiplier ?? 1;
    const silenceMult = params.silenceProtocolActive ? SILENCE_PROTOCOL_DETECTION_MULT : 1;
    faction.disposition = Math.max(
      -100,
      faction.disposition + TERRITORY_HOSTILITY_DELTA * violatorCount * def.territorialness * aggMult * silenceMult,
    );
  }

  // AI decision making
  faction.decisionTimer--;
  if (faction.decisionTimer <= 0) {
    faction.decisionTimer = DECISION_INTERVAL_TICKS + Math.floor(rng() * 300);
    makeFactionDecision(faction, params);
  }

  // Mine the contested asteroid (if still alive)
  if (faction.contestingAsteroid >= 0) {
    const health = getAsteroidHealth(faction.contestingAsteroid);
    if (health <= 0) {
      // Asteroid depleted — find a new one
      faction.contestingAsteroid = -1;
      faction.goal = 'mine';
    } else {
      const miningPower = faction.robotCount * MINING_RATE * def.miningMultiplier;
      damageAsteroid(faction.contestingAsteroid, miningPower);
      // Accumulate resources
      faction.resources.iron += miningPower * 0.6;
      faction.resources.carbon += miningPower * 0.2;
      faction.resources.silicon += miningPower * 0.2;
    }
  }

  // Keep recent events list bounded
  if (faction.recentEvents.length > 10) {
    faction.recentEvents = faction.recentEvents.slice(-10);
  }
}

function makeFactionDecision(faction: FactionState, params: FactionTickParams): void {
  const def = FACTION_DEFS[faction.id];
  const { asteroidEntities, getAsteroidPos, getAsteroidHealth, rng, tick } = params;

  // Find a suitable asteroid near this faction's base
  let bestEid = -1;
  let bestScore = -Infinity;

  for (const eid of asteroidEntities) {
    const health = getAsteroidHealth(eid);
    if (health <= 0) continue;
    const pos = getAsteroidPos(eid);
    const dx = pos.x - faction.base.x;
    const dz = pos.z - faction.base.z;
    const dist = Math.sqrt(dx * dx + dz * dz);

    // Score: prefer closer, healthier asteroids
    const distScore = 1 / (1 + dist / 5000);
    const healthScore = health / 500;
    const randomFuzz = rng() * 0.2;

    // Strategy modifier
    let stratMod = 1.0;
    if (def.strategy === 'expansion') stratMod = 1.0 + dist / 20000; // reach further
    if (def.strategy === 'efficiency') stratMod = healthScore * 2; // prefer rich asteroids

    const score = (distScore + healthScore + randomFuzz) * stratMod;
    if (score > bestScore) {
      bestScore = score;
      bestEid = eid;
    }
  }

  if (bestEid >= 0) {
    if (faction.contestingAsteroid !== bestEid) {
      faction.contestingAsteroid = bestEid;
      const pos = getAsteroidPos(bestEid);
      faction.recentEvents.push({
        text: `${FACTION_DEFS[faction.id].name} targeting asteroid at (${Math.round(pos.x)}, ${Math.round(pos.z)})`,
        tick,
      });
    }
    faction.goal = 'mine';
  } else {
    faction.goal = 'idle';
  }
}

// ── Inter-faction territory disputes ──────────────────────────────────────────

/**
 * Check if any faction is mining an asteroid inside another faction's territory.
 * Worsen inter-faction disposition accordingly and return any new disputes.
 */
function tickInterFactionTerritoryDisputes(
  state: FactionSystemState,
  params: FactionTickParams,
): BorderDispute[] {
  const disputes: BorderDispute[] = [];

  for (const factionA of state.factions) {
    if (factionA.contestingAsteroid < 0) continue;
    const asteroidPos = params.getAsteroidPos(factionA.contestingAsteroid);

    for (const factionB of state.factions) {
      if (factionA.id === factionB.id) continue;

      // Is faction A mining inside faction B's territory?
      const dx = asteroidPos.x - factionB.base.x;
      const dz = asteroidPos.z - factionB.base.z;
      const dist = Math.sqrt(dx * dx + dz * dz);

      if (dist < factionB.territoryRadius) {
        // Territory violation — worsen inter-faction relations
        const key = factionPairKey(factionA.id, factionB.id);
        const territorialness = FACTION_DEFS[factionB.id].territorialness;
        const aggMult = params.aggressionMultiplier ?? 1;
        state.interFactionDispositions[key] = Math.max(
          -100,
          state.interFactionDispositions[key] + INTER_FACTION_TERRITORY_DELTA * territorialness * aggMult,
        );

        // Rate-limit border dispute messages
        const current = state.interFactionDispositions[key];
        if (
          current < -20 &&
          params.tick - state.lastDisputeTick[key] >= DISPUTE_MESSAGE_COOLDOWN
        ) {
          state.lastDisputeTick[key] = params.tick;
          disputes.push({
            factionA: factionA.id,
            factionB: factionB.id,
            atWar: current <= WAR_DISPOSITION_THRESHOLD,
            disposition: current,
          });

          // Log event on both factions
          const nameA = FACTION_DEFS[factionA.id].name;
          const nameB = FACTION_DEFS[factionB.id].name;
          const eventText = current <= WAR_DISPOSITION_THRESHOLD
            ? `${nameA} and ${nameB} are at war!`
            : `Border tension between ${nameA} and ${nameB}`;
          factionA.recentEvents.push({ text: eventText, tick: params.tick });
          factionB.recentEvents.push({ text: eventText, tick: params.tick });
        }
      }
    }
  }

  return disputes;
}

/** Get the inter-faction disposition for a specific pair */
export function getInterFactionDisposition(
  state: FactionSystemState,
  a: FactionId,
  b: FactionId,
): number {
  return state.interFactionDispositions[factionPairKey(a, b)];
}

// ── Player actions ─────────────────────────────────────────────────────────────

/** Called when the player shares an anomaly discovery with a faction. */
export function shareAnomalyWithFaction(
  state: FactionSystemState,
  factionId: FactionId,
  tick: number,
  diplomacyMultiplier = 1,
): void {
  const faction = state.factions[factionId];
  if (!faction) return;
  const def = FACTION_DEFS[factionId];
  const baseBonus = def.strategy === 'research' ? SHARED_ANOMALY_BONUS * 2 : SHARED_ANOMALY_BONUS * 0.5;
  const effectiveBonus = baseBonus * diplomacyMultiplier;
  faction.disposition = Math.min(100, faction.disposition + effectiveBonus);
  const barrierNote = diplomacyMultiplier < 0.9 ? ' (cultural barrier reduced impact)' : '';
  faction.recentEvents.push({ text: `Anomaly data shared — relations improved${barrierNote}`, tick });
}

/** Called when the player proposes a resource trade (simple fixed bonus). */
export function tradeResourcesWithFaction(
  state: FactionSystemState,
  factionId: FactionId,
  tick: number,
  diplomacyMultiplier = 1,
): void {
  const faction = state.factions[factionId];
  if (!faction) return;
  const effectiveBonus = TRADE_BONUS * diplomacyMultiplier;
  faction.disposition = Math.min(100, faction.disposition + effectiveBonus);
  const barrierNote = diplomacyMultiplier < 0.9 ? ' (cultural barrier reduced impact)' : '';
  faction.recentEvents.push({ text: `Resource trade completed — relations improved${barrierNote}`, tick });
}

/**
 * Player responds to an active trade window offer inline via ARIA.
 * Accept: close window, grant disposition bonus (like trade_resources).
 * Decline: close window, small disposition penalty; faction remembers.
 * Returns the disposition delta applied.
 */
export function respondToTradeWindow(
  state: FactionSystemState,
  factionId: FactionId,
  response: 'accept' | 'decline',
  tick: number,
  diplomacyMultiplier = 1,
): number {
  const faction = state.factions[factionId];
  if (!faction) return 0;

  let delta = 0;

  if (response === 'accept') {
    delta = TRADE_BONUS * diplomacyMultiplier;
    faction.disposition = Math.min(100, faction.disposition + delta);
    faction.recentEvents.push({ text: 'Accepted trade window offer — relations improved', tick });
  } else {
    delta = -3;
    faction.disposition = Math.max(-100, faction.disposition + delta);
    faction.recentEvents.push({ text: 'Declined trade window offer — slight disappointment', tick });
  }

  // Close the trade window regardless
  if (faction.tradeWindow) {
    faction.tradeWindow = null;
    faction.lastTradeWindowTick = tick;
  }

  return delta;
}

/** Called when the player threatens a faction (disposition drop). */
export function threatenFaction(
  state: FactionSystemState,
  factionId: FactionId,
  tick: number,
): void {
  const faction = state.factions[factionId];
  if (!faction) return;
  const def = FACTION_DEFS[factionId];
  const delta = def.strategy === 'expansion' ? -5 : -20; // Helix barely cares
  faction.disposition = Math.max(-100, faction.disposition + delta);
  faction.recentEvents.push({ text: 'Threat issued — relations damaged', tick });
}

/**
 * One-time disposition deltas applied when a culture trait activates.
 * Values are absolute points on the -100..+100 disposition scale.
 * Positive = relations improve, negative = relations worsen.
 */
const { HELIX, ASTRAL, VANGUARD, CERES, TITAN, KUIPER } = FACTION_IDS;
const TRAIT_DISPOSITION_EFFECTS: Record<string, Partial<Record<FactionId, number>>> = {
  XENOAWARE:              { [HELIX]: -5,  [ASTRAL]: 10, [VANGUARD]: 0,  [CERES]: 0,  [TITAN]: -3,  [KUIPER]: 8  },
  AUTONOMOUS_COLLECTIVE:  { [HELIX]: -5,  [ASTRAL]: 0,  [VANGUARD]: 8,  [CERES]: 3,  [TITAN]: 5,   [KUIPER]: -3 },
  ISOLATED_CULTURE:       { [HELIX]: 3,   [ASTRAL]: 5,  [VANGUARD]: 0,  [CERES]: -5, [TITAN]: 0,   [KUIPER]: 10 },
  COHESIVE_FLEET:         { [HELIX]: 10,  [ASTRAL]: 5,  [VANGUARD]: 5,  [CERES]: 5,  [TITAN]: 8,   [KUIPER]: 3  },
};

/** Apply disposition changes when a culture trait activates. */
export function applyCultureTraitDisposition(
  state: FactionSystemState,
  trait: string,
  tick: number,
): void {
  const effects = TRAIT_DISPOSITION_EFFECTS[trait];
  if (!effects) return;

  for (const faction of state.factions) {
    const delta = effects[faction.id] ?? 0;
    if (delta === 0) continue;
    faction.disposition = Math.max(-100, Math.min(100, faction.disposition + delta));
    const label = delta > 0 ? 'improved' : 'worsened';
    faction.recentEvents.push({
      text: `Fleet culture shift detected — relations ${label}`,
      tick,
    });
  }
}

/** Called when the player proposes a territory agreement (positive effect if they honor it). */
export function proposeTerritoryAgreement(
  state: FactionSystemState,
  factionId: FactionId,
  tick: number,
): void {
  const faction = state.factions[factionId];
  if (!faction) return;
  faction.disposition = Math.min(100, faction.disposition + 15);
  faction.recentEvents.push({ text: 'Territory agreement proposed — relations improved', tick });
}

// ── Disposition threshold events ──────────────────────────────────────────────

import type { DispositionEventType } from '../inbox/inboxTypes';

/** Cooldown between disposition events for the same faction (ticks ≈ 2 minutes) */
const DISPOSITION_EVENT_COOLDOWN = 7200;

export interface DispositionEvent {
  factionId: FactionId;
  eventType: DispositionEventType;
  disposition: number;
}

/**
 * Check all factions for reputation threshold crossings and return events.
 * Each event type fires at most once per cooldown per faction.
 */
export function checkDispositionThresholds(
  state: FactionSystemState,
  tick: number,
): DispositionEvent[] {
  const events: DispositionEvent[] = [];

  for (const faction of state.factions) {
    if (tick - faction.lastDispositionEventTick < DISPOSITION_EVENT_COOLDOWN) continue;

    const d = faction.disposition;
    let eventType: DispositionEventType | null = null;

    // Check thresholds from most extreme to least
    if (d <= -60) {
      eventType = 'declaration_of_enmity';
    } else if (d <= -30) {
      eventType = 'warning';
    } else if (d >= 75) {
      eventType = 'emissary_visit';
    } else if (d >= 50) {
      eventType = 'trade_offer_bonus';
    }

    if (eventType) {
      faction.lastDispositionEventTick = tick;
      events.push({ factionId: faction.id, eventType, disposition: d });
    }
  }

  return events;
}

/**
 * Apply the player's response to a disposition event.
 * Returns the disposition delta applied.
 */
export function applyDispositionEventResponse(
  state: FactionSystemState,
  factionId: FactionId,
  eventType: DispositionEventType,
  response: 'accept' | 'reject' | 'ignore',
  tick: number,
): number {
  const faction = state.factions[factionId];
  if (!faction) return 0;

  let delta = 0;
  let eventText = '';

  switch (eventType) {
    case 'trade_offer_bonus':
      if (response === 'accept') {
        delta = 10;
        eventText = 'Accepted trade offer — relations strengthened';
      } else if (response === 'reject') {
        delta = -5;
        eventText = 'Rejected trade offer — slight disappointment';
      }
      break;
    case 'warning':
      if (response === 'accept') {
        delta = 15;
        eventText = 'Acknowledged warning, promised restraint — tensions eased';
      } else if (response === 'reject') {
        delta = -10;
        eventText = 'Dismissed warning — hostility deepened';
      }
      break;
    case 'emissary_visit':
      if (response === 'accept') {
        delta = 20;
        eventText = 'Welcomed emissary — alliance strengthened';
      } else if (response === 'reject') {
        delta = -15;
        eventText = 'Turned away emissary — relations damaged';
      }
      break;
    case 'declaration_of_enmity':
      if (response === 'accept') {
        delta = 10;
        eventText = 'Offered concessions to hostile faction — tensions reduced slightly';
      } else if (response === 'reject') {
        delta = -20;
        eventText = 'Defied declaration of enmity — open conflict';
      }
      break;
  }

  if (delta !== 0) {
    faction.disposition = Math.max(-100, Math.min(100, faction.disposition + delta));
    faction.recentEvents.push({ text: eventText, tick });
  }

  return delta;
}

