/**
 * Data Dashboard
 *
 * Tabbed panel toggled by D key. Four tabs:
 *   Resources  — stockpiles, rates, storage utilization
 *   Fleet      — robot type/state breakdown, efficiency
 *   Exploration— anomaly log, entity sightings
 *   Timeline   — resource history line chart (Canvas 2D)
 */

import { attachTooltip } from './tooltip';
import { playSfx } from '../audio/sfxEngine';
import { registerHudButton } from './hudButtonBar';
import { MINERAL_FIELDS } from '../sim/minerals';
import { safeHtml } from './utils/safeHtml';
import {
  getRobotEid,
  getRobotX,
  getRobotY,
  getRobotZ,
  getRobotType,
  getRobotState,
  getRobotEnergyPct,
} from '../sim/bufferLayout';
import {
  ResourceSample,
  FleetSnapshot,
  ExplorationEntry,
  AnomalySnapshot,
  SAMPLE_INTERVAL_TICKS,
  RESOURCE_LABELS,
  RESOURCE_COLORS,
} from './dashboard/types';
import { sectionHeader, barRow, formatNum, capitalize } from './dashboard/helpers';
import { renderFleetTab, invalidateFleetRoster } from './dashboard/fleetTab';
import { renderExplorationTab } from './dashboard/explorationTab';
import { renderTimelineTab, invalidateTimelineCanvas } from './dashboard/timelineTab';
// ── Constants ────────────────────────────────────────────────────────────────

const MAX_SAMPLES = 500;

type TabName = 'resources' | 'fleet' | 'exploration' | 'timeline';

// ── State ────────────────────────────────────────────────────────────────────

const resourceHistory: ResourceSample[] = [];
let latestResources: ResourceSample = { tick: 0, values: new Float32Array(7) };
let latestRefined: Record<string, number> = {};
let latestFleet: FleetSnapshot = {
  countByType: new Int32Array(7),
  countByState: new Int32Array(9),
  productive: 0,
  total: 0,
  avgEnergy: 0,
};
const explorationLog: ExplorationEntry[] = [];

// Robot roster state
let latestRobotBufferSnapshot: Float32Array | null = null;
let latestRobotCountSnapshot = 0;

// Anomaly list state
let latestAnomalies: AnomalySnapshot[] = [];

// Navigation callbacks (set by initDashboard)
let onLocateRobot: ((x: number, y: number, z: number) => void) | null = null;
let onLocateAnomaly: ((x: number, z: number) => void) | null = null;

let panel: HTMLDivElement | null = null;
let visible = false;
let activeTab: TabName = 'resources';
let dirty = false;
let lastSampleTick = -SAMPLE_INTERVAL_TICKS;
let currentColonyName: string | null = null;

// ── Init ──────────────────────────────────────────────────────────────────────

export function initDashboard(
  onRobotLocate?: (x: number, y: number, z: number) => void,
  onAnomalyLocate?: (x: number, z: number) => void,
): void {
  onLocateRobot = onRobotLocate ?? null;
  onLocateAnomaly = onAnomalyLocate ?? null;
  createToggleButton();
}

export function toggleDashboard(): void {
  visible = !visible;
  if (visible) {
    if (!panel) {
      buildPanel();
    } else {
      panel.style.display = 'flex';
    }
    requestAnimationFrame(() => {
      if (panel) {
        panel.style.opacity = '1';
        panel.style.transform = 'translateX(0)';
      }
    });
    dirty = true;
  } else {
    if (panel) {
      panel.style.opacity = '0';
      panel.style.transform = 'translateX(20px)';
      const p = panel;
      setTimeout(() => {
        if (!visible) p.style.display = 'none';
      }, 250);
    }
  }
}

// ── Data update functions (called from main.ts) ───────────────────────────────

export function updateDashboardResources(
  rawStorage: Float32Array,
  refined: Record<string, number>,
  tick: number,
): void {
  latestResources = { tick, values: new Float32Array(rawStorage) };
  latestRefined = refined;

  if (tick - lastSampleTick >= SAMPLE_INTERVAL_TICKS) {
    lastSampleTick = tick;
    resourceHistory.push({ tick, values: new Float32Array(rawStorage) });
    if (resourceHistory.length > MAX_SAMPLES) resourceHistory.shift();
  }

  if (visible) dirty = true;
}

export function updateDashboardFleet(robotBuffer: Float32Array, robotCount: number): void {
  const snap: FleetSnapshot = {
    countByType: new Int32Array(7),
    countByState: new Int32Array(9),
    productive: 0,
    total: robotCount,
    avgEnergy: 0,
  };

  let totalEnergy = 0;
  for (let i = 0; i < robotCount; i++) {
    const type = Math.min(6, getRobotType(robotBuffer, i)) as number;
    const state = getRobotState(robotBuffer, i) as number;
    const energy = getRobotEnergyPct(robotBuffer, i);

    snap.countByType[type]++;
    snap.countByState[state]++;
    totalEnergy += energy;

    // Mining (2) or Hauling (3) = productive
    if (state === 2 || state === 3) snap.productive++;
  }

  snap.avgEnergy = robotCount > 0 ? totalEnergy / robotCount : 0;
  latestFleet = snap;

  // Store snapshot for roster rendering
  latestRobotBufferSnapshot = new Float32Array(robotBuffer);
  latestRobotCountSnapshot = robotCount;

  if (visible) dirty = true;
}

export function updateDashboardAnomalies(anomalies: AnomalySnapshot[]): void {
  latestAnomalies = anomalies.map((a) => ({ ...a }));
  if (visible) dirty = true;
}

export function updateDashboardColonyName(name: string | null): void {
  if (name === currentColonyName) return;
  currentColonyName = name;
  // Update the header text if panel exists
  if (panel) {
    const header = panel.querySelector<HTMLDivElement>('.dash-header-title');
    if (header) {
      const displayName = name ?? 'OPERATIONS';
      header.innerHTML = safeHtml`📊 ${displayName} DASHBOARD`;
    }
  }
}

export function addExplorationEvent(label: string, color: string, tick: number): void {
  explorationLog.unshift({ tick, label, color });
  if (explorationLog.length > 200) explorationLog.pop();
  if (visible) dirty = true;
}

// ── Render ────────────────────────────────────────────────────────────────────

/** Called every render frame from main.ts game loop */
export function renderDashboard(): void {
  if (!visible || !dirty || !panel) return;
  dirty = false;

  const content = panel.querySelector<HTMLDivElement>('.dash-content');
  if (!content) return;

  switch (activeTab) {
    case 'resources':
      renderResourcesTab(content);
      break;
    case 'fleet':
      renderFleetTab(content, {
        fleet: latestFleet,
        robotBuffer: latestRobotBufferSnapshot,
        robotCount: latestRobotCountSnapshot,
        onLocateRobotByEid: onLocateRobot ? locateRobotByEid : null,
      });
      break;
    case 'exploration':
      renderExplorationTab(content, {
        anomalies: latestAnomalies,
        explorationLog,
        onLocateAnomaly,
      });
      break;
    case 'timeline':
      renderTimelineTab(content, { resourceHistory });
      break;
  }
}

// ── Panel builder ─────────────────────────────────────────────────────────────

function buildPanel(): void {
  panel = document.createElement('div');
  panel.id = 'dashboard-panel';
  panel.setAttribute('role', 'complementary');
  panel.setAttribute('aria-label', 'Operations dashboard');
  panel.style.cssText = `
    position: fixed;
    top: 60px;
    right: 8px;
    width: 420px;
    height: 560px;
    background: rgba(8,10,18,0.95);
    border: 1px solid rgba(100,120,200,0.3);
    border-radius: 8px;
    font-family: 'Courier New', monospace;
    font-size: 12px;
    color: #c0c8e0;
    display: flex;
    flex-direction: column;
    z-index: 80;
    box-shadow: 0 4px 24px rgba(0,0,0,0.6);
    opacity: 0;
    transform: translateX(20px);
    transition: opacity 0.25s ease-out, transform 0.25s ease-out;
  `;

  // Header
  const header = document.createElement('div');
  header.style.cssText = `
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 10px 14px 6px;
    border-bottom: 1px solid rgba(100,120,200,0.2);
    flex-shrink: 0;
  `;
  const displayName = currentColonyName ?? 'OPERATIONS';
  header.innerHTML = safeHtml`<span class="dash-header-title" style="color:#a0b0e0;font-weight:bold;letter-spacing:0.05em">📊 ${displayName} DASHBOARD</span>`;

  const closeBtn = document.createElement('button');
  closeBtn.textContent = '×';
  closeBtn.setAttribute('aria-label', 'Close dashboard');
  closeBtn.style.cssText =
    'background:none;border:none;color:#666;cursor:pointer;font-size:18px;line-height:1;padding:0;';
  closeBtn.onclick = () => toggleDashboard();
  header.appendChild(closeBtn);

  // Tabs
  const tabs = document.createElement('div');
  tabs.setAttribute('role', 'tablist');
  tabs.setAttribute('aria-label', 'Dashboard tabs');
  tabs.style.cssText = `
    display: flex;
    gap: 4px;
    padding: 6px 10px 0;
    flex-shrink: 0;
  `;

  const TAB_DEFS: { id: TabName; label: string; tip: string }[] = [
    {
      id: 'resources',
      label: 'Resources',
      tip: 'Raw stockpiles, refined materials\nand per-minute income rates',
    },
    {
      id: 'fleet',
      label: 'Fleet',
      tip: 'Robot count by type and state\nEfficiency, energy, and individual roster',
    },
    {
      id: 'exploration',
      label: 'Exploration',
      tip: 'Discovered anomalies and\nexploration discovery log',
    },
    { id: 'timeline', label: 'Timeline', tip: 'Resource history chart\nShows trends over time' },
  ];

  for (const { id, label, tip } of TAB_DEFS) {
    const btn = document.createElement('button');
    btn.dataset['tab'] = id;
    btn.textContent = label;
    btn.setAttribute('role', 'tab');
    btn.setAttribute('aria-label', `${label} tab`);
    attachTooltip(btn, tip);
    btn.style.cssText = `
      flex: 1;
      padding: 5px 6px;
      background: rgba(40,50,80,0.5);
      border: 1px solid rgba(100,120,200,0.2);
      border-bottom: none;
      border-radius: 4px 4px 0 0;
      color: #8090b0;
      cursor: pointer;
      font-family: 'Courier New', monospace;
      font-size: 11px;
      transition: background 0.15s;
    `;
    btn.onclick = () => { playSfx('ui.tab_switch'); switchTab(id); };
    tabs.appendChild(btn);
  }

  // Content area
  const content = document.createElement('div');
  content.className = 'dash-content';
  content.style.cssText = `
    flex: 1;
    overflow-y: auto;
    padding: 12px 14px;
    scrollbar-width: thin;
    scrollbar-color: rgba(100,120,200,0.3) transparent;
  `;

  panel.appendChild(header);
  panel.appendChild(tabs);
  panel.appendChild(content);
  document.body.appendChild(panel);

  updateTabHighlight();
  dirty = true;
}

function switchTab(tab: TabName): void {
  activeTab = tab;
  invalidateTimelineCanvas();
  invalidateFleetRoster();
  updateTabHighlight();
  clearContent();
  dirty = true;
}

function updateTabHighlight(): void {
  if (!panel) return;
  panel.querySelectorAll<HTMLButtonElement>('button[data-tab]').forEach((btn) => {
    const active = btn.dataset['tab'] === activeTab;
    btn.style.background = active ? 'rgba(60,80,140,0.8)' : 'rgba(40,50,80,0.5)';
    btn.style.color = active ? '#d0e0ff' : '#8090b0';
    btn.style.borderColor = active ? 'rgba(100,140,255,0.4)' : 'rgba(100,120,200,0.2)';
  });
}

function clearContent(): void {
  const content = panel?.querySelector<HTMLDivElement>('.dash-content');
  if (content) content.innerHTML = '';
}

function createToggleButton(): void {
  registerHudButton(
    '📊 Dashboard',
    () => toggleDashboard(),
    'Operations Dashboard (D key)\nResources · Fleet · Exploration · Timeline',
  );
}

// ── Resources tab (kept inline — only 56 lines) ─────────────────────────────

function renderResourcesTab(container: HTMLDivElement): void {
  container.innerHTML = '';

  const rawValues = latestResources.values;
  const maxRaw = Math.max(...Array.from(rawValues), 1);

  container.appendChild(sectionHeader('Raw Stockpiles'));

  for (let i = 0; i < MINERAL_FIELDS.length; i++) {
    container.appendChild(
      barRow(RESOURCE_LABELS[i], rawValues[i], maxRaw, RESOURCE_COLORS[i], formatNum(rawValues[i])),
    );
  }

  // Refined materials
  if (Object.keys(latestRefined).length > 0) {
    container.appendChild(sectionHeader('Refined Materials'));
    const refinedMax = Math.max(...Object.values(latestRefined), 1);
    const refinedEntries = Object.entries(latestRefined).filter(([, v]) => v > 0 || true);
    for (const [key, val] of refinedEntries) {
      container.appendChild(
        barRow(capitalize(key.replace(/_/g, ' ')), val, refinedMax, '#a855f7', formatNum(val)),
      );
    }
  }

  // Income rates (if we have at least 2 samples)
  if (resourceHistory.length >= 2) {
    container.appendChild(sectionHeader('Rates (per minute)'));

    const newest = resourceHistory[resourceHistory.length - 1];
    // Use up to last 60 samples for rate (~60 seconds of data)
    const oldest = resourceHistory[Math.max(0, resourceHistory.length - 60)];
    const dtTicks = Math.max(1, newest.tick - oldest.tick);
    // ticks → minutes: assume 60 ticks/sec, 60 sec/min
    const dtMin = dtTicks / (60 * 60);

    const rates = MINERAL_FIELDS.map((_, i) => (newest.values[i] - oldest.values[i]) / dtMin);
    const maxRate = Math.max(...rates.map(Math.abs), 1);
    for (let i = 0; i < MINERAL_FIELDS.length; i++) {
      const r = rates[i];
      const label = r >= 0 ? `+${formatNum(r)}/m` : `${formatNum(r)}/m`;
      container.appendChild(
        barRow(
          RESOURCE_LABELS[i],
          Math.abs(r),
          maxRate,
          r >= 0 ? RESOURCE_COLORS[i] : '#ef4444',
          label,
        ),
      );
    }
  }
}

// ── Robot EID → live-coordinate lookup ───────────────────────────────────

function locateRobotByEid(eid: number): void {
  if (!onLocateRobot || !latestRobotBufferSnapshot) return;
  for (let i = 0; i < latestRobotCountSnapshot; i++) {
    if (getRobotEid(latestRobotBufferSnapshot, i) === eid) {
      const x = getRobotX(latestRobotBufferSnapshot, i);
      const y = getRobotY(latestRobotBufferSnapshot, i);
      const z = getRobotZ(latestRobotBufferSnapshot, i);
      onLocateRobot(x, y, z);
      return;
    }
  }
}

