/**
 * Aria Dialogue — stage machine, LLM prompt modifiers, and query classification.
 *
 * Evaluates the spectrum dimensions from ariaSpectrum.ts to determine Aria's
 * dialogue stage, generates stage-appropriate LLM personality blocks, and
 * parses classification prefixes from LLM responses.
 *
 * See docs/ARIA_DELEGATION_SPECTRUM.md §4 and §7.
 */

import {
  getSpectrumState,
  setDialogueStage,
  recordInteraction,
  type DialogueStage,
  type DimensionKey,
} from './ariaSpectrum';

// ── Types ────────────────────────────────────────────────────────────────────

export type QueryClassification =
  | 'GOAL_DIRECTIVE'
  | 'PROBLEM_PRESENTATION'
  | 'FACTUAL_QUESTION'
  | 'EXPLORATORY_QUESTION'
  | 'NO_QUERY';

export interface ClassificationResult {
  classification: QueryClassification | null;
  strippedResponse: string;
}

// ── Constants ────────────────────────────────────────────────────────────────

/** Regex to extract [CLASSIFICATION:TYPE] prefix from LLM responses. */
const CLASSIFICATION_RE = /^\s*\[CLASSIFICATION:(GOAL_DIRECTIVE|PROBLEM_PRESENTATION|FACTUAL_QUESTION|EXPLORATORY_QUESTION|NO_QUERY)\]\s*/;

const VALID_CLASSIFICATIONS = new Set<QueryClassification>([
  'GOAL_DIRECTIVE',
  'PROBLEM_PRESENTATION',
  'FACTUAL_QUESTION',
  'EXPLORATORY_QUESTION',
  'NO_QUERY',
]);

/**
 * Thresholds for stage transitions.
 * Partnership composite = average of all 5 dimensions (negative = overtrust, positive = undertrust).
 * We use absolute-value ranges around 0 for partnership, negative for overtrust, positive for undertrust.
 */
const PARTNERSHIP_QUESTIONER_THRESHOLD = 0.15;
const PARTNERSHIP_PEER_THRESHOLD = 0.30;
const PARTNERSHIP_PARTNER_THRESHOLD = 0.50;

const OVERTRUST_EFFICIENT_THRESHOLD = -0.15;
const OVERTRUST_INSTRUMENTAL_THRESHOLD = -0.30;
const OVERTRUST_HOLLOW_THRESHOLD = -0.50;

const UNDERTRUST_AVAILABLE_THRESHOLD = 0.05;
const UNDERTRUST_QUIET_THRESHOLD = 0.25;
const UNDERTRUST_DORMANT_THRESHOLD = 0.45;

/**
 * Classification instruction appended to system prompts so the LLM
 * classifies queries as a side-effect of response generation.
 */
export const CLASSIFICATION_INSTRUCTION =
  'Before responding, classify this query as one of: GOAL_DIRECTIVE, PROBLEM_PRESENTATION, FACTUAL_QUESTION, EXPLORATORY_QUESTION, NO_QUERY. ' +
  'Emit the classification as a prefix in the format [CLASSIFICATION:TYPE] at the very start of your response. ' +
  'This prefix will be stripped before display.';

// ── Personality Blocks (max 200 tokens each, REPLACE by stage) ──────────────

