/**
 * Tech Tree Panel UI
 *
 * Renders the tech tree as a DOM overlay panel showing:
 * - All visible nodes grouped by branch
 * - Node states: locked, available, in-progress, unlocked
 * - Active research progress bar
 * - Click to start research
 */

import type { SerializedTechState } from '../sim/techTree';
import {
  TECH_NODES,
  TECH_BRANCHES,
  TECH_NODE_BY_ID,
  deserializeTechState,
  isTechUnlocked,
  isTechVisible,
  getAvailableNodes,
} from '../sim/techTree';
import { attachTooltip } from './tooltip';
import { registerHudButton } from './hudButtonBar';
import { safeHtml } from './utils/safeHtml';

function formatEta(seconds: number): string {
  if (seconds < 10) return '< 10s';
  if (seconds < 60) return `~${Math.round(seconds)}s`;
  const m = Math.floor(seconds / 60);
  const s = Math.round(seconds % 60);
  return s > 0 ? `~${m}m ${s}s` : `~${m}m`;
}

type StartResearchCallback = (nodeId: string) => void;

const BRANCH_NAMES: Record<number, string> = {
  [TECH_BRANCHES.MINING]: 'Mining',
  [TECH_BRANCHES.LOGISTICS]: 'Logistics',
  [TECH_BRANCHES.ANOMALY]: 'Anomaly Research',
  [TECH_BRANCHES.ENERGY]: 'Energy & Thermal',
  [TECH_BRANCHES.PROPULSION]: 'Propulsion & Navigation',
};

const BRANCH_COLORS: Record<number, string> = {
  [TECH_BRANCHES.MINING]: '#f97316', // orange
  [TECH_BRANCHES.LOGISTICS]: '#22d3ee', // cyan
  [TECH_BRANCHES.ANOMALY]: '#a855f7', // purple
  [TECH_BRANCHES.ENERGY]: '#eab308', // yellow
  [TECH_BRANCHES.PROPULSION]: '#ef4444', // red
};

let panel: HTMLDivElement | null = null;
let isOpen = false;
let onStartResearch: StartResearchCallback | null = null;
let currentTechState: ReturnType<typeof deserializeTechState> | null = null;
let currentRefined: Record<string, number> = {};
let _renderScheduled = false;
let activeTab: number = TECH_BRANCHES.MINING;

// Track current node elements for pulse animation
const nodeEls: Map<string, HTMLDivElement> = new Map();
// Nodes pending a pulse (requested while panel was closed)
const pendingPulse: Set<string> = new Set();

function injectTechPulseKeyframes(): void {
  if (document.getElementById('tech-pulse-style')) return;
  const style = document.createElement('style');
  style.id = 'tech-pulse-style';
  style.textContent = `
    @keyframes techNodeUnlock {
      0%   { box-shadow: 0 0 0 0 #22c55e88; border-color: #22c55e; }
      40%  { box-shadow: 0 0 0 10px #22c55e00; border-color: #22c55e; }
      60%  { box-shadow: 0 0 6px 2px #22c55e66; }
      100% { box-shadow: none; }
    }
  `;
  document.head.appendChild(style);
}

/** Trigger a pulse glow on a newly unlocked tech node. */
export function pulseUnlockedNode(nodeId: string): void {
  injectTechPulseKeyframes();
  const el = nodeEls.get(nodeId);
  if (el) {
    el.style.animation = 'none';
    // Force reflow before re-triggering
    void el.offsetHeight;
    el.style.animation = 'techNodeUnlock 0.8s ease-out forwards';
  } else {
    pendingPulse.add(nodeId);
  }
}

export function initTechTreePanel(callback: StartResearchCallback): void {
  onStartResearch = callback;
  createToggleButton();
}

function createToggleButton(): void {
  registerHudButton(
    '🔬 Research',
    togglePanel,
    'Research technologies (T key)\nUnlock new robots, upgrades and anomaly tools',
  );
}

export function toggleTechTreePanel(): void {
  if (isOpen) {
    isOpen = false;
    if (panel) {
      const p = panel;
      panel = null;
      p.style.opacity = '0';
      p.style.transform = 'translateX(-50%) translateY(-8px)';
      setTimeout(() => p.remove(), 250);
    }
  } else {
    openPanel();
  }
}

function togglePanel(): void {
  toggleTechTreePanel();
}

function openPanel(): void {
  isOpen = true;
  panel = document.createElement('div');
  panel.id = 'tech-tree-panel';
  panel.style.cssText = `
    position: absolute;
    top: 40px;
    left: 50%;
    transform: translateX(-50%) translateY(-8px);
    width: 680px;
    max-height: 70vh;
    overflow-y: auto;
    background: rgba(5, 5, 15, 0.95);
    border: 1px solid #333;
    border-radius: 8px;
    padding: 16px;
    font-family: 'Courier New', monospace;
    font-size: 12px;
    color: #ccc;
    z-index: 200;
    pointer-events: auto;
    box-shadow: 0 0 40px rgba(0,0,0,0.8);
    opacity: 0;
    transition: opacity 0.25s ease-out, transform 0.25s ease-out;
  `;

  renderPanel();

  const hudOverlay = document.getElementById('hud-overlay');
  if (hudOverlay) hudOverlay.appendChild(panel);
  requestAnimationFrame(() => {
    if (panel) {
      panel.style.opacity = '1';
      panel.style.transform = 'translateX(-50%) translateY(0)';
    }
  });
}

function renderPanel(): void {
  if (!panel) return;
  panel.innerHTML = '';
  nodeEls.clear();

  // Header
  const header = document.createElement('div');
  header.style.cssText =
    'display: flex; justify-content: space-between; align-items: center; margin-bottom: 12px;';
  header.innerHTML = `
    <span style="color: #a855f7; font-size: 14px; font-weight: bold;">RESEARCH TREE</span>
    <button id="tech-close-btn" style="background:none;border:none;color:#666;cursor:pointer;font-size:16px;">✕</button>
  `;
  panel.appendChild(header);
  panel.querySelector('#tech-close-btn')?.addEventListener('click', togglePanel);

  // Active research progress
  if (currentTechState?.activeResearch) {
    const ar = currentTechState.activeResearch;
    const pct = Math.min(100, (ar.pointsAccumulated / ar.pointsRequired) * 100);
    const node = TECH_NODE_BY_ID.get(ar.nodeId);
    const progressDiv = document.createElement('div');
    progressDiv.style.cssText = `
      margin-bottom: 16px;
      padding: 10px;
      background: rgba(168, 85, 247, 0.1);
      border: 1px solid rgba(168, 85, 247, 0.4);
      border-radius: 6px;
    `;
    const rate = currentTechState?.researchRate ?? 0;
    const remaining = ar.pointsRequired - ar.pointsAccumulated;
    const etaStr = rate > 0 ? formatEta(remaining / rate) : '';
    progressDiv.innerHTML = safeHtml`
      <div style="color: #a855f7; margin-bottom: 6px;">
        Researching: <strong>${node?.name ?? ar.nodeId}</strong>
        — ${Math.round(pct)}%
        (${Math.round(ar.pointsAccumulated)}/${ar.pointsRequired} pts)
        ${etaStr ? `<span style="color:#888;font-size:10px;"> · ${etaStr} remaining</span>` : ''}
      </div>
      <div style="background: #1a1a2e; border-radius: 3px; height: 8px; overflow: hidden;">
        <div style="background: #a855f7; height: 100%; width: ${pct}%; transition: width 0.3s;"></div>
      </div>
      <div style="margin-top: 4px; color: #666; font-size: 10px;">
        Research rate: ${rate.toFixed(1)} RP/s${rate <= 0.3 ? ' — <span style="color:#f97316">build Researcher robots to speed up research</span>' : ''}
      </div>
    `;
    panel.appendChild(progressDiv);
  } else if (currentTechState && !currentTechState.activeResearch) {
    const hint = document.createElement('div');
    hint.style.cssText = `
      margin-bottom: 12px;
      padding: 8px 10px;
      background: rgba(168,85,247,0.06);
      border: 1px solid rgba(168,85,247,0.2);
      border-radius: 4px;
      color: #8870a0;
      font-size: 11px;
    `;
    hint.innerHTML = '▶ <strong style="color:#c0a0e0">Click a highlighted node below to start research.</strong><br><span style="font-size:10px;opacity:0.7;">Completed research unlocks new robots, upgrades, and abilities.</span>';
    panel.appendChild(hint);
  } else if (!currentTechState) {
    const hint = document.createElement('div');
    hint.style.cssText = 'color: #555; margin-bottom: 12px; font-style: italic;';
    hint.textContent = 'Loading research data...';
    panel.appendChild(hint);
  }

  // Tab bar
  const branches = [TECH_BRANCHES.MINING, TECH_BRANCHES.LOGISTICS, TECH_BRANCHES.ANOMALY, TECH_BRANCHES.ENERGY, TECH_BRANCHES.PROPULSION];
  const tabBar = document.createElement('div');
  tabBar.style.cssText = 'display: flex; gap: 4px; margin-bottom: 12px; flex-wrap: wrap;';
  for (const branch of branches) {
    const color = BRANCH_COLORS[branch];
    const name = BRANCH_NAMES[branch];
    const isActive = branch === activeTab;
    const tab = document.createElement('button');
    tab.style.cssText = `
      background: ${isActive ? `${color}33` : 'rgba(20,20,30,0.8)'};
      border: 1px solid ${isActive ? color : '#444'};
      border-radius: 4px;
      color: ${isActive ? color : '#666'};
      cursor: pointer;
      font-family: 'Courier New', monospace;
      font-size: 10px;
      padding: 4px 10px;
      letter-spacing: 0.5px;
      transition: background 0.15s, color 0.15s;
    `;
    tab.textContent = name;
    tab.addEventListener('click', () => {
      activeTab = branch;
      renderPanel();
    });
    tabBar.appendChild(tab);
  }
  panel.appendChild(tabBar);

  // Active branch nodes
  {
    const branch = activeTab;
    const branchNodes = TECH_NODES.filter((n) => n.branch === branch);
    const color = BRANCH_COLORS[branch];

    const branchDiv = document.createElement('div');
    branchDiv.style.cssText = 'margin-bottom: 16px;';

    const grid = document.createElement('div');
    grid.style.cssText = 'display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px;';

    for (const node of branchNodes) {
      if (currentTechState && !isTechVisible(currentTechState, node.id)) continue;

      const isUnlocked = currentTechState ? isTechUnlocked(currentTechState, node.id) : false;
      const isActive = currentTechState?.activeResearch?.nodeId === node.id;
      const available = currentTechState ? getAvailableNodes(currentTechState) : [];
      const isAvailable = available.some((n) => n.id === node.id);

      let bgColor = 'rgba(20,20,30,0.8)';
      let borderColor = '#333';
      let textColor = '#555';
      let cursor = 'default';

      if (isUnlocked) {
        bgColor = 'rgba(34,197,94,0.1)';
        borderColor = '#22c55e';
        textColor = '#86efac';
      } else if (isActive) {
        bgColor = 'rgba(168,85,247,0.15)';
        borderColor = '#a855f7';
        textColor = '#d8b4fe';
        cursor = 'default';
      } else if (isAvailable) {
        bgColor = `${color}1a`; // hex + 10% alpha
        borderColor = color;
        textColor = '#ccc';
        cursor = 'pointer';
      }

      const nodeDiv = document.createElement('div');
      nodeDiv.style.cssText = `
        background: ${bgColor};
        border: 1px solid ${borderColor};
        border-radius: 6px;
        padding: 8px;
        cursor: ${cursor};
        transition: opacity 0.2s;
      `;

      const costStr = Object.entries(node.resourceCost)
        .map(([r, q]) => `${q} ${r}`)
        .join(', ');

      const effectsStr = node.unlockEffects
        .map((e) => {
          if (e.kind === 'tool_tier') return `Tool T${e.tier}`;
          if (e.kind === 'robot_type') return `+Robot Type`;
          if (e.kind === 'building') return `+${e.buildingType}`;
          if (e.kind === 'efficiency')
            return `+${Math.round((e.multiplier - 1) * 100)}% ${e.system}`;
          if (e.kind === 'narrative_trigger') return `Narrative`;
          return '';
        })
        .filter(Boolean)
        .join(', ');

      const canStart = isAvailable && !isActive && !isUnlocked && currentTechState?.activeResearch === null;
      const blockedByActive = isAvailable && !isActive && !isUnlocked && currentTechState?.activeResearch !== null;
      const startLabel = canStart
        ? `<div style="margin-top:5px;padding:2px 6px;background:${color}33;border:1px solid ${borderColor};border-radius:3px;color:${textColor};font-size:10px;text-align:center;">▶ Start Research</div>`
        : blockedByActive
          ? `<div style="margin-top:5px;color:#555;font-size:10px;font-style:italic;">⏸ Finish current research first</div>`
          : '';
      nodeDiv.innerHTML = safeHtml`
        <div style="color: ${textColor}; font-weight: bold; margin-bottom: 4px; font-size: 11px;">
          ${isUnlocked ? '✓ ' : isActive ? '⚡ ' : ''}${node.name}
        </div>
        <div style="color: #8090a0; font-size: 10px; margin-bottom: 4px; line-height: 1.3;">${node.description}</div>
        ${
          !isUnlocked
            ? `
          <div style="color: #666; font-size: 10px;">${node.researchPoints} pts${costStr ? ` · <span style="color:#999">${costStr}</span>` : ''}</div>
          ${effectsStr ? `<div style="color: ${color}; font-size: 10px; margin-top: 2px;">${effectsStr}</div>` : ''}
          ${startLabel}
        `
            : `<div style="color: #22c55e; font-size: 10px;">✓ Unlocked</div>`
        }
      `;

      // Tooltip: show description, prerequisites and cost for unresearched nodes
      const prereqNames = node.prerequisites
        .map((p) => TECH_NODE_BY_ID.get(p)?.name ?? p)
        .join(', ');
      const nodeCostStr = Object.entries(node.resourceCost)
        .map(([r, q]) => `${q} ${r.replace(/_/g, ' ')}`)
        .join(', ');
      const tipParts: string[] = [node.description];
      if (!isUnlocked) {
        if (prereqNames) tipParts.push(`Requires: ${prereqNames}`);
        if (nodeCostStr) tipParts.push(`Cost: ${nodeCostStr}`);
        tipParts.push(`Research: ${node.researchPoints} pts`);
      } else {
        tipParts.push('Unlocked');
      }
      attachTooltip(nodeDiv, tipParts.join('\n'));

      if (isAvailable && !isActive && !isUnlocked && currentTechState?.activeResearch === null) {
        nodeDiv.addEventListener('click', () => {
          if (onStartResearch) {
            onStartResearch(node.id);
          }
        });
        nodeDiv.addEventListener('mouseenter', () => {
          nodeDiv.style.opacity = '0.8';
        });
        nodeDiv.addEventListener('mouseleave', () => {
          nodeDiv.style.opacity = '1';
        });
      }

      // Track for pulse animation
      nodeEls.set(node.id, nodeDiv);
      if (pendingPulse.has(node.id)) {
        pendingPulse.delete(node.id);
        injectTechPulseKeyframes();
        nodeDiv.style.animation = 'techNodeUnlock 0.8s ease-out forwards';
      }

      grid.appendChild(nodeDiv);
    }

    branchDiv.appendChild(grid);
    panel.appendChild(branchDiv);
  }

  // Refined materials section
  const refinedKeys = Object.keys(currentRefined).filter((k) => (currentRefined[k] ?? 0) > 0);
  if (refinedKeys.length > 0) {
    const refinedDiv = document.createElement('div');
    refinedDiv.style.cssText = `
      margin-top: 12px;
      padding: 8px;
      background: rgba(34,211,238,0.05);
      border: 1px solid rgba(34,211,238,0.2);
      border-radius: 6px;
    `;
    refinedDiv.innerHTML = safeHtml`
      <div style="color: #22d3ee; font-size: 11px; margin-bottom: 6px;">REFINED MATERIALS</div>
      <div style="display: flex; flex-wrap: wrap; gap: 8px;">
        ${refinedKeys
          .map(
            (k) =>
              `<span style="color: #ccc; font-size: 11px;">${k.replace(/_/g, ' ')}: <strong style="color:#22d3ee">${Math.floor(currentRefined[k])}</strong></span>`,
          )
          .join('')}
      </div>
    `;
    panel.appendChild(refinedDiv);
  }
}

export function updateTechTreePanel(
  serializedState: SerializedTechState,
  refined: Record<string, number>,
): void {
  currentTechState = deserializeTechState(serializedState);
  currentRefined = refined;

  if (isOpen && panel && !_renderScheduled) {
    _renderScheduled = true;
    requestAnimationFrame(() => {
      _renderScheduled = false;
      renderPanel();
    });
  }

  // Update button to show active research
  const btn = document.getElementById('tech-tree-btn');
  if (btn && currentTechState?.activeResearch) {
    const ar = currentTechState.activeResearch;
    const pct = Math.round((ar.pointsAccumulated / ar.pointsRequired) * 100);
    btn.textContent = `🔬 Research (${pct}%)`;
    (btn as HTMLButtonElement).style.color = '#a855f7';
  } else if (btn) {
    btn.textContent = '🔬 Research';
  }
}
