/**
 * Comms handlers: sim:comms_message — robot radio transmissions.
 */
import type { WorkerToMainMessage, SimCommsMessage } from '../sim/messages';
import { addCommsMessage, initCommsLog } from '../ui/commsLog';
import type { HandlerMap } from './types';

export function registerCommsHandlers(): HandlerMap {
  let initialized = false;

  return {
    'sim:comms_message': (msg: WorkerToMainMessage) => {
      if (!initialized) {
        initCommsLog();
        initialized = true;
      }
      const { payload } = msg as SimCommsMessage;
      addCommsMessage(payload.robotName, payload.message, payload.category);
    },
  };
}
