/**
 * Worker → main thread message dispatch.
 *
 * Thin router: initialises panel callbacks, then delegates every
 * worker message to the per-subsystem handler registered in
 * src/messageHandlers/.
 */
import * as Sentry from '@sentry/browser';
import type { WorkerToMainMessage } from './sim/messages';
import { initInboxPanel, setInboxProcessing, setInboxSummary } from './ui/inboxPanel';
import { initHabitatPanel } from './ui/habitatPanel';
import { showWorkerCrashModal } from './ui/notifications';
import { processInbox } from './advisor/commanderInbox';
import { createDispatchMap, createHandlerState } from './messageHandlers';
import type { HandlerMap } from './messageHandlers';
import { registerAchievementHandlers } from './messageHandlers/achievementHandlers';
import { registerEventLogHandlers } from './messageHandlers/eventLogHandlers';
import type { AchievementService } from './achievements/AchievementService';
import type { RendererHandles } from './rendererInit';
import type { GameRefs } from './gameRuntimeState';

export interface LazyPanelHandles {
  getDashboard(): typeof import('./ui/dashboard') | null;
  getFactionPanel(): typeof import('./ui/factionPanel') | null;
  getMegaPanel(): typeof import('./ui/megastructurePanel') | null;
  getAdvisor(): AdvisorMod | null;
  /** Load (or return cached) dashboard module. */
  loadDashboard(): Promise<typeof import('./ui/dashboard')>;
  initDashboardOnce(m: typeof import('./ui/dashboard')): void;
  /** Load (or return cached) faction panel module. */
  loadFactionPanel(): Promise<typeof import('./ui/factionPanel')>;
  initFactionOnce(m: typeof import('./ui/factionPanel')): void;
  /** Load (or return cached) megastructure panel module. */
  loadMegaPanel(): Promise<typeof import('./ui/megastructurePanel')>;
  initMegaOnce(m: typeof import('./ui/megastructurePanel')): void;
  loadAdvisorLazy(): Promise<AdvisorMod>;
  initAdvisorOnce(m: AdvisorMod): void;
}

type AdvisorMod = {
  panel: typeof import('./ui/advisorPanel') & { toggleAdvisorPanel: () => void };
  service: typeof import('./advisor/advisorService');
  gameState: typeof import('./advisor/gameState');
  delegate?: typeof import('./advisor/commanderDelegate');
};

export interface WorkerMessageCallbacks {
  scheduleIdleHint(): void;
}

export function setupWorkerMessages(
  worker: Worker,
  refs: GameRefs,
  renderers: RendererHandles,
  lazy: LazyPanelHandles,
  cbs: WorkerMessageCallbacks,
  achievements?: AchievementService,
): void {
  // Initialize inbox panel callbacks
  initInboxPanel({
    onMarkRead: (messageId) => {
      worker.postMessage({ type: 'sim:inbox_mark_read', payload: { messageId } });
    },
    onDeleteMessage: (messageId) => {
      worker.postMessage({ type: 'sim:inbox_delete', payload: { messageId } });
    },
    onProcessInbox: () => {
      if (!refs.latestInboxSnapshot) return;
      setInboxProcessing(true);
      processInbox(refs.latestInboxSnapshot).then((result) => {
        setInboxSummary(result);
        if (result.triageResults.length > 0) {
          worker.postMessage({
            type: 'sim:inbox_triage_result',
            payload: { results: result.triageResults },
          });
        }
      }).catch((err: unknown) => {
        console.error('[main] processInbox failed:', err);
        Sentry.captureException(err, { tags: { source: 'processInbox' } });
      });
    },
    onReplacementChoice: (legacyEid, choice) => {
      worker.postMessage({ type: 'sim:replacement_choice', payload: { legacyEid, choice } });
    },
    onDarkForestChoice: (choice) => {
      worker.postMessage({ type: 'sim:dark_forest_choice', payload: { choice } });
    },
    onHabitatDemandResponse: (demandId, action) => {
      worker.postMessage({ type: 'sim:habitat_demand_response', payload: { demandId, action } });
    },
    onDispositionEventResponse: (factionId, eventType, response) => {
      worker.postMessage({ type: 'sim:disposition_event_response', payload: { factionId, eventType, response } });
    },
    onThreatResponse: (threatId, response) => {
      worker.postMessage({ type: 'sim:threat_response', payload: { threatId, response } });
    },
  });

  // Initialize habitat panel with demand-response callback
  initHabitatPanel((msg) => {
    worker.postMessage(msg);
  });

  // Build the dispatch map
  const state = createHandlerState();
  const handlers = createDispatchMap({ worker, refs, renderers, lazy, cbs }, state);

  // Layer achievement handlers on top — for overlapping message types,
  // both the original and achievement handler run.
  let achHandlers: HandlerMap = {};
  if (achievements) {
    const { handlers: ah } = registerAchievementHandlers(achievements);
    achHandlers = ah;
  }

  // Layer event log handlers — captures game events for the event log panel.
  const eventLogHandlers = registerEventLogHandlers();

  worker.onerror = (e) => {
    console.error('[main] Worker error:', e);
    showWorkerCrashModal();
  };

  worker.onmessage = (e: MessageEvent<WorkerToMainMessage>) => {
    const handler = handlers[e.data.type];
    const achHandler = achHandlers[e.data.type];
    const evtLogHandler = eventLogHandlers[e.data.type];

    if (!handler && !achHandler && !evtLogHandler) {
      console.warn(`[main] No handler registered for worker message type: ${e.data.type}`);
      return;
    }

    if (handler) {
      try {
        handler(e.data);
      } catch (err) {
        console.error('[main] Message handler threw for type', e.data.type, err);
        Sentry.captureException(err, { tags: { source: 'message_handler', messageType: e.data.type } });
      }
    }

    if (achHandler) {
      try {
        achHandler(e.data);
      } catch (err) {
        console.error('[main] Achievement handler threw for type', e.data.type, err);
        Sentry.captureException(err, { tags: { source: 'achievement_handler', messageType: e.data.type } });
      }
    }

    if (evtLogHandler) {
      try {
        evtLogHandler(e.data);
      } catch (err) {
        console.error('[main] Event log handler threw for type', e.data.type, err);
        Sentry.captureException(err, { tags: { source: 'event_log_handler', messageType: e.data.type } });
      }
    }
  };
}
