import { ANOMALY_TYPE_NAMES as ANOMALY_NAMES, ANOMALY_COLORS } from '../sim/anomalyTypes';
import { safeHtml, trustedHtml } from './utils/safeHtml';

let container: HTMLDivElement | null = null;
let screenFlashEl: HTMLDivElement | null = null;

// ── Rate limiting state ──────────────────────────────────────────────────────

/** Cooldown per notification category (ms). */
const COOLDOWN_MS: Record<string, number> = {
  warning: 5000,
  danger: 5000,
  info: 3000,
  success: 3000,
  research: 3000,
  build: 3000,
};
const DEFAULT_COOLDOWN_MS = 3000;
const MAX_VISIBLE_TOASTS = 3;
const SCREEN_FLASH_COOLDOWN_MS = 10000;

/** Tracks last notification time per category. */
const lastNotifyByCategory = new Map<string, number>();
/** Tracks last notification message to deduplicate identical toasts. */
const lastNotifyByMessage = new Map<string, number>();
/** Timestamp of the last screen flash. */
let lastFlashTime = 0;

/** Grace period: suppress all non-critical notifications after load (MUL-3262). */
const LOAD_GRACE_PERIOD_MS = 10000;
let graceUntil = 0;

/** Queue for rate-limited notifications that couldn't display immediately. */
const notificationQueue: Array<{ message: string; color: string; category?: NotifyCategory }> = [];
const QUEUE_DRAIN_INTERVAL_MS = 3000;
const MAX_QUEUE_SIZE = 4;
let queueDrainTimer: ReturnType<typeof setTimeout> | null = null;

// ── Collapse state (REQ-NOTIF-005) ──────────────────────────────────────────
/** After COLLAPSE_THRESHOLD notifications in the same category within
 *  COLLAPSE_WINDOW_MS, subsequent ones update a "×N" badge on the
 *  existing toast instead of spawning new ones. */
const COLLAPSE_THRESHOLD = 3;
const COLLAPSE_WINDOW_MS = 15000;
/** Per-category: { count, firstTime, latestMessage, element } */
const collapseGroups = new Map<string, {
  count: number;
  firstTime: number;
  latestMessage: string;
  element: HTMLDivElement | null;
}>();

/** Reset all rate-limiting state (for tests). */
export function resetNotificationState(): void {
  lastNotifyByCategory.clear();
  lastNotifyByMessage.clear();
  lastFlashTime = 0;
  graceUntil = 0;
  notificationQueue.length = 0;
  collapseGroups.clear();
  if (queueDrainTimer !== null) {
    clearTimeout(queueDrainTimer);
    queueDrainTimer = null;
  }
}

/**
 * Begin a grace period that suppresses all toast notifications and screen
 * flashes for LOAD_GRACE_PERIOD_MS. Call on game load so milestone re-checks
 * don't flood the screen.
 */
export function beginLoadGracePeriod(): void {
  graceUntil = Date.now() + LOAD_GRACE_PERIOD_MS;
}

/** Brief screen-edge flash overlay. color should be a CSS color string. */
export function showScreenFlash(color: string, durationMs = 400): void {
  const now = Date.now();
  if (now < graceUntil) return;
  if (now - lastFlashTime < SCREEN_FLASH_COOLDOWN_MS) return;
  lastFlashTime = now;
  if (!screenFlashEl) {
    screenFlashEl = document.createElement('div');
    screenFlashEl.style.cssText = `
      position: fixed;
      inset: 0;
      pointer-events: none;
      z-index: 200;
      opacity: 0;
      transition: opacity 0.4s ease;
    `;
    document.body.appendChild(screenFlashEl);
  }

  const el = screenFlashEl;
  el.style.background = `radial-gradient(ellipse at center, transparent 40%, ${color}33 100%)`;
  el.style.opacity = '0.4';
  el.style.transition = 'opacity 0.4s ease';

  setTimeout(() => {
    el.style.transition = `opacity ${Math.max(durationMs, 600)}ms ease`;
    el.style.opacity = '0';
  }, 400);
}

function getContainer(): HTMLDivElement {
  if (!container) {
    container = document.createElement('div');
    container.style.cssText = `
      position: fixed;
      top: 185px;
      right: 12px;
      display: flex;
      flex-direction: column;
      gap: 8px;
      z-index: 100;
      pointer-events: none;
      max-width: 320px;
    `;
    document.body.appendChild(container);
  }
  return container;
}

// Inject anomaly glow keyframe once
(function injectAnomalyKeyframes(): void {
  if (document.getElementById('anomaly-glow-style')) return;
  const style = document.createElement('style');
  style.id = 'anomaly-glow-style';
  style.textContent = `
    @keyframes anomalyGlowPulse {
      0%   { box-shadow: 0 0 6px var(--anomaly-color, #a855f7), inset 0 0 8px rgba(0,0,0,0.5); }
      50%  { box-shadow: 0 0 18px var(--anomaly-color, #a855f7), 0 0 32px var(--anomaly-color, #a855f7)55, inset 0 0 8px rgba(0,0,0,0.5); }
      100% { box-shadow: 0 0 6px var(--anomaly-color, #a855f7), inset 0 0 8px rgba(0,0,0,0.5); }
    }
  `;
  document.head.appendChild(style);
})();

export function showAnomalyToast(
  robotEid: number,
  anomalyType: number,
  x: number,
  y: number,
  z: number,
): void {
  const name = ANOMALY_NAMES[anomalyType] ?? 'Unknown Anomaly';
  const color = ANOMALY_COLORS[anomalyType] ?? '#ffffff';
  const cx = Math.round(x);
  const cy = Math.round(y);
  const cz = Math.round(z);

  const toast = document.createElement('div');
  toast.style.cssText = `
    --anomaly-color: ${color};
    background: rgba(0, 8, 20, 0.88);
    border: 1px solid ${color};
    box-shadow: 0 0 8px ${color}44, inset 0 0 8px rgba(0,0,0,0.5);
    color: ${color};
    font-family: 'Courier New', monospace;
    font-size: 11px;
    line-height: 1.5;
    padding: 8px 12px;
    border-radius: 2px;
    opacity: 0;
    transform: translateX(20px);
    transition: opacity 0.3s ease, transform 0.3s ease;
    animation: anomalyGlowPulse 1.6s ease-in-out 3;
    pointer-events: none;
  `;

  toast.innerHTML = safeHtml`
    <div style="font-size:10px;opacity:0.6;text-transform:uppercase;letter-spacing:1px;margin-bottom:2px;">ANOMALY DETECTED</div>
    <div style="font-weight:bold;">${name}</div>
    <div style="opacity:0.8;">Robot-${robotEid} at (${cx}, ${cy}, ${cz})</div>
  `;

  getContainer().appendChild(toast);

  // Animate in
  requestAnimationFrame(() => {
    toast.style.opacity = '1';
    toast.style.transform = 'translateX(0)';
  });

  // Auto-dismiss after 8 seconds
  setTimeout(() => {
    toast.style.opacity = '0';
    toast.style.transform = 'translateX(20px)';
    setTimeout(() => toast.remove(), 350);
  }, 8000);
}

/** Show a prominent blocking modal when the sim worker crashes. Non-dismissible. */
export function showWorkerCrashModal(): void {
  const overlay = document.createElement('div');
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.85);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 9999;
  `;

  const box = document.createElement('div');
  box.style.cssText = `
    background: rgba(0, 8, 20, 0.96);
    border: 2px solid #ef4444;
    box-shadow: 0 0 32px #ef444488, inset 0 0 16px rgba(0,0,0,0.6);
    color: #ef4444;
    font-family: 'Courier New', monospace;
    padding: 32px 40px;
    border-radius: 4px;
    max-width: 420px;
    text-align: center;
  `;

  box.innerHTML = `
    <div style="font-size:11px;opacity:0.6;text-transform:uppercase;letter-spacing:2px;margin-bottom:12px;">CRITICAL ERROR</div>
    <div style="font-size:18px;font-weight:bold;margin-bottom:12px;">Simulation Worker Crashed</div>
    <div style="font-size:13px;opacity:0.8;line-height:1.6;margin-bottom:24px;">
      The simulation has stopped unexpectedly. Game state may be inconsistent.<br>
      Reload to restart.
    </div>
    <button id="worker-crash-reload" style="
      background: #ef4444;
      color: #fff;
      border: none;
      padding: 10px 28px;
      font-family: 'Courier New', monospace;
      font-size:13px;
      font-weight:bold;
      letter-spacing:1px;
      cursor:pointer;
      border-radius:2px;
      text-transform:uppercase;
    ">Reload Game</button>
  `;

  overlay.appendChild(box);
  document.body.appendChild(overlay);

  document.getElementById('worker-crash-reload')?.addEventListener('click', () => {
    window.location.reload();
  });
}

/** Notification category for visual differentiation */
export type NotifyCategory = 'info' | 'success' | 'warning' | 'danger' | 'research' | 'build';

const CATEGORY_ICONS: Record<NotifyCategory, string> = {
  info: '◈',
  success: '✓',
  warning: '⚠',
  danger: '✗',
  research: '◆',
  build: '⚙',
};

const CATEGORY_LABELS: Record<NotifyCategory, string> = {
  info: 'INFO',
  success: 'OPPORTUNITY',
  warning: 'WARNING',
  danger: 'ALERT',
  research: 'RESEARCH',
  build: 'BUILD',
};

/** Drain one queued notification. */
function drainQueue(): void {
  queueDrainTimer = null;
  if (notificationQueue.length === 0) return;
  const next = notificationQueue.shift()!;
  displayNotification(next.message, next.color, next.category);
  if (notificationQueue.length > 0) {
    queueDrainTimer = setTimeout(drainQueue, QUEUE_DRAIN_INTERVAL_MS);
  }
}

/** Show a notification toast with optional category styling.
 *  Rate-limited per category and deduplicated by message content.
 *  Excess notifications are queued with staggered delays. */
export function showNotification(
  message: string,
  color: string = '#22c55e',
  category?: NotifyCategory,
): void {
  const now = Date.now();
  if (now < graceUntil) return;
  const catKey = category ?? 'default';
  const cooldown = COOLDOWN_MS[catKey] ?? DEFAULT_COOLDOWN_MS;

  // Message deduplication (5s window regardless of category)
  const lastMsg = lastNotifyByMessage.get(message) ?? 0;
  if (now - lastMsg < 5000) return;

  // Category cooldown — queue instead of dropping
  const lastCat = lastNotifyByCategory.get(catKey) ?? 0;
  if (now - lastCat < cooldown) {
    if (notificationQueue.length < MAX_QUEUE_SIZE) {
      notificationQueue.push({ message, color, category });
      if (queueDrainTimer === null) {
        queueDrainTimer = setTimeout(drainQueue, QUEUE_DRAIN_INTERVAL_MS);
      }
    }
    return;
  }

  displayNotification(message, color, category);
}

/** Internal: render a notification toast immediately. */
function displayNotification(
  message: string,
  color: string,
  category?: NotifyCategory,
): void {
  const now = Date.now();
  const catKey = category ?? 'default';

  lastNotifyByCategory.set(catKey, now);
  lastNotifyByMessage.set(message, now);

  // ── Collapse logic (REQ-NOTIF-005) ──────────────────────────────────────
  const group = collapseGroups.get(catKey);
  if (group && (now - group.firstTime) < COLLAPSE_WINDOW_MS) {
    group.count++;
    group.latestMessage = message;
    // If past threshold and existing element is still in DOM, update badge
    if (group.count >= COLLAPSE_THRESHOLD && group.element?.parentNode) {
      const badge = group.element.querySelector('[data-collapse-badge]');
      if (badge) {
        badge.textContent = `×${group.count}`;
      }
      const msgEl = group.element.querySelector('[data-collapse-msg]');
      if (msgEl) {
        msgEl.textContent = message;
      }
      return; // Don't create a new toast
    }
  } else {
    // Start a new collapse group
    collapseGroups.set(catKey, { count: 1, firstTime: now, latestMessage: message, element: null });
  }

  // Enforce max visible toasts — drop oldest if full
  const cont = getContainer();
  while (cont.children.length >= MAX_VISIBLE_TOASTS && cont.firstChild) {
    cont.firstChild.remove();
  }

  const icon = category ? CATEGORY_ICONS[category] : null;
  const isDanger = category === 'danger' || category === 'warning';

  const toast = document.createElement('div');
  toast.style.cssText = `
    background: rgba(0, 8, 20, 0.88);
    border: 1px solid ${color};
    border-left: 3px solid ${color};
    box-shadow: 0 0 8px ${color}44;
    color: ${color};
    font-family: 'Courier New', monospace;
    font-size: 11px;
    line-height: 1.5;
    padding: 8px 12px;
    border-radius: 2px;
    opacity: 0;
    transform: translateX(20px) scale(0.96);
    transition: opacity 0.3s ease, transform 0.3s ease;
    pointer-events: none;
    display: flex;
    align-items: center;
    gap: 8px;
  `;

  const iconHtml = icon
    ? `<span style="font-size:14px;opacity:0.9;flex-shrink:0;">${icon}</span>`
    : '';
  const labelHtml = category
    ? `<div style="font-size:9px;opacity:0.6;text-transform:uppercase;letter-spacing:1px;margin-bottom:1px;">${CATEGORY_LABELS[category]}</div>`
    : '';
  const badgeHtml = `<span data-collapse-badge style="font-size:10px;opacity:0.7;margin-left:4px;"></span>`;
  toast.innerHTML = safeHtml`${trustedHtml(iconHtml)}<div>${trustedHtml(labelHtml)}<div style="font-weight:bold;display:flex;align-items:center;"><span data-collapse-msg>${message}</span>${trustedHtml(badgeHtml)}</div></div>`;
  getContainer().appendChild(toast);

  // Track element for collapse updates
  const currentGroup = collapseGroups.get(catKey);
  if (currentGroup) currentGroup.element = toast;

  requestAnimationFrame(() => {
    toast.style.opacity = '1';
    toast.style.transform = 'translateX(0) scale(1)';
  });

  const duration = isDanger ? 7000 : 5000;
  setTimeout(() => {
    toast.style.opacity = '0';
    toast.style.transform = 'translateX(20px) scale(0.96)';
    setTimeout(() => {
      toast.remove();
      // Clear collapse group when toast is removed
      const g = collapseGroups.get(catKey);
      if (g && g.element === toast) collapseGroups.delete(catKey);
    }, 350);
  }, duration);
}
