/**
 * Fleet Manifesto Modal
 *
 * Purpose-setting ritual where players choose (or write) their colony's manifesto.
 * Shown once early in the game, revisable from the Culture panel.
 */

import { MANIFESTO_PRESETS, MANIFESTO_MAX_LENGTH } from '../sim/culture';
import { trapFocus } from './focusTrap';

type ManifestoResult = { presetId: string | null; text: string };

let overlay: HTMLDivElement | null = null;
let removeFocusTrap: (() => void) | null = null;
let shownThisSession = false;

/** Whether the manifesto modal has been shown this session (prevents re-prompt). */
export function hasManifestoBeenShown(): boolean {
  return shownThisSession;
}

/** Reset shown state (for save/load). */
export function resetManifestoModalState(): void {
  shownThisSession = false;
}

export function showManifestoModal(
  onSubmit: (result: ManifestoResult) => void,
  existingManifesto?: string | null,
): void {
  if (overlay) return; // already open
  shownThisSession = true;

  const isRevision = !!existingManifesto;

  overlay = document.createElement('div');
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.85);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 2000;
    font-family: 'Courier New', monospace;
    opacity: 0;
    transition: opacity 0.5s ease;
  `;
  document.body.appendChild(overlay);
  requestAnimationFrame(() => {
    if (overlay) overlay.style.opacity = '1';
  });

  const modal = document.createElement('div');
  modal.setAttribute('role', 'dialog');
  modal.setAttribute('aria-label', 'Fleet Manifesto');
  modal.setAttribute('aria-modal', 'true');
  modal.setAttribute('tabindex', '-1');
  modal.style.cssText = `
    background: rgba(0, 4, 12, 0.98);
    border: 1px solid #06b6d4;
    box-shadow: 0 0 60px rgba(6,182,212,0.15), inset 0 0 40px rgba(0,0,0,0.6);
    color: #e2e8f0;
    max-width: 580px;
    width: 90vw;
    padding: 36px 32px;
    border-radius: 2px;
    position: relative;
  `;

  // Header
  const headerHtml = `
    <div style="font-size:9px; color:#06b6d4; opacity:0.7; text-transform:uppercase; letter-spacing:3px; margin-bottom:6px;">
      ARIA — ${isRevision ? 'CULTURAL SHIFT' : 'COLONY FOUNDING'}
    </div>
    <div style="font-size:18px; font-weight:bold; color:#06b6d4; margin-bottom:16px; letter-spacing:1px;">
      ${isRevision ? 'Revise Fleet Manifesto' : 'What Is Your Colony For?'}
    </div>
    <p style="margin:0 0 20px; line-height:1.7; color:#94a3b8; font-size:12px;">
      ${isRevision
        ? 'Your fleet\'s purpose can evolve. Changing it marks a Cultural Shift milestone.'
        : 'Commander, before we begin — every civilization needs a reason to exist. Choose the purpose that will guide your fleet, or write your own.'}
    </p>
  `;

  // Preset options
  let presetsHtml = '<div style="display:flex; flex-direction:column; gap:8px; margin-bottom:16px;">';
  for (const preset of MANIFESTO_PRESETS) {
    presetsHtml += `
      <button data-manifesto-preset="${preset.id}" style="
        background: transparent;
        border: 1px solid #06b6d488;
        color: #e2e8f0;
        font-family: 'Courier New', monospace;
        font-size: 12px;
        padding: 12px 16px;
        cursor: pointer;
        text-align: left;
        border-radius: 2px;
        transition: background 0.2s, border-color 0.2s;
        line-height: 1.6;
      " onmouseover="this.style.background='rgba(6,182,212,0.1)';this.style.borderColor='#06b6d4'" onmouseout="this.style.background='transparent';this.style.borderColor='#06b6d488'">
        <em>"${escapeHtml(preset.text)}"</em>
      </button>
    `;
  }
  presetsHtml += '</div>';

  // Freetext option
  const freetextHtml = `
    <div style="margin-top:4px;">
      <div style="font-size:10px; color:#64748b; text-transform:uppercase; letter-spacing:1px; margin-bottom:8px;">Or write your own</div>
      <textarea id="manifesto-freetext" maxlength="${MANIFESTO_MAX_LENGTH}" placeholder="Your colony's purpose (${MANIFESTO_MAX_LENGTH} chars max)..." style="
        width: 100%;
        height: 60px;
        background: rgba(0,0,0,0.4);
        border: 1px solid #06b6d444;
        border-radius: 2px;
        color: #e2e8f0;
        font-family: 'Courier New', monospace;
        font-size: 12px;
        padding: 10px;
        resize: none;
        outline: none;
        box-sizing: border-box;
      ">${existingManifesto ? escapeHtml(existingManifesto) : ''}</textarea>
      <div style="display:flex; justify-content:space-between; margin-top:6px;">
        <span id="manifesto-char-count" style="font-size:10px; color:#475569;">0/${MANIFESTO_MAX_LENGTH}</span>
        <button id="manifesto-submit-freetext" style="
          background: transparent;
          border: 1px solid #06b6d488;
          color: #06b6d4;
          font-family: 'Courier New', monospace;
          font-size: 11px;
          padding: 6px 18px;
          cursor: pointer;
          border-radius: 2px;
          letter-spacing: 1px;
          text-transform: uppercase;
          transition: background 0.2s;
        " onmouseover="this.style.background='rgba(6,182,212,0.15)'" onmouseout="this.style.background='transparent'">DECLARE</button>
      </div>
    </div>
  `;

  // Skip option (only for first time, not revisions)
  const skipHtml = isRevision
    ? `<div style="margin-top:12px; text-align:center;">
        <button id="manifesto-cancel" style="
          background:none; border:none; color:#475569; cursor:pointer;
          font-family:'Courier New',monospace; font-size:10px; text-transform:uppercase; letter-spacing:1px;
        ">Cancel</button>
      </div>`
    : `<div style="margin-top:12px; text-align:center;">
        <button id="manifesto-skip" style="
          background:none; border:none; color:#475569; cursor:pointer;
          font-family:'Courier New',monospace; font-size:10px; text-transform:uppercase; letter-spacing:1px;
        ">Skip for now</button>
      </div>`;

  modal.innerHTML = headerHtml + presetsHtml + freetextHtml + skipHtml;
  overlay.appendChild(modal);
  removeFocusTrap = trapFocus(modal);

  // Wire up preset buttons
  modal.querySelectorAll<HTMLButtonElement>('[data-manifesto-preset]').forEach((btn) => {
    btn.addEventListener('click', () => {
      const presetId = btn.dataset.manifestoPreset!;
      const preset = MANIFESTO_PRESETS.find((p) => p.id === presetId);
      if (preset) {
        onSubmit({ presetId, text: preset.text });
        closeModal();
      }
    });
  });

  // Wire up freetext
  const textarea = modal.querySelector<HTMLTextAreaElement>('#manifesto-freetext')!;
  const charCount = modal.querySelector<HTMLSpanElement>('#manifesto-char-count')!;
  const submitBtn = modal.querySelector<HTMLButtonElement>('#manifesto-submit-freetext')!;

  const updateCount = () => {
    charCount.textContent = `${textarea.value.length}/${MANIFESTO_MAX_LENGTH}`;
  };
  textarea.addEventListener('input', updateCount);
  updateCount();

  submitBtn.addEventListener('click', () => {
    const text = textarea.value.trim();
    if (text.length > 0) {
      onSubmit({ presetId: null, text });
      closeModal();
    } else {
      textarea.style.outline = '2px solid #ef4444';
      textarea.focus();
      setTimeout(() => { textarea.style.outline = ''; }, 1500);
    }
  });

  // Skip/Cancel
  const skipBtn = modal.querySelector<HTMLButtonElement>('#manifesto-skip');
  skipBtn?.addEventListener('click', closeModal);
  const cancelBtn = modal.querySelector<HTMLButtonElement>('#manifesto-cancel');
  cancelBtn?.addEventListener('click', closeModal);
}

function closeModal(): void {
  if (!overlay) return;
  removeFocusTrap?.();
  removeFocusTrap = null;
  overlay.style.opacity = '0';
  const ref = overlay;
  setTimeout(() => ref.remove(), 500);
  overlay = null;
}

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}
