/**
 * Shared mutable runtime state passed by reference to all subsystems.
 *
 * Extracted from src/main.ts to enable unit-testing worker dispatch and input
 * handling in isolation without a 1275-line god function.
 */
import type { SimStatsMessage, SimCultureStateMessage } from './sim/messages';
import type { SimHabitatStateMessage } from './shared/habitatTypes';
import type { MegastructureProjectSnapshot } from './shared/megastructureTypes';
import type { SaveData } from './sim/saveLoad';
import type { SerializedTechState } from './sim/techTree';
import type { InboxSnapshot } from './sim/inbox/inboxTypes';
import type { FactionSnapshot } from './sim/factions/factionSystem';
import type { SerializedBuilding } from './sim/buildings';
import type { TransitSnapshot } from './sim/transit';

export interface Discovery {
  robotEid: number;
  asteroidEid: number;
  anomalyType: number;
  x: number;
  y: number;
  z: number;
  tick: number;
}

/** Accumulated anomaly discoveries — read by advisor and dashboard. */
export const discoveries: Discovery[] = [];

/**
 * Current base storage values. Reassigned (not mutated) on each sim:frame.
 * Indices match MINERAL_FIELDS order (7 elements):
 * [iron, nickel, cobalt, platinum, ice, carbon, silicate].
 * NOTE: callers that import this must re-read the binding each frame; it is
 * a live ES-module export but reassignment only propagates to module-level
 * reads, not to captured local copies.
 */
export let storageValues = new Float32Array(7);

/** Must be called (not direct assignment) to update storageValues from outside this module. */
export function setStorageValues(v: Float32Array<ArrayBuffer>): void {
  storageValues = v;
}

/**
 * All mutable runtime state shared across subsystems (worker messages,
 * input handlers, render loop). Passed by object reference so mutations
 * are visible everywhere.
 */
export interface GameRefs {
  // Latest sim data received from the worker
  latestAsteroidBuffer: Float64Array | null;
  latestAsteroidCount: number;
  latestRobotBuffer: Float32Array | null;
  latestRobotCount: number;
  latestThreatBuffer: Float32Array | null;
  latestThreatCount: number;
  lastStats: SimStatsMessage['payload'] | null;
  latestTick: number;
  latestRefined: Record<string, number>;
  latestUnlockedMask: bigint;
  latestTechState: SerializedTechState | null;
  latestFactoryQueueLength: number;
  latestRobotCap: number;
  latestMegaProjects: MegastructureProjectSnapshot[];
  latestBuildings: SerializedBuilding[];
  latestInboxSnapshot: InboxSnapshot | null;
  latestFactionSnapshots: FactionSnapshot[];
  latestCultureState: SimCultureStateMessage['payload'] | null;
  latestHabitatState: SimHabitatStateMessage['payload'] | null;
  latestTransitSnapshot: (TransitSnapshot & { tick: number }) | null;

  // Camera / interaction state
  followedRobotEid: number | null;
  isPlacingBase: boolean;
  /** Robot EID selected for manual targeting (Mine command). */
  targetingRobotEid: number | null;
  /** True when awaiting an asteroid click to assign a mine task. */
  isTargetingMode: boolean;
  /** Robot EID selected for explore targeting (Explore command). */
  exploreRobotEid: number | null;
  /** True when awaiting a world click to assign an explore task. */
  isExploreMode: boolean;
  /** Faction asteroid claims: faction id → contested asteroid EID. */
  factionClaims: Array<{ factionId: number; asteroidEid: number; color: string }>;
  /** Asteroid EIDs the player has manually assigned for mining. */
  playerTargetAsteroids: number[];
  /** Faction base positions and territory radii for 3D territory visualization. */
  factionTerritories: Array<{ x: number; z: number; radius: number; color: string }>;

  // Game flow
  pendingLoad: SaveData | null;
  pendingFirstLaunch: boolean;

  // Render loop accumulator
  elapsed: number;

  // Speed control
  speedMultiplier: number;
}

export function createGameRefs(): GameRefs {
  return {
    latestAsteroidBuffer: null,
    latestAsteroidCount: 0,
    latestRobotBuffer: null,
    latestRobotCount: 0,
    latestThreatBuffer: null,
    latestThreatCount: 0,
    lastStats: null,
    latestTick: 0,
    latestRefined: {},
    latestUnlockedMask: 0n,
    latestTechState: null,
    latestFactoryQueueLength: 0,
    latestRobotCap: 0,
    latestMegaProjects: [],
    latestBuildings: [],
    latestInboxSnapshot: null,
    latestFactionSnapshots: [],
    latestCultureState: null,
    latestHabitatState: null,
    latestTransitSnapshot: null,
    followedRobotEid: null,
    isPlacingBase: false,
    targetingRobotEid: null,
    isTargetingMode: false,
    exploreRobotEid: null,
    isExploreMode: false,
    factionClaims: [],
    playerTargetAsteroids: [],
    factionTerritories: [],
    pendingLoad: null,
    pendingFirstLaunch: false,
    elapsed: 0,
    speedMultiplier: 1,
  };
}
