/**
 * Shared types and constants for the dashboard tab modules.
 */

import { MINERAL_FIELDS } from '../../sim/minerals';

// ── Constants ────────────────────────────────────────────────────────────────

export const SAMPLE_INTERVAL_TICKS = 60;

export const ROBOT_TYPE_COLORS = [
  '#64748b',
  '#f59e0b',
  '#06b6d4',
  '#a855f7',
  '#10b981',
  '#ef4444',
  '#f97316',
];

export const RESOURCE_LABELS = MINERAL_FIELDS.map((f) => f.charAt(0).toUpperCase() + f.slice(1));
export const RESOURCE_COLORS = ['#ef4444', '#94a3b8', '#3b82f6', '#eab308', '#06b6d4', '#6b7280', '#22c55e'];

// ── Data types ───────────────────────────────────────────────────────────────

export interface ResourceSample {
  tick: number;
  /** Values in MINERAL_FIELDS order: iron, nickel, cobalt, platinum, ice, carbon, silicate */
  values: Float32Array;
}

export interface FleetSnapshot {
  countByType: Int32Array;  // 7 types
  countByState: Int32Array; // 9 states
  productive: number;       // mining + hauling
  total: number;
  avgEnergy: number;
}

export interface ExplorationEntry {
  tick: number;
  label: string;
  color: string;
}

export interface AnomalySnapshot {
  anomalyType: number;
  x: number;
  y: number;
  z: number;
  tick: number;
}
