/**
 * Context-sensitive UX hints for first-time players.
 *
 * Hints appear as subtle toasts (bottom-left, lighter opacity, smaller font)
 * distinct from game notifications. Each hint is shown at most once per session
 * via sessionStorage.
 */

const SESSION_PREFIX = 'asteroid_miner_hint_';

let hintContainer: HTMLDivElement | null = null;

function getHintContainer(): HTMLDivElement {
  if (!hintContainer) {
    hintContainer = document.createElement('div');
    hintContainer.style.cssText = `
      position: fixed;
      bottom: 24px;
      left: 16px;
      display: flex;
      flex-direction: column;
      gap: 6px;
      z-index: 90;
      pointer-events: none;
      max-width: 300px;
    `;
    document.body.appendChild(hintContainer);
  }
  return hintContainer;
}

/**
 * Show a contextual hint toast once per session.
 * @param key     Unique key stored in sessionStorage to prevent repeats.
 * @param message The hint text to display.
 */
export function showHint(key: string, message: string): void {
  const storageKey = SESSION_PREFIX + key;
  try {
    if (sessionStorage.getItem(storageKey)) return;
    sessionStorage.setItem(storageKey, '1');
  } catch {
    // sessionStorage unavailable — show anyway but don't deduplicate
  }

  const toast = document.createElement('div');
  toast.style.cssText = `
    background: rgba(0, 8, 20, 0.65);
    border: 1px solid rgba(100, 140, 220, 0.35);
    color: rgba(160, 190, 240, 0.75);
    font-family: 'Courier New', monospace;
    font-size: 10px;
    line-height: 1.4;
    padding: 6px 10px;
    border-radius: 2px;
    opacity: 0;
    transform: translateX(-12px);
    transition: opacity 0.3s ease, transform 0.3s ease;
    pointer-events: none;
  `;
  toast.innerHTML = `<span style="opacity:0.5;font-size:9px;text-transform:uppercase;letter-spacing:1px;margin-right:4px;">HINT</span>`;
  toast.append(document.createTextNode(message));

  getHintContainer().appendChild(toast);

  requestAnimationFrame(() => {
    toast.style.opacity = '1';
    toast.style.transform = 'translateX(0)';
  });

  setTimeout(() => {
    toast.style.opacity = '0';
    toast.style.transform = 'translateX(-12px)';
    setTimeout(() => toast.remove(), 350);
  }, 6000);
}

/** Returns true if a hint with the given key has already been shown this session. */
export function wasHintShown(key: string): boolean {
  try {
    return !!sessionStorage.getItem(SESSION_PREFIX + key);
  } catch {
    return false;
  }
}
