import {
  AdditiveBlending,
  BufferAttribute,
  BufferGeometry,
  Points,
  Scene,
  ShaderMaterial,
  Sphere,
  Vector3,
} from 'three';

/**
 * GPU-driven decorative particles. Positions computed entirely in the vertex shader
 * using deterministic hashing — zero CPU cost per frame.
 */
export class DecorativeParticles {
  private points: Points;
  private material: ShaderMaterial;
  private particleCount: number;

  constructor(scene: Scene, particleCount: number = 8000) {
    this.particleCount = particleCount;
    // Index attribute - each particle gets a unique index
    const indices = new Float32Array(particleCount);
    for (let i = 0; i < particleCount; i++) {
      indices[i] = i;
    }

    const geometry = new BufferGeometry();
    geometry.setAttribute('particleIndex', new BufferAttribute(indices, 1));
    // Dummy position attribute (required by Three.js)
    geometry.setAttribute('position', new BufferAttribute(new Float32Array(particleCount * 3), 3));

    this.material = new ShaderMaterial({
      vertexShader: `
        attribute float particleIndex;
        uniform float uTime;
        uniform vec3 uCameraPos;
        uniform float uZoomDistance;
        uniform float uMaxActive;
        varying float vAlpha;
        varying vec3 vColor;

        // Hash function for deterministic particle placement
        float hash(float n) {
          return fract(sin(n) * 43758.5453);
        }

        vec3 hashPosition(float idx) {
          return vec3(
            hash(idx * 1.123),
            hash(idx * 2.456),
            hash(idx * 3.789)
          );
        }

        void main() {
          float idx = particleIndex;

          // Base position from hash
          vec3 basePos = hashPosition(idx);

          // Spread based on zoom distance
          float spread = max(uZoomDistance * 2.0, 5000.0);
          vec3 pos = (basePos - 0.5) * spread + uCameraPos;

          // Slow drift over time
          float driftSpeed = hash(idx * 4.567) * 0.5 + 0.1;
          pos.x += sin(uTime * driftSpeed + idx) * 10.0;
          pos.y += cos(uTime * driftSpeed * 0.7 + idx * 1.3) * 5.0;
          pos.z += sin(uTime * driftSpeed * 0.5 + idx * 2.1) * 10.0;

          // Size and alpha based on zoom
          float baseSize = hash(idx * 5.678) * 2.0 + 0.5;
          float zoomScale = clamp(uZoomDistance / 1000.0, 0.5, 5.0);
          float size = baseSize * zoomScale;

          // Distance-based fade
          float dist = length(pos - uCameraPos);
          float fadeStart = spread * 0.4;
          float fadeEnd = spread * 0.5;
          vAlpha = 1.0 - smoothstep(fadeStart, fadeEnd, dist);
          vAlpha *= 0.3; // keep subtle
          // Density culling: hide particles above the active threshold
          vAlpha *= step(particleIndex, uMaxActive - 0.5);

          // Color variation: mostly grey dust, some with warm/cool tints
          float colorHash = hash(idx * 6.789);
          if (colorHash < 0.7) {
            vColor = vec3(0.4, 0.38, 0.36);
          } else if (colorHash < 0.85) {
            vColor = vec3(0.5, 0.4, 0.3);
          } else {
            vColor = vec3(0.3, 0.35, 0.45);
          }

          // Skip rasterization for invisible particles (density-culled or fully faded)
          if (vAlpha <= 0.0) {
            gl_PointSize = 0.0;
            gl_Position = vec4(2.0, 2.0, 2.0, 1.0);
            return;
          }

          vec4 mvPos = modelViewMatrix * vec4(pos, 1.0);
          gl_PointSize = size * (200.0 / -mvPos.z);
          gl_PointSize = clamp(gl_PointSize, 0.5, 6.0);
          gl_Position = projectionMatrix * mvPos;
        }
      `,
      fragmentShader: `
        varying float vAlpha;
        varying vec3 vColor;
        void main() {
          float d = length(gl_PointCoord - vec2(0.5));
          if (d > 0.5) discard;
          float alpha = vAlpha * (1.0 - smoothstep(0.2, 0.5, d));
          gl_FragColor = vec4(vColor, alpha);
        }
      `,
      uniforms: {
        uTime: { value: 0 },
        uCameraPos: { value: new Vector3() },
        uZoomDistance: { value: 1000 },
        uMaxActive: { value: particleCount },
      },
      transparent: true,
      depthWrite: false,
      blending: AdditiveBlending,
    });

    this.points = new Points(geometry, this.material);
    this.points.frustumCulled = true;
    // Initialize bounding sphere — updated dynamically in update()
    geometry.boundingSphere = new Sphere(new Vector3(), 5000);
    scene.add(this.points);
  }

  /** Set particle density: 0 = none, 1 = full (8000 particles). */
  setDensity(factor: number): void {
    this.material.uniforms.uMaxActive.value = Math.round(factor * this.particleCount);
  }

  update(cameraPosition: Vector3, zoomDistance: number, time: number): void {
    this.material.uniforms.uTime.value = time;
    this.material.uniforms.uCameraPos.value.copy(cameraPosition);
    this.material.uniforms.uZoomDistance.value = zoomDistance;

    // Update bounding sphere to match particle spread around camera
    const spread = Math.max(zoomDistance * 2, 5000);
    const bs = this.points.geometry.boundingSphere!;
    bs.center.copy(cameraPosition);
    bs.radius = spread * 0.5;
  }

  dispose(): void {
    this.points.geometry.dispose();
    this.material.dispose();
  }
}
