/**
 * Logistics Panel — shows per-base storage levels, active routes, and starvation warnings.
 * Toggle with the B key or the Logistics HUD button.
 *
 * Positioned top-right so it doesn't overlap the Base Buildings panel (top-center).
 * Uses event delegation for all button interactions (no window globals).
 * Registered with the window manager for z-index stacking and drag support.
 */

import type { BaseInfo, HaulRoute } from '../sim/logistics';
import { MINERAL_FIELDS } from '../sim/minerals';
import { showNotification, showScreenFlash } from './notifications';
import { makeDraggable, registerWindow } from './windowManager';
import { escapeHtml, safeHtml, trustedHtml } from './utils/safeHtml';

let panel: HTMLDivElement | null = null;
let isVisible = false;

let latestBases: BaseInfo[] = [];
let latestRoutes: HaulRoute[] = [];

let onEnterPlacementMode: (() => void) | null = null;
let onUpsertRoute: ((route: HaulRoute) => void) | null = null;
let onDeleteRoute: ((id: string) => void) | null = null;
let _logisticsKeyListenerAttached = false;

const MINERALS = MINERAL_FIELDS;
const STARVATION_THRESHOLD = 50;

function formatStorage(base: BaseInfo): string {
  const lines: string[] = [];
  const cap = base.capacity > 0 ? base.capacity : Infinity;
  for (const mineral of MINERALS) {
    const val = base[mineral as keyof BaseInfo] as number;
    if (val > 0 || cap < Infinity) {
      const pct = cap < Infinity ? ` (${Math.round((val / cap) * 100)}%)` : '';
      const warn = val < STARVATION_THRESHOLD && !base.isPrimary ? ' ⚠' : '';
      lines.push(`  ${mineral.padEnd(9)}: ${Math.floor(val)}${pct}${warn}`);
    }
  }
  return lines.length > 0 ? lines.join('\n') : '  (empty)';
}

function createPanel(): HTMLDivElement {
  const el = document.createElement('div');
  el.id = 'logistics-panel';
  el.style.cssText = `
    position: absolute;
    top: 40px;
    right: 20px;
    background: rgba(10, 20, 40, 0.97);
    border: 1px solid #1e40af;
    border-radius: 8px;
    padding: 0;
    min-width: 480px;
    max-width: 600px;
    max-height: 70vh;
    overflow-y: auto;
    font-family: 'Courier New', monospace;
    font-size: 12px;
    color: #e2e8f0;
    pointer-events: auto;
    box-shadow: 0 0 40px rgba(0,0,0,0.9);
    opacity: 0;
    display: none;
    transition: opacity 0.2s ease-out;
  `;

  const hudOverlay = document.getElementById('hud-overlay');
  if (hudOverlay) hudOverlay.appendChild(el);

  // Event delegation — handles all button actions via data-action attributes.
  // This listener survives innerHTML replacement in renderPanel().
  el.addEventListener('click', (e: MouseEvent) => {
    const target = e.target as HTMLElement;

    const actionEl = target.closest<HTMLElement>('[data-action]');
    if (!actionEl) return;

    const action = actionEl.dataset['action'];

    if (action === 'close') {
      hidePanel();
    } else if (action === 'enter-placement') {
      hidePanel();
      onEnterPlacementMode?.();
    } else if (action === 'add-route') {
      handleAddRoute(el);
    } else if (action?.startsWith('delete-route:')) {
      const routeId = action.split(':')[1];
      if (routeId) {
        onDeleteRoute?.(routeId);
        latestRoutes = latestRoutes.filter((r) => r.id !== routeId);
        renderPanel();
      }
    }
  });

  registerWindow('logistics', el);
  makeDraggable(el);
  return el;
}

function handleAddRoute(el: HTMLElement): void {
  const fromEl = el.querySelector<HTMLSelectElement>('#route-from');
  const toEl = el.querySelector<HTMLSelectElement>('#route-to');
  const resEl = el.querySelector<HTMLSelectElement>('#route-resource');
  const surEl = el.querySelector<HTMLInputElement>('#route-surplus');

  const fromEid = parseInt(fromEl?.value ?? '0');
  const toEid = parseInt(toEl?.value ?? '0');
  const resource = resEl?.value ?? 'iron';
  const minSurplus = parseFloat(surEl?.value ?? '200');

  if (fromEid === toEid) return;

  const route: HaulRoute = {
    id: `route_${Date.now()}`,
    name: `${resource} transfer`,
    fromBaseEid: fromEid,
    toBaseEid: toEid,
    resource,
    minSurplus: isNaN(minSurplus) ? 200 : minSurplus,
    enabled: true,
    priority: 5,
  };
  onUpsertRoute?.(route);
  latestRoutes = [...latestRoutes, route];
  renderPanel();
}

function getOrCreatePanel(): HTMLDivElement {
  if (!panel) panel = createPanel();
  return panel;
}

function showPanel(): void {
  isVisible = true;
  const el = getOrCreatePanel();
  renderPanel();
  el.style.display = 'block';
  requestAnimationFrame(() => {
    el.style.opacity = '1';
  });
}

function hidePanel(): void {
  isVisible = false;
  const el = getOrCreatePanel();
  el.style.opacity = '0';
  setTimeout(() => {
    el.style.display = 'none';
  }, 200);
}

function renderPanel(): void {
  const el = getOrCreatePanel();
  if (!isVisible) return;

  const basesSummary = latestBases
    .map((base, i) => {
      const label = base.isPrimary ? 'PRIMARY BASE' : `OUTPOST ${i}`;
      const pos = `(${Math.round(base.x)}, ${Math.round(base.z)})`;
      const storage = formatStorage(base);
      const capInfo = base.capacity > 0 ? `  Capacity: ${base.capacity}` : '  Capacity: unlimited';
      return `<div style="margin-bottom:10px;">
        <div style="color:#60a5fa;font-weight:bold">${escapeHtml(label)} ${escapeHtml(pos)}</div>
        <div style="color:#94a3b8">${escapeHtml(capInfo)}</div>
        <pre style="margin:4px 0;color:#e2e8f0">${escapeHtml(storage)}</pre>
      </div>`;
    })
    .join('');

  const routesSummary =
    latestRoutes.length === 0
      ? '<div style="color:#64748b">No routes configured.</div>'
      : latestRoutes
          .map((r) => {
            const srcIdx = latestBases.findIndex((b) => b.eid === r.fromBaseEid);
            const dstIdx = latestBases.findIndex((b) => b.eid === r.toBaseEid);
            const srcLabel = srcIdx === 0 ? 'Primary' : `Outpost ${srcIdx}`;
            const dstLabel = dstIdx === 0 ? 'Primary' : `Outpost ${dstIdx}`;
            const status = r.enabled ? '✓' : '✗';
            const statusColor = r.enabled ? '#22c55e' : '#ef4444';
            return `<div style="color:#94a3b8;margin:2px 0;display:flex;align-items:center;gap:6px;">
              <span style="color:${statusColor}">${status}</span>
              <span>${escapeHtml(r.name)}: ${escapeHtml(srcLabel)} → ${escapeHtml(dstLabel)} [${escapeHtml(r.resource)}] surplus&gt;${escapeHtml(r.minSurplus)}</span>
              <button data-action="delete-route:${escapeHtml(r.id)}" style="
                background:none;border:1px solid #ef444466;color:#ef4444;
                cursor:pointer;font-size:10px;padding:1px 5px;
                border-radius:2px;font-family:monospace;
              " title="Remove route">✗</button>
            </div>`;
          })
          .join('');

  const progressionHint =
    latestBases.length === 1
      ? `<div style="color:#94a3b8;font-size:11px;margin-bottom:8px;line-height:1.5;">
          Outposts let you mine distant asteroid clusters. Place one near a
          resource-rich area, then set up transfer routes to move materials
          back to your primary base.
        </div>`
      : '';

  const buildSection =
    latestBases.length < 4
      ? `<div style="margin-top:12px;border-top:1px solid #1e3a5f;padding-top:10px;">
          <div style="color:#60a5fa;margin-bottom:6px">Build New Outpost (cost: 500 Fe + 200 C)</div>
          ${progressionHint}
          <div style="color:#94a3b8;font-size:11px;margin-bottom:8px">Select a location in the game world to place your outpost.</div>
          <button data-action="enter-placement" style="
            background:#1e40af;border:none;color:#e2e8f0;padding:5px 14px;
            cursor:pointer;font-family:monospace;border-radius:4px;font-size:12px;
          ">▣ Place Outpost</button>
        </div>`
      : '<div style="color:#64748b;margin-top:10px;font-size:11px">Max bases (4) reached.</div>';

  const addRouteSection =
    latestBases.length >= 2
      ? `<div style="margin-top:10px;border-top:1px solid #1e3a5f;padding-top:10px;">
          <div style="color:#60a5fa;margin-bottom:6px">Add Transfer Route</div>
          <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap">
            <select id="route-from" style="background:#0f172a;border:1px solid #334155;color:#e2e8f0;padding:2px 4px;font-family:monospace;border-radius:3px;">
              ${latestBases.map((b, i) => `<option value="${b.eid}">${i === 0 ? 'Primary' : `Outpost ${i}`}</option>`).join('')}
            </select>
            <span style="color:#60a5fa;">→</span>
            <select id="route-to" style="background:#0f172a;border:1px solid #334155;color:#e2e8f0;padding:2px 4px;font-family:monospace;border-radius:3px;">
              ${latestBases.map((b, i) => `<option value="${b.eid}">${i === 0 ? 'Primary' : `Outpost ${i}`}</option>`).join('')}
            </select>
            <select id="route-resource" style="background:#0f172a;border:1px solid #334155;color:#e2e8f0;padding:2px 4px;font-family:monospace;border-radius:3px;">
              ${MINERALS.map((m) => `<option value="${m}">${m}</option>`).join('')}
            </select>
            <input id="route-surplus" type="number" value="200" style="width:60px;background:#0f172a;border:1px solid #334155;color:#e2e8f0;padding:2px 4px;font-family:monospace;border-radius:3px;" title="Min surplus before transferring">
            <button data-action="add-route" style="
              background:#1e40af;border:none;color:#e2e8f0;padding:3px 10px;
              cursor:pointer;font-family:monospace;border-radius:4px;font-size:12px;
            ">Add</button>
          </div>
        </div>`
      : '';

  el.innerHTML = safeHtml`
    <div class="win-drag-handle" style="
      display:flex;justify-content:space-between;align-items:center;
      padding:12px 16px 10px;
      border-bottom:1px solid #1e3a5f;
      cursor:move;user-select:none;
    ">
      <span style="color:#93c5fd;font-size:14px;font-weight:bold;letter-spacing:2px;">▦ LOGISTICS</span>
      <button data-action="close" style="
        background:none;border:1px solid #555;color:#aaa;
        padding:2px 8px;cursor:pointer;border-radius:3px;
        font-family:monospace;font-size:11px;
      " title="Close (B)">✕ close</button>
    </div>
    <div style="padding:16px;">
      <div style="margin-bottom:10px">
        <div style="color:#60a5fa;margin-bottom:6px;font-weight:bold;letter-spacing:1px;">BASES</div>
        ${trustedHtml(basesSummary)}
      </div>
      <div style="border-top:1px solid #1e3a5f;padding-top:10px">
        <div style="color:#60a5fa;margin-bottom:6px;font-weight:bold;letter-spacing:1px;">TRANSFER ROUTES</div>
        ${trustedHtml(routesSummary)}
      </div>
      ${trustedHtml(buildSection)}
      ${trustedHtml(addRouteSection)}
    </div>
  `;
}

export function initLogisticsPanel(
  enterPlacementModeCb: () => void,
  upsertRouteCb: (route: HaulRoute) => void,
  deleteRouteCb: (id: string) => void,
): void {
  onEnterPlacementMode = enterPlacementModeCb;
  onUpsertRoute = upsertRouteCb;
  onDeleteRoute = deleteRouteCb;

  // B key toggles the panel — guard prevents duplicate registration on re-init
  if (!_logisticsKeyListenerAttached) {
    _logisticsKeyListenerAttached = true;
    window.addEventListener('keydown', (e: KeyboardEvent) => {
      if ((e.target as HTMLElement).tagName === 'INPUT') return;
      if (e.key === 'b' || e.key === 'B') {
        if (isVisible) {
          hidePanel();
        } else {
          showPanel();
        }
      }
    });
  }
}

export function updateLogisticsState(bases: BaseInfo[], routes: HaulRoute[]): void {
  latestBases = bases;
  latestRoutes = routes;
  if (isVisible) renderPanel();
}

export function showBaseBuiltNotification(ok: boolean, error?: string): void {
  if (!ok) {
    showNotification(`Base build failed: ${error ?? 'unknown error'}`, '#ef4444');
  } else {
    showNotification('▲ NEW OUTPOST CONSTRUCTED', '#22d3ee');
    showScreenFlash('#22d3ee', 700);
    if (isVisible) renderPanel();
  }
}
