/**
 * Tutorial System
 *
 * First-time player guidance shown as a floating step card.
 * Steps advance automatically on detected player actions or via "Next ›" button.
 * Skip button dismisses immediately. Progress persisted to localStorage.
 */

import { highlightResourceHUD } from './hud';
import { trackTutorialComplete } from '../analytics';

const STORAGE_KEY = 'cultures_of_the_belt_tutorial';
const COMPLETED_KEY = 'cultures_of_the_belt_tutorial_done';

// ── Step definitions ──────────────────────────────────────────────────────────

interface TutorialStep {
  id: string;
  title: string;
  body: string;
  hint?: string; // small tip shown below
  autoAdvance?: boolean; // advance automatically when trigger fires (set via advance())
}

const STEPS: TutorialStep[] = [
  {
    id: 'mission',
    title: '1 / 9 — Mission Briefing',
    body: 'You command an asteroid mining operation. Mine ore, advance your tech, and build a Dyson Sphere — your robots will develop cultural traits that shape your colony along the way.',
    hint: 'Mine → Research → Build. Click Next › to continue.',
  },
  {
    id: 'camera',
    title: '2 / 9 — Camera Controls',
    body: 'Pan with WASD or arrow keys. Zoom with the scroll wheel. Your fleet is already at work near the base.',
    hint: 'Scroll out to see the full asteroid belt.',
  },
  {
    id: 'watch',
    title: '3 / 9 — Your Fleet',
    body: 'Scouts explore, Miners extract raw ore, Haulers return it to base. Aim for roughly 1 Hauler per 3 Miners so ore doesn\'t pile up.',
    hint: 'Watch the bottom-right minimap — your fleet is already working.',
    autoAdvance: true,
  },
  {
    id: 'resources',
    title: '4 / 9 — Resources',
    body: 'Watch the resource counters in the top-left — they update live as ore is collected. Fe (iron), C (carbon), Si (silicon), and H₂O (water). Press D for the full Dashboard.',
    hint: 'Press D to open the Dashboard (or click Next ›).',
  },
  {
    id: 'research',
    title: '5 / 9 — Research',
    body: 'Press T to open the Research Tree and start your first research. Tech unlocks are the key to winning.',
    hint: 'Press T to open the Research Tree (or click Next ›).',
  },
  {
    id: 'buildings',
    title: '6 / 9 — Base Buildings',
    body: 'Research unlocks three base buildings: Robot Factory (raises fleet cap), Defense Turret (auto-fires at threats), Comm Relay (extends sensor range).',
    hint: 'Press V to view Buildings once unlocked (or click Next ›).',
  },
  {
    id: 'factory',
    title: '7 / 9 — Expand Your Fleet',
    body: 'Press C to open the Construction Bay and queue your first robot build. Raw ore works early — refined materials unlock better options later.',
    hint: 'Press C to open the Construction Bay (or click Next ›).',
  },
  {
    id: 'anomaly',
    title: '8 / 9 — Anomalies',
    body: 'Some asteroids contain anomalies — unusual readings that defy standard geological models. Scout robots discover them automatically.',
    hint: 'Anomalies appear as pulsing purple dots. Open the Codex (J) to study them.',
  },
  {
    id: 'aria',
    title: '9 / 9 — ARIA',
    body: 'ARIA is your AI advisor. She analyzes your operation and gives strategic guidance. Click the ARIA panel to ask her anything.',
    hint: 'ARIA responds to anomaly discoveries automatically.',
  },
];

// ── State ─────────────────────────────────────────────────────────────────────

let currentStep = 0;
let card: HTMLDivElement | null = null;
let active = false;

// Auto-advance timer for 'watch' step
let autoAdvanceTimeout: ReturnType<typeof setTimeout> | null = null;

// Step-shown callbacks: called whenever a specific tutorial step becomes visible
const stepShownCallbacks: Map<string, Array<() => void>> = new Map();

// ── Public API ────────────────────────────────────────────────────────────────

/** Call on first game start. Returns true if tutorial should be shown. */
export function shouldShowTutorial(): boolean {
  return !localStorage.getItem(COMPLETED_KEY);
}

export function initTutorial(): void {
  // Restore progress
  try {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) currentStep = Math.min(parseInt(saved, 10), STEPS.length - 1);
  } catch {
    currentStep = 0;
  }

  buildCard();
  active = true;
  showStep(currentStep);
}

/** Returns true while the tutorial overlay is active. */
export function isTutorialActive(): boolean {
  return active;
}

/** Advance only if currently on a specific step id */
export function advanceTutorialIfOnStep(stepId: string): void {
  if (!active) return;
  if (STEPS[currentStep]?.id === stepId) nextStep();
}

/**
 * Register a callback to fire when a specific tutorial step is shown.
 * Used by external systems (e.g. the advisor panel) to react to tutorial state.
 */
export function onTutorialStepShown(stepId: string, callback: () => void): void {
  const existing = stepShownCallbacks.get(stepId) ?? [];
  existing.push(callback);
  stepShownCallbacks.set(stepId, existing);
}

// ── Internals ─────────────────────────────────────────────────────────────────

function nextStep(): void {
  if (autoAdvanceTimeout) {
    clearTimeout(autoAdvanceTimeout);
    autoAdvanceTimeout = null;
  }

  currentStep++;
  if (currentStep >= STEPS.length) {
    finish();
    return;
  }

  try {
    localStorage.setItem(STORAGE_KEY, String(currentStep));
  } catch {
    /* ignore */
  }
  showStep(currentStep);
}

function finish(): void {
  active = false;
  highlightResourceHUD(false);
  trackTutorialComplete();
  try {
    localStorage.setItem(COMPLETED_KEY, '1');
  } catch {
    /* ignore */
  }
  if (card) {
    card.style.opacity = '0';
    card.style.transition = 'opacity 0.4s';
    setTimeout(() => card?.remove(), 400);
    card = null;
  }
}

function buildCard(): void {
  card = document.createElement('div');
  card.style.cssText = `
    position: fixed;
    bottom: 80px;
    left: 50%;
    transform: translateX(-50%);
    background: rgba(10,14,28,0.96);
    border: 1px solid rgba(100,140,255,0.35);
    border-radius: 8px;
    padding: 16px 20px;
    width: 380px;
    font-family: 'Courier New', monospace;
    color: #c0d0f0;
    z-index: 85;
    box-shadow: 0 4px 24px rgba(0,0,0,0.6);
    transition: opacity 0.3s;
  `;
  document.body.appendChild(card);
}

function showStep(index: number): void {
  if (!card) return;
  const step = STEPS[index];
  if (!step) return;

  // Highlight the resource HUD when on the resources step
  highlightResourceHUD(step.id === 'resources');

  // Fire any registered step-shown callbacks
  const callbacks = stepShownCallbacks.get(step.id);
  if (callbacks) callbacks.forEach((cb) => cb());

  card.innerHTML = '';

  // Progress dots
  const dots = document.createElement('div');
  dots.style.cssText = 'display:flex;gap:4px;margin-bottom:10px;';
  for (let i = 0; i < STEPS.length; i++) {
    const dot = document.createElement('div');
    dot.style.cssText = `
      width: 6px; height: 6px; border-radius: 50%;
      background: ${i < index ? '#4060c0' : i === index ? '#7090ff' : '#2a3050'};
    `;
    dots.appendChild(dot);
  }
  card.appendChild(dots);

  // Title
  const title = document.createElement('div');
  title.style.cssText = 'font-size:12px;color:#7090e0;margin-bottom:6px;font-weight:bold;';
  title.textContent = step.title;
  card.appendChild(title);

  // Body
  const body = document.createElement('div');
  body.style.cssText = 'font-size:12px;color:#a0b0d0;line-height:1.5;margin-bottom:8px;';
  body.textContent = step.body;
  card.appendChild(body);

  // Hint
  if (step.hint) {
    const hint = document.createElement('div');
    hint.style.cssText = 'font-size:10px;color:#5060a0;margin-bottom:10px;';
    hint.textContent = `💡 ${step.hint}`;
    card.appendChild(hint);
  }

  // Buttons
  const buttons = document.createElement('div');
  buttons.style.cssText = 'display:flex;justify-content:space-between;gap:8px;';

  const skipBtn = document.createElement('button');
  skipBtn.textContent = 'Skip tutorial';
  skipBtn.style.cssText = `
    padding: 4px 12px;
    background: none;
    border: 1px solid rgba(80,90,130,0.4);
    border-radius: 4px;
    color: #4a5568;
    cursor: pointer;
    font-family: 'Courier New', monospace;
    font-size: 11px;
  `;
  skipBtn.onclick = () => finish();
  buttons.appendChild(skipBtn);

  const nextBtn = document.createElement('button');
  nextBtn.textContent = index < STEPS.length - 1 ? 'Next ›' : 'Finish ✓';
  nextBtn.style.cssText = `
    padding: 4px 16px;
    background: rgba(50,70,150,0.6);
    border: 1px solid rgba(100,140,255,0.3);
    border-radius: 4px;
    color: #a0c0ff;
    cursor: pointer;
    font-family: 'Courier New', monospace;
    font-size: 11px;
  `;
  nextBtn.onclick = () => nextStep();
  buttons.appendChild(nextBtn);

  card.appendChild(buttons);

  // Auto-advance 'watch' step after 8s
  if (step.autoAdvance) {
    autoAdvanceTimeout = setTimeout(() => {
      autoAdvanceTimeout = null;
      nextStep();
    }, 8000);
  }
}
