/**
 * Error handlers: sim:error, sim:worker_error.
 */
import * as Sentry from '@sentry/browser';
import type {
  WorkerToMainMessage,
  SimErrorMessage,
  SimWorkerErrorMessage,
} from '../sim/messages';
import { showNotification } from '../ui/notifications';
import type { HandlerMap } from './types';

export function registerErrorHandlers(): HandlerMap {
  return {
    'sim:error': (msg: WorkerToMainMessage) => {
      const errMsg = msg as SimErrorMessage;
      const error = new Error(errMsg.payload.message);
      error.name = 'SimError';
      console.error('[main] Sim error:', errMsg.payload.message);
      Sentry.captureException(error, {
        tags: { source: 'sim:error', tick: errMsg.payload.tick },
      });
      showNotification(
        `[ARIA] Sim error at tick ${errMsg.payload.tick} — game loop continuing`,
        '#ef4444',
      );
    },

    'sim:worker_error': (msg: WorkerToMainMessage) => {
      const errMsg = msg as SimWorkerErrorMessage;
      const e = errMsg.payload;
      const error = new Error(e.message);
      error.name = 'SimWorkerError';
      if (e.stack) error.stack = e.stack;
      console.error(`[worker_error] system=${e.system} tick=${e.tick}: ${e.message}`, e.stack ?? '');
      Sentry.captureException(error, {
        tags: { source: 'sim:worker_error', system: e.system, tick: e.tick },
      });
      showNotification(
        `[ARIA] Worker error in ${e.system} at tick ${e.tick} — game loop continuing`,
        '#ef4444',
      );
    },
  };
}
