/**
 * Fleet tab renderer — robot type/state breakdown, efficiency, roster.
 *
 * The roster section is cached and only rebuilt when robotCount changes,
 * preventing DOM replacement from swallowing click events between
 * mousedown and click (the rows would otherwise be destroyed mid-click
 * by the per-frame re-render).
 *
 * Navigation uses robot EID lookup against the live buffer so coordinates
 * are always current, even if the roster DOM is from a previous frame.
 */

import { attachTooltip } from '../tooltip';
import { playSfx } from '../../audio/sfxEngine';
import {
  getRobotEid,
  getRobotType,
  getRobotState,
  getRobotEnergyPct,
} from '../../sim/bufferLayout';
import { ROBOT_TYPE_NAMES } from '../../sim/robotProfiles';
import { ROBOT_STATE_NAMES } from '../../sim/robotCreation';
import { FleetSnapshot, ROBOT_TYPE_COLORS } from './types';
import { sectionHeader, barRow, statRow } from './helpers';

export interface FleetTabData {
  fleet: FleetSnapshot;
  robotBuffer: Float32Array | null;
  robotCount: number;
  /** Navigate camera to a robot by its entity ID (reads live coords). */
  onLocateRobotByEid: ((eid: number) => void) | null;
}

// ── Roster cache ────────────────────────────────────────────────────────────
// Survives across re-renders so click handlers remain attached to live DOM.

let cachedRoster: HTMLDivElement | null = null;
let cachedRosterCount = -1;
let cachedRosterClickable = false;

/** Reset roster cache (e.g. on tab switch or game load). */
export function invalidateFleetRoster(): void {
  cachedRoster = null;
  cachedRosterCount = -1;
}

// ── Render ──────────────────────────────────────────────────────────────────

export function renderFleetTab(container: HTMLDivElement, data: FleetTabData): void {
  container.innerHTML = '';

  const { fleet, robotBuffer, robotCount, onLocateRobotByEid } = data;
  const total = fleet.total;

  // Efficiency summary
  container.appendChild(sectionHeader('Fleet Overview'));

  const eff = total > 0 ? Math.round((fleet.productive / total) * 100) : 0;
  const idle = fleet.countByState[0];
  const broken = fleet.countByState[6];

  container.appendChild(statRow('Total robots', String(total)));

  const productiveRow = statRow('Productive', `${fleet.productive} (${eff}%)`);
  attachTooltip(
    productiveRow,
    'Robots actively mining or hauling\nHigher % = better fleet utilization\nTarget: >70%',
  );
  container.appendChild(productiveRow);

  const idleRow = statRow('Idle', String(idle));
  attachTooltip(
    idleRow,
    'Robots waiting for assignments\nHigh idle count may mean no accessible asteroids\nor insufficient haulers to clear the queue',
  );
  container.appendChild(idleRow);

  const brokenRow = statRow('Broken', String(broken));
  attachTooltip(
    brokenRow,
    'Robots that need repair\nEngineer robots can repair broken units\nBroken robots do not consume energy',
  );
  container.appendChild(brokenRow);

  const energyRow = statRow('Avg energy', `${Math.round(fleet.avgEnergy * 100)}%`);
  attachTooltip(
    energyRow,
    'Average battery charge across all robots\nRobots return to base to recharge when low\n<25% means robots are spending more time charging than working',
  );
  container.appendChild(energyRow);

  // By type
  container.appendChild(sectionHeader('By Type'));
  for (let t = 0; t < 7; t++) {
    const count = fleet.countByType[t];
    if (count === 0) continue;
    container.appendChild(
      barRow(
        ROBOT_TYPE_NAMES[t],
        count,
        Math.max(...Array.from(fleet.countByType), 1),
        ROBOT_TYPE_COLORS[t],
        String(count),
      ),
    );
  }

  // By state
  container.appendChild(sectionHeader('By State'));
  const stateColors = ['#64748b', '#3b82f6', '#f59e0b', '#06b6d4', '#6366f1', '#22c55e', '#ef4444'];
  for (let s = 0; s < 7; s++) {
    const count = fleet.countByState[s];
    if (count === 0) continue;
    container.appendChild(
      barRow(ROBOT_STATE_NAMES[s], count, Math.max(total, 1), stateColors[s], String(count)),
    );
  }

  // Individual robot roster (cached across re-renders)
  if (robotBuffer && robotCount > 0) {
    container.appendChild(sectionHeader(`Roster (${robotCount} robots)`));

    const clickable = onLocateRobotByEid !== null;
    const hint = document.createElement('div');
    hint.style.cssText = 'color:#4a5568;font-size:10px;margin-bottom:4px;';
    hint.textContent = clickable ? 'Click a robot to navigate camera to it.' : '';
    container.appendChild(hint);

    // Rebuild roster only when robot count or clickability changes
    if (robotCount !== cachedRosterCount || clickable !== cachedRosterClickable || !cachedRoster) {
      cachedRoster = buildRoster(robotBuffer, robotCount, onLocateRobotByEid);
      cachedRosterCount = robotCount;
      cachedRosterClickable = clickable;
    } else {
      // Update energy/state text in existing rows without rebuilding DOM
      updateRosterInPlace(cachedRoster, robotBuffer, robotCount);
    }

    container.appendChild(cachedRoster);
  }
}

// ── Roster builder ──────────────────────────────────────────────────────────

function buildRoster(
  robotBuffer: Float32Array,
  robotCount: number,
  onLocateRobotByEid: ((eid: number) => void) | null,
): HTMLDivElement {
  const rosterList = document.createElement('div');
  rosterList.style.cssText =
    'display:flex;flex-direction:column;gap:2px;max-height:220px;overflow-y:auto;';

  for (let i = 0; i < robotCount; i++) {
    const eid = getRobotEid(robotBuffer, i);
    const type = Math.min(6, getRobotType(robotBuffer, i));
    const state = getRobotState(robotBuffer, i);
    const energy = getRobotEnergyPct(robotBuffer, i);

    const row = document.createElement('div');
    row.dataset.robotEid = String(eid);
    row.style.cssText = `
      display: flex;
      align-items: center;
      gap: 6px;
      padding: 3px 6px;
      background: rgba(30,40,70,0.4);
      border-radius: 3px;
      border-left: 3px solid ${ROBOT_TYPE_COLORS[type]};
      ${onLocateRobotByEid ? 'cursor:pointer;' : ''}
    `;

    const nameEl = document.createElement('span');
    nameEl.style.cssText = `color:${ROBOT_TYPE_COLORS[type]};font-size:11px;width:70px;flex-shrink:0;`;
    nameEl.textContent = ROBOT_TYPE_NAMES[type] ?? 'Unknown';

    const stateEl = document.createElement('span');
    stateEl.className = 'roster-state';
    stateEl.style.cssText = 'color:#8090b0;font-size:10px;flex:1;';
    stateEl.textContent = ROBOT_STATE_NAMES[state] ?? '?';

    const energyPct = Math.round(energy * 100);
    const energyEl = document.createElement('span');
    energyEl.className = 'roster-energy';
    energyEl.style.cssText = `color:${energyColor(energyPct)};font-size:10px;width:35px;text-align:right;flex-shrink:0;`;
    energyEl.textContent = `${energyPct}%`;

    row.appendChild(nameEl);
    row.appendChild(stateEl);
    row.appendChild(energyEl);

    if (onLocateRobotByEid) {
      const locateFn = onLocateRobotByEid;
      const robotEid = eid;
      row.addEventListener('click', () => {
        playSfx('ui.ship_highlight');
        locateFn(robotEid);
      });
      row.addEventListener('mouseenter', () => {
        row.style.background = 'rgba(50,60,100,0.6)';
      });
      row.addEventListener('mouseleave', () => {
        row.style.background = 'rgba(30,40,70,0.4)';
      });
    }

    rosterList.appendChild(row);
  }

  return rosterList;
}

// ── In-place roster update ──────────────────────────────────────────────────
// Update energy and state text without replacing DOM nodes.

function updateRosterInPlace(
  rosterList: HTMLDivElement,
  robotBuffer: Float32Array,
  robotCount: number,
): void {
  const rows = rosterList.children;
  const count = Math.min(rows.length, robotCount);
  for (let i = 0; i < count; i++) {
    const row = rows[i] as HTMLElement;
    const state = getRobotState(robotBuffer, i);
    const energy = getRobotEnergyPct(robotBuffer, i);

    const stateEl = row.querySelector('.roster-state') as HTMLElement | null;
    if (stateEl) stateEl.textContent = ROBOT_STATE_NAMES[state] ?? '?';

    const energyPct = Math.round(energy * 100);
    const energyEl = row.querySelector('.roster-energy') as HTMLElement | null;
    if (energyEl) {
      energyEl.textContent = `${energyPct}%`;
      energyEl.style.color = energyColor(energyPct);
    }
  }
}

function energyColor(pct: number): string {
  return pct < 25 ? '#ef4444' : pct < 60 ? '#f59e0b' : '#22c55e';
}
