/**
 * SolarSystemRenderer — renders planets and the Sun as procedural sprites
 * at their real 2089-03-22 heliocentric positions.
 *
 * Each body gets a canvas-drawn texture turned into a Three.js Sprite.
 * Labels are separate sprites that fade based on camera distance.
 */

import {
  CanvasTexture,
  Group,
  LinearFilter,
  Scene,
  Sprite,
  SpriteMaterial,
  Vector3,
} from 'three';
import { SOLAR_BODIES, type SolarBody } from '../../sim/solarSystem';

const TEX_SIZE = 128;
const LABEL_TEX_W = 256;
const LABEL_TEX_H = 48;

/** Reference distance for apparent size scaling. */
const REF_DIST = 50_000;
const MIN_SCALE = 80;
const MAX_SCALE = 1200;
const SUN_MIN_SCALE = 800;
const SUN_MAX_SCALE = 12_000;
const MOON_MIN_SCALE = 15;
const MOON_MAX_SCALE = 120;

/** Label starts fading beyond this distance, fully gone at 2x. */
const LABEL_FADE_NEAR = 120_000;
const LABEL_FADE_FAR = 400_000;

interface BodySprite {
  body: SolarBody;
  sprite: Sprite;
  label: Sprite;
  labelMat: SpriteMaterial;
  baseScale: number;
  minScale: number;
  maxScale: number;
}

export class SolarSystemRenderer {
  private group: Group;
  private bodies: BodySprite[] = [];

  constructor(scene: Scene) {
    this.group = new Group();
    this.group.renderOrder = 0; // after skybox (-1) so planets are visible

    for (const body of SOLAR_BODIES) {
      const tex = createBodyTexture(body);
      const mat = new SpriteMaterial({ map: tex, transparent: true, depthWrite: false });
      const sprite = new Sprite(mat);
      sprite.position.set(body.x, 0, body.z);

      const baseScale = body.name === 'Sun' ? 4000 : body.isMoon ? 40 : scaleForRadius(body.radiusKm);
      const [minS, maxS] = body.name === 'Sun'
        ? [SUN_MIN_SCALE, SUN_MAX_SCALE]
        : body.isMoon
          ? [MOON_MIN_SCALE, MOON_MAX_SCALE]
          : [MIN_SCALE, MAX_SCALE];
      sprite.scale.setScalar(baseScale);

      this.group.add(sprite);

      // Label sprite
      const { texture: labelTex, material: labelMat } = createLabelSprite(body.name);
      const label = new Sprite(labelMat);
      label.position.set(body.x, baseScale * 0.6, body.z);
      label.scale.set(baseScale * 1.5, baseScale * 0.3, 1);
      this.group.add(label);

      this.bodies.push({ body, sprite, label, labelMat, baseScale, minScale: minS, maxScale: maxS });
    }

    scene.add(this.group);
  }

  update(cameraPosition: Vector3): void {
    for (const b of this.bodies) {
      const dx = cameraPosition.x - b.body.x;
      const dz = cameraPosition.z - b.body.z;
      const dist = Math.sqrt(dx * dx + dz * dz) || 1;

      // Apparent size: closer = bigger, clamped
      const apparent = b.baseScale * (REF_DIST / dist);
      const scale = Math.min(b.maxScale, Math.max(b.minScale, apparent));
      b.sprite.scale.setScalar(scale);

      // Label position and size
      b.label.position.set(b.body.x, scale * 0.6, b.body.z);
      b.label.scale.set(scale * 1.8, scale * 0.35, 1);

      // Label fade
      const fadeT = Math.max(0, Math.min(1, (dist - LABEL_FADE_NEAR) / (LABEL_FADE_FAR - LABEL_FADE_NEAR)));
      b.labelMat.opacity = 1 - fadeT;
    }
  }

  dispose(): void {
    for (const b of this.bodies) {
      b.sprite.material.map?.dispose();
      b.sprite.material.dispose();
      b.labelMat.map?.dispose();
      b.labelMat.dispose();
    }
    this.group.parent?.remove(this.group);
  }
}

// ── Texture generation ──────────────────────────────────────────────────────

function scaleForRadius(radiusKm: number): number {
  // Log scale so Jupiter doesn't dwarf everything, but large enough to see from belt distance
  return 120 + Math.log2(radiusKm / 1000) * 80;
}

function createBodyTexture(body: SolarBody): CanvasTexture {
  const canvas = document.createElement('canvas');
  canvas.width = TEX_SIZE;
  canvas.height = TEX_SIZE;
  const ctx = canvas.getContext('2d')!;
  const cx = TEX_SIZE / 2;
  const cy = TEX_SIZE / 2;
  const r = TEX_SIZE * 0.4;

  if (body.name === 'Sun') {
    drawSun(ctx, cx, cy, r);
  } else if (body.name === 'Jupiter') {
    drawJupiter(ctx, cx, cy, r);
  } else if (body.name === 'Saturn') {
    drawSaturn(ctx, cx, cy, r);
  } else if (body.name === 'Earth') {
    drawEarth(ctx, cx, cy, r);
  } else if (body.isMoon) {
    drawMoon(ctx, cx, cy, r);
  } else {
    drawGenericPlanet(ctx, cx, cy, r, body.color);
  }

  const tex = new CanvasTexture(canvas);
  tex.minFilter = LinearFilter;
  tex.magFilter = LinearFilter;
  return tex;
}

function drawSun(ctx: CanvasRenderingContext2D, cx: number, cy: number, r: number): void {
  // Outer glow
  const glow = ctx.createRadialGradient(cx, cy, r * 0.3, cx, cy, r * 1.2);
  glow.addColorStop(0, 'rgba(255,255,240,1)');
  glow.addColorStop(0.3, 'rgba(255,240,180,0.9)');
  glow.addColorStop(0.6, 'rgba(255,200,60,0.4)');
  glow.addColorStop(1, 'rgba(255,180,40,0)');
  ctx.fillStyle = glow;
  ctx.fillRect(0, 0, TEX_SIZE, TEX_SIZE);

  // Core
  const core = ctx.createRadialGradient(cx, cy, 0, cx, cy, r * 0.5);
  core.addColorStop(0, '#fffff0');
  core.addColorStop(1, '#ffdd66');
  ctx.beginPath();
  ctx.arc(cx, cy, r * 0.5, 0, Math.PI * 2);
  ctx.fillStyle = core;
  ctx.fill();
}

function drawJupiter(ctx: CanvasRenderingContext2D, cx: number, cy: number, r: number): void {
  // Base tan sphere
  const grad = ctx.createRadialGradient(cx - r * 0.2, cy - r * 0.2, 0, cx, cy, r);
  grad.addColorStop(0, '#e8c888');
  grad.addColorStop(1, '#a07840');
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI * 2);
  ctx.fillStyle = grad;
  ctx.fill();

  // Horizontal bands
  const bands = [
    { y: -0.6, h: 0.15, color: 'rgba(180,140,80,0.5)' },
    { y: -0.3, h: 0.12, color: 'rgba(200,160,100,0.4)' },
    { y: 0.0,  h: 0.18, color: 'rgba(160,110,60,0.5)' },
    { y: 0.3,  h: 0.14, color: 'rgba(190,150,90,0.4)' },
    { y: 0.6,  h: 0.10, color: 'rgba(170,120,70,0.5)' },
  ];

  ctx.save();
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI * 2);
  ctx.clip();
  for (const band of bands) {
    ctx.fillStyle = band.color;
    ctx.fillRect(cx - r, cy + band.y * r, r * 2, band.h * r);
  }
  // Great Red Spot hint
  ctx.fillStyle = 'rgba(180,80,50,0.6)';
  ctx.beginPath();
  ctx.ellipse(cx + r * 0.2, cy + r * 0.2, r * 0.15, r * 0.1, 0, 0, Math.PI * 2);
  ctx.fill();
  ctx.restore();
}

function drawSaturn(ctx: CanvasRenderingContext2D, cx: number, cy: number, r: number): void {
  // Ring first (behind planet body)
  ctx.strokeStyle = 'rgba(200,180,140,0.5)';
  ctx.lineWidth = r * 0.12;
  ctx.beginPath();
  ctx.ellipse(cx, cy, r * 1.6, r * 0.35, 0, 0, Math.PI * 2);
  ctx.stroke();

  // Inner ring
  ctx.strokeStyle = 'rgba(180,160,120,0.3)';
  ctx.lineWidth = r * 0.06;
  ctx.beginPath();
  ctx.ellipse(cx, cy, r * 1.3, r * 0.28, 0, 0, Math.PI * 2);
  ctx.stroke();

  // Body
  const grad = ctx.createRadialGradient(cx - r * 0.15, cy - r * 0.15, 0, cx, cy, r * 0.75);
  grad.addColorStop(0, '#e0c890');
  grad.addColorStop(1, '#907850');
  ctx.beginPath();
  ctx.arc(cx, cy, r * 0.75, 0, Math.PI * 2);
  ctx.fillStyle = grad;
  ctx.fill();
}

function drawEarth(ctx: CanvasRenderingContext2D, cx: number, cy: number, r: number): void {
  // Blue ocean base
  const grad = ctx.createRadialGradient(cx - r * 0.2, cy - r * 0.2, 0, cx, cy, r);
  grad.addColorStop(0, '#5599dd');
  grad.addColorStop(1, '#224488');
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI * 2);
  ctx.fillStyle = grad;
  ctx.fill();

  // Crude continent shapes
  ctx.save();
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI * 2);
  ctx.clip();
  ctx.fillStyle = 'rgba(80,140,60,0.6)';
  // "Africa/Europe"
  ctx.beginPath();
  ctx.ellipse(cx + r * 0.1, cy - r * 0.1, r * 0.25, r * 0.4, 0.2, 0, Math.PI * 2);
  ctx.fill();
  // "Americas"
  ctx.beginPath();
  ctx.ellipse(cx - r * 0.4, cy + r * 0.1, r * 0.15, r * 0.35, -0.3, 0, Math.PI * 2);
  ctx.fill();
  // Ice caps
  ctx.fillStyle = 'rgba(220,230,255,0.5)';
  ctx.beginPath();
  ctx.ellipse(cx, cy - r * 0.85, r * 0.3, r * 0.1, 0, 0, Math.PI * 2);
  ctx.fill();
  ctx.restore();
}

function drawMoon(ctx: CanvasRenderingContext2D, cx: number, cy: number, r: number): void {
  const grad = ctx.createRadialGradient(cx - r * 0.2, cy - r * 0.2, 0, cx, cy, r);
  grad.addColorStop(0, '#bbbbbb');
  grad.addColorStop(1, '#666666');
  ctx.beginPath();
  ctx.arc(cx, cy, r * 0.6, 0, Math.PI * 2);
  ctx.fillStyle = grad;
  ctx.fill();
}

function drawGenericPlanet(ctx: CanvasRenderingContext2D, cx: number, cy: number, r: number, color: string): void {
  const grad = ctx.createRadialGradient(cx - r * 0.2, cy - r * 0.2, 0, cx, cy, r);
  grad.addColorStop(0, lighten(color, 0.3));
  grad.addColorStop(1, color);
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI * 2);
  ctx.fillStyle = grad;
  ctx.fill();
}

function lighten(hex: string, amount: number): string {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return `rgb(${Math.min(255, r + (255 - r) * amount)}, ${Math.min(255, g + (255 - g) * amount)}, ${Math.min(255, b + (255 - b) * amount)})`;
}

// ── Label sprites ───────────────────────────────────────────────────────────

function createLabelSprite(name: string): { texture: CanvasTexture; material: SpriteMaterial } {
  const canvas = document.createElement('canvas');
  canvas.width = LABEL_TEX_W;
  canvas.height = LABEL_TEX_H;
  const ctx = canvas.getContext('2d')!;

  ctx.font = 'bold 28px "Courier New", monospace';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillStyle = 'rgba(200,220,255,0.85)';
  ctx.fillText(name, LABEL_TEX_W / 2, LABEL_TEX_H / 2);

  const texture = new CanvasTexture(canvas);
  texture.minFilter = LinearFilter;
  texture.magFilter = LinearFilter;
  const material = new SpriteMaterial({
    map: texture,
    transparent: true,
    depthWrite: false,
  });
  return { texture, material };
}
