/**
 * Megastructure handlers: sim:megastructure_state.
 */
import type {
  WorkerToMainMessage,
  SimMegastructureStateMessage,
} from '../sim/messages';
import { ROBOT_TYPES } from '../sim/robotProfiles';
import { getRobotType } from '../sim/bufferLayout';
import { showNotification } from '../ui/notifications';
import { showHint } from '../ui/hints';
import { checkAchievements } from '../ui/milestones';
import { getMegastructureBroadcast, seedKnownMegastructureStages } from '../advisor/ariaProactiveBroadcasts';
import { MEGASTRUCTURE_DEFS, type MegastructureId } from '../sim/megastructures';
import { showColonyEpithetModal, hasColonyEpithetBeenPrompted } from '../ui/colonyEpithetModal';
import { updateMegaCrisisCountdownHUD } from '../ui/hud';
import type { HandlerContext, HandlerMap, HandlerState } from './types';

/** Dyson Swarm completed-stage threshold for the epithet prompt (≈25% of 8 stages). */
const DYSON_EPITHET_THRESHOLD = 2;

export function registerMegastructureHandlers(
  ctx: HandlerContext,
  state: HandlerState,
): HandlerMap {
  const { refs, lazy } = ctx;

  return {
    'sim:megastructure_state': (msg: WorkerToMainMessage) => {
      const mMsg = msg as SimMegastructureStateMessage;
      refs.latestMegaProjects = mMsg.payload.projects;
      if (state.firstMegastructureMessage) {
        state.firstMegastructureMessage = false;
        seedKnownMegastructureStages(mMsg.payload.projects);
      } else {
        for (const p of mMsg.payload.projects) {
          if (p.completedStages > 0) {
            const broadcastMsg = getMegastructureBroadcast(
              p.id as MegastructureId,
              p.completedStages,
            );
            if (broadcastMsg) {
              void lazy.loadAdvisorLazy().then((m) => {
                lazy.initAdvisorOnce(m);
                m.panel.addProactiveBroadcast(broadcastMsg);
              });
            }
          }
        }
      }
      let engCount = 0;
      if (refs.latestRobotBuffer && refs.latestRobotCount > 0) {
        for (let i = 0; i < refs.latestRobotCount; i++) {
          if (getRobotType(refs.latestRobotBuffer, i) === ROBOT_TYPES.ENGINEER) engCount++;
        }
      }
      lazy.getMegaPanel()?.updateMegastructurePanel(refs.latestMegaProjects, engCount, refs.latestRefined);
      // Drive crisis countdown HUD
      const countdownItems = mMsg.payload.projects
        .filter((p) => p.crisisCountdownTicksRemaining != null && p.crisisCountdownTicksRemaining > 0)
        .map((p) => ({
          structureName: MEGASTRUCTURE_DEFS[p.id as MegastructureId]?.name ?? p.id,
          stageName: p.activeStageIndex != null
            ? (MEGASTRUCTURE_DEFS[p.id as MegastructureId]?.stages[p.activeStageIndex]?.name ?? `Stage ${p.activeStageIndex}`)
            : 'Unknown',
          ticksRemaining: p.crisisCountdownTicksRemaining!,
        }));
      updateMegaCrisisCountdownHUD(countdownItems);
      checkAchievements(
        {
          megastructureCompletedStages: Object.fromEntries(
            refs.latestMegaProjects.map((p) => [p.id, p.completedStages]),
          ),
          techNodeCount: 0,
          totalTechNodes: 0,
          robotCount: refs.latestRobotCount,
        },
        showNotification,
      );
      {
        const dyson = refs.latestMegaProjects.find((p) => p.id === 'dyson_swarm');
        if (dyson) {
          showHint('lategame_megastructure_unlock', 'ARIA: The Dyson Swarm is now available — humanity\'s long-term win condition. Press G to manage megastructure construction.');
          if (dyson.completedStages >= 6) {
            showHint('lategame_dyson_approach', 'ARIA: The swarm is nearing full enclosure. Commander, completing this will broadcast our presence to the cosmos. There is no undoing a Type II energy signature.');
          }
          // Prompt colony epithet when Dyson reaches 25% and no epithet set yet
          if (
            dyson.completedStages >= DYSON_EPITHET_THRESHOLD &&
            !hasColonyEpithetBeenPrompted() &&
            !refs.latestCultureState?.colonyEpithet
          ) {
            showColonyEpithetModal((epithet) => {
              ctx.worker.postMessage({
                type: 'sim:set_colony_epithet',
                payload: { epithet },
              });
            });
          }
        }
      }
    },
  };
}
