/**
 * Asteroid Info Panel
 *
 * Contextual panel shown when clicking a scanned asteroid.
 * Displays type, size, composition, health, richness, anomaly, depletion estimate,
 * and allows player to name the asteroid.
 */

import { playSfx } from '../audio/sfxEngine';
import { ASTEROID_NAME_MAX_LENGTH } from '../sim/culture';

// ── Types ─────────────────────────────────────────────────────────────────────

export interface AsteroidDetail {
  eid: number;
  typeName: string;
  sizeTier: number;
  composition: Record<string, number>;
  healthPct: number;
  richness: number;
  anomalyType: number;
  estimatedDepletionTicks: number | null;
}

// ── Constants ─────────────────────────────────────────────────────────────────

const SIZE_TIER_NAMES: Record<number, string> = {
  0: 'Small',
  1: 'Medium',
  2: 'Large',
  3: 'Mega',
};

const ANOMALY_NAMES: Record<number, string> = {
  1: 'Strange Mineral',
  2: 'Structured Signal',
  3: 'Spatial Distortion',
};

const MINERAL_LABELS: Record<string, string> = {
  iron: 'Iron', nickel: 'Nickel', cobalt: 'Cobalt', platinum: 'Platinum',
  ice: 'Ice', carbon: 'Carbon', silicate: 'Silicate',
};

// ── State ─────────────────────────────────────────────────────────────────────

let panel: HTMLDivElement | null = null;
let currentEid = -1;

/** Callback for naming an asteroid. Set via setAsteroidNameCallback. */
let onNameAsteroid: ((eid: number, name: string) => void) | null = null;

/** Known player-named asteroids, synced from culture state. */
const knownAsteroidNames = new Map<number, string>();

// ── Public API ────────────────────────────────────────────────────────────────

/** Register the callback for naming asteroids (called from main thread wiring). */
export function setAsteroidNameCallback(cb: (eid: number, name: string) => void): void {
  onNameAsteroid = cb;
}

/** Update the known asteroid names from culture state broadcasts. */
export function updateKnownAsteroidNames(names: Array<{ eid: number; name: string }>): void {
  knownAsteroidNames.clear();
  for (const { eid, name } of names) {
    knownAsteroidNames.set(eid, name);
  }
}

/**
 * Show the asteroid panel placeholder and request detail from worker.
 */
export function showAsteroidInfoPanel(eid: number, screenX: number, screenY: number): void {
  playSfx('ui.panel_open');
  currentEid = eid;
  if (!panel) buildPanel();
  positionPanel(screenX, screenY);
  panel!.style.display = 'block';
  renderLoading();
}

/**
 * Hide the asteroid panel.
 */
export function hideAsteroidInfoPanel(): void {
  if (panel) panel.style.display = 'none';
  currentEid = -1;
}

/**
 * Check whether the asteroid panel is currently visible.
 */
export function isAsteroidInfoPanelVisible(): boolean {
  return panel !== null && panel.style.display !== 'none';
}

/**
 * Update the panel with detail data received from the worker.
 */
export function updateAsteroidInfoPanel(detail: AsteroidDetail): void {
  if (detail.eid !== currentEid || !panel) return;
  renderDetail(detail);
}

// ── Private ───────────────────────────────────────────────────────────────────

function buildPanel(): void {
  panel = document.createElement('div');
  panel.id = 'asteroid-info-panel';
  panel.style.cssText = `
    position: fixed;
    display: none;
    background: rgba(8,12,24,0.97);
    border: 1px solid rgba(180,140,60,0.4);
    border-radius: 8px;
    padding: 12px 14px;
    min-width: 210px;
    max-width: 260px;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    color: #c0d0f0;
    box-shadow: 0 4px 20px rgba(0,0,0,0.7);
    z-index: 300;
  `;
  document.body.appendChild(panel);

  document.addEventListener('click', (e) => {
    if (panel && panel.style.display !== 'none') {
      if (!panel.contains(e.target as Node)) {
        hideAsteroidInfoPanel();
      }
    }
  });
}

function positionPanel(screenX: number, screenY: number): void {
  if (!panel) return;
  const margin = 8;
  const panelW = 240;
  const panelH = 280;
  const vw = window.innerWidth;
  const vh = window.innerHeight;
  let left = screenX + margin;
  let top = screenY - panelH / 2;
  if (left + panelW > vw - margin) left = screenX - panelW - margin;
  if (top < margin) top = margin;
  if (top + panelH > vh - margin) top = vh - panelH - margin;
  panel.style.left = `${left}px`;
  panel.style.top = `${top}px`;
}

function renderLoading(): void {
  if (!panel) return;
  panel.innerHTML = '';

  const header = makeHeader();
  panel.appendChild(header);

  const loading = document.createElement('div');
  loading.style.cssText = 'color:#4a5568;text-align:center;padding:16px 0;';
  loading.textContent = 'Scanning...';
  panel.appendChild(loading);
}

function renderDetail(detail: AsteroidDetail): void {
  if (!panel) return;
  panel.innerHTML = '';

  panel.appendChild(makeHeader());

  // Info rows
  const info = document.createElement('div');
  info.style.cssText = 'margin-bottom:10px;';

  const sizeName = SIZE_TIER_NAMES[detail.sizeTier] ?? `Tier ${detail.sizeTier}`;

  const rows: [string, string, string?][] = [
    ['Type', detail.typeName, typeColor(detail.typeName)],
    ['Size', sizeName],
    ['Richness', `\u00d7${detail.richness.toFixed(1)}`],
  ];

  for (const [key, val, color] of rows) {
    info.appendChild(makeRow(key, val, color));
  }

  panel.appendChild(info);

  // Health bar
  const healthSection = document.createElement('div');
  healthSection.style.cssText = 'margin-bottom:10px;';

  const healthLabel = document.createElement('div');
  healthLabel.style.cssText = 'display:flex;justify-content:space-between;margin-bottom:4px;';
  const healthKey = document.createElement('span');
  healthKey.style.cssText = 'color:#5060a0;';
  healthKey.textContent = 'Health';
  const healthVal = document.createElement('span');
  healthVal.style.cssText = 'color:#a0c0ff;';
  healthVal.textContent = `${Math.round(detail.healthPct * 100)}%`;
  healthLabel.appendChild(healthKey);
  healthLabel.appendChild(healthVal);
  healthSection.appendChild(healthLabel);

  const healthBar = document.createElement('div');
  healthBar.style.cssText = 'height:4px;background:rgba(255,255,255,0.1);border-radius:2px;';
  const healthFill = document.createElement('div');
  const pct = Math.round(detail.healthPct * 100);
  const barColor = pct > 60 ? '#4ade80' : pct > 25 ? '#f59e0b' : '#ef4444';
  healthFill.style.cssText = `height:100%;width:${pct}%;background:${barColor};border-radius:2px;transition:width 0.3s;`;
  healthBar.appendChild(healthFill);
  healthSection.appendChild(healthBar);

  if (detail.estimatedDepletionTicks !== null) {
    const deplete = document.createElement('div');
    deplete.style.cssText = 'color:#f59e0b;font-size:10px;margin-top:4px;';
    const minutes = Math.ceil(detail.estimatedDepletionTicks / 60);
    deplete.textContent = `Depletes in ~${minutes < 1 ? '<1' : minutes} min`;
    healthSection.appendChild(deplete);
  }

  panel.appendChild(healthSection);

  // Composition
  const compSection = document.createElement('div');
  compSection.style.cssText = 'border-top:1px solid rgba(180,140,60,0.15);padding-top:6px;margin-bottom:8px;';

  const compTitle = document.createElement('div');
  compTitle.style.cssText = 'color:#5060a0;font-size:10px;margin-bottom:4px;';
  compTitle.textContent = 'COMPOSITION';
  compSection.appendChild(compTitle);

  // Sort minerals by amount, show top entries
  const entries = Object.entries(detail.composition)
    .filter(([, v]) => v > 0.01)
    .sort(([, a], [, b]) => b - a);

  if (entries.length === 0) {
    const empty = document.createElement('div');
    empty.style.cssText = 'color:#2d3748;font-size:10px;';
    empty.textContent = 'No minerals detected';
    compSection.appendChild(empty);
  } else {
    const total = entries.reduce((sum, [, v]) => sum + v, 0);
    for (const [field, amount] of entries) {
      const label = MINERAL_LABELS[field] ?? field;
      const pctVal = total > 0 ? Math.round((amount / total) * 100) : 0;
      compSection.appendChild(makeRow(label, `${pctVal}%`, '#a0c0ff'));
    }
  }

  panel.appendChild(compSection);

  // Anomaly
  if (detail.anomalyType > 0) {
    const anomaly = document.createElement('div');
    anomaly.style.cssText = 'border-top:1px solid rgba(180,140,60,0.15);padding-top:6px;margin-bottom:8px;';
    const anomalyName = ANOMALY_NAMES[detail.anomalyType] ?? `Unknown Anomaly (${detail.anomalyType})`;
    anomaly.appendChild(makeRow('Anomaly', anomalyName, '#a855f7'));
    panel.appendChild(anomaly);
  }

  // Naming section
  if (onNameAsteroid) {
    const nameSection = document.createElement('div');
    nameSection.style.cssText = 'border-top:1px solid rgba(180,140,60,0.15);padding-top:6px;';

    const existingName = knownAsteroidNames.get(detail.eid);

    if (existingName) {
      // Show current name with edit option
      const nameRow = document.createElement('div');
      nameRow.style.cssText = 'display:flex;justify-content:space-between;align-items:center;';
      const nameLabel = document.createElement('span');
      nameLabel.style.cssText = 'color:#06b6d4;font-size:11px;';
      nameLabel.textContent = `"${existingName}"`;
      nameRow.appendChild(nameLabel);

      const editBtn = document.createElement('button');
      editBtn.textContent = 'Rename';
      editBtn.style.cssText = 'background:none;border:1px solid #06b6d444;color:#06b6d4;cursor:pointer;font-family:"Courier New",monospace;font-size:9px;padding:2px 8px;border-radius:2px;text-transform:uppercase;letter-spacing:0.5px;';
      editBtn.addEventListener('click', () => {
        showNameInput(nameSection, detail.eid, existingName);
      });
      nameRow.appendChild(editBtn);
      nameSection.appendChild(nameRow);
    } else {
      // Show "Name this asteroid" button
      const nameBtn = document.createElement('button');
      nameBtn.textContent = 'Name this asteroid';
      nameBtn.style.cssText = 'width:100%;background:none;border:1px solid #06b6d444;color:#06b6d4;cursor:pointer;font-family:"Courier New",monospace;font-size:10px;padding:6px;border-radius:2px;text-transform:uppercase;letter-spacing:0.5px;transition:background 0.2s;';
      nameBtn.addEventListener('mouseover', () => {
        nameBtn.style.background = 'rgba(6,182,212,0.1)';
      });
      nameBtn.addEventListener('mouseout', () => {
        nameBtn.style.background = 'none';
      });
      nameBtn.addEventListener('click', () => {
        showNameInput(nameSection, detail.eid);
      });
      nameSection.appendChild(nameBtn);
    }

    panel.appendChild(nameSection);
  }
}

function showNameInput(container: HTMLDivElement, eid: number, existing?: string): void {
  container.innerHTML = '';

  const inputRow = document.createElement('div');
  inputRow.style.cssText = 'display:flex;gap:4px;align-items:center;';

  const input = document.createElement('input');
  input.type = 'text';
  input.maxLength = ASTEROID_NAME_MAX_LENGTH;
  input.placeholder = 'Name...';
  input.value = existing ?? '';
  input.style.cssText = 'flex:1;background:rgba(0,0,0,0.4);border:1px solid #06b6d444;border-radius:2px;color:#e2e8f0;font-family:"Courier New",monospace;font-size:11px;padding:4px 6px;outline:none;box-sizing:border-box;';

  const okBtn = document.createElement('button');
  okBtn.textContent = 'OK';
  okBtn.style.cssText = 'background:none;border:1px solid #06b6d488;color:#06b6d4;cursor:pointer;font-family:"Courier New",monospace;font-size:10px;padding:4px 10px;border-radius:2px;';
  okBtn.addEventListener('click', () => {
    const name = input.value.trim();
    if (name && onNameAsteroid) {
      onNameAsteroid(eid, name);
      knownAsteroidNames.set(eid, name);
      // Update display
      container.innerHTML = '';
      const nameLabel = document.createElement('span');
      nameLabel.style.cssText = 'color:#06b6d4;font-size:11px;';
      nameLabel.textContent = `Named: "${name}"`;
      container.appendChild(nameLabel);
    }
  });

  input.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') okBtn.click();
    e.stopPropagation(); // Prevent game hotkeys
  });
  input.addEventListener('keyup', (e) => e.stopPropagation());

  inputRow.appendChild(input);
  inputRow.appendChild(okBtn);
  container.appendChild(inputRow);

  requestAnimationFrame(() => input.focus());
}

function makeHeader(): HTMLDivElement {
  const header = document.createElement('div');
  header.style.cssText = 'display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;padding-bottom:6px;border-bottom:1px solid rgba(180,140,60,0.2);';

  const existingName = knownAsteroidNames.get(currentEid);
  const title = document.createElement('span');
  title.style.cssText = 'color:#b48c3c;font-size:12px;font-weight:bold;';
  title.textContent = existingName ? `${existingName}` : `Asteroid #${currentEid}`;
  header.appendChild(title);

  const closeBtn = document.createElement('button');
  closeBtn.textContent = '\u00d7';
  closeBtn.setAttribute('aria-label', 'Close asteroid panel');
  closeBtn.style.cssText = 'background:none;border:none;color:#666;cursor:pointer;font-size:16px;padding:0;line-height:1;';
  closeBtn.onclick = () => {
    playSfx('ui.panel_close');
    hideAsteroidInfoPanel();
  };
  header.appendChild(closeBtn);

  return header;
}

function makeRow(key: string, val: string, valColor?: string): HTMLDivElement {
  const row = document.createElement('div');
  row.style.cssText = 'display:flex;justify-content:space-between;margin-bottom:3px;';
  const keyEl = document.createElement('span');
  keyEl.style.cssText = 'color:#5060a0;';
  keyEl.textContent = key;
  const valEl = document.createElement('span');
  valEl.style.cssText = `color:${valColor ?? '#a0c0ff'};`;
  valEl.textContent = val;
  row.appendChild(keyEl);
  row.appendChild(valEl);
  return row;
}

function typeColor(typeName: string): string {
  switch (typeName) {
    case 'Carbonaceous': return '#6b7280';
    case 'Silicate': return '#a0c0ff';
    case 'Metallic': return '#c0c0c0';
    case 'Exotic': return '#a855f7';
    default: return '#a0c0ff';
  }
}
