/**
 * Builds the unified message dispatch map from all handler groups.
 */
import type { HandlerContext, HandlerMap, HandlerState } from './types';
import { createHandlerState } from './types';
import { registerStateHandlers } from './stateHandlers';
import { registerLoreHandlers } from './loreHandlers';
import { registerBuildHandlers } from './buildHandlers';
import { registerResearchHandlers } from './researchHandlers';
import { registerFactionHandlers } from './factionHandlers';
import { registerCultureHandlers } from './cultureHandlers';
import { registerMegastructureHandlers } from './megastructureHandlers';
import { registerHabitatHandlers } from './habitatHandlers';
import { registerMarketHandlers } from './marketHandlers';
import { registerErrorHandlers } from './errorHandlers';
import { registerAsteroidHandlers } from './asteroidHandlers';
import { registerTransientClusterHandlers } from './transientClusterHandlers';
import { registerCommsHandlers } from './commsHandlers';
import { registerMeridianHandlers } from './meridianHandlers';
import { registerTransitHandlers } from './transitHandlers';

export type { HandlerContext, HandlerMap, HandlerState };
export { createHandlerState };

/**
 * Create the full dispatch map by merging all handler groups.
 */
export function createDispatchMap(
  ctx: HandlerContext,
  state: HandlerState,
): HandlerMap {
  return {
    ...registerErrorHandlers(),
    ...registerStateHandlers(ctx, state),
    ...registerLoreHandlers(ctx),
    ...registerBuildHandlers(ctx),
    ...registerResearchHandlers(ctx),
    ...registerFactionHandlers(ctx, state),
    ...registerCultureHandlers(ctx, state),
    ...registerMegastructureHandlers(ctx, state),
    ...registerHabitatHandlers(ctx),
    ...registerMarketHandlers(),
    ...registerAsteroidHandlers(),
    ...registerTransientClusterHandlers(),
    ...registerCommsHandlers(),
    ...registerMeridianHandlers(ctx),
    ...registerTransitHandlers(ctx.refs),
  };
}
