/**
 * Audio Engine
 *
 * Web Audio API-based engine for Asteroid Miner.
 * All audio is procedurally generated — no external files needed.
 *
 * Features:
 * - Procedural ambient drone with mood system (calm → tense → dread)
 * - Space ambient music: evolving pads, sparse melodic motifs, hard sci-fi aesthetic
 * - DynamicsCompressor on master bus to eliminate feedback artifacts
 * - Spatial audio: attenuation by camera distance
 * - SFX: mining, thruster, discovery, research, UI, entity proximity
 * - Entity-specific audio: Drifter (infrasonic drone), Resonant (crystalline chiming)
 * - Volume controls: master, SFX, music (persisted to localStorage)
 * - M key mute toggle
 */

// ── Types ────────────────────────────────────────────────────────────────────

export interface AudioSettings {
  masterVolume: number; // 0-1
  sfxVolume: number;
  musicVolume: number;
  muted: boolean;
}

const SETTINGS_KEY = 'asteroid_miner_audio';
const DEFAULT_SETTINGS: AudioSettings = {
  masterVolume: 0.7,
  sfxVolume: 0.8,
  musicVolume: 0.6,
  muted: false,
};

// ── AudioEngine ───────────────────────────────────────────────────────────────

export class AudioEngine {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private sfxGain: GainNode | null = null;
  private musicGain: GainNode | null = null;
  private compressor: DynamicsCompressorNode | null = null;

  private settings: AudioSettings = { ...DEFAULT_SETTINGS };
  private initialized = false;

  // Music system (evolving pad layers)
  private musicNodes: {
    osc: OscillatorNode;
    filter: BiquadFilterNode;
    gain: GainNode;
    lfo: OscillatorNode;
    lfoGain: GainNode;
  }[] = [];
  private musicRunning = false;
  private musicScheduleTimer: ReturnType<typeof setTimeout> | null = null;

  // Entity audio
  private drifterNode: { osc: OscillatorNode; filter: BiquadFilterNode; gain: GainNode } | null =
    null;
  private resonantNodes: { osc: OscillatorNode; filter: BiquadFilterNode; gain: GainNode }[] = [];

  // Thruster hum (continuous while robots are moving)
  private thrusterNode: { osc: OscillatorNode; filter: BiquadFilterNode; gain: GainNode } | null =
    null;

  constructor() {
    this.loadSettings();
  }

  // ── Initialization ────────────────────────────────────────────────────────

  /**
   * Initialize audio on first user interaction.
   * Must be called from a user gesture handler (click, keydown).
   */
  async init(): Promise<void> {
    if (this.initialized) return;

    this.ctx = new AudioContext();
    if (this.ctx.state === 'suspended') {
      await this.ctx.resume();
    }

    // Master bus: compressor → masterGain → destination
    // DynamicsCompressor eliminates feedback artifacts from overlapping oscillators
    this.compressor = this.ctx.createDynamicsCompressor();
    this.compressor.threshold.value = -18; // dBFS
    this.compressor.knee.value = 10;
    this.compressor.ratio.value = 4;
    this.compressor.attack.value = 0.003;
    this.compressor.release.value = 0.25;
    this.compressor.connect(this.ctx.destination);

    this.masterGain = this.ctx.createGain();
    this.masterGain.gain.value = this.settings.muted ? 0 : this.settings.masterVolume;
    this.masterGain.connect(this.compressor);

    this.sfxGain = this.ctx.createGain();
    this.sfxGain.gain.value = this.settings.sfxVolume;
    this.sfxGain.connect(this.masterGain);

    this.musicGain = this.ctx.createGain();
    this.musicGain.gain.value = this.settings.musicVolume;
    this.musicGain.connect(this.masterGain);

    this.initialized = true;

    this.startMusic();
    this.startEntityAudio();
    this.startThrusterHum();
  }

  private ensureInit(): boolean {
    return this.initialized && this.ctx !== null;
  }

  // ── Space ambient music ───────────────────────────────────────────────────

  /**
   * Space ambient music: evolving low-pass filtered pad layers with slow LFOs.
   * Hard sci-fi asteroid belt aesthetic — sparse, cold, atmospheric.
   *
   * Architecture: 4 filtered pad layers using detuned oscillators through
   * slow-sweeping lowpass filters. Layered to create an evolving texture
   * without repeating loops.
   */
  private startMusic(): void {
    if (!this.ensureInit() || this.musicRunning) return;
    this.musicRunning = true;

    const ctx = this.ctx!;

    // Pad layers: root + fifth + octave + high-fifth in a sparse voicing
    // Using A minor tonality for sci-fi / space feel
    const padConfig = [
      { freq: 110, filterFreq: 400, lfoRate: 0.03, lfoDepth: 80, vol: 0.055 }, // A2
      { freq: 164.8, filterFreq: 600, lfoRate: 0.05, lfoDepth: 120, vol: 0.045 }, // E3
      { freq: 220, filterFreq: 900, lfoRate: 0.07, lfoDepth: 200, vol: 0.035 }, // A3
      { freq: 329.6, filterFreq: 1200, lfoRate: 0.04, lfoDepth: 300, vol: 0.025 }, // E4
    ];

    for (let i = 0; i < padConfig.length; i++) {
      const cfg = padConfig[i];

      // Oscillator: triangle for warm, softer tone than sawtooth
      const osc = ctx.createOscillator();
      osc.type = 'triangle';
      // Slight detune per layer to avoid perfect cancellation
      osc.frequency.value = cfg.freq * (1 + (i % 2 === 0 ? 0.002 : -0.002));

      // Lowpass filter sweeps slowly via LFO — creates evolving texture
      const filter = ctx.createBiquadFilter();
      filter.type = 'lowpass';
      filter.frequency.value = cfg.filterFreq;
      filter.Q.value = 0.5; // gentle roll-off

      // LFO modulates filter cutoff
      const lfo = ctx.createOscillator();
      lfo.type = 'sine';
      lfo.frequency.value = cfg.lfoRate;
      // Stagger start phase to avoid all pads peaking simultaneously
      lfo.frequency.value = cfg.lfoRate + i * 0.007;

      const lfoGain = ctx.createGain();
      lfoGain.gain.value = cfg.lfoDepth;

      lfo.connect(lfoGain);
      lfoGain.connect(filter.frequency);

      const gain = ctx.createGain();
      gain.gain.value = cfg.vol;

      osc.connect(filter);
      filter.connect(gain);
      gain.connect(this.musicGain!);

      lfo.start();
      osc.start();

      this.musicNodes.push({ osc, filter, gain, lfo, lfoGain });
    }

    // Schedule sparse melodic motifs (repeating)
    this.scheduleMelodicMotif();
  }

  /**
   * Sparse melodic motif: occasionally plays a 3-4 note phrase using
   * high-register sine tones with long decay. Re-schedules itself.
   * Adds musical interest without being intrusive.
   */
  private scheduleMelodicMotif(): void {
    if (!this.ensureInit()) return;

    // Random interval 15–40s between motifs
    const delay = 15000 + Math.random() * 25000;

    this.musicScheduleTimer = setTimeout(() => {
      if (!this.ensureInit()) return;
      this.playMelodicMotif();
      this.scheduleMelodicMotif(); // reschedule
    }, delay);
  }

  /**
   * Single melodic motif: 3-4 note phrase using pentatonic minor scale.
   * Pentatonic minor gives a universal "exotic/mysterious" quality.
   * Notes: A4=440, C5=523, E5=659, G5=784 (Am pentatonic)
   */
  private playMelodicMotif(): void {
    if (!this.ensureInit()) return;
    const ctx = this.ctx!;
    const now = ctx.currentTime;

    // Pick 3-4 random notes from Am pentatonic (A C D E G)
    const scale = [440, 523.25, 587.33, 659.25, 783.99]; // A4, C5, D5, E5, G5
    const numNotes = 3 + Math.floor(Math.random() * 2);
    const noteIndices: number[] = [];
    for (let i = 0; i < numNotes; i++) {
      noteIndices.push(Math.floor(Math.random() * scale.length));
    }

    // Sparse timing: 0.8–2.0s between notes
    let offset = 0;
    for (const idx of noteIndices) {
      const freq = scale[idx];
      const noteStart = now + offset;

      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.value = freq;

      // Bell-like envelope: fast attack, long decay
      gain.gain.setValueAtTime(0, noteStart);
      gain.gain.linearRampToValueAtTime(0.04, noteStart + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.001, noteStart + 3.0);

      osc.connect(gain);
      gain.connect(this.musicGain!);
      osc.start(noteStart);
      osc.stop(noteStart + 3.1);

      offset += 0.8 + Math.random() * 1.2;
    }
  }

  // ── Entity audio ──────────────────────────────────────────────────────────

  private startEntityAudio(): void {
    if (!this.ensureInit()) return;
    const ctx = this.ctx!;

    // Drifter: deep sub-bass drone (almost infrasonic)
    // Highpass at 30Hz prevents speaker intermod distortion from 28Hz signal
    {
      const osc = ctx.createOscillator();
      const filter = ctx.createBiquadFilter();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.value = 40; // raised from 28Hz to reduce intermod distortion
      filter.type = 'highpass';
      filter.frequency.value = 30;
      gain.gain.value = 0;
      osc.connect(filter);
      filter.connect(gain);
      gain.connect(this.musicGain!);
      osc.start();
      this.drifterNode = { osc, filter, gain };
    }

    // Resonant: lowpass-filtered to remove harsh high-frequency feedback artifacts.
    // Three detuned oscillators produce a gentle beating effect.
    // Frequencies reduced to 264/267/270 Hz (half of original) — more consonant.
    const resonantFreqs = [264, 267, 270];
    for (const freq of resonantFreqs) {
      const osc = ctx.createOscillator();
      const filter = ctx.createBiquadFilter();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.value = freq;
      // Lowpass at 1500Hz cuts harsh upper harmonics that caused feedback-like artifacts
      filter.type = 'lowpass';
      filter.frequency.value = 1500;
      filter.Q.value = 0.7;
      gain.gain.value = 0;
      osc.connect(filter);
      filter.connect(gain);
      gain.connect(this.musicGain!);
      osc.start();
      this.resonantNodes.push({ osc, filter, gain });
    }
  }

  /**
   * Update entity audio volumes based on proximity.
   * Call this each frame with normalized proximity values (0 = far, 1 = very close).
   */
  updateEntityAudio(drifterProximity: number, resonantProximity: number): void {
    if (!this.ensureInit()) return;
    const now = this.ctx!.currentTime;

    // Reduced max volumes to prevent feedback artifacts
    const drifterTarget = Math.min(0.2, drifterProximity * 0.2);
    const resonantTarget = Math.min(0.08, resonantProximity * 0.08);

    if (this.drifterNode) {
      this.drifterNode.gain.gain.linearRampToValueAtTime(drifterTarget, now + 2);
    }

    for (const node of this.resonantNodes) {
      node.gain.gain.linearRampToValueAtTime(
        resonantTarget / this.resonantNodes.length,
        now + 1.5,
      );
    }
  }

  // ── Thruster hum ──────────────────────────────────────────────────────────

  private startThrusterHum(): void {
    if (!this.ensureInit()) return;
    const ctx = this.ctx!;

    const osc = ctx.createOscillator();
    const filter = ctx.createBiquadFilter();
    const gain = ctx.createGain();

    osc.type = 'sawtooth';
    osc.frequency.value = 120;

    // Lowpass filter removes harsh sawtooth harmonics above 300Hz
    filter.type = 'lowpass';
    filter.frequency.value = 300;
    filter.Q.value = 1.0;

    gain.gain.value = 0;
    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.sfxGain!);
    osc.start();
    this.thrusterNode = { osc, filter, gain };
  }

  /**
   * Set thruster hum intensity based on number of moving robots.
   * 0 = silent, 1 = full
   */
  setThrusterIntensity(intensity: number): void {
    if (!this.ensureInit() || !this.thrusterNode) return;
    const now = this.ctx!.currentTime;
    const target = Math.min(0.04, intensity * 0.04);
    this.thrusterNode.gain.gain.linearRampToValueAtTime(target, now + 0.5);
  }

  // ── One-shot SFX ──────────────────────────────────────────────────────────

  /** Play anomaly discovery alert */
  playDiscovery(): void {
    if (!this.ensureInit()) return;
    const ctx = this.ctx!;
    const now = ctx.currentTime;

    // Rising tone: 440 → 880 Hz over 0.3s
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(440, now);
    osc.frequency.linearRampToValueAtTime(880, now + 0.3);
    gain.gain.setValueAtTime(0.15, now);
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.8);
    osc.connect(gain);
    gain.connect(this.sfxGain!);
    osc.start(now);
    osc.stop(now + 0.85);
  }

  /** Play research completion chime */
  playResearchComplete(): void {
    if (!this.ensureInit()) return;
    const ctx = this.ctx!;
    const now = ctx.currentTime;

    // Three-note ascending chime
    const notes = [523.25, 659.25, 783.99]; // C5, E5, G5
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.value = freq;
      const start = now + i * 0.15;
      gain.gain.setValueAtTime(0, start);
      gain.gain.linearRampToValueAtTime(0.12, start + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.001, start + 0.7);
      osc.connect(gain);
      gain.connect(this.sfxGain!);
      osc.start(start);
      osc.stop(start + 0.75);
    });
  }

  /** Play a short UI click */
  playUIClick(): void {
    if (!this.ensureInit()) return;
    const ctx = this.ctx!;
    const now = ctx.currentTime;

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'square';
    osc.frequency.value = 800;
    gain.gain.setValueAtTime(0.05, now);
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.06);
    osc.connect(gain);
    gain.connect(this.sfxGain!);
    osc.start(now);
    osc.stop(now + 0.07);
  }

  /** Play mining impact sound (brief noise burst) */
  playMiningImpact(): void {
    if (!this.ensureInit()) return;
    const ctx = this.ctx!;
    const now = ctx.currentTime;

    // White noise burst filtered to low-mid frequencies
    const buffer = ctx.createBuffer(1, ctx.sampleRate * 0.1, ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < data.length; i++) {
      data[i] = (Math.random() * 2 - 1) * 0.6;
    }

    const source = ctx.createBufferSource();
    source.buffer = buffer;
    const filter = ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.value = 300 + Math.random() * 200;
    filter.Q.value = 1.5;
    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.08, now);
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.1);
    source.connect(filter);
    filter.connect(gain);
    gain.connect(this.sfxGain!);
    source.start(now);
  }

  /** Play lore fragment reveal (ethereal shimmer) */
  playLoreReveal(): void {
    if (!this.ensureInit()) return;
    const ctx = this.ctx!;
    const now = ctx.currentTime;

    // Shimmer: rising high-frequency sine with long decay
    const freqs = [2093, 2637, 3136]; // C7, E7, G7
    freqs.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.value = freq;
      const start = now + i * 0.1;
      gain.gain.setValueAtTime(0.04, start);
      gain.gain.exponentialRampToValueAtTime(0.001, start + 1.5);
      osc.connect(gain);
      gain.connect(this.sfxGain!);
      osc.start(start);
      osc.stop(start + 1.6);
    });
  }

  // ── Volume / mute controls ────────────────────────────────────────────────

  toggleMute(): boolean {
    this.settings.muted = !this.settings.muted;
    this.applyMasterGain();
    this.saveSettings();
    return this.settings.muted;
  }

  get muted(): boolean {
    return this.settings.muted;
  }

  setMasterVolume(v: number): void {
    this.settings.masterVolume = Math.max(0, Math.min(1, v));
    this.applyMasterGain();
    this.saveSettings();
  }

  setSfxVolume(v: number): void {
    this.settings.sfxVolume = Math.max(0, Math.min(1, v));
    if (this.sfxGain) this.sfxGain.gain.value = v;
    this.saveSettings();
  }

  setMusicVolume(v: number): void {
    this.settings.musicVolume = Math.max(0, Math.min(1, v));
    if (this.musicGain) this.musicGain.gain.value = v;
    this.saveSettings();
  }

  getSettings(): Readonly<AudioSettings> {
    return { ...this.settings };
  }

  /** Expose AudioContext for external music systems (e.g. MusicManager). Null until init(). */
  getAudioContext(): AudioContext | null {
    return this.ctx;
  }

  /** Expose music GainNode for external music systems to connect to. Null until init(). */
  getMusicGain(): GainNode | null {
    return this.musicGain;
  }

  /** Expose SFX GainNode for external SFX systems to connect to. Null until init(). */
  getSfxGain(): GainNode | null {
    return this.sfxGain;
  }

  /**
   * Stop the procedural pad music layers and melodic motifs.
   * The ambient drone (startAmbient) is kept running.
   * Called when a real music track system takes over.
   */
  stopProceduralMusic(): void {
    // Clear scheduled melodic motif timer
    if (this.musicScheduleTimer !== null) {
      clearTimeout(this.musicScheduleTimer);
      this.musicScheduleTimer = null;
    }
    // Fade out and stop pad oscillators
    const ctx = this.ctx;
    if (ctx) {
      const fadeEnd = ctx.currentTime + 2;
      for (const n of this.musicNodes) {
        n.gain.gain.linearRampToValueAtTime(0, fadeEnd);
        setTimeout(() => {
          try { n.osc.stop(); } catch { /* already stopped */ }
          try { n.lfo.stop(); } catch { /* already stopped */ }
        }, 2100);
      }
    }
    this.musicNodes = [];
    this.musicRunning = false;
  }

  private applyMasterGain(): void {
    if (!this.masterGain) return;
    this.masterGain.gain.value = this.settings.muted ? 0 : this.settings.masterVolume;
  }

  // ── Persistence ───────────────────────────────────────────────────────────

  private loadSettings(): void {
    try {
      const json = localStorage.getItem(SETTINGS_KEY);
      if (json) {
        const parsed = JSON.parse(json) as Partial<AudioSettings>;
        this.settings = { ...DEFAULT_SETTINGS, ...parsed };
      }
    } catch {
      /* ignore */
    }
  }

  private saveSettings(): void {
    try {
      localStorage.setItem(SETTINGS_KEY, JSON.stringify(this.settings));
    } catch {
      /* ignore */
    }
  }

  // ── Cleanup ───────────────────────────────────────────────────────────────

  dispose(): void {
    if (this.musicScheduleTimer !== null) {
      clearTimeout(this.musicScheduleTimer);
      this.musicScheduleTimer = null;
    }
    for (const n of this.musicNodes) {
      n.osc.stop();
      n.lfo.stop();
    }
    this.musicNodes = [];
    this.drifterNode?.osc.stop();
    this.drifterNode = null;
    for (const n of this.resonantNodes) n.osc.stop();
    this.resonantNodes = [];
    this.thrusterNode?.osc.stop();
    this.thrusterNode = null;
    this.ctx?.close();
    this.ctx = null;
    this.initialized = false;
  }
}

// ── Singleton ─────────────────────────────────────────────────────────────────

export const audioEngine = new AudioEngine();
