/**
 * Asteroid detail handler: routes sim:asteroid_detail to the info panel.
 */
import type { WorkerToMainMessage, SimAsteroidDetailMessage } from '../sim/messages';
import { updateAsteroidInfoPanel } from '../ui/asteroidInfoPanel';
import type { HandlerMap } from './types';

export function registerAsteroidHandlers(): HandlerMap {
  return {
    'sim:asteroid_detail': (msg: WorkerToMainMessage) => {
      const { payload } = msg as SimAsteroidDetailMessage;
      updateAsteroidInfoPanel(payload);
    },
  };
}
