/**
 * Blueprint Library Panel — save, view, compare, and load automation blueprints.
 *
 * Includes:
 *   - Blueprint list with efficiency metrics
 *   - A/B comparison view
 *   - Efficiency trend sparkline
 */

import type { SerializedBlueprintState, SerializedBlueprint, EfficiencySample } from '../sim/blueprints';
import { compareBlueprints } from '../sim/blueprints';
import type { Blueprint } from '../sim/blueprints';
import { safeHtml } from './utils/safeHtml';

type WorkerSend = (msg: object) => void;

let panel: HTMLElement | null = null;
let workerSend: WorkerSend | null = null;
let visible = false;

let _blueprints: SerializedBlueprint[] = [];
let _efficiencyHistory: EfficiencySample[] = [];
let _compareA: string | null = null;
let _compareB: string | null = null;

// ── Init ──────────────────────────────────────────────────────────────────────

export function initBlueprintPanel(sendToWorker: WorkerSend): void {
  workerSend = sendToWorker;

  panel = document.createElement('div');
  panel.id = 'blueprint-panel';
  panel.style.cssText = `
    position: fixed;
    top: 60px;
    left: 20px;
    width: 360px;
    max-height: calc(100vh - 80px);
    overflow-y: auto;
    background: rgba(8, 12, 24, 0.95);
    border: 1px solid rgba(56, 189, 248, 0.3);
    border-radius: 8px;
    padding: 16px;
    font-family: 'JetBrains Mono', 'Courier New', monospace;
    font-size: 12px;
    color: #e2e8f0;
    display: none;
    z-index: 200;
    box-shadow: 0 4px 32px rgba(0,0,0,0.7);
  `;

  document.body.appendChild(panel);
  renderPanel();
}

export function toggleBlueprintPanel(): void {
  if (!panel) return;
  visible = !visible;
  panel.style.display = visible ? 'block' : 'none';
}

export function hideBlueprintPanel(): void {
  if (!panel) return;
  visible = false;
  panel.style.display = 'none';
}

export function updateBlueprintState(state: SerializedBlueprintState): void {
  _blueprints = state.blueprints;
  _efficiencyHistory = state.efficiencyHistory;
  renderPanel();
}

// ── Rendering ─────────────────────────────────────────────────────────────────

function renderPanel(): void {
  if (!panel) return;

  const trendHtml = renderTrend();
  const listHtml = renderBlueprintList();
  const compareHtml = renderComparison();

  panel.innerHTML = safeHtml`
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">
      <div style="color:#38bdf8;font-weight:bold;font-size:13px;letter-spacing:0.05em;">AUTOMATION BLUEPRINTS</div>
      <button id="bp-close-btn" style="${btnStyle('#475569')}">✕</button>
    </div>
    ${trendHtml}
    <div style="margin-bottom:12px;display:flex;gap:6px;flex-wrap:wrap;">
      <input id="bp-new-name" type="text" placeholder="Blueprint name…" style="${inputStyle('auto')};flex:1" maxlength="32">
      <button id="bp-save-btn" style="${btnStyle('#0ea5e9')}">Save Current</button>
    </div>
    ${listHtml}
    ${compareHtml}
    <div style="margin-top:10px;color:#64748b;font-size:10px;">Press Y to close</div>
  `;

  bindEvents();
}

function renderTrend(): string {
  if (_efficiencyHistory.length < 2) {
    return `<div style="color:#64748b;font-size:11px;margin-bottom:12px;">Efficiency trend: gathering data…</div>`;
  }

  // Draw a simple sparkline using a canvas
  return `
    <div style="margin-bottom:12px;">
      <div style="color:#94a3b8;font-size:11px;font-weight:bold;margin-bottom:4px;">EFFICIENCY TREND</div>
      <canvas id="bp-trend-canvas" width="320" height="50" style="width:100%;height:50px;border-radius:4px;background:rgba(0,0,0,0.3);"></canvas>
      <div style="display:flex;justify-content:space-between;color:#64748b;font-size:10px;margin-top:2px;">
        <span>Resources/min</span>
        <span>Last ${_efficiencyHistory.length} samples</span>
      </div>
    </div>
  `;
}

function drawTrendCanvas(): void {
  const canvas = panel?.querySelector('#bp-trend-canvas') as HTMLCanvasElement | null;
  if (!canvas || _efficiencyHistory.length < 2) return;

  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  const w = canvas.width;
  const h = canvas.height;
  const data = _efficiencyHistory;
  const values = data.map((s) => s.resourcesPerMinute);
  const max = Math.max(...values, 1);
  const stepX = w / (data.length - 1);

  ctx.clearRect(0, 0, w, h);

  // Resource line (cyan)
  ctx.strokeStyle = '#38bdf8';
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  for (let i = 0; i < data.length; i++) {
    const x = i * stepX;
    const y = h - (values[i] / max) * (h - 4) - 2;
    if (i === 0) ctx.moveTo(x, y);
    else ctx.lineTo(x, y);
  }
  ctx.stroke();

  // Idle robot line (amber)
  const idleValues = data.map((s) => s.idleRobotPct);
  ctx.strokeStyle = '#f59e0b';
  ctx.lineWidth = 1;
  ctx.setLineDash([3, 3]);
  ctx.beginPath();
  for (let i = 0; i < data.length; i++) {
    const x = i * stepX;
    const y = h - idleValues[i] * (h - 4) - 2;
    if (i === 0) ctx.moveTo(x, y);
    else ctx.lineTo(x, y);
  }
  ctx.stroke();
  ctx.setLineDash([]);
}

function renderBlueprintList(): string {
  if (_blueprints.length === 0) {
    return `<div style="color:#64748b;font-size:11px;margin-bottom:12px;">No blueprints saved yet. Save your current automation config above.</div>`;
  }

  const rows = _blueprints.map((bp) => {
    const isCompareA = _compareA === bp.id;
    const isCompareB = _compareB === bp.id;
    const activeTag = bp.active ? '<span style="color:#4ade80;font-size:10px;margin-left:4px;">ACTIVE</span>' : '';
    const compareBorder = isCompareA ? 'border-left:3px solid #38bdf8;' : isCompareB ? 'border-left:3px solid #f59e0b;' : '';

    return `
      <div style="padding:8px;margin-bottom:6px;background:rgba(255,255,255,0.04);border-radius:4px;${compareBorder}">
        <div style="display:flex;align-items:center;gap:6px;">
          <span style="flex:1;color:#cbd5e1;font-weight:500;">${esc(bp.name)}${activeTag}</span>
          <button data-bp-load="${bp.id}" style="${btnStyle('#10b981')}" title="Load this blueprint">Load</button>
          <button data-bp-del="${bp.id}" style="${btnStyle('#dc2626')}" title="Delete">✕</button>
        </div>
        <div style="color:#64748b;font-size:10px;margin-top:4px;display:flex;gap:12px;">
          <span>Res/min: <span style="color:#38bdf8">${bp.efficiency.resourcesPerMinute.toFixed(1)}</span></span>
          <span>Idle: <span style="color:#f59e0b">${(bp.efficiency.idleRobotPct * 100).toFixed(0)}%</span></span>
          <span>E-waste: <span style="color:#ef4444">${(bp.efficiency.energyWastePct * 100).toFixed(0)}%</span></span>
        </div>
        <div style="margin-top:4px;display:flex;gap:4px;">
          <span style="color:#475569;font-size:10px;">Queues: ${bp.automation.queues.length} · Rules: ${bp.automation.supplyRules.length} · Sectors: ${bp.automation.sectors.length}</span>
        </div>
        <div style="margin-top:4px;display:flex;gap:4px;">
          <button data-bp-compare-a="${bp.id}" style="${btnStyle(isCompareA ? '#38bdf8' : '#334155')};font-size:10px;">A</button>
          <button data-bp-compare-b="${bp.id}" style="${btnStyle(isCompareB ? '#f59e0b' : '#334155')};font-size:10px;">B</button>
        </div>
      </div>
    `;
  }).join('');

  return `
    <div style="margin-bottom:12px;">
      <div style="color:#94a3b8;font-size:11px;font-weight:bold;margin-bottom:8px;border-bottom:1px solid rgba(255,255,255,0.1);padding-bottom:4px;">
        SAVED BLUEPRINTS (${_blueprints.length})
      </div>
      ${rows}
    </div>
  `;
}

function renderComparison(): string {
  if (!_compareA || !_compareB) return '';
  const a = _blueprints.find((bp) => bp.id === _compareA);
  const b = _blueprints.find((bp) => bp.id === _compareB);
  if (!a || !b) return '';

  const diff = compareBlueprints(a as Blueprint, b as Blueprint);
  const rSign = diff.resourcesDelta >= 0 ? '+' : '';
  const rColor = diff.resourcesDelta >= 0 ? '#4ade80' : '#ef4444';
  const iSign = diff.idleDelta <= 0 ? '' : '+';
  const iColor = diff.idleDelta <= 0 ? '#4ade80' : '#ef4444';

  return `
    <div style="padding:10px;background:rgba(56,189,248,0.06);border:1px solid rgba(56,189,248,0.15);border-radius:6px;margin-bottom:12px;">
      <div style="color:#94a3b8;font-size:11px;font-weight:bold;margin-bottom:8px;">A/B COMPARISON</div>
      <div style="display:flex;gap:8px;margin-bottom:6px;">
        <span style="color:#38bdf8;font-size:11px;">A: ${esc(a.name)}</span>
        <span style="color:#64748b;">vs</span>
        <span style="color:#f59e0b;font-size:11px;">B: ${esc(b.name)}</span>
      </div>
      <div style="color:#e2e8f0;font-size:11px;line-height:1.6;">
        <div>Resources/min: <span style="color:${rColor}">${rSign}${diff.resourcesDelta.toFixed(1)} (${rSign}${diff.resourcesDeltaPct.toFixed(0)}%)</span></div>
        <div>Idle robots: <span style="color:${iColor}">${iSign}${(diff.idleDelta * 100).toFixed(1)}%</span></div>
        <div>Energy waste: <span style="color:${diff.energyWasteDelta <= 0 ? '#4ade80' : '#ef4444'}">${diff.energyWasteDelta <= 0 ? '' : '+'}${(diff.energyWasteDelta * 100).toFixed(1)}%</span></div>
      </div>
      <div style="color:#64748b;font-size:10px;margin-top:6px;">
        ${diff.resourcesDeltaPct > 0 ? `"${esc(a.name)}" mines ${Math.abs(diff.resourcesDeltaPct).toFixed(0)}% more resources` : diff.resourcesDeltaPct < 0 ? `"${esc(b.name)}" mines ${Math.abs(diff.resourcesDeltaPct).toFixed(0)}% more resources` : 'Both produce equal resources'}
        ${Math.abs(diff.energyWasteDelta) > 0.01 ? ` but ${diff.energyWasteDelta > 0 ? 'wastes' : 'saves'} ${Math.abs(diff.energyWasteDelta * 100).toFixed(0)}% ${diff.energyWasteDelta > 0 ? 'more' : 'less'} energy.` : '.'}
      </div>
    </div>
  `;
}

// ── Events ────────────────────────────────────────────────────────────────────

function bindEvents(): void {
  if (!panel) return;

  panel.querySelector('#bp-close-btn')?.addEventListener('click', () => {
    hideBlueprintPanel();
  });

  panel.querySelector('#bp-save-btn')?.addEventListener('click', () => {
    const nameInput = panel?.querySelector('#bp-new-name') as HTMLInputElement | null;
    const name = nameInput?.value.trim();
    if (!name) return;
    workerSend?.({ type: 'sim:save_blueprint', payload: { name } });
    if (nameInput) nameInput.value = '';
  });

  // Load blueprint
  panel.querySelectorAll('[data-bp-load]').forEach((el) => {
    el.addEventListener('click', () => {
      const id = (el as HTMLElement).dataset.bpLoad;
      if (id) workerSend?.({ type: 'sim:load_blueprint', payload: { id } });
    });
  });

  // Delete blueprint
  panel.querySelectorAll('[data-bp-del]').forEach((el) => {
    el.addEventListener('click', () => {
      const id = (el as HTMLElement).dataset.bpDel;
      if (id) workerSend?.({ type: 'sim:delete_blueprint', payload: { id } });
    });
  });

  // Compare A/B selection
  panel.querySelectorAll('[data-bp-compare-a]').forEach((el) => {
    el.addEventListener('click', () => {
      const id = (el as HTMLElement).dataset.bpCompareA;
      _compareA = _compareA === id ? null : (id ?? null);
      renderPanel();
    });
  });

  panel.querySelectorAll('[data-bp-compare-b]').forEach((el) => {
    el.addEventListener('click', () => {
      const id = (el as HTMLElement).dataset.bpCompareB;
      _compareB = _compareB === id ? null : (id ?? null);
      renderPanel();
    });
  });

  // Draw trend canvas after DOM is ready
  requestAnimationFrame(() => drawTrendCanvas());
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function btnStyle(color: string): string {
  return `background:${color};color:#fff;border:none;border-radius:4px;padding:3px 8px;cursor:pointer;font-size:11px;font-family:inherit;`;
}

function inputStyle(width = '100%'): string {
  return `background:rgba(255,255,255,0.07);border:1px solid rgba(255,255,255,0.15);border-radius:4px;padding:4px 6px;color:#e2e8f0;font-size:11px;font-family:inherit;width:${width};box-sizing:border-box;`;
}

function esc(s: string): string {
  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
