/**
 * Habitat handlers: sim:habitat_state.
 */
import type {
  WorkerToMainMessage,
  SimHabitatStateMessage,
} from '../sim/messages';
import { revealHabitatHudButton, updateHabitatPanel } from '../ui/habitatPanel';
import type { HandlerContext, HandlerMap } from './types';

export function registerHabitatHandlers(ctx: HandlerContext): HandlerMap {
  const { refs } = ctx;

  return {
    'sim:habitat_state': (msg: WorkerToMainMessage) => {
      const habitatMsg = msg as SimHabitatStateMessage;
      refs.latestHabitatState = habitatMsg.payload;
      revealHabitatHudButton();
      updateHabitatPanel(habitatMsg.payload);
    },
  };
}
