/**
 * Pure key-to-action routing for game hotkeys.
 * No DOM, no Three.js, no side effects — fully testable in Node.js.
 */

export type KeyAction =
  | 'save'
  | 'toggleEventLog'
  | 'toggleGameEventLog'
  | 'toggleDashboard'
  | 'toggleTechTree'
  | 'toggleKeybindingHelp'
  | 'toggleFactionPanel'
  | 'toggleMegastructurePanel'
  | 'toggleAudioMute'
  | 'toggleBuildPanel'
  | 'toggleBuildingsPanel'
  | 'toggleAdvisorPanel'
  | 'toggleInboxPanel'
  | 'toggleCulturePanel'
  | 'toggleHabitatPanel'
  | 'toggleCodex'
  | 'toggleArchivesPanel'
  | 'toggleMaterialPriorityPanel'
  | 'toggleCommandersLog'
  | 'toggleBlueprintPanel'
  | 'toggleSystemMap'
  | 'snapToBase'
  | 'followNextRobot'
  | 'followPrevRobot'
  | 'speedUp'
  | 'speedDown'
  | 'setSpeed1'
  | 'setSpeed2'
  | 'setSpeed4'
  | 'escape';

/**
 * Map a KeyboardEvent's key + modifier to a game action name.
 * Returns null for unrecognized keys.
 */
export function getKeyAction(key: string, ctrlKey: boolean, shiftKey?: boolean): KeyAction | null {
  if (ctrlKey && key === 's') return 'save';
  if (key === 'l' || key === 'L') return 'toggleEventLog';
  if (key === 'd' || key === 'D') return 'toggleDashboard';
  if (key === 't' || key === 'T') return 'toggleTechTree';
  if (key === 'h' || key === 'H') return 'toggleKeybindingHelp';
  if (key === 'f' || key === 'F') return 'toggleFactionPanel';
  if (key === 'g' || key === 'G') return 'toggleMegastructurePanel';
  if (key === 'm' || key === 'M') return 'toggleAudioMute';
  if (key === 'a' || key === 'A') return 'toggleAdvisorPanel';
  if (key === 'c' || key === 'C') return 'toggleBuildPanel';
  // B key is handled by the logistics panel's own listener (logisticsPanel.ts)
  // to avoid double-toggling both panels at once.
  if (key === 'v' || key === 'V') return 'toggleBuildingsPanel';
  if (key === 'i' || key === 'I') return 'toggleInboxPanel';
  if (key === 'u' || key === 'U') return 'toggleCulturePanel';
  if (key === 'k' || key === 'K') return 'toggleHabitatPanel';
  if (key === 'j' || key === 'J') return 'toggleCodex';
  if (key === 'p' || key === 'P') return 'toggleArchivesPanel';
  if (key === 'w' || key === 'W') return 'toggleMaterialPriorityPanel';
  if (key === 'n' || key === 'N') return 'toggleCommandersLog';
  if (key === 'y' || key === 'Y') return 'toggleBlueprintPanel';
  if (key === 'o' || key === 'O') return 'toggleSystemMap';
  if (key === 'e' || key === 'E') return 'toggleGameEventLog';
  if (key === 'Home') return 'snapToBase';
  if (key === 'Tab' && !ctrlKey) return shiftKey ? 'followPrevRobot' : 'followNextRobot';
  if (key === '.' || key === '>') return 'speedUp';
  if (key === ',' || key === '<') return 'speedDown';
  if (key === '1') return 'setSpeed1';
  if (key === '2') return 'setSpeed2';
  if (key === '3') return 'setSpeed4';
  if (key === 'Escape') return 'escape';
  return null;
}
