/**
 * State handlers: sim:ready, sim:frame, sim:stats, sim:save_data, sim:save_failed,
 * sim:loaded, sim:load_failed, sim:robot_detail, sim:dust_state, sim:worker_perf,
 * sim:entity_frame, sim:inbox_snapshot.
 */
import type {
  WorkerToMainMessage,
  SimFrameMessage,
  SimStatsMessage,
  SimSaveDataMessage,
  SimLoadedMessage,
  SimEntityFrameMessage,
  SimRobotDetailMessage,
  SimInboxSnapshotMessage,
  SimDustStateMessage,
  SimWorkerPerfMessage,
} from '../sim/messages';
import { ENTITY_TYPES } from '../sim/entities/entitySystem';
import { setStorageValues, discoveries, storageValues } from '../gameRuntimeState';
import { hideLoadingScreen } from '../ui/loadingScreen';
import { maybeShowTouchHints } from '../ui/touchHints';
import { showNotification } from '../ui/notifications';
import { showHint } from '../ui/hints';
import { playSfx } from '../audio/sfxEngine';
import { receiveWorkerSave } from '../ui/pauseMenu';
import { getAnnotations, restoreAnnotations } from '../ui/codexPanel';
import { setMaterialWeights } from '../ui/materialPriorityPanel';
import { serializeCommandersLog, restoreCommandersLog, resetCommandersLog } from '../ui/commandersLogPanel';
import { serializeEventLog, restoreEventLog, resetEventLog as resetGameEventLog } from '../ui/eventLogPanel';
import { updateShipDetail } from '../ui/shipPanel';
import { checkResourceMilestones, seedResourceMilestones } from '../ui/milestones';
import { beginLoadGracePeriod } from '../ui/notifications';
import { updateMinimapRobots, updateMinimapEntities, updateMinimapAsteroids, updateMinimapThreats } from '../ui/minimap';
import { updateCacheTick } from '../advisor/cache';
import { resetEventLog } from '../ui/eventModal';
import { resetProactiveBroadcastState } from '../advisor/ariaProactiveBroadcasts';
import { beginBroadcastGracePeriod } from '../ui/advisorPanel/messages';
import { resetAutoAnalysis, startAutoAnalysis } from '../advisor/ariaAutoAnalysis';
import { resetColonyNameModalState } from '../ui/colonyNameModal';
import { resetColonyEpithetModalState } from '../ui/colonyEpithetModal';
import { tickEchoDelivery, resetEchoDelivery, getEchoDeliveryState, restoreEchoDeliveryState } from '../beltEchoes';
import { updateInboxPanel } from '../ui/inboxPanel';
import { showDarkForestModal, hasDarkForestBeenShown } from '../ui/darkForestModal';
import { audioEngine } from '../audio/audioEngine';
import { musicManager } from '../audio/musicManager';
import { trackFirstMine } from '../analytics';
import type { HandlerContext, HandlerMap, HandlerState } from './types';

export function registerStateHandlers(
  ctx: HandlerContext,
  state: HandlerState,
): HandlerMap {
  const { worker, refs, renderers, lazy, cbs } = ctx;
  const { entityRenderer } = renderers;

  return {
    'sim:ready': () => {
      hideLoadingScreen();
      maybeShowTouchHints();
      worker.postMessage({ type: 'sim:start' });
      if (refs.pendingLoad) {
        worker.postMessage({ type: 'sim:load', payload: { data: refs.pendingLoad } });
        refs.pendingLoad = null;
      }
      if (refs.pendingFirstLaunch) {
        refs.pendingFirstLaunch = false;
        playSfx('game.robot_deploy');
        setTimeout(() => {
          showNotification(
            '[ARIA] Seven robots deployed. Follow the tutorial steps below to get operational — then ask me anything, Commander.',
            '#a855f7',
          );
        }, 1200);
      }
      showHint('game_start_help', 'Press H to see all keyboard shortcuts');
      setTimeout(() => {
        showHint('mining_dashboard', 'Press D to open Dashboard');
      }, 30_000);
      cbs.scheduleIdleHint();
    },

    'sim:frame': (msg: WorkerToMainMessage) => {
      const frame = msg as SimFrameMessage;
      refs.latestAsteroidBuffer = new Float64Array(frame.payload.asteroidBuffer);
      refs.latestAsteroidCount = frame.payload.asteroidCount;
      refs.latestRobotBuffer = new Float32Array(frame.payload.robotBuffer);
      refs.latestRobotCount = frame.payload.robotCount;
      refs.latestThreatBuffer = new Float32Array(frame.payload.threatBuffer);
      refs.latestThreatCount = frame.payload.threatCount;
      // Play alert when new threats appear
      if (refs.latestThreatCount > state.prevThreatCount && state.prevThreatCount >= 0) {
        playSfx('game.combat_start');
      }
      state.prevThreatCount = refs.latestThreatCount;
      setStorageValues(new Float32Array(frame.payload.storageBuffer));
      refs.latestTick = frame.payload.tick;
      lazy.getAdvisor()?.delegate?.tickDelegation(frame.payload.tick);
      updateCacheTick(frame.payload.tick);
      lazy.getDashboard()?.updateDashboardResources(storageValues, refs.latestRefined, refs.latestTick);
      if (storageValues[0] > 155) {
        showHint('hauler_first_delivery', 'Haulers automatically collect ore from miners and return it to base.');
        trackFirstMine();
        if (!state.firstOreNotified) {
          state.firstOreNotified = true;
          playSfx('game.resource_collect');
          showNotification('First ore delivered! Your mining operation is up and running.', '#4ade80');
        }
      }
      // On first frame after load, pre-populate milestones so already-crossed
      // thresholds don't re-fire as notifications once the grace period ends.
      if (state.needsMilestoneSeed) {
        state.needsMilestoneSeed = false;
        seedResourceMilestones({
          iron: storageValues[0],
          carbon: storageValues[5],
          silicon: storageValues[6],
          water: storageValues[4],
          ...refs.latestRefined,
        });
      }
      if (refs.latestTick % 120 === 0) {
        checkResourceMilestones(
          {
            iron: storageValues[0],
            carbon: storageValues[5],
            silicon: storageValues[6],
            water: storageValues[4],
            ...refs.latestRefined,
          },
          showNotification,
        );
      }
      if (refs.latestRobotBuffer && refs.latestRobotCount > 0) {
        lazy.getDashboard()?.updateDashboardFleet(refs.latestRobotBuffer, refs.latestRobotCount);
        updateMinimapRobots(refs.latestRobotBuffer, refs.latestRobotCount);
      }
      if (refs.latestAsteroidBuffer && refs.latestAsteroidCount > 0) {
        updateMinimapAsteroids(refs.latestAsteroidBuffer, refs.latestAsteroidCount);
      }
      if (refs.latestThreatBuffer && refs.latestThreatCount > 0) {
        updateMinimapThreats(refs.latestThreatBuffer, refs.latestThreatCount);
      } else {
        updateMinimapThreats(new Float32Array(0), 0);
      }
      // Belt Echoes: tick the delivery loop (checks interval internally)
      tickEchoDelivery(frame.payload.tick, refs.latestUnlockedMask);
    },

    'sim:stats': (msg: WorkerToMainMessage) => {
      const stats = msg as SimStatsMessage;
      refs.lastStats = stats.payload;
    },

    'sim:save_data': (msg: WorkerToMainMessage) => {
      const saveMsg = msg as SimSaveDataMessage;
      const saveData = saveMsg.payload.data;
      const delegateMod = lazy.getAdvisor()?.delegate;
      if (delegateMod) {
        saveData.commanderState = delegateMod.serializeDelegationState();
      }
      // Inject player annotations from the Anomaly Archive (main-thread-only state)
      const annots = getAnnotations();
      if (Object.keys(annots).length > 0) {
        saveData.anomalyAnnotations = annots;
      }
      // Inject Commander's Log entries (main-thread-only state)
      const logData = serializeCommandersLog();
      if (logData.entries.length > 0) {
        saveData.commandersLog = logData;
      }
      // Inject game event log (main-thread-only state)
      const evtLogData = serializeEventLog();
      if (evtLogData.entries.length > 0) {
        saveData.gameEventLog = evtLogData;
      }
      // Inject Belt Echoes delivery state (main-thread-only state)
      saveData.beltEchoesState = getEchoDeliveryState();
      receiveWorkerSave(saveMsg.payload.slot, saveData);
    },

    'sim:save_failed': () => {
      showNotification('Save failed — data could not be serialized');
    },

    'sim:loaded': (msg: WorkerToMainMessage) => {
      const loadedMsg = msg as SimLoadedMessage;
      refs.latestTick = loadedMsg.payload.tick;
      discoveries.length = 0;
      state.seenEntityIds.clear();
      resetEventLog();
      resetProactiveBroadcastState();
      resetAutoAnalysis();
      resetColonyNameModalState();
      resetColonyEpithetModalState();
      if (loadedMsg.payload.beltEchoesState) {
        restoreEchoDeliveryState(loadedMsg.payload.beltEchoesState);
      } else {
        resetEchoDelivery();
      }
      startAutoAnalysis();
      state.firstCultureMessage = true;
      state.firstFactionMessage = true;
      state.firstMegastructureMessage = true;
      state.needsMilestoneSeed = true;
      state.firstOreNotified = true; // don't fire first-ore toast on loaded saves
      // Suppress all notifications/broadcasts for 3s to prevent load-time flood
      beginLoadGracePeriod();
      beginBroadcastGracePeriod();
      lazy.getDashboard()?.updateDashboardAnomalies([]);
      if (loadedMsg.payload.commanderState) {
        const cs = loadedMsg.payload.commanderState;
        lazy.getAdvisor()?.delegate?.restoreDelegationState(cs);
      }
      if (loadedMsg.payload.anomalyAnnotations) {
        restoreAnnotations(loadedMsg.payload.anomalyAnnotations);
      }
      if (loadedMsg.payload.materialWeights) {
        setMaterialWeights(loadedMsg.payload.materialWeights);
      }
      if (loadedMsg.payload.commandersLog) {
        restoreCommandersLog(loadedMsg.payload.commandersLog);
      } else {
        resetCommandersLog();
      }
      if (loadedMsg.payload.gameEventLog) {
        restoreEventLog(loadedMsg.payload.gameEventLog);
      } else {
        resetGameEventLog();
      }
    },

    'sim:load_failed': () => {
      showNotification('Load failed — save data may be corrupt');
    },

    'sim:robot_detail': (msg: WorkerToMainMessage) => {
      const rdMsg = msg as SimRobotDetailMessage;
      updateShipDetail(rdMsg.payload);
    },

    'sim:dust_state': (msg: WorkerToMainMessage) => {
      const dustMsg = msg as SimDustStateMessage;
      renderers.skybox?.updateDustMap(dustMsg.payload.cells);
    },

    'sim:worker_perf': (msg: WorkerToMainMessage) => {
      const perfMsg = msg as SimWorkerPerfMessage;
      const p = perfMsg.payload;
      if (typeof window !== 'undefined') {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        (window as any).__asteroidPerf = {
          tick: p.tick,
          avgTickMs: p.avgTickMs,
          maxTickMs: p.maxTickMs,
          entityCount: p.entityCount,
          robotCount: p.robotCount,
          asteroidCount: p.asteroidCount,
          phaseMaxMs: p.phaseMaxMs,
          thresholdExceeded: p.thresholdExceeded,
        };
        if (p.thresholdExceeded) {
          const hot = Object.entries(p.phaseMaxMs)
            .filter(([, ms]) => ms > 16)
            .map(([name, ms]) => `${name}: ${ms.toFixed(1)}ms`);
          console.warn(`[perf] phase threshold exceeded — ${hot.join(', ')}`);
        }
      }
    },

    'sim:entity_frame': (msg: WorkerToMainMessage) => {
      const eFrame = msg as SimEntityFrameMessage;
      for (const entity of eFrame.payload.entities) {
        if (!state.seenEntityIds.has(entity.id)) {
          state.seenEntityIds.add(entity.id);
          const name =
            entity.type === ENTITY_TYPES.DRIFTER ? 'Drifter'
            : entity.type === ENTITY_TYPES.ALIEN_FLEET ? 'Alien Fleet'
            : 'Resonant';
          const color =
            entity.type === ENTITY_TYPES.DRIFTER ? '#8866ff'
            : entity.type === ENTITY_TYPES.ALIEN_FLEET ? '#4466ff'
            : '#44ffcc';
          lazy.getDashboard()?.addExplorationEvent(
            `[Entity] ${name} detected at (${Math.round(entity.x)},${Math.round(entity.z)})`,
            color,
            eFrame.payload.tick,
          );
        }
      }
      updateMinimapEntities(eFrame.payload.entities);
      entityRenderer.update(
        eFrame.payload.entities,
        eFrame.payload.drifterProximity,
        eFrame.payload.resonantInterference,
        refs.latestTick / 60,
        eFrame.payload.alienFleetProximity,
      );
      audioEngine.updateEntityAudio(
        eFrame.payload.drifterProximity ? 1 : 0,
        eFrame.payload.resonantInterference ? 1 : 0,
      );
      if (eFrame.payload.alienFleetProximity || eFrame.payload.drifterProximity) {
        musicManager.setState('combat');
      } else if (eFrame.payload.resonantInterference || discoveries.length > 0) {
        if (musicManager.getState() === 'combat' || musicManager.getState() === 'mid_combat') {
          musicManager.setState('post_combat');
        } else {
          musicManager.setState('focus');
        }
      } else {
        const ms = musicManager.getState();
        if (ms === 'combat' || ms === 'mid_combat' || ms === 'casualties' || ms === 'post_combat') {
          musicManager.setState('recovery');
        } else if (ms !== 'recovery' && ms !== 'long_session' && ms !== 'very_long' &&
                   ms !== 'progress' && ms !== 'industrial') {
          musicManager.setState(refs.latestRobotCount > 5 ? 'mining' : 'idle');
        }
      }
    },

    'sim:inbox_snapshot': (msg: WorkerToMainMessage) => {
      const inboxMsg = msg as SimInboxSnapshotMessage;
      refs.latestInboxSnapshot = inboxMsg.payload;
      updateInboxPanel(inboxMsg.payload);

      for (const m of inboxMsg.payload.messages) {
        if ((m.type === 'dark_forest_choice' || m.type === 'dark_forest_collective') && !hasDarkForestBeenShown(m.id)) {
          showDarkForestModal(
            m.id,
            m.body,
            m.type === 'dark_forest_collective',
            (choice) => {
              worker.postMessage({ type: 'sim:dark_forest_choice', payload: { choice } });
              worker.postMessage({ type: 'sim:inbox_mark_read', payload: { messageId: m.id } });
            },
          );
        }
      }
    },
  };
}
