/**
 * Narrative Event UI
 *
 * - Full-screen modal for Revelation and Dilemma events
 * - Toast notification for Discovery, Threat, Opportunity events
 * - Event log panel (L key) showing event history
 */

import type { NarrativeEvent } from '../sim/events/eventEngine';
import { trapFocus } from './focusTrap';
import { safeHtml } from './utils/safeHtml';

// ── Shared DOM state ──────────────────────────────────────────────────────────

let modalOverlay: HTMLDivElement | null = null;
let removeFocusTrap: (() => void) | null = null;
let logPanel: HTMLDivElement | null = null;
let logVisible = false;

/** Called when player makes a dilemma choice */
let onChoiceCallback: ((eventId: string, choiceId: string) => void) | null = null;

// ── Event log ─────────────────────────────────────────────────────────────────

interface LogEntry {
  tick: number;
  event: NarrativeEvent;
  choiceMade?: string;
}

const eventLog: LogEntry[] = [];

/** Clear the event log. Call on new game / load to prevent unbounded growth across sessions. */
export function resetEventLog(): void {
  eventLog.length = 0;
}

function addToLog(event: NarrativeEvent, tick: number, choiceMade?: string): void {
  eventLog.push({ tick, event, choiceMade });
  if (logVisible) renderLog();
}

// ── Event type styling ────────────────────────────────────────────────────────

const TYPE_COLOR: Record<string, string> = {
  discovery: '#22c55e',
  dilemma: '#f59e0b',
  revelation: '#a855f7',
  threat: '#ef4444',
  opportunity: '#06b6d4',
};

const TYPE_LABEL: Record<string, string> = {
  discovery: 'DISCOVERY',
  dilemma: 'DECISION REQUIRED',
  revelation: 'ARIA REVELATION',
  threat: 'THREAT DETECTED',
  opportunity: 'OPPORTUNITY',
};

// ── Modal ─────────────────────────────────────────────────────────────────────

function getOrCreateOverlay(): HTMLDivElement {
  if (!modalOverlay) {
    modalOverlay = document.createElement('div');
    modalOverlay.style.cssText = `
      position: fixed;
      inset: 0;
      background: rgba(0, 0, 0, 0.75);
      display: flex;
      align-items: center;
      justify-content: center;
      z-index: 500;
      font-family: 'Courier New', monospace;
      opacity: 0;
      transition: opacity 0.3s ease;
    `;
    document.body.appendChild(modalOverlay);
    requestAnimationFrame(() => {
      if (modalOverlay) modalOverlay.style.opacity = '1';
    });
  }
  return modalOverlay;
}

function closeModal(): void {
  if (!modalOverlay) return;
  removeFocusTrap?.();
  removeFocusTrap = null;
  modalOverlay.style.opacity = '0';
  setTimeout(() => {
    modalOverlay?.remove();
    modalOverlay = null;
  }, 300);
}

export function showEventModal(
  event: NarrativeEvent,
  tick: number,
  onChoice: (eventId: string, choiceId: string) => void,
): void {
  onChoiceCallback = onChoice;

  const overlay = getOrCreateOverlay();
  const color = TYPE_COLOR[event.type] ?? '#ffffff';
  const label = TYPE_LABEL[event.type] ?? event.type.toUpperCase();

  const modal = document.createElement('div');
  modal.setAttribute('role', 'dialog');
  modal.setAttribute('aria-label', label);
  modal.setAttribute('aria-modal', 'true');
  modal.setAttribute('tabindex', '-1');
  modal.style.cssText = `
    background: rgba(0, 8, 20, 0.96);
    border: 1px solid ${color};
    box-shadow: 0 0 32px ${color}44, inset 0 0 32px rgba(0,0,0,0.5);
    color: #e2e8f0;
    max-width: 640px;
    width: 90vw;
    padding: 32px;
    border-radius: 2px;
    position: relative;
  `;

  const headerLine = `<div style="font-size:10px;color:${color};opacity:0.8;text-transform:uppercase;letter-spacing:2px;margin-bottom:8px;">${label}</div>`;
  const titleLine = `<div style="font-size:18px;font-weight:bold;color:${color};margin-bottom:20px;letter-spacing:1px;">${escapeHtml(event.title)}</div>`;

  // Body — respect newlines by converting to paragraphs
  const bodyHtml = event.body
    .split('\n\n')
    .map((para) => {
      // Handle italic via *text*
      const rendered = para.replace(/\*/g, '').trim();
      return `<p style="margin:0 0 12px;line-height:1.7;color:#cbd5e1;font-size:13px;">${escapeHtml(rendered)}</p>`;
    })
    .join('');

  let choicesHtml = '';
  if (event.choices) {
    choicesHtml = `<div style="margin-top:24px;display:flex;flex-direction:column;gap:10px;">`;
    for (const choice of event.choices) {
      choicesHtml += `
        <button
          data-choice-id="${choice.id}"
          aria-label="${escapeHtml(choice.label)}"
          style="
            background: transparent;
            border: 1px solid ${color}88;
            color: ${color};
            font-family: 'Courier New', monospace;
            font-size:12px;
            padding: 10px 16px;
            cursor: pointer;
            text-align: left;
            border-radius: 2px;
            transition: background 0.2s, border-color 0.2s;
          "
          onmouseover="this.style.background='${color}22';this.style.borderColor='${color}'"
          onmouseout="this.style.background='transparent';this.style.borderColor='${color}88'"
        >▸ ${escapeHtml(choice.label)}</button>
      `;
    }
    choicesHtml += `</div>`;
  } else {
    // Dismiss button for non-dilemma events
    choicesHtml = `
      <div style="margin-top:24px;text-align:right;">
        <button
          id="evt-dismiss"
          aria-label="Acknowledge event"
          style="
            background: transparent;
            border: 1px solid ${color}88;
            color: ${color};
            font-family: 'Courier New', monospace;
            font-size:11px;
            padding: 8px 20px;
            cursor: pointer;
            border-radius: 2px;
            letter-spacing:1px;
            text-transform:uppercase;
          "
          onmouseover="this.style.background='${color}22'"
          onmouseout="this.style.background='transparent'"
        >ACKNOWLEDGE</button>
      </div>
    `;
  }

  const tickStr = `<div style="position:absolute;top:12px;right:16px;font-size:9px;color:#475569;letter-spacing:1px;">TICK ${tick.toLocaleString()}</div>`;

  modal.innerHTML = headerLine + titleLine + bodyHtml + choicesHtml + tickStr;
  overlay.appendChild(modal);
  removeFocusTrap = trapFocus(modal);

  // Wire up choice buttons
  if (event.choices) {
    for (const btn of modal.querySelectorAll<HTMLButtonElement>('[data-choice-id]')) {
      btn.addEventListener('click', () => {
        const choiceId = btn.getAttribute('data-choice-id')!;
        const choice = event.choices!.find((c) => c.id === choiceId);
        if (onChoiceCallback) {
          onChoiceCallback(event.id, choiceId);
        }
        addToLog(event, tick, choice?.label);
        closeModal();
      });
    }
  } else {
    modal.querySelector('#evt-dismiss')?.addEventListener('click', () => {
      addToLog(event, tick);
      closeModal();
    });
  }
}

// ── Toast notification (for minor events) ────────────────────────────────────

export function showEventToast(event: NarrativeEvent, tick: number): void {
  addToLog(event, tick);

  const color = TYPE_COLOR[event.type] ?? '#ffffff';
  const label = TYPE_LABEL[event.type] ?? event.type.toUpperCase();

  // Reuse the notifications container by creating a toast in the same style
  const container = getToastContainer();
  const toast = document.createElement('div');
  toast.style.cssText = `
    background: rgba(0, 8, 20, 0.92);
    border: 1px solid ${color};
    box-shadow: 0 0 12px ${color}44;
    color: ${color};
    font-family: 'Courier New', monospace;
    font-size: 11px;
    line-height: 1.5;
    padding: 10px 14px;
    border-radius: 2px;
    opacity: 0;
    transform: translateX(20px);
    transition: opacity 0.3s ease, transform 0.3s ease;
    max-width: 340px;
    cursor: pointer;
  `;
  toast.innerHTML = safeHtml`
    <div style="font-size:9px;opacity:0.7;text-transform:uppercase;letter-spacing:1px;margin-bottom:3px;">${label}</div>
    <div style="font-weight:bold;margin-bottom:2px;">${event.title}</div>
    <div style="opacity:0.75;font-size:10px;">${event.body.slice(0, 90)}…</div>
  `;
  container.appendChild(toast);

  requestAnimationFrame(() => {
    toast.style.opacity = '1';
    toast.style.transform = 'translateX(0)';
  });

  const dismiss = (): void => {
    toast.style.opacity = '0';
    toast.style.transform = 'translateX(20px)';
    setTimeout(() => toast.remove(), 350);
  };

  toast.addEventListener('click', dismiss);
  setTimeout(dismiss, 12000);
}

function getToastContainer(): HTMLDivElement {
  let c = document.querySelector<HTMLDivElement>('#evt-toast-container');
  if (!c) {
    c = document.createElement('div');
    c.id = 'evt-toast-container';
    c.style.cssText = `
      position: fixed;
      top: 12px;
      right: 12px;
      display: flex;
      flex-direction: column;
      gap: 8px;
      z-index: 400;
      pointer-events: none;
    `;
    // Allow click-through except on individual toasts
    document.body.appendChild(c);
  }
  return c;
}

// ── Event log panel ───────────────────────────────────────────────────────────

export function toggleEventLog(): void {
  if (logVisible) {
    hideEventLog();
  } else {
    showEventLog();
  }
}

export function isEventLogVisible(): boolean {
  return logVisible;
}

function showEventLog(): void {
  logVisible = true;
  if (!logPanel) {
    logPanel = document.createElement('div');
    logPanel.setAttribute('role', 'dialog');
    logPanel.setAttribute('aria-label', 'Event log');
    logPanel.setAttribute('tabindex', '-1');
    logPanel.style.cssText = `
      position: fixed;
      top: 60px;
      left: 50%;
      transform: translateX(-50%);
      width: min(700px, 95vw);
      max-height: 70vh;
      background: rgba(0, 8, 20, 0.96);
      border: 1px solid #334155;
      box-shadow: 0 0 40px rgba(0,0,0,0.8);
      color: #e2e8f0;
      font-family: 'Courier New', monospace;
      font-size: 12px;
      border-radius: 2px;
      z-index: 450;
      display: flex;
      flex-direction: column;
      overflow: hidden;
    `;
    document.body.appendChild(logPanel);

    // Key handler to close log
    document.addEventListener('keydown', handleLogKey);
  }
  renderLog();
}

function hideEventLog(): void {
  logVisible = false;
  logPanel?.remove();
  logPanel = null;
  document.removeEventListener('keydown', handleLogKey);
}

function handleLogKey(e: KeyboardEvent): void {
  if (e.key === 'l' || e.key === 'L' || e.key === 'Escape') {
    hideEventLog();
  }
}

function renderLog(): void {
  if (!logPanel) return;
  logPanel.innerHTML = '';

  // Header
  const header = document.createElement('div');
  header.style.cssText = `
    padding: 12px 16px;
    border-bottom: 1px solid #1e293b;
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-shrink: 0;
  `;
  header.innerHTML = safeHtml`
    <span style="color:#94a3b8;font-size:10px;text-transform:uppercase;letter-spacing:2px;">Event Log</span>
    <div style="display:flex;gap:16px;align-items:center;">
      <span style="color:#475569;font-size:10px;">${eventLog.length} event${eventLog.length !== 1 ? 's' : ''}</span>
      <button id="log-close" aria-label="Close event log" style="background:none;border:none;color:#64748b;cursor:pointer;font-size:16px;padding:0;line-height:1;">×</button>
    </div>
  `;
  logPanel.appendChild(header);
  header.querySelector('#log-close')?.addEventListener('click', hideEventLog);

  // Scrollable content
  const content = document.createElement('div');
  content.style.cssText = `
    overflow-y: auto;
    flex: 1;
    padding: 8px 0;
  `;

  if (eventLog.length === 0) {
    content.innerHTML = `<div style="padding:24px;color:#475569;text-align:center;">No events recorded yet.</div>`;
  } else {
    // Show newest first
    for (let i = eventLog.length - 1; i >= 0; i--) {
      const { tick, event, choiceMade } = eventLog[i];
      const color = TYPE_COLOR[event.type] ?? '#ffffff';
      const label = TYPE_LABEL[event.type] ?? event.type;

      const entry = document.createElement('div');
      entry.style.cssText = `
        padding: 12px 16px;
        border-bottom: 1px solid #0f172a;
        cursor: pointer;
      `;
      entry.innerHTML = safeHtml`
        <div style="display:flex;justify-content:space-between;margin-bottom:4px;">
          <span style="color:${color};font-size:9px;text-transform:uppercase;letter-spacing:1px;">${label}</span>
          <span style="color:#475569;font-size:9px;">tick ${tick.toLocaleString()}</span>
        </div>
        <div style="font-weight:bold;color:#e2e8f0;margin-bottom:4px;">${event.title}</div>
        <div style="color:#94a3b8;font-size:11px;line-height:1.5;">${event.body.slice(0, 160)}${event.body.length > 160 ? '…' : ''}</div>
        ${choiceMade ? safeHtml`<div style="margin-top:6px;color:${color};font-size:10px;opacity:0.8;">▸ Chose: ${choiceMade}</div>` : ''}
      `;
      entry.addEventListener('mouseover', () => {
        entry.style.background = '#0f172a';
      });
      entry.addEventListener('mouseout', () => {
        entry.style.background = '';
      });
      content.appendChild(entry);
    }
  }

  logPanel.appendChild(content);

  // Footer hint
  const footer = document.createElement('div');
  footer.style.cssText = `
    padding: 8px 16px;
    border-top: 1px solid #1e293b;
    color: #475569;
    font-size: 9px;
    text-transform: uppercase;
    letter-spacing: 1px;
    flex-shrink: 0;
  `;
  footer.textContent = 'Press L or ESC to close';
  logPanel.appendChild(footer);
}

// ── Helper ────────────────────────────────────────────────────────────────────

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}
