// ── Name generation ──────────────────────────────────────────────────────────

const CONSONANTS = ['Br', 'Wh', 'Th', 'Gl', 'Sk', 'Kr', 'Vel', 'Ash'] as const;
const VOWELS = ['ey', 'ar', 'on', 'al', 'is', 'un'] as const;

/**
 * Simple seeded hash for deterministic name generation.
 * Returns a number in [0, 1).
 */
function seedHash(seed: number, step: number): number {
  let s = ((seed + step * 0x6d2b79f5) | 0) >>> 0;
  s = Math.imul(s ^ (s >>> 15), 1 | s);
  s = (s + Math.imul(s ^ (s >>> 7), 61 | s)) ^ s;
  return ((s ^ (s >>> 14)) >>> 0) / 4294967296;
}

/**
 * Generate a deterministic name from a numeric seed.
 * Same seed always produces the same name.
 * Always two syllables for variety (8×6×8×6 = 2304 combinations).
 */
export function generateName(seed: number): string {
  const c1 = CONSONANTS[Math.floor(seedHash(seed, 0) * CONSONANTS.length)];
  const v1 = VOWELS[Math.floor(seedHash(seed, 1) * VOWELS.length)];
  const c2 = CONSONANTS[Math.floor(seedHash(seed, 2) * CONSONANTS.length)];
  const v2 = VOWELS[Math.floor(seedHash(seed, 3) * VOWELS.length)];
  return c1 + v1 + c2.toLowerCase() + v2;
}

/**
 * Generate a robot name from its EID.
 * Deterministic: same EID always gets the same name.
 */
export function generateRobotName(eid: number): string {
  return generateName(eid ^ 0x70b07);
}

// ── Location naming ──────────────────────────────────────────────────────────

/** Minimum ticks a robot must stay near an asteroid to name it. */
const LOCATION_NAMING_PROXIMITY_TICKS = 2000;
/** Distance threshold for "near" an asteroid. */
const LOCATION_NAMING_RADIUS = 500;
/** How often to check for location naming opportunities (ticks). */
export const LOCATION_NAMING_CHECK_INTERVAL = 5000;

export interface LocationNamingInput {
  /** Current tick. */
  tick: number;
  /** Positions of robots with their EIDs. */
  robots: Array<{ eid: number; x: number; y: number; z: number }>;
  /** Asteroid positions with their EIDs. */
  asteroids: Array<{ eid: number; x: number; y: number; z: number }>;
}

/**
 * Per-robot proximity tracker: how many ticks each robot has spent near each asteroid.
 * Keyed by numeric composite: robotEid * EID_MULTIPLIER + asteroidEid.
 */
export type ProximityTracker = Map<number, number>;

/** Multiplier for encoding robot/asteroid EID pairs as a single number. */
const EID_MULTIPLIER = 0x100000; // 1M — safe for EIDs < 1M

/** Encode a (robotEid, asteroidEid) pair into a single numeric key. */
function encodeProximityKey(robotEid: number, asteroidEid: number): number {
  return robotEid * EID_MULTIPLIER + asteroidEid;
}

/** Decode a proximity key back into (robotEid, asteroidEid). */
function decodeProximityKey(key: number): [number, number] {
  const asteroidEid = key % EID_MULTIPLIER;
  const robotEid = (key - asteroidEid) / EID_MULTIPLIER;
  return [robotEid, asteroidEid];
}

/**
 * Check for location naming opportunities and apply them.
 * Called every LOCATION_NAMING_CHECK_INTERVAL ticks.
 */
export function checkLocationNaming(
  state: CultureState,
  input: LocationNamingInput,
  proximityTracker: ProximityTracker,
): void {
  const { robots, asteroids, tick } = input;
  const radiusSq = LOCATION_NAMING_RADIUS * LOCATION_NAMING_RADIUS;

  // Build EID → asteroid lookup for O(1) access
  const asteroidByEid = new Map<number, { eid: number; x: number; y: number; z: number }>();
  for (const a of asteroids) {
    asteroidByEid.set(a.eid, a);
  }

  // Update proximity tracker: for each robot, find which asteroids are within range
  for (const robot of robots) {
    for (const asteroid of asteroids) {
      const dx = robot.x - asteroid.x;
      const dy = robot.y - asteroid.y;
      const dz = robot.z - asteroid.z;
      const distSq = dx * dx + dy * dy + dz * dz;
      const key = encodeProximityKey(robot.eid, asteroid.eid);

      if (distSq <= radiusSq) {
        const current = proximityTracker.get(key) ?? 0;
        proximityTracker.set(key, current + LOCATION_NAMING_CHECK_INTERVAL);
      } else {
        proximityTracker.delete(key);
      }
    }
  }

  // Build set of already-named asteroid EIDs by matching named locations to nearest asteroid
  const namedAsteroidEids = new Set<number>();
  for (const nl of state.namedLocations) {
    let bestEid = -1;
    let bestDist = Infinity;
    for (const a of asteroids) {
      const dx = a.x - nl.x;
      const dy = a.y - nl.y;
      const dz = a.z - nl.z;
      const d = dx * dx + dy * dy + dz * dz;
      if (d < bestDist) {
        bestDist = d;
        bestEid = a.eid;
      }
    }
    namedAsteroidEids.add(bestEid);
  }

  for (const [key, ticks] of proximityTracker) {
    if (ticks < LOCATION_NAMING_PROXIMITY_TICKS) continue;

    const [robotEid, asteroidEid] = decodeProximityKey(key);

    // Skip if already named
    if (namedAsteroidEids.has(asteroidEid)) continue;

    // O(1) asteroid lookup
    const asteroid = asteroidByEid.get(asteroidEid);
    if (!asteroid) continue;

    const name = generateName(robotEid ^ asteroidEid ^ tick);
    state.namedLocations.push({
      name,
      x: asteroid.x,
      y: asteroid.y,
      z: asteroid.z,
      namedByEid: robotEid,
      namedAtTick: tick,
    });
    namedAsteroidEids.add(asteroidEid);

    // Track in robot stats
    const stats = state.robotStats.get(robotEid);
    if (stats) {
      stats.asteroidsNamed++;
    }
  }
}

// ── Robot death & legacy migration ───────────────────────────────────────────

/**
 * Migrate a robot's stats into the legacy archive when it is destroyed.
 * Returns the created RobotLegacy entry.
 */
export function migrateRobotToLegacy(
  state: CultureState,
  eid: number,
  currentTick: number,
  robotType: number = 0,
): RobotLegacy {
  const stats = state.robotStats.get(eid);
  const spawnTick = stats?.spawnTick ?? 0;
  const legacy: RobotLegacy = {
    eid,
    name: state.robotNames.get(eid) ?? null,
    robotType,
    tasksCompleted: stats?.tasksCompleted ?? 0,
    asteroidsNamed: stats?.asteroidsNamed ?? 0,
    anomaliesStudied: stats?.anomaliesStudied ?? 0,
    ticksAlive: currentTick - spawnTick,
    replacementChoice: null,
  };
  state.robotLegacies.push(legacy);

  // Clean up live-robot tracking
  state.robotStats.delete(eid);
  state.robotNames.delete(eid);
  state.glitchFlags.delete(eid);
  state.efficiencyMultipliers.delete(eid);

  return legacy;
}

/**
 * Apply the player's replacement choice for a destroyed robot.
 * Updates fleetCohesion and returns the legacy index that was updated.
 */
export function applyReplacementChoice(
  state: CultureState,
  legacyEid: number,
  choice: ReplacementChoice,
): void {
  // Find the legacy entry (most recent one for this EID)
  // Find the most recent legacy entry for this EID
  let legacy: RobotLegacy | undefined;
  for (let i = state.robotLegacies.length - 1; i >= 0; i--) {
    if (state.robotLegacies[i].eid === legacyEid) {
      legacy = state.robotLegacies[i];
      break;
    }
  }
  if (!legacy) return;
  legacy.replacementChoice = choice;

  switch (choice) {
    case 'full':
      state.fleetCohesion = clampScore(state.fleetCohesion + 3);
      break;
    case 'partial':
      state.fleetCohesion = clampScore(state.fleetCohesion + 1);
      break;
    case 'clean':
      state.fleetCohesion = clampScore(state.fleetCohesion - 2);
      break;
  }
}

/**
 * Configure a newly spawned replacement robot based on the chosen replacement type.
 * - full: glitch flag set, full efficiency inheritance
 * - partial: 50% efficiency inheritance
 * - clean: no special effects
 */
export function configureReplacementRobot(
  state: CultureState,
  newEid: number,
  choice: ReplacementChoice,
): void {
  switch (choice) {
    case 'full':
      state.glitchFlags.add(newEid);
      state.efficiencyMultipliers.set(newEid, 1.05);
      break;
    case 'partial':
      state.efficiencyMultipliers.set(newEid, 1.025); // 50% of +5% bonus
      break;
    case 'clean':
      // Standard robot, no special effects
      break;
  }
}

