// ── Intelligence tiers ───────────────────────────────────────────────────────

/**
 * Intelligence tier names. Robots progress through tiers based on tasks
 * completed AND research gates (AI Core techs).
 */
export const INTELLIGENCE_TIERS = {
  AUTOMATON: 0,
  RESPONSIVE: 1,
  ADAPTIVE: 2,
  SENTIENT: 3,
  EMERGENT: 4,
} as const;

export type IntelligenceTier = (typeof INTELLIGENCE_TIERS)[keyof typeof INTELLIGENCE_TIERS];

export const INTELLIGENCE_TIER_NAMES: Record<IntelligenceTier, string> = {
  0: 'Automaton',
  1: 'Responsive',
  2: 'Adaptive',
  3: 'Sentient',
  4: 'Emergent',
};

/** Tasks required to reach each tier (must also pass research gate). */
export const INTELLIGENCE_TIER_THRESHOLDS: Record<IntelligenceTier, number> = {
  0: 0,
  1: 10,
  2: 30,
  3: 60,
  4: 120,
};

/** Tech IDs that gate higher tiers. Tiers 0–1 have no gate. */
export const INTELLIGENCE_TIER_RESEARCH_GATES: Partial<Record<IntelligenceTier, string>> = {
  2: 'ai_core_1',
  3: 'ai_core_2',
  4: 'ai_core_3',
};

/** Efficiency multiplier per tier (applied to mining/task speed). */
export const INTELLIGENCE_TIER_EFFICIENCY: Record<IntelligenceTier, number> = {
  0: 1.0,
  1: 1.05,
  2: 1.10,
  3: 1.15,
  4: 1.20,
};

/** Leadership aura bonus for nearby lower-tier robots (tier 4 only). */
export const EMERGENT_LEADERSHIP_BONUS = 0.05;

/**
 * Compute a robot's intelligence tier from tasks completed and researched techs.
 * @param tasksCompleted Number of tasks the robot has completed.
 * @param isResearched Callback that checks if a tech ID is unlocked.
 */
export function getIntelligenceTier(
  tasksCompleted: number,
  isResearched: (techId: string) => boolean = () => false,
): IntelligenceTier {
  // Check tiers from highest to lowest
  for (let tier = 4 as IntelligenceTier; tier >= 0; tier--) {
    if (tasksCompleted < INTELLIGENCE_TIER_THRESHOLDS[tier]) continue;
    const gate = INTELLIGENCE_TIER_RESEARCH_GATES[tier];
    if (gate && !isResearched(gate)) continue;
    return tier;
  }
  return 0;
}

/** Minimum tier for culture trait mechanical effects to apply. */
export const CULTURE_TRAIT_MIN_TIER: IntelligenceTier = 3;

// ── Drift specialization ──────────────────────────────────────────────────────

/** Maximum task history length to track for drift specialization. */
export const DRIFT_HISTORY_LENGTH = 25;

/** Minimum consecutive same-type tasks before specialization kicks in. */
export const DRIFT_SPECIALIZATION_THRESHOLD = 20;

/** Efficiency multiplier for drift-specialized robots. */
export const DRIFT_SPECIALIZATION_MULT = 1.1;

/**
 * Get the drift specialization multiplier for a robot.
 * Returns DRIFT_SPECIALIZATION_MULT if the last 20+ tasks are the same type, 1.0 otherwise.
 * Also returns the dominant task type (-1 if none).
 */
export function getDriftSpecialization(lastTaskTypes: number[]): { mult: number; dominantType: number } {
  if (lastTaskTypes.length < DRIFT_SPECIALIZATION_THRESHOLD) return { mult: 1.0, dominantType: -1 };
  const recent = lastTaskTypes.slice(-DRIFT_SPECIALIZATION_THRESHOLD);
  const first = recent[0];
  for (let i = 1; i < recent.length; i++) {
    if (recent[i] !== first) return { mult: 1.0, dominantType: -1 };
  }
  return { mult: DRIFT_SPECIALIZATION_MULT, dominantType: first };
}

// ── Cultural Divergence (C_d) ─────────────────────────────────────────────────

/**
 * Compute the Cultural Divergence metric (0.0–1.0).
 * Measures how culturally developed and distinct this colony is.
 */
export function computeCulturalDivergence(state: CultureState): number {
  const dimensionDepth =
    (state.autonomyScore + state.isolationScore + state.anomalyExposure + state.fleetCohesion) / 400;
  const traitFraction = state.traits.size / 4;
  return Math.max(0, Math.min(1, 0.65 * dimensionDepth + 0.35 * traitFraction));
}

// ── Score helpers ─────────────────────────────────────────────────────────────

/** Clamp a value to [0, 100]. */
export function clampScore(v: number): number {
  return Math.max(0, Math.min(100, v));
}

/** Lerp toward a target value at the given rate per call. */
export function lerpScore(current: number, target: number, rate: number): number {
  return clampScore(current + (target - current) * rate);
}

// ── Score accumulation ───────────────────────────────────────────────────────

export interface ScoreInputs {
  /** Number of active auto-queue rules. */
  activeAutoQueueCount: number;
  /** Total robot count. */
  robotCount: number;
  /** Average distance of robots from base. */
  avgRobotDistanceFromBase: number;
  /** Number of robots currently studying anomalies. */
  studyingRobotCount: number;
  /** Number of anomalies with study stage ≥ 2. */
  analyzedAnomalyCount: number;
}

/** Smoothing rate per 1000-tick call. Lower = slower change. */
const LERP_RATE = 0.1;

/**
 * Update culture scores based on current game state.
 * Called every 1000 ticks from tick.ts.
 */
export function updateCultureScores(state: CultureState, inputs: ScoreInputs, pauseAnomalyExposure = false): void {
  // Autonomy: driven by auto-queue usage (more automation = more autonomy)
  const autonomyTarget = clampScore(inputs.activeAutoQueueCount * 20);
  state.autonomyScore = lerpScore(state.autonomyScore, autonomyTarget, LERP_RATE);

  // Isolation: driven by average distance from base (farther = more isolated)
  // Normalise: 2000 units = 100% isolation target
  const isolationTarget = clampScore((inputs.avgRobotDistanceFromBase / 2000) * 100);
  state.isolationScore = lerpScore(state.isolationScore, isolationTarget, LERP_RATE);

  // Anomaly exposure: driven by active study + analyzed count
  // When Dark Forest choice is "hidden", anomaly exposure accumulation is paused
  if (!pauseAnomalyExposure) {
    const exposureTarget = clampScore(
      inputs.studyingRobotCount * 10 + inputs.analyzedAnomalyCount * 15,
    );
    state.anomalyExposure = lerpScore(state.anomalyExposure, exposureTarget, LERP_RATE);
  }

  // Fleet cohesion: driven by robot count (more robots together = more cohesion)
  // 10 robots = 50, 20 robots = 100
  const cohesionTarget = clampScore(inputs.robotCount * 5);
  state.fleetCohesion = lerpScore(state.fleetCohesion, cohesionTarget, LERP_RATE);
}

// ── Trait recomputation ──────────────────────────────────────────────────────

/**
 * Recompute active traits from current scores.
 * Returns the set of newly activated traits (for event triggers).
 */
export function recomputeTraits(state: CultureState): CultureTrait[] {
  const newlyActivated: CultureTrait[] = [];

  for (const [trait, { dimension, min }] of Object.entries(TRAIT_THRESHOLDS) as [CultureTrait, { dimension: keyof CultureScores; min: number }][]) {
    const score = state[dimension];
    const wasActive = state.traits.has(trait);
    if (score >= min) {
      if (!wasActive) {
        state.traits.add(trait);
        newlyActivated.push(trait);
      }
    } else {
      // Hysteresis: deactivate only if score drops 10 below threshold
      if (wasActive && score < min - 10) {
        state.traits.delete(trait);
      }
    }
  }

  return newlyActivated;
}

// ── Serialization ────────────────────────────────────────────────────────────

export function serializeCultureState(state: CultureState): SerializedCultureState {
  return {
    autonomyScore: state.autonomyScore,
    isolationScore: state.isolationScore,
    anomalyExposure: state.anomalyExposure,
    fleetCohesion: state.fleetCohesion,
    traits: Array.from(state.traits),
    robotNames: Array.from(state.robotNames.entries()),
    namedLocations: state.namedLocations,
    robotLegacies: state.robotLegacies,
    robotStats: Array.from(state.robotStats.entries()),
    darkForestChoice: state.darkForestChoice,
    darkForestUnlockTick: state.darkForestUnlockTick,
    glitchFlags: Array.from(state.glitchFlags),
    efficiencyMultipliers: Array.from(state.efficiencyMultipliers.entries()),
    fleetColorPaletteId: state.fleetColorPaletteId,
    fleetManifesto: state.fleetManifesto,
    fleetManifestoPresetId: state.fleetManifestoPresetId,
    colonyName: state.colonyName,
    playerNamedAsteroids: Array.from(state.playerNamedAsteroids.entries()),
    colonyEpithet: state.colonyEpithet,
  };
}

export function deserializeCultureState(data: SerializedCultureState): CultureState {
  return {
    autonomyScore: data.autonomyScore,
    isolationScore: data.isolationScore,
    anomalyExposure: data.anomalyExposure,
    fleetCohesion: data.fleetCohesion,
    traits: new Set(data.traits),
    robotNames: new Map(data.robotNames),
    namedLocations: data.namedLocations,
    robotLegacies: data.robotLegacies,
    robotStats: new Map(data.robotStats.map(([eid, s]) => [eid, { ...s, taskHint: s.taskHint ?? -1, knowledgeBoostUntil: s.knowledgeBoostUntil ?? 0, mourningUntil: s.mourningUntil ?? 0, lastTaskTypes: s.lastTaskTypes ?? [] }])),
    darkForestChoice: data.darkForestChoice,
    darkForestUnlockTick: data.darkForestUnlockTick,
    glitchFlags: new Set(data.glitchFlags),
    efficiencyMultipliers: new Map(data.efficiencyMultipliers),
    fleetColorPaletteId: data.fleetColorPaletteId ?? null,
    fleetManifesto: data.fleetManifesto ?? null,
    fleetManifestoPresetId: data.fleetManifestoPresetId ?? null,
    colonyName: data.colonyName ?? null,
    playerNamedAsteroids: new Map(data.playerNamedAsteroids ?? []),
    colonyEpithet: data.colonyEpithet ?? null,
  };
}
