/**
 * Colony Dialect System — language drift and isolation sub-traits.
 *
 * As a colony's isolation score rises, robots develop unique vocabulary
 * ("void dialect") that replaces standard Belt terminology in comms.
 * Each faction also has a distinct dialect reflecting their culture.
 *
 * Isolation sub-traits activate at progressive thresholds, giving the
 * player visible feedback on how their colony's culture is evolving.
 */

import type { FactionId } from './factions/factionDefs';
import { FACTION_DEFS } from './factions/factionDefs';
import type { CultureState, CultureScores } from './culture';

// ── Dialect words ──────────────────────────────────────────────────────────────

export interface DialectWord {
  /** Standard Belt term. */
  standard: string;
  /** Colony-drifted replacement. */
  drifted: string;
  /** Minimum isolation score to start using this word. */
  minIsolation: number;
}

