// ── Dialect application ─────────────────────────────────────────────────────

/**
 * Get active colony dialect words for the current isolation level.
 * Returns only words whose threshold has been met.
 */
export function getActiveDialectWords(isolationScore: number): DialectWord[] {
  return COLONY_DIALECT.filter((w) => isolationScore >= w.minIsolation);
}

/**
 * Apply colony dialect to a message string.
 * Replaces standard terms with drifted equivalents (case-insensitive, whole-word).
 */
export function applyDialect(message: string, isolationScore: number): string {
  const activeWords = getActiveDialectWords(isolationScore);
  if (activeWords.length === 0) return message;

  let result = message;
  for (const word of activeWords) {
    const regex = new RegExp(`\\b${word.standard}\\b`, 'gi');
    result = result.replace(regex, word.drifted);
  }
  return result;
}

/**
 * Apply a faction's dialect to a message string.
 */
export function applyFactionDialect(message: string, factionId: FactionId): string {
  const words = FACTION_DIALECT[factionId];
  if (!words) return message;

  let result = message;
  for (const word of words) {
    const regex = new RegExp(`\\b${word.standard}\\b`, 'gi');
    result = result.replace(regex, word.drifted);
  }
  return result;
}

