// ── Cultural knowledge barriers ────────────────────────────────────────────────

/** Cultural Sovereignty: flat cultural distance boost when isolation ≥ 90. */
export const CULTURAL_SOVEREIGNTY_DISTANCE_BOOST = 0.3;

/**
 * Compute cultural distance between the player's colony and a faction (0.0–1.0).
 * Higher distance = harder to communicate/trade effectively.
 *
 * Distance is driven by:
 * - Player isolation score (primary factor — isolated colonies diverge from everyone)
 * - Mismatch between player culture profile and faction values
 */
export function computeCulturalDistance(
  cultureState: Pick<CultureState, keyof CultureScores>,
  factionId: FactionId,
): number {
  const def = FACTION_DEFS[factionId];
  let distance = 0;

  // Isolation creates baseline distance with everyone
  distance += cultureState.isolationScore / 250; // max 0.4

  // Faction-specific affinities reduce or increase distance
  switch (def.strategy) {
    case 'expansion':
      // Expansionists distrust autonomous/isolated fleets
      distance += cultureState.autonomyScore / 500;
      distance += cultureState.isolationScore / 500;
      break;
    case 'research':
      // Researchers appreciate xenoaware fleets, dislike isolation
      distance -= cultureState.anomalyExposure / 400;
      distance += cultureState.isolationScore / 400;
      break;
    case 'efficiency':
      // Efficiency-focused factions want connected, predictable partners
      distance += cultureState.isolationScore / 400;
      distance -= cultureState.fleetCohesion / 500;
      break;
  }

  // Sirius Fleet specifically respect isolation
  if (factionId === 5) {
    distance -= cultureState.isolationScore / 300;
  }

  // Cultural Sovereignty: at extreme isolation (≥90), the colony's ways become
  // incomprehensible to outsiders — a flat knowledge barrier applied to ALL factions.
  if (cultureState.isolationScore >= 90) {
    distance += CULTURAL_SOVEREIGNTY_DISTANCE_BOOST;
  }

  return Math.max(0, Math.min(1, distance));
}

/**
 * Compute the diplomacy effectiveness multiplier (0.5–1.0) based on cultural distance.
 * Higher cultural distance → lower multiplier → reduced disposition gains.
 */
export function getDiplomacyMultiplier(culturalDistance: number): number {
  // Linear falloff: distance 0 → mult 1.0, distance 1 → mult 0.5
  return 1.0 - culturalDistance * 0.5;
}

/**
 * Describe the knowledge barrier level for UI display.
 */
export function getBarrierLabel(culturalDistance: number): { label: string; color: string } {
  if (culturalDistance < 0.15) return { label: 'None', color: '#22c55e' };
  if (culturalDistance < 0.35) return { label: 'Mild', color: '#84cc16' };
  if (culturalDistance < 0.55) return { label: 'Moderate', color: '#f59e0b' };
  if (culturalDistance < 0.75) return { label: 'Strong', color: '#ef4444' };
  return { label: 'Impenetrable', color: '#991b1b' };
}
