import { state } from './state';
import { updateUsageSummaryEl } from './usageDisplay';

// ── Broadcast rate limiting ─────────────────────────────────────────────────

const BROADCAST_MIN_INTERVAL_MS = 5000;
const BROADCAST_MAX_QUEUE = 3;
const BROADCAST_GRACE_PERIOD_MS = 10000;
let lastBroadcastTime = 0;
let broadcastGraceUntil = 0;
const broadcastQueue: string[] = [];
let broadcastDrainTimer: ReturnType<typeof setTimeout> | null = null;

/** Reset broadcast rate-limiting state (for tests). */
export function resetBroadcastState(): void {
  lastBroadcastTime = 0;
  broadcastGraceUntil = 0;
  broadcastQueue.length = 0;
  if (broadcastDrainTimer !== null) {
    clearTimeout(broadcastDrainTimer);
    broadcastDrainTimer = null;
  }
}

/**
 * Begin a grace period that suppresses all ARIA broadcasts for a few seconds
 * after game load, preventing notification flood from state replay.
 */
export function beginBroadcastGracePeriod(): void {
  broadcastGraceUntil = Date.now() + BROADCAST_GRACE_PERIOD_MS;
}

function drainBroadcastQueue(): void {
  broadcastDrainTimer = null;
  if (broadcastQueue.length === 0) return;
  const text = broadcastQueue.shift()!;
  displayBroadcast(text);
  if (broadcastQueue.length > 0) {
    broadcastDrainTimer = setTimeout(drainBroadcastQueue, BROADCAST_MIN_INTERVAL_MS);
  }
}

export function showOfflineBanner(): void {
  if (!state.messagesEl) return;
  const div = document.createElement('div');
  div.style.background = 'rgba(60, 50, 0, 0.5)';
  div.style.border = '1px solid rgba(245, 158, 11, 0.35)';
  div.style.borderLeft = '2px solid #f59e0b';
  div.style.padding = '8px 10px';
  div.style.borderRadius = '2px';
  div.style.color = '#e0c890';
  div.style.lineHeight = '1.6';
  div.style.fontSize = '10px';
  div.dataset.offlineBanner = 'true';
  div.innerHTML =
    '\u2699\uFE0F ARIA AI advisor is not configured.<br>' +
    'To enable intelligent responses, click the settings icon (\uD83D\uDD11) and enter your API key, or use a proxy link.<br>' +
    '<span style="opacity:0.6">Supported: Anthropic (Claude), Groq, or Multiverse proxy.</span>';
  state.messagesEl.appendChild(div);
}

export function removeOfflineBanner(): void {
  if (!state.messagesEl) return;
  const banner = state.messagesEl.querySelector('[data-offline-banner]');
  if (banner) banner.remove();
}

export function showAuthErrorBanner(): void {
  if (!state.messagesEl) return;
  // Don't duplicate
  if (state.messagesEl.querySelector('[data-auth-error-banner]')) return;
  const div = document.createElement('div');
  div.style.background = 'rgba(80, 20, 20, 0.5)';
  div.style.border = '1px solid rgba(239, 68, 68, 0.35)';
  div.style.borderLeft = '2px solid #ef4444';
  div.style.padding = '8px 10px';
  div.style.borderRadius = '2px';
  div.style.color = '#f0a0a0';
  div.style.lineHeight = '1.6';
  div.style.fontSize = '10px';
  div.dataset.authErrorBanner = 'true';
  div.innerHTML =
    '\u26A0 ARIA API key appears invalid or expired.<br>' +
    'Responses are using onboard heuristic analysis.<br>' +
    '<span style="opacity:0.6">Update your API key in settings (\uD83D\uDD11) to restore AI responses.</span>';
  state.messagesEl.appendChild(div);
}

export function removeAuthErrorBanner(): void {
  if (!state.messagesEl) return;
  const banner = state.messagesEl.querySelector('[data-auth-error-banner]');
  if (banner) banner.remove();
}

function scrollToBottom(): void {
  if (state.messagesEl) {
    state.messagesEl.scrollTop = state.messagesEl.scrollHeight;
  }
}

export function handleSubmit(): void {
  if (!state.inputEl || !state.playerSubmitCallback) return;
  const text = state.inputEl.value.trim();
  if (!text) return;
  addPlayerMessage(text);
  state.inputEl.value = '';
  state.playerSubmitCallback(text);
}

function addPlayerMessage(text: string): void {
  if (!state.messagesEl) return;
  const div = document.createElement('div');
  div.style.background = 'rgba(0, 40, 80, 0.5)';
  div.style.border = '1px solid rgba(0, 200, 255, 0.1)';
  div.style.padding = '6px 8px';
  div.style.borderRadius = '2px';
  div.style.alignSelf = 'flex-end';
  div.style.maxWidth = '85%';
  div.style.color = '#7fb3c8';
  div.style.wordWrap = 'break-word';
  div.textContent = text;
  state.messagesEl.appendChild(div);
  scrollToBottom();
}

export function addAdvisorMessage(text: string): void {
  updateUsageSummaryEl();
  if (!state.messagesEl) return;
  const div = document.createElement('div');
  div.style.background = 'rgba(0, 20, 40, 0.7)';
  div.style.border = '1px solid rgba(0, 200, 255, 0.15)';
  div.style.borderLeft = '2px solid #06b6d4';
  div.style.padding = '6px 8px';
  div.style.borderRadius = '2px';
  div.style.alignSelf = 'flex-start';
  div.style.maxWidth = '95%';
  div.style.color = '#9ecfdf';
  div.style.lineHeight = '1.5';
  div.style.wordWrap = 'break-word';
  const label = document.createElement('div');
  label.style.fontSize = '9px';
  label.style.color = '#06b6d4';
  label.style.letterSpacing = '1px';
  label.style.marginBottom = '3px';
  label.style.opacity = '0.7';
  label.textContent = 'ARIA';
  div.appendChild(label);
  div.appendChild(document.createTextNode(text));
  state.messagesEl.appendChild(div);
  scrollToBottom();
}

export function addProactiveBroadcast(text: string): void {
  const now = Date.now();
  if (now < broadcastGraceUntil) return;
  if (now - lastBroadcastTime < BROADCAST_MIN_INTERVAL_MS) {
    if (broadcastQueue.length < BROADCAST_MAX_QUEUE) {
      broadcastQueue.push(text);
      if (broadcastDrainTimer === null) {
        broadcastDrainTimer = setTimeout(drainBroadcastQueue, BROADCAST_MIN_INTERVAL_MS);
      }
    }
    return;
  }
  displayBroadcast(text);
}

// ── Trade offer ID tracking ──────────────────────────────────────────────────

const displayedTradeOffers = new Set<string>();

/** Reset trade offer tracking state (for tests). */
export function resetTradeOfferState(): void {
  displayedTradeOffers.clear();
}

export interface TradeOfferParams {
  factionId: number;
  factionName: string;
  factionColor: string;
  resource: string;
  resourceLabel: string;
  rateMultiplier: number;
  ticksRemaining: number;
}

/**
 * Display an inline faction trade offer in the ARIA chat with accept/decline buttons.
 * Returns true if the message was displayed, false if suppressed (e.g. during grace period or duplicate).
 */
export function addTradeOfferMessage(offer: TradeOfferParams): boolean {
  const now = Date.now();
  if (now < broadcastGraceUntil) return false;
  if (!state.messagesEl) return false;

  const offerKey = `${offer.factionId}:${offer.resource}`;
  if (displayedTradeOffers.has(offerKey)) return false;
  displayedTradeOffers.add(offerKey);

  const div = document.createElement('div');
  div.style.background = 'rgba(0, 40, 20, 0.7)';
  div.style.border = '1px solid rgba(34, 197, 94, 0.25)';
  div.style.borderLeft = `3px solid ${offer.factionColor}`;
  div.style.padding = '8px 10px';
  div.style.borderRadius = '2px';
  div.style.alignSelf = 'flex-start';
  div.style.maxWidth = '95%';
  div.style.lineHeight = '1.5';
  div.style.wordWrap = 'break-word';
  div.dataset.tradeOffer = offerKey;

  // Label
  const label = document.createElement('div');
  label.style.fontSize = '9px';
  label.style.color = '#22c55e';
  label.style.letterSpacing = '1px';
  label.style.marginBottom = '4px';
  label.style.opacity = '0.7';
  label.textContent = 'TRADE PROPOSAL';
  div.appendChild(label);

  // Description
  const desc = document.createElement('div');
  desc.style.color = '#a7f3d0';
  desc.style.fontSize = '11px';
  desc.style.marginBottom = '8px';
  desc.textContent = `${offer.factionName} offers a ${offer.resourceLabel} trade at ${offer.rateMultiplier}\u00d7 rate \u2014 ${offer.ticksRemaining} ticks remaining.`;
  div.appendChild(desc);

  // Button container
  const btnContainer = document.createElement('div');
  btnContainer.style.display = 'flex';
  btnContainer.style.gap = '6px';

  const makeBtn = (text: string, bg: string, border: string, color: string): HTMLButtonElement => {
    const btn = document.createElement('button');
    btn.style.flex = '1';
    btn.style.background = bg;
    btn.style.border = `1px solid ${border}`;
    btn.style.color = color;
    btn.style.fontFamily = 'inherit';
    btn.style.fontSize = '10px';
    btn.style.fontWeight = 'bold';
    btn.style.padding = '6px 8px';
    btn.style.cursor = 'pointer';
    btn.style.borderRadius = '3px';
    btn.style.transition = 'background 0.15s';
    btn.textContent = text;
    return btn;
  };

  const acceptBtn = makeBtn('Accept Trade', 'rgba(34,197,94,0.15)', '#22c55e88', '#22c55e');
  const declineBtn = makeBtn('Decline', 'rgba(239,68,68,0.15)', '#ef444488', '#ef4444');

  const handleResponse = (response: 'accept' | 'decline') => {
    // Replace buttons with confirmation
    btnContainer.remove();
    const result = document.createElement('div');
    result.style.fontSize = '10px';
    result.style.fontStyle = 'italic';
    result.style.marginTop = '4px';
    if (response === 'accept') {
      result.style.color = '#22c55e';
      result.textContent = 'Trade accepted \u2014 relations strengthened.';
    } else {
      result.style.color = '#ef4444';
      result.textContent = 'Trade declined.';
    }
    div.appendChild(result);
    state.tradeOfferResponseCallback?.(offer.factionId, response);
  };

  acceptBtn.addEventListener('click', () => handleResponse('accept'));
  declineBtn.addEventListener('click', () => handleResponse('decline'));

  btnContainer.appendChild(acceptBtn);
  btnContainer.appendChild(declineBtn);
  div.appendChild(btnContainer);

  state.messagesEl.appendChild(div);
  scrollToBottom();
  return true;
}

function displayBroadcast(text: string): void {
  lastBroadcastTime = Date.now();
  updateUsageSummaryEl();
  if (!state.messagesEl) return;
  const div = document.createElement('div');
  div.style.background = 'rgba(30, 20, 0, 0.7)';
  div.style.border = '1px solid rgba(255, 180, 0, 0.25)';
  div.style.borderLeft = '2px solid #f59e0b';
  div.style.padding = '6px 8px';
  div.style.borderRadius = '2px';
  div.style.alignSelf = 'flex-start';
  div.style.maxWidth = '95%';
  div.style.color = '#e0c890';
  div.style.lineHeight = '1.5';
  div.style.wordWrap = 'break-word';
  const label = document.createElement('div');
  label.style.fontSize = '9px';
  label.style.color = '#f59e0b';
  label.style.letterSpacing = '1px';
  label.style.marginBottom = '3px';
  label.style.opacity = '0.7';
  label.textContent = 'ARIA BROADCAST';
  div.appendChild(label);
  div.appendChild(document.createTextNode(text));
  state.messagesEl.appendChild(div);
  scrollToBottom();
}
