import {
  AdditiveBlending,
  BufferAttribute,
  BufferGeometry,
  DynamicDrawUsage,
  Points,
  Scene,
  ShaderMaterial,
} from 'three';
import {
  getRobotState,
  getRobotX,
  getRobotY,
  getRobotZ,
} from '../../sim/bufferLayout';

/**
 * Mining spark particles. When a robot is in MINING state (state=2),
 * bright orange/yellow sparks radiate outward from its position.
 * GPU-efficient: particle positions computed in vertex shader using per-particle seeds.
 * CPU updates only emitter positions (one vec3 per active mining robot).
 */

const MAX_EMITTERS = 64;
const PARTICLES_PER_EMITTER = 20;
const TOTAL = MAX_EMITTERS * PARTICLES_PER_EMITTER;

export class MiningParticles {
  private points: Points;
  private material: ShaderMaterial;
  private emitterPosData: Float32Array;
  private emitterPosAttr: BufferAttribute;

  constructor(scene: Scene) {
    // Static random seed per particle (set once, read by shader)
    const seeds = new Float32Array(TOTAL);
    for (let i = 0; i < TOTAL; i++) {
      seeds[i] = i * 137.508; // deterministic seed per particle
    }

    // Emitter position attribute — updated CPU-side each frame
    this.emitterPosData = new Float32Array(TOTAL * 3).fill(1e6);

    const dummyPos = new Float32Array(TOTAL * 3);

    const geo = new BufferGeometry();
    geo.setAttribute('position', new BufferAttribute(dummyPos, 3));

    this.emitterPosAttr = new BufferAttribute(this.emitterPosData, 3);
    this.emitterPosAttr.setUsage(DynamicDrawUsage);
    geo.setAttribute('emitterPos', this.emitterPosAttr);
    geo.setAttribute('particleSeed', new BufferAttribute(seeds, 1));

    this.material = new ShaderMaterial({
      vertexShader: `
        attribute vec3 emitterPos;
        attribute float particleSeed;
        uniform float uTime;
        varying float vAlpha;
        varying vec3 vColor;

        float hash(float n) { return fract(sin(n) * 43758.5453); }

        void main() {
          float s = particleSeed;

          // Spherical direction for this spark
          float a1 = hash(s) * 6.2832;
          float a2 = hash(s + 1.0) * 3.1416;
          float speed = hash(s + 2.0) * 0.7 + 0.3;

          // Cycling life phase [0, 1)
          float rate = hash(s + 3.0) * 2.5 + 1.5;
          float life = fract(uTime * rate + hash(s + 4.0));

          // Fly outward
          float radius = life * 14.0 * speed;
          vec3 dir = normalize(vec3(
            sin(a2) * cos(a1),
            cos(a2),
            sin(a2) * sin(a1)
          ));
          vec3 pos = emitterPos + dir * radius;

          // Fade as spark ages
          vAlpha = (1.0 - smoothstep(0.5, 1.0, life)) * 0.95;

          // Orange -> yellow-white gradient
          float ct = hash(s + 5.0);
          vColor = mix(vec3(1.0, 0.3, 0.0), vec3(1.0, 0.95, 0.4), ct * (1.0 - life * 0.6));

          vec4 mvPos = modelViewMatrix * vec4(pos, 1.0);
          gl_PointSize = clamp(1.8 * (1.0 - life * 0.6) * (300.0 / -mvPos.z), 1.0, 8.0);
          gl_Position = projectionMatrix * mvPos;
        }
      `,
      fragmentShader: `
        varying float vAlpha;
        varying vec3 vColor;
        void main() {
          float d = length(gl_PointCoord - vec2(0.5));
          if (d > 0.5) discard;
          float a = vAlpha * (1.0 - smoothstep(0.1, 0.5, d));
          gl_FragColor = vec4(vColor, a);
        }
      `,
      uniforms: {
        uTime: { value: 0 },
      },
      transparent: true,
      depthWrite: false,
      blending: AdditiveBlending,
    });

    this.points = new Points(geo, this.material);
    this.points.frustumCulled = false;
    scene.add(this.points);
  }

  /**
   * robotBuffer stride ROBOT_STRIDE: [eid, x, y, z, rotation, type, state, energyPct]
   */
  update(robotBuffer: Float32Array, robotCount: number, time: number): void {
    this.material.uniforms.uTime.value = time;

    // Write mining robot positions directly to attribute data (no temp arrays)
    let emitterCount = 0;
    for (let i = 0; i < robotCount && emitterCount < MAX_EMITTERS; i++) {
      if (getRobotState(robotBuffer, i) === 2) {
        const px = getRobotX(robotBuffer, i);
        const py = getRobotY(robotBuffer, i);
        const pz = getRobotZ(robotBuffer, i);
        const base = emitterCount * PARTICLES_PER_EMITTER * 3;
        for (let p = 0; p < PARTICLES_PER_EMITTER; p++) {
          const idx = base + p * 3;
          this.emitterPosData[idx] = px;
          this.emitterPosData[idx + 1] = py;
          this.emitterPosData[idx + 2] = pz;
        }
        emitterCount++;
      }
    }

    // Park inactive emitters off-screen
    for (let e = emitterCount; e < MAX_EMITTERS; e++) {
      const base = e * PARTICLES_PER_EMITTER * 3;
      for (let p = 0; p < PARTICLES_PER_EMITTER; p++) {
        const idx = base + p * 3;
        this.emitterPosData[idx] = 1e6;
        this.emitterPosData[idx + 1] = 1e6;
        this.emitterPosData[idx + 2] = 1e6;
      }
    }

    this.emitterPosAttr.needsUpdate = true;
  }

  dispose(): void {
    this.points.geometry.dispose();
    this.material.dispose();
  }
}
