/**
 * Commander's Log Panel — press N to toggle.
 *
 * A persistent in-game journal where the player can write free-text entries
 * and ARIA auto-generates entries at key milestones. Morning reports are
 * also appended automatically.
 */

import { registerHudButton } from './hudButtonBar';

// ── Data model ──────────────────────────────────────────────────────────────

export interface LogEntry {
  /** Unix timestamp (ms) when the entry was created */
  timestamp: number;
  /** 'player' for manual entries, 'aria' for auto-generated */
  source: 'player' | 'aria';
  /** The entry text */
  text: string;
}

export interface SerializedCommandersLog {
  entries: LogEntry[];
}

// ── Internal state ──────────────────────────────────────────────────────────

let panel: HTMLDivElement | null = null;
let visible = false;
let entries: LogEntry[] = [];

// ── Public API ──────────────────────────────────────────────────────────────

export function initCommandersLogPanel(): void {
  registerHudButton('📓 LOG', toggleCommandersLogPanel, "Commander's Log (N)");
}

export function toggleCommandersLogPanel(): void {
  if (visible) hidePanel(); else showPanel();
}

export function hideCommandersLogPanel(): void {
  hidePanel();
}

/** Add a player-authored entry. */
export function addPlayerLogEntry(text: string): void {
  const trimmed = text.trim();
  if (!trimmed) return;
  entries.push({ timestamp: Date.now(), source: 'player', text: trimmed });
  if (visible) renderPanel();
}

/** Add an ARIA-authored entry (milestones, founding, morning reports). */
export function addAriaLogEntry(text: string): void {
  const trimmed = text.trim();
  if (!trimmed) return;
  entries.push({ timestamp: Date.now(), source: 'aria', text: trimmed });
  if (visible) renderPanel();
}

/** Serialize for save. */
export function serializeCommandersLog(): SerializedCommandersLog {
  return { entries: [...entries] };
}

/** Restore from save. */
export function restoreCommandersLog(data: SerializedCommandersLog): void {
  entries = Array.isArray(data.entries) ? [...data.entries] : [];
  if (visible) renderPanel();
}

/** Reset state (new game). */
export function resetCommandersLog(): void {
  entries = [];
  if (visible) renderPanel();
}

// ── Lifecycle ───────────────────────────────────────────────────────────────

function showPanel(): void {
  visible = true;
  if (!panel) buildPanel();
  renderPanel();
  panel!.style.display = 'flex';
}

function hidePanel(): void {
  visible = false;
  if (panel) panel.style.display = 'none';
}

function buildPanel(): void {
  panel = document.createElement('div');
  panel.style.cssText = `
    position: fixed; inset: 0;
    background: rgba(4,6,14,0.85);
    display: flex; align-items: center; justify-content: center;
    z-index: 190;
    backdrop-filter: blur(3px);
    font-family: 'Courier New', monospace;
  `;
  panel.addEventListener('click', (e) => {
    if (e.target === panel) hidePanel();
  });
  document.body.appendChild(panel);
}

function renderPanel(): void {
  if (!panel) return;

  const card = document.createElement('div');
  card.style.cssText = `
    background: rgba(8,12,24,0.97);
    border: 1px solid rgba(100,140,255,0.3);
    border-radius: 10px;
    width: min(700px, 92vw);
    max-height: 85vh;
    display: flex; flex-direction: column;
    box-shadow: 0 8px 40px rgba(0,0,0,0.7);
    color: #c0d0f0;
    overflow: hidden;
  `;

  // ── Header ──────────────────────────────────────────────────────────────
  const header = document.createElement('div');
  header.style.cssText = `
    padding: 16px 20px;
    border-bottom: 1px solid rgba(100,140,255,0.15);
  `;
  const title = document.createElement('div');
  title.style.cssText = 'font-size: 14px; color: #7090e0; letter-spacing: 2px;';
  title.textContent = "COMMANDER'S LOG";
  header.appendChild(title);
  card.appendChild(header);

  // ── Entries ─────────────────────────────────────────────────────────────
  const content = document.createElement('div');
  content.style.cssText = 'padding: 12px 20px; overflow-y: auto; flex: 1;';

  if (entries.length === 0) {
    const empty = document.createElement('div');
    empty.style.cssText = 'text-align: center; padding: 40px 0; color: #475569;';
    empty.innerHTML = `
      <div style="font-size: 12px; margin-bottom: 8px;">LOG EMPTY</div>
      <div style="font-size: 10px;">Write your first entry below.</div>
    `;
    content.appendChild(empty);
  } else {
    // Show entries in reverse chronological order
    for (let i = entries.length - 1; i >= 0; i--) {
      content.appendChild(createEntryElement(entries[i]));
    }
  }

  card.appendChild(content);

  // ── Input area ──────────────────────────────────────────────────────────
  const inputArea = document.createElement('div');
  inputArea.style.cssText = `
    padding: 12px 20px;
    border-top: 1px solid rgba(100,140,255,0.15);
    display: flex; gap: 8px; align-items: flex-end;
  `;

  const textarea = document.createElement('textarea');
  textarea.placeholder = 'Write a log entry...';
  textarea.style.cssText = `
    flex: 1;
    background: rgba(0,8,16,0.6);
    border: 1px solid rgba(100,140,255,0.2);
    border-radius: 4px;
    color: #c0d0f0;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    padding: 8px;
    resize: vertical;
    min-height: 36px;
    max-height: 100px;
    outline: none;
  `;
  textarea.addEventListener('focus', () => {
    textarea.style.borderColor = 'rgba(100,140,255,0.5)';
  });
  textarea.addEventListener('blur', () => {
    textarea.style.borderColor = 'rgba(100,140,255,0.2)';
  });
  textarea.addEventListener('keydown', (e) => {
    // Enter submits (Shift+Enter for newline)
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      submitEntry(textarea);
    }
    // Stop propagation so game keybindings don't fire while typing
    e.stopPropagation();
  });

  const submitBtn = document.createElement('button');
  submitBtn.textContent = 'LOG';
  submitBtn.style.cssText = `
    background: rgba(100,140,255,0.15);
    border: 1px solid rgba(100,140,255,0.3);
    border-radius: 4px;
    color: #7090e0;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    padding: 8px 16px;
    cursor: pointer;
    letter-spacing: 1px;
    transition: background 0.2s;
  `;
  submitBtn.addEventListener('mouseenter', () => {
    submitBtn.style.background = 'rgba(100,140,255,0.25)';
  });
  submitBtn.addEventListener('mouseleave', () => {
    submitBtn.style.background = 'rgba(100,140,255,0.15)';
  });
  submitBtn.addEventListener('click', () => submitEntry(textarea));

  inputArea.appendChild(textarea);
  inputArea.appendChild(submitBtn);
  card.appendChild(inputArea);

  // ── Close hint ──────────────────────────────────────────────────────────
  const closeHint = document.createElement('div');
  closeHint.style.cssText = 'padding: 8px 20px; text-align: center; font-size: 10px; color: #475569; border-top: 1px solid rgba(100,140,255,0.1);';
  closeHint.textContent = 'Press N or click outside to close • Enter to submit • Shift+Enter for newline';
  card.appendChild(closeHint);

  panel.innerHTML = '';
  panel.appendChild(card);

  // Auto-scroll to top (newest entries)
  content.scrollTop = 0;
}

function submitEntry(textarea: HTMLTextAreaElement): void {
  const text = textarea.value.trim();
  if (!text) return;
  addPlayerLogEntry(text);
  textarea.value = '';
}

function createEntryElement(entry: LogEntry): HTMLElement {
  const el = document.createElement('div');
  const isAria = entry.source === 'aria';
  const borderColor = isAria ? 'rgba(168,85,247,0.25)' : 'rgba(100,140,255,0.25)';
  el.style.cssText = `
    background: rgba(0,8,16,0.6);
    border: 1px solid rgba(100,140,255,0.1);
    border-left: 2px solid ${borderColor};
    padding: 10px 12px;
    margin-bottom: 8px;
    border-radius: 4px;
  `;

  const header = document.createElement('div');
  header.style.cssText = 'font-size: 9px; color: #64748b; letter-spacing: 1px; margin-bottom: 6px; display: flex; justify-content: space-between;';

  const date = new Date(entry.timestamp);
  const dateStr = date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  const timeStr = date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });

  const dateEl = document.createElement('span');
  dateEl.textContent = `${dateStr} ${timeStr}`;

  const sourceEl = document.createElement('span');
  sourceEl.style.color = isAria ? '#a855f7' : '#7090e0';
  sourceEl.textContent = isAria ? 'ARIA' : 'COMMANDER';

  header.appendChild(dateEl);
  header.appendChild(sourceEl);

  const body = document.createElement('div');
  body.style.cssText = `font-size: 11px; color: ${isAria ? '#b8a0d8' : '#94a3b8'}; line-height: 1.6; white-space: pre-wrap;`;
  body.textContent = entry.text;

  el.appendChild(header);
  el.appendChild(body);
  return el;
}
