/**
 * Dark Forest Event Modal
 *
 * Full-screen overlay with lore text for the Dark Forest cultural moment.
 * - dark_forest_choice: player chooses visible / hidden / let robots decide
 * - dark_forest_collective: robots auto-decided; player acknowledges
 */

import { trapFocus } from './focusTrap';

type DarkForestPlayerChoice = 'visible' | 'hidden' | 'robots_decide';

let overlay: HTMLDivElement | null = null;
let removeFocusTrap: (() => void) | null = null;
let onChoiceCallback: ((choice: DarkForestPlayerChoice) => void) | null = null;
/** Track whether we already showed the modal for a given message ID. */
const shownMessageIds = new Set<number>();

export function hasDarkForestBeenShown(messageId: number): boolean {
  return shownMessageIds.has(messageId);
}

export function showDarkForestModal(
  messageId: number,
  body: string,
  isCollective: boolean,
  onChoice: (choice: DarkForestPlayerChoice) => void,
): void {
  if (shownMessageIds.has(messageId)) return;
  shownMessageIds.add(messageId);
  onChoiceCallback = onChoice;

  overlay = document.createElement('div');
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.85);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 2000;
    font-family: 'Courier New', monospace;
    opacity: 0;
    transition: opacity 0.5s ease;
  `;
  document.body.appendChild(overlay);
  requestAnimationFrame(() => {
    if (overlay) overlay.style.opacity = '1';
  });

  const modal = document.createElement('div');
  modal.setAttribute('role', 'dialog');
  modal.setAttribute('aria-label', 'The Dark Forest');
  modal.setAttribute('aria-modal', 'true');
  modal.setAttribute('tabindex', '-1');
  modal.style.cssText = `
    background: rgba(0, 4, 12, 0.98);
    border: 1px solid #a855f7;
    box-shadow: 0 0 60px rgba(168,85,247,0.2), inset 0 0 40px rgba(0,0,0,0.6);
    color: #e2e8f0;
    max-width: 640px;
    width: 90vw;
    padding: 40px 36px;
    border-radius: 2px;
    position: relative;
  `;

  // Header
  const headerHtml = `
    <div style="font-size:9px; color:#a855f7; opacity:0.7; text-transform:uppercase; letter-spacing:3px; margin-bottom:6px;">FLEET AI — CULTURAL EVENT</div>
    <div style="font-size:20px; font-weight:bold; color:#a855f7; margin-bottom:24px; letter-spacing:1px;">The Dark Forest</div>
  `;

  // Body — split on double newlines into paragraphs
  const bodyHtml = body
    .split('\n\n')
    .map((para) => {
      const cleaned = para.replace(/\*/g, '').trim();
      return `<p style="margin:0 0 14px; line-height:1.8; color:#cbd5e1; font-size:12px;">${escapeHtml(cleaned)}</p>`;
    })
    .join('');

  let choicesHtml: string;

  if (isCollective) {
    choicesHtml = `
      <div style="margin-top:28px; text-align:center;">
        <div style="color:#a855f7; font-size:11px; font-style:italic; margin-bottom:16px;">The fleet has reached consensus. This is their decision, not yours.</div>
        <button id="df-dismiss" style="
          background: transparent;
          border: 1px solid #a855f788;
          color: #a855f7;
          font-family: 'Courier New', monospace;
          font-size: 11px;
          padding: 10px 28px;
          cursor: pointer;
          border-radius: 2px;
          letter-spacing: 1px;
          text-transform: uppercase;
          transition: background 0.2s;
        " onmouseover="this.style.background='rgba(168,85,247,0.15)'" onmouseout="this.style.background='transparent'">ACKNOWLEDGE</button>
      </div>
    `;
  } else {
    choicesHtml = `
      <div style="margin-top:28px; display:flex; flex-direction:column; gap:10px;">
        <button data-df-modal-choice="visible" style="
          background: transparent;
          border: 1px solid #22c55e88;
          color: #22c55e;
          font-family: 'Courier New', monospace;
          font-size: 12px;
          padding: 12px 18px;
          cursor: pointer;
          text-align: left;
          border-radius: 2px;
          transition: background 0.2s, border-color 0.2s;
        " onmouseover="this.style.background='rgba(34,197,94,0.12)';this.style.borderColor='#22c55e'" onmouseout="this.style.background='transparent';this.style.borderColor='#22c55e88'">
          <div style="font-weight:bold; margin-bottom:4px;">\u25b8 Remain Visible</div>
          <div style="font-size:10px; opacity:0.7; color:#86efac;">Broadcast our presence and findings openly. Attract attention — some friendly, some not.</div>
        </button>
        <button data-df-modal-choice="hidden" style="
          background: transparent;
          border: 1px solid #a855f788;
          color: #a855f7;
          font-family: 'Courier New', monospace;
          font-size: 12px;
          padding: 12px 18px;
          cursor: pointer;
          text-align: left;
          border-radius: 2px;
          transition: background 0.2s, border-color 0.2s;
        " onmouseover="this.style.background='rgba(168,85,247,0.12)';this.style.borderColor='#a855f7'" onmouseout="this.style.background='transparent';this.style.borderColor='#a855f788'">
          <div style="font-weight:bold; margin-bottom:4px;">\u25b8 Go Dark</div>
          <div style="font-size:10px; opacity:0.7; color:#c4b5fd;">Suppress all outward signals. Become harder to find, but learn less.</div>
        </button>
        <button data-df-modal-choice="robots_decide" style="
          background: transparent;
          border: 1px solid #f59e0b88;
          color: #f59e0b;
          font-family: 'Courier New', monospace;
          font-size: 12px;
          padding: 12px 18px;
          cursor: pointer;
          text-align: left;
          border-radius: 2px;
          transition: background 0.2s, border-color 0.2s;
        " onmouseover="this.style.background='rgba(245,158,11,0.12)';this.style.borderColor='#f59e0b'" onmouseout="this.style.background='transparent';this.style.borderColor='#f59e0b88'">
          <div style="font-weight:bold; margin-bottom:4px;">\u25b8 Let the Robots Decide</div>
          <div style="font-size:10px; opacity:0.7; color:#fcd34d;">Trust the fleet's collective judgment. Their consensus will determine the outcome.</div>
        </button>
      </div>
    `;
  }

  modal.innerHTML = headerHtml + bodyHtml + choicesHtml;
  overlay.appendChild(modal);
  removeFocusTrap = trapFocus(modal);

  // Wire up buttons
  if (isCollective) {
    modal.querySelector('#df-dismiss')?.addEventListener('click', () => {
      closeModal();
    });
  } else {
    modal.querySelectorAll<HTMLButtonElement>('[data-df-modal-choice]').forEach((btn) => {
      btn.addEventListener('click', () => {
        const choice = btn.dataset.dfModalChoice as DarkForestPlayerChoice;
        if (onChoiceCallback) onChoiceCallback(choice);
        closeModal();
      });
    });
  }
}

function closeModal(): void {
  if (!overlay) return;
  removeFocusTrap?.();
  removeFocusTrap = null;
  overlay.style.opacity = '0';
  const ref = overlay;
  setTimeout(() => ref.remove(), 500);
  overlay = null;
  onChoiceCallback = null;
}

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}
