/**
 * Automation Panel (A key) — Tiers 1-3 UI
 *
 * Tier 1: Named task queues (always visible)
 * Tier 2: Supply chain rules (visible when automated_logistics unlocked)
 * Tier 3: Autonomous sectors (visible when sector_mapping unlocked)
 */

import type { AutoQueue, SupplyRule, Sector, SerializedAutomationState } from '../sim/automation';
import { TASK_TYPES } from '../sim/taskQueue';
import { MINERAL_FIELDS } from '../sim/minerals';
import { safeHtml } from './utils/safeHtml';

type WorkerSend = (msg: object) => void;

let panel: HTMLElement | null = null;
let workerSend: WorkerSend | null = null;

let _unlockedTier2 = false;
let _unlockedTier3 = false;
let _autoKeyListenerAttached = false;

// Local mirror of server state
let _queues: AutoQueue[] = [];
let _supplyRules: SupplyRule[] = [];
let _sectors: Sector[] = [];

// ── Init ──────────────────────────────────────────────────────────────────────

export function initAutomationPanel(sendToWorker: WorkerSend): void {
  workerSend = sendToWorker;

  panel = document.createElement('div');
  panel.id = 'automation-panel';
  panel.style.cssText = `
    position: fixed;
    top: 60px;
    right: 20px;
    width: 380px;
    max-height: calc(100vh - 80px);
    overflow-y: auto;
    background: rgba(8, 12, 24, 0.95);
    border: 1px solid rgba(56, 189, 248, 0.3);
    border-radius: 8px;
    padding: 16px;
    font-family: 'JetBrains Mono', 'Courier New', monospace;
    font-size: 12px;
    color: #e2e8f0;
    display: none;
    z-index: 200;
    box-shadow: 0 4px 32px rgba(0,0,0,0.7);
  `;

  document.body.appendChild(panel);

  // A key toggles panel — guard prevents duplicate registration on re-init
  if (!_autoKeyListenerAttached) {
    _autoKeyListenerAttached = true;
    document.addEventListener('keydown', (e) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (e.key === 'a' || e.key === 'A') togglePanel();
    });
  }

  renderPanel();
}

export function setAutomationTechUnlocks(tier2: boolean, tier3: boolean): void {
  _unlockedTier2 = tier2;
  _unlockedTier3 = tier3;
  renderPanel();
}

export function updateAutomationState(state: SerializedAutomationState): void {
  _queues = state.queues;
  _supplyRules = state.supplyRules;
  _sectors = state.sectors;
  renderPanel();
}

function togglePanel(): void {
  if (!panel) return;
  panel.style.display = panel.style.display === 'none' ? 'block' : 'none';
}

// ── Rendering ─────────────────────────────────────────────────────────────────

function renderPanel(): void {
  if (!panel) return;

  panel.innerHTML = safeHtml`
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">
      <div style="color:#38bdf8;font-weight:bold;font-size:13px;letter-spacing:0.05em;">⚙ AUTOMATION</div>
      <button id="auto-close-btn" style="${btnStyle('#475569')}">✕</button>
    </div>
    ${renderTier1()}
    ${_unlockedTier2 ? renderTier2() : renderLockedSection('SUPPLY CHAIN', 'Requires: Automated Logistics tech')}
    ${_unlockedTier3 ? renderTier3() : renderLockedSection('AUTONOMOUS SECTORS', 'Requires: Sector Mapping tech')}
    <div style="margin-top:10px;color:#64748b;font-size:10px;">Press A to close</div>
  `;

  panel.querySelector('#auto-close-btn')?.addEventListener('click', () => {
    if (panel) panel.style.display = 'none';
  });

  bindTier1Events();
  if (_unlockedTier2) bindTier2Events();
  if (_unlockedTier3) bindTier3Events();
}

function renderTier1(): string {
  const rows = _queues
    .map(
      (q) => `
    <div style="display:flex;align-items:center;gap:6px;margin-bottom:6px;padding:6px;background:rgba(255,255,255,0.04);border-radius:4px;">
      <input type="checkbox" data-queue-id="${q.id}" class="queue-toggle" ${q.enabled ? 'checked' : ''}>
      <span style="flex:1;color:#cbd5e1;">${esc(q.name)}</span>
      <span style="color:#64748b;font-size:10px;">${taskTypeName(q.taskType)}${q.repeat ? ' ↺' : ''}</span>
      <button data-queue-del="${q.id}" style="${btnStyle('#dc2626')}">✕</button>
    </div>
  `,
    )
    .join('');

  return `
    <div style="margin-bottom:16px;">
      <div style="color:#94a3b8;font-size:11px;font-weight:bold;margin-bottom:8px;border-bottom:1px solid rgba(255,255,255,0.1);padding-bottom:4px;">
        TIER 1 — TASK QUEUES
      </div>
      ${rows || '<div style="color:#64748b;font-size:11px;">No queues defined.</div>'}
      <div style="margin-top:8px;display:flex;gap:6px;flex-wrap:wrap;">
        <input id="new-queue-name" type="text" placeholder="Queue name…" style="${inputStyle()}" maxlength="32">
        <select id="new-queue-type" style="${selectStyle()}">
          <option value="0">Mine</option>
          <option value="2">Explore</option>
        </select>
        <label style="display:flex;align-items:center;gap:4px;color:#94a3b8;font-size:11px;">
          <input type="checkbox" id="new-queue-repeat"> Repeat
        </label>
        <button id="add-queue-btn" style="${btnStyle('#0ea5e9')}">+ Add Queue</button>
      </div>
    </div>
  `;
}

function renderTier2(): string {
  const RESOURCES = MINERAL_FIELDS;
  const rows = _supplyRules
    .map(
      (r) => `
    <div style="display:flex;align-items:center;gap:6px;margin-bottom:6px;padding:6px;background:rgba(255,255,255,0.04);border-radius:4px;">
      <input type="checkbox" data-supply-res="${r.resource}" class="supply-toggle" ${r.enabled ? 'checked' : ''}>
      <span style="flex:1;color:#cbd5e1;text-transform:capitalize;">${esc(r.resource)}</span>
      <span style="color:#64748b;font-size:10px;">≥ ${r.targetLevel.toLocaleString()}</span>
      <button data-supply-del="${r.resource}" style="${btnStyle('#dc2626')}">✕</button>
    </div>
  `,
    )
    .join('');

  return `
    <div style="margin-bottom:16px;">
      <div style="color:#94a3b8;font-size:11px;font-weight:bold;margin-bottom:8px;border-bottom:1px solid rgba(255,255,255,0.1);padding-bottom:4px;">
        TIER 2 — SUPPLY CHAINS
      </div>
      ${rows || '<div style="color:#64748b;font-size:11px;">No supply rules defined.</div>'}
      <div style="margin-top:8px;display:flex;gap:6px;flex-wrap:wrap;align-items:center;">
        <select id="new-supply-res" style="${selectStyle()}">
          ${RESOURCES.map((r) => `<option value="${r}">${r}</option>`).join('')}
        </select>
        <span style="color:#64748b;font-size:11px;">target:</span>
        <input id="new-supply-target" type="number" min="1" value="500" style="${inputStyle('60px')}">
        <button id="add-supply-btn" style="${btnStyle('#10b981')}">+ Add Rule</button>
      </div>
    </div>
  `;
}

function renderTier3(): string {
  const rows = _sectors
    .map(
      (s) => `
    <div style="padding:6px;margin-bottom:6px;background:rgba(255,255,255,0.04);border-radius:4px;">
      <div style="display:flex;align-items:center;gap:6px;">
        <input type="checkbox" data-sector-id="${s.id}" class="sector-toggle" ${s.enabled ? 'checked' : ''}>
        <span style="flex:1;color:#cbd5e1;">${esc(s.name)}</span>
        <span style="color:#64748b;font-size:10px;">${s.goal.replace('_', ' ')}</span>
        <button data-sector-del="${s.id}" style="${btnStyle('#dc2626')}">✕</button>
      </div>
      <div style="color:#475569;font-size:10px;margin-top:3px;padding-left:20px;">
        X: [${s.minX.toFixed(0)}, ${s.maxX.toFixed(0)}] Z: [${s.minZ.toFixed(0)}, ${s.maxZ.toFixed(0)}]
        · tasks: ${s.tasksGenerated}
      </div>
    </div>
  `,
    )
    .join('');

  return `
    <div style="margin-bottom:16px;">
      <div style="color:#94a3b8;font-size:11px;font-weight:bold;margin-bottom:8px;border-bottom:1px solid rgba(255,255,255,0.1);padding-bottom:4px;">
        TIER 3 — AUTONOMOUS SECTORS
      </div>
      ${rows || '<div style="color:#64748b;font-size:11px;">No sectors defined.</div>'}
      <div style="margin-top:8px;display:grid;grid-template-columns:1fr 1fr;gap:4px;">
        <input id="new-sector-name" type="text" placeholder="Sector name…" style="${inputStyle()}" maxlength="24">
        <select id="new-sector-goal" style="${selectStyle()}">
          <option value="maximize_mining">Max Mining</option>
          <option value="explore_anomalies">Explore Anomalies</option>
          <option value="balanced">Balanced</option>
        </select>
        <input id="new-sector-minx" type="number" placeholder="Min X" style="${inputStyle()}">
        <input id="new-sector-maxx" type="number" placeholder="Max X" style="${inputStyle()}">
        <input id="new-sector-minz" type="number" placeholder="Min Z" style="${inputStyle()}">
        <input id="new-sector-maxz" type="number" placeholder="Max Z" style="${inputStyle()}">
      </div>
      <button id="add-sector-btn" style="${btnStyle('#a855f7')};margin-top:6px;width:100%;">+ Add Sector</button>
    </div>
  `;
}

function renderLockedSection(title: string, hint: string): string {
  return `
    <div style="margin-bottom:16px;opacity:0.4;">
      <div style="color:#94a3b8;font-size:11px;font-weight:bold;margin-bottom:8px;border-bottom:1px solid rgba(255,255,255,0.1);padding-bottom:4px;">
        ${title} 🔒
      </div>
      <div style="color:#64748b;font-size:11px;">${hint}</div>
    </div>
  `;
}

// ── Event Binding ─────────────────────────────────────────────────────────────

function bindTier1Events(): void {
  // Toggle queues
  panel?.querySelectorAll('.queue-toggle').forEach((el) => {
    el.addEventListener('change', (e) => {
      const id = (e.target as HTMLElement).dataset.queueId;
      const q = _queues.find((qq) => qq.id === id);
      if (q) {
        const updated = { ...q, enabled: (e.target as HTMLInputElement).checked };
        workerSend?.({ type: 'sim:upsert_auto_queue', payload: updated });
      }
    });
  });

  // Delete queues
  panel?.querySelectorAll('[data-queue-del]').forEach((el) => {
    el.addEventListener('click', () => {
      const id = (el as HTMLElement).dataset.queueDel;
      if (id) workerSend?.({ type: 'sim:delete_auto_queue', payload: { id } });
    });
  });

  // Add queue
  panel?.querySelector('#add-queue-btn')?.addEventListener('click', () => {
    const name = (panel?.querySelector('#new-queue-name') as HTMLInputElement)?.value.trim();
    const type = parseInt(
      (panel?.querySelector('#new-queue-type') as HTMLSelectElement)?.value ?? '0',
    );
    const repeat =
      (panel?.querySelector('#new-queue-repeat') as HTMLInputElement)?.checked ?? false;
    if (!name) return;

    const q: AutoQueue = {
      id: `q_${Date.now()}`,
      name,
      taskType: type,
      priority: 5,
      repeat,
      enabled: true,
    };
    workerSend?.({ type: 'sim:upsert_auto_queue', payload: q });
    // Optimistic update
    _queues = [..._queues, q];
    renderPanel();
  });
}

function bindTier2Events(): void {
  // Toggle rules
  panel?.querySelectorAll('.supply-toggle').forEach((el) => {
    el.addEventListener('change', (e) => {
      const resource = (e.target as HTMLElement).dataset.supplyRes;
      const rule = _supplyRules.find((r) => r.resource === resource);
      if (rule) {
        const updated = { ...rule, enabled: (e.target as HTMLInputElement).checked };
        workerSend?.({ type: 'sim:upsert_supply_rule', payload: updated });
      }
    });
  });

  // Delete rules
  panel?.querySelectorAll('[data-supply-del]').forEach((el) => {
    el.addEventListener('click', () => {
      const resource = (el as HTMLElement).dataset.supplyDel;
      if (resource) workerSend?.({ type: 'sim:delete_supply_rule', payload: { resource } });
    });
  });

  // Add rule
  panel?.querySelector('#add-supply-btn')?.addEventListener('click', () => {
    const resource = (panel?.querySelector('#new-supply-res') as HTMLSelectElement)?.value;
    const target = parseInt(
      (panel?.querySelector('#new-supply-target') as HTMLInputElement)?.value ?? '500',
    );
    if (!resource || isNaN(target) || target <= 0) return;

    const rule: SupplyRule = { resource, targetLevel: target, priority: 6, enabled: true };
    workerSend?.({ type: 'sim:upsert_supply_rule', payload: rule });
    _supplyRules = [..._supplyRules.filter((r) => r.resource !== resource), rule];
    renderPanel();
  });
}

function bindTier3Events(): void {
  // Toggle sectors
  panel?.querySelectorAll('.sector-toggle').forEach((el) => {
    el.addEventListener('change', (e) => {
      const id = (e.target as HTMLElement).dataset.sectorId;
      const sector = _sectors.find((s) => s.id === id);
      if (sector) {
        const updated = { ...sector, enabled: (e.target as HTMLInputElement).checked };
        workerSend?.({ type: 'sim:upsert_sector', payload: updated });
      }
    });
  });

  // Delete sectors
  panel?.querySelectorAll('[data-sector-del]').forEach((el) => {
    el.addEventListener('click', () => {
      const id = (el as HTMLElement).dataset.sectorDel;
      if (id) workerSend?.({ type: 'sim:delete_sector', payload: { id } });
    });
  });

  // Add sector
  panel?.querySelector('#add-sector-btn')?.addEventListener('click', () => {
    const name = (panel?.querySelector('#new-sector-name') as HTMLInputElement)?.value.trim();
    const goal = (panel?.querySelector('#new-sector-goal') as HTMLSelectElement)
      ?.value as Sector['goal'];
    const minX = parseFloat(
      (panel?.querySelector('#new-sector-minx') as HTMLInputElement)?.value ?? '0',
    );
    const maxX = parseFloat(
      (panel?.querySelector('#new-sector-maxx') as HTMLInputElement)?.value ?? '0',
    );
    const minZ = parseFloat(
      (panel?.querySelector('#new-sector-minz') as HTMLInputElement)?.value ?? '0',
    );
    const maxZ = parseFloat(
      (panel?.querySelector('#new-sector-maxz') as HTMLInputElement)?.value ?? '0',
    );

    if (!name || isNaN(minX) || isNaN(maxX) || isNaN(minZ) || isNaN(maxZ)) return;
    if (minX >= maxX || minZ >= maxZ) return;

    const sector: Sector = {
      id: `sec_${Date.now()}`,
      name,
      minX,
      maxX,
      minZ,
      maxZ,
      goal,
      enabled: true,
      assignedRobotEids: [],
      tasksGenerated: 0,
    };
    workerSend?.({ type: 'sim:upsert_sector', payload: sector });
    _sectors = [..._sectors, sector];
    renderPanel();
  });
}

// ── Style helpers ─────────────────────────────────────────────────────────────

function btnStyle(color: string): string {
  return `background:${color};color:#fff;border:none;border-radius:4px;padding:3px 8px;cursor:pointer;font-size:11px;font-family:inherit;`;
}

function inputStyle(width = '100%'): string {
  return `background:rgba(255,255,255,0.07);border:1px solid rgba(255,255,255,0.15);border-radius:4px;padding:4px 6px;color:#e2e8f0;font-size:11px;font-family:inherit;width:${width};box-sizing:border-box;`;
}

function selectStyle(): string {
  return `background:rgba(15,20,40,0.95);border:1px solid rgba(255,255,255,0.15);border-radius:4px;padding:4px 6px;color:#e2e8f0;font-size:11px;font-family:inherit;`;
}

function taskTypeName(t: number): string {
  if (t === TASK_TYPES.MINE) return 'Mine';
  if (t === TASK_TYPES.HAUL) return 'Haul';
  if (t === TASK_TYPES.EXPLORE) return 'Explore';
  return '?';
}

function esc(s: string): string {
  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
