/**
 * Keybinding Help Overlay
 *
 * H key shows all keybindings. Press H or Escape to dismiss.
 */

import { trapFocus } from './focusTrap';

let overlay: HTMLDivElement | null = null;
let visible = false;
let removeFocusTrap: (() => void) | null = null;

const BINDINGS: Array<{ key: string; desc: string }> = [
  { key: 'WASD / Arrow Keys', desc: 'Pan camera' },
  { key: 'Scroll wheel', desc: 'Zoom in/out' },
  { key: 'Middle-click drag', desc: 'Pan camera' },
  { key: 'Left-click robot', desc: 'Follow robot (click again or ESC to stop)' },
  { key: 'Tab', desc: 'Follow next robot' },
  { key: 'Shift+Tab', desc: 'Follow previous robot' },
  { key: 'Home', desc: 'Return camera to base station' },
  { key: 'T', desc: 'Tech tree / Research' },
  { key: 'J', desc: 'Journal / Codex' },
  { key: 'C', desc: 'Construction bay — build robots' },
  { key: 'A', desc: 'Automation panel' },
  { key: 'W', desc: 'Material priorities — fleet targeting weights' },
  { key: 'V', desc: 'Base Buildings — upgrade outpost infrastructure' },
  { key: 'B', desc: 'Bases & logistics (build outposts, hauler routes)' },
  { key: 'D', desc: 'Operations dashboard' },
  { key: 'F', desc: 'Faction relations & diplomacy' },
  { key: 'L', desc: 'Event log' },
  { key: 'U', desc: 'Fleet culture & traits' },
  { key: 'E', desc: 'Game event log — scrollable history' },
  { key: 'N', desc: "Commander's Log — personal journal" },
  { key: 'P', desc: 'Meridian Archives & Historical Database' },
  { key: 'M', desc: 'Mute / unmute audio' },
  { key: 'H', desc: 'Show this help' },
  { key: 'ESC', desc: 'Pause menu' },
  { key: 'Ctrl+S', desc: 'Quick save' },
];

export function initKeybindingHelp(): void {
  // Nothing to do — overlay is built lazily
}

export function toggleKeybindingHelp(): void {
  if (visible) {
    hideHelp();
  } else {
    showHelp();
  }
}

export function hideKeybindingHelp(): void {
  hideHelp();
}

function showHelp(): void {
  visible = true;
  if (!overlay) buildOverlay();
  overlay!.style.display = 'flex';
  const card = overlay!.querySelector<HTMLElement>('[role="dialog"]');
  if (card) removeFocusTrap = trapFocus(card);
}

function hideHelp(): void {
  visible = false;
  removeFocusTrap?.();
  removeFocusTrap = null;
  if (overlay) overlay.style.display = 'none';
}

function buildOverlay(): void {
  overlay = document.createElement('div');
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(4,6,14,0.85);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 200;
    backdrop-filter: blur(4px);
  `;

  const card = document.createElement('div');
  card.setAttribute('role', 'dialog');
  card.setAttribute('aria-label', 'Keyboard reference');
  card.setAttribute('tabindex', '-1');
  card.style.cssText = `
    background: rgba(10,14,28,0.97);
    border: 1px solid rgba(100,140,255,0.3);
    border-radius: 10px;
    padding: 28px 36px;
    min-width: 380px;
    font-family: 'Courier New', monospace;
    color: #c0d0f0;
    box-shadow: 0 8px 40px rgba(0,0,0,0.7);
  `;

  // Title
  const title = document.createElement('div');
  title.style.cssText = `
    font-size: 14px;
    color: #7090e0;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    margin-bottom: 20px;
    border-bottom: 1px solid rgba(100,140,255,0.2);
    padding-bottom: 10px;
  `;
  title.textContent = '⌨ Keyboard Reference';
  card.appendChild(title);

  // Binding rows
  const grid = document.createElement('div');
  grid.style.cssText = 'display:grid;grid-template-columns:auto 1fr;gap:6px 20px;';

  for (const { key, desc } of BINDINGS) {
    const keyEl = document.createElement('span');
    keyEl.style.cssText = `
      background: rgba(60,80,140,0.5);
      border: 1px solid rgba(100,140,255,0.25);
      border-radius: 3px;
      padding: 2px 7px;
      font-size: 11px;
      color: #a0c0ff;
      white-space: nowrap;
      text-align: center;
    `;
    keyEl.textContent = key;

    const descEl = document.createElement('span');
    descEl.style.cssText = 'font-size:12px;color:#8090b0;align-self:center;';
    descEl.textContent = desc;

    grid.appendChild(keyEl);
    grid.appendChild(descEl);
  }
  card.appendChild(grid);

  // Dismiss hint + close button
  const footer = document.createElement('div');
  footer.style.cssText = 'text-align:center;margin-top:20px;display:flex;flex-direction:column;align-items:center;gap:8px;';
  const hint = document.createElement('div');
  hint.style.cssText = 'font-size:10px;color:#4a5568;';
  hint.textContent = 'Press H or Escape to close';
  const closeBtn = document.createElement('button');
  closeBtn.textContent = 'Close';
  closeBtn.setAttribute('aria-label', 'Close keyboard reference');
  closeBtn.style.cssText = `
    padding: 5px 20px;
    background: rgba(60,80,140,0.6);
    border: 1px solid rgba(100,140,255,0.3);
    border-radius: 5px;
    color: #a0c0ff;
    cursor: pointer;
    font-family: 'Courier New', monospace;
    font-size: 11px;
  `;
  closeBtn.onclick = () => hideHelp();
  footer.appendChild(hint);
  footer.appendChild(closeBtn);
  card.appendChild(footer);

  overlay.appendChild(card);

  // Click backdrop or press Escape to close
  overlay.addEventListener('click', (e) => {
    if (e.target === overlay) hideHelp();
  });
  overlay.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') hideHelp();
  });

  document.body.appendChild(overlay);
}
