import * as Sentry from '@sentry/browser';

/**
 * Lightweight analytics via Umami (self-hosted, privacy-first).
 *
 * All events use umami.track() custom events. No PII is collected.
 * One-time events (first_mine, tutorial_complete, etc.) are deduplicated
 * per session so they only fire once.
 */

declare global {
  interface Window {
    umami?: {
      track: (event: string, data?: Record<string, string | number>) => void;
    };
  }
}

const fired = new Set<string>();

/** Track a custom event. If `once` is true, only fires once per session. */
export function trackEvent(
  event: string,
  data?: Record<string, string | number>,
  once = false,
): void {
  if (once && fired.has(event)) return;
  if (once) fired.add(event);
  Sentry.addBreadcrumb({ category: 'analytics', message: event, level: 'info' });
  try {
    window.umami?.track(event, data);
  } catch {
    // Silently ignore — analytics should never break the game.
  }
}

// ── Session duration tracking ─────────────────────────────────────────────────

let sessionStartTime = 0;

export function startSession(): void {
  sessionStartTime = Date.now();
  trackEvent('game_start');
}

export function endSession(): void {
  if (sessionStartTime > 0) {
    const durationSec = Math.round((Date.now() - sessionStartTime) / 1000);
    trackEvent('session_end', { duration_sec: durationSec });
  }
}

// ── Convenience one-time events ───────────────────────────────────────────────

export function trackTutorialComplete(): void {
  trackEvent('tutorial_complete', undefined, true);
}

export function trackFirstMine(): void {
  trackEvent('first_mine', undefined, true);
}

export function trackFirstFactionContact(): void {
  trackEvent('first_faction_contact', undefined, true);
}

export function trackAriaUsage(): void {
  trackEvent('aria_usage');
}

export function trackDysonComplete(): void {
  trackEvent('dyson_complete', undefined, true);
}

/** Reset session-level dedup (call on new game). */
export function resetAnalytics(): void {
  fired.clear();
}
