/** Touch device detection and on-screen gesture hints. */

export const isTouchDevice =
  typeof window !== 'undefined' &&
  ('ontouchstart' in window || navigator.maxTouchPoints > 0);

const STORAGE_KEY = 'ast_touch_hints_shown';

/**
 * On touch devices: show a brief gesture hint overlay on first load.
 * Auto-dismisses after 4s or on tap.
 * Uses sessionStorage so it only shows once per session.
 */
export function maybeShowTouchHints(): void {
  if (!isTouchDevice) return;
  if (sessionStorage.getItem(STORAGE_KEY)) return;
  sessionStorage.setItem(STORAGE_KEY, '1');

  const overlay = document.createElement('div');
  overlay.style.cssText = `
    position: fixed;
    bottom: 80px;
    left: 50%;
    transform: translateX(-50%);
    background: rgba(0, 8, 20, 0.85);
    border: 1px solid rgba(34, 211, 238, 0.4);
    box-shadow: 0 0 16px rgba(34, 211, 238, 0.15);
    color: rgba(34, 211, 238, 0.9);
    font-family: 'Courier New', monospace;
    font-size: 12px;
    line-height: 1.8;
    padding: 12px 20px;
    border-radius: 4px;
    z-index: 200;
    pointer-events: auto;
    text-align: center;
    opacity: 0;
    transition: opacity 0.4s ease;
    white-space: nowrap;
  `;
  overlay.innerHTML = `
    <div style="font-size:10px;opacity:0.5;text-transform:uppercase;letter-spacing:1px;margin-bottom:6px;">Gesture Controls</div>
    <div>Drag to pan &nbsp;·&nbsp; Pinch to zoom &nbsp;·&nbsp; Tap robot to follow</div>
  `;

  document.body.appendChild(overlay);

  requestAnimationFrame(() => {
    overlay.style.opacity = '1';
  });

  const dismiss = (): void => {
    overlay.style.opacity = '0';
    setTimeout(() => overlay.remove(), 400);
  };

  overlay.addEventListener('touchend', dismiss, { once: true });
  setTimeout(dismiss, 4000);
}

let _styleInjected = false;

/**
 * Adds 'touch-device' class to body and injects CSS rules:
 * - Min 44px touch targets on all interactive elements
 * - Hides elements with .mouse-hint class on touch devices
 *
 * Idempotent: safe to call multiple times — style is only injected once.
 */
export function applyTouchDeviceClass(): void {
  if (!isTouchDevice) return;
  document.body.classList.add('touch-device');

  if (_styleInjected) return;
  _styleInjected = true;

  try {
    const style = document.createElement('style');
    style.textContent = `
    .touch-device button,
    .touch-device [role="button"] {
      min-height: 44px;
      min-width: 44px;
    }
    .touch-device .mouse-hint {
      display: none !important;
    }
  `;
    document.head.appendChild(style);
  } catch {
    // DOM manipulation failed (e.g. restrictive CSP); skip silently.
  }
}

/** Reset injection state — for testing only. */
export function _resetStyleInjected(): void {
  _styleInjected = false;
}
