import {
  AdditiveBlending,
  BufferAttribute,
  BufferGeometry,
  DynamicDrawUsage,
  Points,
  Scene,
  ShaderMaterial,
} from 'three';

/**
 * One-shot debris burst when an asteroid is fully depleted.
 * Rocks/dust expand outward from the depletion point, then fade out.
 *
 * Uses a fixed pool of burst slots. Each burst has a start time;
 * particles older than BURST_DURATION are hidden by the shader.
 */

const MAX_BURSTS = 16;
const PARTICLES_PER_BURST = 32;
const TOTAL = MAX_BURSTS * PARTICLES_PER_BURST;
const BURST_DURATION = 2.0; // seconds

export class DepletionParticles {
  private points: Points;
  private material: ShaderMaterial;
  private emitterPosData: Float32Array;
  private emitterMetaData: Float32Array;
  private emitterPosAttr: BufferAttribute;
  private emitterMetaAttr: BufferAttribute;
  private nextSlot = 0;

  constructor(scene: Scene) {
    const seeds = new Float32Array(TOTAL);
    for (let i = 0; i < TOTAL; i++) {
      seeds[i] = i * 97.31 + 0.5;
    }

    this.emitterPosData = new Float32Array(TOTAL * 3);
    this.emitterMetaData = new Float32Array(TOTAL * 2);
    // Initialize start times to -999 so all particles are invisible
    for (let i = 0; i < TOTAL; i++) {
      this.emitterMetaData[i * 2] = -999;
    }

    const dummyPos = new Float32Array(TOTAL * 3);
    const geo = new BufferGeometry();
    geo.setAttribute('position', new BufferAttribute(dummyPos, 3));
    geo.setAttribute('particleSeed', new BufferAttribute(seeds, 1));

    this.emitterPosAttr = new BufferAttribute(this.emitterPosData, 3);
    this.emitterPosAttr.setUsage(DynamicDrawUsage);
    geo.setAttribute('emitterPos', this.emitterPosAttr);

    this.emitterMetaAttr = new BufferAttribute(this.emitterMetaData, 2);
    this.emitterMetaAttr.setUsage(DynamicDrawUsage);
    geo.setAttribute('emitterMeta', this.emitterMetaAttr);

    this.material = new ShaderMaterial({
      vertexShader: VERT,
      fragmentShader: FRAG,
      uniforms: { uTime: { value: 0 } },
      transparent: true,
      depthWrite: false,
      blending: AdditiveBlending,
    });

    this.points = new Points(geo, this.material);
    this.points.frustumCulled = false;
    scene.add(this.points);
  }

  /** Spawn a debris burst at the given position. */
  spawn(x: number, y: number, z: number, radius: number, time: number): void {
    const base = this.nextSlot * PARTICLES_PER_BURST;
    for (let p = 0; p < PARTICLES_PER_BURST; p++) {
      const idx = base + p;
      this.emitterPosData[idx * 3] = x;
      this.emitterPosData[idx * 3 + 1] = y;
      this.emitterPosData[idx * 3 + 2] = z;
      this.emitterMetaData[idx * 2] = time;
      this.emitterMetaData[idx * 2 + 1] = radius;
    }
    this.nextSlot = (this.nextSlot + 1) % MAX_BURSTS;
  }

  update(time: number): void {
    this.material.uniforms.uTime.value = time;
    this.emitterPosAttr.needsUpdate = true;
    this.emitterMetaAttr.needsUpdate = true;
  }

  dispose(): void {
    this.points.geometry.dispose();
    this.material.dispose();
  }
}

const VERT = /* glsl */ `
  attribute vec3 emitterPos;
  attribute vec2 emitterMeta; // x = startTime, y = radius
  attribute float particleSeed;
  uniform float uTime;
  varying float vAlpha;
  varying vec3 vColor;

  float hash(float n) { return fract(sin(n) * 43758.5453); }

  void main() {
    float startTime = emitterMeta.x;
    float radius = emitterMeta.y;
    float age = uTime - startTime;
    float life = clamp(age / ${BURST_DURATION.toFixed(1)}, 0.0, 1.0);

    // Hide expired or not-yet-spawned particles
    if (age < 0.0 || age > ${BURST_DURATION.toFixed(1)}) {
      gl_Position = vec4(0.0, 0.0, -2.0, 1.0);
      gl_PointSize = 0.0;
      vAlpha = 0.0;
      vColor = vec3(0.0);
      return;
    }

    float s = particleSeed;

    // Random spherical direction
    float a1 = hash(s) * 6.2832;
    float a2 = hash(s + 1.0) * 3.1416 - 1.5708;
    float speed = hash(s + 2.0) * 0.6 + 0.4;

    // Debris flies outward, decelerating
    float dist = radius * 3.0 * speed * (1.0 - (1.0 - life) * (1.0 - life));
    float yDrift = -life * life * radius * 0.3;

    vec3 dir = vec3(
      cos(a2) * cos(a1),
      sin(a2),
      cos(a2) * sin(a1)
    );
    vec3 pos = emitterPos + dir * dist;
    pos.y += yDrift;

    // Quick burst then fade
    vAlpha = (1.0 - smoothstep(0.3, 1.0, life)) * 0.85;

    // Rock debris color: brownish-grey with variation
    float ct = hash(s + 5.0);
    vColor = mix(
      vec3(0.6, 0.45, 0.25),
      vec3(0.4, 0.38, 0.35),
      ct
    );
    // Some bright sparks
    if (hash(s + 6.0) > 0.85) {
      vColor = mix(vColor, vec3(1.0, 0.7, 0.2), 0.6);
    }

    vec4 mvPos = modelViewMatrix * vec4(pos, 1.0);
    float baseSize = mix(2.0, 4.0, hash(s + 3.0)) * (radius / 10.0 + 0.5);
    gl_PointSize = clamp(baseSize * (1.0 - life * 0.5) * (500.0 / -mvPos.z), 1.0, 12.0);
    gl_Position = projectionMatrix * mvPos;
  }
`;

const FRAG = /* glsl */ `
  varying float vAlpha;
  varying vec3 vColor;
  void main() {
    float d = length(gl_PointCoord - vec2(0.5));
    if (d > 0.5) discard;
    float a = vAlpha * (1.0 - smoothstep(0.2, 0.5, d));
    gl_FragColor = vec4(vColor, a);
  }
`;
