/**
 * ARIA Auto-Analysis — periodic proactive game-state briefings.
 *
 * Fires every AUTO_ANALYSIS_INTERVAL_MS of real time when:
 *   - The game is running (not paused, not loading)
 *   - A meaningful change in game state has occurred since the last analysis
 *   - The player has not interacted with ARIA in the last 300 ticks
 *   - No unread ARIA auto-insight is already queued
 *
 * Uses LLM when available; falls back to rule-based heuristic insights otherwise.
 * Results are posted as Commander Inbox messages with type 'aria_auto'.
 */

import { askAdvisor, hasApiKey } from './advisorService';
import { isOverBudget } from './usage';
import { determineFallbackTier } from './fallbackChain';
import { getDialogueStage } from './ariaSpectrum';
import { buildStageAwareAutoAnalysisQuery } from './ariaDialogue';
import type { GameStateSummary } from './gameState';
import type { InboxMessage, InboxSnapshot } from '../sim/inbox/inboxTypes';
import type { MainToWorkerMessage } from '../sim/messages';

// ── Configuration ─────────────────────────────────────────────────────────────

/** Real-time interval between auto-analysis checks (5 minutes). */
export const AUTO_ANALYSIS_INTERVAL_MS = 5 * 60 * 1000;

/** Minimum ticks since last player interaction with ARIA before proactive insight fires. */
const INTERACTION_COOLDOWN_TICKS = 300;

const AUTO_ANALYSIS_QUERY_BASE = `Provide a brief operational briefing of the current mining operation status.
Start your response with "[Periodic Review]" for routine status, or "[Alert]" if you detect a critical situation (critically low resources, imminent threat, megastructure crisis imminent, hostile faction, or significant opportunity).
If a megastructure has a crisis warning, prioritize alerting the player to stockpile resolution materials before the crisis strikes.
If faction standings are available, reference notable relationships — especially hostile factions or strong allies that affect strategy.
Keep it concise — 2-4 sentences. Reference specific data from the game state.`;

const AUTO_ANALYSIS_RESEARCH_ADDENDUM = ` You may include research direction recommendations if they are strategically relevant.`;

function buildAutoAnalysisQuery(canDirectResearch: boolean): string {
  return canDirectResearch
    ? AUTO_ANALYSIS_QUERY_BASE + AUTO_ANALYSIS_RESEARCH_ADDENDUM
    : AUTO_ANALYSIS_QUERY_BASE + ` Do not recommend spending research points or directing research — focus only on fleet, resources, and field operations.`;
}

// ── State ─────────────────────────────────────────────────────────────────────

let intervalId: ReturnType<typeof setInterval> | null = null;
let running = false;

let workerSendFn: ((msg: MainToWorkerMessage) => void) | null = null;
let buildStateFn: (() => GameStateSummary) | null = null;
let isPausedFn: (() => boolean) | null = null;
let getInboxSnapshotFn: (() => InboxSnapshot | null) | null = null;

/** Snapshot of game state metrics from the last completed analysis */
let lastSnapshot: StateSnapshot | null = null;

/** Unique ID counter for injected ARIA messages (uses high offset to avoid collision with worker IDs) */
let nextAutoMsgId = 10_000_000;

/** Tick of last player interaction with ARIA (query or panel open) */
let lastPlayerInteractionTick = -Infinity;

interface StateSnapshot {
  totalResources: number;
  robotCount: number;
  discoveryCount: number;
  crisisEligibleCount: number;
  hostileFactionCount: number;
}

// ── Public API ────────────────────────────────────────────────────────────────

export function setAutoAnalysisWorkerSend(fn: (msg: MainToWorkerMessage) => void): void {
  workerSendFn = fn;
}

export function setAutoAnalysisBuildState(fn: () => GameStateSummary): void {
  buildStateFn = fn;
}

export function setAutoAnalysisIsPaused(fn: () => boolean): void {
  isPausedFn = fn;
}

export function setAutoAnalysisInboxSnapshot(fn: () => InboxSnapshot | null): void {
  getInboxSnapshotFn = fn;
}

/** Call when the player interacts with ARIA (sends a message, opens advisor panel). */
export function recordPlayerInteraction(tick: number): void {
  lastPlayerInteractionTick = tick;
}

export function startAutoAnalysis(): void {
  if (intervalId !== null) return;
  intervalId = setInterval(() => {
    void runAutoAnalysis();
  }, AUTO_ANALYSIS_INTERVAL_MS);

  // Suspend when tab is hidden (browsers throttle setInterval to 1/min anyway)
  if (typeof document !== 'undefined') {
    document.addEventListener('visibilitychange', handleVisibilityChange);
  }
  // Clean up on page unload / HMR
  if (typeof window !== 'undefined') {
    window.addEventListener('beforeunload', stopAutoAnalysis);
  }
}

export function stopAutoAnalysis(): void {
  if (intervalId !== null) {
    clearInterval(intervalId);
    intervalId = null;
  }
  if (typeof document !== 'undefined') {
    document.removeEventListener('visibilitychange', handleVisibilityChange);
  }
  if (typeof window !== 'undefined') {
    window.removeEventListener('beforeunload', stopAutoAnalysis);
  }
}

function handleVisibilityChange(): void {
  if (document.hidden) {
    // Suspend: clear interval while tab is hidden
    if (intervalId !== null) {
      clearInterval(intervalId);
      intervalId = null;
    }
  } else {
    // Resume: restart interval when tab becomes visible
    if (intervalId === null) {
      intervalId = setInterval(() => {
        void runAutoAnalysis();
      }, AUTO_ANALYSIS_INTERVAL_MS);
    }
  }
}

/** Reset state — primarily for tests. */
export function resetAutoAnalysis(): void {
  stopAutoAnalysis();
  running = false;
  lastSnapshot = null;
  nextAutoMsgId = 10_000_000;
  lastPlayerInteractionTick = -Infinity;
  resetCrisisWarnings();
}

// ── Internal ──────────────────────────────────────────────────────────────────

async function runAutoAnalysis(): Promise<void> {
  if (running) return;
  if (!workerSendFn || !buildStateFn) return;
  if (isPausedFn && isPausedFn()) return;

  const state = buildStateFn();

  // Don't interrupt active conversations
  if (state.tick - lastPlayerInteractionTick < INTERACTION_COOLDOWN_TICKS) return;

  // Rate-limit: max 1 unread auto-insight at a time
  if (hasUnreadAutoInsight()) return;

  if (!hasMeaningfulChange(state)) return;

  running = true;
  try {
    let response: string;
    let isAlert: boolean;

    // Use formalized fallback chain to decide LLM vs heuristic path
    const tier = determineFallbackTier(hasApiKey(), isOverBudget(), false);

    if (tier === 'all_clear') {
      // LLM path — adapt query to dialogue stage (partner = independent observations)
      const stage = getDialogueStage();
      if (stage === 'dormant') {
        // Dormant Aria doesn't initiate auto-analysis
        lastSnapshot = buildSnapshot(state);
        return;
      }
      const baseQuery = buildAutoAnalysisQuery(state.ariaCanDirectResearch);
      const stageQuery = buildStageAwareAutoAnalysisQuery(baseQuery, stage);
      response = await askAdvisor(stageQuery, state);
      isAlert = response.startsWith('[Alert]');
    } else {
      // Tiers 1-3: heuristic fallback — no LLM needed
      const heuristic = generateHeuristicInsight(state);
      if (!heuristic) {
        // No noteworthy insight to report
        lastSnapshot = buildSnapshot(state);
        return;
      }
      response = heuristic.body;
      isAlert = heuristic.isAlert;
    }

    const subject = isAlert ? '[Alert] ARIA Briefing' : '[Periodic Review] ARIA Briefing';
    const priority = isAlert ? 'urgent' : 'normal';

    const msg: InboxMessage = {
      id: nextAutoMsgId++,
      factionId: null,
      senderName: 'ARIA',
      type: 'aria_auto',
      subject,
      body: response,
      priority,
      tick: 0, // will be set by worker tick context; 0 is acceptable for injected messages
      triaged: true,
      triageResult: isAlert ? 'urgent' : 'relevant',
      read: false,
    };

    workerSendFn({
      type: 'sim:inbox_inject',
      payload: { message: msg },
    });

    // Update snapshot after successful analysis
    lastSnapshot = buildSnapshot(state);
  } catch (err) {
    console.warn('[AriaAutoAnalysis] Analysis failed:', err);
  } finally {
    running = false;
  }
}

/** Check if the inbox already has an unread aria_auto message. */
function hasUnreadAutoInsight(): boolean {
  if (!getInboxSnapshotFn) return false;
  const snapshot = getInboxSnapshotFn();
  if (!snapshot) return false;
  return snapshot.messages.some((m) => m.type === 'aria_auto' && !m.read);
}

function buildSnapshot(state: GameStateSummary): StateSnapshot {
  const { iron, carbon, silicon, water } = state.resources;
  return {
    totalResources: iron + carbon + silicon + water,
    robotCount: state.fleet.total,
    discoveryCount: state.discoveries.length,
    crisisEligibleCount: state.megastructures.filter((m) => m.crisisEligible).length,
    hostileFactionCount: state.factionStandings.filter((f) => f.disposition <= -60).length,
  };
}

/** Returns true if game state has changed enough to warrant a new analysis. */
function hasMeaningfulChange(state: GameStateSummary): boolean {
  if (!lastSnapshot) return true; // Always run on first trigger

  const current = buildSnapshot(state);

  // New discovery
  if (current.discoveryCount > lastSnapshot.discoveryCount) return true;

  // Robot count changed
  if (current.robotCount !== lastSnapshot.robotCount) return true;

  // Resources changed by more than 10%
  const prevTotal = lastSnapshot.totalResources;
  if (prevTotal > 0) {
    const delta = Math.abs(current.totalResources - prevTotal) / prevTotal;
    if (delta > 0.1) return true;
  } else if (current.totalResources > 0) {
    return true;
  }

  // Megastructure became crisis-eligible
  if (current.crisisEligibleCount > lastSnapshot.crisisEligibleCount) return true;

  // Faction hostility changed
  if (current.hostileFactionCount !== lastSnapshot.hostileFactionCount) return true;

  return false;
}

// ── Heuristic Insights ────────────────────────────────────────────────────────

interface HeuristicResult {
  body: string;
  isAlert: boolean;
}

/** Tracks which megastructure stages we've already warned about (prevents spam). */
const notifiedCrisisWarnings = new Set<string>();

/** Reset crisis warning tracking (for tests and save/load). */
export function resetCrisisWarnings(): void {
  notifiedCrisisWarnings.clear();
}

/** Generate a rule-based insight from game state thresholds. No LLM needed. */
export function generateHeuristicInsight(state: GameStateSummary): HeuristicResult | null {
  const { resources, fleet, research, field } = state;

  // Highest priority: megastructure crisis imminent
  for (const mega of state.megastructures) {
    if (!mega.crisisEligible) continue;
    const key = `${mega.id}:${mega.activeStageIndex}`;
    if (notifiedCrisisWarnings.has(key)) continue;
    notifiedCrisisWarnings.add(key);
    return {
      body: `[Alert] Warning: ${mega.name} is approaching a critical stress point during "${mega.stageName}" construction. ` +
        `A ${mega.crisisTypeName} crisis could strike at any moment. ` +
        `Stockpile resolution materials now — you have limited time to prepare before construction is halted.`,
      isAlert: true,
    };
  }

  // Critical: very low resources
  const totalResources = resources.iron + resources.carbon + resources.silicon + resources.water;
  if (totalResources < 50 && fleet.total > 0) {
    const lowest = getLowestResource(resources);
    return {
      body: `[Alert] Resource stockpiles are critically low — ${lowest.name} at ${lowest.amount}. ` +
        `With ${fleet.total} robots deployed, extraction must be prioritized immediately.`,
      isAlert: true,
    };
  }

  // Faction hostility alert
  const hostileFactions = state.factionStandings.filter((f) => f.disposition <= -60);
  if (hostileFactions.length > 0) {
    const names = hostileFactions.map((f) => f.name).join(', ');
    const single = hostileFactions.length === 1;
    return {
      body: `[Alert] ${names} ${single ? 'has' : 'have'} turned hostile. ` +
        `${single ? 'Their' : 'Their'} disposition is at ${Math.round(hostileFactions[0].disposition)}. ` +
        `Consider diplomatic outreach or reinforcing operations near ${single ? 'their' : 'contested'} territory.`,
      isAlert: true,
    };
  }

  // Faction relationship opportunity
  const strongAllies = state.factionStandings.filter((f) => f.disposition >= 60);
  const worseningFactions = state.factionStandings.filter((f) => f.trend === 'worsening' && f.disposition > -60);

  // Alert: idle fleet
  const idleCount = fleet.byState['idle'] ?? 0;
  if (idleCount > 0 && idleCount >= fleet.total * 0.5 && fleet.total >= 3) {
    return {
      body: `[Alert] ${idleCount} of ${fleet.total} robots are idle. ` +
        `Consider assigning mining tasks or enabling auto-queue to keep the fleet productive.`,
      isAlert: true,
    };
  }

  // Alert: no active mining with asteroids available
  if (field.activeMining === 0 && field.totalAsteroids > 0 && fleet.total > 0) {
    return {
      body: `[Alert] No robots are currently mining despite ${field.totalAsteroids} asteroids in range. ` +
        `Fleet may need manual task assignment or auto-queue configuration.`,
      isAlert: true,
    };
  }

  // Research idle
  if (!research.activeNodeId && fleet.total >= 3) {
    return {
      body: `[Periodic Review] Research queue is idle — no active research project. ` +
        `Opening the Tech Tree (T) and selecting a research target would advance your capabilities.`,
      isAlert: false,
    };
  }

  // Fleet at capacity
  if (fleet.robotCap > 0 && fleet.total >= fleet.robotCap) {
    return {
      body: `[Periodic Review] Fleet is at capacity (${fleet.total}/${fleet.robotCap}). ` +
        `Building an Orbital Platform or additional infrastructure could expand your robot cap.`,
      isAlert: false,
    };
  }

  // Faction worsening trend
  if (worseningFactions.length > 0) {
    const worst = worseningFactions.reduce((a, b) => a.disposition < b.disposition ? a : b);
    return {
      body: `[Periodic Review] ${worst.name} relations are deteriorating (${worst.label}, ${Math.round(worst.disposition)}). ` +
        `Their disposition is trending downward. Consider reducing operations near their territory or initiating a trade.`,
      isAlert: false,
    };
  }

  // Faction alliance opportunity
  if (strongAllies.length > 0 && strongAllies.some((f) => f.trend === 'improving')) {
    const best = strongAllies.reduce((a, b) => a.disposition > b.disposition ? a : b);
    return {
      body: `[Periodic Review] Your standing with ${best.name} is strong (${best.label}, ${Math.round(best.disposition)}). ` +
        `Consider expanding operations near their territory to leverage this alliance.`,
      isAlert: false,
    };
  }

  // Resource surplus — routine update
  if (totalResources > 500) {
    return {
      body: `[Periodic Review] Operations nominal. Stockpiles healthy at ${Math.floor(totalResources)} total resources. ` +
        `${fleet.total} robots active, ${field.activeMining} currently mining.`,
      isAlert: false,
    };
  }

  // Generic status when nothing noteworthy
  if (fleet.total > 0) {
    return {
      body: `[Periodic Review] ${fleet.total} robots deployed, ${field.activeMining} mining across ${field.totalAsteroids} visible asteroids. ` +
        `Stockpiles: Iron ${resources.iron}, Carbon ${resources.carbon}, Silicon ${resources.silicon}, Water ${resources.water}.`,
      isAlert: false,
    };
  }

  return null;
}

function getLowestResource(resources: GameStateSummary['resources']): { name: string; amount: number } {
  const entries: Array<{ name: string; amount: number }> = [
    { name: 'Iron', amount: resources.iron },
    { name: 'Carbon', amount: resources.carbon },
    { name: 'Silicon', amount: resources.silicon },
    { name: 'Water', amount: resources.water },
  ];
  entries.sort((a, b) => a.amount - b.amount);
  return entries[0];
}
