import {
  BufferAttribute,
  BufferGeometry,
  Color,
  DynamicDrawUsage,
  IcosahedronGeometry,
  InstancedMesh,
  MeshStandardMaterial,
  Object3D,
  Points,
  Scene,
  ShaderMaterial,
  Vector3,
} from 'three';
import {
  ASTEROID_STRIDE,
  ASTEROID_OFF_EID,
  ASTEROID_OFF_X,
  ASTEROID_OFF_Y,
  ASTEROID_OFF_Z,
  ASTEROID_OFF_RADIUS,
  ASTEROID_OFF_TYPE,
  ASTEROID_OFF_ANOMALY_FLAG,
  ASTEROID_OFF_HUSK_FLAG,
  ASTEROID_OFF_CLUSTER_FLAG,
  ASTEROID_OFF_TRANSIT_FACTOR,
} from '../../sim/bufferLayout';

// Asteroid type colors
const TYPE_COLORS: Record<number, Color> = {
  0: new Color(0.3, 0.25, 0.2), // Carbonaceous - dark brown
  1: new Color(0.5, 0.45, 0.4), // Silicate - grey-tan
  2: new Color(0.7, 0.65, 0.55), // Metallic - bright silvery
  3: new Color(0.4, 0.2, 0.5), // Exotic - purple-ish
};

const TYPE_EMISSIVE: Record<number, number> = {
  0: 0.0,
  1: 0.0,
  2: 0.15, // Metallic asteroids have a subtle glow
  3: 0.25, // Exotic asteroids glow more
};

const MAX_INSTANCES = 5000;

// LOD hysteresis thresholds — squared to avoid Math.sqrt per asteroid per frame.
// 10% band around nominal 500 / 3000 unit boundaries.
const LOD_01_UPGRADE_SQ = 450 * 450;       // LOD1 → LOD0: enter close range
const LOD_01_DOWNGRADE_SQ = 550 * 550;     // LOD0 → LOD1: leave close range
const LOD_12_UPGRADE_SQ = 2700 * 2700;     // LOD2 → LOD1: enter mid range
const LOD_12_DOWNGRADE_SQ = 3300 * 3300;   // LOD1 → LOD2: leave mid range

// Crossfade transition zone for LOD1↔LOD2 (smooth blend, no pop-in).
// 15% overlap zone centered on the 3000 unit boundary.
/** @internal exported for testing */
export const CROSSFADE_12_INNER_SQ = 2700 * 2700; // mesh starts fading out
/** @internal exported for testing */
export const CROSSFADE_12_OUTER_SQ = 3300 * 3300; // mesh fully gone, points fully opaque
// Pre-computed for linear interpolation in squared-distance space
const CROSSFADE_12_RANGE = CROSSFADE_12_OUTER_SQ - CROSSFADE_12_INNER_SQ;

/**
 * Pure LOD computation with hysteresis — extracted for testability.
 * Returns the LOD tier (0, 1, or 2) given squared distance and previous LOD.
 */
export function computeLOD(distSq: number, prevLOD: number | undefined): number {
  if (prevLOD === undefined) {
    return distSq < 500 * 500 ? 0 : distSq < 3000 * 3000 ? 1 : 2;
  } else if (prevLOD === 0) {
    return distSq < LOD_01_DOWNGRADE_SQ ? 0 : distSq < LOD_12_DOWNGRADE_SQ ? 1 : 2;
  } else if (prevLOD === 1) {
    return distSq < LOD_01_UPGRADE_SQ ? 0 : distSq < LOD_12_DOWNGRADE_SQ ? 1 : 2;
  } else {
    return distSq >= LOD_12_UPGRADE_SQ ? 2 : distSq >= LOD_01_UPGRADE_SQ ? 1 : 0;
  }
}

/**
 * Compute crossfade blend factor for the LOD1↔LOD2 transition zone.
 * Returns 0 (fully mesh) to 1 (fully points), or -1 if outside the zone.
 */
export function computeCrossfadeBlend(distSq: number): number {
  if (distSq < CROSSFADE_12_INNER_SQ || distSq > CROSSFADE_12_OUTER_SQ) return -1;
  return Math.min(1, Math.max(0, (distSq - CROSSFADE_12_INNER_SQ) / CROSSFADE_12_RANGE));
}

// Point sprite shader for LOD 2 (far asteroids)
const LOD2_VERT = /* glsl */ `
  attribute float aPointSize;
  attribute vec3 aColor;
  varying vec3 vColor;
  void main() {
    vColor = aColor;
    vec4 mvPosition = modelViewMatrix * vec4(position, 1.0);
    gl_PointSize = max(1.5, aPointSize * (800.0 / -mvPosition.z));
    gl_Position = projectionMatrix * mvPosition;
  }
`;

const LOD2_FRAG = /* glsl */ `
  varying vec3 vColor;
  void main() {
    vec2 cxy = 2.0 * gl_PointCoord - 1.0;
    float r = dot(cxy, cxy);
    if (r > 1.0) discard;
    float alpha = 1.0 - smoothstep(0.6, 1.0, r);
    gl_FragColor = vec4(vColor, alpha);
  }
`;

interface MeshBucket {
  kind: 'mesh';
  mesh: InstancedMesh;
  count: number;
  dummy: Object3D;
  prevCount: number;
  prevMatrixHash: number;
  prevColorHash: number;
}

interface PointBucket {
  kind: 'points';
  points: Points;
  positions: Float32Array;
  colors: Float32Array;
  sizes: Float32Array;
  posAttr: BufferAttribute;
  colorAttr: BufferAttribute;
  sizeAttr: BufferAttribute;
  count: number;
  prevCount: number;
  prevPosHash: number;
}

type AsteroidBucket = MeshBucket | PointBucket;

export class InstancedAsteroidRenderer {
  private scene: Scene;
  private buckets: Map<string, AsteroidBucket> = new Map();
  // keyed by `${type}_${lod}` for LOD 0/1, or `lod2_${type}` for point buckets
  private meshGeometries: Map<string, BufferGeometry> = new Map(); // `${type}_${lod}`
  private materials: Map<number, MeshStandardMaterial> = new Map();
  private lod2Material: ShaderMaterial;

  // Per-entity LOD state for hysteresis
  private entityLODs: Map<number, number> = new Map();
  // Entities seen in current frame — used to prune stale entityLODs entries
  private seenEntities: Set<number> = new Set();

  // Track known husks to detect newly depleted asteroids
  private knownHusks: Set<number> = new Set();
  // Newly depleted asteroid positions from the latest frame
  private newDepletions: { x: number; y: number; z: number; radius: number }[] = [];

  // Region color bias — set by BeltRegionRenderer each frame
  private regionBias = new Color(0.5, 0.45, 0.4);
  private regionBiasStrength = 0.0;

  // XENOAWARE predicted anomaly asteroid EIDs — set by culture state handler
  private predictedAnomalyIds: Set<number> = new Set();

  // Pre-allocated working color to avoid per-instance allocations
  private static readonly _workColor = new Color();
  // Transit window tint colors
  private static readonly _transitGreen = new Color(0.2, 0.8, 0.3);
  private static readonly _transitRed = new Color(0.8, 0.2, 0.15);

  constructor(scene: Scene) {
    this.scene = scene;
    this.lod2Material = new ShaderMaterial({
      vertexShader: LOD2_VERT,
      fragmentShader: LOD2_FRAG,
      transparent: true,
      depthWrite: false,
    });
    this.createGeometries();
    this.createMaterials();
  }

  private createGeometries(): void {
    for (let type = 0; type < 4; type++) {
      // LOD 1 (mid, 500-3000): low-poly icosahedron, ~20 triangles
      const lod1 = new IcosahedronGeometry(1, 0);
      this.meshGeometries.set(`${type}_1`, lod1);

      // LOD 0 (close, <500): high-detail displaced sphere, ~320 triangles
      const lod0 = new IcosahedronGeometry(1, 2);
      const positions = lod0.attributes.position;
      for (let i = 0; i < positions.count; i++) {
        // Per-vertex noise using deterministic seed from type + vertex index
        const offset = 0.85 + Math.sin(i * 17.3 + type * 5.7) * 0.15;
        positions.setX(i, positions.getX(i) * offset);
        positions.setY(i, positions.getY(i) * offset);
        positions.setZ(i, positions.getZ(i) * offset);
      }
      lod0.computeVertexNormals();
      this.meshGeometries.set(`${type}_0`, lod0);
    }
    // LOD 2 (far, >3000): point sprites — geometry created lazily per bucket
  }

  private createMaterials(): void {
    for (let type = 0; type < 4; type++) {
      const color = TYPE_COLORS[type] || new Color(0.5, 0.5, 0.5);
      const emissiveIntensity = TYPE_EMISSIVE[type] || 0;
      const mat = new MeshStandardMaterial({
        color,
        roughness: type === 2 ? 0.3 : 0.8,
        metalness: type === 2 ? 0.7 : 0.1,
        emissive: color.clone().multiplyScalar(emissiveIntensity),
        emissiveIntensity,
        flatShading: true,
      });
      this.materials.set(type, mat);
    }
  }

  private getOrCreateMeshBucket(type: number, lod: number): MeshBucket {
    const key = `${type}_${lod}`;
    let bucket = this.buckets.get(key);
    if (!bucket) {
      const geo = this.meshGeometries.get(key)!;
      const mat = this.materials.get(type)!;
      const mesh = new InstancedMesh(geo, mat, MAX_INSTANCES);
      mesh.count = 0;
      mesh.frustumCulled = false;
      this.scene.add(mesh);
      bucket = { kind: 'mesh', mesh, count: 0, dummy: new Object3D(), prevCount: -1, prevMatrixHash: -1, prevColorHash: -1 };
      this.buckets.set(key, bucket);
    }
    return bucket as MeshBucket;
  }

  private getOrCreatePointBucket(type: number): PointBucket {
    const key = `lod2_${type}`;
    let bucket = this.buckets.get(key);
    if (!bucket) {
      const geo = new BufferGeometry();
      const positions = new Float32Array(MAX_INSTANCES * 3);
      const colors = new Float32Array(MAX_INSTANCES * 3);
      const sizes = new Float32Array(MAX_INSTANCES);

      const posAttr = new BufferAttribute(positions, 3);
      const colorAttr = new BufferAttribute(colors, 3);
      const sizeAttr = new BufferAttribute(sizes, 1);
      posAttr.usage = DynamicDrawUsage;
      colorAttr.usage = DynamicDrawUsage;
      sizeAttr.usage = DynamicDrawUsage;

      geo.setAttribute('position', posAttr);
      geo.setAttribute('aColor', colorAttr);
      geo.setAttribute('aPointSize', sizeAttr);

      const points = new Points(geo, this.lod2Material);
      points.frustumCulled = false;
      this.scene.add(points);

      bucket = {
        kind: 'points',
        points,
        positions,
        colors,
        sizes,
        posAttr,
        colorAttr,
        sizeAttr,
        count: 0,
        prevCount: -1,
        prevPosHash: -1,
      };
      this.buckets.set(key, bucket);
    }
    return bucket as PointBucket;
  }

  /** Set the per-region color bias from BeltRegionRenderer. */
  setRegionBias(color: Color, strength: number): void {
    this.regionBias.copy(color);
    this.regionBiasStrength = strength;
  }

  /** XENOAWARE: update the set of asteroid EIDs with predicted anomalies. */
  setPredictedAnomalyIds(ids: number[]): void {
    this.predictedAnomalyIds = new Set(ids);
  }

  /**
   * Compute LOD tier with hysteresis to prevent single-frame geometry pop.
   * Takes distSq (squared distance) to avoid Math.sqrt per asteroid per frame.
   * 10% band around nominal thresholds (500, 3000 units).
   */
  private computeLODSq(distSq: number, entityId: number): number {
    const prev = this.entityLODs.get(entityId);
    const lod = computeLOD(distSq, prev);
    this.entityLODs.set(entityId, lod);
    return lod;
  }

  /**
   * FNV-1a hash over Float32Array range via Uint32 reinterpret view.
   * No data copy — just reinterprets the buffer. Used to detect GPU upload dirty state.
   */
  private static hashF32(arr: Float32Array, count: number): number {
    const u32 = new Uint32Array(arr.buffer, arr.byteOffset, count);
    let h = 2166136261 >>> 0;
    for (let i = 0; i < count; i++) {
      h = Math.imul(h ^ u32[i], 16777619) >>> 0;
    }
    return h;
  }

  /**
   * Update all asteroid instances from simulation data.
   * asteroidBuffer: Float64Array with stride ASTEROID_STRIDE: [eid, x, y, z, radius, typeEnum, anomalyFlag, huskFlag]
   */
  updateFromBuffer(
    asteroidBuffer: Float64Array,
    asteroidCount: number,
    cameraPosition: Vector3,
  ): void {
    // Reset all bucket counts
    for (const bucket of this.buckets.values()) {
      bucket.count = 0;
    }
    this.seenEntities.clear();
    this.newDepletions.length = 0;

    for (let i = 0; i < asteroidCount; i++) {
      const offset = i * ASTEROID_STRIDE;
      const eid = asteroidBuffer[offset + ASTEROID_OFF_EID];
      const x = asteroidBuffer[offset + ASTEROID_OFF_X];
      const y = asteroidBuffer[offset + ASTEROID_OFF_Y];
      const z = asteroidBuffer[offset + ASTEROID_OFF_Z];
      const radius = asteroidBuffer[offset + ASTEROID_OFF_RADIUS];
      const type = asteroidBuffer[offset + ASTEROID_OFF_TYPE];
      const anomaly = asteroidBuffer[offset + ASTEROID_OFF_ANOMALY_FLAG];
      const isHusk = asteroidBuffer[offset + ASTEROID_OFF_HUSK_FLAG] > 0;
      const isCluster = asteroidBuffer[offset + ASTEROID_OFF_CLUSTER_FLAG] > 0;
      const transitFactor = asteroidBuffer[offset + ASTEROID_OFF_TRANSIT_FACTOR];

      // Detect newly depleted asteroids
      if (isHusk && !this.knownHusks.has(eid)) {
        this.knownHusks.add(eid);
        this.newDepletions.push({ x, y, z, radius });
      }

      // Simple distance-based culling
      const dx = x - cameraPosition.x;
      const dy = y - cameraPosition.y;
      const dz = z - cameraPosition.z;
      const distSq = dx * dx + dy * dy + dz * dz;
      if (distSq > 100000 * 100000) continue; // cull far asteroids

      this.seenEntities.add(eid);
      const lod = this.computeLODSq(distSq, eid);

      // Compute color: cluster = golden, husk = dark grey, predicted anomaly = teal, anomaly = purple, otherwise type + region bias
      const wc = InstancedAsteroidRenderer._workColor;
      if (isCluster) {
        // Golden shimmer for transient cluster asteroids
        wc.setRGB(0.95, 0.75, 0.2);
      } else if (isHusk) {
        wc.setRGB(0.15, 0.14, 0.13);
      } else if (this.predictedAnomalyIds.has(eid) && anomaly > 0) {
        // XENOAWARE: teal shimmer for predicted undiscovered anomalies
        wc.setRGB(0.1, 0.8, 0.7);
      } else if (anomaly > 0) {
        wc.setRGB(0.5, 0.2, 0.8);
      } else {
        wc.copy(TYPE_COLORS[type] ?? new Color(0.5, 0.5, 0.5));
        if (this.regionBiasStrength > 0) {
          wc.lerp(this.regionBias, this.regionBiasStrength * 0.25);
        }
        // Transit window tint: green when in window (factor→1), red when out (factor→0)
        if (transitFactor >= 0.8) {
          // Good window — subtle green tint
          wc.lerp(InstancedAsteroidRenderer._transitGreen, 0.25);
        } else if (transitFactor <= 0.3) {
          // Bad window — subtle red tint
          wc.lerp(InstancedAsteroidRenderer._transitRed, 0.2 * (1 - transitFactor / 0.3));
        }
      }

      // Crossfade zone: dual-render in both mesh (LOD1) and points during transition
      const inCrossfade12 = distSq >= CROSSFADE_12_INNER_SQ && distSq <= CROSSFADE_12_OUTER_SQ;
      // blendToPoints: 0 = fully mesh, 1 = fully points
      const blendToPoints = inCrossfade12
        ? Math.min(1, Math.max(0, (distSq - CROSSFADE_12_INNER_SQ) / CROSSFADE_12_RANGE))
        : 0;

      if (lod === 2 || inCrossfade12) {
        // Far or crossfade: point sprite (fade in during crossfade)
        const bucket = this.getOrCreatePointBucket(type);
        if (bucket.count < MAX_INSTANCES) {
          const idx3 = bucket.count * 3;
          bucket.positions[idx3] = x;
          bucket.positions[idx3 + 1] = y;
          bucket.positions[idx3 + 2] = z;
          // During crossfade, dim the point color by blend factor (simulates alpha fade-in)
          const ptAlpha = inCrossfade12 ? blendToPoints : 1;
          bucket.colors[idx3] = wc.r * ptAlpha;
          bucket.colors[idx3 + 1] = wc.g * ptAlpha;
          bucket.colors[idx3 + 2] = wc.b * ptAlpha;
          bucket.sizes[bucket.count] = radius;
          bucket.count++;
        }
      }

      if (lod <= 1 || inCrossfade12) {
        // Close (LOD0), mid (LOD1), or crossfade: instanced mesh
        const meshLod = lod <= 1 ? lod : 1; // crossfade always uses LOD1 mesh
        const bucket = this.getOrCreateMeshBucket(type, meshLod);
        if (bucket.count < MAX_INSTANCES) {
          // During crossfade, shrink mesh toward point (scale fade-out)
          const meshScale = inCrossfade12 ? radius * (1 - blendToPoints) : radius;

          bucket.dummy.position.set(x, y, z);
          bucket.dummy.scale.setScalar(meshScale);
          // Deterministic rotation from position
          bucket.dummy.rotation.set(x * 0.01, y * 0.01, z * 0.01);
          bucket.dummy.updateMatrix();

          bucket.mesh.setMatrixAt(bucket.count, bucket.dummy.matrix);
          bucket.mesh.setColorAt(bucket.count, wc);
          bucket.count++;
        }
      }
    }

    // Prune stale entityLODs and knownHusks entries for destroyed/culled asteroids
    if (this.entityLODs.size > this.seenEntities.size + 100) {
      for (const eid of this.entityLODs.keys()) {
        if (!this.seenEntities.has(eid)) {
          this.entityLODs.delete(eid);
        }
      }
      for (const eid of this.knownHusks) {
        if (!this.seenEntities.has(eid)) {
          this.knownHusks.delete(eid);
        }
      }
    }

    // Upload to GPU — only when bucket data has changed (dirty flag via content hash)
    for (const bucket of this.buckets.values()) {
      if (bucket.kind === 'mesh') {
        bucket.mesh.count = bucket.count;
        if (bucket.count > 0) {
          const matArr = bucket.mesh.instanceMatrix.array as Float32Array;
          const matHash = InstancedAsteroidRenderer.hashF32(matArr, bucket.count * 16);
          const countChanged = bucket.count !== bucket.prevCount;
          if (countChanged || matHash !== bucket.prevMatrixHash) {
            bucket.mesh.instanceMatrix.needsUpdate = true;
            bucket.prevMatrixHash = matHash;
          }
          if (bucket.mesh.instanceColor) {
            const colArr = bucket.mesh.instanceColor.array as Float32Array;
            const colHash = InstancedAsteroidRenderer.hashF32(colArr, bucket.count * 3);
            if (countChanged || colHash !== bucket.prevColorHash) {
              bucket.mesh.instanceColor.needsUpdate = true;
              bucket.prevColorHash = colHash;
            }
          }
          bucket.prevCount = bucket.count;
        }
      } else {
        // Point bucket: update draw range and mark attributes dirty only if data changed
        bucket.points.geometry.setDrawRange(0, bucket.count);
        if (bucket.count > 0) {
          const posHash = InstancedAsteroidRenderer.hashF32(bucket.positions, bucket.count * 3);
          if (bucket.count !== bucket.prevCount || posHash !== bucket.prevPosHash) {
            bucket.posAttr.needsUpdate = true;
            bucket.colorAttr.needsUpdate = true;
            bucket.sizeAttr.needsUpdate = true;
            bucket.prevPosHash = posHash;
          }
          bucket.prevCount = bucket.count;
        }
      }
    }
  }

  /** Positions of asteroids that became husks this frame. Consumed by DepletionParticles. */
  getNewDepletions(): ReadonlyArray<{ x: number; y: number; z: number; radius: number }> {
    return this.newDepletions;
  }

  dispose(): void {
    for (const bucket of this.buckets.values()) {
      if (bucket.kind === 'mesh') {
        this.scene.remove(bucket.mesh);
        bucket.mesh.dispose();
      } else {
        this.scene.remove(bucket.points);
        bucket.points.geometry.dispose();
      }
    }
    for (const geo of this.meshGeometries.values()) geo.dispose();
    for (const mat of this.materials.values()) mat.dispose();
    this.lod2Material.dispose();
    this.buckets.clear();
    this.entityLODs.clear();
  }
}
