/**
 * BuildingRenderer — Three.js visuals for base buildings.
 *
 * Each building type gets a distinct geometry. Construction stages:
 *   PLANNED (0):            translucent wireframe outline at the site
 *   UNDER_CONSTRUCTION (1): solid geometry scales from 0→1 as progress advances
 *   COMPLETE (2):           full geometry with emissive glow
 *
 * Manages a Map of building id → Three.js Group, creating/updating/disposing as needed.
 */

import {
  BoxGeometry,
  CylinderGeometry,
  Group,
  Material,
  Mesh,
  MeshStandardMaterial,
  Scene,
  SphereGeometry,
  TorusGeometry,
} from 'three';
import type { SerializedBuilding } from '../shared/buildingTypes';
import { BUILDING_TYPES, CONSTRUCTION_STATE } from '../shared/buildingTypes';

// ── Per-type geometry builders ───────────────────────────────────────────────

interface BuildingVisual {
  group: Group;
  solidMat: MeshStandardMaterial;
}

function createFactoryVisual(): BuildingVisual {
  const group = new Group();
  const mat = new MeshStandardMaterial({
    color: 0xf59e0b,
    emissive: 0xd97706,
    emissiveIntensity: 0.6,
    metalness: 0.85,
    roughness: 0.2,
  });
  // Main body — flat box
  const body = new Mesh(new BoxGeometry(8, 5, 8), mat);
  body.position.y = 2.5;
  group.add(body);
  // Chimney
  const chimney = new Mesh(new CylinderGeometry(1, 1.5, 4, 8), mat);
  chimney.position.set(2, 7, 2);
  group.add(chimney);
  return { group, solidMat: mat };
}

function createTurretVisual(): BuildingVisual {
  const group = new Group();
  const mat = new MeshStandardMaterial({
    color: 0xef4444,
    emissive: 0x991b1b,
    emissiveIntensity: 0.5,
    metalness: 0.9,
    roughness: 0.15,
  });
  // Base cylinder
  const base = new Mesh(new CylinderGeometry(3, 4, 3, 8), mat);
  base.position.y = 1.5;
  group.add(base);
  // Barrel
  const barrel = new Mesh(new CylinderGeometry(0.5, 0.5, 6, 6), mat);
  barrel.rotation.z = Math.PI / 2;
  barrel.position.set(3, 4, 0);
  group.add(barrel);
  return { group, solidMat: mat };
}

function createSolarPanelVisual(): BuildingVisual {
  const group = new Group();
  const mat = new MeshStandardMaterial({
    color: 0x3b82f6,
    emissive: 0x1d4ed8,
    emissiveIntensity: 0.7,
    metalness: 0.6,
    roughness: 0.3,
  });
  // Panel — flat box
  const panel = new Mesh(new BoxGeometry(10, 0.3, 6), mat);
  panel.position.y = 5;
  panel.rotation.x = -0.3; // tilted
  group.add(panel);
  // Support pole
  const pole = new Mesh(new CylinderGeometry(0.4, 0.4, 5, 6), mat);
  pole.position.y = 2.5;
  group.add(pole);
  return { group, solidMat: mat };
}

function createReactorVisual(): BuildingVisual {
  const group = new Group();
  const mat = new MeshStandardMaterial({
    color: 0x10b981,
    emissive: 0x059669,
    emissiveIntensity: 0.8,
    metalness: 0.8,
    roughness: 0.2,
  });
  // Core sphere
  const core = new Mesh(new SphereGeometry(4, 12, 12), mat);
  core.position.y = 5;
  group.add(core);
  // Containment ring
  const ring = new Mesh(new TorusGeometry(5, 0.8, 8, 24), mat);
  ring.position.y = 5;
  ring.rotation.x = Math.PI / 2;
  group.add(ring);
  return { group, solidMat: mat };
}

function createGenericVisual(): BuildingVisual {
  const group = new Group();
  const mat = new MeshStandardMaterial({
    color: 0x94a3b8,
    emissive: 0x475569,
    emissiveIntensity: 0.4,
    metalness: 0.7,
    roughness: 0.3,
  });
  const body = new Mesh(new BoxGeometry(6, 4, 6), mat);
  body.position.y = 2;
  group.add(body);
  return { group, solidMat: mat };
}

function createVisualForType(buildingType: number): BuildingVisual {
  switch (buildingType) {
    case BUILDING_TYPES.FACTORY:
      return createFactoryVisual();
    case BUILDING_TYPES.TURRET:
      return createTurretVisual();
    case BUILDING_TYPES.SOLAR_PANEL:
    case BUILDING_TYPES.SOLAR_FURNACE:
      return createSolarPanelVisual();
    case BUILDING_TYPES.FISSION_REACTOR:
    case BUILDING_TYPES.FUSION_REACTOR:
    case BUILDING_TYPES.RTG_MODULE:
      return createReactorVisual();
    default:
      return createGenericVisual();
  }
}

// ── BuildingRenderer class ──────────────────────────────────────────────────

interface BuildingEntry {
  id: number;
  visual: BuildingVisual;
  constructionState: number;
}

export class BuildingRenderer {
  private scene: Scene;
  private entries: Map<number, BuildingEntry> = new Map();

  constructor(scene: Scene) {
    this.scene = scene;
  }

  /**
   * Sync renderer state with latest serialized buildings from the sim.
   * Creates new visuals, updates construction progress, removes destroyed buildings.
   */
  update(buildings: SerializedBuilding[], _time: number): void {
    const currentIds = new Set<number>();

    for (const b of buildings) {
      currentIds.add(b.id);
      let entry = this.entries.get(b.id);

      if (!entry) {
        // Create new building visual
        const visual = createVisualForType(b.type);
        visual.group.position.set(b.worldX, b.worldY, b.worldZ);
        this.scene.add(visual.group);
        entry = { id: b.id, visual, constructionState: -1 };
        this.entries.set(b.id, entry);
      }

      // Update construction state visuals
      const { group, solidMat } = entry.visual;

      if (b.constructionState === CONSTRUCTION_STATE.PLANNED) {
        // Wireframe translucent ghost
        solidMat.wireframe = true;
        solidMat.opacity = 0.3;
        solidMat.transparent = true;
        solidMat.emissiveIntensity = 0.2;
        group.scale.setScalar(1);
      } else if (b.constructionState === CONSTRUCTION_STATE.UNDER_CONSTRUCTION) {
        // Solid, scaling up with progress
        solidMat.wireframe = false;
        solidMat.opacity = 0.6 + b.constructionProgress * 0.4;
        solidMat.transparent = b.constructionProgress < 1;
        solidMat.emissiveIntensity = 0.3 + b.constructionProgress * 0.3;
        const scale = 0.3 + b.constructionProgress * 0.7;
        group.scale.setScalar(scale);
      } else {
        // Complete — full solid with glow
        solidMat.wireframe = false;
        solidMat.opacity = 1;
        solidMat.transparent = false;
        solidMat.emissiveIntensity = 0.8;
        group.scale.setScalar(1);
      }

      // Apply material to all meshes in the group (the solidMat is shared per building)
      group.traverse((obj) => {
        const mesh = obj as Mesh;
        if (mesh.isMesh) {
          mesh.material = solidMat;
        }
      });

      entry.constructionState = b.constructionState;
    }

    // Remove buildings that no longer exist
    for (const [id, entry] of this.entries) {
      if (!currentIds.has(id)) {
        this._disposeEntry(entry);
        this.entries.delete(id);
      }
    }
  }

  private _disposeEntry(entry: BuildingEntry): void {
    const { group, solidMat } = entry.visual;
    group.traverse((obj) => {
      const mesh = obj as Mesh;
      if (mesh.isMesh) {
        mesh.geometry.dispose();
      }
    });
    solidMat.dispose();
    group.parent?.remove(group);
  }

  dispose(): void {
    for (const entry of this.entries.values()) {
      this._disposeEntry(entry);
    }
    this.entries.clear();
  }
}
