function renderTradeData(trade: NonNullable<InboxMessage['tradeData']>): string {
  const offering = Object.entries(trade.offering).map(([r, n]) => `${n} ${r}`).join(', ');
  const requesting = Object.entries(trade.requesting).map(([r, n]) => `${n} ${r}`).join(', ');
  return `
    <div style="margin-top:6px; padding:6px; background:rgba(30,41,59,0.3); border-radius:4px; font-size:10px;">
      <div style="color:#86efac;">Offering: ${escapeHtml(offering)}</div>
      <div style="color:#fca5a5;">Requesting: ${escapeHtml(requesting)}</div>
      ${trade.hiddenClause ? `<div style="color:#f97316; margin-top:4px;">\u26a0 Hidden clause detected</div>` : ''}
    </div>
  `;
}

function filterMessages(messages: InboxMessage[]): InboxMessage[] {
  switch (activeFilter) {
    case 'urgent': return messages.filter((m) => m.triageResult === 'urgent');
    case 'relevant': return messages.filter((m) => m.triageResult === 'relevant');
    case 'spam': return messages.filter((m) => m.triageResult === 'spam');
    case 'unread': return messages.filter((m) => !m.read);
    default: return messages;
  }
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

