/**
 * Loading screen controller.
 * The #loading-screen element is rendered in index.html so it appears
 * immediately (< 100ms) without waiting for JS to execute.
 * This module advances the progress stages and fades out when done.
 */

const STAGES = [
  { label: 'Initializing renderer', pct: 20 },
  { label: 'Generating asteroid field', pct: 60 },
  { label: 'Starting simulation', pct: 90 },
] as const;

export type LoadingStage = 0 | 1 | 2;

let stageEl: HTMLElement | null = null;
let barEl: HTMLElement | null = null;
let screenEl: HTMLElement | null = null;

function getEls(): void {
  if (!screenEl) screenEl = document.getElementById('loading-screen');
  if (!stageEl) stageEl = document.getElementById('loading-stage');
  if (!barEl) barEl = document.getElementById('loading-bar-fill');
}

/** Advance the visible loading stage (0 = renderer, 1 = asteroid field, 2 = simulation). */
export function setLoadingStage(stage: LoadingStage): void {
  getEls();
  const s = STAGES[stage];
  if (stageEl) stageEl.textContent = s.label;
  if (barEl) barEl.style.width = `${s.pct}%`;
}

/**
 * Fade out and remove the loading screen.
 * Call this when the game is ready to show (title screen or first frame).
 */
export function hideLoadingScreen(): void {
  getEls();
  if (!screenEl) return;
  // Fill bar to 100% before fading
  if (barEl) barEl.style.width = '100%';
  // Short delay so the 100% fill is visible before fade
  setTimeout(() => {
    if (!screenEl) return;
    screenEl.classList.add('fade-out');
    screenEl.addEventListener('transitionend', () => screenEl?.remove(), { once: true });
  }, 200);
}
