/**
 * Belt Echoes — Echo Delivery Loop
 *
 * Polls the Folkfork Echo API on a 10-20 minute interval of active play,
 * then queues intercepted transmissions into the ARIA panel as proactive
 * broadcasts. Respects the Belt Echoes settings toggle and progression
 * gating.
 *
 * The delivery loop is driven by game ticks (not wall clock) so it only
 * advances during active play and pauses when the game is paused.
 */

import { getProgressionStage } from './progressionStage';
import { fillTemplate, randomSector, randomDelay, getTemplatesForStage } from './echoTemplates';
import { getGameSettings } from '../ui/settingsPanel';

/** Folkfork Echo API response shape. */
export interface EchoApiResponse {
  milestoneType: string;
  sector?: string;
  delayHours?: number;
}

/** Minimum interval between polls in game ticks (10 min = 36000 ticks at 60 tps). */
const MIN_POLL_INTERVAL_TICKS = 36_000;
/** Maximum interval between polls in game ticks (20 min = 72000 ticks at 60 tps). */
const MAX_POLL_INTERVAL_TICKS = 72_000;

/** State for the delivery loop. */
let lastPollTick = 0;
let nextPollInterval = randomInterval();
let pendingEcho: string | null = null;
let ariaDialogueActive = false;

/** Callback to display an echo in the ARIA panel. Injected at init time. */
let displayCallback: ((message: string) => void) | null = null;

/** Folkfork API base URL — null until configured. */
let apiBaseUrl: string | null = null;

function randomInterval(): number {
  return MIN_POLL_INTERVAL_TICKS + Math.floor(Math.random() * (MAX_POLL_INTERVAL_TICKS - MIN_POLL_INTERVAL_TICKS));
}

/**
 * Initialise the echo delivery loop.
 *
 * @param onDisplay — called when an echo should be shown in the ARIA panel
 * @param folkforkUrl — base URL for the Folkfork Echo API (optional; omit to use local templates only)
 */
export function initEchoDelivery(
  onDisplay: (message: string) => void,
  folkforkUrl?: string,
): void {
  displayCallback = onDisplay;
  apiBaseUrl = folkforkUrl ?? null;
}

/**
 * Notify the delivery loop whether ARIA is currently displaying dialogue.
 * When active, echo delivery is deferred until dialogue completes.
 */
export function setAriaDialogueActive(active: boolean): void {
  ariaDialogueActive = active;
  // If dialogue just ended and we have a pending echo, deliver it now
  if (!active && pendingEcho && displayCallback) {
    displayCallback(pendingEcho);
    pendingEcho = null;
  }
}

/**
 * Tick the echo delivery loop. Call this once per game tick from the
 * main thread frame handler.
 *
 * @param currentTick — current simulation tick
 * @param unlockedMask — tech tree bitmask from latest sim state
 */
export function tickEchoDelivery(currentTick: number, unlockedMask: bigint): void {
  // Bail if disabled in settings
  if (!getGameSettings().beltEchoesEnabled) return;
  if (!displayCallback) return;

  // Check if it's time to poll
  if (currentTick - lastPollTick < nextPollInterval) return;

  lastPollTick = currentTick;
  nextPollInterval = randomInterval();

  const stage = getProgressionStage(unlockedMask);

  if (apiBaseUrl) {
    // Poll the Folkfork Echo API
    void fetchEcho(apiBaseUrl, stage).then((message) => {
      if (message) deliverOrQueue(message);
    });
  } else {
    // Fallback: pick a random local template for the current stage
    const message = pickLocalEcho(stage);
    if (message) deliverOrQueue(message);
  }
}

function deliverOrQueue(message: string): void {
  if (ariaDialogueActive) {
    // Queue — will be delivered when dialogue ends
    pendingEcho = message;
  } else if (displayCallback) {
    displayCallback(message);
    pendingEcho = null;
  }
}

async function fetchEcho(baseUrl: string, maxStage: number): Promise<string | null> {
  try {
    const url = `${baseUrl}/api/echoes/cotb?maxProgressionStage=${maxStage}`;
    const res = await fetch(url, { signal: AbortSignal.timeout(5000) });
    if (!res.ok) return null;
    const data: EchoApiResponse[] = await res.json();
    if (!data || data.length === 0) return null;

    // Pick the first echo and format it
    const echo = data[0];
    const sector = echo.sector ?? randomSector();
    const delay = echo.delayHours ?? randomDelay();

    // Find a matching local template to format with, or use a generic wrapper
    const templates = getTemplatesForStage(maxStage);
    const matching = templates.find((t) => t.milestoneType === echo.milestoneType);
    if (matching && matching.templates.length > 0) {
      const template = matching.templates[Math.floor(Math.random() * matching.templates.length)];
      return fillTemplate(template, sector, delay);
    }

    // Generic fallback for unknown milestone types
    return `Signal intercepted from Sector ${sector}. Logged ${delay}h ago. Origin: unknown colony. Event classification: ${echo.milestoneType.replace(/_/g, ' ')}.`;
  } catch {
    // Network errors are expected (offline play, API not deployed yet)
    return null;
  }
}

function pickLocalEcho(stage: number): string | null {
  const templates = getTemplatesForStage(stage);
  if (templates.length === 0) return null;

  // Pick a random template group, then a random template within it
  const group = templates[Math.floor(Math.random() * templates.length)];
  const template = group.templates[Math.floor(Math.random() * group.templates.length)];
  return fillTemplate(template, randomSector(), randomDelay());
}

/** Serializable snapshot of the delivery loop state. */
export interface SerializedBeltEchoesState {
  lastPollTick: number;
  nextPollInterval: number;
  pendingEcho: string | null;
}

/** Capture current delivery loop state for save. */
export function getEchoDeliveryState(): SerializedBeltEchoesState {
  return { lastPollTick, nextPollInterval, pendingEcho };
}

/**
 * Restore delivery loop state from a save.
 * Preserves displayCallback and apiBaseUrl (set at init time, not serialized).
 */
export function restoreEchoDeliveryState(state: SerializedBeltEchoesState): void {
  lastPollTick = state.lastPollTick;
  nextPollInterval = state.nextPollInterval;
  pendingEcho = state.pendingEcho;
  ariaDialogueActive = false; // always safe to clear on load
}

/** Reset all state (for tests and save/load). */
export function resetEchoDelivery(): void {
  lastPollTick = 0;
  nextPollInterval = randomInterval();
  pendingEcho = null;
  ariaDialogueActive = false;
  displayCallback = null;
  apiBaseUrl = null;
}
