import {
  AdditiveBlending,
  BufferAttribute,
  BufferGeometry,
  DynamicDrawUsage,
  Points,
  Scene,
  ShaderMaterial,
} from 'three';
import {
  getRobotState,
  getRobotX,
  getRobotY,
  getRobotZ,
  getRobotRotation,
} from '../../sim/bufferLayout';
import { ROBOT_STATES } from '../../sim/robotSystems';

/**
 * Thruster trail particles. Shown when robots are in MOVING_TO, HAULING,
 * or RETURNING state. A small blue-white engine glow trails behind each robot.
 * GPU-efficient: only emitter positions and rotations are updated CPU-side per frame.
 */

const MAX_EMITTERS = 64;
const PARTICLES_PER_EMITTER = 10;
const TOTAL = MAX_EMITTERS * PARTICLES_PER_EMITTER;

// Robot states that have active thrusters
const MOVING_STATES: Set<number> = new Set([ROBOT_STATES.MOVING_TO, ROBOT_STATES.HAULING, ROBOT_STATES.RETURNING]);

export class ThrusterParticles {
  private points: Points;
  private material: ShaderMaterial;
  private emitterPosData: Float32Array;
  private emitterRotData: Float32Array;
  private emitterPosAttr: BufferAttribute;
  private emitterRotAttr: BufferAttribute;

  constructor(scene: Scene) {
    const seeds = new Float32Array(TOTAL);
    for (let i = 0; i < TOTAL; i++) {
      seeds[i] = i * 97.321;
    }

    this.emitterPosData = new Float32Array(TOTAL * 3).fill(1e6);
    this.emitterRotData = new Float32Array(TOTAL).fill(0);

    const dummyPos = new Float32Array(TOTAL * 3);

    const geo = new BufferGeometry();
    geo.setAttribute('position', new BufferAttribute(dummyPos, 3));

    this.emitterPosAttr = new BufferAttribute(this.emitterPosData, 3);
    this.emitterPosAttr.setUsage(DynamicDrawUsage);
    geo.setAttribute('emitterPos', this.emitterPosAttr);

    this.emitterRotAttr = new BufferAttribute(this.emitterRotData, 1);
    this.emitterRotAttr.setUsage(DynamicDrawUsage);
    geo.setAttribute('emitterRot', this.emitterRotAttr);

    geo.setAttribute('particleSeed', new BufferAttribute(seeds, 1));

    this.material = new ShaderMaterial({
      vertexShader: `
        attribute vec3 emitterPos;
        attribute float emitterRot;
        attribute float particleSeed;
        uniform float uTime;
        varying float vAlpha;
        varying vec3 vColor;

        float hash(float n) { return fract(sin(n) * 43758.5453); }

        void main() {
          float s = particleSeed;

          // Life phase cycling quickly for a flickery thruster look
          float rate = hash(s + 0.0) * 4.0 + 3.0;
          float life = fract(uTime * rate + hash(s + 1.0));

          // Offset behind the robot: -forward direction
          // With rotation.y = emitterRot, forward = (sin(rot), 0, cos(rot))
          float trailDist = life * 8.0 + 1.5;
          float sideways = (hash(s + 2.0) - 0.5) * 2.5;
          vec3 behind = vec3(
            -sin(emitterRot) * trailDist + cos(emitterRot) * sideways,
            (hash(s + 3.0) - 0.5) * 2.0,
            -cos(emitterRot) * trailDist - sin(emitterRot) * sideways
          );
          vec3 pos = emitterPos + behind;

          // Fade: bright near robot, dim as trail extends
          vAlpha = (1.0 - smoothstep(0.0, 1.0, life)) * 0.85;

          // Blue -> white-cyan thruster color
          float ct = hash(s + 4.0);
          vColor = mix(vec3(0.3, 0.7, 1.0), vec3(0.8, 0.95, 1.0), ct * (1.0 - life));

          vec4 mvPos = modelViewMatrix * vec4(pos, 1.0);
          gl_PointSize = clamp(1.5 * (1.0 - life * 0.8) * (300.0 / -mvPos.z), 1.0, 6.0);
          gl_Position = projectionMatrix * mvPos;
        }
      `,
      fragmentShader: `
        varying float vAlpha;
        varying vec3 vColor;
        void main() {
          float d = length(gl_PointCoord - vec2(0.5));
          if (d > 0.5) discard;
          float a = vAlpha * (1.0 - smoothstep(0.0, 0.5, d));
          gl_FragColor = vec4(vColor, a);
        }
      `,
      uniforms: {
        uTime: { value: 0 },
      },
      transparent: true,
      depthWrite: false,
      blending: AdditiveBlending,
    });

    this.points = new Points(geo, this.material);
    this.points.frustumCulled = false;
    scene.add(this.points);
  }

  /**
   * robotBuffer stride ROBOT_STRIDE: [eid, x, y, z, rotation, type, state, energyPct]
   */
  update(robotBuffer: Float32Array, robotCount: number, time: number): void {
    this.material.uniforms.uTime.value = time;

    // Write moving robot positions directly to attribute data (no temp arrays)
    let emitterCount = 0;
    for (let i = 0; i < robotCount && emitterCount < MAX_EMITTERS; i++) {
      if (MOVING_STATES.has(getRobotState(robotBuffer, i))) {
        const px = getRobotX(robotBuffer, i);
        const py = getRobotY(robotBuffer, i);
        const pz = getRobotZ(robotBuffer, i);
        const rot = getRobotRotation(robotBuffer, i);
        const base = emitterCount * PARTICLES_PER_EMITTER;
        for (let p = 0; p < PARTICLES_PER_EMITTER; p++) {
          const pi = base + p;
          const idx3 = pi * 3;
          this.emitterPosData[idx3] = px;
          this.emitterPosData[idx3 + 1] = py;
          this.emitterPosData[idx3 + 2] = pz;
          this.emitterRotData[pi] = rot;
        }
        emitterCount++;
      }
    }

    // Park inactive emitters off-screen
    for (let e = emitterCount; e < MAX_EMITTERS; e++) {
      const base = e * PARTICLES_PER_EMITTER;
      for (let p = 0; p < PARTICLES_PER_EMITTER; p++) {
        const pi = base + p;
        const idx3 = pi * 3;
        this.emitterPosData[idx3] = 1e6;
        this.emitterPosData[idx3 + 1] = 1e6;
        this.emitterPosData[idx3 + 2] = 1e6;
        this.emitterRotData[pi] = 0;
      }
    }

    this.emitterPosAttr.needsUpdate = true;
    this.emitterRotAttr.needsUpdate = true;
  }

  dispose(): void {
    this.points.geometry.dispose();
    this.material.dispose();
  }
}
