/**
 * Input handling — keyboard, mouse, and touch event listeners.
 *
 * Extracted from main.ts. Owns: keydown shortcuts, canvas click/mousedown,
 * mousemove (placement ghost), contextmenu, touchstart/touchend, and the
 * robot raycasting + follow-mode helpers.
 *
 * Returns handles that the render loop needs for follow-mode tracking.
 */
import { Raycaster, Vector2 } from 'three';
import { getKeyAction } from './input/keyboardHandler';
import { showFollowIndicator, hideFollowIndicator, speedUp, speedDown, setSpeed } from './ui/hud';
import { showNotification } from './ui/notifications';
import { toggleEventLog } from './ui/eventModal';
import { toggleTechTreePanel } from './ui/techTreePanel';
import { toggleKeybindingHelp, hideKeybindingHelp } from './ui/keybindingHelp';
import { toggleBuildPanel } from './ui/buildPanel';
import { toggleBaseBuildingsPanel } from './ui/baseBuildingsPanel';
import { toggleInboxPanel } from './ui/inboxPanel';
import { toggleCulturePanel, hideCulturePanel } from './ui/culturePanel';
import { toggleCodex } from './ui/codexPanel';
import { toggleArchivesPanel, hideArchivesPanel } from './ui/archivesPanel';
import { toggleMaterialPriorityPanel, hideMaterialPriorityPanel } from './ui/materialPriorityPanel';
import { toggleBlueprintPanel, hideBlueprintPanel } from './ui/blueprintPanel';
import { toggleSystemMapPanel, hideSystemMapPanel } from './ui/systemMapPanel';
import { toggleCommandersLogPanel, hideCommandersLogPanel } from './ui/commandersLogPanel';
import { toggleEventLogPanel, hideEventLogPanel } from './ui/eventLogPanel';
import { toggleHabitatPanel, hideHabitatPanel } from './ui/habitatPanel';
import { isPauseMenuOpen, openPauseMenu, closePauseMenu } from './ui/pauseMenu';
import { showShipPanel, setShipPanelFollowing } from './ui/shipPanel';
import { showAsteroidInfoPanel, hideAsteroidInfoPanel, isAsteroidInfoPanelVisible } from './ui/asteroidInfoPanel';
import { advanceTutorialIfOnStep } from './ui/tutorial';
import { showHint } from './ui/hints';
import { audioEngine } from './audio/audioEngine';
import { playSfx } from './audio/sfxEngine';
import { musicManager } from './audio/musicManager';
import { getRobotEid } from './sim/bufferLayout';
import {
  ASTEROID_STRIDE,
  ASTEROID_OFF_EID,
  ASTEROID_OFF_X,
  ASTEROID_OFF_Y,
  ASTEROID_OFF_Z,
  ASTEROID_OFF_RADIUS,
} from './sim/bufferLayout';
import { TASK_TYPES } from './sim/taskQueue';
import type { RendererHandles } from './rendererInit';
import type { GameRefs } from './gameRuntimeState';
import type { LazyPanelHandles } from './workerMessages';

export interface InputCallbacks {
  snapCameraToBase(): void;
  enterBasePlacementMode(): void;
  exitBasePlacementMode(): void;
  requestSave(slot: import('./sim/saveLoad').SaveSlot): void;
}

export interface InputHandles {
  /** Starts follow-agent camera mode for the given robot EID. */
  startFollow(eid: number): void;
  /** Stops follow-agent camera mode. */
  stopFollow(): void;
  /** Begins the idle-hint timer (call once after sim:ready). */
  scheduleIdleHint(): void;
  /** Enters targeting mode — next asteroid click creates a manual mine task. */
  enterTargetingMode(robotEid: number): void;
  /** Enters explore targeting mode — next world click creates an explore task. */
  enterExploreMode(robotEid: number): void;
}

export function initInputHandlers(
  canvas: HTMLCanvasElement,
  worker: Worker,
  refs: GameRefs,
  renderers: RendererHandles,
  lazy: LazyPanelHandles,
  cbs: InputCallbacks,
): InputHandles {
  const { camera, robotRenderer, cameraRig, placementNdc, placementPlane, placementTarget, placementGhostMesh } = renderers;

  // ── Follow-mode helpers (shared with render loop via returned handles) ────

  function startFollow(eid: number): void {
    refs.followedRobotEid = eid;
    setShipPanelFollowing(eid);
    showFollowIndicator(eid, () => stopFollow());
  }

  function stopFollow(): void {
    refs.followedRobotEid = null;
    cameraRig.setFollowTarget(null);
    setShipPanelFollowing(null);
    hideFollowIndicator();
  }

  // ── Idle hint ─────────────────────────────────────────────────────────────

  let lastInputTime = Date.now();
  let idleHintScheduled = false;

  function resetIdleTimer(): void {
    lastInputTime = Date.now();
  }

  function scheduleIdleHint(): void {
    if (idleHintScheduled) return;
    idleHintScheduled = true;
    const check = (): void => {
      if (Date.now() - lastInputTime >= 15_000) {
        showHint('idle_techtree', 'Press T to open Tech Tree');
      } else {
        setTimeout(check, 5_000);
      }
    };
    setTimeout(check, 15_000);
  }

  window.addEventListener('keydown', resetIdleTimer, { capture: true });
  window.addEventListener('wheel', resetIdleTimer, { capture: true, passive: true });
  window.addEventListener('mousedown', resetIdleTimer, { capture: true });
  window.addEventListener('touchstart', resetIdleTimer, { capture: true, passive: true });

  const onFirstScroll = (): void => {
    showHint('first_scroll', 'Scroll to zoom out and see the asteroid field');
    window.removeEventListener('wheel', onFirstScroll);
  };
  window.addEventListener('wheel', onFirstScroll, { passive: true });

  // ── Audio init (browser policy: first interaction) ────────────────────────

  let audioReady = false;
  async function initAudioOnce(): Promise<void> {
    if (audioReady) return;
    audioReady = true;
    await audioEngine.init();
    audioEngine.stopProceduralMusic();
    const _ctx = audioEngine.getAudioContext();
    const _musicGain = audioEngine.getMusicGain();
    if (_ctx && _musicGain) {
      musicManager.init(_ctx, _musicGain);
    }
  }

  // ── Raycasting ────────────────────────────────────────────────────────────

  const raycaster = new Raycaster();
  const ndcMouse = new Vector2();

  function pickRobotAt(clientX: number, clientY: number): boolean {
    const rect = canvas.getBoundingClientRect();
    ndcMouse.x = ((clientX - rect.left) / rect.width) * 2 - 1;
    ndcMouse.y = -((clientY - rect.top) / rect.height) * 2 + 1;
    raycaster.setFromCamera(ndcMouse, camera);

    for (const [type, mesh] of robotRenderer.getMeshes()) {
      if (mesh.count === 0) continue;
      const intersects = raycaster.intersectObject(mesh);
      if (intersects.length > 0 && intersects[0].instanceId !== undefined) {
        const eid = robotRenderer.getInstanceEid(type, intersects[0].instanceId);
        if (eid >= 0) {
          playSfx('ui.ship_highlight');
          startFollow(eid);
          showShipPanel(eid, clientX, clientY);
          return true;
        }
      }
    }
    if (refs.followedRobotEid !== null) {
      stopFollow();
      showNotification('Follow mode off', '#94a3b8');
    }
    return false;
  }

  /**
   * Find the closest asteroid to the click point using the asteroid buffer.
   * Returns { eid, x, y, z } or null if no asteroid near the click.
   */
  function pickAsteroidAt(clientX: number, clientY: number): { eid: number; x: number; y: number; z: number } | null {
    if (!refs.latestAsteroidBuffer || refs.latestAsteroidCount === 0) return null;
    const rect = canvas.getBoundingClientRect();
    ndcMouse.x = ((clientX - rect.left) / rect.width) * 2 - 1;
    ndcMouse.y = -((clientY - rect.top) / rect.height) * 2 + 1;
    raycaster.setFromCamera(ndcMouse, camera);
    const ray = raycaster.ray;

    let bestEid = -1;
    let bestDist = Infinity;
    let bestX = 0, bestY = 0, bestZ = 0;
    const buf = refs.latestAsteroidBuffer;

    for (let i = 0; i < refs.latestAsteroidCount; i++) {
      const off = i * ASTEROID_STRIDE;
      const ax = buf[off + ASTEROID_OFF_X];
      const ay = buf[off + ASTEROID_OFF_Y];
      const az = buf[off + ASTEROID_OFF_Z];
      const radius = buf[off + ASTEROID_OFF_RADIUS];
      // Distance from ray to asteroid center
      const dx = ax - ray.origin.x;
      const dy = ay - ray.origin.y;
      const dz = az - ray.origin.z;
      const dot = dx * ray.direction.x + dy * ray.direction.y + dz * ray.direction.z;
      if (dot < 0) continue; // behind camera
      const cx = ray.origin.x + dot * ray.direction.x - ax;
      const cy = ray.origin.y + dot * ray.direction.y - ay;
      const cz = ray.origin.z + dot * ray.direction.z - az;
      const distSq = cx * cx + cy * cy + cz * cz;
      // Use a generous pick radius (at least 8 units for small asteroids)
      const pickRadius = Math.max(radius * 1.5, 8);
      if (distSq < pickRadius * pickRadius && dot < bestDist) {
        bestDist = dot;
        bestEid = buf[off + ASTEROID_OFF_EID];
        bestX = ax;
        bestY = ay;
        bestZ = az;
      }
    }

    return bestEid >= 0 ? { eid: bestEid, x: bestX, y: bestY, z: bestZ } : null;
  }

  function enterTargetingMode(robotEid: number): void {
    refs.targetingRobotEid = robotEid;
    refs.isTargetingMode = true;
    canvas.style.cursor = 'crosshair';
    showNotification('Click an asteroid to mine', '#f59e0b');
  }

  function exitTargetingMode(): void {
    refs.targetingRobotEid = null;
    refs.isTargetingMode = false;
    canvas.style.cursor = '';
  }

  function enterExploreMode(robotEid: number): void {
    refs.exploreRobotEid = robotEid;
    refs.isExploreMode = true;
    canvas.style.cursor = 'crosshair';
    showNotification('Click a location to explore', '#a855f7');
  }

  function exitExploreMode(): void {
    refs.exploreRobotEid = null;
    refs.isExploreMode = false;
    canvas.style.cursor = '';
  }

  function getWorldXZAtMouse(clientX: number, clientY: number): import('three').Vector3 | null {
    const rect = canvas.getBoundingClientRect();
    placementNdc.x = ((clientX - rect.left) / rect.width) * 2 - 1;
    placementNdc.y = -((clientY - rect.top) / rect.height) * 2 + 1;
    raycaster.setFromCamera(placementNdc, camera);
    return raycaster.ray.intersectPlane(placementPlane, placementTarget)
      ? placementTarget.clone()
      : null;
  }

  // ── Keyboard ──────────────────────────────────────────────────────────────

  window.addEventListener('keydown', (e: KeyboardEvent) => {
    void initAudioOnce();
    const activeEl = document.activeElement;
    if (activeEl instanceof HTMLInputElement || activeEl instanceof HTMLTextAreaElement) return;

    const action = getKeyAction(e.key, e.ctrlKey, e.shiftKey);
    switch (action) {
      case 'save':
        e.preventDefault();
        cbs.requestSave(0);
        break;
      case 'toggleEventLog':
        toggleEventLog();
        break;
      case 'toggleGameEventLog':
        toggleEventLogPanel();
        break;
      case 'toggleDashboard':
        void lazy.loadDashboard().then((m) => {
          lazy.initDashboardOnce(m);
          m.toggleDashboard();
        }).catch((err) => {
          console.error('[ui] Failed to load dashboard panel:', err);
          showNotification('Failed to load panel — try again', '#ef4444');
        });
        advanceTutorialIfOnStep('resources');
        break;
      case 'toggleTechTree':
        toggleTechTreePanel();
        advanceTutorialIfOnStep('research');
        break;
      case 'toggleKeybindingHelp':
        toggleKeybindingHelp();
        break;
      case 'toggleFactionPanel':
        void lazy.loadFactionPanel().then((m) => {
          lazy.initFactionOnce(m);
          m.toggleFactionPanel();
        }).catch((err) => {
          console.error('[ui] Failed to load faction panel:', err);
          showNotification('Failed to load panel — try again', '#ef4444');
        });
        break;
      case 'toggleMegastructurePanel':
        void lazy.loadMegaPanel().then((m) => {
          lazy.initMegaOnce(m);
          m.toggleMegastructurePanel();
        }).catch((err) => {
          console.error('[ui] Failed to load megastructure panel:', err);
          showNotification('Failed to load panel — try again', '#ef4444');
        });
        break;
      case 'toggleAudioMute': {
        const nowMuted = audioEngine.toggleMute();
        showNotification(nowMuted ? '🔇 Audio muted' : '🔊 Audio enabled', '#94a3b8');
        break;
      }
      case 'toggleAdvisorPanel':
        void lazy.loadAdvisorLazy().then((m) => {
          lazy.initAdvisorOnce(m);
          m.panel.toggleAdvisorPanel();
        }).catch((err) => {
          console.error('[ui] Failed to load advisor panel:', err);
          showNotification('Failed to load panel — try again', '#ef4444');
        });
        break;
      case 'toggleBuildPanel':
        toggleBuildPanel();
        advanceTutorialIfOnStep('factory');
        break;
      case 'toggleBuildingsPanel':
        toggleBaseBuildingsPanel();
        advanceTutorialIfOnStep('buildings');
        break;
      case 'toggleInboxPanel':
        toggleInboxPanel();
        break;
      case 'toggleCulturePanel':
        toggleCulturePanel();
        break;
      case 'toggleHabitatPanel':
        toggleHabitatPanel();
        break;
      case 'toggleCodex':
        toggleCodex();
        break;
      case 'toggleArchivesPanel':
        toggleArchivesPanel();
        break;
      case 'toggleMaterialPriorityPanel':
        toggleMaterialPriorityPanel();
        break;
      case 'toggleBlueprintPanel':
        toggleBlueprintPanel();
        break;
      case 'toggleSystemMap':
        toggleSystemMapPanel();
        break;
      case 'toggleCommandersLog':
        toggleCommandersLogPanel();
        break;
      case 'snapToBase':
        e.preventDefault();
        cbs.snapCameraToBase();
        break;
      case 'followNextRobot': {
        e.preventDefault();
        if (refs.latestRobotBuffer && refs.latestRobotCount > 0) {
          let nextIdx = 0;
          if (refs.followedRobotEid !== null) {
            for (let i = 0; i < refs.latestRobotCount; i++) {
              if (getRobotEid(refs.latestRobotBuffer, i) === refs.followedRobotEid) {
                nextIdx = (i + 1) % refs.latestRobotCount;
                break;
              }
            }
          }
          startFollow(getRobotEid(refs.latestRobotBuffer, nextIdx));
        }
        break;
      }
      case 'followPrevRobot': {
        e.preventDefault();
        if (refs.latestRobotBuffer && refs.latestRobotCount > 0) {
          let prevIdx = refs.latestRobotCount - 1;
          if (refs.followedRobotEid !== null) {
            for (let i = 0; i < refs.latestRobotCount; i++) {
              if (getRobotEid(refs.latestRobotBuffer, i) === refs.followedRobotEid) {
                prevIdx = (i - 1 + refs.latestRobotCount) % refs.latestRobotCount;
                break;
              }
            }
          }
          startFollow(getRobotEid(refs.latestRobotBuffer, prevIdx));
        }
        break;
      }
      case 'speedUp':
        speedUp();
        break;
      case 'speedDown':
        speedDown();
        break;
      case 'setSpeed1':
        setSpeed(1);
        break;
      case 'setSpeed2':
        setSpeed(2);
        break;
      case 'setSpeed4':
        setSpeed(4);
        break;
      case 'escape':
        hideKeybindingHelp();
        hideCulturePanel();
        hideHabitatPanel();
        hideAsteroidInfoPanel();
        hideMaterialPriorityPanel();
        hideBlueprintPanel();
        hideCommandersLogPanel();
        hideEventLogPanel();
        hideSystemMapPanel();
        lazy.getFactionPanel()?.hideFactionPanel();
        lazy.getMegaPanel()?.hideMegastructurePanel();
        hideArchivesPanel();
        if (refs.isTargetingMode) {
          exitTargetingMode();
          showNotification('Targeting cancelled', '#94a3b8');
          return;
        }
        if (refs.isExploreMode) {
          exitExploreMode();
          showNotification('Explore cancelled', '#94a3b8');
          return;
        }
        if (refs.isPlacingBase) {
          cbs.exitBasePlacementMode();
          showNotification('Outpost placement cancelled', '#94a3b8');
          return;
        }
        if (refs.followedRobotEid !== null) {
          stopFollow();
          showNotification('Follow mode off', '#94a3b8');
          return;
        }
        if (isPauseMenuOpen()) {
          closePauseMenu();
          worker.postMessage({ type: 'sim:resume' });
        } else {
          openPauseMenu();
          worker.postMessage({ type: 'sim:pause' });
        }
        break;
    }
  });

  canvas.addEventListener('click', () => void initAudioOnce(), { once: true });
  document.addEventListener('pointerdown', () => void initAudioOnce(), { once: true });

  // ── Mouse ─────────────────────────────────────────────────────────────────

  canvas.addEventListener('mousemove', (e: MouseEvent) => {
    if (!refs.isPlacingBase) return;
    const pos = getWorldXZAtMouse(e.clientX, e.clientY);
    if (pos) {
      placementGhostMesh.position.set(pos.x, 0.5, pos.z);
    }
  });

  let mouseDownX = 0;
  let mouseDownY = 0;

  canvas.addEventListener('mousedown', (e: MouseEvent) => {
    mouseDownX = e.clientX;
    mouseDownY = e.clientY;
  });

  canvas.addEventListener('click', (e: MouseEvent) => {
    if (Math.abs(e.clientX - mouseDownX) > 5 || Math.abs(e.clientY - mouseDownY) > 5) return;
    if (cameraRig.wasDragPanning()) return; // suppress click after drag-pan
    if (e.button !== 0) return;
    if (refs.isPlacingBase) {
      const pos = getWorldXZAtMouse(e.clientX, e.clientY);
      if (pos) {
        worker.postMessage({ type: 'sim:build_base', payload: { x: pos.x, y: 0, z: pos.z } });
      }
      cbs.exitBasePlacementMode();
      return;
    }
    if (refs.isTargetingMode) {
      const asteroid = pickAsteroidAt(e.clientX, e.clientY);
      if (asteroid) {
        worker.postMessage({
          type: 'sim:add_task',
          payload: {
            taskType: TASK_TYPES.MINE,
            targetEid: asteroid.eid,
            targetX: asteroid.x,
            targetY: asteroid.y,
            targetZ: asteroid.z,
            priority: 10,
            robotEid: refs.targetingRobotEid ?? undefined,
          },
        });
        playSfx('ui.button_press');
        showNotification('Mining task assigned', '#4ade80');
        if (!refs.playerTargetAsteroids.includes(asteroid.eid)) {
          refs.playerTargetAsteroids.push(asteroid.eid);
        }
      } else {
        showNotification('No asteroid found — try again', '#94a3b8');
      }
      exitTargetingMode();
      e.stopPropagation();
      return;
    }
    if (refs.isExploreMode) {
      const pos = getWorldXZAtMouse(e.clientX, e.clientY);
      if (pos) {
        worker.postMessage({
          type: 'sim:add_task',
          payload: {
            taskType: TASK_TYPES.EXPLORE,
            targetEid: -1,
            targetX: pos.x,
            targetY: 0,
            targetZ: pos.z,
            priority: 10,
            robotEid: refs.exploreRobotEid ?? undefined,
          },
        });
        playSfx('ui.button_press');
        showNotification('Explore task assigned', '#a855f7');
      } else {
        showNotification('Invalid location — try again', '#94a3b8');
      }
      exitExploreMode();
      e.stopPropagation();
      return;
    }
    if (pickRobotAt(e.clientX, e.clientY)) {
      e.stopPropagation();
      return;
    }
    // No robot hit — check for asteroid
    const asteroid = pickAsteroidAt(e.clientX, e.clientY);
    if (asteroid) {
      showAsteroidInfoPanel(asteroid.eid, e.clientX, e.clientY);
      worker.postMessage({ type: 'sim:query_asteroid', payload: { eid: asteroid.eid } });
      e.stopPropagation();
      return;
    }
    // Clicked empty space — dismiss asteroid panel if open
    if (isAsteroidInfoPanelVisible()) {
      hideAsteroidInfoPanel();
    }
  });

  canvas.addEventListener('contextmenu', (e: MouseEvent) => {
    if (refs.isTargetingMode) {
      e.preventDefault();
      exitTargetingMode();
      showNotification('Targeting cancelled', '#94a3b8');
      return;
    }
    if (refs.isExploreMode) {
      e.preventDefault();
      exitExploreMode();
      showNotification('Explore cancelled', '#94a3b8');
      return;
    }
    if (refs.isPlacingBase) {
      e.preventDefault();
      cbs.exitBasePlacementMode();
      showNotification('Outpost placement cancelled', '#94a3b8');
    }
  });

  // ── Touch ─────────────────────────────────────────────────────────────────

  let touchStartX = 0;
  let touchStartY = 0;

  canvas.addEventListener('touchstart', (e: TouchEvent) => {
    if (e.touches.length === 1) {
      touchStartX = e.touches[0].clientX;
      touchStartY = e.touches[0].clientY;
    }
  });

  canvas.addEventListener('touchend', (e: TouchEvent) => {
    void initAudioOnce();
    if (e.changedTouches.length === 1) {
      const dx = e.changedTouches[0].clientX - touchStartX;
      const dy = e.changedTouches[0].clientY - touchStartY;
      if (Math.abs(dx) < 10 && Math.abs(dy) < 10) {
        if (pickRobotAt(e.changedTouches[0].clientX, e.changedTouches[0].clientY)) {
          e.preventDefault();
        }
      }
    }
  });

  return { startFollow, stopFollow, scheduleIdleHint, enterTargetingMode, enterExploreMode };
}
