/**
 * Market Panel — player-initiated resource sales to factions.
 * Toggle with the M key or the Market HUD button.
 *
 * Shows active listings, allows creating new ones and cancelling pending ones.
 */

import type { MarketListing } from '../sim/market';
import { RESOURCE_VALUE } from '../sim/market';
import type { FactionId, FactionSnapshot } from '../sim/factions/factionSystem';
import { FACTION_DEFS } from '../sim/factions/factionSystem';
import { makeDraggable, registerWindow } from './windowManager';
import { safeHtml } from './utils/safeHtml';

let panel: HTMLDivElement | null = null;
let isVisible = false;

let latestListings: MarketListing[] = [];
let latestFactions: FactionSnapshot[] = [];

let onCreateListing: ((resource: string, quantity: number, buyerFactionId: FactionId) => void) | null = null;
let onCancelListing: ((listingId: string) => void) | null = null;
let _marketKeyListenerAttached = false;

const TRADEABLE_RESOURCES = ['iron', 'carbon', 'silicon', 'water'] as const;

const RESOURCE_LABELS: Record<string, string> = {
  iron: 'Iron',
  carbon: 'Carbon',
  silicon: 'Silicon',
  water: 'Water',
};

const STATUS_COLORS: Record<string, string> = {
  pending: '#f59e0b',
  hauling: '#3b82f6',
  completed: '#22c55e',
  cancelled: '#64748b',
};

const STATUS_LABELS: Record<string, string> = {
  pending: 'Awaiting Hauler',
  hauling: 'In Transit',
  completed: 'Delivered',
  cancelled: 'Cancelled',
};

function createPanel(): HTMLDivElement {
  const el = document.createElement('div');
  el.id = 'market-panel';
  el.style.cssText = `
    position: absolute;
    top: 80px;
    right: 20px;
    background: rgba(10, 20, 40, 0.97);
    border: 1px solid #1e40af;
    border-radius: 8px;
    padding: 0;
    min-width: 440px;
    max-width: 560px;
    max-height: 70vh;
    overflow-y: auto;
    font-family: 'Courier New', monospace;
    font-size: 12px;
    color: #e2e8f0;
    pointer-events: auto;
    box-shadow: 0 0 40px rgba(0,0,0,0.9);
    opacity: 0;
    display: none;
    transition: opacity 0.2s ease-out;
  `;

  const hudOverlay = document.getElementById('hud-overlay');
  if (hudOverlay) hudOverlay.appendChild(el);

  el.addEventListener('click', (e: MouseEvent) => {
    const target = e.target as HTMLElement;
    const actionEl = target.closest<HTMLElement>('[data-action]');
    if (!actionEl) return;

    const action = actionEl.dataset['action'];

    if (action === 'close') {
      hidePanel();
    } else if (action === 'create-listing') {
      handleCreateListing(el);
    } else if (action?.startsWith('cancel-listing:')) {
      const listingId = action.split(':')[1];
      if (listingId) {
        onCancelListing?.(listingId);
      }
    }
  });

  registerWindow('market', el);
  makeDraggable(el);
  return el;
}

function handleCreateListing(el: HTMLElement): void {
  const resEl = el.querySelector<HTMLSelectElement>('#market-resource');
  const qtyEl = el.querySelector<HTMLInputElement>('#market-quantity');
  const factionEl = el.querySelector<HTMLSelectElement>('#market-faction');

  const resource = resEl?.value ?? 'iron';
  const quantity = parseInt(qtyEl?.value ?? '100');
  const factionId = parseInt(factionEl?.value ?? '0') as FactionId;

  if (isNaN(quantity) || quantity <= 0) return;

  onCreateListing?.(resource, quantity, factionId);
}

function getOrCreatePanel(): HTMLDivElement {
  if (!panel) panel = createPanel();
  return panel;
}

function showPanel(): void {
  isVisible = true;
  const el = getOrCreatePanel();
  renderPanel();
  el.style.display = 'block';
  requestAnimationFrame(() => {
    el.style.opacity = '1';
  });
}

function hidePanel(): void {
  isVisible = false;
  const el = getOrCreatePanel();
  el.style.opacity = '0';
  setTimeout(() => {
    el.style.display = 'none';
  }, 200);
}

function renderPanel(): void {
  const el = getOrCreatePanel();
  if (!isVisible) return;

  const activeListings = latestListings.filter(
    (l) => l.status === 'pending' || l.status === 'hauling',
  );
  const recentCompleted = latestListings
    .filter((l) => l.status === 'completed' || l.status === 'cancelled')
    .slice(-5);

  const listingsHtml =
    activeListings.length === 0 && recentCompleted.length === 0
      ? '<div style="color:#64748b;margin:8px 0;">No active listings.</div>'
      : [...activeListings, ...recentCompleted]
          .map((l) => {
            const factionDef = FACTION_DEFS[l.buyerFactionId];
            const statusColor = STATUS_COLORS[l.status] ?? '#64748b';
            const statusLabel = STATUS_LABELS[l.status] ?? l.status;
            const payment = (l.quantity * l.pricePerUnit).toFixed(0);
            const cancelBtn =
              l.status === 'pending'
                ? `<button data-action="cancel-listing:${l.id}" style="
                    background:none;border:1px solid #ef444466;color:#ef4444;
                    cursor:pointer;font-size:10px;padding:1px 5px;
                    border-radius:2px;font-family:monospace;margin-left:6px;
                  " title="Cancel listing">✗</button>`
                : '';
            return `<div style="color:#94a3b8;margin:4px 0;display:flex;align-items:center;gap:6px;flex-wrap:wrap;">
              <span style="color:${statusColor};font-weight:bold;min-width:100px;">${statusLabel}</span>
              <span>${l.quantity} ${RESOURCE_LABELS[l.resource] ?? l.resource}</span>
              <span style="color:#64748b;">→</span>
              <span style="color:${factionDef?.color ?? '#aaa'}">${factionDef?.name ?? 'Unknown'}</span>
              <span style="color:#22c55e;font-size:11px;">(+${payment} Fe)</span>
              ${cancelBtn}
            </div>`;
          })
          .join('');

  // Faction demand summary
  const factionDemandHtml = latestFactions.length > 0
    ? latestFactions
        .map((f) => {
          const res = f.resources;
          const entries = Object.entries(res).sort(([, a], [, b]) => a - b);
          const shortage = entries[0];
          const surplus = entries[entries.length - 1];
          return `<div style="color:#94a3b8;margin:2px 0;">
            <span style="color:${f.color};font-weight:bold;">${f.name}</span>
            <span style="color:#64748b;"> — needs</span>
            <span style="color:#ef4444;"> ${shortage?.[0] ?? '?'}</span>
            <span style="color:#64748b;">, has surplus</span>
            <span style="color:#22c55e;"> ${surplus?.[0] ?? '?'}</span>
          </div>`;
        })
        .join('')
    : '<div style="color:#64748b;">No faction data yet.</div>';

  const createListingHtml = `
    <div style="margin-top:10px;border-top:1px solid #1e3a5f;padding-top:10px;">
      <div style="color:#60a5fa;margin-bottom:6px;font-weight:bold;letter-spacing:1px;">NEW LISTING</div>
      <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;">
        <select id="market-resource" style="background:#0f172a;border:1px solid #334155;color:#e2e8f0;padding:2px 4px;font-family:monospace;border-radius:3px;">
          ${TRADEABLE_RESOURCES.map((r) => `<option value="${r}">${RESOURCE_LABELS[r]}</option>`).join('')}
        </select>
        <input id="market-quantity" type="number" value="100" min="1" style="width:70px;background:#0f172a;border:1px solid #334155;color:#e2e8f0;padding:2px 4px;font-family:monospace;border-radius:3px;" title="Quantity to sell">
        <span style="color:#60a5fa;">→</span>
        <select id="market-faction" style="background:#0f172a;border:1px solid #334155;color:#e2e8f0;padding:2px 4px;font-family:monospace;border-radius:3px;">
          ${FACTION_DEFS.map((f) => `<option value="${f.id}">${f.name}</option>`).join('')}
        </select>
        <button data-action="create-listing" style="
          background:#1e40af;border:none;color:#e2e8f0;padding:3px 10px;
          cursor:pointer;font-family:monospace;border-radius:4px;font-size:12px;
        ">Sell</button>
      </div>
      <div style="color:#64748b;font-size:11px;margin-top:4px;">
        Resources are reserved on listing. A hauler will deliver to the buyer. Payment in iron on delivery.
      </div>
    </div>
  `;

  el.innerHTML = safeHtml`
    <div class="win-drag-handle" style="
      display:flex;justify-content:space-between;align-items:center;
      padding:12px 16px 10px;
      border-bottom:1px solid #1e3a5f;
      cursor:move;user-select:none;
    ">
      <span style="color:#93c5fd;font-size:14px;font-weight:bold;letter-spacing:2px;">$ MARKET</span>
      <button data-action="close" style="
        background:none;border:1px solid #555;color:#aaa;
        padding:2px 8px;cursor:pointer;border-radius:3px;
        font-family:monospace;font-size:11px;
      " title="Close (M)">✕ close</button>
    </div>
    <div style="padding:16px;">
      <div style="margin-bottom:10px">
        <div style="color:#60a5fa;margin-bottom:6px;font-weight:bold;letter-spacing:1px;">FACTION DEMAND</div>
        ${factionDemandHtml}
      </div>
      <div style="border-top:1px solid #1e3a5f;padding-top:10px;">
        <div style="color:#60a5fa;margin-bottom:6px;font-weight:bold;letter-spacing:1px;">LISTINGS</div>
        ${listingsHtml}
      </div>
      ${createListingHtml}
    </div>
  `;
}

export function initMarketPanel(
  createListingCb: (resource: string, quantity: number, buyerFactionId: FactionId) => void,
  cancelListingCb: (listingId: string) => void,
): void {
  onCreateListing = createListingCb;
  onCancelListing = cancelListingCb;

  if (!_marketKeyListenerAttached) {
    _marketKeyListenerAttached = true;
    window.addEventListener('keydown', (e: KeyboardEvent) => {
      if ((e.target as HTMLElement).tagName === 'INPUT') return;
      if (e.key === 'm' || e.key === 'M') {
        if (isVisible) hidePanel();
        else showPanel();
      }
    });
  }
}

export function updateMarketState(listings: MarketListing[]): void {
  latestListings = listings;
  if (isVisible) renderPanel();
}

export function updateMarketFactions(factions: FactionSnapshot[]): void {
  latestFactions = factions;
  if (isVisible) renderPanel();
}

export function toggleMarketPanel(): void {
  if (isVisible) hidePanel();
  else showPanel();
}
