/**
 * Settings Panel
 *
 * Accessible via the pause menu or a dedicated button.
 * Sections: Audio (volume sliders), Graphics (bloom, particles), Game (auto-save interval)
 * All settings persisted to localStorage.
 */

import { audioEngine } from '../audio/audioEngine';
import { musicManager } from '../audio/musicManager';
import {
  ALL_SFX_FILES,
  loadSfxMap,
  saveSfxMap,
  resetSfxMap,
  previewSfx,
  playSfx,
  type SfxEvent,
  type SfxEventMap,
} from '../audio/sfxEngine';
import { attachTooltip } from './tooltip';
import { trapFocus } from './focusTrap';

const STORAGE_KEY = 'asteroid_miner_settings';

export interface GameSettings {
  bloomIntensity: number; // 0-2
  particleDensity: number; // 0-1
  autoSaveIntervalMin: number; // 1-30
  beltEchoesEnabled: boolean; // Belt Echoes cross-player discovery feed
}

const DEFAULT_SETTINGS: GameSettings = {
  bloomIntensity: 1.0,
  particleDensity: 1.0,
  autoSaveIntervalMin: 5,
  beltEchoesEnabled: true,
};

let currentSettings: GameSettings = loadSettings();
let panel: HTMLDivElement | null = null;
let visible = false;
let onSettingsChange: ((s: GameSettings) => void) | null = null;
let removeFocusTrap: (() => void) | null = null;

// ── Public API ────────────────────────────────────────────────────────────────

export function initSettingsPanel(callback: (s: GameSettings) => void): GameSettings {
  onSettingsChange = callback;
  return currentSettings;
}

export function toggleSettingsPanel(): void {
  if (visible) hideSettings();
  else showSettings();
}

export function showSettingsPanel(): void {
  showSettings();
}

export function hideSettingsPanel(): void {
  hideSettings();
}

export function getGameSettings(): GameSettings {
  return currentSettings;
}

// ── Private ───────────────────────────────────────────────────────────────────

function loadSettings(): GameSettings {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) return { ...DEFAULT_SETTINGS, ...JSON.parse(raw) };
  } catch {
    // ignore
  }
  return { ...DEFAULT_SETTINGS };
}

function saveSettings(): void {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(currentSettings));
  } catch {
    // ignore
  }
}

function showSettings(): void {
  visible = true;
  if (!panel) buildPanel();
  panel!.style.display = 'flex';
  const card = panel!.querySelector<HTMLElement>('[role="dialog"]');
  if (card) removeFocusTrap = trapFocus(card);
}

function hideSettings(): void {
  visible = false;
  removeFocusTrap?.();
  removeFocusTrap = null;
  if (panel) panel.style.display = 'none';
}

function buildPanel(): void {
  panel = document.createElement('div');
  panel.setAttribute('aria-modal', 'true');
  panel.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(4,6,14,0.8);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 190;
    backdrop-filter: blur(3px);
  `;

  const card = document.createElement('div');
  card.setAttribute('role', 'dialog');
  card.setAttribute('aria-label', 'Settings');
  card.setAttribute('tabindex', '-1');
  card.style.cssText = `
    background: rgba(10,14,28,0.98);
    border: 1px solid rgba(100,140,255,0.3);
    border-radius: 10px;
    padding: 28px 32px;
    width: 400px;
    font-family: 'Courier New', monospace;
    color: #c0d0f0;
    box-shadow: 0 8px 40px rgba(0,0,0,0.7);
  `;

  // Header
  const header = document.createElement('div');
  header.style.cssText = `
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 20px;
    padding-bottom: 10px;
    border-bottom: 1px solid rgba(100,140,255,0.2);
  `;
  header.innerHTML = `<span style="font-size:14px;color:#7090e0;letter-spacing:0.1em;text-transform:uppercase;">⚙ Settings</span>`;
  const closeBtn = document.createElement('button');
  closeBtn.textContent = '×';
  closeBtn.setAttribute('aria-label', 'Close settings');
  closeBtn.style.cssText = 'background:none;border:none;color:#666;cursor:pointer;font-size:18px;';
  closeBtn.onclick = () => { playSfx('ui.panel_close'); hideSettings(); };
  header.appendChild(closeBtn);
  card.appendChild(header);

  // ── Audio section ──────────────────────────────────────────────────────────
  card.appendChild(sectionLabel('Audio'));

  const audio = audioEngine.getSettings();

  card.appendChild(
    sliderRow('Master Volume', audio.masterVolume, 0, 1, 0.05, (v) => {
      audioEngine.setMasterVolume(v);
    }),
  );
  card.appendChild(
    sliderRow('SFX Volume', audio.sfxVolume, 0, 1, 0.05, (v) => {
      audioEngine.setSfxVolume(v);
    }),
  );
  card.appendChild(
    sliderRow('Music Volume', audio.musicVolume, 0, 1, 0.05, (v) => {
      audioEngine.setMusicVolume(v);
    }),
  );

  // Music toggle row
  const musicToggleRow = document.createElement('div');
  musicToggleRow.style.cssText = 'display:flex;align-items:center;gap:10px;margin-bottom:8px;';
  const musicToggleLabel = document.createElement('span');
  musicToggleLabel.style.cssText = 'flex:0 0 120px;font-size:11px;color:#8090b0;';
  musicToggleLabel.textContent = 'Music';
  const musicToggleBtn = document.createElement('button');
  let savedMusicVol = audio.musicVolume > 0 ? audio.musicVolume : 0.6;
  const isMusicOn = (): boolean => audioEngine.getSettings().musicVolume > 0;
  musicToggleBtn.textContent = isMusicOn() ? 'On' : 'Off';
  musicToggleBtn.style.cssText = `
  padding:3px 12px;
  background:${isMusicOn() ? 'rgba(60,120,60,0.6)' : 'rgba(60,60,80,0.4)'};
  border:1px solid rgba(100,140,255,0.3);
  border-radius:4px;
  color:#a0c0ff;
  cursor:pointer;
  font-family:'Courier New',monospace;
  font-size:11px;
`;
  musicToggleBtn.onclick = () => {
    playSfx('ui.button_press');
    if (isMusicOn()) {
      savedMusicVol = audioEngine.getSettings().musicVolume;
      audioEngine.setMusicVolume(0);
      musicToggleBtn.textContent = 'Off';
      musicToggleBtn.style.background = 'rgba(60,60,80,0.4)';
    } else {
      audioEngine.setMusicVolume(savedMusicVol);
      musicToggleBtn.textContent = 'On';
      musicToggleBtn.style.background = 'rgba(60,120,60,0.6)';
    }
  };
  musicToggleRow.appendChild(musicToggleLabel);
  musicToggleRow.appendChild(musicToggleBtn);
  const skipTrackBtn = document.createElement('button');
  skipTrackBtn.textContent = '⏭ Skip';
  skipTrackBtn.title = 'Skip to next track';
  skipTrackBtn.style.cssText = `
  padding:3px 10px;
  background:rgba(40,60,100,0.4);
  border:1px solid rgba(100,140,255,0.3);
  border-radius:4px;
  color:#a0c0ff;
  cursor:pointer;
  font-family:'Courier New',monospace;
  font-size:11px;
`;
  skipTrackBtn.onclick = () => {
    playSfx('ui.button_press');
    musicManager.skipTrack();
  };
  musicToggleRow.appendChild(skipTrackBtn);
  card.appendChild(musicToggleRow);

  // ── Graphics section ───────────────────────────────────────────────────────
  card.appendChild(sectionLabel('Graphics'));

  card.appendChild(
    sliderRow(
      'Bloom Intensity',
      currentSettings.bloomIntensity,
      0,
      2,
      0.1,
      (v) => {
        currentSettings.bloomIntensity = v;
        saveSettings();
        onSettingsChange?.(currentSettings);
      },
      undefined,
      'Glow effect intensity around bright objects\n0 = off · 1 = default · 2 = intense\nHigher values may reduce performance',
    ),
  );

  card.appendChild(
    sliderRow(
      'Particle Density',
      currentSettings.particleDensity,
      0,
      1,
      0.1,
      (v) => {
        currentSettings.particleDensity = v;
        saveSettings();
        onSettingsChange?.(currentSettings);
      },
      undefined,
      'Density of dust and debris particles\n0 = none · 1 = full\nReduce if experiencing frame rate drops',
    ),
  );

  // ── Game section ───────────────────────────────────────────────────────────
  card.appendChild(sectionLabel('Game'));

  card.appendChild(
    sliderRow(
      'Auto-save (min)',
      currentSettings.autoSaveIntervalMin,
      1,
      30,
      1,
      (v) => {
        currentSettings.autoSaveIntervalMin = Math.round(v);
        saveSettings();
        onSettingsChange?.(currentSettings);
      },
      (v) => `${Math.round(v)}m`,
      'How often the game auto-saves\n1m = frequent (safe) · 30m = infrequent\nAuto-save briefly pauses simulation',
    ),
  );

  // Belt Echoes toggle
  const beltEchoesRow = document.createElement('div');
  beltEchoesRow.style.cssText = 'display:flex;align-items:center;gap:10px;margin-bottom:8px;';
  const beltEchoesLabel = document.createElement('span');
  beltEchoesLabel.style.cssText = 'flex:0 0 120px;font-size:11px;color:#8090b0;';
  beltEchoesLabel.textContent = 'Belt Echoes';
  const beltEchoesBtn = document.createElement('button');
  beltEchoesBtn.textContent = currentSettings.beltEchoesEnabled ? 'On' : 'Off';
  beltEchoesBtn.style.cssText = `
    padding:3px 12px;
    background:${currentSettings.beltEchoesEnabled ? 'rgba(60,120,60,0.6)' : 'rgba(60,60,80,0.4)'};
    border:1px solid rgba(100,140,255,0.3);
    border-radius:4px;
    color:#a0c0ff;
    cursor:pointer;
    font-family:'Courier New',monospace;
    font-size:11px;
  `;
  beltEchoesBtn.onclick = () => {
    playSfx('ui.button_press');
    currentSettings.beltEchoesEnabled = !currentSettings.beltEchoesEnabled;
    beltEchoesBtn.textContent = currentSettings.beltEchoesEnabled ? 'On' : 'Off';
    beltEchoesBtn.style.background = currentSettings.beltEchoesEnabled
      ? 'rgba(60,120,60,0.6)'
      : 'rgba(60,60,80,0.4)';
    saveSettings();
    onSettingsChange?.(currentSettings);
  };
  attachTooltip(beltEchoesRow, 'Receive anonymous transmissions from other colonies in the belt.\nThese are intercepted signals — echoes of what others have achieved.');
  beltEchoesRow.appendChild(beltEchoesLabel);
  beltEchoesRow.appendChild(beltEchoesBtn);
  card.appendChild(beltEchoesRow);

  // Dev mode toggle
  const devToggleRow = document.createElement('div');
  devToggleRow.style.cssText = 'display:flex;align-items:center;gap:10px;margin-bottom:8px;';
  const devToggleLabel = document.createElement('span');
  devToggleLabel.style.cssText = 'flex:0 0 120px;font-size:11px;color:#8090b0;';
  devToggleLabel.textContent = 'Dev Mode';
  const devToggleBtn = document.createElement('button');
  const isDevMode = (): boolean =>
    new URLSearchParams(window.location.search).get('dev') === 'true' ||
    localStorage.getItem('devMode') === 'true';
  devToggleBtn.textContent = isDevMode() ? 'On' : 'Off';
  devToggleBtn.style.cssText = `
    padding:3px 12px;
    background:${isDevMode() ? 'rgba(60,120,60,0.6)' : 'rgba(60,60,80,0.4)'};
    border:1px solid rgba(100,140,255,0.3);
    border-radius:4px;
    color:#a0c0ff;
    cursor:pointer;
    font-family:'Courier New',monospace;
    font-size:11px;
  `;
  devToggleBtn.onclick = () => {
    playSfx('ui.button_press');
    const next = !isDevMode();
    localStorage.setItem('devMode', next ? 'true' : 'false');
    devToggleBtn.textContent = next ? 'On' : 'Off';
    devToggleBtn.style.background = next ? 'rgba(60,120,60,0.6)' : 'rgba(60,60,80,0.4)';
    // Show/hide sound designer section
    const sdSection = card.querySelector<HTMLElement>('[data-sound-designer]');
    if (sdSection) sdSection.style.display = next ? 'block' : 'none';
  };
  devToggleRow.appendChild(devToggleLabel);
  devToggleRow.appendChild(devToggleBtn);
  card.appendChild(devToggleRow);

  // ── Sound Designer section (dev only) ──────────────────────────────────────
  const sdSection = document.createElement('div');
  sdSection.setAttribute('data-sound-designer', '');
  sdSection.style.display = isDevMode() ? 'block' : 'none';
  sdSection.appendChild(sectionLabel('Sound Designer (Dev)'));

  const sfxEvents = Object.keys(loadSfxMap()) as SfxEvent[];

  const renderSoundDesigner = (): void => {
    // Clear previous rows
    while (sdSection.children.length > 1) sdSection.removeChild(sdSection.lastChild!);

    const currentMap: SfxEventMap = loadSfxMap();

    for (const event of sfxEvents) {
      const row = document.createElement('div');
      row.style.cssText = 'display:flex;align-items:center;gap:6px;margin-bottom:6px;';

      const labelEl = document.createElement('span');
      labelEl.style.cssText = 'flex:0 0 160px;font-size:10px;color:#7080a0;word-break:break-all;';
      labelEl.textContent = event;

      const select = document.createElement('select');
      select.style.cssText = `
        flex:1;
        background:rgba(10,14,28,0.9);
        border:1px solid rgba(100,140,255,0.25);
        border-radius:3px;
        color:#a0c0ff;
        font-size:10px;
        font-family:'Courier New',monospace;
        padding:2px;
      `;
      for (const file of ALL_SFX_FILES) {
        const opt = document.createElement('option');
        opt.value = file;
        opt.textContent = file.replace(/\.mp3$/i, '').slice(0, 40);
        opt.title = file;
        if (file === currentMap[event]) opt.selected = true;
        select.appendChild(opt);
      }
      select.onchange = () => {
        const updated = loadSfxMap();
        updated[event] = select.value;
        saveSfxMap(updated);
      };

      const playBtn = document.createElement('button');
      playBtn.textContent = '▶';
      playBtn.setAttribute('aria-label', `Preview ${event}`);
      playBtn.style.cssText = `
        background:rgba(40,60,100,0.6);
        border:1px solid rgba(100,140,255,0.3);
        border-radius:3px;
        color:#a0c0ff;
        cursor:pointer;
        font-size:11px;
        padding:2px 6px;
      `;
      playBtn.onclick = () => previewSfx(select.value);

      row.appendChild(labelEl);
      row.appendChild(select);
      row.appendChild(playBtn);
      sdSection.appendChild(row);
    }

    // Reset to defaults button
    const resetBtn = document.createElement('button');
    resetBtn.textContent = 'Reset to Defaults';
    resetBtn.style.cssText = `
      margin-top:8px;
      padding:5px 14px;
      background:rgba(80,30,30,0.5);
      border:1px solid rgba(200,80,80,0.4);
      border-radius:4px;
      color:#f0a0a0;
      cursor:pointer;
      font-family:'Courier New',monospace;
      font-size:10px;
    `;
    resetBtn.onclick = () => {
      resetSfxMap();
      renderSoundDesigner();
    };
    sdSection.appendChild(resetBtn);
  };

  renderSoundDesigner();
  card.appendChild(sdSection);

  // Dismiss
  const footer = document.createElement('div');
  footer.style.cssText = 'text-align:center;margin-top:20px;';
  const closeFullBtn = document.createElement('button');
  closeFullBtn.textContent = 'Close';
  closeFullBtn.setAttribute('aria-label', 'Close settings');
  closeFullBtn.style.cssText = `
    padding: 7px 28px;
    background: rgba(60,80,140,0.6);
    border: 1px solid rgba(100,140,255,0.3);
    border-radius: 5px;
    color: #a0c0ff;
    cursor: pointer;
    font-family: 'Courier New', monospace;
    font-size: 12px;
  `;
  closeFullBtn.onclick = () => { playSfx('ui.panel_close'); hideSettings(); };
  footer.appendChild(closeFullBtn);
  card.appendChild(footer);

  // Click backdrop or press Escape to close
  panel.addEventListener('click', (e) => {
    if (e.target === panel) hideSettings();
  });
  panel.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') hideSettings();
  });

  panel.appendChild(card);
  document.body.appendChild(panel);
}

// ── DOM helpers ───────────────────────────────────────────────────────────────

function sectionLabel(title: string): HTMLDivElement {
  const el = document.createElement('div');
  el.style.cssText = `
    font-size: 10px;
    color: #5060a0;
    letter-spacing: 0.1em;
    text-transform: uppercase;
    margin: 14px 0 8px;
    border-bottom: 1px solid rgba(100,120,200,0.15);
    padding-bottom: 4px;
  `;
  el.textContent = title;
  return el;
}

function sliderRow(
  label: string,
  initial: number,
  min: number,
  max: number,
  step: number,
  onChange: (v: number) => void,
  format?: (v: number) => string,
  tooltip?: string,
): HTMLDivElement {
  const row = document.createElement('div');
  row.style.cssText = 'display:flex;align-items:center;gap:10px;margin-bottom:8px;';
  if (tooltip) attachTooltip(row, tooltip);

  const labelEl = document.createElement('span');
  labelEl.style.cssText = 'flex:0 0 120px;font-size:11px;color:#8090b0;';
  labelEl.textContent = label;

  const input = document.createElement('input');
  input.type = 'range';
  input.min = String(min);
  input.max = String(max);
  input.step = String(step);
  input.value = String(initial);
  input.style.cssText = 'flex:1;accent-color:#6080d0;cursor:pointer;';

  const valEl = document.createElement('span');
  valEl.style.cssText = 'flex:0 0 40px;text-align:right;font-size:11px;color:#a0c0ff;';
  valEl.textContent = format ? format(initial) : initial.toFixed(2);

  input.oninput = () => {
    const v = parseFloat(input.value);
    valEl.textContent = format ? format(v) : v.toFixed(2);
    onChange(v);
  };

  row.appendChild(labelEl);
  row.appendChild(input);
  row.appendChild(valEl);
  return row;
}
