import type { BeltRegion } from '../shared/beltRegions';

/** Per-region visual config used by BeltRegionRenderer */
export interface BeltRegionVisual {
  /** Display name */
  name: string;
  /** Ambient light color [r, g, b] 0–1 */
  ambientColor: [number, number, number];
  /** Ambient light intensity */
  ambientIntensity: number;
  /** Nebula dust tint [r, g, b] 0–1 for ParallaxSkybox */
  nebulaTint: [number, number, number];
  /** Nebula tint strength 0–1 */
  nebulaStrength: number;
  /** Asteroid color bias [r, g, b] — blended subtly onto asteroid base color */
  asteroidColorBias: [number, number, number];
  /** Strength of asteroid color bias 0–1 */
  asteroidBiasStrength: number;
}

