/**
 * Base Buildings Panel
 *
 * Shows available building types with unlock status, costs, and a build button.
 * Toggled by the 🏭 Buildings HUD button (or V key).
 *
 * Uses show/hide pattern (panel element is created once and reused).
 * Registered with the window manager for z-index stacking and drag support.
 */

import { BUILDING_DEFS, BUILDING_TYPES, computeBuildingCostMultiplier } from '../sim/buildings';
import type { SerializedBuilding, BuildingType } from '../sim/buildings';
import type { SimBuildBuildingMessage } from '../sim/messages';
import { techBitmask } from '../sim/techTree';
import { registerHudButton } from './hudButtonBar';
import { makeDraggable, registerWindow } from './windowManager';

type WorkerSend = (msg: SimBuildBuildingMessage) => void;

let panel: HTMLDivElement | null = null;
let isOpen = false;
let workerSend: WorkerSend | null = null;

// Latest state from sim
let _rawStorage: Record<string, number> = {};
let _unlockedMask = 0n;
let _buildings: SerializedBuilding[] = [];

const BUILDING_ORDER = [
  BUILDING_TYPES.FACTORY,
  BUILDING_TYPES.SOLAR_PANEL,
  BUILDING_TYPES.RADIATOR,
  BUILDING_TYPES.SOLAR_FURNACE,
  BUILDING_TYPES.RTG_MODULE,
  BUILDING_TYPES.FISSION_REACTOR,
  BUILDING_TYPES.FUSION_REACTOR,
  BUILDING_TYPES.ENERGY_RELAY,
  BUILDING_TYPES.TURRET,
  BUILDING_TYPES.RELAY,
] as const;

export function initBaseBuildingsPanel(send: WorkerSend): void {
  workerSend = send;
  registerHudButton('🏭 Buildings', toggleBaseBuildingsPanel, 'Base Buildings');
}

export function updateBuildingsState(
  rawStorage: Record<string, number>,
  unlockedMask: bigint,
  buildings: SerializedBuilding[],
): void {
  _rawStorage = rawStorage;
  _unlockedMask = unlockedMask;
  _buildings = buildings;
  if (isOpen) renderPanel();
}

export function toggleBaseBuildingsPanel(): void {
  if (isOpen) {
    closePanel();
  } else {
    openPanel();
  }
}

function isUnlocked(buildingType: number): boolean {
  const def = BUILDING_DEFS[buildingType as keyof typeof BUILDING_DEFS];
  if (!def?.unlockTechId) return true;
  return (_unlockedMask & techBitmask(def.unlockTechId)) !== 0n;
}

function scaledCostEntries(buildingType: number): Array<[string, number]> {
  const def = BUILDING_DEFS[buildingType as keyof typeof BUILDING_DEFS];
  if (!def) return [];
  const existing = countBuilt(buildingType);
  const multiplier = computeBuildingCostMultiplier(buildingType as BuildingType, existing);
  return Object.entries(def.cost).map(([mat, amt]) => [mat, Math.ceil((amt ?? 0) * multiplier)]);
}

function canAfford(buildingType: number): boolean {
  for (const [mat, need] of scaledCostEntries(buildingType)) {
    if ((_rawStorage[mat] ?? 0) < need) return false;
  }
  return true;
}

function formatCost(buildingType: number): string {
  return scaledCostEntries(buildingType)
    .map(([mat, need]) => {
      const have = Math.floor(_rawStorage[mat] ?? 0);
      const ok = have >= need;
      return `<span style="color:${ok ? '#4aff4a' : '#ff4444'}">${need} ${mat} (${have})</span>`;
    })
    .join(', ');
}

function countBuilt(buildingType: number): number {
  return _buildings.filter((b) => b.type === buildingType).length;
}

function countActive(buildingType: number): number {
  return _buildings.filter((b) => b.type === buildingType && b.active).length;
}

function getOrCreatePanel(): HTMLDivElement {
  if (panel) return panel;

  panel = document.createElement('div');
  panel.id = 'base-buildings-panel';
  panel.style.cssText = `
    position: absolute;
    top: 40px;
    left: 50%;
    transform: translateX(-50%);
    width: 600px;
    max-height: 70vh;
    overflow-y: auto;
    background: rgba(5,10,20,0.97);
    border: 1px solid #f59e0b55;
    border-radius: 8px;
    padding: 0;
    font-family: 'Courier New', monospace;
    font-size: 12px;
    color: #ccc;
    pointer-events: auto;
    box-shadow: 0 0 40px rgba(0,0,0,0.9);
    opacity: 0;
    display: none;
    transition: opacity 0.2s ease-out;
  `;

  // Click delegation — handles close and build buttons without re-attaching listeners
  panel.addEventListener('click', (e: MouseEvent) => {
    const target = e.target as HTMLElement;
    if (target.closest('#buildings-close-btn')) {
      closePanel();
      return;
    }
    const buildBtn = target.closest<HTMLElement>('.buildings-build-btn');
    if (buildBtn) {
      const buildingType = parseInt(buildBtn.dataset['buildingType'] ?? '-1', 10);
      if (buildingType >= 0 && workerSend) {
        workerSend({ type: 'sim:build_building', payload: { buildingType } });
      }
    }
  });

  document.getElementById('hud-overlay')?.appendChild(panel);
  registerWindow('base-buildings', panel);
  makeDraggable(panel);
  return panel;
}

function openPanel(): void {
  isOpen = true;
  const p = getOrCreatePanel();
  renderPanel();
  p.style.display = 'block';
  requestAnimationFrame(() => {
    p.style.opacity = '1';
  });
}

function closePanel(): void {
  isOpen = false;
  if (panel) {
    const p = panel;
    p.style.opacity = '0';
    setTimeout(() => {
      p.style.display = 'none';
    }, 200);
  }
}

function renderPanel(): void {
  if (!panel) return;

  let html = `
    <div class="win-drag-handle" style="
      display:flex;justify-content:space-between;align-items:center;
      padding:12px 16px 10px;
      border-bottom:1px solid #f59e0b33;
      cursor:move;user-select:none;
    ">
      <h2 style="margin:0;color:#f59e0b;font-size:14px;letter-spacing:2px;">⚙ BASE BUILDINGS</h2>
      <button id="buildings-close-btn" style="
        background:none;border:1px solid #555;color:#aaa;
        padding:2px 8px;cursor:pointer;border-radius:3px;
        font-family:monospace;font-size:11px;
      " title="Close (F)">✕ close</button>
    </div>
    <div style="padding:16px;display:flex;flex-direction:column;gap:10px;">`;

  for (const buildingType of BUILDING_ORDER) {
    const def = BUILDING_DEFS[buildingType];
    const unlocked = isUnlocked(buildingType);
    const affordable = unlocked && canAfford(buildingType);
    const built = countActive(buildingType);
    const cardColor = !unlocked ? '#1a1a1a' : affordable ? '#0a1a0a' : '#1a0a0a';
    const borderColor = !unlocked ? '#333' : affordable ? '#f59e0b44' : '#66333344';

    html += `<div style="background:${cardColor};border:1px solid ${borderColor};border-radius:6px;padding:10px;">`;
    html += `<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px;">`;
    html += `<span style="color:${unlocked ? '#f59e0b' : '#555'};font-weight:bold;">${def.name}</span>`;
    if (built > 0) {
      html += `<span style="color:#4aff4a;font-size:11px;">✓ Built ×${built}</span>`;
    }
    html += `</div>`;

    html += `<div style="color:${unlocked ? '#6a8a6a' : '#444'};font-size:10px;margin-bottom:6px;">${def.description}</div>`;

    if (!unlocked) {
      html += `<div style="color:#555;font-style:italic;font-size:11px;">🔒 Requires: ${def.unlockTechId?.replace(/_/g, ' ') ?? 'unknown tech'}</div>`;
    } else {
      html += `<div style="margin-bottom:8px;font-size:11px;line-height:1.6;">${formatCost(buildingType)}</div>`;
      html += `<button data-building-type="${buildingType}" class="buildings-build-btn" style="
        width:100%;padding:4px 0;
        background:${affordable ? 'rgba(245,158,11,0.15)' : 'rgba(80,40,40,0.15)'};
        border:1px solid ${affordable ? '#f59e0b' : '#555'};
        color:${affordable ? '#f59e0b' : '#666'};
        border-radius:3px;cursor:${affordable ? 'pointer' : 'not-allowed'};
        font-family:monospace;font-size:11px;
      " ${affordable ? '' : 'disabled'}>
        ${affordable ? '+ Build' : 'Insufficient resources'}
      </button>`;
    }
    html += `</div>`;
  }

  html += `</div>`;
  panel.innerHTML = html;
}
