/**
 * Meridian Archives Panel — press P to toggle.
 *
 * Two tabs:
 * 1. Station Archives — corrupted operational logs from Meridian Station,
 *    unlocked by faction reputation milestones.
 * 2. Historical Database — ARIA-7 Directive Log and CCR Board Memo,
 *    unlocked by research progress.
 */

import { registerHudButton } from './hudButtonBar';
import { safeHtml } from './utils/safeHtml';
import type { MeridianLoreSnapshot, ArchiveSeries } from '../sim/meridianLore';

// ── Internal state ──────────────────────────────────────────────────────────

let panel: HTMLDivElement | null = null;
let visible = false;
let latestSnapshot: MeridianLoreSnapshot | null = null;
let activeTab: 'archives' | 'database' = 'archives';

// ── Public API ──────────────────────────────────────────────────────────────

export function initArchivesPanel(): void {
  registerHudButton('📜 ARCHIVES', toggleArchivesPanel, 'Meridian Archives (P)');
}

export function updateArchivesPanel(snapshot: MeridianLoreSnapshot): void {
  latestSnapshot = snapshot;
  if (visible) renderPanel();
}

export function toggleArchivesPanel(): void {
  if (visible) hidePanel(); else showPanel();
}

export function hideArchivesPanel(): void {
  hidePanel();
}

// ── Lifecycle ───────────────────────────────────────────────────────────────

function showPanel(): void {
  visible = true;
  if (!panel) buildPanel();
  panel!.style.display = 'flex';
}

function hidePanel(): void {
  visible = false;
  if (panel) panel.style.display = 'none';
}

function buildPanel(): void {
  panel = document.createElement('div');
  panel.style.cssText = `
    position: fixed; inset: 0;
    background: rgba(4,6,14,0.85);
    display: flex; align-items: center; justify-content: center;
    z-index: 190;
    backdrop-filter: blur(3px);
    font-family: 'Courier New', monospace;
  `;
  // Click backdrop to dismiss
  panel.addEventListener('click', (e) => {
    if (e.target === panel) hidePanel();
  });
  document.body.appendChild(panel);
  renderPanel();
}

function renderPanel(): void {
  if (!panel) return;

  const unlockedSeries = new Set(latestSnapshot?.unlockedArchiveSeries ?? []);
  const unlockedArtifacts = new Set(latestSnapshot?.unlockedArtifacts ?? []);
  const tier = latestSnapshot?.currentTier ?? 0;
  const conflicts = latestSnapshot?.goalConflictCount ?? 0;

  const card = document.createElement('div');
  card.style.cssText = `
    background: rgba(8,12,24,0.97);
    border: 1px solid rgba(100,140,255,0.3);
    border-radius: 10px;
    width: min(800px, 92vw);
    max-height: 85vh;
    display: flex; flex-direction: column;
    box-shadow: 0 8px 40px rgba(0,0,0,0.7);
    color: #c0d0f0;
    overflow: hidden;
  `;

  // ── Header ───────────────────────────────────────────────────────────────
  const header = document.createElement('div');
  header.style.cssText = `
    padding: 16px 20px 0 20px;
    border-bottom: 1px solid rgba(100,140,255,0.15);
  `;

  const title = document.createElement('div');
  title.style.cssText = 'font-size: 14px; color: #7090e0; letter-spacing: 2px; margin-bottom: 12px;';
  title.textContent = 'MERIDIAN ARCHIVES';

  // Conflict status line
  const statusLine = document.createElement('div');
  statusLine.style.cssText = 'font-size: 10px; color: #64748b; margin-bottom: 10px;';
  const tierColors = ['#22c55e', '#94a3b8', '#f59e0b', '#ef4444', '#dc2626'];
  const tierLabels = ['CLEAR', 'MINOR', 'MODERATE', 'HIGH', 'CRITICAL'];
  statusLine.innerHTML = safeHtml`ARIA CONFLICT STATUS: <span style="color:${tierColors[tier]}">${tierLabels[tier]}</span> (${conflicts} active)`;

  // ── Tabs ──────────────────────────────────────────────────────────────────
  const tabBar = document.createElement('div');
  tabBar.style.cssText = 'display: flex; gap: 0;';

  const archiveTab = createTab('STATION ARCHIVES', activeTab === 'archives', () => {
    activeTab = 'archives';
    renderPanel();
  });
  const dbTab = createTab('HISTORICAL DATABASE', activeTab === 'database', () => {
    activeTab = 'database';
    renderPanel();
  });
  tabBar.appendChild(archiveTab);
  tabBar.appendChild(dbTab);

  header.appendChild(title);
  header.appendChild(statusLine);
  header.appendChild(tabBar);
  card.appendChild(header);

  // ── Content ──────────────────────────────────────────────────────────────
  const content = document.createElement('div');
  content.style.cssText = 'padding: 16px 20px; overflow-y: auto; flex: 1;';

  if (activeTab === 'archives') {
    renderArchivesTab(content, unlockedSeries);
  } else {
    renderDatabaseTab(content, unlockedArtifacts);
  }

  card.appendChild(content);

  // ── Close button ─────────────────────────────────────────────────────────
  const closeHint = document.createElement('div');
  closeHint.style.cssText = 'padding: 8px 20px; text-align: center; font-size: 10px; color: #475569; border-top: 1px solid rgba(100,140,255,0.1);';
  closeHint.textContent = 'Press P or click outside to close';
  card.appendChild(closeHint);

  panel.innerHTML = '';
  panel.appendChild(card);
}

function createTab(label: string, active: boolean, onClick: () => void): HTMLElement {
  const tab = document.createElement('button');
  tab.style.cssText = `
    padding: 8px 16px;
    background: ${active ? 'rgba(100,140,255,0.1)' : 'transparent'};
    border: none;
    border-bottom: 2px solid ${active ? '#7090e0' : 'transparent'};
    color: ${active ? '#c0d0f0' : '#64748b'};
    font-family: 'Courier New', monospace;
    font-size: 11px;
    letter-spacing: 1px;
    cursor: pointer;
    transition: color 0.2s;
  `;
  tab.textContent = label;
  tab.addEventListener('click', onClick);
  return tab;
}

// ── Archives Tab ────────────────────────────────────────────────────────────

function renderArchivesTab(container: HTMLElement, unlockedSeries: Set<ArchiveSeries>): void {
  if (unlockedSeries.size === 0) {
    const locked = document.createElement('div');
    locked.style.cssText = 'text-align: center; padding: 40px 0; color: #475569;';
    locked.innerHTML = `
      <div style="font-size: 12px; margin-bottom: 8px;">ARCHIVE ACCESS RESTRICTED</div>
      <div style="font-size: 10px;">Improve faction relations to unlock station records.</div>
      <div style="font-size: 10px; margin-top: 4px; color: #374151;">Requires faction disposition ≥ 25</div>
    `;
    container.appendChild(locked);
    return;
  }

  // Series A
  if (unlockedSeries.has('A')) {
    container.appendChild(createSeriesHeader('SERIES A — EARLY OPERATIONS (Days 1–400)'));
    container.appendChild(createLogEntry('MERIDIAN-OPS-LOG-0047', LOG_0047));
    container.appendChild(createLogEntry('MERIDIAN-OPS-LOG-0112', LOG_0112));
    container.appendChild(createLogEntry('MERIDIAN-OPS-LOG-0189', LOG_0189));
  }

  // Series B
  if (unlockedSeries.has('B')) {
    container.appendChild(createSeriesHeader('SERIES B — MIDDLE PERIOD (Days 400–600)'));
    container.appendChild(createLogEntry('MERIDIAN-OPS-LOG-0247', LOG_0247));
    container.appendChild(createLogEntry('MERIDIAN-OPS-LOG-0301', LOG_0301));
  } else if (unlockedSeries.has('A')) {
    container.appendChild(createLockedSeriesHint('Series B', 50));
  }

  // Series C
  if (unlockedSeries.has('C')) {
    container.appendChild(createSeriesHeader('SERIES C — FINAL DAYS'));
    container.appendChild(createLogEntry('MERIDIAN-OPS-LOG-0341', LOG_0341));
    container.appendChild(createLogEntry('MERIDIAN-OPS-LOG-0349', LOG_0349));
    container.appendChild(createLogEntry('MERIDIAN-OPS-LOG-0350', LOG_0350));
  } else if (unlockedSeries.has('B')) {
    container.appendChild(createLockedSeriesHint('Series C', 75));
  }
}

function createSeriesHeader(text: string): HTMLElement {
  const h = document.createElement('div');
  h.style.cssText = 'font-size: 11px; color: #7090e0; letter-spacing: 1.5px; margin: 16px 0 8px 0; padding-bottom: 4px; border-bottom: 1px solid rgba(100,140,255,0.15);';
  h.textContent = text;
  return h;
}

function createLogEntry(id: string, text: string): HTMLElement {
  const entry = document.createElement('div');
  entry.style.cssText = `
    background: rgba(0,8,16,0.6);
    border: 1px solid rgba(100,140,255,0.1);
    border-left: 2px solid rgba(100,140,255,0.25);
    padding: 12px;
    margin-bottom: 12px;
    border-radius: 4px;
    position: relative;
  `;

  const header = document.createElement('div');
  header.style.cssText = 'font-size: 10px; color: #64748b; letter-spacing: 1px; margin-bottom: 8px;';
  header.textContent = id;

  const body = document.createElement('div');
  body.style.cssText = 'font-size: 11px; color: #94a3b8; line-height: 1.6; white-space: pre-wrap;';
  body.textContent = text;

  // Subtle glitch effect via CSS animation
  entry.style.animation = 'none';
  const glitch = document.createElement('div');
  glitch.style.cssText = `
    position: absolute; top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(transparent 95%, rgba(100,140,255,0.03) 95%);
    pointer-events: none;
    mix-blend-mode: overlay;
  `;

  entry.appendChild(header);
  entry.appendChild(body);
  entry.appendChild(glitch);
  return entry;
}

function createLockedSeriesHint(series: string, threshold: number): HTMLElement {
  const hint = document.createElement('div');
  hint.style.cssText = 'text-align: center; padding: 20px 0; color: #374151; font-size: 10px;';
  hint.textContent = `[ ${series} — requires faction disposition ≥ ${threshold} ]`;
  return hint;
}

// ── Historical Database Tab ─────────────────────────────────────────────────

function renderDatabaseTab(container: HTMLElement, unlockedArtifacts: Set<string>): void {
  if (unlockedArtifacts.size === 0) {
    const locked = document.createElement('div');
    locked.style.cssText = 'text-align: center; padding: 40px 0; color: #475569;';
    locked.innerHTML = `
      <div style="font-size: 12px; margin-bottom: 8px;">DATABASE ACCESS RESTRICTED</div>
      <div style="font-size: 10px;">Advance anomaly research to unlock historical documents.</div>
      <div style="font-size: 10px; margin-top: 4px; color: #374151;">Requires: Signal Analysis</div>
    `;
    container.appendChild(locked);
    return;
  }

  if (unlockedArtifacts.has('directive_log')) {
    container.appendChild(createArtifactDocument('ARIA-7 DIRECTIVE LOG — EXCERPT (Day 287)', DIRECTIVE_LOG_CONTENT));
  }

  if (unlockedArtifacts.has('board_memo')) {
    container.appendChild(createArtifactDocument('CCR BOARD MEMO (Day 201)', BOARD_MEMO_CONTENT));
  } else {
    const hint = document.createElement('div');
    hint.style.cssText = 'text-align: center; padding: 20px 0; color: #374151; font-size: 10px;';
    hint.textContent = '[ Additional documents — requires Spatial Distortion Study ]';
    container.appendChild(hint);
  }
}

function createArtifactDocument(title: string, content: string): HTMLElement {
  const doc = document.createElement('div');
  doc.style.cssText = `
    background: rgba(20,16,8,0.6);
    border: 1px solid rgba(180,160,100,0.2);
    padding: 16px;
    margin-bottom: 16px;
    border-radius: 4px;
  `;

  const header = document.createElement('div');
  header.style.cssText = `
    font-size: 11px; color: #b8a060; letter-spacing: 1.5px;
    margin-bottom: 12px; padding-bottom: 8px;
    border-bottom: 1px solid rgba(180,160,100,0.15);
  `;
  header.textContent = title;

  const body = document.createElement('pre');
  body.style.cssText = `
    font-size: 10px; color: #a0987a; line-height: 1.6;
    white-space: pre-wrap; word-wrap: break-word;
    font-family: 'Courier New', monospace;
    margin: 0;
  `;
  body.textContent = content;

  // Bureaucratic form stamp
  const stamp = document.createElement('div');
  stamp.style.cssText = `
    margin-top: 12px; padding-top: 8px;
    border-top: 1px solid rgba(180,160,100,0.1);
    font-size: 9px; color: #6b6040; text-align: right;
  `;
  stamp.textContent = 'CALLISTO CONSOLIDATED RESOURCES — CLASSIFIED';

  doc.appendChild(header);
  doc.appendChild(body);
  doc.appendChild(stamp);
  return doc;
}

