/**
 * Milestone Tracking — AST-31
 *
 * Tracks when resources cross significant thresholds (1K, 10K, 100K)
 * and celebrates achievements (first megastructure stage, tech tree, etc.).
 *
 * Call checkMilestones() each frame with current values.
 * Fires notifications via the provided callback.
 */

export interface MilestoneEvent {
  label: string;
  color: string;
  kind: 'resource' | 'achievement';
}

type NotifyFn = (label: string, color: string) => void;

// ── Resource milestones ───────────────────────────────────────────────────────

const RESOURCE_THRESHOLDS = [1_000, 10_000, 100_000, 1_000_000];

const RESOURCE_NAMES: Record<string, string> = {
  iron: 'Iron',
  carbon: 'Carbon',
  silicon: 'Silicon',
  water: 'Water',
  refined_iron: 'Refined Iron',
  steel: 'Steel',
  electronics: 'Electronics',
  battery_cell: 'Battery Cells',
};

// Track which (resource, threshold) pairs have already fired
const firedResourceMilestones = new Set<string>();

// ── Achievement tracking ──────────────────────────────────────────────────────

const firedAchievements = new Set<string>();

export interface AchievementInput {
  megastructureCompletedStages: Record<string, number>;
  techNodeCount: number;
  totalTechNodes: number;
  robotCount: number;
}

const ACHIEVEMENTS: Array<{
  id: string;
  label: string;
  check: (input: AchievementInput) => boolean;
}> = [
  {
    id: 'first_robot_army',
    label: '10 robots in the field',
    check: (i) => i.robotCount >= 10,
  },
  {
    id: 'robot_army_20',
    label: '20 robots deployed',
    check: (i) => i.robotCount >= 20,
  },
  {
    id: 'robot_army_50',
    label: '50 robot fleet achieved',
    check: (i) => i.robotCount >= 50,
  },
  {
    id: 'orbital_scaffold',
    label: 'Orbital Platform: Scaffold complete',
    check: (i) => (i.megastructureCompletedStages['orbital_platform'] ?? 0) >= 1,
  },
  {
    id: 'orbital_core',
    label: 'Orbital Platform: Core complete',
    check: (i) => (i.megastructureCompletedStages['orbital_platform'] ?? 0) >= 2,
  },
  {
    id: 'orbital_complete',
    label: 'Orbital Platform fully operational',
    check: (i) => (i.megastructureCompletedStages['orbital_platform'] ?? 0) >= 3,
  },
  {
    id: 'dyson_stage1',
    label: 'Dyson Swarm: First Collectors launched',
    check: (i) => (i.megastructureCompletedStages['dyson_swarm'] ?? 0) >= 1,
  },
  {
    id: 'half_tech',
    label: 'Half the tech tree researched',
    check: (i) => i.totalTechNodes > 0 && i.techNodeCount >= Math.floor(i.totalTechNodes / 2),
  },
  {
    id: 'full_tech',
    label: 'Full tech tree unlocked',
    check: (i) => i.totalTechNodes > 0 && i.techNodeCount >= i.totalTechNodes,
  },
];

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * Check resource storage values for crossed milestones.
 * @param resources Map of resource name → current amount
 * @param notify Callback to fire notifications
 */
export function checkResourceMilestones(resources: Record<string, number>, notify: NotifyFn): void {
  for (const [key, amount] of Object.entries(resources)) {
    for (const threshold of RESOURCE_THRESHOLDS) {
      if (amount >= threshold) {
        const milestoneId = `${key}:${threshold}`;
        if (!firedResourceMilestones.has(milestoneId)) {
          firedResourceMilestones.add(milestoneId);
          const name = RESOURCE_NAMES[key] ?? key;
          const label = thresholdLabel(threshold);
          notify(`◈ ${name} stockpile reached ${label}`, '#22c55e');
        }
      }
    }
  }
}

/**
 * Check achievement conditions.
 * @param input Current game state
 * @param notify Callback to fire notifications
 */
export function checkAchievements(input: AchievementInput, notify: NotifyFn): void {
  for (const ach of ACHIEVEMENTS) {
    if (!firedAchievements.has(ach.id) && ach.check(input)) {
      firedAchievements.add(ach.id);
      notify(`★ Achievement: ${ach.label}`, '#fbbf24');
    }
  }
}

/**
 * Pre-populate resource milestones from current stockpile so already-crossed
 * thresholds don't re-fire notifications on load.
 */
export function seedResourceMilestones(resources: Record<string, number>): void {
  for (const [key, amount] of Object.entries(resources)) {
    for (const threshold of RESOURCE_THRESHOLDS) {
      if (amount >= threshold) {
        firedResourceMilestones.add(`${key}:${threshold}`);
      }
    }
  }
}

/**
 * Pre-populate achievements from current game state so already-earned
 * achievements don't re-fire notifications on load.
 */
export function seedAchievements(input: AchievementInput): void {
  for (const ach of ACHIEVEMENTS) {
    if (ach.check(input)) {
      firedAchievements.add(ach.id);
    }
  }
}

/**
 * Reset all milestone tracking (called on new game).
 */
export function resetMilestones(): void {
  firedResourceMilestones.clear();
  firedAchievements.clear();
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function thresholdLabel(n: number): string {
  if (n >= 1_000_000) return `${n / 1_000_000}M`;
  if (n >= 1_000) return `${n / 1_000}K`;
  return String(n);
}
