/**
 * Renders small colored markers above asteroids claimed by factions or
 * targeted by the player for mining.
 *
 * Faction claims: colored sphere matching faction color.
 * Player targets: cyan diamond marker.
 */
import {
  Color,
  Mesh,
  MeshBasicMaterial,
  OctahedronGeometry,
  Scene,
  SphereGeometry,
} from 'three';
import {
  ASTEROID_STRIDE,
  ASTEROID_OFF_EID,
  ASTEROID_OFF_X,
  ASTEROID_OFF_Y,
  ASTEROID_OFF_Z,
  ASTEROID_OFF_RADIUS,
} from '../sim/bufferLayout';

const MAX_FACTION_MARKERS = 10;
const MAX_PLAYER_MARKERS = 20;
const MARKER_Y_OFFSET = 6;

export class ClaimMarkerRenderer {
  private scene: Scene;
  private factionMarkers: Mesh[] = [];
  private factionMaterials: MeshBasicMaterial[] = [];
  private playerMarkers: Mesh[] = [];
  private playerMaterial: MeshBasicMaterial;

  constructor(scene: Scene) {
    this.scene = scene;

    // Pre-create faction marker meshes (reusable pool)
    const sphereGeo = new SphereGeometry(1.5, 8, 6);
    for (let i = 0; i < MAX_FACTION_MARKERS; i++) {
      const mat = new MeshBasicMaterial({ color: 0xff0000, transparent: true, opacity: 0.85 });
      const mesh = new Mesh(sphereGeo, mat);
      mesh.visible = false;
      scene.add(mesh);
      this.factionMarkers.push(mesh);
      this.factionMaterials.push(mat);
    }

    // Pre-create player target marker meshes
    const diamondGeo = new OctahedronGeometry(2, 0);
    this.playerMaterial = new MeshBasicMaterial({ color: 0x22d3ee, transparent: true, opacity: 0.8 });
    for (let i = 0; i < MAX_PLAYER_MARKERS; i++) {
      const mesh = new Mesh(diamondGeo, this.playerMaterial);
      mesh.visible = false;
      scene.add(mesh);
      this.playerMarkers.push(mesh);
    }
  }

  update(
    asteroidBuffer: Float64Array | null,
    asteroidCount: number,
    factionClaims: Array<{ factionId: number; asteroidEid: number; color: string }>,
    playerTargetAsteroids: number[],
    elapsed: number,
  ): void {
    // Hide all markers first
    for (const m of this.factionMarkers) m.visible = false;
    for (const m of this.playerMarkers) m.visible = false;

    if (!asteroidBuffer || asteroidCount === 0) return;

    // Build a quick lookup of asteroid EID → position
    const needEids = new Set<number>();
    for (const c of factionClaims) needEids.add(c.asteroidEid);
    for (const eid of playerTargetAsteroids) needEids.add(eid);

    if (needEids.size === 0) return;

    const eidPos = new Map<number, { x: number; y: number; z: number; r: number }>();
    for (let i = 0; i < asteroidCount; i++) {
      const off = i * ASTEROID_STRIDE;
      const eid = asteroidBuffer[off + ASTEROID_OFF_EID];
      if (needEids.has(eid)) {
        eidPos.set(eid, {
          x: asteroidBuffer[off + ASTEROID_OFF_X],
          y: asteroidBuffer[off + ASTEROID_OFF_Y],
          z: asteroidBuffer[off + ASTEROID_OFF_Z],
          r: asteroidBuffer[off + ASTEROID_OFF_RADIUS],
        });
      }
    }

    // Position faction markers
    let fi = 0;
    for (const claim of factionClaims) {
      if (fi >= MAX_FACTION_MARKERS) break;
      const pos = eidPos.get(claim.asteroidEid);
      if (!pos) continue;
      const marker = this.factionMarkers[fi];
      const mat = this.factionMaterials[fi];
      mat.color.set(claim.color);
      marker.position.set(pos.x, pos.y + pos.r + MARKER_Y_OFFSET, pos.z);
      marker.visible = true;
      fi++;
    }

    // Position player target markers (with pulse animation)
    const pulse = 1 + 0.3 * Math.abs(Math.sin(elapsed * 2));
    let pi = 0;
    for (const eid of playerTargetAsteroids) {
      if (pi >= MAX_PLAYER_MARKERS) break;
      const pos = eidPos.get(eid);
      if (!pos) {
        // Asteroid no longer in buffer (depleted) — remove from list
        continue;
      }
      const marker = this.playerMarkers[pi];
      marker.position.set(pos.x, pos.y + pos.r + MARKER_Y_OFFSET, pos.z);
      marker.rotation.y = elapsed * 2;
      marker.scale.setScalar(pulse);
      marker.visible = true;
      pi++;
    }
  }

  dispose(): void {
    for (const m of this.factionMarkers) {
      this.scene.remove(m);
      m.geometry.dispose();
      (m.material as MeshBasicMaterial).dispose();
    }
    for (const m of this.playerMarkers) {
      this.scene.remove(m);
      m.geometry.dispose();
    }
    this.playerMaterial.dispose();
  }
}
