/**
 * Achievement handlers: listens to existing worker messages and
 * triggers achievement unlocks in the AchievementService.
 */
import type {
  WorkerToMainMessage,
  SimBuildingBuiltMessage,
  SimBaseBuiltMessage,
  SimTechStateMessage,
  SimFactionStateMessage,
  SimCultureTraitActivatedMessage,
  SimRobotProducedMessage,
  SimEventMessage,
  SimNarrativeEventMessage,
} from '../sim/messages';
import { ACHIEVEMENT } from '../achievements/definitions';
import type { AchievementService } from '../achievements/AchievementService';
import type { HandlerMap } from './types';
import { ROBOT_TYPES } from '../sim/robotProfiles';

/**
 * Achievement-specific mutable state to track first-occurrence events
 * within a session (localStorage dedup handles cross-session).
 */
interface AchievementState {
  sawFactionContact: boolean;
  sawAlliance: boolean;
  sawMegastructure: boolean;
  sawAsteroidCharted: boolean;
}

export function registerAchievementHandlers(
  achievements: AchievementService,
): { handlers: HandlerMap; state: AchievementState } {
  const achState: AchievementState = {
    sawFactionContact: false,
    sawAlliance: false,
    sawMegastructure: false,
    sawAsteroidCharted: false,
  };

  const handlers: HandlerMap = {
    'sim:building_built': (msg: WorkerToMainMessage) => {
      const bMsg = msg as SimBuildingBuiltMessage;
      if (bMsg.payload.success) {
        void achievements.unlock(ACHIEVEMENT.FIRST_BUILDING, {
          buildingType: bMsg.payload.buildingType,
        });
      }
    },

    'sim:base_built': (msg: WorkerToMainMessage) => {
      const builtMsg = msg as SimBaseBuiltMessage;
      if (builtMsg.payload.ok) {
        void achievements.unlock(ACHIEVEMENT.FIRST_BASE);
      }
    },

    'sim:robot_produced': (msg: WorkerToMainMessage) => {
      const rMsg = msg as SimRobotProducedMessage;
      void achievements.unlock(ACHIEVEMENT.FIRST_ROBOT);

      // FIRST_MINE: first miner robot deployed
      if (rMsg.payload.robotType === ROBOT_TYPES.MINER) {
        void achievements.unlock(ACHIEVEMENT.FIRST_MINE);
      }

      // FIRST_REFINERY: first refiner robot deployed
      if (rMsg.payload.robotType === ROBOT_TYPES.REFINER) {
        void achievements.unlock(ACHIEVEMENT.FIRST_REFINERY);
      }
    },

    'sim:tech_state': (msg: WorkerToMainMessage) => {
      const techMsg = msg as SimTechStateMessage;
      if (techMsg.payload.justUnlocked) {
        void achievements.unlock(ACHIEVEMENT.FIRST_RESEARCH, {
          nodeId: techMsg.payload.justUnlocked,
        });
      }
    },

    'sim:faction_state': (msg: WorkerToMainMessage) => {
      const fMsg = msg as SimFactionStateMessage;
      if (!fMsg.payload.factions || fMsg.payload.factions.length === 0) return;

      // FIRST_FACTION_CONTACT: first time a faction with non-neutral disposition appears
      if (!achState.sawFactionContact) {
        const hasContact = fMsg.payload.factions.some((f) =>
          f.disposition < -20 || f.disposition > 20,
        );
        if (hasContact) {
          achState.sawFactionContact = true;
          void achievements.unlock(ACHIEVEMENT.FIRST_FACTION_CONTACT);
        }
      }

      // FIRST_ALLIANCE: a faction reaches Allied disposition (> 60)
      if (!achState.sawAlliance) {
        const ally = fMsg.payload.factions.find((f) => f.disposition > 60);
        if (ally) {
          achState.sawAlliance = true;
          void achievements.unlock(ACHIEVEMENT.FIRST_ALLIANCE, {
            factionName: ally.name,
          });
        }
      }
    },

    'sim:culture_trait_activated': (_msg: WorkerToMainMessage) => {
      void achievements.unlock(ACHIEVEMENT.CULTURE_TRAIT);
    },

    'sim:megastructure_state': (msg: WorkerToMainMessage) => {
      if (achState.sawMegastructure) return;
      const payload = (msg as { payload: { projects?: Array<{ completedStages: number }> } }).payload;
      if (payload.projects && payload.projects.some((p) => p.completedStages > 0)) {
        achState.sawMegastructure = true;
        void achievements.unlock(ACHIEVEMENT.MEGASTRUCTURE_STARTED);
      }
    },

    'sim:event': (msg: WorkerToMainMessage) => {
      const evt = msg as SimEventMessage;
      if (evt.payload.kind === 'anomaly_discovered') {
        // FIRST_ASTEROID_CHARTED: charting the asteroid where an anomaly was found
        if (!achState.sawAsteroidCharted) {
          achState.sawAsteroidCharted = true;
          void achievements.unlock(ACHIEVEMENT.FIRST_ASTEROID_CHARTED, {
            asteroidEid: evt.payload.asteroidEid,
          });
        }

        // ANOMALY_DISCOVERED
        void achievements.unlock(ACHIEVEMENT.ANOMALY_DISCOVERED, {
          anomalyType: evt.payload.anomalyType,
          asteroidEid: evt.payload.asteroidEid,
        });
      }
    },

    'sim:narrative_event': (msg: WorkerToMainMessage) => {
      const nevt = msg as SimNarrativeEventMessage;
      // DYSON_COMPLETE: the ending narrative event carries endScreenStats
      if (nevt.payload.endScreenStats) {
        void achievements.unlock(ACHIEVEMENT.DYSON_COMPLETE);
      }
    },
  };

  return { handlers, state: achState };
}
