/**
 * Faction Definitions
 *
 * Constants, type definitions, state shapes, and factory functions for the faction system.
 */

export const FACTION_IDS = { HELIX: 0, ASTRAL: 1, VANGUARD: 2, CERES: 3, TITAN: 4, KUIPER: 5 } as const;
export type FactionId = 0 | 1 | 2 | 3 | 4 | 5;
export const FACTION_COUNT = 6;

/** Disposition: -100 (Hostile) … 0 (Neutral) … +100 (Allied) */
export type Disposition = number;

export const DISPOSITION_LABELS: Record<string, string> = {
  hostile: 'Hostile',
  wary: 'Wary',
  neutral: 'Neutral',
  friendly: 'Friendly',
  allied: 'Allied',
};

export function dispositionLabel(d: Disposition): string {
  if (d <= -60) return 'Hostile';
  if (d <= -20) return 'Wary';
  if (d <= 20) return 'Neutral';
  if (d <= 60) return 'Friendly';
  return 'Allied';
}

