// ── Faction state ──────────────────────────────────────────────────────────────

export interface FactionBase {
  x: number;
  y: number;
  z: number;
}

export interface FactionState {
  id: FactionId;
  base: FactionBase;
  resources: { iron: number; carbon: number; silicon: number };
  robotCount: number;
  disposition: Disposition;
  /** Current strategic goal */
  goal: 'mine' | 'expand' | 'study_anomaly' | 'idle';
  /** Asteroid eid currently being mined by this faction (-1 if none) */
  contestingAsteroid: number;
  /** Ticks until next AI decision */
  decisionTimer: number;
  /** Ring of territory claim radius around base (world units) */
  territoryRadius: number;
  /** Recent event messages for the player log */
  recentEvents: Array<{ text: string; tick: number }>;
  /** Last tick a disposition event was fired (cooldown) */
  lastDispositionEventTick: number;
  /** Active trade window, or null if none */
  tradeWindow: FactionTradeWindow | null;
  /** Last tick a trade window was opened (cooldown) */
  lastTradeWindowTick: number;
}

/**
 * Key for a pair of factions (always low-high order).
 * e.g. "0-1" = Helix↔Astral, "0-2" = Helix↔Vanguard, etc.
 */
export type FactionPairKey = `${number}-${number}`;

export function factionPairKey(a: FactionId, b: FactionId): FactionPairKey {
  const lo = Math.min(a, b) as FactionId;
  const hi = Math.max(a, b) as FactionId;
  return `${lo}-${hi}` as FactionPairKey;
}

/** Generate all faction pair keys */
export function generateAllFactionPairs(): FactionPairKey[] {
  const pairs: FactionPairKey[] = [];
  for (let i = 0; i < FACTION_COUNT; i++) {
    for (let j = i + 1; j < FACTION_COUNT; j++) {
      pairs.push(`${i}-${j}` as FactionPairKey);
    }
  }
  return pairs;
}

export const ALL_FACTION_PAIRS: FactionPairKey[] = generateAllFactionPairs();

export interface FactionSystemState {
  factions: FactionState[];
  initialized: boolean;
  /** Pairwise disposition between factions (-100 Hostile … +100 Allied) */
  interFactionDispositions: Record<FactionPairKey, number>;
  /** Tick of last border dispute message per faction pair (rate-limiting) */
  lastDisputeTick: Record<FactionPairKey, number>;
  /** Disposition at last broadcast — used to compute delta for UI flash */
  lastBroadcastDispositions: number[];
}

// ── Construction ───────────────────────────────────────────────────────────────

/**
 * Place the three faction bases evenly around the asteroid belt.
 * Offset by ~120° from each other and positioned at mid-belt radius.
 */
export function makeDefaultPairRecord<T>(value: T): Record<FactionPairKey, T> {
  const rec: Record<string, T> = {};
  for (const key of ALL_FACTION_PAIRS) rec[key] = value;
  return rec as Record<FactionPairKey, T>;
}

export function createFactionSystem(
  beltInnerRadius: number,
  beltOuterRadius: number,
): FactionSystemState {
  const midR = (beltInnerRadius + beltOuterRadius) * 0.55; // slightly outer belt
  // Space factions evenly around the belt (360° / FACTION_COUNT)
  const angleStep = (2 * Math.PI) / FACTION_COUNT;
  const angleOffset = Math.PI / 3; // start at ~60°

  const factions: FactionState[] = FACTION_DEFS.map((def, i) => {
    const angle = angleOffset + i * angleStep;
    return {
      id: def.id,
      base: {
        x: Math.cos(angle) * midR,
        y: 0,
        z: Math.sin(angle) * midR,
      },
      resources: { iron: 500, carbon: 200, silicon: 150 },
      robotCount: 5 + def.id * 2,
      disposition: 0, // start Neutral
      goal: 'mine' as const,
      contestingAsteroid: -1,
      decisionTimer: 60 * (10 + def.id * 7), // stagger initial decisions
      territoryRadius: 8000 + (def.id % 3) * 2000,
      recentEvents: [],
      lastDispositionEventTick: -Infinity,
      tradeWindow: null,
      lastTradeWindowTick: -Infinity,
    };
  });

  return {
    factions,
    initialized: true,
    interFactionDispositions: makeDefaultPairRecord(0),
    lastDisputeTick: makeDefaultPairRecord(-Infinity),
    lastBroadcastDispositions: factions.map((f) => f.disposition),
  };
}

// ── Tick parameter types ───────────────────────────────────────────────────────

export interface FactionTickParams {
  tick: number;
  asteroidEntities: number[];
  getAsteroidPos: (eid: number) => { x: number; y: number; z: number };
  getAsteroidHealth: (eid: number) => number;
  damageAsteroid: (eid: number, amount: number) => void;
  playerBasePos: { x: number; y: number; z: number };
  playerRobotPositions: Array<{ x: number; y: number; z: number }>;
  rng: () => number;
  /** Difficulty-based multiplier for territorial hostility (default 1). */
  aggressionMultiplier?: number;
  /** When true, silence_protocol isolation trait is active — reduces faction detection. */
  silenceProtocolActive?: boolean;
}

/** A border dispute event to surface to the player via inbox */
export interface BorderDispute {
  factionA: FactionId;
  factionB: FactionId;
  atWar: boolean;
  disposition: number;
}

