/**
 * Colony Epithet Modal
 *
 * Late-game naming prompt shown when the Dyson Sphere reaches ≥25% completion.
 * Asks the player to choose an epithet for their colony.
 */

import { COLONY_EPITHET_MAX_LENGTH } from '../sim/culture';
import { trapFocus } from './focusTrap';
import { safeHtml } from './utils/safeHtml';

let overlay: HTMLDivElement | null = null;
let removeFocusTrap: (() => void) | null = null;
let prompted = false;

/** Whether the colony epithet prompt has been shown this session. */
export function hasColonyEpithetBeenPrompted(): boolean {
  return prompted;
}

/** Reset state (for save/load). */
export function resetColonyEpithetModalState(): void {
  prompted = false;
}

export function showColonyEpithetModal(
  onSubmit: (epithet: string) => void,
): void {
  if (overlay) return;
  prompted = true;

  const color = '#a855f7'; // revelation purple — matches Dyson/endgame theme

  overlay = document.createElement('div');
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.85);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 2000;
    font-family: 'Courier New', monospace;
    opacity: 0;
    transition: opacity 0.5s ease;
  `;
  document.body.appendChild(overlay);
  requestAnimationFrame(() => {
    if (overlay) overlay.style.opacity = '1';
  });

  const modal = document.createElement('div');
  modal.setAttribute('role', 'dialog');
  modal.setAttribute('aria-label', 'Colony Epithet');
  modal.setAttribute('aria-modal', 'true');
  modal.setAttribute('tabindex', '-1');
  modal.style.cssText = `
    background: rgba(0, 4, 12, 0.98);
    border: 1px solid ${color};
    box-shadow: 0 0 60px ${color}22, inset 0 0 40px rgba(0,0,0,0.6);
    color: #e2e8f0;
    max-width: 460px;
    width: 90vw;
    padding: 36px 32px;
    border-radius: 2px;
    position: relative;
  `;

  modal.innerHTML = safeHtml`
    <div style="font-size:9px; color:${color}; opacity:0.7; text-transform:uppercase; letter-spacing:3px; margin-bottom:6px;">
      ARIA — COLONY LEGACY
    </div>
    <div style="font-size:18px; font-weight:bold; color:${color}; margin-bottom:16px; letter-spacing:1px;">
      Colony Epithet
    </div>
    <p style="margin:0 0 20px; line-height:1.7; color:#94a3b8; font-size:12px;">
      Some colonies become legendary. The Dyson Swarm grows, and with it your place in history. What will yours be known for?
    </p>
    <input id="epithet-input" type="text" maxlength="${COLONY_EPITHET_MAX_LENGTH}" placeholder="e.g. The Unyielding, Starforgers..." style="
      width: 100%;
      background: rgba(0,0,0,0.4);
      border: 1px solid ${color}44;
      border-radius: 2px;
      color: #e2e8f0;
      font-family: 'Courier New', monospace;
      font-size: 14px;
      padding: 12px;
      outline: none;
      box-sizing: border-box;
      letter-spacing: 0.5px;
    " />
    <div style="display:flex; justify-content:space-between; align-items:center; margin-top:12px;">
      <span id="epithet-count" style="font-size:10px; color:#475569;">0/${COLONY_EPITHET_MAX_LENGTH}</span>
      <div style="display:flex; gap:12px;">
        <button id="epithet-skip" style="
          background:none; border:none; color:#475569; cursor:pointer;
          font-family:'Courier New',monospace; font-size:10px; text-transform:uppercase; letter-spacing:1px;
        ">Skip</button>
        <button id="epithet-submit" style="
          background: transparent;
          border: 1px solid ${color}88;
          color: ${color};
          font-family: 'Courier New', monospace;
          font-size: 11px;
          padding: 6px 18px;
          cursor: pointer;
          border-radius: 2px;
          letter-spacing: 1px;
          text-transform: uppercase;
          transition: background 0.2s;
        ">Claim Epithet</button>
      </div>
    </div>
  `;

  overlay.appendChild(modal);
  removeFocusTrap = trapFocus(modal);

  const input = modal.querySelector<HTMLInputElement>('#epithet-input')!;
  const charCount = modal.querySelector<HTMLSpanElement>('#epithet-count')!;
  const submitBtn = modal.querySelector<HTMLButtonElement>('#epithet-submit')!;
  const skipBtn = modal.querySelector<HTMLButtonElement>('#epithet-skip')!;

  input.addEventListener('input', () => {
    charCount.textContent = `${input.value.length}/${COLONY_EPITHET_MAX_LENGTH}`;
  });

  submitBtn.addEventListener('click', () => {
    const epithet = input.value.trim();
    if (epithet.length > 0) {
      onSubmit(epithet);
    }
    closeModal();
  });

  submitBtn.addEventListener('mouseover', () => {
    submitBtn.style.background = `${color}22`;
  });
  submitBtn.addEventListener('mouseout', () => {
    submitBtn.style.background = 'transparent';
  });

  skipBtn.addEventListener('click', closeModal);

  input.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') {
      const epithet = input.value.trim();
      if (epithet.length > 0) {
        onSubmit(epithet);
      }
      closeModal();
    }
  });

  // Auto-focus the input
  requestAnimationFrame(() => input.focus());
}

function closeModal(): void {
  if (!overlay) return;
  removeFocusTrap?.();
  removeFocusTrap = null;
  overlay.style.opacity = '0';
  const ref = overlay;
  setTimeout(() => ref.remove(), 500);
  overlay = null;
}
