import {
  listSaves,
  readSaveResult,
  hasSaves,
} from '../sim/saveLoad';
import type { SaveData } from '../sim/saveLoad';
import { makeButton, makeSmallButton, showToast } from './menuHelpers';
import { safeHtml } from './utils/safeHtml';

/** Show the load screen on game start if saves exist. */
export function maybeShowLoadScreen(onLoad: (data: SaveData) => void, onNewGame: () => void): void {
  if (!hasSaves()) {
    onNewGame();
    return;
  }

  const overlay = document.createElement('div');
  overlay.setAttribute('role', 'dialog');
  overlay.setAttribute('aria-label', 'Load saved game');
  overlay.setAttribute('aria-modal', 'true');
  overlay.style.cssText = `
    position: fixed;
    top: 0; left: 0;
    width: 100%; height: 100%;
    background: rgba(0,5,0,0.97);
    z-index: 2000;
    display: flex;
    align-items: center;
    justify-content: center;
    font-family: 'Courier New', monospace;
    color: #aaffaa;
  `;

  const panel = document.createElement('div');
  panel.style.cssText = `
    background: rgba(0,10,0,0.95);
    border: 1px solid #4aff4a;
    border-radius: 8px;
    padding: 32px;
    min-width: 420px;
  `;

  // Logo block
  const logoWrap = document.createElement('div');
  logoWrap.style.cssText = 'text-align:center;margin-bottom:20px;';
  const logo = document.createElement('div');
  logo.style.cssText = `
    font-family: 'Courier New', monospace;
    font-size: 11px;
    color: #4aff4a;
    letter-spacing: 0.05em;
    line-height: 1.2;
    white-space: pre;
    text-shadow: 0 0 8px rgba(74,255,74,0.5);
  `;
  logo.textContent = ['★ CULTURES OF THE BELT ★'].join('\n');
  logoWrap.appendChild(logo);

  const tagline = document.createElement('div');
  tagline.style.cssText =
    'font-size:10px;color:#3a7a3a;letter-spacing:2px;margin-top:6px;text-transform:uppercase;';
  tagline.textContent = 'Hard Sci-Fi 4X Mining Sim';
  logoWrap.appendChild(tagline);

  const ver = document.createElement('div');
  ver.style.cssText = 'font-size:9px;color:#2a4a2a;margin-top:3px;';
  ver.textContent = `v${__APP_VERSION__}`;
  logoWrap.appendChild(ver);

  panel.appendChild(logoWrap);

  const subtitle = document.createElement('div');
  subtitle.style.cssText = 'font-size: 12px; color: #888; margin-bottom: 20px; text-align: center;';
  subtitle.textContent = 'Continue a previous game?';
  panel.appendChild(subtitle);

  // Show saves
  const saves = listSaves();
  for (const meta of saves) {
    const row = document.createElement('div');
    row.style.cssText = `
      display: flex;
      align-items: center;
      gap: 12px;
      margin-bottom: 10px;
      padding: 10px;
      border: 1px solid #1a4a1a;
      border-radius: 4px;
      cursor: pointer;
    `;
    const date = new Date(meta.timestamp).toLocaleString();
    const label = document.createElement('div');
    label.style.cssText = 'flex: 1; font-size: 12px;';
    label.innerHTML = safeHtml`<div style="color:#4aff4a">${meta.label}</div><div style="color:#888;font-size:11px">${date}</div><div style="color:#aaa;font-size:11px">Tick ${meta.tick} · ${meta.robotCount} robots · ${meta.asteroidCount} asteroids</div>`;
    row.appendChild(label);

    const loadBtn = makeSmallButton('LOAD', () => {
      const result = readSaveResult(meta.slot);
      if (!result.data) {
        const detail = result.parseError
          ? 'JSON parse error — file may be truncated'
          : 'Core save fields missing — cannot recover';
        showToast(`Save corrupt: ${detail}`);
        return;
      }
      if (result.recovered.length > 0) {
        console.warn(
          `[saveLoad] Partial recovery for slot ${meta.slot}: defaulted ${result.recovered.join(', ')}`,
        );
        showToast(`Warning: save partially recovered (missing: ${result.recovered.join(', ')})`);
      }
      overlay.remove();
      onLoad(result.data);
    });
    row.appendChild(loadBtn);
    panel.appendChild(row);
  }

  const sep = document.createElement('hr');
  sep.style.cssText = 'border-color: #1a4a1a; margin: 20px 0;';
  panel.appendChild(sep);

  const newBtn = makeButton('NEW GAME', '#888', () => {
    overlay.remove();
    onNewGame();
  });
  panel.appendChild(newBtn);

  overlay.appendChild(panel);
  document.body.appendChild(overlay);
}
