/**
 * Anomaly Archive — press J to toggle.
 *
 * Personal Belt lore collection: discovered fragments organized by anomaly,
 * study stage progress, discovery chain visualization, player annotations,
 * and an undiscovered-anomaly tease.
 *
 * Drives 4 (Ownership) + 7 (Curiosity) — no timers, no pressure.
 */

import { LORE_FRAGMENTS, STUDY_STAGES } from '../sim/anomalyStudy';
import type { StudyStage } from '../sim/anomalyStudy';
import { ANOMALY_TYPE_NAMES as ANOMALY_NAMES, ANOMALY_COLORS } from '../sim/anomalyTypes';
import { escapeHtml, safeHtml } from './utils/safeHtml';

const STAGE_NAMES: Record<number, string> = {
  1: 'DISCOVERED',
  2: 'SCANNING',
  3: 'ANALYZED',
  4: 'UNDERSTOOD',
};

/** Total number of anomaly types in the game */
const TOTAL_ANOMALY_TYPES = 7;

/** Discovery chains: arrays of anomaly types that form a narrative thread */
const CHAINS: number[][] = [
  [1, 2, 3], // Strange Mineral → Structured Signal → Spatial Distortion
  [4, 5],    // Geometric Void → Biological Trace
  [6, 7],    // Gravitational Anomaly → Convergence Point
];

const ANNOTATION_STORAGE_KEY = 'asteroid_miner_annotations';
const ANNOTATION_MAX_LENGTH = 140;

export interface CodexEntry {
  anomalyType: number;
  asteroidEid: number;
  stage: StudyStage;
  progress: number;
  revealedFragments: number[];
}

// ── Internal state ──────────────────────────────────────────────────────────

let panel: HTMLDivElement | null = null;
let visible = false;
const entries = new Map<number, CodexEntry>(); // asteroidEid → entry
/** Revelations collected (chain completions) */
const revelations: string[] = [];
/** Player annotations keyed by anomaly type */
let annotations: Record<number, string> = loadAnnotations();
/** Discovery ticks keyed by asteroidEid — populated externally */
const discoveryTicks = new Map<number, number>();
/** Whether the first-understood milestone has fired */
let firstUnderstoodFired = false;

// ── Annotation persistence ──────────────────────────────────────────────────

function loadAnnotations(): Record<number, string> {
  try {
    const json = localStorage.getItem(ANNOTATION_STORAGE_KEY);
    if (!json) return {};
    return JSON.parse(json) as Record<number, string>;
  } catch {
    return {};
  }
}

function saveAnnotations(): void {
  try {
    localStorage.setItem(ANNOTATION_STORAGE_KEY, JSON.stringify(annotations));
  } catch {
    // quota exceeded — silently ignore
  }
}

// ── Testable logic (exported for unit tests) ────────────────────────────────

export interface ArchiveAnomalyGroup {
  anomalyType: number;
  name: string;
  color: string;
  stageLabel: string;
  highestStage: number;
  revealedCount: number;
  totalFragments: number;
  discoveryTick: number | null;
}

/** Build grouped anomaly data from current entries (pure, testable) */
export function buildAnomalyGroups(
  entryMap: ReadonlyMap<number, CodexEntry>,
  tickMap: ReadonlyMap<number, number>,
): ArchiveAnomalyGroup[] {
  const byType = new Map<number, CodexEntry[]>();
  for (const entry of entryMap.values()) {
    if (!byType.has(entry.anomalyType)) byType.set(entry.anomalyType, []);
    byType.get(entry.anomalyType)!.push(entry);
  }

  const groups: ArchiveAnomalyGroup[] = [];
  for (const [anomalyType, typeEntries] of byType) {
    const revealedIndices = new Set<number>();
    let highestStage = 0;
    let earliestTick: number | null = null;
    for (const e of typeEntries) {
      for (const fi of e.revealedFragments) revealedIndices.add(fi);
      if (e.stage > highestStage) highestStage = e.stage;
      const tick = tickMap.get(e.asteroidEid);
      if (tick !== undefined && (earliestTick === null || tick < earliestTick)) {
        earliestTick = tick;
      }
    }
    const allFragments = LORE_FRAGMENTS[anomalyType] ?? [];
    groups.push({
      anomalyType,
      name: ANOMALY_NAMES[anomalyType] ?? `Anomaly ${anomalyType}`,
      color: ANOMALY_COLORS[anomalyType] ?? '#94a3b8',
      stageLabel: STAGE_NAMES[highestStage] ?? 'DISCOVERED',
      highestStage,
      revealedCount: revealedIndices.size,
      totalFragments: allFragments.length,
      discoveryTick: earliestTick,
    });
  }
  return groups;
}

/** Count unique discovered anomaly types */
export function countDiscoveredTypes(entryMap: ReadonlyMap<number, CodexEntry>): number {
  const types = new Set<number>();
  for (const e of entryMap.values()) types.add(e.anomalyType);
  return types.size;
}

/** Check if any anomaly has reached UNDERSTOOD stage */
export function hasUnderstoodAnomaly(entryMap: ReadonlyMap<number, CodexEntry>): boolean {
  for (const e of entryMap.values()) {
    if (e.stage === STUDY_STAGES.UNDERSTOOD) return true;
  }
  return false;
}

/** Get chain connection data for visualization */
export function getChainConnections(
  discoveredTypes: Set<number>,
): Array<{ from: number; to: number; bothDiscovered: boolean }> {
  const connections: Array<{ from: number; to: number; bothDiscovered: boolean }> = [];
  for (const chain of CHAINS) {
    for (let i = 0; i < chain.length - 1; i++) {
      connections.push({
        from: chain[i],
        to: chain[i + 1],
        bothDiscovered: discoveredTypes.has(chain[i]) && discoveredTypes.has(chain[i + 1]),
      });
    }
  }
  return connections;
}

// ── DOM helpers ─────────────────────────────────────────────────────────────

function getPanel(): HTMLDivElement {
  if (panel) return panel;

  panel = document.createElement('div');
  panel.id = 'codex-panel';
  panel.style.cssText = `
    position: fixed;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: min(760px, 92vw);
    max-height: 85vh;
    background: rgba(0, 6, 16, 0.96);
    border: 1px solid #1e3a5f;
    box-shadow: 0 0 40px rgba(6, 182, 212, 0.1), inset 0 0 60px rgba(0,0,0,0.5);
    color: #94a3b8;
    font-family: 'Courier New', monospace;
    font-size: 12px;
    display: none;
    flex-direction: column;
    z-index: 200;
    border-radius: 2px;
    overflow: hidden;
  `;

  // Header
  const header = document.createElement('div');
  header.className = 'win-drag-handle';
  header.style.cssText = `
    padding: 12px 16px;
    border-bottom: 1px solid #1e3a5f;
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-shrink: 0;
    cursor: grab;
  `;
  header.innerHTML = safeHtml`
    <div>
      <span style="color:#06b6d4;font-size:10px;letter-spacing:2px;text-transform:uppercase;">Anomaly Archive</span>
      <span style="color:#475569;font-size:10px;margin-left:12px;">Press J to close</span>
    </div>
    <span style="color:#475569;font-size:10px;" id="codex-count">0 of ${TOTAL_ANOMALY_TYPES} anomaly types discovered</span>
  `;
  panel.appendChild(header);

  // Scrollable content
  const content = document.createElement('div');
  content.id = 'codex-content';
  content.style.cssText = `
    overflow-y: auto;
    flex: 1;
    padding: 12px 16px;
  `;
  panel.appendChild(content);

  document.body.appendChild(panel);
  return panel;
}

function renderConnectionMap(discoveredTypes: Set<number>): string {
  const connections = getChainConnections(discoveredTypes);
  if (connections.length === 0) return '';

  // Node positions for each anomaly type in the connection map
  // Laid out as three chains: left, center, right
  const NODE_POS: Record<number, { x: number; y: number }> = {
    1: { x: 60, y: 20 },   // Strange Mineral
    2: { x: 60, y: 50 },   // Structured Signal
    3: { x: 60, y: 80 },   // Spatial Distortion
    4: { x: 180, y: 30 },  // Geometric Void
    5: { x: 180, y: 70 },  // Biological Trace
    6: { x: 300, y: 30 },  // Gravitational Anomaly
    7: { x: 300, y: 70 },  // Convergence Point
  };

  let lines = '';
  for (const conn of connections) {
    const from = NODE_POS[conn.from];
    const to = NODE_POS[conn.to];
    if (!from || !to) continue;
    const color = conn.bothDiscovered ? '#06b6d466' : '#1e3a5f33';
    const dash = conn.bothDiscovered ? '' : 'stroke-dasharray="4 4"';
    lines += `<line x1="${from.x}" y1="${from.y}" x2="${to.x}" y2="${to.y}" stroke="${color}" stroke-width="1" ${dash}/>`;
  }

  let nodes = '';
  for (let t = 1; t <= TOTAL_ANOMALY_TYPES; t++) {
    const pos = NODE_POS[t];
    if (!pos) continue;
    const discovered = discoveredTypes.has(t);
    const color = discovered ? (ANOMALY_COLORS[t] ?? '#94a3b8') : '#1e3a5f';
    const name = ANOMALY_NAMES[t] ?? `Type ${t}`;
    const label = discovered ? name : '???';
    const r = discovered ? 6 : 4;
    const glow = discovered ? `filter="drop-shadow(0 0 3px ${color}44)"` : '';
    nodes += `<circle cx="${pos.x}" cy="${pos.y}" r="${r}" fill="${color}" opacity="${discovered ? 0.8 : 0.3}" ${glow}/>`;
    nodes += `<text x="${pos.x}" y="${pos.y + 16}" fill="${color}" font-size="8" text-anchor="middle" opacity="${discovered ? 0.7 : 0.3}">${escapeHtml(label)}</text>`;
  }

  return `
    <div style="margin-bottom:16px;padding:12px;border:1px solid #1e3a5f33;border-radius:2px;background:rgba(0,6,16,0.5);">
      <div style="color:#475569;font-size:9px;letter-spacing:1.5px;text-transform:uppercase;margin-bottom:8px;">Discovery Chains</div>
      <svg viewBox="0 0 360 100" style="width:100%;height:auto;max-height:100px;">
        ${lines}
        ${nodes}
      </svg>
    </div>
  `;
}

function renderAnnotationInput(anomalyType: number): string {
  const existing = annotations[anomalyType] ?? '';
  const escaped = existing.replace(/"/g, '&quot;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  return `
    <div style="margin-top:4px;margin-bottom:4px;">
      <input
        type="text"
        data-annotation-type="${anomalyType}"
        value="${escaped}"
        maxlength="${ANNOTATION_MAX_LENGTH}"
        placeholder="Add a personal note... (${ANNOTATION_MAX_LENGTH} chars)"
        style="
          width:100%;
          box-sizing:border-box;
          background:rgba(255,255,255,0.02);
          border:1px solid #1e3a5f44;
          border-radius:2px;
          color:#64748b;
          font-family:'Courier New',monospace;
          font-size:11px;
          padding:6px 8px;
          outline:none;
        "
      />
    </div>
  `;
}

function renderContent(): void {
  const p = getPanel();
  const content = p.querySelector('#codex-content') as HTMLDivElement;
  const countEl = p.querySelector('#codex-count') as HTMLSpanElement;

  if (!content) return;

  content.innerHTML = '';

  const discoveredTypeCount = countDiscoveredTypes(entries);

  if (entries.size === 0 && revelations.length === 0) {
    content.innerHTML = safeHtml`
      <div style="color:#334155;text-align:center;padding:40px 0;font-size:11px;line-height:1.8;">
        No anomalies catalogued.<br>
        Assign scouts to discovered anomalies to begin study.<br>
        <span style="color:#1e3a5f;font-size:10px;margin-top:8px;display:inline-block;">
          The belt hides ${TOTAL_ANOMALY_TYPES} anomaly types waiting to be found.
        </span>
      </div>
    `;
    countEl.textContent = `0 of ${TOTAL_ANOMALY_TYPES} anomaly types discovered`;
    return;
  }

  countEl.textContent = `${discoveredTypeCount} of ${TOTAL_ANOMALY_TYPES} anomaly types discovered`;

  // Connection map
  const discoveredTypes = new Set<number>();
  for (const e of entries.values()) discoveredTypes.add(e.anomalyType);
  const mapHtml = renderConnectionMap(discoveredTypes);
  if (mapHtml) {
    const mapDiv = document.createElement('div');
    mapDiv.innerHTML = mapHtml;
    content.appendChild(mapDiv);
  }

  // Group entries by anomalyType
  const groups = buildAnomalyGroups(entries, discoveryTicks);

  for (const group of groups) {
    const { anomalyType, name, color, stageLabel, revealedCount, totalFragments, discoveryTick } = group;
    const allFragments = LORE_FRAGMENTS[anomalyType] ?? [];

    // Collect revealed indices for this type
    const revealedIndices = new Set<number>();
    for (const e of entries.values()) {
      if (e.anomalyType === anomalyType) {
        for (const fi of e.revealedFragments) revealedIndices.add(fi);
      }
    }

    const section = document.createElement('div');
    section.style.cssText = `
      margin-bottom: 24px;
      border-left: 2px solid ${color}55;
      padding-left: 12px;
    `;

    // Progress bar
    const progressPct = totalFragments > 0 ? Math.round((revealedCount / totalFragments) * 100) : 0;
    const timelineNote = discoveryTick !== null ? `Discovered on tick ${discoveryTick}` : '';

    section.innerHTML = safeHtml`
      <div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:4px;">
        <span style="color:${color};font-size:13px;font-weight:bold;">${name}</span>
        <span style="color:#475569;font-size:10px;letter-spacing:1px;">${stageLabel} · ${revealedCount}/${totalFragments} entries</span>
      </div>
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;">
        <div style="flex:1;height:3px;background:#0f172a;border-radius:1px;overflow:hidden;">
          <div style="width:${progressPct}%;height:100%;background:${color}88;transition:width 0.3s;"></div>
        </div>
        <span style="color:#334155;font-size:9px;min-width:30px;text-align:right;">${progressPct}%</span>
      </div>
      ${timelineNote ? `<div style="color:#334155;font-size:9px;margin-bottom:6px;font-style:italic;">${timelineNote}</div>` : ''}
    `;

    // Render revealed fragments
    let fragHtml = '';
    for (let fi = 0; fi < allFragments.length; fi++) {
      if (revealedIndices.has(fi)) {
        fragHtml += `
          <div style="
            margin-bottom:8px;
            padding:8px 10px;
            background:rgba(255,255,255,0.03);
            border-radius:2px;
            line-height:1.6;
            color:#94a3b8;
          ">${escapeHtml(allFragments[fi])}</div>
        `;
      } else {
        fragHtml += `
          <div style="
            margin-bottom:8px;
            padding:8px 10px;
            background:rgba(255,255,255,0.01);
            border-radius:2px;
            color:#1e3a5f;
            font-style:italic;
          ">[STUDY IN PROGRESS — ENTRY ${fi + 1} NOT YET DECODED]</div>
        `;
      }
    }
    section.innerHTML += fragHtml;

    // Player annotation input
    section.innerHTML += renderAnnotationInput(anomalyType);

    content.appendChild(section);
  }

  // Undiscovered anomaly tease
  const undiscoveredCount = TOTAL_ANOMALY_TYPES - discoveredTypeCount;
  if (undiscoveredCount > 0) {
    const teaseDiv = document.createElement('div');
    teaseDiv.style.cssText = `
      margin-bottom: 20px;
      padding: 12px 14px;
      border: 1px dashed #1e3a5f33;
      border-radius: 2px;
      color: #334155;
      font-size: 11px;
      text-align: center;
      font-style: italic;
      line-height: 1.6;
    `;
    teaseDiv.textContent = `The belt still hides ${undiscoveredCount} anomaly type${undiscoveredCount !== 1 ? 's' : ''} you haven't found.`;
    content.appendChild(teaseDiv);
  }

  // Revelations section
  if (revelations.length > 0) {
    const revSection = document.createElement('div');
    revSection.style.cssText = `
      margin-top: 24px;
      padding: 16px;
      border: 1px solid #1e3a5f44;
      border-radius: 2px;
      background: rgba(6,182,212,0.03);
    `;
    revSection.innerHTML = `
      <div style="color:#06b6d4;font-size:10px;letter-spacing:2px;text-transform:uppercase;margin-bottom:12px;">
        ARIA Revelations
      </div>
    `;
    for (const rev of revelations) {
      const el = document.createElement('div');
      el.style.cssText = `
        margin-bottom: 12px;
        padding: 10px 12px;
        background: rgba(6,182,212,0.05);
        border-left: 2px solid #06b6d444;
        color: #06b6d4cc;
        line-height: 1.7;
        font-style: italic;
      `;
      el.textContent = rev;
      revSection.appendChild(el);
    }
    content.appendChild(revSection);
  }

  // Attach annotation listeners after render
  attachAnnotationListeners(content);
}

function attachAnnotationListeners(container: HTMLElement): void {
  const inputs = container.querySelectorAll<HTMLInputElement>('input[data-annotation-type]');
  for (const input of inputs) {
    input.addEventListener('input', () => {
      const aType = Number(input.dataset.annotationType);
      if (isNaN(aType)) return;
      const value = input.value.slice(0, ANNOTATION_MAX_LENGTH);
      if (value) {
        annotations[aType] = value;
      } else {
        delete annotations[aType];
      }
      saveAnnotations();
    });
    // Prevent game hotkeys from firing while typing in annotation
    input.addEventListener('keydown', (e: KeyboardEvent) => {
      e.stopPropagation();
    });
  }
}

// ── Public API ──────────────────────────────────────────────────────────────

/** Update or create a codex entry from a study progress snapshot */
export function updateCodexEntry(
  asteroidEid: number,
  anomalyType: number,
  stage: StudyStage,
  progress: number,
  revealedFragments: number[],
): void {
  const existing = entries.get(asteroidEid);
  if (existing) {
    existing.stage = stage;
    existing.progress = progress;
    // Merge revealed fragments
    for (const fi of revealedFragments) {
      if (!existing.revealedFragments.includes(fi)) existing.revealedFragments.push(fi);
    }
  } else {
    entries.set(asteroidEid, {
      anomalyType,
      asteroidEid,
      stage,
      progress,
      revealedFragments: [...revealedFragments],
    });
  }
  if (visible) renderContent();
}

/** Add a chain revelation text */
export function addRevelation(text: string): void {
  if (!revelations.includes(text)) {
    revelations.push(text);
    if (visible) renderContent();
  }
}

/** Record a discovery tick for timeline display */
export function recordDiscoveryTick(asteroidEid: number, tick: number): void {
  if (!discoveryTicks.has(asteroidEid)) {
    discoveryTicks.set(asteroidEid, tick);
  }
}

/**
 * Check if the first-understood milestone should fire.
 * Returns true exactly once when the first anomaly reaches UNDERSTOOD.
 */
export function checkFirstUnderstoodMilestone(): boolean {
  if (firstUnderstoodFired) return false;
  if (hasUnderstoodAnomaly(entries)) {
    firstUnderstoodFired = true;
    return true;
  }
  return false;
}

/** Get current annotations (for save system) */
export function getAnnotations(): Record<number, string> {
  return { ...annotations };
}

/** Restore annotations (from save system) */
export function restoreAnnotations(saved: Record<number, string>): void {
  annotations = { ...saved };
  saveAnnotations();
}

/** Get internal entries map — for testing */
export function _getEntries(): ReadonlyMap<number, CodexEntry> {
  return entries;
}

export function initCodex(): void {
  getPanel(); // ensure DOM created
}

export function toggleCodex(): void {
  visible = !visible;
  const p = getPanel();
  if (visible) {
    renderContent();
    p.style.display = 'flex';
  } else {
    p.style.display = 'none';
  }
}
