/**
 * Pause menu UI — ESC key toggle.
 * Contains save/load slot management.
 */

import {
  listSaves,
  writeSave,
  readSave,
  readSaveResult,
  deleteSave,
  deleteOldestSave,
  getStorageUsageKB,
} from '../sim/saveLoad';
import type { SaveData, SaveSlot } from '../sim/saveLoad';
import type { DifficultyMode } from '../sim/difficulty';
import { DIFFICULTY_LABELS } from '../sim/difficulty';
import { makeButton, makeSmallButton, showToast } from './menuHelpers';
import { safeHtml } from './utils/safeHtml';

export { showTitleScreen } from './titleScreen';
export { maybeShowLoadScreen } from './saveLoadMenu';

type OnSaveRequest = (slot: SaveSlot) => void;
type OnLoadRequest = (data: SaveData) => void;
type OnResume = () => void;
type OnSettings = () => void;

let container: HTMLDivElement | null = null;
let visible = false;

let _onSave: OnSaveRequest | null = null;
let _onLoad: OnLoadRequest | null = null;
let _onResume: OnResume | null = null;
let _onSettings: OnSettings | null = null;
let _getSeed: (() => number) | null = null;
let _getDifficulty: (() => DifficultyMode) | null = null;

/** Called by main to initiate a save. Main receives worker data, calls receiveWorkerSave(). */
export function initPauseMenu(
  onSave: OnSaveRequest,
  onLoad: OnLoadRequest,
  onResume: OnResume,
  onSettings?: OnSettings,
  getSeed?: () => number,
  getDifficulty?: () => DifficultyMode,
): void {
  _onSave = onSave;
  _onLoad = onLoad;
  _onResume = onResume;
  _onSettings = onSettings ?? null;
  _getSeed = getSeed ?? null;
  _getDifficulty = getDifficulty ?? null;

  container = document.createElement('div');
  container.id = 'pause-menu';
  container.setAttribute('role', 'dialog');
  container.setAttribute('aria-label', 'Pause menu');
  container.setAttribute('aria-modal', 'true');
  container.style.cssText = `
    display: flex;
    position: fixed;
    top: 0; left: 0;
    width: 100%; height: 100%;
    background: rgba(0,0,0,0.75);
    z-index: 1000;
    font-family: 'Courier New', monospace;
    color: #aaffaa;
    align-items: center;
    justify-content: center;
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.25s ease-out;
  `;
  document.body.appendChild(container);
  renderMenu();
}

export function isPauseMenuOpen(): boolean {
  return visible;
}

export function openPauseMenu(): void {
  if (!container) return;
  visible = true;
  container.style.pointerEvents = 'all';
  requestAnimationFrame(() => {
    if (container) container.style.opacity = '1';
  });
  renderMenu();
}

export function closePauseMenu(): void {
  if (!container) return;
  visible = false;
  container.style.opacity = '0';
  container.style.pointerEvents = 'none';
}

export function togglePauseMenu(): void {
  if (visible) {
    closePauseMenu();
    _onResume?.();
  } else {
    openPauseMenu();
  }
}

/** Called when the worker sends back save data for a slot. Persist to localStorage. */
export function receiveWorkerSave(slot: SaveSlot, data: SaveData): void {
  const result = writeSave(slot, data);
  if (!result.ok) {
    if (result.quotaExceeded) {
      showQuotaErrorToast();
    } else {
      showToast('Save failed — data could not be written');
    }
  } else {
    showToast(`Saved to ${slot === 'auto' ? 'auto-save' : `Slot ${Number(slot) + 1}`}`);
    renderMenu();
  }
}

/** Show an actionable toast when storage quota is exceeded. */
function showQuotaErrorToast(): void {
  const usageKB = getStorageUsageKB();
  const toast = document.createElement('div');
  toast.style.cssText = `
    position: fixed;
    bottom: 40px;
    left: 50%;
    transform: translateX(-50%);
    background: rgba(30,10,0,0.97);
    color: #ffaa44;
    font-family: 'Courier New', monospace;
    font-size: 13px;
    padding: 12px 18px;
    border: 1px solid #ff6600;
    border-radius: 4px;
    z-index: 2000;
    max-width: 360px;
    line-height: 1.5;
  `;

  const msg = document.createElement('div');
  msg.textContent = `Save failed — storage full (~${usageKB} KB used). Delete a save slot to free space.`;
  toast.appendChild(msg);

  const btn = document.createElement('button');
  btn.textContent = 'Delete oldest save';
  btn.style.cssText = `
    display: block;
    margin-top: 8px;
    padding: 4px 12px;
    background: transparent;
    border: 1px solid #ff6600;
    color: #ffaa44;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    cursor: pointer;
    border-radius: 3px;
  `;
  btn.addEventListener('click', () => {
    const deleted = deleteOldestSave();
    toast.remove();
    if (deleted !== null) {
      const label = deleted === 'auto' ? 'auto-save' : `Slot ${Number(deleted) + 1}`;
      showToast(`Deleted ${label} — retry your save`);
      renderMenu();
    }
  });
  toast.appendChild(btn);

  document.body.appendChild(toast);
  setTimeout(() => toast.remove(), 6000);
}

function renderMenu(): void {
  if (!container) return;
  container.innerHTML = '';

  const panel = document.createElement('div');
  panel.style.cssText = `
    background: rgba(0, 10, 0, 0.95);
    border: 1px solid #4aff4a;
    border-radius: 8px;
    padding: 32px;
    min-width: 420px;
    max-width: 500px;
  `;

  // Title
  const title = document.createElement('h2');
  title.style.cssText =
    'margin: 0 0 8px; font-size: 20px; color: #4aff4a; text-align: center; letter-spacing: 3px;';
  title.textContent = '— PAUSED —';
  panel.appendChild(title);

  // Seed + difficulty display
  const metaEl = document.createElement('div');
  metaEl.style.cssText = 'font-size: 10px; color: #556655; text-align: center; margin-bottom: 20px; letter-spacing: 1px;';
  const parts: string[] = [];
  if (_getSeed) parts.push(`Seed: ${_getSeed()}`);
  if (_getDifficulty) {
    const mode = _getDifficulty();
    parts.push(`${DIFFICULTY_LABELS[mode]} Mode`);
  }
  if (parts.length) {
    metaEl.textContent = parts.join('  ·  ');
    panel.appendChild(metaEl);
  }

  // Save slots header with storage usage
  const savesHeader = document.createElement('div');
  savesHeader.style.cssText = 'display:flex;justify-content:space-between;align-items:baseline;margin-bottom:12px;';

  const savesTitle = document.createElement('div');
  savesTitle.style.cssText = 'font-size: 12px; color: #4aff4a; letter-spacing: 1px;';
  savesTitle.textContent = 'SAVE SLOTS';
  savesHeader.appendChild(savesTitle);

  const storageEl = document.createElement('div');
  storageEl.style.cssText = 'font-size: 10px; color: #556655;';
  storageEl.textContent = `storage: ~${getStorageUsageKB()} KB`;
  savesHeader.appendChild(storageEl);

  panel.appendChild(savesHeader);

  const saves = listSaves();
  const slotMetas = new Map(saves.map((s) => [s.slot, s]));

  const slots: SaveSlot[] = [0, 1, 2];
  for (const slot of slots) {
    panel.appendChild(renderSaveSlot(slot, slotMetas.get(slot) ?? null));
  }

  // Separator
  const sep = document.createElement('hr');
  sep.style.cssText = 'border-color: #1a4a1a; margin: 24px 0;';
  panel.appendChild(sep);

  // Controls quick-reference card
  panel.appendChild(renderControlsCard());

  // Second separator before action buttons
  const sep2 = document.createElement('hr');
  sep2.style.cssText = 'border-color: #1a4a1a; margin: 16px 0 20px;';
  panel.appendChild(sep2);

  // Settings button
  if (_onSettings) {
    const settingsBtn = makeButton('SETTINGS', '#8090c0', () => {
      closePauseMenu();
      _onSettings?.();
    });
    settingsBtn.style.marginBottom = '8px';
    panel.appendChild(settingsBtn);
  }

  // Resume button
  const resumeBtn = makeButton('RESUME', '#4aff4a', () => {
    closePauseMenu();
    _onResume?.();
  });
  panel.appendChild(resumeBtn);

  container.appendChild(panel);
}

function renderSaveSlot(
  slot: SaveSlot,
  meta: ReturnType<typeof listSaves>[number] | null,
): HTMLDivElement {
  const row = document.createElement('div');
  row.style.cssText = `
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 10px;
    padding: 10px;
    border: 1px solid #1a4a1a;
    border-radius: 4px;
  `;

  const label = document.createElement('div');
  label.style.cssText = 'flex: 1; font-size: 12px;';
  if (meta) {
    const date = new Date(meta.timestamp).toLocaleString();
    label.innerHTML = safeHtml`<div style="color:#4aff4a">Slot ${Number(slot) + 1}</div><div style="color:#888;font-size:11px">${date}</div><div style="color:#aaa;font-size:11px">Tick ${meta.tick} · ${meta.robotCount} robots</div>`;
  } else {
    label.innerHTML = safeHtml`<div style="color:#4aff4a">Slot ${Number(slot) + 1}</div><div style="color:#444;font-size:11px">Empty</div>`;
  }
  row.appendChild(label);

  const saveBtn = makeSmallButton('SAVE', () => {
    if (meta) {
      if (!confirm(`Overwrite Slot ${Number(slot) + 1}?`)) return;
    }
    _onSave?.(slot);
  });
  saveBtn.setAttribute('aria-label', `Save to slot ${Number(slot) + 1}`);
  row.appendChild(saveBtn);

  if (meta) {
    const loadBtn = makeSmallButton('LOAD', () => {
      const result = readSaveResult(slot);
      if (!result.data) {
        const detail = result.parseError
          ? 'JSON parse error — file may be truncated'
          : 'Core save fields missing — cannot recover';
        showToast(`Save corrupt: ${detail}`);
        return;
      }
      if (result.recovered.length > 0) {
        console.warn(
          `[saveLoad] Partial recovery for slot ${slot}: defaulted ${result.recovered.join(', ')}`,
        );
        showToast(`Warning: save partially recovered (missing: ${result.recovered.join(', ')})`);
      }
      if (!confirm(`Load Slot ${Number(slot) + 1}? Current progress will be lost.`)) return;
      closePauseMenu();
      _onLoad?.(result.data);
    });
    loadBtn.setAttribute('aria-label', `Load save from slot ${Number(slot) + 1}`);
    row.appendChild(loadBtn);

    const delBtn = makeSmallButton('DEL', () => {
      if (!confirm(`Delete Slot ${Number(slot) + 1}?`)) return;
      deleteSave(slot);
      renderMenu();
    });
    delBtn.setAttribute('aria-label', `Delete save slot ${Number(slot) + 1}`);
    delBtn.style.color = '#ff4444';
    delBtn.style.borderColor = '#ff4444';
    row.appendChild(delBtn);
  }

  return row;
}

const CONTROLS: Array<{ group: string; bindings: Array<[string, string]> }> = [
  {
    group: 'CAMERA',
    bindings: [
      ['W/A/S/D', 'Pan'],
      ['Scroll', 'Zoom'],
      ['Home', 'Snap to base'],
      ['Click robot', 'Follow'],
    ],
  },
  {
    group: 'PANELS',
    bindings: [
      ['D', 'Dashboard'],
      ['T', 'Tech tree'],
      ['J', 'Codex / Journal'],
      ['F', 'Factions'],
      ['G', 'Megastructure'],
      ['H', 'Controls help'],
    ],
  },
  {
    group: 'ACTIONS',
    bindings: [
      ['Right-click', 'Assign robot'],
      ['Ctrl+S', 'Quick save'],
      ['Esc', 'Pause / resume'],
    ],
  },
];

function renderControlsCard(): HTMLDivElement {
  const card = document.createElement('div');
  card.style.cssText = 'display:flex;gap:16px;';

  for (const { group, bindings } of CONTROLS) {
    const col = document.createElement('div');
    col.style.cssText = 'flex:1;';

    const heading = document.createElement('div');
    heading.style.cssText = 'font-size:10px;color:#4aff4a;letter-spacing:1px;margin-bottom:6px;';
    heading.textContent = group;
    col.appendChild(heading);

    for (const [key, action] of bindings) {
      const row = document.createElement('div');
      row.style.cssText = 'display:flex;justify-content:space-between;gap:8px;margin-bottom:3px;';

      const keyEl = document.createElement('span');
      keyEl.style.cssText = 'font-size:10px;color:#88cc88;white-space:nowrap;';
      keyEl.textContent = key;

      const actEl = document.createElement('span');
      actEl.style.cssText = 'font-size:10px;color:#556655;white-space:nowrap;text-align:right;';
      actEl.textContent = action;

      row.appendChild(keyEl);
      row.appendChild(actEl);
      col.appendChild(row);
    }

    card.appendChild(col);
  }

  return card;
}
