// ── Construction states (re-exported from shared/buildingTypes) ──────────────

/** Ticks required to fully construct a building (30 seconds at 60 tps). */
export const CONSTRUCTION_DURATION_TICKS = 30 * 60;

// ── Building instance state ───────────────────────────────────────────────────

export interface BuildingInstance {
  id: number; // unique instance ID
  type: BuildingType;
  baseEntityId: number; // which base station this belongs to
  health: number;
  active: boolean;
  /** World-space position of this building */
  worldX: number;
  worldY: number;
  worldZ: number;
  /** 0 = planned, 1 = under construction, 2 = complete */
  constructionState: ConstructionState;
  /** 0..1 construction progress */
  constructionProgress: number;
}

// ── Base-level building registry ──────────────────────────────────────────────

export interface BaseBuildingState {
  /** All constructed buildings at this base */
  buildings: BuildingInstance[];
  /** Next instance ID counter */
  nextId: number;
}

export function createBaseBuildingState(): BaseBuildingState {
  return { buildings: [], nextId: 1 };
}

/**
 * Compute a world-space position for a new building, arranged in a ring
 * around the base station at increasing radii.
 */
export function computeBuildingSitePosition(
  state: BaseBuildingState,
  baseX: number,
  baseY: number,
  baseZ: number,
): { x: number; y: number; z: number } {
  const existingCount = state.buildings.length;
  const ringRadius = 40 + Math.floor(existingCount / 8) * 25; // expand rings
  const angle = (existingCount % 8) * (Math.PI / 4) + (Math.floor(existingCount / 8) * 0.3);
  return {
    x: baseX + Math.cos(angle) * ringRadius,
    y: baseY,
    z: baseZ + Math.sin(angle) * ringRadius,
  };
}

/**
 * Attempt to construct a building at a base.
 * Deducts cost from storage. Returns instance in PLANNED state.
 * Building becomes active only after construction completes.
 */
export function buildBuilding(
  state: BaseBuildingState,
  type: BuildingType,
  baseEntityId: number,
  storage: Record<string, number>,
  unlockedTechIds: Set<string>,
  baseX: number,
  baseY: number,
  baseZ: number,
  /** Optional max building slots for this base (outposts have limited slots). */
  maxBuildingSlots?: number,
): BuildingInstance | null {
  const def = BUILDING_DEFS[type];
  if (!def) return null;

  // Building slot limit check (for outposts)
  if (maxBuildingSlots != null) {
    const baseBuildings = state.buildings.filter((b) => b.baseEntityId === baseEntityId);
    if (baseBuildings.length >= maxBuildingSlots) return null;
  }

  // Tech check
  if (def.unlockTechId && !unlockedTechIds.has(def.unlockTechId)) return null;

  // Escalating cost: each successive building of the same type costs more
  const existingCount = type === BUILDING_TYPES.FACTORY
    ? countActiveFactories(state)
    : countBuildingsOfType(state, type);
  const costMultiplier = computeBuildingCostMultiplier(type, existingCount);

  // Affordability check
  for (const [res, qty] of Object.entries(def.cost)) {
    const scaledQty = Math.ceil((qty ?? 0) * costMultiplier);
    if ((storage[res] ?? 0) < scaledQty) return null;
  }

  // Deduct cost
  for (const [res, qty] of Object.entries(def.cost)) {
    if (qty !== undefined) {
      const scaledQty = Math.ceil(qty * costMultiplier);
      storage[res] = (storage[res] ?? 0) - scaledQty;
    }
  }

  const site = computeBuildingSitePosition(state, baseX, baseY, baseZ);

  const instance: BuildingInstance = {
    id: state.nextId++,
    type,
    baseEntityId,
    health: def.maxHealth,
    active: false, // not active until construction completes
    worldX: site.x,
    worldY: site.y,
    worldZ: site.z,
    constructionState: CONSTRUCTION_STATE.PLANNED,
    constructionProgress: 0,
  };
  state.buildings.push(instance);
  return instance;
}

/**
 * Advance construction progress on a building. Called per tick by engineer robots.
 * Returns true when construction completes.
 */
export function advanceConstruction(
  building: BuildingInstance,
  amount: number,
): boolean {
  if (building.constructionState === CONSTRUCTION_STATE.COMPLETE) return true;
  building.constructionState = CONSTRUCTION_STATE.UNDER_CONSTRUCTION;
  building.constructionProgress = Math.min(1, building.constructionProgress + amount);
  if (building.constructionProgress >= 1) {
    building.constructionState = CONSTRUCTION_STATE.COMPLETE;
    building.constructionProgress = 1;
    building.active = true;
    return true;
  }
  return false;
}

/**
 * Count how many factories are active at this base.
 */
export function countActiveFactories(state: BaseBuildingState): number {
  return state.buildings.filter((b) => b.type === BUILDING_TYPES.FACTORY && b.active).length;
}

/**
 * Count how many buildings of a given type exist at this base (active or under construction).
 */
export function countBuildingsOfType(state: BaseBuildingState, type: BuildingType): number {
  return state.buildings.filter((b) => b.type === type).length;
}

/**
 * Compute the cost multiplier for building the Nth instance of a building type.
 * - Factory: 3^existingCount (exponential, very aggressive)
 * - All others: 1 + 0.12 * existingCount (linear, 12% more per existing building)
 *
 * The 12% rate was calibrated via Monte Carlo simulation (buildingCostMonteCarlo.test.ts):
 * it prevents stockpile spam (10K iron stockpile → ~27 panels vs ~66 with flat costs)
 * while keeping the first few buildings affordable in early game.
 *
 * @param type The building type
 * @param existingCount How many of this type already exist
 */
export function computeBuildingCostMultiplier(type: BuildingType, existingCount: number): number {
  if (type === BUILDING_TYPES.FACTORY) {
    return Math.pow(3, existingCount);
  }
  return 1 + 0.12 * existingCount;
}

/**
 * Compute robot cap for a base.
 * Base cap is 10; each Factory adds +3 with diminishing returns.
 * Factory 1: +3, Factory 2: +2, Factory 3: +1, Factory 4+: +1 each (floor of 3 / sqrt(n))
 * Only Robot Factories increase robot cap — power buildings affect energy/research instead.
 */
export function computeRobotCap(state: BaseBuildingState): number {
  const BASE_CAP = 10;
  const factories = countActiveFactories(state);
  let bonus = 0;
  for (let i = 1; i <= factories; i++) {
    bonus += Math.max(1, Math.floor(BUILDING_DEFS[BUILDING_TYPES.FACTORY].robotCapBonus / Math.sqrt(i)));
  }
  return BASE_CAP + bonus;
}

// ── Aggregate building effects ──────────────────────────────────────────────

export interface BuildingEffects {
  /** Flat bonus to research points per second */
  researchRateBonus: number;
  /** Base defense score (from turrets) */
  defenseScore: number;
  /** Refining speed multiplier (stacks multiplicatively) */
  refiningSpeedMultiplier: number;
  /** Flat bonus to robot charge rate (energy/sec) from Energy Relays */
  chargeRateBonus: number;
}

/**
 * Compute aggregate sim effects from active non-factory buildings.
 * Robot cap is handled separately in computeRobotCap().
 */
export function computeBuildingEffects(state: BaseBuildingState): BuildingEffects {
  const effects: BuildingEffects = {
    researchRateBonus: 0,
    defenseScore: 0,
    refiningSpeedMultiplier: 1.0,
    chargeRateBonus: 0,
  };
  for (const b of state.buildings) {
    if (!b.active) continue;
    switch (b.type) {
      case BUILDING_TYPES.RELAY:
        effects.researchRateBonus += 0.07;
        break;
      case BUILDING_TYPES.RTG_MODULE:
        effects.researchRateBonus += 0.07;
        break;
      case BUILDING_TYPES.FISSION_REACTOR:
        effects.researchRateBonus += 0.15;
        break;
      case BUILDING_TYPES.FUSION_REACTOR:
        effects.researchRateBonus += 0.3;
        effects.refiningSpeedMultiplier *= 1.5;
        break;
      case BUILDING_TYPES.TURRET:
        effects.defenseScore += 1;
        break;
      case BUILDING_TYPES.SOLAR_PANEL:
        effects.chargeRateBonus += 4;
        break;
      case BUILDING_TYPES.ENERGY_RELAY:
        effects.chargeRateBonus += 8;
        break;
    }
  }
  return effects;
}

// ── Building damage ──────────────────────────────────────────────────────────

export interface DamageResult {
  /** Total damage dealt across all buildings */
  totalDamage: number;
  /** Buildings that were destroyed */
  destroyed: BuildingInstance[];
  /** Buildings that were damaged but survived */
  damaged: BuildingInstance[];
}

/**
 * Apply damage to buildings at a base. Distributes damage across active
 * buildings, prioritizing those closest to the impact point.
 * Returns a summary of what was damaged/destroyed.
 */
export function applyDamageToBuildings(
  state: BaseBuildingState,
  impactX: number,
  impactZ: number,
  rawDamage: number,
): DamageResult {
  const result: DamageResult = { totalDamage: 0, destroyed: [], damaged: [] };
  if (rawDamage <= 0) return result;

  // Sort active buildings by distance to impact (closest take damage first)
  const active = state.buildings
    .filter((b) => b.active && b.health > 0)
    .map((b) => {
      const dx = b.worldX - impactX;
      const dz = b.worldZ - impactZ;
      return { building: b, dist: Math.sqrt(dx * dx + dz * dz) };
    })
    .sort((a, b) => a.dist - b.dist);

  let remaining = rawDamage;
  for (const { building } of active) {
    if (remaining <= 0) break;
    // Each building absorbs up to its health
    const dealt = Math.min(remaining, building.health);
    building.health -= dealt;
    remaining -= dealt;
    result.totalDamage += dealt;

    if (building.health <= 0) {
      building.active = false;
      result.destroyed.push(building);
    } else {
      result.damaged.push(building);
    }
  }

  return result;
}

// SerializedBuilding re-exported from shared/buildingTypes

/**
 * Serialize buildings for transport to main thread.
 */
export function serializeBuildingState(state: BaseBuildingState): {
  buildings: SerializedBuilding[];
} {
  return {
    buildings: state.buildings.map((b) => ({
      id: b.id,
      type: b.type,
      health: b.health,
      active: b.active,
      worldX: b.worldX,
      worldY: b.worldY,
      worldZ: b.worldZ,
      constructionState: b.constructionState,
      constructionProgress: b.constructionProgress,
    })),
  };
}
