/**
 * Save/Load system for game state persistence.
 *
 * Serializes the full ECS world + non-ECS sim state to JSON.
 * Stored in localStorage under 'asteroid_miner_save_{slot}'.
 */

import type { SerializedTechState } from './techTree';
import type { SerializedAutomationState } from './automation';
import type { HaulRoute } from './logistics';
import type { SerializedEventState } from './events/eventEngine';
import type { SerializedEntityState } from './entities/entitySystem';
import type { SerializedMegastructureState } from './megastructures';
import type { InboxMessage } from './inbox/inboxTypes';
import type { SerializedCultureState } from './culture';
import type { SerializedHabitatState } from './habitat';
import type { SerializedMarketState } from './market';
import type { SerializedMeridianLoreState } from './meridianLore';
import type { SerializedBlueprintState } from './blueprints';
import type { SerializedBeltEchoesState } from '../beltEchoes/echoDelivery';
import type { SerializedTransitState } from './transit';

export const SAVE_VERSION = 2;
export const SAVE_SLOT_COUNT = 3;
export const AUTO_SAVE_SLOT = 'auto';

export type SaveSlot = 0 | 1 | 2 | typeof AUTO_SAVE_SLOT;

// ── Commander / Inbox serialized types ────────────────────────────────────────

export interface SerializedInboxState {
  messages: InboxMessage[];
  totalGenerated: number;
  lastGenerationTick: number;
}

export interface SerializedPendingAction {
  id: number;
  description: string;
  /** Opaque worker message payload — typed as unknown for JSON round-trip safety */
  message: Record<string, unknown>;
  proposedAtTick: number;
  /** Wall-clock time when proposed (Date.now()), for time-to-approve measurement */
  proposedAtMs?: number;
  reasoning: string;
}

export interface SerializedCommanderState {
  pendingActions: SerializedPendingAction[];
  nextActionId: number;
  delegationEnabled: boolean;
  /** Aria spectrum dimension values [-1, 1] */
  spectrumDimensions?: Record<string, number>;
  /** Current Aria dialogue stage */
  dialogueStage?: string;
  /** Rolling window of classified interaction records */
  interactionHistory?: Array<{
    tick: number;
    dimension: string;
    direction: -1 | 0 | 1;
    magnitude: number;
    source: string;
  }>;
}

