/**
 * Legacy Expedition system — persists prestige data across "New Star System" resets.
 *
 * When a player completes the Dyson Sphere and chooses "New Star System",
 * legacy data is captured before localStorage is cleared and restored after.
 * This gives returning players bonuses and tracks cumulative progress.
 */

export const LEGACY_KEY = 'asteroid_miner_legacy';

/** Persisted across expeditions via a dedicated localStorage key. */
export interface LegacyExpeditionData {
  /** How many expeditions completed (incremented on each New Star System press). */
  expeditionCount: number;
  /** Cumulative robot legacies across all expeditions. */
  totalLegacies: number;
  /** Best (most accomplished) robot name across all expeditions. */
  bestRobotName: string | null;
  /** Highest culture label achieved across all expeditions. */
  bestCultureLabel: string;
  /** Highest tick count reached in any single expedition. */
  bestTick: number;
}

/** Culture label ranking for comparison. Higher index = better. */
const CULTURE_RANK: readonly string[] = [
  'Nascent',
  'Developing',
  'Emerging',
  'Established',
  'Flourishing',
];

function cultureRank(label: string): number {
  const idx = CULTURE_RANK.indexOf(label);
  return idx >= 0 ? idx : 0;
}

/** Read legacy data from localStorage. Returns null if none exists. */
export function readLegacy(): LegacyExpeditionData | null {
  try {
    const json = localStorage.getItem(LEGACY_KEY);
    if (!json) return null;
    const parsed = JSON.parse(json) as unknown;
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return null;
    const r = parsed as Record<string, unknown>;
    if (typeof r.expeditionCount !== 'number') return null;
    if (typeof r.totalLegacies !== 'number') return null;
    return parsed as LegacyExpeditionData;
  } catch {
    return null;
  }
}

/** Write legacy data to localStorage. */
export function writeLegacy(data: LegacyExpeditionData): void {
  try {
    localStorage.setItem(LEGACY_KEY, JSON.stringify(data));
  } catch {
    // Quota exceeded — best-effort
  }
}

/**
 * Build updated legacy data from the current expedition's end-screen stats.
 * Merges with any existing legacy data from prior expeditions.
 */
export function buildLegacyFromStats(
  existing: LegacyExpeditionData | null,
  stats: {
    tick: number;
    topRobotName: string | null;
    legacyCount: number;
    cultureLabel: string;
  },
): LegacyExpeditionData {
  const prev = existing ?? {
    expeditionCount: 0,
    totalLegacies: 0,
    bestRobotName: null,
    bestCultureLabel: 'Nascent',
    bestTick: 0,
  };

  return {
    expeditionCount: prev.expeditionCount + 1,
    totalLegacies: prev.totalLegacies + stats.legacyCount,
    bestRobotName: stats.topRobotName ?? prev.bestRobotName,
    bestCultureLabel:
      cultureRank(stats.cultureLabel) > cultureRank(prev.bestCultureLabel)
        ? stats.cultureLabel
        : prev.bestCultureLabel,
    bestTick: Math.max(prev.bestTick, stats.tick),
  };
}

/**
 * Compute starting mineral bonuses for legacy players.
 * Returns a multiplier (e.g. 1.0 for first expedition, 1.25 for second, etc.).
 * Capped at 2.0x (expedition 5+).
 */
export function legacyMineralMultiplier(expeditionCount: number): number {
  if (expeditionCount <= 0) return 1.0;
  return Math.min(2.0, 1.0 + expeditionCount * 0.25);
}
