/**
 * Research handlers: sim:tech_state, sim:research_error.
 */
import type {
  WorkerToMainMessage,
  SimTechStateMessage,
  SimResearchErrorMessage,
  SimResearchDeadEndMessage,
  SimResearchBonusMessage,
} from '../sim/messages';
import { techBitmask, TECH_NODE_BY_ID } from '../sim/techTree';
import { storageValues } from '../gameRuntimeState';
import { updateTechTreePanel, pulseUnlockedNode } from '../ui/techTreePanel';
import { setAutomationTechUnlocks } from '../ui/automationPanel';
import { updateBuildState } from '../ui/buildPanel';
import { updateBuildingsState } from '../ui/baseBuildingsPanel';
import { showNotification } from '../ui/notifications';
import { showHint } from '../ui/hints';
import { audioEngine } from '../audio/audioEngine';
import { playSfx } from '../audio/sfxEngine';
import { musicManager } from '../audio/musicManager';
import { isAway, recordAwayEvent } from '../advisor/awayEvents';
import type { HandlerContext, HandlerMap } from './types';

export function registerResearchHandlers(ctx: HandlerContext): HandlerMap {
  const { refs } = ctx;

  return {
    'sim:tech_state': (msg: WorkerToMainMessage) => {
      const techMsg = msg as SimTechStateMessage;
      refs.latestRefined = techMsg.payload.refined;
      refs.latestTechState = techMsg.payload.techState;
      refs.latestFactoryQueueLength = techMsg.payload.factoryQueueLength;
      refs.latestBuildings = techMsg.payload.buildings?.buildings ?? [];
      if (techMsg.payload.robotCap !== undefined) refs.latestRobotCap = techMsg.payload.robotCap;
      updateTechTreePanel(techMsg.payload.techState, techMsg.payload.refined);
      if (techMsg.payload.justUnlocked) {
        if (isAway()) {
          recordAwayEvent({ type: 'research_complete', name: techMsg.payload.justUnlocked, timestamp: Date.now() });
        }
        showNotification(`✓ Research complete: ${techMsg.payload.justUnlocked}`, '#22c55e', 'research');
        pulseUnlockedNode(techMsg.payload.justUnlocked);
        audioEngine.playResearchComplete();
        playSfx('game.research_complete');
        musicManager.setState('progress');
      }
      {
        const unlocked = BigInt(techMsg.payload.techState.unlockedMask);
        refs.latestUnlockedMask = unlocked;
        const tier2 = (unlocked & techBitmask('automated_logistics')) !== 0n;
        const tier3 = (unlocked & techBitmask('sector_mapping')) !== 0n;
        setAutomationTechUnlocks(tier2, tier3);
        updateBuildState(
          techMsg.payload.refined,
          unlocked,
          techMsg.payload.factoryQueueLength,
          techMsg.payload.factoryProgress ?? null,
          techMsg.payload.factoryRemainingSeconds ?? null,
          {
            iron: storageValues[0],
            nickel: storageValues[1],
            cobalt: storageValues[2],
            platinum: storageValues[3],
            ice: storageValues[4],
            carbon: storageValues[5],
            silicate: storageValues[6],
          },
        );
        updateBuildingsState(
          {
            iron: storageValues[0],
            nickel: storageValues[1],
            cobalt: storageValues[2],
            platinum: storageValues[3],
            ice: storageValues[4],
            carbon: storageValues[5],
            silicate: storageValues[6],
          },
          unlocked,
          techMsg.payload.buildings?.buildings ?? [],
        );
        // Update building data for renderer
        if (techMsg.payload.buildings) {
          refs.latestBuildings = techMsg.payload.buildings.buildings;
        }
        const robotCap = techMsg.payload.robotCap;
        if (robotCap !== undefined && refs.latestRobotCount >= robotCap && refs.latestRobotCount > 0) {
          showHint('robot_cap_reached', 'Fleet cap reached. Open Buildings (B key) and construct a Robot Factory to increase your limit.');
        }
      }
    },

    'sim:research_error': (msg: WorkerToMainMessage) => {
      const errMsg = msg as SimResearchErrorMessage;
      console.warn('[main] Research error:', errMsg.payload.error);
    },

    'sim:research_dead_end': (msg: WorkerToMainMessage) => {
      const deadEnd = msg as SimResearchDeadEndMessage;
      const nodeName = TECH_NODE_BY_ID.get(deadEnd.payload.nodeId)?.name ?? deadEnd.payload.nodeId;
      showNotification(`⚠ Research dead end: ${nodeName}`, '#f59e0b', 'research');
      playSfx('game.anomaly_detected');
    },

    'sim:research_bonus': (msg: WorkerToMainMessage) => {
      const bonus = msg as SimResearchBonusMessage;
      void bonus; // payload available for future use (asteroidEid, anomalyType)
      showNotification('🔬 Xenotech bonus: +50 research points!', '#06b6d4', 'research');
      playSfx('game.research_complete');
    },
  };
}
