/**
 * Bug Report UI — dead-simple floating button + two-field form for playtesters.
 * Sends reports to the proxy webhook endpoint. No login required.
 */

import { getProxyBaseUrl } from '../advisor/providers';

let bugBtn: HTMLButtonElement | null = null;
let overlay: HTMLDivElement | null = null;

/** Initialize the persistent floating "Report a Bug" button. */
export function initBugReport(): void {
  if (bugBtn) return;

  bugBtn = document.createElement('button');
  bugBtn.id = 'bug-report-btn';
  bugBtn.textContent = '🐛 Report a Bug';
  bugBtn.setAttribute('aria-label', 'Report a bug');
  bugBtn.style.cssText = `
    position: fixed;
    bottom: 12px;
    right: 12px;
    padding: 6px 14px;
    background: rgba(0, 8, 20, 0.85);
    color: #f59e0b;
    border: 1px solid rgba(245, 158, 11, 0.4);
    border-radius: 4px;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    cursor: pointer;
    z-index: 50;
    pointer-events: auto;
    transition: background 0.15s, border-color 0.15s;
  `;
  bugBtn.addEventListener('mouseenter', () => {
    bugBtn!.style.background = 'rgba(40, 30, 0, 0.9)';
    bugBtn!.style.borderColor = 'rgba(245, 158, 11, 0.7)';
  });
  bugBtn.addEventListener('mouseleave', () => {
    bugBtn!.style.background = 'rgba(0, 8, 20, 0.85)';
    bugBtn!.style.borderColor = 'rgba(245, 158, 11, 0.4)';
  });
  bugBtn.addEventListener('click', openBugForm);

  document.body.appendChild(bugBtn);
}

function openBugForm(): void {
  if (overlay) return;

  overlay = document.createElement('div');
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.7);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 9000;
    pointer-events: auto;
  `;

  const panel = document.createElement('div');
  panel.style.cssText = `
    background: rgba(0, 8, 20, 0.96);
    border: 1px solid rgba(245, 158, 11, 0.4);
    border-radius: 6px;
    padding: 24px 28px;
    max-width: 400px;
    width: 90%;
    font-family: 'Courier New', monospace;
    color: #e2e8f0;
  `;

  const title = document.createElement('div');
  title.textContent = 'Report a Bug';
  title.style.cssText = `
    font-size: 16px;
    font-weight: bold;
    color: #f59e0b;
    margin-bottom: 16px;
  `;
  panel.appendChild(title);

  // Field 1: What went wrong?
  const label1 = document.createElement('label');
  label1.textContent = 'What went wrong?';
  label1.style.cssText = 'display:block; font-size:12px; color:#94a3b8; margin-bottom:4px;';
  panel.appendChild(label1);

  const textarea1 = document.createElement('textarea');
  textarea1.placeholder = 'Describe what happened...';
  textarea1.rows = 3;
  textarea1.style.cssText = fieldStyle();
  panel.appendChild(textarea1);

  // Field 2: What were you trying to do?
  const label2 = document.createElement('label');
  label2.textContent = 'What were you trying to do?';
  label2.style.cssText = 'display:block; font-size:12px; color:#94a3b8; margin-bottom:4px; margin-top:12px;';
  panel.appendChild(label2);

  const textarea2 = document.createElement('textarea');
  textarea2.placeholder = 'Optional — what were you doing when this happened?';
  textarea2.rows = 2;
  textarea2.style.cssText = fieldStyle();
  panel.appendChild(textarea2);

  // Button row
  const btnRow = document.createElement('div');
  btnRow.style.cssText = 'display:flex; gap:10px; margin-top:16px; justify-content:flex-end;';

  const cancelBtn = document.createElement('button');
  cancelBtn.textContent = 'Cancel';
  cancelBtn.style.cssText = `
    padding: 6px 16px;
    background: rgba(30,30,40,0.8);
    color: #94a3b8;
    border: 1px solid rgba(100,100,120,0.4);
    border-radius: 4px;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    cursor: pointer;
  `;
  cancelBtn.addEventListener('click', closeBugForm);
  btnRow.appendChild(cancelBtn);

  const submitBtn = document.createElement('button');
  submitBtn.textContent = 'Submit';
  submitBtn.style.cssText = `
    padding: 6px 16px;
    background: rgba(245, 158, 11, 0.2);
    color: #f59e0b;
    border: 1px solid rgba(245, 158, 11, 0.5);
    border-radius: 4px;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    font-weight: bold;
    cursor: pointer;
  `;
  submitBtn.addEventListener('click', async () => {
    const whatWrong = textarea1.value.trim();
    if (!whatWrong) {
      textarea1.style.borderColor = '#ef4444';
      textarea1.focus();
      return;
    }
    submitBtn.disabled = true;
    submitBtn.textContent = 'Sending...';
    await submitBugReport(whatWrong, textarea2.value.trim());
  });
  btnRow.appendChild(submitBtn);

  panel.appendChild(btnRow);
  overlay.appendChild(panel);

  // Close on backdrop click
  overlay.addEventListener('click', (e) => {
    if (e.target === overlay) closeBugForm();
  });

  // Close on Escape
  const onKey = (e: KeyboardEvent) => {
    if (e.key === 'Escape') {
      closeBugForm();
      document.removeEventListener('keydown', onKey);
    }
  };
  document.addEventListener('keydown', onKey);

  document.body.appendChild(overlay);
  textarea1.focus();
}

function closeBugForm(): void {
  if (overlay) {
    overlay.remove();
    overlay = null;
  }
}

function fieldStyle(): string {
  return `
    display: block;
    width: 100%;
    padding: 8px 10px;
    background: rgba(0, 0, 0, 0.5);
    color: #e2e8f0;
    border: 1px solid rgba(100, 150, 255, 0.25);
    border-radius: 3px;
    font-family: 'Courier New', monospace;
    font-size: 12px;
    resize: vertical;
  `;
}

async function submitBugReport(whatWrong: string, whatDoing: string): Promise<void> {
  const proxyKey = localStorage.getItem('aria_proxy_key') ?? undefined;
  const sessionId =
    localStorage.getItem('asteroid_miner_session') ?? crypto.randomUUID();
  localStorage.setItem('asteroid_miner_session', sessionId);

  const payload = {
    game: 'cultures-of-the-belt',
    whatWentWrong: whatWrong,
    whatWereDoing: whatDoing || undefined,
    sessionId,
    userAgent: navigator.userAgent,
    timestamp: new Date().toISOString(),
    url: window.location.href,
  };

  let ok = false;
  try {
    const baseUrl = getProxyBaseUrl();
    const resp = await fetch(`${baseUrl}/v1/bug-report`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...(proxyKey ? { Authorization: `Bearer ${proxyKey}` } : {}),
      },
      body: JSON.stringify(payload),
    });
    ok = resp.ok;
  } catch {
    // Network error — ok stays false
  }

  if (ok) {
    showConfirmation();
  } else {
    showError();
  }
}

function showError(): void {
  closeBugForm();

  const toast = document.createElement('div');
  toast.style.cssText = `
    position: fixed;
    bottom: 50px;
    right: 12px;
    background: rgba(30, 0, 0, 0.92);
    border: 1px solid rgba(239, 68, 68, 0.5);
    color: #ef4444;
    font-family: 'Courier New', monospace;
    font-size: 12px;
    padding: 10px 16px;
    border-radius: 4px;
    z-index: 9001;
    opacity: 0;
    transform: translateY(8px);
    transition: opacity 0.3s ease, transform 0.3s ease;
    pointer-events: none;
  `;
  toast.textContent = 'Failed to send report. Try again later.';
  document.body.appendChild(toast);

  requestAnimationFrame(() => {
    toast.style.opacity = '1';
    toast.style.transform = 'translateY(0)';
  });

  setTimeout(() => {
    toast.style.opacity = '0';
    toast.style.transform = 'translateY(8px)';
    setTimeout(() => toast.remove(), 350);
  }, 4000);
}

function showConfirmation(): void {
  closeBugForm();

  const toast = document.createElement('div');
  toast.style.cssText = `
    position: fixed;
    bottom: 50px;
    right: 12px;
    background: rgba(0, 30, 10, 0.92);
    border: 1px solid rgba(74, 222, 128, 0.5);
    color: #4ade80;
    font-family: 'Courier New', monospace;
    font-size: 12px;
    padding: 10px 16px;
    border-radius: 4px;
    z-index: 9001;
    opacity: 0;
    transform: translateY(8px);
    transition: opacity 0.3s ease, transform 0.3s ease;
    pointer-events: none;
  `;
  toast.textContent = 'Thanks! We got it.';
  document.body.appendChild(toast);

  requestAnimationFrame(() => {
    toast.style.opacity = '1';
    toast.style.transform = 'translateY(0)';
  });

  setTimeout(() => {
    toast.style.opacity = '0';
    toast.style.transform = 'translateY(8px)';
    setTimeout(() => toast.remove(), 350);
  }, 3000);
}
