import {
  BoxGeometry,
  Color,
  CylinderGeometry,
  DynamicDrawUsage,
  Group,
  InstancedMesh,
  Material,
  Matrix4,
  Mesh,
  MeshStandardMaterial,
  Object3D,
  Scene,
  SphereGeometry,
  TorusGeometry,
} from 'three';
import { getFleetColorPalette } from '../shared/fleetColors';
import type { SerializedBuilding } from '../shared/buildingTypes';
import { BUILDING_TYPES, CONSTRUCTION_STATE } from '../shared/buildingTypes';

// Default colors for base station elements
const DEFAULT_RING_COLOR = 0x44aaff;
const DEFAULT_RING_EMISSIVE = 0x2266aa;
const DEFAULT_HUB_COLOR = 0x88ccff;
const DEFAULT_HUB_EMISSIVE = 0x4488cc;

// Growth module limits
const MAX_SOLAR_MODULES = 16;
const MAX_INDUSTRIAL_MODULES = 12;
const MAX_POWER_MODULES = 8;

/**
 * Simple visual for the base station - a glowing ring structure.
 * Grows additional visual modules as buildings are constructed.
 */
export class BaseStationRenderer {
  private group: Group;
  private ringMat: MeshStandardMaterial;
  private hubMat: MeshStandardMaterial;
  private hubMesh: Mesh;
  private currentPaletteId: string | null = null;

  // Growth module instanced meshes
  private solarModules: InstancedMesh;
  private solarMat: MeshStandardMaterial;
  private industrialModules: InstancedMesh;
  private industrialMat: MeshStandardMaterial;
  private powerModules: InstancedMesh;
  private powerMat: MeshStandardMaterial;
  private prevSolarCount = 0;
  private prevIndustrialCount = 0;
  private prevPowerCount = 0;

  /** Scratch object for computing instance matrices. */
  private static _dummy = new Object3D();

  constructor(scene: Scene, x: number, y: number, z: number) {
    this.group = new Group();
    this.group.position.set(x, y, z);

    // Main ring
    const ringGeo = new TorusGeometry(15, 2, 8, 32);
    this.ringMat = new MeshStandardMaterial({
      color: DEFAULT_RING_COLOR,
      emissive: DEFAULT_RING_EMISSIVE,
      emissiveIntensity: 0.8,
      metalness: 0.8,
      roughness: 0.2,
    });
    const ring = new Mesh(ringGeo, this.ringMat);
    ring.rotation.x = Math.PI / 2;
    this.group.add(ring);

    // Central hub
    const hubGeo = new SphereGeometry(5, 16, 16);
    this.hubMat = new MeshStandardMaterial({
      color: DEFAULT_HUB_COLOR,
      emissive: DEFAULT_HUB_EMISSIVE,
      emissiveIntensity: 0.6,
      metalness: 0.7,
      roughness: 0.3,
    });
    this.hubMesh = new Mesh(hubGeo, this.hubMat);
    this.group.add(this.hubMesh);

    // Beacon light
    const beaconGeo = new SphereGeometry(1, 8, 8);
    const beaconMat = new MeshStandardMaterial({
      color: 0xffffff,
      emissive: 0xffffff,
      emissiveIntensity: 2.0,
    });
    const beacon = new Mesh(beaconGeo, beaconMat);
    beacon.position.y = 10;
    this.group.add(beacon);

    // ── Growth modules (instanced) ──────────────────────────────────────────
    // Solar panels — flat blue panels radiating outward
    this.solarMat = new MeshStandardMaterial({
      color: 0x3b82f6,
      emissive: 0x1d4ed8,
      emissiveIntensity: 0.6,
      metalness: 0.6,
      roughness: 0.3,
    });
    const solarGeo = new BoxGeometry(6, 0.3, 3);
    this.solarModules = new InstancedMesh(solarGeo, this.solarMat, MAX_SOLAR_MODULES);
    this.solarModules.count = 0;
    this.solarModules.instanceMatrix.setUsage(DynamicDrawUsage);
    this.group.add(this.solarModules);

    // Industrial modules — amber boxes clustered around the ring
    this.industrialMat = new MeshStandardMaterial({
      color: 0xf59e0b,
      emissive: 0xd97706,
      emissiveIntensity: 0.5,
      metalness: 0.85,
      roughness: 0.2,
    });
    const industrialGeo = new BoxGeometry(3, 3, 3);
    this.industrialModules = new InstancedMesh(industrialGeo, this.industrialMat, MAX_INDUSTRIAL_MODULES);
    this.industrialModules.count = 0;
    this.industrialModules.instanceMatrix.setUsage(DynamicDrawUsage);
    this.group.add(this.industrialModules);

    // Power modules — green glowing spheres
    this.powerMat = new MeshStandardMaterial({
      color: 0x10b981,
      emissive: 0x059669,
      emissiveIntensity: 0.8,
      metalness: 0.8,
      roughness: 0.2,
    });
    const powerGeo = new SphereGeometry(1.5, 8, 8);
    this.powerModules = new InstancedMesh(powerGeo, this.powerMat, MAX_POWER_MODULES);
    this.powerModules.count = 0;
    this.powerModules.instanceMatrix.setUsage(DynamicDrawUsage);
    this.group.add(this.powerModules);

    scene.add(this.group);
  }

  update(_time: number): void {
    this.group.rotation.y += 0.002;
  }

  /**
   * Update growth visuals based on completed buildings.
   * Adds instanced modules around the base proportional to building counts.
   */
  updateGrowth(buildings: SerializedBuilding[]): void {
    let solarCount = 0;
    let industrialCount = 0;
    let powerCount = 0;

    for (const b of buildings) {
      if (b.constructionState !== CONSTRUCTION_STATE.COMPLETE) continue;
      switch (b.type) {
        case BUILDING_TYPES.SOLAR_PANEL:
        case BUILDING_TYPES.SOLAR_FURNACE:
        case BUILDING_TYPES.ENERGY_RELAY:
          solarCount++;
          break;
        case BUILDING_TYPES.FACTORY:
        case BUILDING_TYPES.RADIATOR:
        case BUILDING_TYPES.RELAY:
        case BUILDING_TYPES.TURRET:
          industrialCount++;
          break;
        case BUILDING_TYPES.RTG_MODULE:
        case BUILDING_TYPES.FISSION_REACTOR:
        case BUILDING_TYPES.FUSION_REACTOR:
          powerCount++;
          break;
      }
    }

    solarCount = Math.min(solarCount, MAX_SOLAR_MODULES);
    industrialCount = Math.min(industrialCount, MAX_INDUSTRIAL_MODULES);
    powerCount = Math.min(powerCount, MAX_POWER_MODULES);

    // Scale hub with total buildings (subtle growth)
    const total = solarCount + industrialCount + powerCount;
    const hubScale = 1 + total * 0.03;
    this.hubMesh.scale.setScalar(hubScale);

    if (solarCount !== this.prevSolarCount) {
      this._layoutRing(this.solarModules, solarCount, 20, 2, -0.3);
      this.prevSolarCount = solarCount;
    }

    if (industrialCount !== this.prevIndustrialCount) {
      this._layoutRing(this.industrialModules, industrialCount, 18, 3, 0);
      this.prevIndustrialCount = industrialCount;
    }

    if (powerCount !== this.prevPowerCount) {
      this._layoutRing(this.powerModules, powerCount, 22, 4, 0);
      this.prevPowerCount = powerCount;
    }
  }

  /**
   * Position `count` instances in a ring around the base center.
   * @param im The InstancedMesh to update
   * @param count Number of visible instances
   * @param radius Distance from center
   * @param yOffset Vertical offset
   * @param tiltX Rotation tilt on X axis (for solar panels)
   */
  private _layoutRing(
    im: InstancedMesh,
    count: number,
    radius: number,
    yOffset: number,
    tiltX: number,
  ): void {
    const d = BaseStationRenderer._dummy;
    im.count = count;
    for (let i = 0; i < count; i++) {
      const angle = (i / Math.max(count, 1)) * Math.PI * 2;
      d.position.set(
        Math.cos(angle) * radius,
        yOffset,
        Math.sin(angle) * radius,
      );
      d.rotation.set(tiltX, -angle, 0);
      d.updateMatrix();
      im.setMatrixAt(i, d.matrix);
    }
    im.instanceMatrix.needsUpdate = true;
  }

  /**
   * Apply fleet color palette to base station materials. Pass null to revert to defaults.
   * Uses palette accent for ring color and glow for emissive.
   */
  setFleetColor(paletteId: string | null): void {
    if (paletteId === this.currentPaletteId) return;
    this.currentPaletteId = paletteId;

    if (!paletteId) {
      this.ringMat.color.set(DEFAULT_RING_COLOR);
      this.ringMat.emissive.set(DEFAULT_RING_EMISSIVE);
      this.hubMat.color.set(DEFAULT_HUB_COLOR);
      this.hubMat.emissive.set(DEFAULT_HUB_EMISSIVE);
    } else {
      const palette = getFleetColorPalette(paletteId);
      if (!palette) return;

      const accent = new Color(palette.accent);
      const glow = new Color(palette.glow);

      this.ringMat.color.copy(accent);
      this.ringMat.emissive.copy(glow);
      this.hubMat.color.copy(accent).lerp(new Color(0xffffff), 0.3);
      this.hubMat.emissive.copy(glow);
    }
  }

  dispose(): void {
    this.group.traverse((obj) => {
      const mesh = obj as Mesh;
      if (!mesh.isMesh) return;
      mesh.geometry.dispose();
      (mesh.material as Material).dispose();
    });
    this.group.parent?.remove(this.group);
  }
}
