/**
 * Minimap
 *
 * Canvas 2D map in the top-right corner showing:
 * - Base positions (white cross)
 * - Robots color-coded by type
 * - Anomaly positions (purple dot)
 * - Named asteroid locations (labeled markers)
 * - Entity positions (blue/green dot)
 * - Camera view frustum (dim rectangle)
 *
 * Click to navigate camera to that world position.
 */

import type { EntityState } from '../sim/entities/entitySystem';
import { ENTITY_TYPES } from '../sim/entities/entitySystem';
import { ROBOT_TYPES } from '../sim/robotProfiles';
import { attachTooltip } from './tooltip';
import { getRobotX, getRobotZ, getRobotType } from '../sim/bufferLayout';
import {
  ASTEROID_STRIDE, ASTEROID_OFF_X, ASTEROID_OFF_Z,
  THREAT_STRIDE, THREAT_OFF_TARGET_X, THREAT_OFF_TARGET_Z, THREAT_OFF_PROGRESS,
} from '../sim/bufferLayout';
import { PLANETS } from '../sim/solarSystem';

// ── Config ────────────────────────────────────────────────────────────────────

const DEFAULT_MAP_SIZE = 480; // px (was 160 — 300% larger)
const MIN_MAP_SIZE = 120; // minimum resize bound
const MAX_MAP_SIZE = 800; // maximum resize bound
const MAP_MARGIN = 8; // px from corner
const WORLD_RADIUS = 55000; // world extent ±55000 in X and Z
const REDRAW_INTERVAL = 100; // ms between full redraws
const RESIZE_HANDLE_SIZE = 14; // px — drag zone in bottom-left corner
const MAX_VISIBLE_LABELS = 5; // max named-location labels to show (nearest to camera)
const LABEL_MIN_DIST_PX = 18; // min pixel distance between rendered labels

// Robot type → minimap dot color
const ROBOT_COLORS: Record<number, string> = {
  [ROBOT_TYPES.SCOUT]: '#3b82f6', // blue
  [ROBOT_TYPES.MINER]: '#f59e0b', // amber
  [ROBOT_TYPES.HAULER]: '#22c55e', // green
  [ROBOT_TYPES.RESEARCHER]: '#a855f7', // purple
  [ROBOT_TYPES.REFINER]: '#f97316', // orange
  [ROBOT_TYPES.DEFENDER]: '#ef4444', // red
  [ROBOT_TYPES.ENGINEER]: '#06b6d4', // cyan
};

const DEFAULT_ROBOT_COLOR = '#f59e0b';

// ── State ─────────────────────────────────────────────────────────────────────

interface MinimapState {
  robotBuffer: Float32Array | null;
  robotCount: number;
  asteroidBuffer: Float64Array | null;
  asteroidCount: number;
  threatBuffer: Float32Array | null;
  threatCount: number;
  bases: Array<{ x: number; y: number; z: number }>;
  anomalies: Array<{ x: number; z: number }>;
  entities: EntityState[];
  factionBases: Array<{ x: number; z: number; color: string; name: string; territoryRadius?: number }>;
  namedLocations: Array<{ name: string; x: number; z: number }>;
  cameraX: number;
  cameraZ: number;
  cameraViewSize: number; // half-width in world units
}

const state: MinimapState = {
  robotBuffer: null,
  robotCount: 0,
  asteroidBuffer: null,
  asteroidCount: 0,
  threatBuffer: null,
  threatCount: 0,
  bases: [],
  anomalies: [],
  entities: [],
  factionBases: [],
  namedLocations: [],
  cameraX: 5000,
  cameraZ: 1000,
  cameraViewSize: 8000,
};

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;
let lastRedraw = 0;
let onNavigate: ((x: number, z: number) => void) | null = null;
let mapSize = DEFAULT_MAP_SIZE;

// Resize drag state
let resizing = false;
let resizeStartX = 0;
let resizeStartY = 0;
let resizeStartSize = 0;

// ── Public API ────────────────────────────────────────────────────────────────

export function initMinimap(navigateCallback: (x: number, z: number) => void): void {
  onNavigate = navigateCallback;
  buildCanvas();
}

export function updateMinimapRobots(buffer: Float32Array, count: number): void {
  state.robotBuffer = buffer;
  state.robotCount = count;
}

export function updateMinimapAsteroids(buffer: Float64Array, count: number): void {
  state.asteroidBuffer = buffer;
  state.asteroidCount = count;
}

export function updateMinimapThreats(buffer: Float32Array, count: number): void {
  state.threatBuffer = buffer;
  state.threatCount = count;
}

export function updateMinimapBases(bases: Array<{ x: number; y: number; z: number }>): void {
  state.bases = bases;
}

export function updateMinimapAnomalies(anomalies: Array<{ x: number; z: number }>): void {
  state.anomalies = anomalies;
}

export function updateMinimapEntities(entities: EntityState[]): void {
  state.entities = entities;
}

export function updateMinimapFactions(
  factionBases: Array<{ x: number; z: number; color: string; name: string; territoryRadius?: number }>,
): void {
  state.factionBases = factionBases;
}

export function updateMinimapNamedLocations(
  locations: Array<{ name: string; x: number; y: number; z: number }>,
): void {
  state.namedLocations = locations.map((l) => ({ name: l.name, x: l.x, z: l.z }));
}

export function updateMinimapCamera(worldX: number, worldZ: number, viewSize: number): void {
  state.cameraX = worldX;
  state.cameraZ = worldZ;
  state.cameraViewSize = viewSize;
}

/** Call from game loop render — throttled internally */
export function renderMinimap(now: number): void {
  if (!canvas || !ctx) return;
  if (now - lastRedraw < REDRAW_INTERVAL) return;
  lastRedraw = now;
  draw();
}

// ── Canvas builder ────────────────────────────────────────────────────────────

function applyCanvasSize(): void {
  if (!canvas) return;
  canvas.width = mapSize;
  canvas.height = mapSize;
  canvas.style.width = `${mapSize}px`;
  canvas.style.height = `${mapSize}px`;
}

function buildCanvas(): void {
  canvas = document.createElement('canvas');
  canvas.style.cssText = `
    position: fixed;
    top: ${MAP_MARGIN}px;
    right: ${MAP_MARGIN}px;
    border: 1px solid rgba(100,140,255,0.4);
    border-radius: 6px;
    cursor: crosshair;
    z-index: 70;
    opacity: 0.92;
  `;
  applyCanvasSize();

  canvas.addEventListener('click', handleClick);
  canvas.addEventListener('mousedown', handleResizeStart);
  canvas.addEventListener('mousemove', handleCursorUpdate);
  attachTooltip(
    canvas,
    'Minimap — shows the full asteroid belt\n● Dots = asteroids  ● Red zones = active threats\n● Amber = miners  ● Blue = scouts  ● Green = haulers\n● White ✕ = bases (green ring = territory)\nClick to navigate · Drag bottom-left corner to resize',
  );

  ctx = canvas.getContext('2d');
  document.body.appendChild(canvas);
}

// ── Coordinate helpers ────────────────────────────────────────────────────────

/** World → minimap pixel. World centered at 0; map shows ±WORLD_RADIUS. */
function wx(worldX: number): number {
  return ((worldX + WORLD_RADIUS) / (2 * WORLD_RADIUS)) * mapSize;
}

function wz(worldZ: number): number {
  return ((worldZ + WORLD_RADIUS) / (2 * WORLD_RADIUS)) * mapSize;
}

/** Minimap pixel → world coordinate */
function px(mapX: number): number {
  return (mapX / mapSize) * (2 * WORLD_RADIUS) - WORLD_RADIUS;
}

function pz(mapZ: number): number {
  return (mapZ / mapSize) * (2 * WORLD_RADIUS) - WORLD_RADIUS;
}

// ── Label selection (pure, testable) ──────────────────────────────────────────

/**
 * Select which named-location labels to display on the minimap.
 *
 * Sorts locations by squared camera distance (ascending), takes the nearest
 * MAX_VISIBLE_LABELS, then applies AABB de-overlap: a label is suppressed if
 * any previously placed label is within LABEL_MIN_DIST_PX on BOTH axes
 * (strict `<`, not `<=`). AABB is intentional — cheaper than Euclidean and
 * good enough for axis-aligned text labels.
 */
export function selectVisibleLabels(
  locations: Array<{ name: string; x: number; z: number }>,
  cameraX: number,
  cameraZ: number,
  currentMapSize: number,
): Array<{ name: string; px: number; pz: number }> {
  if (locations.length === 0) return [];

  const candidates = locations
    .map((nl) => ({
      name: nl.name,
      dist: (nl.x - cameraX) ** 2 + (nl.z - cameraZ) ** 2,
      px: ((nl.x + WORLD_RADIUS) / (2 * WORLD_RADIUS)) * currentMapSize,
      pz: ((nl.z + WORLD_RADIUS) / (2 * WORLD_RADIUS)) * currentMapSize,
    }))
    .sort((a, b) => a.dist - b.dist)
    .slice(0, MAX_VISIBLE_LABELS);

  const result: Array<{ name: string; px: number; pz: number }> = [];
  for (const c of candidates) {
    const overlaps = result.some(
      (p) => Math.abs(p.px - c.px) < LABEL_MIN_DIST_PX && Math.abs(p.pz - c.pz) < LABEL_MIN_DIST_PX,
    );
    if (!overlaps) {
      result.push({ name: c.name, px: c.px, pz: c.pz });
    }
  }
  return result;
}

// ── Drawing ───────────────────────────────────────────────────────────────────

function draw(): void {
  if (!ctx) return;

  // Background
  ctx.fillStyle = 'rgba(4,6,14,0.92)';
  ctx.fillRect(0, 0, mapSize, mapSize);

  // Belt ring (inner and outer radius)
  ctx.strokeStyle = 'rgba(80,110,180,0.35)';
  ctx.lineWidth = 1;
  const cx = mapSize / 2;
  const cz = mapSize / 2;
  const innerPx = (5000 / WORLD_RADIUS) * (mapSize / 2);
  const outerPx = (50000 / WORLD_RADIUS) * (mapSize / 2);

  ctx.beginPath();
  ctx.arc(cx, cz, innerPx, 0, Math.PI * 2);
  ctx.stroke();
  ctx.beginPath();
  ctx.arc(cx, cz, outerPx, 0, Math.PI * 2);
  ctx.stroke();

  // Asteroid dots (dim specks along orbital positions)
  if (state.asteroidBuffer && state.asteroidCount > 0) {
    ctx.fillStyle = 'rgba(120,140,180,0.35)';
    const buf = state.asteroidBuffer;
    const count = state.asteroidCount;
    // For large asteroid counts, sample every Nth to keep drawing fast
    const step = count > 2000 ? Math.ceil(count / 2000) : 1;
    for (let i = 0; i < count; i += step) {
      const ax = wx(buf[i * ASTEROID_STRIDE + ASTEROID_OFF_X]);
      const az = wz(buf[i * ASTEROID_STRIDE + ASTEROID_OFF_Z]);
      ctx.fillRect(ax, az, 1.5, 1.5);
    }
  }

  // Planets (colored dots at heliocentric positions)
  for (const planet of PLANETS) {
    const ppx = wx(planet.x);
    const ppz = wz(planet.z);
    // Skip if outside minimap bounds
    if (ppx < -2 || ppx > mapSize + 2 || ppz < -2 || ppz > mapSize + 2) continue;
    ctx.fillStyle = planet.color;
    ctx.beginPath();
    ctx.arc(ppx, ppz, 3, 0, Math.PI * 2);
    ctx.fill();
  }

  // Camera frustum
  const camSize = (state.cameraViewSize / WORLD_RADIUS) * (mapSize / 2);
  const camX = wx(state.cameraX);
  const camZ = wz(state.cameraZ);
  ctx.strokeStyle = 'rgba(160,190,255,0.35)';
  ctx.lineWidth = 1.5;
  ctx.strokeRect(camX - camSize, camZ - camSize, camSize * 2, camSize * 2);

  // Anomalies (purple dots)
  ctx.fillStyle = '#a855f7';
  for (const a of state.anomalies) {
    const ax = wx(a.x);
    const az = wz(a.z);
    ctx.beginPath();
    ctx.arc(ax, az, 3.5, 0, Math.PI * 2);
    ctx.fill();
  }

  // Robots — color-coded by type
  if (state.robotBuffer && state.robotCount > 0) {
    for (let i = 0; i < state.robotCount; i++) {
      const rType = getRobotType(state.robotBuffer, i);
      ctx.fillStyle = ROBOT_COLORS[rType] ?? DEFAULT_ROBOT_COLOR;
      const rx = wx(getRobotX(state.robotBuffer, i));
      const rz = wz(getRobotZ(state.robotBuffer, i));
      ctx.beginPath();
      ctx.arc(rx, rz, 2.5, 0, Math.PI * 2);
      ctx.fill();
    }
  }

  // Entities (drifters = purple; resonants = cyan)
  for (const entity of state.entities) {
    const ex = wx(entity.x);
    const ez = wz(entity.z);
    ctx.fillStyle = entity.type === ENTITY_TYPES.DRIFTER ? '#8866ff' : '#44ffcc';
    ctx.beginPath();
    ctx.arc(ex, ez, 5, 0, Math.PI * 2);
    ctx.fill();
  }

  // Player base territory zones (bright ring around each player base)
  for (const base of state.bases) {
    const bx = wx(base.x);
    const bz = wz(base.z);
    // Player territory radius: 3000 world units (visible claimed zone)
    const radiusPx = (3000 / WORLD_RADIUS) * (mapSize / 2);
    ctx.beginPath();
    ctx.arc(bx, bz, radiusPx, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(0,255,170,0.08)';
    ctx.fill();
    ctx.strokeStyle = 'rgba(0,255,170,0.3)';
    ctx.lineWidth = 1;
    ctx.stroke();
  }

  // Bases (white cross with highlight)
  ctx.strokeStyle = '#ffffff';
  ctx.lineWidth = 2;
  for (const base of state.bases) {
    const bx = wx(base.x);
    const bz = wz(base.z);
    const r = 6;
    // Glow ring
    ctx.beginPath();
    ctx.arc(bx, bz, 9, 0, Math.PI * 2);
    ctx.strokeStyle = 'rgba(255,255,255,0.2)';
    ctx.lineWidth = 1;
    ctx.stroke();
    // Cross
    ctx.strokeStyle = '#ffffff';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(bx - r, bz);
    ctx.lineTo(bx + r, bz);
    ctx.moveTo(bx, bz - r);
    ctx.lineTo(bx, bz + r);
    ctx.stroke();
  }

  // Faction territory zones (subtle tinted circles)
  for (const fb of state.factionBases) {
    if (fb.territoryRadius && fb.territoryRadius > 0) {
      const fbx = wx(fb.x);
      const fbz = wz(fb.z);
      const radiusPx = (fb.territoryRadius / WORLD_RADIUS) * (mapSize / 2);
      ctx.beginPath();
      ctx.arc(fbx, fbz, radiusPx, 0, Math.PI * 2);
      ctx.fillStyle = fb.color + '18'; // very low alpha fill
      ctx.fill();
      ctx.strokeStyle = fb.color + '40'; // low alpha border
      ctx.lineWidth = 1;
      ctx.stroke();
    }
  }

  // Faction bases (colored diamond)
  for (const fb of state.factionBases) {
    const fbx = wx(fb.x);
    const fbz = wz(fb.z);
    const r = 5;
    ctx.fillStyle = fb.color;
    ctx.beginPath();
    ctx.moveTo(fbx, fbz - r);
    ctx.lineTo(fbx + r, fbz);
    ctx.lineTo(fbx, fbz + r);
    ctx.lineTo(fbx - r, fbz);
    ctx.closePath();
    ctx.fill();
  }

  // Threat zones (red pulsing indicators at target positions)
  if (state.threatBuffer && state.threatCount > 0) {
    const buf = state.threatBuffer;
    for (let i = 0; i < state.threatCount; i++) {
      const tx = wx(buf[i * THREAT_STRIDE + THREAT_OFF_TARGET_X]);
      const tz = wz(buf[i * THREAT_STRIDE + THREAT_OFF_TARGET_Z]);
      const progress = buf[i * THREAT_STRIDE + THREAT_OFF_PROGRESS];
      // Pulse radius based on threat progress (larger as it approaches)
      const baseRadius = 6 + progress * 6;
      const alpha = 0.3 + progress * 0.4;
      // Red fill
      ctx.beginPath();
      ctx.arc(tx, tz, baseRadius, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(239,68,68,${(alpha * 0.3).toFixed(2)})`;
      ctx.fill();
      // Red border
      ctx.strokeStyle = `rgba(239,68,68,${alpha.toFixed(2)})`;
      ctx.lineWidth = 1.5;
      ctx.stroke();
    }
  }

  // Sun marker at world origin (0, 0)
  const sunX = wx(0);
  const sunZ = wz(0);
  ctx.fillStyle = '#ffdd44';
  ctx.beginPath();
  ctx.arc(sunX, sunZ, 4, 0, Math.PI * 2);
  ctx.fill();
  // Sun rays
  ctx.strokeStyle = '#ffdd44';
  ctx.lineWidth = 1;
  for (let a = 0; a < Math.PI * 2; a += Math.PI / 4) {
    ctx.beginPath();
    ctx.moveTo(sunX + Math.cos(a) * 5, sunZ + Math.sin(a) * 5);
    ctx.lineTo(sunX + Math.cos(a) * 8, sunZ + Math.sin(a) * 8);
    ctx.stroke();
  }

  // Player position marker (camera pivot = player location)
  const playerX = wx(state.cameraX);
  const playerZ = wz(state.cameraZ);
  ctx.fillStyle = '#00ffaa';
  ctx.beginPath();
  ctx.moveTo(playerX, playerZ - 6);
  ctx.lineTo(playerX + 4.5, playerZ + 4);
  ctx.lineTo(playerX - 4.5, playerZ + 4);
  ctx.closePath();
  ctx.fill();
  ctx.strokeStyle = '#00ffaa';
  ctx.lineWidth = 1;
  ctx.stroke();

  // Named locations — de-overlapped, nearest N only
  if (state.namedLocations.length > 0) {
    const visible = selectVisibleLabels(state.namedLocations, state.cameraX, state.cameraZ, mapSize);
    // Sort by distance to camera, take nearest N — draw dots for all candidates
    const candidates = state.namedLocations
      .map((nl) => ({
        ...nl,
        dist: (nl.x - state.cameraX) ** 2 + (nl.z - state.cameraZ) ** 2,
        px: ((nl.x + WORLD_RADIUS) / (2 * WORLD_RADIUS)) * mapSize,
        pz: ((nl.z + WORLD_RADIUS) / (2 * WORLD_RADIUS)) * mapSize,
      }))
      .sort((a, b) => a.dist - b.dist)
      .slice(0, MAX_VISIBLE_LABELS);

    ctx.font = '9px "Courier New"';
    ctx.textAlign = 'left';
    const visibleCoords = new Set(visible.map((v) => `${v.px},${v.pz}`));
    for (const nl of candidates) {
      // Always draw the dot marker
      ctx.fillStyle = 'rgba(255,220,100,0.7)';
      ctx.beginPath();
      ctx.arc(nl.px, nl.pz, 2.5, 0, Math.PI * 2);
      ctx.fill();

      // Only draw text label for those that passed de-overlap
      if (visibleCoords.has(`${nl.px},${nl.pz}`)) {
        ctx.fillStyle = 'rgba(255,220,100,0.6)';
        ctx.fillText(nl.name, nl.px + 4, nl.pz + 3);
      }
    }
  }

  // Scale indicator
  ctx.fillStyle = 'rgba(140,160,220,0.8)';
  ctx.font = '10px "Courier New"';
  ctx.textAlign = 'right';
  ctx.fillText('Full Belt · 110 Mm', mapSize - 4, mapSize - 4);

  // Legend (bottom-left, above resize handle)
  drawLegend(ctx);

  // Resize handle — bottom-left corner (diagonal lines)
  ctx.strokeStyle = 'rgba(160,190,255,0.5)';
  ctx.lineWidth = 1;
  const h = RESIZE_HANDLE_SIZE;
  for (let i = 3; i <= h; i += 4) {
    ctx.beginPath();
    ctx.moveTo(i, mapSize);
    ctx.lineTo(0, mapSize - i);
    ctx.stroke();
  }
}

function drawLegend(ctx: CanvasRenderingContext2D): void {
  const lineH = 12;
  const items: Array<{ label: string; color: string; shape: 'circle' | 'diamond' | 'cross' | 'sun' | 'triangle' }> = [
    { label: 'You', color: '#00ffaa', shape: 'triangle' },
    { label: 'Sun', color: '#ffdd44', shape: 'sun' },
    { label: 'Base', color: '#ffffff', shape: 'cross' },
    { label: 'Threat', color: '#ef4444', shape: 'circle' },
    { label: 'Faction', color: '#cc66cc', shape: 'diamond' },
    { label: 'Miner', color: '#f59e0b', shape: 'circle' },
    { label: 'Scout', color: '#3b82f6', shape: 'circle' },
  ];

  const x0 = 4;
  const y0 = mapSize - RESIZE_HANDLE_SIZE - items.length * lineH - 4;

  // Background
  ctx.fillStyle = 'rgba(4,6,14,0.7)';
  ctx.fillRect(x0, y0 - 2, 68, items.length * lineH + 4);

  ctx.font = '9px "Courier New"';
  ctx.textAlign = 'left';

  for (let i = 0; i < items.length; i++) {
    const item = items[i];
    const iy = y0 + i * lineH + lineH - 2;
    const ix = x0 + 6;

    ctx.fillStyle = item.color;
    ctx.strokeStyle = item.color;
    ctx.lineWidth = 1.5;

    if (item.shape === 'circle') {
      ctx.beginPath();
      ctx.arc(ix, iy - 3, 3, 0, Math.PI * 2);
      ctx.fill();
    } else if (item.shape === 'diamond') {
      ctx.beginPath();
      ctx.moveTo(ix, iy - 6);
      ctx.lineTo(ix + 3, iy - 3);
      ctx.lineTo(ix, iy);
      ctx.lineTo(ix - 3, iy - 3);
      ctx.closePath();
      ctx.fill();
    } else if (item.shape === 'cross') {
      ctx.beginPath();
      ctx.moveTo(ix - 3, iy - 3);
      ctx.lineTo(ix + 3, iy - 3);
      ctx.moveTo(ix, iy - 6);
      ctx.lineTo(ix, iy);
      ctx.stroke();
    } else if (item.shape === 'sun') {
      ctx.beginPath();
      ctx.arc(ix, iy - 3, 2.5, 0, Math.PI * 2);
      ctx.fill();
    } else if (item.shape === 'triangle') {
      ctx.beginPath();
      ctx.moveTo(ix, iy - 6);
      ctx.lineTo(ix + 3.5, iy);
      ctx.lineTo(ix - 3.5, iy);
      ctx.closePath();
      ctx.fill();
    }

    ctx.fillStyle = 'rgba(180,200,240,0.8)';
    ctx.fillText(item.label, ix + 8, iy);
  }
}

function isInResizeZone(e: MouseEvent): boolean {
  if (!canvas) return false;
  const rect = canvas.getBoundingClientRect();
  const localX = e.clientX - rect.left;
  const localY = e.clientY - rect.top;
  return localX < RESIZE_HANDLE_SIZE && localY > rect.height - RESIZE_HANDLE_SIZE;
}

function handleClick(e: MouseEvent): void {
  if (!canvas || !onNavigate) return;
  // Don't navigate if we just finished resizing
  if (isInResizeZone(e)) return;
  const rect = canvas.getBoundingClientRect();
  const mx = e.clientX - rect.left;
  const mz = e.clientY - rect.top;
  const sx = (mx / rect.width) * mapSize;
  const sz = (mz / rect.height) * mapSize;
  onNavigate(px(sx), pz(sz));
}

function handleCursorUpdate(e: MouseEvent): void {
  if (!canvas) return;
  canvas.style.cursor = isInResizeZone(e) ? 'nesw-resize' : 'crosshair';
}

function handleResizeStart(e: MouseEvent): void {
  if (!isInResizeZone(e)) return;
  e.preventDefault();
  e.stopPropagation();
  resizing = true;
  resizeStartX = e.clientX;
  resizeStartY = e.clientY;
  resizeStartSize = mapSize;
  document.addEventListener('mousemove', handleResizeMove);
  document.addEventListener('mouseup', handleResizeEnd);
}

function handleResizeMove(e: MouseEvent): void {
  if (!resizing) return;
  // Dragging left/down = bigger, right/up = smaller
  // Since map is top-right corner, dragging the bottom-left handle left makes it wider
  const dx = resizeStartX - e.clientX;
  const dy = e.clientY - resizeStartY;
  const delta = Math.max(dx, dy);
  const newSize = Math.round(Math.min(MAX_MAP_SIZE, Math.max(MIN_MAP_SIZE, resizeStartSize + delta)));
  if (newSize !== mapSize) {
    mapSize = newSize;
    applyCanvasSize();
  }
}

function handleResizeEnd(): void {
  resizing = false;
  document.removeEventListener('mousemove', handleResizeMove);
  document.removeEventListener('mouseup', handleResizeEnd);
}
