/**
 * MegastructureRenderer — Three.js visuals for Orbital Platform, Dyson Swarm,
 * Human Habitat, and Relay Network.
 *
 * Orbital Platform: large rotating ring above the base station.
 * Dyson Swarm: growing constellation of mirrors around the system star (origin).
 * Human Habitat: 225m-radius rotating ring with 3 construction stages.
 * Relay Network: deep-space signal array with 4 construction stages.
 *
 * AST-30, MUL-1512, MUL-1670
 */

import {
  BoxGeometry,
  CylinderGeometry,
  Group,
  Mesh,
  MeshStandardMaterial,
  Scene,
  SphereGeometry,
  TorusGeometry,
} from 'three';
import type { MegastructureProjectSnapshot } from '../shared/megastructureTypes';
import type { SimHabitatStateMessage } from '../shared/habitatTypes';

type HabitatPayload = SimHabitatStateMessage['payload'];

export class MegastructureRenderer {
  private scene: Scene;

  // Orbital Platform
  private platformGroup: Group;
  private platformRings: Mesh[] = [];
  private platformHub: Mesh | null = null;
  private platformStage = 0; // 0 = hidden

  // Dyson Swarm
  private swarmGroup: Group;
  private swarmCollectors: Mesh[] = [];
  private swarmStage = 0;

  // Human Habitat
  private habitatGroup: Group;
  private habitatRing: Mesh | null = null;           // main torus, always present when visible
  private habitatSpokes: Mesh[] = [];                // stage 2+: module spokes
  private habitatGlowRing: Mesh | null = null;       // stage 3: inner glow ring
  private habitatRingMat: MeshStandardMaterial | null = null;
  private habitatGlowMat: MeshStandardMaterial | null = null;
  private habitatStage = 0;

  // Relay Network
  private relayGroup: Group;
  private relayDish: Mesh | null = null;           // stage 1: central signal dish
  private relayNodes: Mesh[] = [];                  // stage 2+: amplifier node ring
  private relayBridgeRing: Mesh | null = null;      // stage 3+: resonance bridge ring
  private relayPulseRing: Mesh | null = null;       // stage 4: pulsing signal ring
  private relayDishMat: MeshStandardMaterial | null = null;
  private relayPulseMat: MeshStandardMaterial | null = null;
  private relayStage = 0;

  constructor(scene: Scene, baseX: number, baseY: number, baseZ: number) {
    this.scene = scene;

    // ── Orbital Platform (above base) ─────────────────────────────────────────
    this.platformGroup = new Group();
    this.platformGroup.position.set(baseX, baseY + 400, baseZ);
    this.platformGroup.visible = false;
    scene.add(this.platformGroup);

    // Stage 1: Scaffold — single scaffold ring
    const scaffoldGeo = new TorusGeometry(120, 4, 8, 48);
    const scaffoldMat = new MeshStandardMaterial({
      color: 0x6b7280,
      emissive: 0x374151,
      emissiveIntensity: 0.3,
      metalness: 0.9,
      roughness: 0.3,
      wireframe: false,
    });
    const scaffoldRing = new Mesh(scaffoldGeo, scaffoldMat);
    scaffoldRing.rotation.x = Math.PI / 2;
    this.platformGroup.add(scaffoldRing);
    this.platformRings.push(scaffoldRing);

    // Stage 2: Core — inner ring with glow
    const coreGeo = new TorusGeometry(70, 8, 12, 48);
    const coreMat = new MeshStandardMaterial({
      color: 0x3b82f6,
      emissive: 0x1d4ed8,
      emissiveIntensity: 1.0,
      metalness: 0.8,
      roughness: 0.2,
    });
    const coreRing = new Mesh(coreGeo, coreMat);
    coreRing.rotation.x = Math.PI / 2;
    this.platformGroup.add(coreRing);
    this.platformRings.push(coreRing);

    // Stage 2: Hub sphere
    const hubGeo = new SphereGeometry(25, 16, 16);
    const hubMat = new MeshStandardMaterial({
      color: 0x60a5fa,
      emissive: 0x2563eb,
      emissiveIntensity: 1.2,
      metalness: 0.7,
      roughness: 0.2,
    });
    this.platformHub = new Mesh(hubGeo, hubMat);
    this.platformGroup.add(this.platformHub);

    // Stage 3: Outer ring — massive
    const outerGeo = new TorusGeometry(200, 10, 8, 64);
    const outerMat = new MeshStandardMaterial({
      color: 0xfbbf24,
      emissive: 0xd97706,
      emissiveIntensity: 0.8,
      metalness: 0.9,
      roughness: 0.1,
    });
    const outerRing = new Mesh(outerGeo, outerMat);
    outerRing.rotation.x = Math.PI / 2;
    this.platformGroup.add(outerRing);
    this.platformRings.push(outerRing);

    // ── Dyson Swarm (at system center) ────────────────────────────────────────
    this.swarmGroup = new Group();
    this.swarmGroup.position.set(0, 0, 0);
    this.swarmGroup.visible = false;
    scene.add(this.swarmGroup);

    // Star at center
    const starGeo = new SphereGeometry(80, 16, 16);
    const starMat = new MeshStandardMaterial({
      color: 0xfef08a,
      emissive: 0xfde047,
      emissiveIntensity: 3.0,
      metalness: 0,
      roughness: 1,
    });
    const star = new Mesh(starGeo, starMat);
    this.swarmGroup.add(star);

    // Generate collector mirrors (spawn lazily based on stage)
    this._buildCollectors();

    // ── Human Habitat (offset from base, above) ────────────────────────────
    // Positioned to the side of the base at a different height than the
    // Orbital Platform so both can be seen distinctly.
    this.habitatGroup = new Group();
    this.habitatGroup.position.set(baseX + 350, baseY + 300, baseZ);
    this.habitatGroup.visible = false;
    scene.add(this.habitatGroup);

    this._buildHabitatGeometry();

    // ── Relay Network (far offset, post-Dyson endgame) ────────────────────
    this.relayGroup = new Group();
    this.relayGroup.position.set(baseX - 500, baseY + 500, baseZ - 300);
    this.relayGroup.visible = false;
    scene.add(this.relayGroup);

    this._buildRelayGeometry();
  }

  private _buildHabitatGeometry(): void {
    // ── Stage 1+: Main ring (wireframe-look at stage 1, solid at 2+) ──────
    // 225m radius torus. Low radial segments give a "structural skeleton" look
    // at stage 1; we'll swap to full segments at stage 2 by replacing material.
    const ringGeo = new TorusGeometry(225, 6, 8, 56);
    this.habitatRingMat = new MeshStandardMaterial({
      color: 0x94a3b8,
      emissive: 0x1e3a5f,
      emissiveIntensity: 0.2,
      metalness: 0.9,
      roughness: 0.4,
      wireframe: true,  // Stage 1: wireframe skeleton
    });
    this.habitatRing = new Mesh(ringGeo, this.habitatRingMat);
    // Ring lies in the XZ plane (horizontal spin gravity axis is Y)
    this.habitatRing.rotation.x = Math.PI / 2;
    this.habitatGroup.add(this.habitatRing);

    // ── Stage 2+: Module spokes (4 structural modules evenly spaced) ───────
    const spokeGeo = new BoxGeometry(12, 8, 180);
    const spokeMat = new MeshStandardMaterial({
      color: 0x475569,
      emissive: 0x1e293b,
      emissiveIntensity: 0.3,
      metalness: 0.85,
      roughness: 0.3,
    });
    for (let i = 0; i < 4; i++) {
      const spoke = new Mesh(spokeGeo, spokeMat);
      spoke.rotation.y = (i / 4) * Math.PI * 2;
      spoke.visible = false;
      this.habitatGroup.add(spoke);
      this.habitatSpokes.push(spoke);
    }

    // ── Stage 3: Inner glow ring (life support / human presence indicator) ─
    const glowGeo = new TorusGeometry(180, 4, 8, 56);
    this.habitatGlowMat = new MeshStandardMaterial({
      color: 0x7dd3fc,
      emissive: 0x0ea5e9,
      emissiveIntensity: 1.4,
      metalness: 0.6,
      roughness: 0.2,
    });
    this.habitatGlowRing = new Mesh(glowGeo, this.habitatGlowMat);
    this.habitatGlowRing.rotation.x = Math.PI / 2;
    this.habitatGlowRing.visible = false;
    this.habitatGroup.add(this.habitatGlowRing);
  }

  private _buildRelayGeometry(): void {
    // ── Stage 1: Central signal dish (cone + sphere antenna) ──────────────
    const dishGeo = new CylinderGeometry(2, 50, 30, 16, 1, true);
    this.relayDishMat = new MeshStandardMaterial({
      color: 0x818cf8,
      emissive: 0x4f46e5,
      emissiveIntensity: 0.4,
      metalness: 0.9,
      roughness: 0.2,
    });
    this.relayDish = new Mesh(dishGeo, this.relayDishMat);
    this.relayDish.rotation.x = Math.PI; // dish opens upward
    this.relayGroup.add(this.relayDish);

    // Antenna tip at top of dish
    const antennaGeo = new SphereGeometry(6, 8, 8);
    const antennaMat = new MeshStandardMaterial({
      color: 0xa78bfa,
      emissive: 0x7c3aed,
      emissiveIntensity: 1.0,
      metalness: 0.7,
      roughness: 0.3,
    });
    const antenna = new Mesh(antennaGeo, antennaMat);
    antenna.position.set(0, 25, 0);
    this.relayGroup.add(antenna);

    // ── Stage 2+: Amplifier node ring (8 satellite nodes) ─────────────────
    const nodeGeo = new SphereGeometry(10, 8, 8);
    const nodeMat = new MeshStandardMaterial({
      color: 0x6366f1,
      emissive: 0x4338ca,
      emissiveIntensity: 0.8,
      metalness: 0.85,
      roughness: 0.2,
    });
    for (let i = 0; i < 8; i++) {
      const angle = (i / 8) * Math.PI * 2;
      const node = new Mesh(nodeGeo, nodeMat);
      node.position.set(Math.cos(angle) * 140, 0, Math.sin(angle) * 140);
      node.visible = false;
      this.relayGroup.add(node);
      this.relayNodes.push(node);
    }

    // ── Stage 3+: Resonance bridge ring (connecting the nodes) ────────────
    const bridgeGeo = new TorusGeometry(140, 3, 8, 48);
    const bridgeMat = new MeshStandardMaterial({
      color: 0xa78bfa,
      emissive: 0x7c3aed,
      emissiveIntensity: 0.6,
      metalness: 0.8,
      roughness: 0.3,
    });
    this.relayBridgeRing = new Mesh(bridgeGeo, bridgeMat);
    this.relayBridgeRing.rotation.x = Math.PI / 2;
    this.relayBridgeRing.visible = false;
    this.relayGroup.add(this.relayBridgeRing);

    // ── Stage 4: Outer pulse ring (operational signal transmission) ───────
    const pulseGeo = new TorusGeometry(200, 2, 8, 64);
    this.relayPulseMat = new MeshStandardMaterial({
      color: 0xc4b5fd,
      emissive: 0x8b5cf6,
      emissiveIntensity: 1.6,
      metalness: 0.6,
      roughness: 0.1,
    });
    this.relayPulseRing = new Mesh(pulseGeo, this.relayPulseMat);
    this.relayPulseRing.rotation.x = Math.PI / 2;
    this.relayPulseRing.visible = false;
    this.relayGroup.add(this.relayPulseRing);
  }

  private _buildCollectors(): void {
    const collectorCounts = [8, 20, 40, 80, 160]; // per stage
    const collectorMat = new MeshStandardMaterial({
      color: 0xfbbf24,
      emissive: 0xf59e0b,
      emissiveIntensity: 1.5,
      metalness: 0.95,
      roughness: 0.05,
    });

    let totalForStage5 = 0;
    for (const c of collectorCounts) totalForStage5 += c;

    const collectorGeo = new BoxGeometry(8, 0.5, 12);

    for (let i = 0; i < totalForStage5; i++) {
      const collector = new Mesh(collectorGeo, collectorMat);
      // Distribute on sphere around star
      const phi = Math.acos(2 * this._rng(i * 2) - 1);
      const theta = 2 * Math.PI * this._rng(i * 2 + 1);
      const r = 300 + (i % 5) * 200;
      collector.position.set(
        r * Math.sin(phi) * Math.cos(theta),
        r * Math.sin(phi) * Math.sin(theta),
        r * Math.cos(phi),
      );
      collector.lookAt(0, 0, 0);
      collector.visible = false;
      this.swarmGroup.add(collector);
      this.swarmCollectors.push(collector);
    }
  }

  /** Simple deterministic pseudo-random for stable collector placement */
  private _rng(seed: number): number {
    const x = Math.sin(seed + 1) * 43758.5453123;
    return x - Math.floor(x);
  }

  /** Update visible elements based on current megastructure project snapshots */
  update(
    projects: MegastructureProjectSnapshot[],
    time: number,
    habitatState: HabitatPayload | null = null,
  ): void {
    const platform = projects.find((p) => p.id === 'orbital_platform');
    const swarm = projects.find((p) => p.id === 'dyson_swarm');
    const habitat = projects.find((p) => p.id === 'human_habitat');
    const relay = projects.find((p) => p.id === 'relay_network');

    const newPlatformStage = platform?.completedStages ?? 0;
    const newSwarmStage = swarm?.completedStages ?? 0;
    const newHabitatStage = habitat?.completedStages ?? 0;
    const newRelayStage = relay?.completedStages ?? 0;

    // Update Orbital Platform visibility
    if (newPlatformStage !== this.platformStage) {
      this.platformStage = newPlatformStage;
      this._updatePlatformVisibility();
    }

    // Update Dyson Swarm visibility
    if (newSwarmStage !== this.swarmStage) {
      this.swarmStage = newSwarmStage;
      this._updateSwarmVisibility();
    }

    // Update Habitat visibility
    if (newHabitatStage !== this.habitatStage) {
      this.habitatStage = newHabitatStage;
      this._updateHabitatVisibility();
    }

    // Update Relay Network visibility
    if (newRelayStage !== this.relayStage) {
      this.relayStage = newRelayStage;
      this._updateRelayVisibility();
    }

    // Animate
    if (this.platformGroup.visible) {
      // Outer rings rotate at different speeds
      this.platformGroup.rotation.y = time * 0.05;
      if (this.platformRings[0]) this.platformRings[0].rotation.z = time * 0.08;
      if (this.platformRings[2]) this.platformRings[2].rotation.z = -time * 0.03;
    }

    if (this.swarmGroup.visible) {
      this.swarmGroup.rotation.y = time * 0.01;
    }

    if (this.habitatGroup.visible) {
      // Continuous slow spin on local Y axis (simulating spin gravity)
      this.habitatGroup.rotation.y = time * 0.04;

      // Active habitat glow: colonists are present when megastructure complete
      const hasColonists = (habitat?.complete ?? false) && !(habitatState?.dormant ?? false);
      const inCrisis = (habitat?.activeCrisis !== null && habitat?.activeCrisis !== undefined)
        || (habitatState?.dormant ?? false);

      if (this.habitatRingMat) {
        if (inCrisis) {
          // Crisis: red tint with flicker
          const flicker = 0.5 + 0.5 * Math.sin(time * 12);
          this.habitatRingMat.color.setHex(0xef4444);
          this.habitatRingMat.emissive.setHex(0x7f1d1d);
          this.habitatRingMat.emissiveIntensity = 0.4 + flicker * 0.8;
        } else if (hasColonists) {
          // Active: warm glow indicating human presence
          this.habitatRingMat.color.setHex(0x93c5fd);
          this.habitatRingMat.emissive.setHex(0x1d4ed8);
          this.habitatRingMat.emissiveIntensity = 0.8;
        } else {
          // Normal construction state — restore defaults
          this.habitatRingMat.color.setHex(0x94a3b8);
          this.habitatRingMat.emissive.setHex(0x1e3a5f);
          this.habitatRingMat.emissiveIntensity = this.habitatStage >= 2 ? 0.35 : 0.2;
        }
      }

      if (this.habitatGlowMat && this.habitatGlowRing?.visible) {
        if (inCrisis) {
          this.habitatGlowMat.emissive.setHex(0xdc2626);
          this.habitatGlowMat.emissiveIntensity = 0.6 + 0.5 * Math.sin(time * 12);
        } else {
          this.habitatGlowMat.emissive.setHex(0x0ea5e9);
          this.habitatGlowMat.emissiveIntensity = hasColonists ? 1.8 : 1.4;
        }
      }
    }

    if (this.relayGroup.visible) {
      // Slow counter-rotation for the relay array
      this.relayGroup.rotation.y = -time * 0.02;

      // Crisis: red flicker on dish
      const relayCrisis = relay?.activeCrisis !== null && relay?.activeCrisis !== undefined;
      if (this.relayDishMat) {
        if (relayCrisis) {
          const flicker = 0.5 + 0.5 * Math.sin(time * 12);
          this.relayDishMat.color.setHex(0xef4444);
          this.relayDishMat.emissive.setHex(0x7f1d1d);
          this.relayDishMat.emissiveIntensity = 0.4 + flicker * 0.8;
        } else {
          this.relayDishMat.color.setHex(0x818cf8);
          this.relayDishMat.emissive.setHex(0x4f46e5);
          this.relayDishMat.emissiveIntensity = 0.4;
        }
      }

      // Pulse ring: rhythmic signal transmission effect
      if (this.relayPulseMat && this.relayPulseRing?.visible) {
        const pulse = 0.8 + 0.8 * Math.sin(time * 3);
        this.relayPulseMat.emissiveIntensity = relayCrisis ? 0.3 : 1.2 + pulse;
      }
    }
  }

  private _updatePlatformVisibility(): void {
    this.platformGroup.visible = this.platformStage > 0;

    // Stage 1+: scaffold ring
    if (this.platformRings[0]) this.platformRings[0].visible = this.platformStage >= 1;

    // Stage 2+: core ring + hub
    if (this.platformRings[1]) this.platformRings[1].visible = this.platformStage >= 2;
    if (this.platformHub) this.platformHub.visible = this.platformStage >= 2;

    // Stage 3: outer ring
    if (this.platformRings[2]) this.platformRings[2].visible = this.platformStage >= 3;
  }

  private _updateSwarmVisibility(): void {
    this.swarmGroup.visible = this.swarmStage > 0;

    const stageCollectorCounts = [8, 20, 40, 80, 160];
    let visibleCount = 0;
    for (let s = 0; s < this.swarmStage; s++) {
      visibleCount += stageCollectorCounts[s] ?? 0;
    }

    for (let i = 0; i < this.swarmCollectors.length; i++) {
      this.swarmCollectors[i].visible = i < visibleCount;
    }
  }

  private _updateHabitatVisibility(): void {
    this.habitatGroup.visible = this.habitatStage > 0;

    if (!this.habitatRing || !this.habitatRingMat) return;

    // Stage 1: wireframe skeleton ring only
    this.habitatRing.visible = this.habitatStage >= 1;
    this.habitatRingMat.wireframe = this.habitatStage < 2;

    // Stage 2+: solid ring + module spokes
    for (const spoke of this.habitatSpokes) {
      spoke.visible = this.habitatStage >= 2;
    }

    // Stage 3: inner glow ring (life support active)
    if (this.habitatGlowRing) {
      this.habitatGlowRing.visible = this.habitatStage >= 3;
    }
  }

  private _updateRelayVisibility(): void {
    this.relayGroup.visible = this.relayStage > 0;

    // Stage 1+: central signal dish (always visible once started)
    if (this.relayDish) this.relayDish.visible = this.relayStage >= 1;

    // Stage 2+: amplifier node ring
    for (const node of this.relayNodes) {
      node.visible = this.relayStage >= 2;
    }

    // Stage 3+: resonance bridge ring connecting nodes
    if (this.relayBridgeRing) this.relayBridgeRing.visible = this.relayStage >= 3;

    // Stage 4: outer pulse ring (full operation)
    if (this.relayPulseRing) this.relayPulseRing.visible = this.relayStage >= 4;
  }

  dispose(): void {
    // Dispose platform ring geometries and materials
    for (const mesh of this.platformRings) {
      mesh.geometry.dispose();
      (mesh.material as MeshStandardMaterial).dispose();
    }
    if (this.platformHub) {
      this.platformHub.geometry.dispose();
      (this.platformHub.material as MeshStandardMaterial).dispose();
    }

    // Dispose swarm: star + all collectors share collectorGeo/collectorMat.
    // Track seen objects to avoid double-dispose on shared refs.
    const seenGeo = new Set<{ dispose(): void }>();
    const seenMat = new Set<{ dispose(): void }>();
    this.swarmGroup.traverse((obj) => {
      const mesh = obj as Mesh;
      if (!mesh.isMesh) return;
      if (!seenGeo.has(mesh.geometry)) {
        seenGeo.add(mesh.geometry);
        mesh.geometry.dispose();
      }
      const mat = mesh.material as MeshStandardMaterial;
      if (!seenMat.has(mat)) {
        seenMat.add(mat);
        mat.dispose();
      }
    });

    // Dispose habitat geometry
    if (this.habitatRing) {
      this.habitatRing.geometry.dispose();
      (this.habitatRing.material as MeshStandardMaterial).dispose();
    }
    if (this.habitatGlowRing) {
      this.habitatGlowRing.geometry.dispose();
      (this.habitatGlowRing.material as MeshStandardMaterial).dispose();
    }
    for (const spoke of this.habitatSpokes) {
      spoke.geometry.dispose();
      (spoke.material as MeshStandardMaterial).dispose();
    }

    // Dispose relay network geometry
    const seenRelayGeo = new Set<{ dispose(): void }>();
    const seenRelayMat = new Set<{ dispose(): void }>();
    this.relayGroup.traverse((obj) => {
      const mesh = obj as Mesh;
      if (!mesh.isMesh) return;
      if (!seenRelayGeo.has(mesh.geometry)) {
        seenRelayGeo.add(mesh.geometry);
        mesh.geometry.dispose();
      }
      const mat = mesh.material as MeshStandardMaterial;
      if (!seenRelayMat.has(mat)) {
        seenRelayMat.add(mat);
        mat.dispose();
      }
    });

    this.platformGroup.parent?.remove(this.platformGroup);
    this.swarmGroup.parent?.remove(this.swarmGroup);
    this.habitatGroup.parent?.remove(this.habitatGroup);
    this.relayGroup.parent?.remove(this.relayGroup);
  }
}
