/**
 * Lore handlers: sim:study_update, sim:lore_fragment, sim:event (anomaly),
 * sim:narrative_event.
 */
import type {
  WorkerToMainMessage,
  SimStudyUpdateMessage,
  SimLoreFragmentMessage,
  SimEventMessage,
  SimNarrativeEventMessage,
} from '../sim/messages';
import { LORE_FRAGMENTS } from '../sim/anomalyStudy';
import { ANOMALY_TYPE_NAMES } from '../sim/anomalyTypes';
import { updateCodexEntry, addRevelation, recordDiscoveryTick, checkFirstUnderstoodMilestone } from '../ui/codexPanel';
import { showAnomalyToast, showNotification, showScreenFlash } from '../ui/notifications';
import { showEventModal, showEventToast } from '../ui/eventModal';
import { showEndScreen } from '../ui/endScreen';
import { showHint } from '../ui/hints';
import { advanceTutorialIfOnStep } from '../ui/tutorial';
import { updateMinimapAnomalies } from '../ui/minimap';
import { audioEngine } from '../audio/audioEngine';
import { playSfx } from '../audio/sfxEngine';
import { musicManager } from '../audio/musicManager';
import { discoveries, storageValues } from '../gameRuntimeState';
import type { Discovery } from '../gameRuntimeState';
import type { HandlerContext, HandlerMap } from './types';

export function registerLoreHandlers(ctx: HandlerContext): HandlerMap {
  const { worker, refs, lazy } = ctx;

  return {
    'sim:study_update': (msg: WorkerToMainMessage) => {
      const studyMsg = msg as SimStudyUpdateMessage;
      for (const entry of studyMsg.payload.entries) {
        updateCodexEntry(
          entry.asteroidEid,
          entry.anomalyType,
          entry.stage,
          entry.progress,
          entry.revealedFragments,
        );
      }
    },

    'sim:lore_fragment': (msg: WorkerToMainMessage) => {
      const loreMsg = msg as SimLoreFragmentMessage;
      const { asteroidEid, anomalyType, stage, newFragmentIndices, chainNextType, revelation } = loreMsg.payload;
      updateCodexEntry(asteroidEid, anomalyType, stage, 0, newFragmentIndices);
      const allFragments = LORE_FRAGMENTS[anomalyType] ?? [];
      for (const fi of newFragmentIndices) {
        if (fi < allFragments.length) {
          showNotification(`[CODEX] ${allFragments[fi].slice(0, 80)}…`, '#06b6d4');
          audioEngine.playLoreReveal();
        }
      }
      if (revelation) {
        addRevelation(revelation);
        showNotification(`[ARIA] ${revelation.slice(0, 100)}…`, '#a855f7');
        lazy.getDashboard()?.addExplorationEvent(
          `[ARIA] ${revelation.slice(0, 80)}`,
          '#a855f7',
          loreMsg.payload.tick,
        );
      }
      if (chainNextType > 0) {
        console.log(`[main] Discovery chain triggered: anomaly type ${chainNextType} can now be found`);
      }
      // ARIA milestone: first fully-understood anomaly
      if (checkFirstUnderstoodMilestone()) {
        const milestoneText = "ARIA: You've fully mapped one of the Belt's secrets. There are more.";
        showNotification(`[ARIA] ${milestoneText}`, '#a855f7');
        addRevelation(milestoneText);
        lazy.getDashboard()?.addExplorationEvent(
          '[ARIA] First anomaly fully understood',
          '#a855f7',
          loreMsg.payload.tick,
        );
      }
    },

    'sim:narrative_event': (msg: WorkerToMainMessage) => {
      const nevt = msg as SimNarrativeEventMessage;
      const { event, tick: evtTick, endScreenStats } = nevt.payload;
      if (event.type === 'revelation' || event.type === 'dilemma') {
        showEventModal(event, evtTick, (eventId, choiceId) => {
          worker.postMessage({ type: 'sim:event_choice', payload: { eventId, choiceId } });
          if (endScreenStats) {
            showEndScreen({ tick: evtTick, ...endScreenStats });
          }
        });
      } else {
        showEventToast(event, evtTick);
      }

      if (event.id === 'alien_phase1_faint_readings') {
        showHint('midgame_dark_forest', 'ARIA: A narrative choice is approaching. It will shape the fleet\'s future — not a combat encounter. Press L to review the event log.');
      }
      if (event.id === 'humans_arrive') {
        showHint('midgame_habitat', 'ARIA: Colonists bring demands and morale. Check the inbox for their requests — unresolved demands cost morale.');
      }
    },

    'sim:event': (msg: WorkerToMainMessage) => {
      const evt = msg as SimEventMessage;
      if (evt.payload.kind === 'anomaly_discovered') {
        const d: Discovery = {
          robotEid: evt.payload.robotEid,
          asteroidEid: evt.payload.asteroidEid,
          anomalyType: evt.payload.anomalyType,
          x: evt.payload.x,
          y: evt.payload.y,
          z: evt.payload.z,
          tick: evt.payload.tick,
        };
        discoveries.push(d);
        recordDiscoveryTick(d.asteroidEid, d.tick);
        showAnomalyToast(d.robotEid, d.anomalyType, d.x, d.y, d.z);
        showScreenFlash('#a855f7', 600);
        audioEngine.playDiscovery();
        playSfx('game.anomaly_detected');
        showHint('anomaly_aria', 'Press A to ask ARIA about this discovery');
        updateMinimapAnomalies(discoveries.map((dd) => ({ x: dd.x, z: dd.z })));
        lazy.getDashboard()?.updateDashboardAnomalies(discoveries);
        advanceTutorialIfOnStep('anomaly');
        lazy.getDashboard()?.addExplorationEvent(
          `[Anomaly] ${ANOMALY_TYPE_NAMES[d.anomalyType] ?? 'Unknown'} at (${Math.round(d.x)},${Math.round(d.z)})`,
          '#a855f7',
          d.tick,
        );

        const anomalyName = ANOMALY_TYPE_NAMES[d.anomalyType] ?? 'Unknown Anomaly';
        void lazy.loadAdvisorLazy()
          .then((m) => {
            lazy.initAdvisorOnce(m);
            const gameState = m.gameState.buildGameState(
              storageValues,
              refs.latestRobotBuffer,
              refs.latestRobotCount,
              refs.latestAsteroidBuffer,
              refs.latestAsteroidCount,
              discoveries,
              refs.latestTick,
              refs.latestBuildings,
              {
                refined: refs.latestRefined,
                techState: refs.latestTechState,
                factoryQueueLength: refs.latestFactoryQueueLength,
                robotCap: refs.latestRobotCap,
              },
            );
            m.panel.setLoading(true);
            return m.service.askAdvisorAboutAnomaly(
              d.anomalyType,
              d.asteroidEid,
              anomalyName,
              d.x,
              d.y,
              d.z,
              gameState,
            );
          })
          .then((response) => {
            lazy.getAdvisor()?.panel.addAdvisorMessage(response);
            lazy.getAdvisor()?.panel.setLoading(false);
          })
          .catch(() => lazy.getAdvisor()?.panel.setLoading(false));
      }
    },
  };
}
