import { PerspectiveCamera, Vector3 } from 'three';

export interface CameraState {
  pivot: Vector3;
  zoomDistance: number;
  pitchAngle: number; // radians above ecliptic plane
  viewBoundsMin: Vector3;
  viewBoundsMax: Vector3;
}

const MIN_DISTANCE = 50;
const MAX_DISTANCE = 200000;
const ZOOM_SPEED = 0.08;
const PAN_DAMP = 0.92; // exponential decay factor
const WASD_SPEED_FACTOR = 0.5; // speed relative to zoom distance
const ZOOM_SMOOTH = 0.08; // interpolation factor per frame
const PITCH_SPEED = 0.02; // radians per scroll tick
const PITCH_SMOOTH = 0.08; // interpolation factor per frame
const MIN_PITCH = 5 * Math.PI / 180; // 5 degrees
const MAX_PITCH = 80 * Math.PI / 180; // 80 degrees
const DEFAULT_PITCH = Math.atan2(0.8, 0.3); // ~69.4 degrees — matches original fixed angle

export class CameraRig {
  private camera: PerspectiveCamera;
  private pivot = new Vector3();
  private zoomLevel = 6; // log-space zoom
  private targetZoomLevel = 6;
  private pitchAngle = DEFAULT_PITCH; // radians above ecliptic
  private targetPitchAngle = DEFAULT_PITCH;
  private panVelocity = new Vector3();
  private enabled = true;
  private followTarget: Vector3 | null = null;

  // Smooth pan state
  private targetPivot: Vector3 | null = null;
  private panStartPivot = new Vector3();
  private panDurationMs = 0;
  private panElapsedMs = 0;

  // Mouse input state
  private keys: Set<string> = new Set();
  private isDragging = false;
  private dragButton = -1;
  private dragMoved = false;
  private lastMouse = { x: 0, y: 0 };
  private dragStartMouse = { x: 0, y: 0 };
  private static readonly DRAG_THRESHOLD = 5; // pixels before left-click drag activates

  // Touch input state
  private isTouchPanning = false;
  private lastTouchX = 0;
  private lastTouchY = 0;
  private lastPinchDistance = 0;

  constructor(camera: PerspectiveCamera) {
    this.camera = camera;
    this.bindEvents();
  }

  private onContextMenu = (e: Event): void => { e.preventDefault(); };

  private bindEvents(): void {
    window.addEventListener('wheel', this.onWheel, { passive: false });
    window.addEventListener('mousedown', this.onMouseDown);
    window.addEventListener('mousemove', this.onMouseMove);
    window.addEventListener('mouseup', this.onMouseUp);
    window.addEventListener('keydown', this.onKeyDown);
    window.addEventListener('keyup', this.onKeyUp);
    window.addEventListener('contextmenu', this.onContextMenu);
    window.addEventListener('touchstart', this.onTouchStart, { passive: false });
    window.addEventListener('touchmove', this.onTouchMove, { passive: false });
    window.addEventListener('touchend', this.onTouchEnd, { passive: false });
  }

  dispose(): void {
    window.removeEventListener('wheel', this.onWheel);
    window.removeEventListener('mousedown', this.onMouseDown);
    window.removeEventListener('mousemove', this.onMouseMove);
    window.removeEventListener('mouseup', this.onMouseUp);
    window.removeEventListener('keydown', this.onKeyDown);
    window.removeEventListener('keyup', this.onKeyUp);
    window.removeEventListener('contextmenu', this.onContextMenu);
    window.removeEventListener('touchstart', this.onTouchStart);
    window.removeEventListener('touchmove', this.onTouchMove);
    window.removeEventListener('touchend', this.onTouchEnd);
  }

  private onTouchStart = (e: TouchEvent): void => {
    if (!this.enabled) return;
    if (e.touches.length === 1) {
      this.isTouchPanning = true;
      this.lastTouchX = e.touches[0].clientX;
      this.lastTouchY = e.touches[0].clientY;
    } else if (e.touches.length === 2) {
      this.isTouchPanning = false;
      const dx = e.touches[0].clientX - e.touches[1].clientX;
      const dy = e.touches[0].clientY - e.touches[1].clientY;
      this.lastPinchDistance = Math.sqrt(dx * dx + dy * dy);
    }
  };

  private onTouchMove = (e: TouchEvent): void => {
    if (!this.enabled) return;
    e.preventDefault();
    if (e.touches.length === 1 && this.isTouchPanning) {
      const dx = e.touches[0].clientX - this.lastTouchX;
      const dy = e.touches[0].clientY - this.lastTouchY;
      this.lastTouchX = e.touches[0].clientX;
      this.lastTouchY = e.touches[0].clientY;
      const distance = this.getCurrentDistance();
      const panScale = distance * 0.002;
      this.panVelocity.x -= dx * panScale;
      this.panVelocity.z -= dy * panScale;
    } else if (e.touches.length === 2) {
      const dx = e.touches[0].clientX - e.touches[1].clientX;
      const dy = e.touches[0].clientY - e.touches[1].clientY;
      const pinchDist = Math.sqrt(dx * dx + dy * dy);
      const delta = this.lastPinchDistance - pinchDist;
      this.lastPinchDistance = pinchDist;
      // Map pinch to zoom: positive delta = pinch in = zoom in
      const zoomDelta = (delta / window.innerHeight) * 2;
      this.targetZoomLevel += zoomDelta;
      this.targetZoomLevel = Math.max(
        Math.log(MIN_DISTANCE),
        Math.min(Math.log(MAX_DISTANCE), this.targetZoomLevel),
      );
    }
  };

  private onTouchEnd = (e: TouchEvent): void => {
    if (e.touches.length === 0) {
      this.isTouchPanning = false;
    } else if (e.touches.length === 1) {
      // Transitioned from pinch to single finger — reset pan
      this.isTouchPanning = true;
      this.lastTouchX = e.touches[0].clientX;
      this.lastTouchY = e.touches[0].clientY;
    }
  };

  private onWheel = (e: WheelEvent): void => {
    if (!this.enabled) return;
    // Don't intercept scroll events originating inside UI overlay panels
    if ((e.target as Element)?.closest('#hud-overlay')) return;
    e.preventDefault();
    if (e.shiftKey) {
      // Shift+scroll adjusts pitch (tilt above ecliptic plane)
      this.targetPitchAngle += e.deltaY > 0 ? -PITCH_SPEED : PITCH_SPEED;
      this.targetPitchAngle = Math.max(MIN_PITCH, Math.min(MAX_PITCH, this.targetPitchAngle));
    } else {
      this.targetZoomLevel += e.deltaY > 0 ? ZOOM_SPEED : -ZOOM_SPEED;
      this.targetZoomLevel = Math.max(
        Math.log(MIN_DISTANCE),
        Math.min(Math.log(MAX_DISTANCE), this.targetZoomLevel),
      );
    }
  };

  private onMouseDown = (e: MouseEvent): void => {
    if (!this.enabled) return;
    // Don't start drag inside HUD overlay UI elements
    if ((e.target as Element)?.closest('#hud-overlay [style*="pointer-events: auto"], #hud-overlay button, #hud-overlay input, #hud-overlay select')) return;
    if (e.button === 0 || e.button === 1 || e.button === 2) {
      // left, middle, or right click — all start drag
      this.isDragging = true;
      this.dragButton = e.button;
      this.lastMouse.x = e.clientX;
      this.lastMouse.y = e.clientY;
      this.dragStartMouse.x = e.clientX;
      this.dragStartMouse.y = e.clientY;
      this.dragMoved = false;
    }
  };

  private onMouseMove = (e: MouseEvent): void => {
    if (!this.enabled || !this.isDragging) return;

    // For left-click drag, require a minimum movement threshold before panning
    // to avoid interfering with click-to-select interactions
    if (this.dragButton === 0 && !this.dragMoved) {
      const distX = Math.abs(e.clientX - this.dragStartMouse.x);
      const distY = Math.abs(e.clientY - this.dragStartMouse.y);
      if (distX < CameraRig.DRAG_THRESHOLD && distY < CameraRig.DRAG_THRESHOLD) return;
      this.dragMoved = true;
      // Snap lastMouse to current position to avoid a jump
      this.lastMouse.x = e.clientX;
      this.lastMouse.y = e.clientY;
      return;
    }

    const dx = e.clientX - this.lastMouse.x;
    const dy = e.clientY - this.lastMouse.y;
    this.lastMouse.x = e.clientX;
    this.lastMouse.y = e.clientY;

    const distance = this.getCurrentDistance();
    const panScale = distance * 0.002;
    this.panVelocity.x -= dx * panScale;
    this.panVelocity.z -= dy * panScale;
  };

  private onMouseUp = (e: MouseEvent): void => {
    if (e.button === this.dragButton) {
      this.isDragging = false;
      this.dragButton = -1;
    }
  };

  private onKeyDown = (e: KeyboardEvent): void => {
    if (!this.enabled) return;
    const el = document.activeElement;
    if (el instanceof HTMLInputElement || el instanceof HTMLTextAreaElement) return;
    this.keys.add(e.key.toLowerCase());
  };

  private onKeyUp = (e: KeyboardEvent): void => {
    this.keys.delete(e.key.toLowerCase());
  };

  getCurrentDistance(): number {
    return Math.exp(this.zoomLevel);
  }

  update(dt: number): void {
    if (!this.enabled) return;

    // Smooth zoom interpolation
    this.zoomLevel += (this.targetZoomLevel - this.zoomLevel) * ZOOM_SMOOTH;
    // Smooth pitch interpolation
    this.pitchAngle += (this.targetPitchAngle - this.pitchAngle) * PITCH_SMOOTH;

    const distance = this.getCurrentDistance();

    // Smooth pan interpolation
    if (this.targetPivot) {
      this.panElapsedMs += dt * 1000;
      const t = Math.min(this.panElapsedMs / this.panDurationMs, 1);
      // Ease-out cubic
      const ease = 1 - Math.pow(1 - t, 3);
      this.pivot.lerpVectors(this.panStartPivot, this.targetPivot, ease);
      this.panVelocity.set(0, 0, 0);
      if (t >= 1) this.targetPivot = null;
    }

    if (this.followTarget) {
      // Follow mode: lock pivot to target, suppress pan input
      this.pivot.copy(this.followTarget);
      this.panVelocity.set(0, 0, 0);
    } else if (!this.targetPivot) {
      // WASD input
      const wasdSpeed = distance * WASD_SPEED_FACTOR * dt;
      if (this.keys.has('w') || this.keys.has('arrowup')) this.panVelocity.z -= wasdSpeed;
      if (this.keys.has('s') || this.keys.has('arrowdown')) this.panVelocity.z += wasdSpeed;
      if (this.keys.has('a') || this.keys.has('arrowleft')) this.panVelocity.x -= wasdSpeed;
      if (this.keys.has('d') || this.keys.has('arrowright')) this.panVelocity.x += wasdSpeed;

      // Apply velocity with damping
      this.pivot.add(this.panVelocity);
      this.panVelocity.multiplyScalar(PAN_DAMP);
    }

    // Position camera using pitch angle (angle above ecliptic plane)
    this.camera.position.set(
      this.pivot.x,
      this.pivot.y + distance * Math.sin(this.pitchAngle),
      this.pivot.z + distance * Math.cos(this.pitchAngle),
    );
    this.camera.lookAt(this.pivot);
  }

  setFollowTarget(target: Vector3 | null): void {
    this.followTarget = target;
    if (target) this.panVelocity.set(0, 0, 0);
  }

  isFollowing(): boolean {
    return this.followTarget !== null;
  }

  getState(): CameraState {
    const distance = this.getCurrentDistance();
    const halfWidth = distance * Math.tan((this.camera.fov * Math.PI) / 360) * this.camera.aspect;
    const halfHeight = distance * Math.tan((this.camera.fov * Math.PI) / 360);
    return {
      pivot: this.pivot.clone(),
      zoomDistance: distance,
      pitchAngle: this.pitchAngle,
      viewBoundsMin: new Vector3(
        this.pivot.x - halfWidth,
        this.pivot.y - halfHeight,
        this.pivot.z - distance,
      ),
      viewBoundsMax: new Vector3(
        this.pivot.x + halfWidth,
        this.pivot.y + halfHeight,
        this.pivot.z + distance,
      ),
    };
  }

  setPivot(x: number, y: number, z: number): void {
    this.pivot.set(x, y, z);
    this.targetPivot = null; // cancel any active pan
  }

  panTo(x: number, y: number, z: number, durationMs: number = 800): void {
    this.panStartPivot.copy(this.pivot);
    this.targetPivot = new Vector3(x, y, z);
    this.panDurationMs = durationMs;
    this.panElapsedMs = 0;
    this.followTarget = null;
    this.panVelocity.set(0, 0, 0);
  }

  setZoom(level: number): void {
    this.zoomLevel = level;
    this.targetZoomLevel = level;
  }

  setPitch(radians: number): void {
    this.pitchAngle = Math.max(MIN_PITCH, Math.min(MAX_PITCH, radians));
    this.targetPitchAngle = this.pitchAngle;
  }

  getPitch(): number {
    return this.pitchAngle;
  }

  enable(): void {
    this.enabled = true;
  }

  disable(): void {
    this.enabled = false;
  }

  /** Returns true when a left-click drag pan is actively in progress. */
  wasDragPanning(): boolean {
    return this.dragButton === 0 && this.dragMoved;
  }
}
