/**
 * Shared fleet color palette data.
 *
 * Pure data + lookup — no sim state dependencies.
 * Imported by both sim and render layers.
 */

export interface FleetColorPalette {
  id: string;
  name: string;
  /** Primary color applied to robot models. */
  primary: string;
  /** Accent color for base station ring and UI highlights. */
  accent: string;
  /** Glow/emissive color for ambient lighting effects. */
  glow: string;
}

export const FLEET_COLOR_PALETTES: FleetColorPalette[] = [
  { id: 'emerald', name: 'Emerald Dawn', primary: '#22c55e', accent: '#4ade80', glow: '#166534' },
  { id: 'crimson', name: 'Crimson Vanguard', primary: '#ef4444', accent: '#f87171', glow: '#991b1b' },
  { id: 'azure', name: 'Azure Drift', primary: '#3b82f6', accent: '#60a5fa', glow: '#1e3a8a' },
  { id: 'amber', name: 'Amber Core', primary: '#f59e0b', accent: '#fbbf24', glow: '#92400e' },
  { id: 'violet', name: 'Violet Expanse', primary: '#a855f7', accent: '#c084fc', glow: '#581c87' },
  { id: 'silver', name: 'Silver Tide', primary: '#94a3b8', accent: '#cbd5e1', glow: '#475569' },
];

/** Look up a palette by ID. Returns undefined for unknown IDs. */
export function getFleetColorPalette(id: string): FleetColorPalette | undefined {
  return FLEET_COLOR_PALETTES.find((p) => p.id === id);
}
