/**
 * Epoch milestone overlay.
 *
 * Shown after the player acknowledges the final Dyson Sphere ending event.
 * Frames the Dyson Sphere as a prestige milestone — the belt's civilization
 * can now power an expedition to a new star system, or keep running forever.
 */

import { trapFocus } from './focusTrap';
import { readLegacy, writeLegacy, buildLegacyFromStats, LEGACY_KEY } from '../sim/legacy';
import { trackDysonComplete } from '../analytics';
import { safeHtml } from './utils/safeHtml';

let overlay: HTMLDivElement | null = null;
let removeFocusTrap: (() => void) | null = null;

/** Stats from the current run, captured when the end screen is shown. */
let currentRunStats: {
  tick: number;
  robotCount: number;
  topRobotName: string | null;
  legacyCount: number;
  cultureLabel: string;
} | null = null;

/** Whether the epoch milestone screen is currently visible. */
export function isEndScreenVisible(): boolean {
  return overlay !== null;
}

/** Dismiss the milestone screen (Remain in the Belt). */
export function dismissEndScreen(): void {
  if (!overlay) return;
  removeFocusTrap?.();
  removeFocusTrap = null;
  overlay.style.opacity = '0';
  setTimeout(() => {
    overlay?.remove();
    overlay = null;
  }, 300);
}

/** Clear save data and reload (New Star System — prestige restart). */
export function startNewGame(): void {
  // Capture legacy data before wiping localStorage
  const existing = readLegacy();
  const stats = currentRunStats ?? { tick: 0, topRobotName: null, legacyCount: 0, cultureLabel: 'Nascent' };
  const legacy = buildLegacyFromStats(existing, stats);

  localStorage.clear();

  // Restore legacy data — it persists across expeditions
  writeLegacy(legacy);

  location.reload();
}

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/**
 * Show the epoch milestone overlay with completion stats.
 * @param tick Total ticks elapsed at Dyson Sphere completion.
 * @param robotCount Active robots at completion.
 * @param topRobotName Name of the most accomplished robot (if any).
 * @param legacyCount Number of robot legacies recorded.
 * @param cultureLabel Culture level label (e.g. "Flourishing").
 */
export function showEndScreen(stats: {
  tick: number;
  robotCount: number;
  topRobotName: string | null;
  legacyCount: number;
  cultureLabel: string;
  colonyName?: string | null;
  colonyEpithet?: string | null;
}): void {
  if (overlay) return; // already showing
  trackDysonComplete();

  // Stash stats for startNewGame to capture into legacy
  currentRunStats = { ...stats };

  const color = '#a855f7'; // revelation purple

  overlay = document.createElement('div');
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.85);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 600;
    font-family: 'Courier New', monospace;
    opacity: 0;
    transition: opacity 0.5s ease;
  `;

  const panel = document.createElement('div');
  panel.setAttribute('role', 'dialog');
  panel.setAttribute('aria-label', 'Epoch Complete');
  panel.setAttribute('aria-modal', 'true');
  panel.setAttribute('tabindex', '-1');
  panel.style.cssText = `
    background: rgba(0, 8, 20, 0.96);
    border: 1px solid ${color};
    box-shadow: 0 0 48px ${color}44, inset 0 0 32px rgba(0,0,0,0.5);
    color: #e2e8f0;
    max-width: 520px;
    width: 90vw;
    padding: 40px 36px;
    border-radius: 2px;
    text-align: center;
  `;

  // Stats lines
  const statLines: string[] = [];
  statLines.push(`Ticks elapsed: ${stats.tick.toLocaleString()}`);
  statLines.push(`Robots active: ${stats.robotCount.toLocaleString()}`);
  if (stats.topRobotName) {
    statLines.push(`Most accomplished: ${escapeHtml(stats.topRobotName)}`);
  }
  if (stats.legacyCount > 0) {
    statLines.push(`Legacies recorded: ${stats.legacyCount}`);
  }
  statLines.push(`Culture: ${escapeHtml(stats.cultureLabel)}`);

  const statsHtml = statLines
    .map((l) => `<div style="padding:3px 0;color:#94a3b8;font-size:12px;">${l}</div>`)
    .join('');

  // Legacy stats section (shown if player has prior expeditions)
  const legacy = readLegacy();
  let legacyHtml = '';
  if (legacy && legacy.expeditionCount > 0) {
    const legacyLines: string[] = [];
    legacyLines.push(`Expeditions completed: ${legacy.expeditionCount}`);
    legacyLines.push(`Total legacies across all runs: ${legacy.totalLegacies + stats.legacyCount}`);
    if (legacy.bestRobotName) {
      legacyLines.push(`All-time best robot: ${escapeHtml(legacy.bestRobotName)}`);
    }
    legacyHtml = `
      <div style="margin-bottom:20px;border-top:1px solid ${color}33;padding-top:12px;">
        <div style="font-size:9px;color:${color};opacity:0.6;text-transform:uppercase;letter-spacing:2px;margin-bottom:6px;">Legacy Record</div>
        ${legacyLines.map((l) => `<div style="padding:2px 0;color:#7c8aa0;font-size:11px;">${l}</div>`).join('')}
      </div>`;
  }

  // Colony identity line (name + epithet)
  let colonyIdentityHtml = '';
  if (stats.colonyName) {
    const nameHtml = escapeHtml(stats.colonyName);
    const epithetHtml = stats.colonyEpithet ? ` — <em>${escapeHtml(stats.colonyEpithet)}</em>` : '';
    colonyIdentityHtml = `<div style="font-size:13px;color:#c4b5fd;margin-bottom:16px;letter-spacing:0.5px;">${nameHtml}${epithetHtml}</div>`;
  } else if (stats.colonyEpithet) {
    colonyIdentityHtml = `<div style="font-size:13px;color:#c4b5fd;margin-bottom:16px;letter-spacing:0.5px;font-style:italic;">${escapeHtml(stats.colonyEpithet)}</div>`;
  }

  panel.innerHTML = safeHtml`
    <div style="font-size:10px;color:${color};opacity:0.8;text-transform:uppercase;letter-spacing:3px;margin-bottom:12px;">Epoch Complete</div>
    <div style="font-size:20px;font-weight:bold;color:${color};margin-bottom:8px;letter-spacing:1px;">The Belt Endures</div>
    ${colonyIdentityHtml}
    <div style="font-size:12px;color:#94a3b8;margin-bottom:24px;line-height:1.6;">The Dyson Sphere hums with enough energy to power the stars.<br>The expedition awaits — or the belt runs forever.</div>
    <div style="margin-bottom:28px;">${statsHtml}</div>
    ${legacyHtml}
    <div style="display:flex;gap:12px;justify-content:center;flex-wrap:wrap;">
      <button id="end-new-game" aria-label="Migrate to a new star system" style="
        background: transparent;
        border: 1px solid ${color}88;
        color: ${color};
        font-family: 'Courier New', monospace;
        font-size: 12px;
        padding: 10px 24px;
        cursor: pointer;
        border-radius: 2px;
        letter-spacing: 1px;
        text-transform: uppercase;
        transition: background 0.2s, border-color 0.2s;
      ">New Star System</button>
      <button id="end-keep-playing" aria-label="Remain in the belt" style="
        background: transparent;
        border: 1px solid #47556988;
        color: #94a3b8;
        font-family: 'Courier New', monospace;
        font-size: 12px;
        padding: 10px 24px;
        cursor: pointer;
        border-radius: 2px;
        letter-spacing: 1px;
        text-transform: uppercase;
        transition: background 0.2s, border-color 0.2s;
      ">Remain in Belt</button>
    </div>
  `;

  overlay.appendChild(panel);
  document.body.appendChild(overlay);

  // Wire buttons
  panel.querySelector('#end-new-game')?.addEventListener('click', startNewGame);
  panel.querySelector('#end-keep-playing')?.addEventListener('click', dismissEndScreen);

  // Hover effects
  const newGameBtn = panel.querySelector<HTMLButtonElement>('#end-new-game');
  const keepBtn = panel.querySelector<HTMLButtonElement>('#end-keep-playing');
  if (newGameBtn) {
    newGameBtn.addEventListener('mouseover', () => {
      newGameBtn.style.background = `${color}22`;
      newGameBtn.style.borderColor = color;
    });
    newGameBtn.addEventListener('mouseout', () => {
      newGameBtn.style.background = 'transparent';
      newGameBtn.style.borderColor = `${color}88`;
    });
  }
  if (keepBtn) {
    keepBtn.addEventListener('mouseover', () => {
      keepBtn.style.background = '#47556922';
      keepBtn.style.borderColor = '#475569';
    });
    keepBtn.addEventListener('mouseout', () => {
      keepBtn.style.background = 'transparent';
      keepBtn.style.borderColor = '#47556988';
    });
  }

  removeFocusTrap = trapFocus(panel);

  requestAnimationFrame(() => {
    if (overlay) overlay.style.opacity = '1';
  });
}
