/**
 * Exploration tab renderer — anomaly list and discovery log.
 */

import { ANOMALY_TYPE_NAMES } from '../../sim/anomalyTypes';
import { AnomalySnapshot, ExplorationEntry } from './types';
import { sectionHeader } from './helpers';

export interface ExplorationTabData {
  anomalies: AnomalySnapshot[];
  explorationLog: ExplorationEntry[];
  onLocateAnomaly: ((x: number, z: number) => void) | null;
}

export function renderExplorationTab(container: HTMLDivElement, data: ExplorationTabData): void {
  container.innerHTML = '';

  const { anomalies, explorationLog, onLocateAnomaly } = data;

  // Anomaly list
  if (anomalies.length > 0) {
    container.appendChild(sectionHeader(`Anomalies (${anomalies.length} discovered)`));

    if (onLocateAnomaly) {
      const hint = document.createElement('div');
      hint.style.cssText = 'color:#4a5568;font-size:10px;margin-bottom:4px;';
      hint.textContent = 'Click an anomaly to navigate camera to it.';
      container.appendChild(hint);
    }

    const anomalyList = document.createElement('div');
    anomalyList.style.cssText = 'display:flex;flex-direction:column;gap:3px;margin-bottom:6px;';

    for (const anomaly of anomalies) {
      const row = document.createElement('div');
      row.style.cssText = `
        display: flex;
        align-items: baseline;
        gap: 8px;
        padding: 4px 6px;
        background: rgba(30,40,70,0.4);
        border-radius: 3px;
        border-left: 3px solid #a855f7;
        ${onLocateAnomaly ? 'cursor:pointer;' : ''}
      `;

      const nameEl = document.createElement('span');
      nameEl.style.cssText = 'color:#a855f7;font-size:11px;flex:1;';
      nameEl.textContent = ANOMALY_TYPE_NAMES[anomaly.anomalyType] ?? 'Unknown';

      const posEl = document.createElement('span');
      posEl.style.cssText = 'color:#6070a0;font-size:10px;flex-shrink:0;';
      posEl.textContent = `(${Math.round(anomaly.x)}, ${Math.round(anomaly.z)})`;

      row.appendChild(nameEl);
      row.appendChild(posEl);

      if (onLocateAnomaly) {
        const locateFn = onLocateAnomaly;
        const ax = anomaly.x;
        const az = anomaly.z;
        row.addEventListener('click', () => {
          locateFn(ax, az);
        });
        row.addEventListener('mouseenter', () => {
          row.style.background = 'rgba(50,60,100,0.6)';
        });
        row.addEventListener('mouseleave', () => {
          row.style.background = 'rgba(30,40,70,0.4)';
        });
      }

      anomalyList.appendChild(row);
    }

    container.appendChild(anomalyList);
  }

  container.appendChild(sectionHeader('Discovery Log'));

  if (explorationLog.length === 0) {
    const empty = document.createElement('div');
    empty.style.cssText = 'color:#4a5568;padding:8px 0;font-style:italic;';
    empty.textContent = 'No discoveries yet. Deploy scouts to explore the belt.';
    container.appendChild(empty);
    return;
  }

  const list = document.createElement('div');
  list.style.cssText = 'display:flex;flex-direction:column;gap:4px;';

  for (const entry of explorationLog.slice(0, 100)) {
    const row = document.createElement('div');
    row.style.cssText = `
      display: flex;
      align-items: baseline;
      gap: 8px;
      padding: 4px 6px;
      background: rgba(30,40,70,0.4);
      border-radius: 3px;
      border-left: 3px solid ${entry.color};
    `;

    const tickEl = document.createElement('span');
    tickEl.style.cssText = 'color:#4a5568;font-size:10px;flex-shrink:0;';
    tickEl.textContent = `T${entry.tick}`;

    const labelEl = document.createElement('span');
    labelEl.style.cssText = `color:${entry.color};flex:1;`;
    labelEl.textContent = entry.label;

    row.appendChild(tickEl);
    row.appendChild(labelEl);
    list.appendChild(row);
  }

  container.appendChild(list);
}
