/**
 * Robot Comms Feed — lightweight scrollable UI showing robot radio transmissions.
 *
 * Positioned bottom-left, collapsible. Shows recent messages styled as
 * radio transmissions with robot name and category color.
 */

const MAX_MESSAGES = 12;
const FADE_DURATION_MS = 500;
const MESSAGE_LIFETIME_MS = 30000;

interface CommsEntry {
  robotName: string;
  message: string;
  category: string;
  timestamp: number;
  element: HTMLDivElement;
}

const CATEGORY_COLORS: Record<string, string> = {
  milestone: '#22c55e',
  culture: '#a855f7',
  isolation: '#f59e0b',
  anomaly: '#06b6d4',
  death: '#ef4444',
  naming: '#fbbf24',
  mourning: '#a78bfa',
  groupthink: '#f97316',
  directive_drift: '#fb923c',
  backlash: '#f43f5e',
  dark_forest_echo: '#2dd4bf',
  chorus: '#7c3aed',
  resonance: '#06ffc8',
  soft_autonomy: '#38bdf8',
};

let container: HTMLDivElement | null = null;
let feedEl: HTMLDivElement | null = null;
let headerEl: HTMLDivElement | null = null;
let collapsed = false;
const entries: CommsEntry[] = [];

export function initCommsLog(): void {
  if (container) return;

  container = document.createElement('div');
  container.style.cssText = `
    position: fixed;
    bottom: 80px;
    left: 12px;
    width: 320px;
    max-height: 280px;
    z-index: 85;
    pointer-events: auto;
    font-family: 'Courier New', monospace;
  `;

  // Header (clickable to collapse)
  headerEl = document.createElement('div');
  headerEl.style.cssText = `
    background: rgba(4, 6, 14, 0.85);
    border: 1px solid rgba(100, 140, 255, 0.3);
    border-bottom: none;
    border-radius: 4px 4px 0 0;
    padding: 4px 10px;
    font-size: 9px;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    color: rgba(140, 160, 220, 0.7);
    cursor: pointer;
    user-select: none;
    display: flex;
    justify-content: space-between;
    align-items: center;
  `;
  headerEl.innerHTML = '<span>◈ COMMS</span><span id="comms-toggle">▼</span>';
  headerEl.addEventListener('click', toggleCollapsed);
  container.appendChild(headerEl);

  // Feed container
  feedEl = document.createElement('div');
  feedEl.style.cssText = `
    background: rgba(4, 6, 14, 0.78);
    border: 1px solid rgba(100, 140, 255, 0.2);
    border-radius: 0 0 4px 4px;
    max-height: 240px;
    overflow-y: auto;
    overflow-x: hidden;
    scrollbar-width: thin;
    scrollbar-color: rgba(100,140,255,0.3) transparent;
  `;
  container.appendChild(feedEl);

  document.body.appendChild(container);
}

function toggleCollapsed(): void {
  collapsed = !collapsed;
  if (feedEl) feedEl.style.display = collapsed ? 'none' : 'block';
  const toggle = document.getElementById('comms-toggle');
  if (toggle) toggle.textContent = collapsed ? '▶' : '▼';
}

export function addCommsMessage(
  robotName: string,
  message: string,
  category: string,
): void {
  if (!feedEl) initCommsLog();
  if (!feedEl) return;

  // Uncollapse on new message
  if (collapsed) {
    collapsed = false;
    feedEl.style.display = 'block';
    const toggle = document.getElementById('comms-toggle');
    if (toggle) toggle.textContent = '▼';
  }

  const color = CATEGORY_COLORS[category] ?? '#94a3b8';

  const el = document.createElement('div');
  el.style.cssText = `
    padding: 5px 8px;
    border-left: 2px solid ${color};
    font-size: 10px;
    line-height: 1.4;
    color: rgba(200, 210, 230, 0.85);
    opacity: 0;
    transform: translateY(8px);
    transition: opacity 0.3s ease, transform 0.3s ease;
    border-bottom: 1px solid rgba(40, 50, 80, 0.3);
  `;

  const nameSpan = document.createElement('span');
  nameSpan.style.cssText = `color: ${color}; font-weight: bold; font-size: 9px; text-transform: uppercase; letter-spacing: 0.5px;`;
  nameSpan.textContent = `${robotName}: `;

  const msgSpan = document.createElement('span');
  msgSpan.textContent = message.startsWith(robotName) ? message.slice(message.indexOf(':') + 2) : message;

  el.appendChild(nameSpan);
  el.appendChild(msgSpan);

  feedEl.appendChild(el);

  // Animate in
  requestAnimationFrame(() => {
    el.style.opacity = '1';
    el.style.transform = 'translateY(0)';
  });

  // Auto-scroll to bottom
  feedEl.scrollTop = feedEl.scrollHeight;

  const entry: CommsEntry = {
    robotName,
    message,
    category,
    timestamp: Date.now(),
    element: el,
  };
  entries.push(entry);

  // Auto-fade old messages
  setTimeout(() => fadeEntry(entry), MESSAGE_LIFETIME_MS);

  // Trim excess
  while (entries.length > MAX_MESSAGES) {
    const oldest = entries.shift();
    if (oldest) oldest.element.remove();
  }
}

function fadeEntry(entry: CommsEntry): void {
  const idx = entries.indexOf(entry);
  if (idx === -1) return; // already removed

  entry.element.style.transition = `opacity ${FADE_DURATION_MS}ms ease`;
  entry.element.style.opacity = '0.3';
}
