/**
 * Belt Echoes — ARIA Echo Templates
 *
 * Anonymous cross-player milestone transmissions delivered as
 * intercepted deep-space signals. Hard sci-fi tone, no gamey language.
 *
 * Template variables:
 *   {sector}  — randomized sector designation (e.g. "7-Kappa")
 *   {delay}   — light-delay hours (flavour)
 */

export interface EchoTemplate {
  milestoneType: string;
  progressionStage: number; // minimum stage required to see this echo
  templates: string[];
}

/** Sector designations for flavour text. */
const SECTOR_NAMES = [
  '7-Kappa',
  '12-Vega',
  '3-Cygnus',
  '19-Altair',
  '5-Lyra',
  '8-Draco',
  '14-Aquila',
  '2-Boötes',
  '11-Serpens',
  '6-Hydra',
  '21-Centauri',
  '9-Pavo',
  '16-Fornax',
  '4-Eridanus',
  '17-Sculptor',
];

export function randomSector(): string {
  return SECTOR_NAMES[Math.floor(Math.random() * SECTOR_NAMES.length)];
}

export function randomDelay(): number {
  return Math.floor(Math.random() * 36) + 2; // 2-37 hours
}

export function fillTemplate(template: string, sector: string, delay: number): string {
  return template.replace(/\{sector\}/g, sector).replace(/\{delay\}/g, String(delay));
}

