/**
 * Pick a random template for the given milestone type and fill in variables.
 * Returns null if no template matches.
 */
export function generateEchoMessage(milestoneType: string): string | null {
  const group = ECHO_TEMPLATES.find((t) => t.milestoneType === milestoneType);
  if (!group || group.templates.length === 0) return null;
  const template = group.templates[Math.floor(Math.random() * group.templates.length)];
  return fillTemplate(template, randomSector(), randomDelay());
}

/**
 * Get all echo templates available at or below the given progression stage.
 */
export function getTemplatesForStage(stage: number): EchoTemplate[] {
  return ECHO_TEMPLATES.filter((t) => t.progressionStage <= stage);
}
