/**
 * ThreatRenderer — visualizes active kinetic threats in the 3D scene.
 *
 * Replaces the old FactionShipRenderer (cone meshes) with threat indicators:
 * - Trajectory lines from origin to target (dashed, color-coded by threat type)
 * - Warning zones (pulsing rings at target location)
 * - Beacon markers (small diamonds at the threat's current interpolated position)
 *
 * Reads from a Float32Array threat buffer with stride 10.
 */
import {
  BufferGeometry,
  Color,
  Float32BufferAttribute,
  Line,
  LineBasicMaterial,
  LineDashedMaterial,
  Material,
  Mesh,
  MeshBasicMaterial,
  OctahedronGeometry,
  RingGeometry,
  Scene,
} from 'three';
import {
  THREAT_STRIDE,
  getThreatType,
  getThreatFactionId,
  getThreatOriginX,
  getThreatOriginY,
  getThreatOriginZ,
  getThreatTargetX,
  getThreatTargetY,
  getThreatTargetZ,
  getThreatProgress,
} from '../sim/bufferLayout';

// ── Threat type colors ───────────────────────────────────────────────────────
// 0=trajectory_interjection (orange), 1=claim_jump (yellow),
// 2=mass_driver_threat (red), 3=signal_jam (purple)
const THREAT_COLORS: Color[] = [
  new Color(1.0, 0.6, 0.1),  // trajectory interjection — orange
  new Color(1.0, 0.9, 0.2),  // claim jump — yellow
  new Color(1.0, 0.15, 0.15), // mass driver — red
  new Color(0.6, 0.3, 1.0),  // signal jam — purple
];

const MAX_THREATS = 8;

/** Shared geometry for beacon markers */
const BEACON_GEO = new OctahedronGeometry(6, 0);

/** Shared geometry for warning zone rings */
const WARNING_RING_GEO = new RingGeometry(25, 30, 32);

interface ThreatVisual {
  /** Dashed line from origin to target */
  trajectoryLine: Line;
  trajectoryMat: LineDashedMaterial;
  /** Pulsing ring at target position */
  warningRing: Mesh;
  warningMat: MeshBasicMaterial;
  /** Diamond marker at interpolated threat position along trajectory */
  beacon: Mesh;
  beaconMat: MeshBasicMaterial;
}

export class ThreatRenderer {
  private scene: Scene;
  private visuals: ThreatVisual[] = [];
  private activeCount = 0;

  constructor(scene: Scene) {
    this.scene = scene;

    for (let i = 0; i < MAX_THREATS; i++) {
      const trajectoryMat = new LineDashedMaterial({
        color: 0xff0000,
        dashSize: 20,
        gapSize: 10,
        transparent: true,
        opacity: 0.7,
        depthWrite: false,
      });

      // Line geometry: 2 points (origin → target), updated per frame
      const lineGeo = new BufferGeometry();
      lineGeo.setAttribute('position', new Float32BufferAttribute([0, 0, 0, 0, 0, 0], 3));
      const trajectoryLine = new Line(lineGeo, trajectoryMat);
      trajectoryLine.computeLineDistances();
      trajectoryLine.visible = false;
      trajectoryLine.frustumCulled = false;
      scene.add(trajectoryLine);

      const warningMat = new MeshBasicMaterial({
        color: 0xff0000,
        transparent: true,
        opacity: 0.25,
        depthWrite: false,
      });
      const warningRing = new Mesh(WARNING_RING_GEO, warningMat);
      warningRing.rotation.x = -Math.PI / 2;
      warningRing.visible = false;
      warningRing.frustumCulled = false;
      scene.add(warningRing);

      const beaconMat = new MeshBasicMaterial({
        color: 0xff0000,
        transparent: true,
        opacity: 0.9,
        depthWrite: false,
      });
      const beacon = new Mesh(BEACON_GEO, beaconMat);
      beacon.visible = false;
      beacon.frustumCulled = false;
      scene.add(beacon);

      this.visuals.push({
        trajectoryLine,
        trajectoryMat,
        warningRing,
        warningMat,
        beacon,
        beaconMat,
      });
    }
  }

  /**
   * Update threat visuals from the simulation threat buffer.
   * @param buffer Float32Array with THREAT_STRIDE per entry
   * @param count Number of active threats in the buffer
   * @param elapsed Elapsed time for animation (seconds)
   */
  updateFromBuffer(buffer: Float32Array, count: number, elapsed: number): void {
    const n = Math.min(count, MAX_THREATS);

    for (let i = 0; i < n; i++) {
      const v = this.visuals[i];
      const typeEnum = getThreatType(buffer, i);
      const progress = getThreatProgress(buffer, i);
      const color = THREAT_COLORS[typeEnum] ?? THREAT_COLORS[0];

      const ox = getThreatOriginX(buffer, i);
      const oy = getThreatOriginY(buffer, i);
      const oz = getThreatOriginZ(buffer, i);
      const tx = getThreatTargetX(buffer, i);
      const ty = getThreatTargetY(buffer, i);
      const tz = getThreatTargetZ(buffer, i);

      // ── Trajectory line ──────────────────────────────────────────────────
      const posAttr = v.trajectoryLine.geometry.getAttribute('position') as Float32BufferAttribute;
      posAttr.setXYZ(0, ox, oy + 2, oz);
      posAttr.setXYZ(1, tx, ty + 2, tz);
      posAttr.needsUpdate = true;
      v.trajectoryLine.computeLineDistances();
      v.trajectoryMat.color.copy(color);
      v.trajectoryMat.opacity = 0.3 + progress * 0.5; // grows more visible as threat approaches
      v.trajectoryLine.visible = true;

      // ── Warning zone ring at target ──────────────────────────────────────
      v.warningRing.position.set(tx, ty + 0.5, tz);
      // Pulse scale based on elapsed time and progress
      const pulse = 1 + 0.15 * Math.sin(elapsed * 3 + i * 1.5);
      const warningScale = (0.6 + progress * 0.8) * pulse;
      v.warningRing.scale.set(warningScale, warningScale, warningScale);
      v.warningMat.color.copy(color);
      v.warningMat.opacity = 0.1 + progress * 0.3;
      v.warningRing.visible = true;

      // ── Beacon marker at interpolated position along trajectory ─────────
      const bx = ox + (tx - ox) * progress;
      const by = oy + (ty - oy) * progress + 8; // slightly above ground
      const bz = oz + (tz - oz) * progress;
      v.beacon.position.set(bx, by, bz);
      // Spin the beacon
      v.beacon.rotation.y = elapsed * 2 + i;
      v.beacon.rotation.z = elapsed * 1.5;
      const beaconPulse = 0.8 + 0.3 * Math.sin(elapsed * 5 + i * 2);
      v.beacon.scale.setScalar(beaconPulse);
      v.beaconMat.color.copy(color);
      v.beacon.visible = true;
    }

    // Hide unused visuals
    for (let i = n; i < this.activeCount; i++) {
      const v = this.visuals[i];
      v.trajectoryLine.visible = false;
      v.warningRing.visible = false;
      v.beacon.visible = false;
    }

    this.activeCount = n;
  }

  dispose(): void {
    for (const v of this.visuals) {
      this.scene.remove(v.trajectoryLine);
      v.trajectoryLine.geometry.dispose();
      (v.trajectoryLine.material as Material).dispose();

      this.scene.remove(v.warningRing);
      // Shared geometry — don't dispose per-instance
      v.warningMat.dispose();

      this.scene.remove(v.beacon);
      v.beaconMat.dispose();
    }
  }
}
