/**
 * Orbital mechanics system — simple circular orbits for asteroids.
 *
 * Each asteroid orbits the origin in the xz plane. Orbital periods follow
 * compressed Kepler's law so inner-belt asteroids visibly drift over a
 * play session while outer-belt asteroids move slowly.
 *
 * Transit windows: angular proximity between the player base and an
 * asteroid determines a fuel cost multiplier (1× when nearby, up to
 * MAX_TRANSIT_PENALTY when on the far side of the belt).
 */

import { query } from 'bitecs';
import type { World } from '../core/ecs';
import { Position, AsteroidTag, Orbit } from './components';
import type { SpatialGrid } from './spatialGrid';

// ── Constants ────────────────────────────────────────────────────────────────

// AU mapping — must stay in sync with asteroidGen.ts
const AU_INNER = 2.0;
const AU_OUTER = 3.5;
const BELT_INNER_RADIUS = 5000;  // game units at AU_INNER
const BELT_OUTER_RADIUS = 50000; // game units at AU_OUTER

/**
 * Game-second orbital period for 1 AU (Earth orbit equivalent).
 * Real: 1 year. Compressed so inner belt (2.0 AU) ≈ 900s (~15 min at 1×).
 * PERIOD_1AU * 2.0^1.5 ≈ 900 → PERIOD_1AU ≈ 318.2
 */
const PERIOD_1AU_S = 900 / Math.pow(AU_INNER, 1.5);

/** Half-angle (radians) for a "good" transit window. ~30° each side. */
const TRANSIT_WINDOW_HALF = Math.PI / 6;

/** Half-angle (radians) beyond which maximum penalty applies. ~90° each side. */
const TRANSIT_PENALTY_FULL = Math.PI / 2;

/** Maximum fuel cost multiplier when outside transit window. */
export const MAX_TRANSIT_PENALTY = 4.0;

const TWO_PI = Math.PI * 2;

// ── AU conversion ───────────────────────────────────────────────────────────

/** Convert game-unit orbital radius to astronomical units. */
function gameRadiusToAU(r: number): number {
  return AU_INNER + ((r - BELT_INNER_RADIUS) / (BELT_OUTER_RADIUS - BELT_INNER_RADIUS)) * (AU_OUTER - AU_INNER);
}

// ── Orbital period ───────────────────────────────────────────────────────────

/**
 * Compute orbital period (game-seconds) for a given orbital radius.
 * Converts game units → AU, then applies Kepler's third law: T = T₁ × a^1.5
 * where a is semi-major axis in AU and T₁ is the 1 AU base period.
 */
export function computeOrbitalPeriod(orbitalRadius: number): number {
  const au = gameRadiusToAU(orbitalRadius);
  return PERIOD_1AU_S * Math.pow(au, 1.5);
}

// ── Orbital initialization ───────────────────────────────────────────────────

/**
 * Initialize orbital state for an entity that already has a Position.
 * Derives radius and initial angle from the current (x, z) position.
 */
export function initOrbit(eid: number): void {
  const x = Position.x[eid];
  const y = Position.y[eid];
  const z = Position.z[eid];
  const radius = Math.sqrt(x * x + z * z);
  const angle = Math.atan2(z, x);

  Orbit.radius[eid] = radius;
  Orbit.angle[eid] = angle;
  Orbit.period[eid] = computeOrbitalPeriod(radius);
  Orbit.baseY[eid] = y;
}

// ── Per-tick orbital update ──────────────────────────────────────────────────

/**
 * Advance all orbiting asteroids by dt game-seconds.
 * Updates angular position and derives new (x, y, z) from orbital state.
 * Also updates the spatial grid for any moved entities.
 */
export function orbitalSystem(world: World, dt: number, grid: SpatialGrid): void {
  const asteroids = query(world, [AsteroidTag, Orbit, Position]);

  for (let i = 0; i < asteroids.length; i++) {
    const eid = asteroids[i];
    const period = Orbit.period[eid];
    if (period <= 0) continue;

    // Advance angle
    const angularVelocity = TWO_PI / period;
    let angle = Orbit.angle[eid] + angularVelocity * dt;
    // Keep angle in [0, 2π) to avoid precision loss over long sessions
    if (angle >= TWO_PI) angle -= TWO_PI;
    else if (angle < 0) angle += TWO_PI;
    Orbit.angle[eid] = angle;

    // Derive position from orbital state
    const r = Orbit.radius[eid];
    const newX = r * Math.cos(angle);
    const newZ = r * Math.sin(angle);
    const newY = Orbit.baseY[eid];

    Position.x[eid] = newX;
    Position.y[eid] = newY;
    Position.z[eid] = newZ;

    // Update spatial grid
    grid.update(eid, newX, newY, newZ);
  }
}

// ── Transit window ───────────────────────────────────────────────────────────

/**
 * Compute the angular distance (radians, 0..π) between a point (bx, bz)
 * and an asteroid's current orbital angle.
 */
function angularDistance(asteroidAngle: number, bx: number, bz: number): number {
  const baseAngle = Math.atan2(bz, bx);
  let diff = Math.abs(asteroidAngle - baseAngle);
  if (diff > Math.PI) diff = TWO_PI - diff;
  return diff;
}


/**
 * Get the transit-window fuel cost multiplier for traveling to an asteroid
 * from a given base position. Returns 1.0 if the entity has no orbit data.
 *
 * @param eid - Entity ID (checks Orbit.period to detect orbital entities)
 * @param baseX - Base station X position
 * @param baseZ - Base station Z position
 * @returns Fuel cost multiplier (1.0 to MAX_TRANSIT_PENALTY)
 */
export function transitCostMultiplier(eid: number, baseX: number, baseZ: number): number {
  const period = Orbit.period[eid];
  if (period <= 0) return 1.0;

  const asteroidAngle = Orbit.angle[eid];
  const diff = angularDistance(asteroidAngle, baseX, baseZ);

  if (diff <= TRANSIT_WINDOW_HALF) return 1.0;
  if (diff >= TRANSIT_PENALTY_FULL) return MAX_TRANSIT_PENALTY;

  // Linear ramp from 1.0 to MAX_TRANSIT_PENALTY
  const t = (diff - TRANSIT_WINDOW_HALF) / (TRANSIT_PENALTY_FULL - TRANSIT_WINDOW_HALF);
  return 1.0 + t * (MAX_TRANSIT_PENALTY - 1.0);
}

/**
 * Compute transit cost multiplier from a target (x, z) position relative to
 * a base (bx, bz) position. Works without needing an entity ID — uses raw
 * angular positions. Returns 1.0 if target is at origin.
 */
export function transitCostMultiplierFromPosition(
  targetX: number,
  targetZ: number,
  baseX: number,
  baseZ: number,
): number {
  if (targetX === 0 && targetZ === 0) return 1.0;
  const targetAngle = Math.atan2(targetZ, targetX);
  const diff = angularDistance(targetAngle, baseX, baseZ);

  if (diff <= TRANSIT_WINDOW_HALF) return 1.0;
  if (diff >= TRANSIT_PENALTY_FULL) return MAX_TRANSIT_PENALTY;

  const t = (diff - TRANSIT_WINDOW_HALF) / (TRANSIT_PENALTY_FULL - TRANSIT_WINDOW_HALF);
  return 1.0 + t * (MAX_TRANSIT_PENALTY - 1.0);
}

/**
 * Get a transit window status for UI display.
 * Returns a value 0..1 where 0 = worst (far side), 1 = best (in window).
 */
export function transitWindowFactor(eid: number, baseX: number, baseZ: number): number {
  const period = Orbit.period[eid];
  if (period <= 0) return 1.0;

  const asteroidAngle = Orbit.angle[eid];
  const diff = angularDistance(asteroidAngle, baseX, baseZ);

  if (diff <= TRANSIT_WINDOW_HALF) return 1.0;
  if (diff >= Math.PI) return 0.0;

  return 1.0 - (diff - TRANSIT_WINDOW_HALF) / (Math.PI - TRANSIT_WINDOW_HALF);
}

/**
 * Estimate ticks until the next transit window opens for an asteroid
 * relative to a base position. Returns 0 if already in window.
 */
export function ticksUntilTransitWindow(
  eid: number,
  baseX: number,
  baseZ: number,
  ticksPerSecond: number,
): number {
  const period = Orbit.period[eid];
  if (period <= 0) return 0;

  const asteroidAngle = Orbit.angle[eid];
  const baseAngle = Math.atan2(baseZ, baseX);
  let diff = asteroidAngle - baseAngle;
  if (diff > Math.PI) diff -= TWO_PI;
  if (diff < -Math.PI) diff += TWO_PI;

  const absDiff = Math.abs(diff);
  if (absDiff <= TRANSIT_WINDOW_HALF) return 0;

  // Angular velocity
  const angVel = TWO_PI / period;

  // How far the asteroid needs to travel to reach the window edge.
  // The asteroid orbits counter-clockwise (positive angle direction).
  // The window is centered on baseAngle ± TRANSIT_WINDOW_HALF.
  // Find the nearest window edge the asteroid is approaching.
  const windowEdgeCW = baseAngle - TRANSIT_WINDOW_HALF;
  const windowEdgeCCW = baseAngle + TRANSIT_WINDOW_HALF;

  // Asteroid moves in positive angle direction (CCW).
  // Distance to CCW edge:
  let toCCW = windowEdgeCCW - asteroidAngle;
  if (toCCW < 0) toCCW += TWO_PI;

  // Distance to CW edge (asteroid would reach this coming around):
  let toCW = windowEdgeCW - asteroidAngle;
  if (toCW < 0) toCW += TWO_PI;

  const minAngularDist = Math.min(toCCW, toCW);
  const timeSeconds = minAngularDist / angVel;
  return Math.ceil(timeSeconds * ticksPerSecond);
}
