// --- Kirkwood Gap System ---
// Real asteroid belt resonances mapped linearly into the game belt.
// Real belt: ~2.0–3.5 AU → Game belt: beltInnerRadius–beltOuterRadius.

interface KirkwoodGap {
  au: number; // real AU value
  halfWidth: number; // half-width in game units
  minDensity: number; // floor density inside gap (0.05–0.15)
}

const KIRKWOOD_RESONANCES: KirkwoodGap[] = [
  { au: 2.06, halfWidth: 100, minDensity: 0.15 }, // 4:1
  { au: 2.5, halfWidth: 100, minDensity: 0.05 }, // 3:1 (strongest)
  { au: 2.82, halfWidth: 100, minDensity: 0.1 }, // 5:2
  { au: 3.28, halfWidth: 100, minDensity: 0.08 }, // 2:1
];

const AU_INNER = 2.0;
const AU_OUTER = 3.5;

/** Map a real AU distance to game-unit radius */
function auToGameRadius(au: number, innerRadius: number, outerRadius: number): number {
  return innerRadius + ((au - AU_INNER) / (AU_OUTER - AU_INNER)) * (outerRadius - innerRadius);
}

/** Compute Kirkwood gap game-unit positions for a given belt config */
function kirkwoodPositions(
  innerRadius: number,
  outerRadius: number,
): Array<{ center: number; halfWidth: number; minDensity: number }> {
  return KIRKWOOD_RESONANCES.map((g) => ({
    center: auToGameRadius(g.au, innerRadius, outerRadius),
    halfWidth: g.halfWidth,
    minDensity: g.minDensity,
  }));
}

/**
 * Kirkwood gap density multiplier. Returns 1.0 outside gaps,
 * 0.05–0.15 inside gap bands (±halfWidth game units).
 */
export function kirkwoodGapDensityMultiplier(
  radius: number,
  innerRadius: number,
  outerRadius: number,
): number {
  const gaps = kirkwoodPositions(innerRadius, outerRadius);
  for (const gap of gaps) {
    if (Math.abs(radius - gap.center) < gap.halfWidth) {
      return gap.minDensity;
    }
  }
  return 1.0;
}

// --- Family Clustering ---

interface AsteroidFamilyCenter {
  x: number;
  z: number;
  radius: number; // influence radius (400 units per spec)
  dominantMineral: MineralField;
}

let families: AsteroidFamilyCenter[] | null = null;

function generateFamilies(config: FieldConfig): AsteroidFamilyCenter[] {
  const rng = mulberry32(config.worldSeed + 7777);
  const count = 3 + Math.floor(rng() * 3); // 3–5 families
  const result: AsteroidFamilyCenter[] = [];
  for (let i = 0; i < count; i++) {
    const angle = rng() * Math.PI * 2;
    const dist =
      config.beltInnerRadius + rng() * (config.beltOuterRadius - config.beltInnerRadius);
    result.push({
      x: Math.cos(angle) * dist,
      z: Math.sin(angle) * dist,
      radius: 400,
      dominantMineral: MINERAL_FIELDS[Math.floor(rng() * MINERAL_FIELDS.length)],
    });
  }
  return result;
}

/** Find the nearest family center if within influence radius, or null */
function findNearestFamily(
  x: number,
  z: number,
  familyList: AsteroidFamilyCenter[],
): AsteroidFamilyCenter | null {
  let best: AsteroidFamilyCenter | null = null;
  let bestDist = Infinity;
  for (const fam of familyList) {
    const dx = x - fam.x;
    const dz = z - fam.z;
    const d = Math.sqrt(dx * dx + dz * dz);
    if (d < fam.radius && d < bestDist) {
      best = fam;
      bestDist = d;
    }
  }
  return best;
}

/** Roll a tiered asteroid size. Returns { radius, tier }. */
function rollTieredSize(rng: () => number): { radius: number; tier: number } {
  const tierRoll = rng();
  if (tierRoll < 0.005) {
    // Mega: uniform 100–250 (well below Sun visual scale)
    return { radius: 100 + rng() * 150, tier: 3 };
  } else if (tierRoll < 0.055) {
    // Large: logNormal mean ~4.2 (capped at ~80)
    return { radius: Math.max(40, Math.min(80, logNormal(rng, 4.2, 0.35))), tier: 2 };
  } else if (tierRoll < 0.355) {
    // Medium
    return { radius: Math.max(15, logNormal(rng, 3.2, 0.5)), tier: 1 };
  } else {
    // Small
    return { radius: Math.max(5, logNormal(rng, 2.0, 0.5)), tier: 0 };
  }
}

