/**
 * Main-thread handler for sim:market_state messages.
 */
import type { HandlerMap } from './types';
import type { SimMarketStateMessage } from '../sim/messages';
import { updateMarketState } from '../ui/marketPanel';

export function registerMarketHandlers(): HandlerMap {
  return {
    'sim:market_state': (msg) => {
      const { listings } = (msg as SimMarketStateMessage).payload;
      updateMarketState(listings);
    },
  };
}
