/**
 * Anomaly Study Pipeline
 *
 * Tracks discovered anomalies through study stages.
 * Scouts near an anomaly automatically advance its study progress.
 * Study stages reveal lore fragments and trigger discovery chains.
 */

import { CivilizationAttribution, CIVILIZATION_ATTRIBUTIONS } from './civilizationTypes';

export const STUDY_STAGES = {
  DISCOVERED: 1,
  SCANNING: 2,
  ANALYZED: 3,
  UNDERSTOOD: 4,
} as const;

export type StudyStage = 1 | 2 | 3 | 4;

/** Seconds to complete each stage with 1 scout at tier 1 scanner */
const STAGE_DURATION: Record<StudyStage, number> = {
  [STUDY_STAGES.DISCOVERED]: 30,
  [STUDY_STAGES.SCANNING]: 60,
  [STUDY_STAGES.ANALYZED]: 120,
  [STUDY_STAGES.UNDERSTOOD]: 0, // terminal stage
};

/** Fragment indices revealed when entering each stage */
const FRAGMENTS_AT_STAGE: Record<StudyStage, number[]> = {
  [STUDY_STAGES.DISCOVERED]: [0], // 1 fragment on discovery
  [STUDY_STAGES.SCANNING]: [1, 2], // 2 more when scanning begins
  [STUDY_STAGES.ANALYZED]: [3, 4], // 2 more on analysis
  [STUDY_STAGES.UNDERSTOOD]: [5, 6, 7], // final 2-3 on full understanding (7 = species attribution where present)
};

export interface StudyEntry {
  asteroidEid: number;
  anomalyType: number;
  stage: StudyStage;
  /** 0-1 progress toward completing current stage */
  progress: number;
  x: number;
  y: number;
  z: number;
  /** Indices of revealed lore fragments */
  revealedFragments: number[];
  /** True if a chain reveal was already emitted */
  chainRevealed: boolean;
  /** True after Fragment Index 7 revealed — civilization identity known */
  civilizationAttributed: boolean;
}

export interface StudyUpdate {
  asteroidEid: number;
  anomalyType: number;
  stage: StudyStage;
  progress: number;
  /** New fragment indices just revealed (empty if none) */
  newFragments: number[];
  /** Next anomaly type in chain (0 = no chain trigger) */
  chainNextType: number;
  /** ARIA revelation text when a chain completes */
  revelation: string | null;
  /** Populated at UNDERSTOOD — civilization identity for this anomaly */
  civilizationAttribution: CivilizationAttribution | null;
}

