// ── Discovery chains ────────────────────────────────────────────────────────

/** Maps anomaly type → next anomaly type in chain (0 = chain ends) */
const CHAIN_NEXT: Record<number, number> = {
  1: 2, // Strange Mineral → Structured Signal
  2: 3, // Structured Signal → Spatial Distortion
  3: 0, // Spatial Distortion → (revelation: chain 1 complete)
  4: 5, // Geometric Void → Biological Trace
  5: 0, // Biological Trace → (revelation: chain 2 complete)
  6: 7, // Gravitational Anomaly → Convergence Point
  7: 0, // Convergence Point → (revelation: chain 3 complete / endgame)
};

/** Revelation text emitted when an anomaly type reaches UNDERSTOOD */
const CHAIN_REVELATIONS: Record<number, string> = {
  3: 'ARIA: Three civilizations tried to *know* the Chorus. Each knew more than the last. The Architects froze in understanding. The Encoders drowned in recording. The Seekers heard the answer and fell silent. Knowledge is not the response.',
  5: 'ARIA: The Builders prepared for an answer they could not imagine. The Weavers consumed everything to encode one. Infrastructure without purpose. Appetite without limit. Building is not the response.',
  7: 'ARIA: The Dreamers felt the Chorus. The Shapers became it. Neither survived. But the Shapers understood something the others did not: the response is not something you do. It is something you are. The question is whether *we* understand that.',
};

export function getChainNext(anomalyType: number): number {
  return CHAIN_NEXT[anomalyType] ?? 0;
}

export function getChainRevelation(anomalyType: number): string | null {
  return CHAIN_REVELATIONS[anomalyType] ?? null;
}

// ── AnomalyStudySystem ──────────────────────────────────────────────────────

export class AnomalyStudySystem {
  private entries = new Map<number, StudyEntry>(); // asteroidEid → entry

  /** Register a newly discovered anomaly. Idempotent. */
  discover(
    asteroidEid: number,
    anomalyType: number,
    x: number,
    y: number,
    z: number,
  ): StudyUpdate | null {
    if (this.entries.has(asteroidEid)) return null;

    const initialFragments = FRAGMENTS_AT_STAGE[STUDY_STAGES.DISCOVERED];
    const allFragments = LORE_FRAGMENTS[anomalyType] ?? [];
    const validInitial = initialFragments.filter((fi) => fi < allFragments.length);

    const entry: StudyEntry = {
      asteroidEid,
      anomalyType,
      stage: STUDY_STAGES.DISCOVERED,
      progress: 0,
      x,
      y,
      z,
      revealedFragments: [...validInitial],
      chainRevealed: false,
      civilizationAttributed: false,
    };
    this.entries.set(asteroidEid, entry);

    return {
      asteroidEid,
      anomalyType,
      stage: STUDY_STAGES.DISCOVERED,
      progress: 0,
      newFragments: [...validInitial],
      chainNextType: 0,
      revelation: null,
      civilizationAttribution: null,
    };
  }

  /**
   * Advance all active study entries.
   *
   * @param dt - delta time in seconds
   * @param getScoutCount - returns scout count and avg tier near a position
   */
  tick(
    dt: number,
    getScoutCount: (x: number, y: number, z: number) => { count: number; avgTier: number },
  ): StudyUpdate[] {
    const updates: StudyUpdate[] = [];

    for (const entry of this.entries.values()) {
      if (entry.stage === STUDY_STAGES.UNDERSTOOD) continue;

      const { count, avgTier } = getScoutCount(entry.x, entry.y, entry.z);
      if (count === 0) continue;

      // Speed = scout count × scanner tier (tier 1 baseline)
      const rate = count * Math.max(1, avgTier);
      const duration = STAGE_DURATION[entry.stage];
      entry.progress += (dt * rate) / duration;

      if (entry.progress < 1) continue;

      // Stage complete — advance
      entry.progress = 0;
      const nextStage = (entry.stage + 1) as StudyStage;
      entry.stage = nextStage;

      const newFragments: number[] = [];
      const stageFragmentIndices = FRAGMENTS_AT_STAGE[nextStage] ?? [];
      const allFragments = LORE_FRAGMENTS[entry.anomalyType] ?? [];
      for (const fi of stageFragmentIndices) {
        if (fi < allFragments.length && !entry.revealedFragments.includes(fi)) {
          entry.revealedFragments.push(fi);
          newFragments.push(fi);
        }
      }

      // Check for chain trigger, revelation, and civilization attribution
      let chainNextType = 0;
      let revelation: string | null = null;
      let civilizationAttribution: CivilizationAttribution | null = null;
      if (nextStage === STUDY_STAGES.UNDERSTOOD && !entry.chainRevealed) {
        entry.chainRevealed = true;
        entry.civilizationAttributed = true;
        chainNextType = getChainNext(entry.anomalyType);
        revelation = getChainRevelation(entry.anomalyType);
        civilizationAttribution = CIVILIZATION_ATTRIBUTIONS[entry.anomalyType] ?? null;
      }

      updates.push({
        asteroidEid: entry.asteroidEid,
        anomalyType: entry.anomalyType,
        stage: nextStage,
        progress: 0,
        newFragments,
        chainNextType,
        revelation,
        civilizationAttribution,
      });
    }

    return updates;
  }

  /** Get current progress for all active entries (for periodic broadcast) */
  getProgressSnapshot(): Array<{
    asteroidEid: number;
    anomalyType: number;
    stage: StudyStage;
    progress: number;
    revealedFragments: number[];
  }> {
    return Array.from(this.entries.values()).map((e) => ({
      asteroidEid: e.asteroidEid,
      anomalyType: e.anomalyType,
      stage: e.stage,
      progress: e.progress,
      revealedFragments: [...e.revealedFragments],
    }));
  }

  get size(): number {
    return this.entries.size;
  }

  clear(): void {
    this.entries.clear();
  }

  /** Restore a study entry directly (used by save/load system). */
  restoreEntry(asteroidEid: number, entry: StudyEntry): void {
    this.entries.set(asteroidEid, entry);
  }
}
