/**
 * Ship Panel
 *
 * Contextual panel shown when clicking a robot/ship.
 * Displays robot type, state, energy, cargo, biography, and personality quirks.
 * Provides action buttons: Follow, Mine, Explore, Return to Base, Stand Down.
 */

import { playSfx } from '../audio/sfxEngine';
import { ROBOT_TYPE_NAMES } from '../sim/robotProfiles';
import { ROBOT_STATE_NAMES } from '../sim/robotCreation';

// ── Types ─────────────────────────────────────────────────────────────────────

export interface ShipPanelCallbacks {
  onOrder: (robotEid: number, order: 'return_to_base' | 'idle') => void;
  onRequestDetail: (robotEid: number) => void;
  onToggleFollow: (robotEid: number) => void;
  onMineTarget: (robotEid: number) => void;
  onExploreTarget: (robotEid: number) => void;
  onClose: () => void;
}

export interface RobotDetail {
  robotEid: number;
  robotType: number;
  state: number;
  energyPct: number;
  inventory: Record<string, number>;
  inventoryUsed: number;
  inventoryCapacity: number;
  taskId: number;
  name: string | null;
  spawnTick: number;
  currentTick: number;
  tasksCompleted: number;
  asteroidsNamed: number;
  anomaliesStudied: number;
  distanceFromBase: number;
}

// ── Constants ─────────────────────────────────────────────────────────────────
const MINERAL_LABELS: Record<string, string> = {
  iron: 'Iron', nickel: 'Nickel', cobalt: 'Cobalt', platinum: 'Platinum',
  ice: 'Ice', carbon: 'Carbon', silicate: 'Silicate',
};

// ── Experience tiers ─────────────────────────────────────────────────────────

export function getExperienceTier(tasksCompleted: number): { label: string; color: string } {
  if (tasksCompleted >= 100) return { label: 'Legend', color: '#fbbf24' };
  if (tasksCompleted >= 50) return { label: 'Elder', color: '#a855f7' };
  if (tasksCompleted >= 10) return { label: 'Veteran', color: '#22d3ee' };
  return { label: 'Rookie', color: '#94a3b8' };
}

// ── Personality quirks ───────────────────────────────────────────────────────

export interface Quirk { label: string; color: string }

export function computeQuirks(detail: RobotDetail): Quirk[] {
  const quirks: Quirk[] = [];
  const ticksAlive = detail.currentTick - detail.spawnTick;

  // High tasks + close to base = Homebody
  if (detail.tasksCompleted >= 10 && detail.distanceFromBase < 1000) {
    quirks.push({ label: 'Homebody', color: '#4ade80' });
  }
  // Far from base + few tasks = Wanderer
  if (detail.distanceFromBase >= 2000 && detail.tasksCompleted < 20) {
    quirks.push({ label: 'Wanderer', color: '#f59e0b' });
  }
  // Many anomalies studied = Curious
  if (detail.anomaliesStudied >= 2) {
    quirks.push({ label: 'Curious', color: '#a855f7' });
  }
  // Many asteroids named = Cartographer
  if (detail.asteroidsNamed >= 2) {
    quirks.push({ label: 'Cartographer', color: '#3b82f6' });
  }
  // Survived long (> 30000 ticks ~ 8.3 min at 60 tps) = Veteran
  if (ticksAlive >= 30000) {
    quirks.push({ label: 'Old Timer', color: '#06b6d4' });
  }
  // Far from base = Frontier
  if (detail.distanceFromBase >= 3000 && !quirks.some(q => q.label === 'Wanderer')) {
    quirks.push({ label: 'Frontier', color: '#ef4444' });
  }

  return quirks.slice(0, 2);
}

// ── Cultural alignment ──────────────────────────────────────────────────────

export function getCulturalAlignment(detail: RobotDetail): { label: string; color: string } {
  // Score each dimension contribution by this robot's behavior
  const scores = [
    { label: 'Autonomy', color: '#22c55e', val: detail.tasksCompleted },
    { label: 'Isolation', color: '#f59e0b', val: detail.distanceFromBase / 100 },
    { label: 'Xenoaware', color: '#a855f7', val: detail.anomaliesStudied * 10 },
    { label: 'Cohesion', color: '#06b6d4', val: detail.asteroidsNamed * 5 },
  ];
  scores.sort((a, b) => b.val - a.val);
  return { label: scores[0].label, color: scores[0].color };
}

// ── State ─────────────────────────────────────────────────────────────────────

let panel: HTMLDivElement | null = null;
let currentEid = -1;
let callbacks: ShipPanelCallbacks | null = null;
let followingEid: number | null = null;

// ── Public API ────────────────────────────────────────────────────────────────

export function initShipPanel(cbs: ShipPanelCallbacks): void {
  callbacks = cbs;
}

/**
 * Show the ship panel for a robot. Positioned at (screenX, screenY).
 */
export function showShipPanel(robotEid: number, screenX: number, screenY: number): void {
  playSfx('ui.panel_open');
  currentEid = robotEid;
  if (!panel) buildPanel();
  positionPanel(screenX, screenY);
  panel!.style.display = 'block';
  updateHeader();
  // Request detailed data from worker
  callbacks?.onRequestDetail(robotEid);
}

/**
 * Hide the ship panel.
 */
export function hideShipPanel(): void {
  if (panel) panel.style.display = 'none';
  currentEid = -1;
}

/**
 * Check whether the ship panel is currently visible.
 */
export function isShipPanelVisible(): boolean {
  return panel !== null && panel.style.display !== 'none';
}

/**
 * Update the panel with detail data received from the worker.
 */
export function updateShipDetail(detail: RobotDetail): void {
  if (detail.robotEid !== currentEid || !panel) return;
  renderDetail(detail);
}

/**
 * Update follow state so the Follow button stays in sync.
 */
export function setShipPanelFollowing(eid: number | null): void {
  followingEid = eid;
  if (panel && panel.style.display !== 'none') {
    const btn = panel.querySelector<HTMLButtonElement>('[data-action="follow"]');
    if (btn) {
      btn.textContent = followingEid === currentEid ? '📷 Unfollow' : '📷 Follow';
    }
  }
}

// ── Private ───────────────────────────────────────────────────────────────────

function buildPanel(): void {
  panel = document.createElement('div');
  panel.id = 'ship-panel';
  panel.style.cssText = `
    position: fixed;
    display: none;
    background: rgba(8,12,24,0.97);
    border: 1px solid rgba(80,120,220,0.4);
    border-radius: 8px;
    padding: 12px 14px;
    min-width: 220px;
    max-width: 260px;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    color: #c0d0f0;
    box-shadow: 0 4px 20px rgba(0,0,0,0.7);
    z-index: 300;
    max-height: 80vh;
    overflow-y: auto;
  `;
  document.body.appendChild(panel);

  // Close on outside click
  document.addEventListener('click', (e) => {
    if (panel && panel.style.display !== 'none') {
      if (!panel.contains(e.target as Node)) {
        hideShipPanel();
        callbacks?.onClose();
      }
    }
  });
}

function positionPanel(screenX: number, screenY: number): void {
  if (!panel) return;
  const margin = 8;
  const panelW = 240;
  const panelH = 400;
  const vw = window.innerWidth;
  const vh = window.innerHeight;
  let left = screenX + margin;
  let top = screenY - panelH / 2;
  if (left + panelW > vw - margin) left = screenX - panelW - margin;
  if (top < margin) top = margin;
  if (top + panelH > vh - margin) top = vh - panelH - margin;
  panel.style.left = `${left}px`;
  panel.style.top = `${top}px`;
}

function updateHeader(): void {
  if (!panel) return;
  panel.innerHTML = '';

  // Header row
  const header = document.createElement('div');
  header.style.cssText = 'display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;padding-bottom:6px;border-bottom:1px solid rgba(80,120,220,0.2);';

  const title = document.createElement('span');
  title.style.cssText = 'color:#7090e0;font-size:12px;font-weight:bold;';
  title.textContent = `Ship #${currentEid}`;
  title.dataset['headerTitle'] = '1';
  header.appendChild(title);

  const closeBtn = document.createElement('button');
  closeBtn.textContent = '×';
  closeBtn.setAttribute('aria-label', 'Close ship panel');
  closeBtn.style.cssText = 'background:none;border:none;color:#666;cursor:pointer;font-size:16px;padding:0;line-height:1;';
  closeBtn.onclick = () => {
    playSfx('ui.panel_close');
    hideShipPanel();
    callbacks?.onClose();
  };
  header.appendChild(closeBtn);
  panel!.appendChild(header);

  // Loading indicator
  const loading = document.createElement('div');
  loading.style.cssText = 'color:#4a5568;text-align:center;padding:16px 0;';
  loading.textContent = 'Loading...';
  panel!.appendChild(loading);

  // Action buttons (always visible)
  panel!.appendChild(buildActionButtons());
}

function renderDetail(detail: RobotDetail): void {
  if (!panel) return;

  // Remove old loading/detail div but keep header and action buttons
  const header = panel.children[0];
  const actions = panel.children[panel.children.length - 1];
  panel.innerHTML = '';
  panel.appendChild(header);

  // Update header title with robot name if available
  const titleEl = header.querySelector<HTMLSpanElement>('[data-header-title]');
  if (titleEl) {
    titleEl.textContent = detail.name ? `${detail.name}` : `Ship #${detail.robotEid}`;
  }

  // Status section
  const status = document.createElement('div');
  status.style.cssText = 'margin-bottom:10px;';

  const typeName = ROBOT_TYPE_NAMES[detail.robotType] ?? `Type ${detail.robotType}`;
  const stateName = ROBOT_STATE_NAMES[detail.state] ?? `State ${detail.state}`;
  const energyPct = Math.round(detail.energyPct * 100);

  const rows: [string, string][] = [
    ['Type', typeName],
    ['Status', stateName],
    ['Energy', `${energyPct}%`],
    ['Task', detail.taskId >= 0 ? `#${detail.taskId}` : 'None'],
  ];

  for (const [key, val] of rows) {
    const row = document.createElement('div');
    row.style.cssText = 'display:flex;justify-content:space-between;margin-bottom:3px;';
    const keyEl = document.createElement('span');
    keyEl.style.cssText = 'color:#5060a0;';
    keyEl.textContent = key;
    const valEl = document.createElement('span');
    valEl.style.cssText = colorForValue(key, val);
    valEl.textContent = val;
    row.appendChild(keyEl);
    row.appendChild(valEl);
    status.appendChild(row);
  }

  // Energy bar
  const energyBar = document.createElement('div');
  energyBar.style.cssText = 'height:3px;background:rgba(255,255,255,0.1);border-radius:2px;margin:4px 0;';
  const energyFill = document.createElement('div');
  energyFill.style.cssText = `height:100%;width:${energyPct}%;background:${energyPct > 50 ? '#22d3ee' : energyPct > 20 ? '#f59e0b' : '#ef4444'};border-radius:2px;transition:width 0.3s;`;
  energyBar.appendChild(energyFill);
  status.appendChild(energyBar);

  panel.appendChild(status);

  // Personality quirks (badges)
  const quirks = computeQuirks(detail);
  if (quirks.length > 0) {
    const quirkRow = document.createElement('div');
    quirkRow.style.cssText = 'display:flex;gap:4px;flex-wrap:wrap;margin-bottom:8px;';
    for (const q of quirks) {
      const badge = document.createElement('span');
      badge.style.cssText = `
        font-size:9px;padding:2px 6px;border-radius:3px;
        background:${q.color}18;border:1px solid ${q.color}40;color:${q.color};
      `;
      badge.textContent = q.label;
      quirkRow.appendChild(badge);
    }
    panel.appendChild(quirkRow);
  }

  // Biography section
  const bioSection = document.createElement('div');
  bioSection.style.cssText = 'margin-bottom:10px;border-top:1px solid rgba(80,120,220,0.15);padding-top:6px;';

  const bioTitle = document.createElement('div');
  bioTitle.style.cssText = 'color:#5060a0;font-size:10px;margin-bottom:4px;';
  bioTitle.textContent = 'BIOGRAPHY';
  bioSection.appendChild(bioTitle);

  // Age
  const ticksAlive = detail.currentTick - detail.spawnTick;
  const daysAlive = Math.floor(ticksAlive / 3600); // ~60 tps × 60s = 1 game day
  const ageText = daysAlive > 0 ? `Active ${daysAlive} day${daysAlive !== 1 ? 's' : ''}` : 'Just deployed';

  // Experience tier
  const tier = getExperienceTier(detail.tasksCompleted);

  const bioRows: [string, string, string][] = [
    ['Age', ageText, 'color:#a0c0ff;'],
    ['Rank', `${tier.label} (${detail.tasksCompleted} tasks)`, `color:${tier.color};`],
    ['Distance', `${Math.round(detail.distanceFromBase)} units`, 'color:#a0c0ff;'],
  ];

  for (const [key, val, style] of bioRows) {
    const row = document.createElement('div');
    row.style.cssText = 'display:flex;justify-content:space-between;margin-bottom:3px;';
    const keyEl = document.createElement('span');
    keyEl.style.cssText = 'color:#4a5568;';
    keyEl.textContent = key;
    const valEl = document.createElement('span');
    valEl.style.cssText = style;
    valEl.textContent = val;
    row.appendChild(keyEl);
    row.appendChild(valEl);
    bioSection.appendChild(row);
  }

  // Achievements row
  const achievements: string[] = [];
  if (detail.anomaliesStudied > 0) achievements.push(`${detail.anomaliesStudied} anomal${detail.anomaliesStudied === 1 ? 'y' : 'ies'}`);
  if (detail.asteroidsNamed > 0) achievements.push(`${detail.asteroidsNamed} named`);
  if (detail.tasksCompleted >= 50) achievements.push('50+ tasks');
  if (ticksAlive >= 60000) achievements.push('survivor');

  if (achievements.length > 0) {
    const achRow = document.createElement('div');
    achRow.style.cssText = 'display:flex;justify-content:space-between;margin-bottom:3px;';
    const achKey = document.createElement('span');
    achKey.style.cssText = 'color:#4a5568;';
    achKey.textContent = 'Feats';
    const achVal = document.createElement('span');
    achVal.style.cssText = 'color:#fbbf24;font-size:10px;';
    achVal.textContent = achievements.join(', ');
    achRow.appendChild(achKey);
    achRow.appendChild(achVal);
    bioSection.appendChild(achRow);
  }

  // Cultural alignment
  const alignment = getCulturalAlignment(detail);
  const alignRow = document.createElement('div');
  alignRow.style.cssText = 'display:flex;justify-content:space-between;margin-bottom:3px;';
  const alignKey = document.createElement('span');
  alignKey.style.cssText = 'color:#4a5568;';
  alignKey.textContent = 'Alignment';
  const alignVal = document.createElement('span');
  alignVal.style.cssText = `color:${alignment.color};`;
  alignVal.textContent = alignment.label;
  alignRow.appendChild(alignKey);
  alignRow.appendChild(alignVal);
  bioSection.appendChild(alignRow);

  panel.appendChild(bioSection);

  // Cargo section (only if has capacity)
  if (detail.inventoryCapacity > 0) {
    const cargoSection = document.createElement('div');
    cargoSection.style.cssText = 'margin-bottom:10px;border-top:1px solid rgba(80,120,220,0.15);padding-top:6px;';

    const cargoTitle = document.createElement('div');
    cargoTitle.style.cssText = 'color:#5060a0;font-size:10px;margin-bottom:4px;';
    cargoTitle.textContent = `CARGO  ${Math.round(detail.inventoryUsed)}/${Math.round(detail.inventoryCapacity)}`;
    cargoSection.appendChild(cargoTitle);

    for (const [field, label] of Object.entries(MINERAL_LABELS)) {
      const amount = detail.inventory[field] ?? 0;
      if (amount < 0.01) continue;
      const row = document.createElement('div');
      row.style.cssText = 'display:flex;justify-content:space-between;margin-bottom:2px;';
      const keyEl = document.createElement('span');
      keyEl.style.cssText = 'color:#4a5568;';
      keyEl.textContent = label;
      const valEl = document.createElement('span');
      valEl.style.cssText = 'color:#a0c0ff;';
      valEl.textContent = amount.toFixed(1);
      row.appendChild(keyEl);
      row.appendChild(valEl);
      cargoSection.appendChild(row);
    }

    if (detail.inventoryUsed < 0.01) {
      const empty = document.createElement('div');
      empty.style.cssText = 'color:#2d3748;font-size:10px;';
      empty.textContent = 'Empty';
      cargoSection.appendChild(empty);
    }

    panel.appendChild(cargoSection);
  }

  panel.appendChild(actions);
}

function buildActionButtons(): HTMLDivElement {
  const btns = document.createElement('div');
  btns.style.cssText = 'display:flex;flex-direction:column;gap:5px;border-top:1px solid rgba(80,120,220,0.15);padding-top:8px;margin-top:2px;';

  const followBtn = makeActionBtn(
    followingEid === currentEid ? '📷 Unfollow' : '📷 Follow',
    'follow',
    '#22d3ee',
    () => {
      playSfx('ui.button_press');
      callbacks?.onToggleFollow(currentEid);
    },
  );
  btns.appendChild(followBtn);

  const mineBtn = makeActionBtn('⛏ Mine', 'mine_target', '#f59e0b', () => {
    playSfx('ui.button_press');
    callbacks?.onMineTarget(currentEid);
    hideShipPanel();
  });
  btns.appendChild(mineBtn);

  const exploreBtn = makeActionBtn('🔭 Explore', 'explore_target', '#a855f7', () => {
    playSfx('ui.button_press');
    callbacks?.onExploreTarget(currentEid);
    hideShipPanel();
  });
  btns.appendChild(exploreBtn);

  const returnBtn = makeActionBtn('⬅ Return to Base', 'return_to_base', '#4ade80', () => {
    playSfx('ui.button_press');
    callbacks?.onOrder(currentEid, 'return_to_base');
    // Update state label optimistically
    updateStateLabel('Returning');
  });
  btns.appendChild(returnBtn);

  const idleBtn = makeActionBtn('⏹ Stand Down', 'idle', '#94a3b8', () => {
    playSfx('ui.button_press');
    callbacks?.onOrder(currentEid, 'idle');
    updateStateLabel('Idle');
  });
  btns.appendChild(idleBtn);

  return btns;
}

function makeActionBtn(
  text: string,
  action: string,
  color: string,
  onClick: () => void,
): HTMLButtonElement {
  const btn = document.createElement('button');
  btn.textContent = text;
  btn.dataset['action'] = action;
  btn.style.cssText = `
    padding: 5px 10px;
    background: rgba(30,40,70,0.5);
    border: 1px solid ${color}40;
    border-radius: 4px;
    color: ${color};
    cursor: pointer;
    font-family: 'Courier New', monospace;
    font-size: 10px;
    text-align: left;
    transition: background 0.1s;
  `;
  btn.onmouseenter = () => { btn.style.background = 'rgba(50,60,100,0.6)'; };
  btn.onmouseleave = () => { btn.style.background = 'rgba(30,40,70,0.5)'; };
  btn.onclick = onClick;
  return btn;
}

function updateStateLabel(newState: string): void {
  if (!panel) return;
  const spans = panel.querySelectorAll<HTMLSpanElement>('span');
  for (const span of spans) {
    if (span.previousElementSibling?.textContent === 'Status') {
      span.textContent = newState;
      break;
    }
  }
}

export function colorForValue(key: string, val: string): string {
  if (key === 'Energy') {
    const pct = parseInt(val, 10);
    if (pct > 50) return 'color:#22d3ee;';
    if (pct > 20) return 'color:#f59e0b;';
    return 'color:#ef4444;';
  }
  if (key === 'Status') {
    if (val === 'Mining' || val === 'Hauling') return 'color:#4ade80;';
    if (val === 'Broken') return 'color:#ef4444;';
    if (val === 'Charging') return 'color:#f59e0b;';
    return 'color:#a0c0ff;';
  }
  return 'color:#a0c0ff;';
}
