/**
 * Material Priority Panel — lets the player set per-mineral fleet utility weights.
 *
 * Robots use these weights to autonomously target asteroids rich in prioritized
 * materials. Higher weight = fleet prefers asteroids with that mineral.
 */

import { MINERAL_FIELDS, type MineralField } from '../sim/minerals';
import { createDefaultWeights, type MaterialWeights } from '../sim/materialPriorities';

type WorkerSend = (msg: object) => void;

let panel: HTMLElement | null = null;
let workerSend: WorkerSend | null = null;
let weights: MaterialWeights = createDefaultWeights();
let visible = false;

const MINERAL_COLORS: Record<MineralField, string> = {
  iron: '#b0b0b0',
  nickel: '#8ec9a0',
  cobalt: '#6e9dd9',
  platinum: '#d4c97a',
  ice: '#88d8f5',
  carbon: '#a08070',
  silicate: '#c0a8d0',
};

const MINERAL_LABELS: Record<MineralField, string> = {
  iron: 'Iron',
  nickel: 'Nickel',
  cobalt: 'Cobalt',
  platinum: 'Platinum',
  ice: 'Ice',
  carbon: 'Carbon',
  silicate: 'Silicate',
};

// ── Init ──────────────────────────────────────────────────────────────────────

export function initMaterialPriorityPanel(sendToWorker: WorkerSend): void {
  workerSend = sendToWorker;

  panel = document.createElement('div');
  panel.id = 'material-priority-panel';
  panel.style.cssText = `
    position: fixed;
    top: 60px;
    left: 20px;
    width: 300px;
    background: rgba(8, 12, 24, 0.95);
    border: 1px solid rgba(56, 189, 248, 0.3);
    border-radius: 8px;
    padding: 16px;
    font-family: 'JetBrains Mono', 'Courier New', monospace;
    font-size: 12px;
    color: #e2e8f0;
    display: none;
    z-index: 200;
    box-shadow: 0 4px 32px rgba(0,0,0,0.7);
  `;

  document.body.appendChild(panel);
  renderPanel();
}

export function toggleMaterialPriorityPanel(): void {
  if (!panel) return;
  visible = !visible;
  panel.style.display = visible ? 'block' : 'none';
}

export function hideMaterialPriorityPanel(): void {
  if (!panel) return;
  visible = false;
  panel.style.display = 'none';
}

export function isMaterialPriorityPanelOpen(): boolean {
  return visible;
}

/** Update weights from a save/load or external source. */
export function setMaterialWeights(w: MaterialWeights): void {
  weights = { ...w };
  renderPanel();
}

// ── Render ────────────────────────────────────────────────────────────────────

function renderPanel(): void {
  if (!panel) return;

  let html = `<div style="margin-bottom:12px;font-size:14px;color:#38bdf8;font-weight:600">Fleet Material Priorities</div>`;
  html += `<div style="margin-bottom:10px;color:#94a3b8;font-size:11px">Higher weight = fleet targets that mineral more aggressively</div>`;

  for (const mineral of MINERAL_FIELDS) {
    const w = weights[mineral];
    const color = MINERAL_COLORS[mineral];
    const label = MINERAL_LABELS[mineral];
    html += `
      <div style="display:flex;align-items:center;margin-bottom:8px;gap:8px">
        <span style="width:70px;color:${color};font-weight:500">${label}</span>
        <input type="range" min="0" max="3" step="0.1" value="${w}"
          data-mineral="${mineral}"
          style="flex:1;accent-color:${color};height:4px;cursor:pointer" />
        <span data-mineral-value="${mineral}" style="width:30px;text-align:right;color:#94a3b8;font-size:11px">${w.toFixed(1)}</span>
      </div>`;
  }

  html += `<div style="display:flex;gap:8px;margin-top:12px">`;
  html += `<button id="mat-reset-btn" style="flex:1;padding:6px;background:rgba(56,189,248,0.1);border:1px solid rgba(56,189,248,0.3);border-radius:4px;color:#38bdf8;cursor:pointer;font-family:inherit;font-size:11px">Reset All</button>`;
  html += `</div>`;

  panel.innerHTML = html;

  // Attach slider listeners
  for (const mineral of MINERAL_FIELDS) {
    const slider = panel.querySelector(`input[data-mineral="${mineral}"]`) as HTMLInputElement;
    if (slider) {
      slider.addEventListener('input', () => {
        const val = parseFloat(slider.value);
        weights[mineral] = val;
        const valueSpan = panel!.querySelector(`[data-mineral-value="${mineral}"]`);
        if (valueSpan) valueSpan.textContent = val.toFixed(1);
      });
      slider.addEventListener('change', () => {
        sendWeights();
      });
    }
  }

  // Reset button
  const resetBtn = panel.querySelector('#mat-reset-btn');
  if (resetBtn) {
    resetBtn.addEventListener('click', () => {
      weights = createDefaultWeights();
      sendWeights();
      renderPanel();
    });
  }
}

function sendWeights(): void {
  if (!workerSend) return;
  workerSend({ type: 'sim:set_material_weights', payload: { weights: { ...weights } } });
}
