/**
 * Difficulty mode definitions and multipliers.
 *
 * Each mode defines multipliers applied during world initialization
 * to mineral density, faction aggression, anomaly chance, and starting resources.
 */

export type DifficultyMode = 'easy' | 'normal' | 'hard';

export interface DifficultySettings {
  mode: DifficultyMode;
  /** Multiplier for baseAsteroidDensity in FieldConfig */
  mineralDensity: number;
  /** Multiplier for faction aggression (territorial hostility delta) */
  factionAggression: number;
  /** Absolute anomaly chance (replaces default) */
  anomalyChance: number;
  /** Multiplier for starting iron specifically */
  startingIronMultiplier: number;
}

export const DIFFICULTY_PRESETS: Record<DifficultyMode, DifficultySettings> = {
  easy: {
    mode: 'easy',
    mineralDensity: 1.5,
    factionAggression: 0.6,
    anomalyChance: 0.01,
    startingIronMultiplier: 2,
  },
  normal: {
    mode: 'normal',
    mineralDensity: 1,
    factionAggression: 1,
    anomalyChance: 0.02,
    startingIronMultiplier: 1,
  },
  hard: {
    mode: 'hard',
    mineralDensity: 0.7,
    factionAggression: 1.4,
    anomalyChance: 0.035,
    startingIronMultiplier: 0.5,
  },
};

export const DIFFICULTY_LABELS: Record<DifficultyMode, string> = {
  easy: 'Easy',
  normal: 'Normal',
  hard: 'Hard',
};

export function getDifficultySettings(mode: DifficultyMode): DifficultySettings {
  return DIFFICULTY_PRESETS[mode];
}
