/**
 * Client-side achievement service for Cultures of the Belt.
 *
 * Deduplicates locally via localStorage, reports to the server proxy,
 * and notifies UI listeners on unlock.
 */
import type { AchievementId } from './definitions';

const STORAGE_KEY = 'cotb_unlocked_achievements_v1';
const PLAYER_ID_KEY = 'cotb_player_id_v1';

function loadUnlocked(): Set<string> {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) return new Set(JSON.parse(raw) as string[]);
  } catch { /* ignore corrupt data */ }
  return new Set();
}

function saveUnlocked(set: Set<string>): void {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify([...set]));
  } catch { /* quota exceeded — not critical */ }
}

/** Get or create a persistent anonymous player ID. */
function getOrCreatePlayerId(): string {
  let id = localStorage.getItem(PLAYER_ID_KEY);
  if (!id) {
    id = `cotb-${crypto.randomUUID()}`;
    localStorage.setItem(PLAYER_ID_KEY, id);
  }
  return id;
}

export type UnlockListener = (achievementId: AchievementId) => void;

export class AchievementService {
  private readonly serverUrl: string;
  private readonly playerId: string;
  private readonly unlocked: Set<string>;
  private readonly listeners: UnlockListener[] = [];

  constructor(serverUrl = '') {
    this.serverUrl = serverUrl;
    this.playerId = getOrCreatePlayerId();
    this.unlocked = loadUnlocked();
  }

  /** Register a callback fired on each new unlock. */
  onUnlock(cb: UnlockListener): void {
    this.listeners.push(cb);
  }

  /** Attempt to unlock an achievement. No-ops if already unlocked. */
  async unlock(
    id: AchievementId,
    gameContext: Record<string, unknown> = {},
  ): Promise<void> {
    if (this.unlocked.has(id)) return;

    this.unlocked.add(id);
    saveUnlocked(this.unlocked);

    for (const cb of this.listeners) {
      try { cb(id); } catch (e) { console.warn('[AchievementService] listener error:', e); }
    }

    await this._report(id, gameContext);
  }

  /** Check whether an achievement has already been unlocked locally. */
  isUnlocked(id: AchievementId): boolean {
    return this.unlocked.has(id);
  }

  private async _report(
    achievementId: string,
    gameContext: Record<string, unknown>,
  ): Promise<void> {
    try {
      const res = await fetch(`${this.serverUrl}/api/achievements/unlock`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          achievementId,
          playerId: this.playerId,
          gameContext: { ...gameContext, gameOrigin: 'cotb' },
        }),
      });
      if (!res.ok) {
        console.warn(`[AchievementService] unlock failed (${res.status}) for ${achievementId}`);
      }
    } catch (err) {
      console.warn('[AchievementService] network error:', err);
    }
  }
}
