/**
 * Renderer initialization — creates all Three.js objects, instanced renderers,
 * and the CameraRig. Returns handles consumed by the render loop and input handlers.
 *
 * No simulation state is touched here; this is purely a Three.js setup module.
 */
import { Mesh, MeshBasicMaterial, Plane, RingGeometry, Vector2, Vector3, Scene, PerspectiveCamera, AmbientLight, DirectionalLight } from 'three';
import { EffectComposer } from 'three/examples/jsm/postprocessing/EffectComposer.js';
import { UnrealBloomPass } from 'three/examples/jsm/postprocessing/UnrealBloomPass.js';
import { initRenderer } from './render/renderer';
import { CameraRig } from './render/camera/CameraRig';
import { InstancedAsteroidRenderer } from './render/instancing/InstancedAsteroidRenderer';
import { ParallaxSkybox } from './render/background/ParallaxSkybox';
import { DecorativeParticles } from './render/particles/DecorativeParticles';
import { MiningParticles } from './render/particles/MiningParticles';
import { ThrusterParticles } from './render/particles/ThrusterParticles';
import { DepletionParticles } from './render/particles/DepletionParticles';
import { RobotRenderer } from './render/RobotRenderer';
import { BaseStationRenderer } from './render/BaseStationRenderer';
import { ThreatRenderer } from './render/ThreatRenderer';
import { BeltRegionRenderer } from './render/BeltRegionRenderer';
import { EntityRenderer } from './render/EntityRenderer';
import { MegastructureRenderer } from './render/MegastructureRenderer';
import { NamedLocationLabels } from './render/NamedLocationLabels';
import { ClaimMarkerRenderer } from './render/ClaimMarkerRenderer';
import { TerritoryZoneRenderer } from './render/TerritoryZoneRenderer';
import { SolarSystemRenderer } from './render/background/SolarSystemRenderer';
import { BuildingRenderer } from './render/BuildingRenderer';
import { DEFAULT_FIELD_CONFIG } from './sim/asteroidGen';
import { pause as pauseGameLoop, resume as resumeGameLoop } from './core/gameLoop';
import { showNotification } from './ui/notifications';

export interface RendererHandles {
  scene: Scene;
  camera: PerspectiveCamera;
  composer: EffectComposer;
  bloomPass: UnrealBloomPass;
  ambientLight: AmbientLight;
  sunLight: DirectionalLight;
  cameraRig: CameraRig;
  /** World X coordinate of the primary base station. */
  baseX: number;
  /** World Z coordinate of the primary base station. */
  baseZ: number;
  asteroidRenderer: InstancedAsteroidRenderer;
  robotRenderer: RobotRenderer;
  skybox: ParallaxSkybox;
  beltRegionRenderer: BeltRegionRenderer;
  particles: DecorativeParticles;
  miningParticles: MiningParticles;
  depletionParticles: DepletionParticles;
  thrusterParticles: ThrusterParticles;
  baseStation: BaseStationRenderer;
  /** Additional (non-primary) base station renderers, grown at runtime. */
  extraBaseRenderers: BaseStationRenderer[];
  entityRenderer: EntityRenderer;
  megastructureRenderer: MegastructureRenderer;
  threatRenderer: ThreatRenderer;
  namedLocationLabels: NamedLocationLabels;
  claimMarkerRenderer: ClaimMarkerRenderer;
  territoryZoneRenderer: TerritoryZoneRenderer;
  solarSystemRenderer: SolarSystemRenderer;
  buildingRenderer: BuildingRenderer;
  /** Follow-mode ring mesh pulsed around the selected robot. */
  followRingMesh: Mesh;
  followRingMat: MeshBasicMaterial;
  /** Ghost ring shown during base-placement mode. */
  placementGhostMesh: Mesh;
  placementGhostMat: MeshBasicMaterial;
  /** Horizontal plane used for raycasting during base placement. */
  placementPlane: Plane;
  /** Scratch Vector2 for placement raycasting NDC coordinates. */
  placementNdc: Vector2;
  /** Scratch Vector3 for placement raycasting world target. */
  placementTarget: Vector3;
}

export async function initRenderers(canvas: HTMLCanvasElement): Promise<RendererHandles> {
  const { scene, camera, composer, bloomPass, ambientLight, sunLight } = await initRenderer(canvas, {
    onContextLost: () => {
      pauseGameLoop();
      showNotification('[ARIA] Graphics context lost — attempting restore', '#f59e0b');
    },
    onContextRestored: () => {
      resumeGameLoop();
      showNotification('[ARIA] Graphics context restored', '#22c55e');
    },
  });

  const cameraRig = new CameraRig(camera);
  const baseCX = Math.floor(DEFAULT_FIELD_CONFIG.beltInnerRadius / DEFAULT_FIELD_CONFIG.chunkSize);
  const baseX = baseCX * DEFAULT_FIELD_CONFIG.chunkSize + DEFAULT_FIELD_CONFIG.chunkSize * 0.5;
  const baseZ = DEFAULT_FIELD_CONFIG.chunkSize * 0.5;
  const INITIAL_ZOOM = Math.log(3000);
  cameraRig.setPivot(baseX, 0, baseZ);
  cameraRig.setZoom(INITIAL_ZOOM);

  const asteroidRenderer = new InstancedAsteroidRenderer(scene);
  const robotRenderer = new RobotRenderer(scene);
  const skybox = new ParallaxSkybox(scene);
  const beltRegionRenderer = new BeltRegionRenderer(ambientLight, sunLight, skybox);
  const particles = new DecorativeParticles(scene);
  const miningParticles = new MiningParticles(scene);
  const depletionParticles = new DepletionParticles(scene);
  const thrusterParticles = new ThrusterParticles(scene);

  const baseStation = new BaseStationRenderer(
    scene,
    baseX,
    0,
    DEFAULT_FIELD_CONFIG.chunkSize * 0.5,
  );

  const followRingGeo = new RingGeometry(8, 10, 32);
  const followRingMat = new MeshBasicMaterial({ color: 0x22d3ee, transparent: true, opacity: 0 });
  const followRingMesh = new Mesh(followRingGeo, followRingMat);
  followRingMesh.rotation.x = -Math.PI / 2;
  scene.add(followRingMesh);

  const placementGhostGeo = new RingGeometry(18, 22, 32);
  const placementGhostMat = new MeshBasicMaterial({ color: 0x22d3ee, transparent: true, opacity: 0 });
  const placementGhostMesh = new Mesh(placementGhostGeo, placementGhostMat);
  placementGhostMesh.rotation.x = -Math.PI / 2;
  scene.add(placementGhostMesh);

  const entityRenderer = new EntityRenderer(scene);

  const megastructureRenderer = new MegastructureRenderer(
    scene,
    baseX,
    0,
    DEFAULT_FIELD_CONFIG.chunkSize * 0.5,
  );

  const threatRenderer = new ThreatRenderer(scene);

  const namedLocationLabels = new NamedLocationLabels();
  const claimMarkerRenderer = new ClaimMarkerRenderer(scene);
  const territoryZoneRenderer = new TerritoryZoneRenderer(scene);
  const solarSystemRenderer = new SolarSystemRenderer(scene);
  const buildingRenderer = new BuildingRenderer(scene);

  return {
    scene,
    camera,
    composer,
    bloomPass,
    ambientLight,
    sunLight,
    cameraRig,
    baseX,
    baseZ,
    asteroidRenderer,
    robotRenderer,
    skybox,
    beltRegionRenderer,
    particles,
    miningParticles,
    depletionParticles,
    thrusterParticles,
    baseStation,
    extraBaseRenderers: [],
    entityRenderer,
    megastructureRenderer,
    threatRenderer,
    namedLocationLabels,
    claimMarkerRenderer,
    territoryZoneRenderer,
    solarSystemRenderer,
    buildingRenderer,
    followRingMesh,
    followRingMat,
    placementGhostMesh,
    placementGhostMat,
    placementPlane: new Plane(new Vector3(0, 1, 0), 0),
    placementNdc: new Vector2(),
    placementTarget: new Vector3(),
  };
}
