/**
 * Shared building type constants and serialization types.
 *
 * Imported by both sim and render layers — keeps the worker/main thread boundary clean.
 */

export const BUILDING_TYPES = {
  FACTORY: 0,
  TURRET: 1,
  RELAY: 2,
  SOLAR_PANEL: 3,
  RADIATOR: 4,
  SOLAR_FURNACE: 5,
  RTG_MODULE: 6,
  FISSION_REACTOR: 7,
  FUSION_REACTOR: 8,
  ENERGY_RELAY: 9,
} as const;

export type BuildingType = (typeof BUILDING_TYPES)[keyof typeof BUILDING_TYPES];

export const CONSTRUCTION_STATE = {
  PLANNED: 0,
  UNDER_CONSTRUCTION: 1,
  COMPLETE: 2,
} as const;

export type ConstructionState = (typeof CONSTRUCTION_STATE)[keyof typeof CONSTRUCTION_STATE];

export interface SerializedBuilding {
  id: number;
  type: number;
  health: number;
  active: boolean;
  worldX: number;
  worldY: number;
  worldZ: number;
  constructionState: number;
  constructionProgress: number;
}
