/**
 * Timeline tab renderer — resource history line chart (Canvas 2D).
 */

import { MINERAL_FIELDS } from '../../sim/minerals';
import { ResourceSample, SAMPLE_INTERVAL_TICKS, RESOURCE_COLORS, RESOURCE_LABELS } from './types';
import { sectionHeader, formatNum } from './helpers';

// Canvas element cached across renders
let timelineCanvas: HTMLCanvasElement | null = null;

export interface TimelineTabData {
  resourceHistory: ResourceSample[];
}

/** Call when switching away from the timeline tab to invalidate the cached canvas. */
export function invalidateTimelineCanvas(): void {
  timelineCanvas = null;
}

export function renderTimelineTab(container: HTMLDivElement, data: TimelineTabData): void {
  const { resourceHistory } = data;

  // Reuse canvas if already in container
  if (!timelineCanvas || !container.contains(timelineCanvas)) {
    container.innerHTML = '';

    container.appendChild(sectionHeader('Resource History'));

    const hint = document.createElement('div');
    hint.style.cssText = 'color:#4a5568;font-size:10px;margin-bottom:8px;';
    hint.textContent = `${resourceHistory.length} samples — 1 per ${SAMPLE_INTERVAL_TICKS} ticks`;
    container.appendChild(hint);

    // Legend
    const legend = document.createElement('div');
    legend.style.cssText = 'display:flex;gap:12px;margin-bottom:8px;flex-wrap:wrap;';
    for (let i = 0; i < 4; i++) {
      const item = document.createElement('span');
      item.style.cssText = `color:${RESOURCE_COLORS[i]};font-size:10px;`;
      item.textContent = `■ ${RESOURCE_LABELS[i]}`;
      legend.appendChild(item);
    }
    container.appendChild(legend);

    const canvas = document.createElement('canvas');
    canvas.width = 388;
    canvas.height = 220;
    canvas.style.cssText = 'border:1px solid rgba(100,120,200,0.15);border-radius:3px;';
    container.appendChild(canvas);
    timelineCanvas = canvas;
  }

  drawTimelineChart(timelineCanvas, resourceHistory);
}

function drawTimelineChart(canvas: HTMLCanvasElement, resourceHistory: ResourceSample[]): void {
  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  const W = canvas.width;
  const H = canvas.height;
  const PAD = { top: 10, right: 10, bottom: 24, left: 50 };
  const cW = W - PAD.left - PAD.right;
  const cH = H - PAD.top - PAD.bottom;

  // Background
  ctx.fillStyle = 'rgba(8,10,18,0.9)';
  ctx.fillRect(0, 0, W, H);

  if (resourceHistory.length < 2) {
    ctx.fillStyle = '#4a5568';
    ctx.font = '11px "Courier New"';
    ctx.textAlign = 'center';
    ctx.fillText('Collecting data…', W / 2, H / 2);
    return;
  }

  // Compute max value for Y axis
  let maxVal = 1;
  for (const s of resourceHistory) {
    maxVal = Math.max(maxVal, ...Array.from(s.values));
  }

  // Grid lines
  ctx.strokeStyle = 'rgba(100,120,200,0.1)';
  ctx.lineWidth = 1;
  const gridLines = 4;
  for (let g = 0; g <= gridLines; g++) {
    const y = PAD.top + cH - (g / gridLines) * cH;
    ctx.beginPath();
    ctx.moveTo(PAD.left, y);
    ctx.lineTo(PAD.left + cW, y);
    ctx.stroke();

    // Y labels
    const v = (g / gridLines) * maxVal;
    ctx.fillStyle = '#4a5568';
    ctx.font = '9px "Courier New"';
    ctx.textAlign = 'right';
    ctx.fillText(formatNum(v), PAD.left - 4, y + 3);
  }

  // X axis tick labels (time)
  const firstTick = resourceHistory[0].tick;
  const lastTick = resourceHistory[resourceHistory.length - 1].tick;

  ctx.fillStyle = '#4a5568';
  ctx.font = '9px "Courier New"';
  ctx.textAlign = 'center';
  const xTicks = 4;
  for (let xt = 0; xt <= xTicks; xt++) {
    const tick = firstTick + (xt / xTicks) * (lastTick - firstTick);
    const x = PAD.left + (xt / xTicks) * cW;
    ctx.fillText(`T${Math.round(tick / 60)}s`, x, H - 6);
  }

  // Draw lines for each resource (all 7 minerals)
  const n = resourceHistory.length;

  for (let ri = 0; ri < MINERAL_FIELDS.length; ri++) {
    ctx.strokeStyle = RESOURCE_COLORS[ri];
    ctx.lineWidth = 1.5;
    ctx.beginPath();

    for (let i = 0; i < n; i++) {
      const sample = resourceHistory[i];
      const x = PAD.left + (i / (n - 1)) * cW;
      const y = PAD.top + cH - (sample.values[ri] / maxVal) * cH;
      if (i === 0) ctx.moveTo(x, y);
      else ctx.lineTo(x, y);
    }
    ctx.stroke();
  }

  // Y axis line
  ctx.strokeStyle = 'rgba(100,120,200,0.3)';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(PAD.left, PAD.top);
  ctx.lineTo(PAD.left, PAD.top + cH);
  ctx.stroke();
}
