/**
 * Belt Echoes — Progression Stage Mapping
 *
 * Maps the player's tech tree state to a progression stage (1-5)
 * used to gate which echo templates are visible.
 *
 * Stage 1: Basic mining/logistics (start)
 * Stage 2: Research unlocked, multi-base operations
 * Stage 3: Advanced energy, factions engaged, advanced anomaly research
 * Stage 4: Megastructures, habitat module, late-game logistics
 * Stage 5: Fusion prototype, dark forest protocol, endgame
 */

import { TECH_NODES, type TechNode } from '../sim/techTree';

/** Node indices by id, built once. */
const NODE_INDEX_BY_ID = new Map<string, number>();
for (const node of TECH_NODES) {
  NODE_INDEX_BY_ID.set(node.id, node.index);
}

function isUnlocked(mask: bigint, nodeId: string): boolean {
  const index = NODE_INDEX_BY_ID.get(nodeId);
  if (index === undefined) return false;
  return (mask & (1n << BigInt(index))) !== 0n;
}

/** Tech gates for each progression stage (player must have ANY of the listed nodes). */
const STAGE_GATES: Array<{ stage: number; anyOf: string[] }> = [
  {
    stage: 5,
    anyOf: ['fusion_prototype', 'dark_forest_protocol'],
  },
  {
    stage: 4,
    anyOf: ['habitat_module', 'automated_production', 'mass_driver'],
  },
  {
    stage: 3,
    anyOf: ['fission_reactor', 'signal_analysis', 'defense_systems', 'sector_mapping'],
  },
  {
    stage: 2,
    anyOf: ['researcher_bots', 'multi_base', 'robot_factory', 'ion_drives'],
  },
];

/**
 * Compute the player's progression stage (1-5) from the tech tree bitmask.
 * Returns 1 if no stage gates are met.
 */
export function getProgressionStage(unlockedMask: bigint): number {
  for (const gate of STAGE_GATES) {
    if (gate.anyOf.some((nodeId) => isUnlocked(unlockedMask, nodeId))) {
      return gate.stage;
    }
  }
  return 1;
}
