/**
 * Shared belt region types, boundaries, and lookup.
 *
 * Imported by both sim and render layers — keeps the worker/main thread boundary clean.
 */

export type BeltRegion =
  | 'kindling_ring'
  | 'shardfall_gap'
  | 'consortium_fields'
  | 'pale_meridian'
  | 'veil_reach'
  | 'the_forgetting';

/** Region boundary radii matching gap positions in DEFAULT_FIELD_CONFIG */
export const BELT_REGION_BOUNDARIES: ReadonlyArray<[number, BeltRegion]> = [
  [14250, 'kindling_ring'],
  [16500, 'shardfall_gap'],
  [23750, 'consortium_fields'],
  [27250, 'pale_meridian'],
  [38750, 'veil_reach'],
  [Infinity, 'the_forgetting'],
];

/** Map radial distance from origin to named belt region */
export function getBeltRegion(radialDist: number): BeltRegion {
  for (const [boundary, region] of BELT_REGION_BOUNDARIES) {
    if (radialDist < boundary) return region;
  }
  return 'the_forgetting';
}
