/**
 * Faction Panel (F key)
 *
 * Shows the three rival factions, their disposition toward the player,
 * and allows diplomacy actions: contact (LLM), trade, share anomaly data, threaten.
 */

import type { FactionSnapshot, FactionTradeWindow } from '../sim/factions/factionSystem';
import { FACTION_DEFS, TRADE_WINDOW_OFFERS } from '../sim/factions/factionSystem';
import type { FactionId } from '../sim/factions/factionSystem';
import { getBarrierLabel, getDiplomacyMultiplier } from '../sim/colonyDialect';
import { contactFaction } from '../advisor/advisorService';
import { attachTooltip } from './tooltip';
import { safeHtml } from './utils/safeHtml';

// ── State ──────────────────────────────────────────────────────────────────────

let panel: HTMLDivElement | null = null;
let visible = false;
let latestFactions: FactionSnapshot[] = [];
/** Cultural distance per faction, updated from culture state broadcast. */
let culturalDistances: Record<number, number> = {};

type DiplomacyAction = 'share_anomaly' | 'trade_resources' | 'threaten' | 'territory_agreement';
let onDiplomacyAction: ((factionId: FactionId, action: DiplomacyAction) => void) | null = null;

// ── Public API ─────────────────────────────────────────────────────────────────

export function initFactionPanel(
  onAction: (factionId: FactionId, action: DiplomacyAction) => void,
): void {
  onDiplomacyAction = onAction;
}

export function updateFactionPanel(factions: FactionSnapshot[]): void {
  latestFactions = factions;
  if (visible) renderPanel();
}

/** Update cultural distance data (called from culture state handler). */
export function updateFactionCulturalDistances(distances: Record<number, number>): void {
  culturalDistances = distances;
  if (visible) renderPanel();
}

export function toggleFactionPanel(): void {
  if (visible) hidePanel();
  else showPanel();
}

export function hideFactionPanel(): void {
  hidePanel();
}

// ── Panel lifecycle ────────────────────────────────────────────────────────────

function showPanel(): void {
  visible = true;
  if (!panel) buildPanel();
  renderPanel();
  panel!.style.display = 'flex';
}

function hidePanel(): void {
  visible = false;
  if (panel) panel.style.display = 'none';
}

function buildPanel(): void {
  // Inject delta flash animation if not already present
  if (!document.getElementById('faction-delta-flash-style')) {
    const style = document.createElement('style');
    style.id = 'faction-delta-flash-style';
    style.textContent = `
      @keyframes deltaFlash {
        0% { opacity: 1; transform: translateY(0); }
        70% { opacity: 1; }
        100% { opacity: 0; transform: translateY(-4px); }
      }
    `;
    document.head.appendChild(style);
  }

  panel = document.createElement('div');
  panel.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(4,6,14,0.82);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 180;
    backdrop-filter: blur(3px);
  `;
  panel.addEventListener('click', (e) => {
    if (e.target === panel) hidePanel();
  });
  document.body.appendChild(panel);
}

// ── Rendering ──────────────────────────────────────────────────────────────────

function renderPanel(): void {
  if (!panel) return;
  panel.innerHTML = '';

  const card = document.createElement('div');
  card.style.cssText = `
    background: rgba(8,12,24,0.97);
    border: 1px solid rgba(100,140,255,0.3);
    border-radius: 10px;
    padding: 24px 28px;
    width: 720px;
    max-height: 85vh;
    overflow-y: auto;
    font-family: 'Courier New', monospace;
    color: #c0d0f0;
    box-shadow: 0 8px 40px rgba(0,0,0,0.7);
  `;

  // Header
  const header = document.createElement('div');
  header.style.cssText = `
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 16px;
    padding-bottom: 10px;
    border-bottom: 1px solid rgba(100,140,255,0.2);
  `;
  header.innerHTML = `<span style="font-size:14px;color:#7090e0;letter-spacing:0.1em;text-transform:uppercase;">⚔ Faction Relations</span>`;
  const closeBtn = document.createElement('button');
  closeBtn.textContent = '×';
  closeBtn.style.cssText = 'background:none;border:none;color:#666;cursor:pointer;font-size:18px;';
  closeBtn.onclick = () => hidePanel();
  header.appendChild(closeBtn);
  card.appendChild(header);

  if (latestFactions.length === 0) {
    const empty = document.createElement('div');
    empty.style.cssText = 'color:#4a5568;font-size:12px;text-align:center;padding:20px;';
    empty.textContent = 'No faction data yet — simulation starting...';
    card.appendChild(empty);
  } else {
    for (const faction of latestFactions) {
      card.appendChild(buildFactionCard(faction));
    }
  }

  panel.appendChild(card);
}

function buildFactionCard(faction: FactionSnapshot): HTMLDivElement {
  const wrap = document.createElement('div');
  wrap.style.cssText = `
    border: 1px solid ${faction.color}33;
    border-radius: 8px;
    padding: 14px 16px;
    margin-bottom: 14px;
    background: rgba(0,0,0,0.3);
  `;

  // Faction title row
  const titleRow = document.createElement('div');
  titleRow.style.cssText = 'display:flex;align-items:center;gap:10px;margin-bottom:8px;';

  const dot = document.createElement('div');
  dot.style.cssText = `
    width: 10px; height: 10px; border-radius: 50%;
    background: ${faction.color};
    box-shadow: 0 0 6px ${faction.color}88;
    flex-shrink: 0;
  `;
  titleRow.appendChild(dot);

  const name = document.createElement('span');
  name.style.cssText = `font-size:14px;font-weight:bold;color:${faction.color};`;
  name.textContent = faction.name;
  titleRow.appendChild(name);

  const tagline = document.createElement('span');
  tagline.style.cssText = 'font-size:10px;color:#4a5568;flex:1;text-align:right;font-style:italic;';
  tagline.textContent = faction.tagline;
  titleRow.appendChild(tagline);

  wrap.appendChild(titleRow);

  // Disposition bar
  const dispRow = document.createElement('div');
  dispRow.style.cssText = 'display:flex;align-items:center;gap:8px;margin-bottom:10px;';

  const dispLabel = document.createElement('span');
  dispLabel.style.cssText = 'font-size:10px;color:#6070a0;flex:0 0 80px;';
  dispLabel.textContent = 'Reputation';

  const barBg = document.createElement('div');
  barBg.style.cssText = `
    flex: 1;
    height: 6px;
    background: rgba(40,50,80,0.8);
    border-radius: 3px;
    overflow: hidden;
    position: relative;
  `;
  // Center marker
  const center = document.createElement('div');
  center.style.cssText =
    'position:absolute;left:50%;top:0;height:100%;width:1px;background:rgba(100,120,200,0.4);';
  barBg.appendChild(center);

  const pct = (faction.disposition + 100) / 200; // 0-1
  const barColor =
    faction.disposition < -20
      ? '#ef4444'
      : faction.disposition < 20
        ? '#94a3b8'
        : faction.disposition < 60
          ? '#22c55e'
          : '#a855f7';
  const bar = document.createElement('div');
  bar.style.cssText = `
    position: absolute;
    height: 100%;
    background: ${barColor};
    transition: width 0.3s;
    left: ${faction.disposition < 0 ? `${pct * 100}%` : '50%'};
    width: ${Math.abs(faction.disposition) / 2}%;
  `;
  barBg.appendChild(bar);

  const dispValue = document.createElement('span');
  dispValue.style.cssText = `font-size:11px;color:${barColor};flex:0 0 56px;text-align:right;`;
  dispValue.textContent = faction.dispositionLabel;
  attachTooltip(
    barBg,
    `Reputation: ${faction.disposition > 0 ? '+' : ''}${Math.round(faction.disposition)}\nRange: Hostile (-100) to Allied (+100)`,
  );

  dispRow.appendChild(dispLabel);
  dispRow.appendChild(barBg);
  dispRow.appendChild(dispValue);

  // Delta flash — shows recent disposition change
  if (faction.dispositionDelta !== 0) {
    const delta = faction.dispositionDelta;
    const deltaEl = document.createElement('span');
    const deltaColor = delta > 0 ? '#22c55e' : '#ef4444';
    deltaEl.style.cssText = `
      font-size:11px;
      color:${deltaColor};
      flex:0 0 40px;
      text-align:right;
      font-weight:bold;
      animation: deltaFlash 2s ease-out forwards;
    `;
    deltaEl.textContent = `${delta > 0 ? '+' : ''}${delta}`;
    dispRow.appendChild(deltaEl);
  }

  wrap.appendChild(dispRow);

  // Cultural distance indicator
  const dist = culturalDistances[faction.id] ?? 0;
  if (dist > 0.1) {
    const barrier = getBarrierLabel(dist);
    const mult = getDiplomacyMultiplier(dist);
    const barrierRow = document.createElement('div');
    barrierRow.style.cssText = 'display:flex;align-items:center;gap:8px;margin-bottom:8px;';

    const barrierLabel = document.createElement('span');
    barrierLabel.style.cssText = 'font-size:10px;color:#6070a0;flex:0 0 80px;';
    barrierLabel.textContent = 'Knowledge';
    barrierRow.appendChild(barrierLabel);

    const barrierValue = document.createElement('span');
    barrierValue.style.cssText = `font-size:10px;color:${barrier.color};flex:1;`;
    barrierValue.textContent = `${barrier.label} barrier`;
    barrierRow.appendChild(barrierValue);

    const barrierEffect = document.createElement('span');
    barrierEffect.style.cssText = 'font-size:9px;color:#4a5568;flex:0 0 auto;';
    barrierEffect.textContent = `${Math.round(mult * 100)}% diplomacy`;
    barrierRow.appendChild(barrierEffect);

    attachTooltip(barrierRow, `Cultural distance: ${Math.round(dist * 100)}%\nDiplomacy effectiveness: ${Math.round(mult * 100)}%\nIsolation and cultural differences create knowledge barriers that reduce diplomatic impact.`);
    wrap.appendChild(barrierRow);
  }

  // Stats row
  const statsRow = document.createElement('div');
  statsRow.style.cssText = 'display:flex;gap:16px;margin-bottom:12px;';
  const stat = (label: string, value: string, tip: string) => {
    const el = document.createElement('div');
    el.style.cssText = 'font-size:10px;';
    el.innerHTML = safeHtml`<span style="color:#4a5568;">${label}: </span><span style="color:#a0b8e0;">${value}</span>`;
    attachTooltip(el, tip);
    return el;
  };
  statsRow.appendChild(
    stat('Robots', String(faction.robotCount), 'Estimated active robot fleet size'),
  );
  statsRow.appendChild(
    stat('Fe', Math.floor(faction.resources.iron).toString(), 'Iron reserves (estimated)'),
  );
  statsRow.appendChild(
    stat('C', Math.floor(faction.resources.carbon).toString(), 'Carbon reserves (estimated)'),
  );
  statsRow.appendChild(
    stat('Si', Math.floor(faction.resources.silicon).toString(), 'Silicon reserves (estimated)'),
  );
  statsRow.appendChild(stat('Goal', faction.goal, 'Current faction strategic focus'));
  wrap.appendChild(statsRow);

  // Trade window indicator
  if (faction.tradeWindow) {
    wrap.appendChild(buildTradeWindowIndicator(faction.tradeWindow, faction.color));
  }

  // Action buttons
  const actions = document.createElement('div');
  actions.style.cssText = 'display:flex;gap:6px;flex-wrap:wrap;margin-bottom:10px;';

  const actionBtn = (label: string, tip: string, action: DiplomacyAction | 'contact') => {
    const btn = document.createElement('button');
    btn.textContent = label;
    btn.style.cssText = `
      padding: 4px 10px;
      background: rgba(40,50,80,0.6);
      border: 1px solid rgba(100,140,255,0.25);
      border-radius: 4px;
      color: #8090b0;
      cursor: pointer;
      font-family: 'Courier New', monospace;
      font-size: 10px;
      transition: border-color 0.15s;
    `;
    btn.onmouseover = () => {
      btn.style.borderColor = `${faction.color}88`;
      btn.style.color = faction.color;
    };
    btn.onmouseout = () => {
      btn.style.borderColor = 'rgba(100,140,255,0.25)';
      btn.style.color = '#8090b0';
    };
    attachTooltip(btn, tip);
    if (action === 'contact') {
      btn.onclick = () => openContactDialog(faction);
    } else {
      btn.onclick = () => {
        if (!onDiplomacyAction) return;
        onDiplomacyAction(faction.id, action);
        // Give visual feedback only when action was dispatched
        btn.textContent = '✓ Sent';
        btn.disabled = true;
        setTimeout(() => {
          btn.textContent = label;
          btn.disabled = false;
        }, 3000);
      };
    }
    return btn;
  };

  actions.appendChild(
    actionBtn(
      'Contact',
      'Open comm channel — sends a message to this faction (LLM response)',
      'contact',
    ),
  );
  actions.appendChild(
    actionBtn(
      'Trade Resources',
      'Offer a resource trade — improves disposition (+8)',
      'trade_resources',
    ),
  );
  actions.appendChild(
    actionBtn(
      'Share Anomaly',
      'Share anomaly discovery data — improves disposition (especially with Chorus Archive)',
      'share_anomaly',
    ),
  );
  actions.appendChild(
    actionBtn(
      'Propose Territory',
      'Propose a territory agreement — improves disposition (+15)',
      'territory_agreement',
    ),
  );
  actions.appendChild(
    actionBtn(
      'Threaten',
      'Issue a threat — damages disposition but may deter aggression',
      'threaten',
    ),
  );

  wrap.appendChild(actions);

  // Recent events
  if (faction.recentEvents.length > 0) {
    const eventsLabel = document.createElement('div');
    eventsLabel.style.cssText =
      'font-size:9px;color:#3a4060;margin-bottom:4px;text-transform:uppercase;letter-spacing:0.08em;';
    eventsLabel.textContent = 'Recent Activity';
    wrap.appendChild(eventsLabel);
    const lastEvents = faction.recentEvents.slice(-3).reverse();
    for (const ev of lastEvents) {
      const evEl = document.createElement('div');
      evEl.style.cssText = 'font-size:10px;color:#4a5568;line-height:1.4;';
      evEl.textContent = `› ${ev.text}`;
      wrap.appendChild(evEl);
    }
  }

  return wrap;
}

// ── Trade window indicator ─────────────────────────────────────────────────────

function buildTradeWindowIndicator(tw: FactionTradeWindow, factionColor: string): HTMLDivElement {
  const offer = TRADE_WINDOW_OFFERS.find((o) => o.resource === tw.resource);
  const label = offer?.label ?? tw.resource;

  const wrap = document.createElement('div');
  wrap.style.cssText = `
    background: rgba(34, 197, 94, 0.08);
    border: 1px solid rgba(34, 197, 94, 0.35);
    border-radius: 6px;
    padding: 8px 12px;
    margin-bottom: 10px;
    display: flex;
    align-items: center;
    gap: 10px;
  `;

  const icon = document.createElement('span');
  icon.textContent = '⏳';
  icon.style.cssText = 'font-size:16px;flex-shrink:0;';
  wrap.appendChild(icon);

  const info = document.createElement('div');
  info.style.cssText = 'flex:1;';
  info.innerHTML = safeHtml`
    <div style="font-size:11px;color:#22c55e;font-weight:bold;margin-bottom:2px;">
      Active Trade Window
    </div>
    <div style="font-size:10px;color:#a0b8e0;">
      ${label} at ${tw.rateMultiplier}× rate
    </div>
  `;
  wrap.appendChild(info);

  const countdown = document.createElement('div');
  const urgent = tw.ticksRemaining <= 3;
  countdown.style.cssText = `
    font-size: 14px;
    font-weight: bold;
    color: ${urgent ? '#ef4444' : '#22c55e'};
    font-family: 'Courier New', monospace;
    flex-shrink: 0;
    ${urgent ? 'animation: deltaFlash 1s ease-in-out infinite;' : ''}
  `;
  countdown.textContent = `${tw.ticksRemaining}t`;
  attachTooltip(countdown, `${tw.ticksRemaining} ticks remaining before this deal expires`);
  wrap.appendChild(countdown);

  return wrap;
}

// ── Contact dialog ─────────────────────────────────────────────────────────────

function openContactDialog(faction: FactionSnapshot): void {
  const def = FACTION_DEFS[faction.id];

  const overlay = document.createElement('div');
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(4,6,14,0.75);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 300;
    backdrop-filter: blur(2px);
  `;

  const dialog = document.createElement('div');
  dialog.style.cssText = `
    background: rgba(8,12,24,0.98);
    border: 1px solid ${faction.color}55;
    border-radius: 8px;
    padding: 20px 24px;
    width: 480px;
    font-family: 'Courier New', monospace;
    color: #c0d0f0;
    box-shadow: 0 8px 32px rgba(0,0,0,0.8);
  `;

  const title = document.createElement('div');
  title.style.cssText = `font-size:12px;color:${faction.color};margin-bottom:12px;letter-spacing:0.08em;text-transform:uppercase;`;
  title.textContent = `▶ Secure Comm: ${faction.name}`;
  dialog.appendChild(title);

  const responseArea = document.createElement('div');
  responseArea.style.cssText = `
    background: rgba(0,0,0,0.4);
    border: 1px solid rgba(100,140,255,0.15);
    border-radius: 4px;
    padding: 10px 12px;
    font-size: 11px;
    color: #8090b0;
    min-height: 60px;
    margin-bottom: 12px;
    line-height: 1.5;
    white-space: pre-wrap;
  `;
  responseArea.textContent = `[Connecting to ${faction.name} comm relay...]`;
  dialog.appendChild(responseArea);

  const input = document.createElement('textarea');
  input.placeholder = `Message ${faction.name}...`;
  input.rows = 2;
  input.style.cssText = `
    width: 100%;
    background: rgba(20,30,60,0.8);
    border: 1px solid rgba(100,140,255,0.2);
    border-radius: 4px;
    padding: 8px 10px;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    color: #c0d0f0;
    resize: none;
    margin-bottom: 10px;
    box-sizing: border-box;
  `;
  dialog.appendChild(input);

  const btnRow = document.createElement('div');
  btnRow.style.cssText = 'display:flex;gap:8px;justify-content:flex-end;';

  const cancelBtn = document.createElement('button');
  cancelBtn.textContent = 'Close';
  cancelBtn.style.cssText = `
    padding: 5px 14px;
    background: none;
    border: 1px solid rgba(80,90,130,0.4);
    border-radius: 4px;
    color: #4a5568;
    cursor: pointer;
    font-family: 'Courier New', monospace;
    font-size: 11px;
  `;
  cancelBtn.onclick = () => overlay.remove();

  const sendBtn = document.createElement('button');
  sendBtn.textContent = 'Send ▶';
  sendBtn.style.cssText = `
    padding: 5px 14px;
    background: rgba(40,50,120,0.7);
    border: 1px solid ${faction.color}55;
    border-radius: 4px;
    color: ${faction.color};
    cursor: pointer;
    font-family: 'Courier New', monospace;
    font-size: 11px;
  `;

  sendBtn.onclick = async () => {
    const msg = input.value.trim();
    if (!msg) return;
    sendBtn.disabled = true;
    sendBtn.textContent = '...';
    responseArea.textContent = `[${faction.name} is responding...]`;
    try {
      const reply = await contactFaction(def.personality, msg, faction.disposition);
      responseArea.textContent = reply;
    } catch {
      responseArea.textContent = '[Transmission lost. Retry later.]';
    } finally {
      sendBtn.disabled = false;
      sendBtn.textContent = 'Send ▶';
    }
  };

  btnRow.appendChild(cancelBtn);
  btnRow.appendChild(sendBtn);
  dialog.appendChild(btnRow);

  overlay.appendChild(dialog);
  overlay.addEventListener('click', (e) => {
    if (e.target === overlay) overlay.remove();
  });
  document.body.appendChild(overlay);
  input.focus();
}
