import { AmbientLight, Color, DirectionalLight, Vector3 } from 'three';
import { getBeltRegion, BELT_REGION_BOUNDARIES, type BeltRegion } from '../shared/beltRegions';
import { BELT_REGION_VISUALS, type BeltRegionVisual } from './beltRegionVisuals';
import type { ParallaxSkybox } from './background/ParallaxSkybox';

/** Radius over which we blend between adjacent regions */
const TRANSITION_RADIUS = 2000;

/** Lerp factor per frame — smooths rapid camera movement */
const LERP_SPEED = 0.04;

/**
 * BeltRegionRenderer — updates scene lighting and skybox tint based on
 * the camera's radial position in the asteroid belt.
 *
 * Per-region visuals from BELT_REGIONS.md (MUL-1265):
 *  - Kindling Ring:      warm amber, dusty orange
 *  - Shardfall Gap:      silver-grey, cold blue
 *  - Consortium Fields:  grey-silver metallic
 *  - Pale Meridian:      cool blue-white, pale cyan
 *  - Veil Reach:         deep blue-violet, teal
 *  - The Forgetting:     near-black, deep violet
 */
export class BeltRegionRenderer {
  private ambientLight: AmbientLight;
  private sunLight: DirectionalLight;
  private skybox: ParallaxSkybox;

  // Current blended values (interpolated each frame)
  private currentAmbientColor = new Color(0.20, 0.20, 0.28);
  private currentAmbientIntensity = 0.8;
  private currentNebulaTint = new Color(0.10, 0.05, 0.18);
  private currentNebulaStrength = 0.40;
  private _currentAsteroidBias = new Color(0.5, 0.45, 0.4);
  private _currentAsteroidBiasStrength = 0.15;

  // Target values from region config
  private targetAmbientColor = new Color();
  private targetNebulaTint = new Color();

  // Scratch Color instances to avoid per-frame allocations
  private readonly _scratchA = new Color();
  private readonly _scratchB = new Color();

  constructor(
    ambientLight: AmbientLight,
    sunLight: DirectionalLight,
    skybox: ParallaxSkybox,
  ) {
    this.ambientLight = ambientLight;
    this.sunLight = sunLight;
    this.skybox = skybox;
  }

  /**
   * Call once per frame with the camera's world position.
   */
  update(cameraPosition: Vector3): void {
    const radialDist = Math.sqrt(
      cameraPosition.x * cameraPosition.x + cameraPosition.z * cameraPosition.z,
    );

    const visual = this._blendedVisualAt(radialDist);

    // Compute targets
    this.targetAmbientColor.setRGB(
      visual.ambientColor[0],
      visual.ambientColor[1],
      visual.ambientColor[2],
    );
    this.targetNebulaTint.setRGB(
      visual.nebulaTint[0],
      visual.nebulaTint[1],
      visual.nebulaTint[2],
    );

    // Smooth interpolation toward targets
    this.currentAmbientColor.lerp(this.targetAmbientColor, LERP_SPEED);
    this.currentAmbientIntensity +=
      (visual.ambientIntensity - this.currentAmbientIntensity) * LERP_SPEED;
    this.currentNebulaTint.lerp(this.targetNebulaTint, LERP_SPEED);
    this.currentNebulaStrength +=
      (visual.nebulaStrength - this.currentNebulaStrength) * LERP_SPEED;

    this._currentAsteroidBias.setRGB(
      visual.asteroidColorBias[0],
      visual.asteroidColorBias[1],
      visual.asteroidColorBias[2],
    );
    this._currentAsteroidBiasStrength = visual.asteroidBiasStrength;

    // Apply to scene
    this.ambientLight.color.copy(this.currentAmbientColor);
    this.ambientLight.intensity = this.currentAmbientIntensity;

    // Tint the sun based on region warmth (inner = warm, outer = cold)
    this._applyRegionalSunTint(visual);

    // Apply to skybox
    this.skybox.setNebulaTint(
      this.currentNebulaTint.r,
      this.currentNebulaTint.g,
      this.currentNebulaTint.b,
      this.currentNebulaStrength,
    );
  }

  /** Current asteroid color bias — read by InstancedAsteroidRenderer */
  get asteroidBiasColor(): Color {
    return this._currentAsteroidBias;
  }

  /** Current asteroid bias strength 0–1 */
  get asteroidBiasStrength(): number {
    return this._currentAsteroidBiasStrength;
  }

  /**
   * Returns a blended BeltRegionVisual by interpolating between two adjacent
   * regions when the camera is within TRANSITION_RADIUS of a boundary.
   */
  private _blendedVisualAt(radialDist: number): BeltRegionVisual {
    const region = getBeltRegion(radialDist);
    const visual = BELT_REGION_VISUALS[region];

    // Find nearest boundary and check if we should blend
    for (const [boundary] of BELT_REGION_BOUNDARIES) {
      const distToBoundary = Math.abs(radialDist - boundary);
      if (distToBoundary < TRANSITION_RADIUS && boundary !== Infinity) {
        const t = distToBoundary / TRANSITION_RADIUS; // 0 = at boundary, 1 = far
        // Determine which side of boundary we're on
        const innerDist = radialDist < boundary ? radialDist : radialDist - TRANSITION_RADIUS * 2;
        const outerDist = radialDist >= boundary ? radialDist : radialDist + TRANSITION_RADIUS * 2;
        const nearRegion = getBeltRegion(innerDist);
        const farRegion = getBeltRegion(outerDist);
        if (nearRegion === farRegion) continue; // same region either side

        // Blend: t=0 means 50/50, t=1 means fully in current region
        const alpha = radialDist < boundary ? 0.5 + t * 0.5 : 0.5 - t * 0.5;
        return this._blend(BELT_REGION_VISUALS[nearRegion], BELT_REGION_VISUALS[farRegion], alpha);
      }
    }

    return visual;
  }

  /** Linear blend between two region visuals */
  private _blend(a: BeltRegionVisual, b: BeltRegionVisual, t: number): BeltRegionVisual {
    const lerp = (x: number, y: number) => x * t + y * (1 - t); // t=1→a, t=0→b
    return {
      name: a.name,
      ambientColor: [
        lerp(a.ambientColor[0], b.ambientColor[0]),
        lerp(a.ambientColor[1], b.ambientColor[1]),
        lerp(a.ambientColor[2], b.ambientColor[2]),
      ],
      ambientIntensity: lerp(a.ambientIntensity, b.ambientIntensity),
      nebulaTint: [
        lerp(a.nebulaTint[0], b.nebulaTint[0]),
        lerp(a.nebulaTint[1], b.nebulaTint[1]),
        lerp(a.nebulaTint[2], b.nebulaTint[2]),
      ],
      nebulaStrength: lerp(a.nebulaStrength, b.nebulaStrength),
      asteroidColorBias: [
        lerp(a.asteroidColorBias[0], b.asteroidColorBias[0]),
        lerp(a.asteroidColorBias[1], b.asteroidColorBias[1]),
        lerp(a.asteroidColorBias[2], b.asteroidColorBias[2]),
      ],
      asteroidBiasStrength: lerp(a.asteroidBiasStrength, b.asteroidBiasStrength),
    };
  }

  /** Shift sun directional light color slightly toward warm/cool per region */
  private _applyRegionalSunTint(visual: BeltRegionVisual): void {
    // Warm regions get a slightly warmer sun, cold regions get cooler
    const warmth = visual.ambientColor[0] - visual.ambientColor[2]; // r - b
    const sunR = 1.0;
    const sunG = 0.96 - warmth * 0.04;
    const sunB = 0.88 + warmth * 0.10;
    // Only apply subtle shift — avoid jarring changes
    this._scratchA.setRGB(sunR, Math.max(0.85, sunG), Math.max(0.75, sunB));
    this.sunLight.color.lerp(this._scratchA, LERP_SPEED * 0.5);
  }
}
