/**
 * Renders translucent territory rings around faction bases in the 3D scene.
 *
 * Each faction gets a ring on the XZ plane at y=0 showing their territory
 * radius. The ring is a thin torus with low opacity — visible enough to see
 * boundaries without cluttering the view.
 */
import {
  Color,
  Mesh,
  MeshBasicMaterial,
  RingGeometry,
  Scene,
} from 'three';

const MAX_FACTIONS = 4;
/** Ring thickness as a fraction of the territory radius. */
const RING_THICKNESS_FRAC = 0.012;
/** Minimum ring thickness in world units. */
const MIN_RING_THICKNESS = 40;

export interface TerritoryZone {
  x: number;
  z: number;
  radius: number;
  color: string;
}

export class TerritoryZoneRenderer {
  private scene: Scene;
  private rings: Mesh[] = [];
  private materials: MeshBasicMaterial[] = [];
  private prevZones: string = '';

  constructor(scene: Scene) {
    this.scene = scene;

    for (let i = 0; i < MAX_FACTIONS; i++) {
      const mat = new MeshBasicMaterial({
        color: 0xff0000,
        transparent: true,
        opacity: 0.12,
        depthWrite: false,
      });
      // Placeholder geometry — will be rebuilt when zones change
      const geo = new RingGeometry(1, 2, 64);
      const mesh = new Mesh(geo, mat);
      mesh.rotation.x = -Math.PI / 2; // lay flat on XZ plane
      mesh.visible = false;
      scene.add(mesh);
      this.rings.push(mesh);
      this.materials.push(mat);
    }
  }

  update(zones: TerritoryZone[]): void {
    // Quick fingerprint to avoid rebuilding geometry every frame
    const fingerprint = zones.map((z) => `${z.x},${z.z},${z.radius},${z.color}`).join('|');
    const changed = fingerprint !== this.prevZones;
    if (changed) this.prevZones = fingerprint;

    for (let i = 0; i < MAX_FACTIONS; i++) {
      const mesh = this.rings[i];
      const mat = this.materials[i];

      if (i >= zones.length) {
        mesh.visible = false;
        continue;
      }

      const zone = zones[i];

      if (changed) {
        // Rebuild geometry for this ring
        const thickness = Math.max(zone.radius * RING_THICKNESS_FRAC, MIN_RING_THICKNESS);
        const innerRadius = zone.radius - thickness;
        const outerRadius = zone.radius;
        mesh.geometry.dispose();
        mesh.geometry = new RingGeometry(innerRadius, outerRadius, 64);
        mat.color.set(new Color(zone.color));
        mesh.position.set(zone.x, 0, zone.z);
      }

      mesh.visible = true;
    }
  }

  dispose(): void {
    for (const mesh of this.rings) {
      this.scene.remove(mesh);
      mesh.geometry.dispose();
      (mesh.material as MeshBasicMaterial).dispose();
    }
  }
}
