/**
 * Handler for sim:transit_state worker broadcasts.
 * Stores the transit snapshot in GameRefs and updates the System Map panel.
 */
import type { WorkerToMainMessage, SimTransitStateMessage } from '../sim/messages';
import type { HandlerMap } from './types';
import type { GameRefs } from '../gameRuntimeState';
import { updateTransitSnapshot } from '../ui/systemMapPanel';

export function registerTransitHandlers(refs: GameRefs): HandlerMap {
  return {
    'sim:transit_state': (msg: WorkerToMainMessage) => {
      const payload = (msg as SimTransitStateMessage).payload;
      refs.latestTransitSnapshot = payload;
      updateTransitSnapshot(payload);
    },
  };
}
