/**
 * Entry point — orchestrates renderer init, worker setup, panel wiring, and
 * the render loop. All heavy logic lives in the extracted subsystem modules:
 *   - src/rendererInit.ts  — Three.js renderer and instanced mesh creation
 *   - src/workerMessages.ts — sim worker → main thread message dispatch
 *   - src/inputHandlers.ts  — keyboard / mouse / touch handling
 *   - src/gameRuntimeState.ts — shared mutable runtime state
 */

import * as Sentry from '@sentry/browser';

import {
  start as startGameLoop,
  getDiagnostics,
  setRenderErrorHandler,
  isPaused as isGamePaused,
} from './core/gameLoop';
import { updateHUD, updateResourceHUD, initHomeButton, updateGameClock, initObjectiveWidget, initBuildGuidanceHint, initSpeedControl, resetSpeed, setSpeed } from './ui/hud';
import { initBugReport } from './ui/bugReport';
import { showNotification } from './ui/notifications';
import { initCodex } from './ui/codexPanel';
import { initArchivesPanel } from './ui/archivesPanel';
import { initCommandersLogPanel, addAriaLogEntry } from './ui/commandersLogPanel';
import { initEventLogPanel } from './ui/eventLogPanel';
import { initTechTreePanel } from './ui/techTreePanel';
import { initAutomationPanel } from './ui/automationPanel';
import { initMaterialPriorityPanel } from './ui/materialPriorityPanel';
import { initBlueprintPanel } from './ui/blueprintPanel';
import { initBuildPanel } from './ui/buildPanel';
import { initBaseBuildingsPanel } from './ui/baseBuildingsPanel';
import { initLogisticsPanel } from './ui/logisticsPanel';
import { initMarketPanel } from './ui/marketPanel';
import { initSystemMapPanel } from './ui/systemMapPanel';
import { initPauseMenu, maybeShowLoadScreen, showTitleScreen } from './ui/pauseMenu';
import { initShipPanel } from './ui/shipPanel';
import { shouldShowTutorial, initTutorial, onTutorialStepShown } from './ui/tutorial';
import { setLoadingStage, hideLoadingScreen } from './ui/loadingScreen';
import { applyTouchDeviceClass } from './ui/touchHints';
import { initMinimap, updateMinimapCamera, renderMinimap } from './ui/minimap';
import { initKeybindingHelp } from './ui/keybindingHelp';
import { initSettingsPanel, showSettingsPanel } from './ui/settingsPanel';
import { resetMilestones } from './ui/milestones';
import { resetColonyNameModalState } from './ui/colonyNameModal';
import { resetColonyEpithetModalState } from './ui/colonyEpithetModal';
import type { HaulRoute } from './sim/logistics';
import type { SaveData, SaveSlot } from './sim/saveLoad';
import { readLegacy } from './sim/legacy';
import { getRobotEid, getRobotX, getRobotY, getRobotZ, getRobotState } from './sim/bufferLayout';
import { audioEngine } from './audio/audioEngine';

import { discoveries, storageValues, createGameRefs } from './gameRuntimeState';
import { startSession, endSession, resetAnalytics, trackAriaUsage } from './analytics';
import { startVersionCheck } from './versionCheck';
import { setAwaySendFn, startAwayTracking } from './advisor/awayEvents';

import { initRenderers } from './rendererInit';
import { setupWorkerMessages } from './workerMessages';
import type { LazyPanelHandles } from './workerMessages';
import { initInputHandlers } from './inputHandlers';
import { initSupportPrompt, recordAdvisorUsage } from './ui/supportPrompt';
import { AchievementService, AchievementNotification, ACHIEVEMENT } from './achievements';
import { initEchoDelivery, setAriaDialogueActive } from './beltEchoes';

/** Generate a random 6-digit seed for new games. */
function randomSeed(): number {
  return Math.floor(Math.random() * 1_000_000);
}

let gameSeed = 42;

async function main(): Promise<void> {
  // Bail on unsupported devices (mobile / no WebGL) — flag set by index.html gate
  if ((window as unknown as { __unsupported?: boolean }).__unsupported) return;

  const canvas = document.getElementById('game-canvas') as HTMLCanvasElement;
  if (!canvas) {
    console.error('Canvas element not found');
    return;
  }

  setLoadingStage(0);
  const renderers = await initRenderers(canvas);
  const {
    camera, composer, bloomPass, cameraRig,
    baseX, baseZ,
    asteroidRenderer, robotRenderer, threatRenderer, skybox, beltRegionRenderer,
    particles, miningParticles, depletionParticles, thrusterParticles,
    baseStation, extraBaseRenderers,
    buildingRenderer,
    megastructureRenderer,
    namedLocationLabels, claimMarkerRenderer, territoryZoneRenderer,
    followRingMesh, followRingMat,
    placementGhostMesh, placementGhostMat,
    solarSystemRenderer,
  } = renderers;

  setLoadingStage(1);

  const INITIAL_ZOOM = Math.log(3000);
  const refs = createGameRefs();

  function snapCameraToBase(): void {
    cameraRig.setPivot(baseX, 0, baseZ);
    cameraRig.setZoom(INITIAL_ZOOM);
    if (refs.followedRobotEid !== null) input.stopFollow();
  }

  function enterBasePlacementMode(): void {
    refs.isPlacingBase = true;
    showNotification('Click to place outpost — Esc or right-click to cancel', '#22d3ee');
    placementGhostMat.opacity = 0.6;
    canvas.style.cursor = 'crosshair';
  }

  function exitBasePlacementMode(): void {
    refs.isPlacingBase = false;
    placementGhostMat.opacity = 0;
    canvas.style.cursor = '';
  }

  // ── Lazy-loaded panel modules ────────────────────────────────────────────

  type DashboardMod = typeof import('./ui/dashboard');
  type FactionPanelMod = typeof import('./ui/factionPanel');
  type MegaPanelMod = typeof import('./ui/megastructurePanel');
  type AdvisorMod = {
    panel: typeof import('./ui/advisorPanel') & { toggleAdvisorPanel: () => void };
    service: typeof import('./advisor/advisorService');
    gameState: typeof import('./advisor/gameState');
    commander: typeof import('./advisor/commanderService');
    inbox: typeof import('./advisor/commanderInbox');
    delegate: typeof import('./advisor/commanderDelegate');
    autoAnalysis: typeof import('./advisor/ariaAutoAnalysis');
  };

  let _dashboard: DashboardMod | null = null;
  let _dashboardLoading: Promise<DashboardMod> | null = null;
  let _dashboardInitialized = false;
  let _factionPanel: FactionPanelMod | null = null;
  let _factionInitialized = false;
  let _megaPanel: MegaPanelMod | null = null;
  let _megaInitialized = false;
  let _advisor: AdvisorMod | null = null;
  let _advisorLoading: Promise<AdvisorMod> | null = null;
  let _advisorInitialized = false;

  function loadDashboard(): Promise<DashboardMod> {
    if (!_dashboardLoading) {
      _dashboardLoading = import('./ui/dashboard')
        .then((m) => { _dashboard = m; return m; })
        .catch((err: unknown) => {
          _dashboardLoading = null;
          showNotification('[ARIA] Dashboard failed to load — press D to retry', '#ef4444');
          console.error('[main] Failed to load dashboard:', err);
          return Promise.reject(err) as Promise<DashboardMod>;
        });
    }
    return _dashboardLoading;
  }

  function initDashboardOnce(m: DashboardMod): void {
    if (_dashboardInitialized) return;
    _dashboardInitialized = true;
    m.initDashboard(
      (x: number, y: number, z: number) => {
        cameraRig.panTo(x, y, z, 800);
        if (refs.followedRobotEid !== null) input.stopFollow();
        m.toggleDashboard();
      },
      (x: number, z: number) => {
        cameraRig.setPivot(x, 0, z);
        m.toggleDashboard();
      },
    );
  }

  function loadFactionPanel(): Promise<FactionPanelMod> {
    return import('./ui/factionPanel')
      .then((m) => { _factionPanel = m; return m; })
      .catch((err: unknown) => {
        showNotification('[ARIA] Faction panel failed to load — try again', '#ef4444');
        console.error('[main] Failed to load faction panel:', err);
        return Promise.reject(err) as Promise<FactionPanelMod>;
      });
  }

  function initFactionOnce(m: FactionPanelMod): void {
    if (_factionInitialized) return;
    _factionInitialized = true;
    m.initFactionPanel((factionId, action) => {
      worker.postMessage({ type: 'sim:faction_diplomacy', payload: { factionId, action } });
    });
  }

  function loadMegaPanel(): Promise<MegaPanelMod> {
    return import('./ui/megastructurePanel')
      .then((m) => { _megaPanel = m; return m; })
      .catch((err: unknown) => {
        showNotification('[ARIA] Megastructure panel failed to load — try again', '#ef4444');
        console.error('[main] Failed to load megastructure panel:', err);
        return Promise.reject(err) as Promise<MegaPanelMod>;
      });
  }

  function initMegaOnce(m: MegaPanelMod): void {
    if (_megaInitialized) return;
    _megaInitialized = true;
    m.initMegastructurePanel({
      onStartStage: (id, stageIndex) => worker.postMessage({ type: 'sim:start_megastructure_stage', payload: { id, stageIndex } }),
      onResolveCrisis: (id) => worker.postMessage({ type: 'sim:resolve_megastructure_crisis', payload: { id } }),
      onSkipCrisis: (id) => worker.postMessage({ type: 'sim:skip_megastructure_crisis', payload: { id } }),
    });
  }

  function loadAdvisorLazy(): Promise<AdvisorMod> {
    if (!_advisorLoading) {
      _advisorLoading = Promise.all([
        import('./ui/advisorPanel'),
        import('./advisor/advisorService'),
        import('./advisor/gameState'),
        import('./advisor/commanderService'),
        import('./advisor/commanderInbox'),
        import('./advisor/commanderDelegate'),
        import('./advisor/ariaAutoAnalysis'),
      ])
        .then(([panel, service, gameState, commander, inbox, delegate, autoAnalysis]) => { _advisor = { panel, service, gameState, commander, inbox, delegate, autoAnalysis }; return _advisor; })
        .catch((err: unknown) => {
          _advisorLoading = null;
          showNotification('[ARIA] Advisor panel failed to load — try again', '#ef4444');
          console.error('[main] Failed to load advisor:', err);
          return Promise.reject(err) as Promise<AdvisorMod>;
        });
    }
    return _advisorLoading;
  }

  function buildCurrentGameState(m: AdvisorMod): import('./advisor/gameState').GameStateSummary {
    return m.gameState.buildGameState(
      storageValues,
      refs.latestRobotBuffer,
      refs.latestRobotCount,
      refs.latestAsteroidBuffer,
      refs.latestAsteroidCount,
      discoveries,
      refs.latestTick,
      refs.latestBuildings,
      {
        refined: refs.latestRefined,
        techState: refs.latestTechState,
        factoryQueueLength: refs.latestFactoryQueueLength,
        robotCap: refs.latestRobotCap,
        megastructureProjects: refs.latestMegaProjects,
        factionStandings: refs.latestFactionSnapshots.map((f) => ({
          name: f.name,
          disposition: f.disposition,
          label: f.dispositionLabel,
          trend: f.dispositionDelta > 0 ? 'improving' as const : f.dispositionDelta < 0 ? 'worsening' as const : 'stable' as const,
        })),
      },
    );
  }

  function initAdvisorOnce(m: AdvisorMod): void {
    if (_advisorInitialized) return;
    _advisorInitialized = true;
    const { panel, service, commander, inbox, delegate, autoAnalysis } = m;
    panel.initAdvisorPanel();
    // Open the advisor automatically when the tutorial reaches the ARIA step
    // so new players experience the onboarding guidance without having to discover the panel.
    onTutorialStepShown('aria', () => panel.toggleAdvisorPanel());
    panel.setCurrentProvider(service.getProvider());
    panel.setApiKeyStatus(service.hasApiKey());
    panel.onProviderSet((p) => {
      service.setProvider(p as import('./advisor/advisorService').LlmProvider);
      panel.setCurrentProvider(p);
    });
    panel.onApiKeySet((key) => {
      service.saveApiKey(key);
      panel.setApiKeyStatus(service.hasApiKey());
      panel.removeOfflineBanner();
      panel.removeAuthErrorBanner();
      commander.setCommanderApiKey(key);
      inbox.setInboxApiKey(key);
    });

    // Wire Commander to sim worker
    commander.setCommanderWorkerSend((msg) => worker.postMessage(msg));
    commander.setCommanderApiKey(service.getApiKey());
    inbox.setInboxApiKey(service.getApiKey());

    // Wire auto-delegation
    delegate.setDelegationWorkerSend((msg) => worker.postMessage(msg));
    delegate.setDelegationBuildState(() => buildCurrentGameState(m));

    // Wire ARIA auto-analysis
    autoAnalysis.setAutoAnalysisWorkerSend((msg) => worker.postMessage(msg));
    autoAnalysis.setAutoAnalysisBuildState(() => buildCurrentGameState(m));
    autoAnalysis.setAutoAnalysisIsPaused(() => isGamePaused());
    autoAnalysis.setAutoAnalysisInboxSnapshot(() => refs.latestInboxSnapshot);
    autoAnalysis.startAutoAnalysis();
    delegate.onPendingActionsChange((actions) => {
      panel.updatePendingActions(actions);
    });

    // Commander toggle
    panel.onCommanderToggle((enabled: boolean) => {
      commander.setCommanderEnabled(enabled);
    });

    // Delegation toggle
    panel.onDelegationToggle((enabled: boolean) => {
      delegate.setDelegationEnabled(enabled);
    });

    // Pending action approve/reject
    panel.onPendingActionApprove((id: number) => delegate.approveAction(id));
    panel.onPendingActionReject((id: number) => delegate.rejectAction(id));
    panel.onPendingActionApproveAll(() => delegate.approveAllActions());
    panel.onPendingActionRejectAll(() => delegate.rejectAllActions());

    // Inline trade offer accept/decline
    panel.onTradeOfferResponse((factionId, response) => {
      worker.postMessage({
        type: 'sim:trade_window_response',
        payload: { factionId, response },
      });
    });

    /** Check auth error state after an advisor call and update UI accordingly. */
    function syncAuthErrorUI(): void {
      if (service.isAuthError()) {
        panel.setApiKeyStatus(service.hasApiKey(), true);
        panel.showAuthErrorBanner();
      }
    }

    panel.onPlayerSubmit(async (text: string) => {
      trackAriaUsage();
      recordAdvisorUsage();
      autoAnalysis.recordPlayerInteraction(refs.latestTick ?? 0);
      // Block manual Commander queries while auto-delegation is capturing
      if (delegate.isCapturing()) {
        panel.addAdvisorMessage('Auto-delegation in progress — please wait a moment.');
        return;
      }
      panel.setLoading(true);
      setAriaDialogueActive(true);
      const state = buildCurrentGameState(m);

      if (commander.isCommanderEnabled()) {
        const result = await commander.askCommander(text, state);
        let response = result.explanation;
        if (result.actions.length > 0) {
          response += '\n\n**Actions taken:**\n' + result.actions.map((a) => `• ${a}`).join('\n');
        }
        if (result.error) {
          response += `\n\n⚠ ${result.error}`;
        }
        panel.addAdvisorMessage(response);
      } else {
        const response = await service.askAdvisor(text, state);
        panel.addAdvisorMessage(response);
      }
      syncAuthErrorUI();
      panel.setLoading(false);
      setAriaDialogueActive(false);
    });
  }

  const lazy: LazyPanelHandles = {
    getDashboard: () => _dashboard,
    getFactionPanel: () => _factionPanel,
    getMegaPanel: () => _megaPanel,
    getAdvisor: () => _advisor,
    loadDashboard,
    initDashboardOnce,
    loadFactionPanel,
    initFactionOnce,
    loadMegaPanel,
    initMegaOnce,
    loadAdvisorLazy,
    initAdvisorOnce,
  };

  function schedulePreloads(): void {
    const idle = (cb: () => void): void => {
      if ('requestIdleCallback' in window) {
        window.requestIdleCallback(cb, { timeout: 3000 });
      } else {
        setTimeout(cb, 1000);
      }
    };
    void loadDashboard().then(initDashboardOnce).catch((err) => {
      console.error('[main] Failed to preload dashboard:', err);
    });
    idle(() => void loadFactionPanel().then(initFactionOnce).catch((err) => {
      console.error('[main] Failed to preload faction panel:', err);
    }));
    idle(() => void loadMegaPanel().then(initMegaOnce).catch((err) => {
      console.error('[main] Failed to preload megastructure panel:', err);
    }));
    idle(() => void loadAdvisorLazy().then(initAdvisorOnce).catch((err) => {
      console.error('[main] Failed to preload advisor panel:', err);
    }));
  }

  // ── UI init ───────────────────────────────────────────────────────────────

  applyTouchDeviceClass();
  initMinimap((wx, wz) => cameraRig.panTo(wx, 0, wz, 800));
  initKeybindingHelp();
  initHomeButton(snapCameraToBase);
  initSpeedControl((multiplier) => {
    refs.speedMultiplier = multiplier;
    worker.postMessage({ type: 'sim:set_speed', payload: { multiplier } });
  });
  initObjectiveWidget();
  initBuildGuidanceHint();
  initBugReport();

  let autoSaveTimer: ReturnType<typeof setInterval>;
  const initialSettings = initSettingsPanel((s) => {
    bloomPass.strength = s.bloomIntensity;
    particles.setDensity(s.particleDensity);
    clearInterval(autoSaveTimer);
    autoSaveTimer = setInterval(() => requestSave('auto'), s.autoSaveIntervalMin * 60_000);
  });
  bloomPass.strength = initialSettings.bloomIntensity;
  particles.setDensity(initialSettings.particleDensity);

  initCodex();
  initArchivesPanel();
  initCommandersLogPanel();
  initEventLogPanel();

  setLoadingStage(2);

  // ── Worker + panel init ───────────────────────────────────────────────────

  const worker = new Worker(new URL('./sim/worker.ts', import.meta.url), { type: 'module' });

  // ARIA away-event tracking (accumulates events while tab hidden, posts summary on return)
  setAwaySendFn((msg) => worker.postMessage(msg));
  startAwayTracking();

  initTechTreePanel((nodeId: string) => worker.postMessage({ type: 'sim:start_research', payload: { nodeId } }));
  initAutomationPanel((msg) => worker.postMessage(msg));
  initMaterialPriorityPanel((msg) => worker.postMessage(msg));
  initBlueprintPanel((msg) => worker.postMessage(msg));
  initBuildPanel((msg) => worker.postMessage(msg));
  initBaseBuildingsPanel((msg) => worker.postMessage(msg));

  initLogisticsPanel(
    () => enterBasePlacementMode(),
    (route: HaulRoute) => worker.postMessage({ type: 'sim:upsert_route', payload: route }),
    (id: string) => worker.postMessage({ type: 'sim:delete_route', payload: { id } }),
  );

  initMarketPanel(
    (resource, quantity, buyerFactionId) =>
      worker.postMessage({ type: 'sim:market_create_listing', payload: { resource, quantity, buyerFactionId } }),
    (listingId) =>
      worker.postMessage({ type: 'sim:market_cancel_listing', payload: { listingId } }),
  );

  initSystemMapPanel((destinationId: string) => {
    // Dispatch cargo stub — opens a notification prompting player to use cargo dispatch
    // Full dispatch dialog is a follow-up feature
    showNotification(`Dispatch to ${destinationId} — use cargo dispatch to send resources`, '#22d3ee');
  });

  if (shouldShowTutorial()) initTutorial();

  // ── Input handlers ────────────────────────────────────────────────────────

  // input.startFollow / stopFollow are also consumed by the render loop and ship panel
  const input = initInputHandlers(canvas, worker, refs, renderers, lazy, {
    snapCameraToBase,
    enterBasePlacementMode,
    exitBasePlacementMode,
    requestSave: (slot: SaveSlot) => worker.postMessage({ type: 'sim:save_request', payload: { slot, seed: gameSeed } }),
  });

  initShipPanel({
    onOrder: (robotEid, order) => worker.postMessage({ type: 'sim:robot_order', payload: { robotEid, order } }),
    onRequestDetail: (robotEid) => worker.postMessage({ type: 'sim:robot_detail_request', payload: { robotEid } }),
    onToggleFollow: (robotEid) => {
      if (refs.followedRobotEid === robotEid) input.stopFollow();
      else input.startFollow(robotEid);
    },
    onMineTarget: (robotEid) => input.enterTargetingMode(robotEid),
    onExploreTarget: (robotEid) => input.enterExploreMode(robotEid),
    onClose: () => {},
  });

  // ── Achievement tracking ───────────────────────────────────────────────────

  const achievementService = new AchievementService();
  const achievementNotif = new AchievementNotification();
  achievementService.onUnlock((id) => achievementNotif.show(id));

  // ── Worker message dispatch ───────────────────────────────────────────────

  setupWorkerMessages(worker, refs, renderers, lazy, {
    scheduleIdleHint: input.scheduleIdleHint,
  }, achievementService);

  // ── Belt Echoes init ────────────────────────────────────────────────────
  initEchoDelivery((message) => {
    void lazy.loadAdvisorLazy().then((m) => {
      lazy.initAdvisorOnce(m);
      m.panel.addProactiveBroadcast(message);
    });
  });

  // ── Save / Load ───────────────────────────────────────────────────────────

  function requestSave(slot: SaveSlot): void {
    worker.postMessage({ type: 'sim:save_request', payload: { slot, seed: gameSeed } });
  }

  function loadGame(data: SaveData): void {
    gameSeed = data.seed;
    selectedDifficulty = data.difficultyMode ?? 'normal';
    const savedSpeed = data.speedMultiplier ?? 1;
    refs.speedMultiplier = savedSpeed;
    setSpeed(savedSpeed);
    worker.postMessage({ type: 'sim:set_speed', payload: { multiplier: savedSpeed } });
    worker.postMessage({ type: 'sim:load', payload: { data } });
  }

  let selectedDifficulty: import('./sim/difficulty').DifficultyMode = 'normal';

  initPauseMenu(requestSave, loadGame, () => {}, () => showSettingsPanel(), () => gameSeed, () => selectedDifficulty);

  autoSaveTimer = setInterval(() => requestSave('auto'), initialSettings.autoSaveIntervalMin * 60_000);
  window.addEventListener('beforeunload', () => {
    requestSave('auto');
    endSession();
  });

  // ── Game start / load ─────────────────────────────────────────────────────

  function buildInitPayload(): { seed: number; legacyExpeditionCount?: number; difficultyMode?: import('./sim/difficulty').DifficultyMode } {
    const legacy = readLegacy();
    const count = legacy?.expeditionCount ?? 0;
    const base: { seed: number; legacyExpeditionCount?: number; difficultyMode?: import('./sim/difficulty').DifficultyMode } = { seed: gameSeed };
    if (count > 0) base.legacyExpeditionCount = count;
    if (selectedDifficulty !== 'normal') base.difficultyMode = selectedDifficulty;
    return base;
  }

  function startNewGame(customSeed?: number, difficulty?: import('./sim/difficulty').DifficultyMode): void {
    gameSeed = customSeed ?? randomSeed();
    selectedDifficulty = difficulty ?? 'normal';
    refs.pendingFirstLaunch = shouldShowTutorial();
    resetColonyNameModalState();
    resetColonyEpithetModalState();
    resetAnalytics();
    startSession();
    refs.speedMultiplier = 1;
    resetSpeed();
    worker.postMessage({ type: 'sim:set_speed', payload: { multiplier: 1 } });
    worker.postMessage({ type: 'sim:init', payload: buildInitPayload() });
  }

  hideLoadingScreen();
  startVersionCheck();
  initSupportPrompt();

  maybeShowLoadScreen(
    (data: SaveData) => {
      gameSeed = data.seed;
      startSession();
      cameraRig.setPivot(data.base.x, data.base.y, data.base.z);
      const now = Date.now();
      void Promise.all([import('./sim/offlineSim'), import('./ui/morningReport')]).then(
        ([offlineMod, morningMod]) => {
          if (offlineMod.shouldShowMorningReport(data, now)) {
            const offlineResult = offlineMod.computeOfflineProgress(data, now);
            data.timestamp = now;
            worker.postMessage({ type: 'sim:init', payload: buildInitPayload() });
            refs.pendingLoad = data;
            // Append morning report summary to Commander's Log
            const totalOre = Object.values(offlineResult.resourcesGained).reduce((s, n) => s + n, 0);
            const parts: string[] = [`[Morning Report] Fleet operated autonomously for ${offlineResult.elapsedLabel}.`];
            if (totalOre > 0) parts.push(`Resources gathered: ~${Math.round(totalOre)} units.`);
            if (offlineResult.researchGained > 0) parts.push(`Research accumulated: ${Math.round(offlineResult.researchGained)} points.`);
            if (offlineResult.anomaliesFound > 0) parts.push(`Anomalies flagged: ${offlineResult.anomaliesFound}.`);
            addAriaLogEntry(parts.join(' '));
            setTimeout(() => morningMod.showMorningReport(offlineResult, () => {}), 800);
          } else {
            worker.postMessage({ type: 'sim:init', payload: buildInitPayload() });
            refs.pendingLoad = data;
          }
        },
      ).catch((err: unknown) => {
        console.error('[main] Failed to load offline sim modules, loading save directly:', err);
        showNotification('[ARIA] Morning report unavailable — loading save directly', '#f59e0b');
        worker.postMessage({ type: 'sim:init', payload: buildInitPayload() });
        refs.pendingLoad = data;
      });
    },
    () => {
      resetMilestones();
      showTitleScreen((customSeed, difficulty) => startNewGame(customSeed, difficulty), () => showSettingsPanel());
    },
  );

  schedulePreloads();

  setRenderErrorHandler((err) => {
    showNotification('[ARIA] Render error — check console', '#ef4444');
    console.error('[main] Render error:', err);
  });

  // ── Render loop ───────────────────────────────────────────────────────────

  startGameLoop({
    onFixedUpdate: (dt: number) => {
      refs.elapsed += dt;
    },
    onRender: (_alpha: number) => {
      const diag = getDiagnostics();

      cameraRig.update(1 / 60);
      const camState = cameraRig.getState();

      beltRegionRenderer.update(camera.position);
      asteroidRenderer.setRegionBias(
        beltRegionRenderer.asteroidBiasColor,
        beltRegionRenderer.asteroidBiasStrength,
      );
      skybox.update(camera.position, refs.elapsed);
      solarSystemRenderer.update(camera.position);
      particles.update(camera.position, camState.zoomDistance, refs.elapsed);
      baseStation.update(refs.elapsed);
      baseStation.updateGrowth(refs.latestBuildings);
      for (const ebr of extraBaseRenderers) ebr.update(refs.elapsed);
      buildingRenderer.update(refs.latestBuildings, refs.elapsed);
      megastructureRenderer.update(refs.latestMegaProjects, refs.elapsed, refs.latestHabitatState);

      if (refs.latestAsteroidBuffer && refs.latestAsteroidCount > 0) {
        asteroidRenderer.updateFromBuffer(refs.latestAsteroidBuffer, refs.latestAsteroidCount, camera.position);
        // Spawn debris bursts for newly depleted asteroids
        for (const dep of asteroidRenderer.getNewDepletions()) {
          depletionParticles.spawn(dep.x, dep.y, dep.z, dep.radius, refs.elapsed);
        }
      }
      depletionParticles.update(refs.elapsed);

      threatRenderer.updateFromBuffer(
        refs.latestThreatBuffer ?? new Float32Array(0),
        refs.latestThreatCount,
        refs.elapsed,
      );

      claimMarkerRenderer.update(
        refs.latestAsteroidBuffer,
        refs.latestAsteroidCount,
        refs.factionClaims,
        refs.playerTargetAsteroids,
        refs.elapsed,
      );

      territoryZoneRenderer.update(refs.factionTerritories);

      if (refs.latestRobotBuffer && refs.latestRobotCount > 0) {
        robotRenderer.updateFromBuffer(refs.latestRobotBuffer, refs.latestRobotCount);
        miningParticles.update(refs.latestRobotBuffer, refs.latestRobotCount, refs.elapsed);
        thrusterParticles.update(refs.latestRobotBuffer, refs.latestRobotCount, refs.elapsed);
        audioEngine.setThrusterIntensity(Math.min(1, refs.latestRobotCount / 20));

        // Mining impact audio: count robots in MINING state (2) and play
        // periodic impact sounds proportional to active miners
        {
          let miningCount = 0;
          for (let i = 0; i < refs.latestRobotCount; i++) {
            if (getRobotState(refs.latestRobotBuffer, i) === 2) miningCount++;
          }
          if (miningCount > 0) {
            // Stochastic trigger: ~1 impact every 2s per miner, capped at 3/s
            const chance = Math.min(miningCount * 0.008, 0.05);
            if (Math.random() < chance) audioEngine.playMiningImpact();
          }
        }

        if (refs.followedRobotEid !== null) {
          let found = false;
          for (let i = 0; i < refs.latestRobotCount; i++) {
            if (getRobotEid(refs.latestRobotBuffer, i) === refs.followedRobotEid) {
              const fx = getRobotX(refs.latestRobotBuffer, i);
              const fy = getRobotY(refs.latestRobotBuffer, i);
              const fz = getRobotZ(refs.latestRobotBuffer, i);
              cameraRig.setFollowTarget({ x: fx, y: fy, z: fz } as import('three').Vector3);
              const pulse = 1 + 0.25 * Math.abs(Math.sin(refs.elapsed * 2.5));
              followRingMesh.position.set(fx, fy + 1, fz);
              followRingMesh.scale.setScalar(pulse);
              followRingMat.opacity = 0.55;
              found = true;
              break;
            }
          }
          if (!found) {
            input.stopFollow();
            followRingMat.opacity = 0;
            showNotification('Robot lost — follow mode disabled', '#94a3b8');
          }
        } else {
          followRingMat.opacity = 0;
        }
      } else if (refs.followedRobotEid !== null && (!refs.latestRobotBuffer || refs.latestRobotCount === 0)) {
        input.stopFollow();
        followRingMat.opacity = 0;
      }

      if (refs.isPlacingBase) {
        const ghostPulse = 1 + 0.15 * Math.sin(refs.elapsed * 3);
        placementGhostMesh.scale.setScalar(ghostPulse);
        placementGhostMat.opacity = 0.5 + 0.2 * Math.abs(Math.sin(refs.elapsed * 2));
      }

      _dashboard?.renderDashboard();
      namedLocationLabels.update(camera);

      updateMinimapCamera(camState.pivot.x, camState.pivot.z, camState.zoomDistance);
      renderMinimap(Date.now());

      composer.render();

      updateHUD(
        diag.fps,
        refs.lastStats?.entityCount ?? 0,
        refs.lastStats?.asteroidCount ?? 0,
        refs.lastStats?.robotCount ?? 0,
      );
      updateResourceHUD(storageValues[0], storageValues[5], storageValues[6], storageValues[4]);
      updateGameClock(refs.latestTick);
    },
  });
}

if (import.meta.env.VITE_SENTRY_DSN) {
  Sentry.init({
    dsn: import.meta.env.VITE_SENTRY_DSN,
    environment: import.meta.env.MODE,
    sendDefaultPii: false,
    sampleRate: 1.0,
    beforeSend(event) { delete event.user; return event; },
  });
}

window.addEventListener('error', (e) => Sentry.captureException(e.error));
window.addEventListener('unhandledrejection', (e) => Sentry.captureException(e.reason));

main().catch(console.error);
