/**
 * Ancient Entity System
 *
 * Manages Drifters and Resonants — the cosmic horror elements of the belt.
 *
 * Drifters: massive, slow-moving entities that drift through the asteroid field.
 * Resonants: smaller crystalline entities that appear near studied anomalies.
 *
 * Runs in the sim worker thread. Broadcasts positions for rendering each frame.
 */

import { mulberry32 } from '../prng';

// Re-exported from shared layer for backward compatibility
import { ENTITY_TYPES } from '../../shared/entityTypes';
import type { EntityType, EntityState } from '../../shared/entityTypes';
export { ENTITY_TYPES } from '../../shared/entityTypes';
export type { EntityType, EntityState } from '../../shared/entityTypes';

export interface ProximityEffect {
  /** Entity type causing the effect */
  entityType: EntityType;
  /** Distance from entity centre to nearest robot */
  minRobotDist: number;
  /** Entity position */
  x: number;
  y: number;
  z: number;
}

export interface EntitySystemParams {
  /** Number of active robots (affects resonant spawn rate) */
  robotCount: number;
  /** Number of anomalies at ANALYZED or UNDERSTOOD stage */
  analyzedAnomalyCount: number;
  /** Positions of active robots (for proximity calculations) */
  robotPositions: Array<{ x: number; y: number; z: number }>;
  /** Positions of studied anomalies */
  anomalyPositions: Array<{ x: number; y: number; z: number }>;
  /** Belt outer radius (for spawning drifters at edge) */
  beltOuterRadius: number;
  /** Global tick count */
  tick: number;
  /** Set to true when alien_arrived event flag fires (phase 4) */
  alienArrived?: boolean;
  /** Multiplier on resonant spawn interval (> 1 = slower spawns). Default 1. */
  resonantSpawnMultiplier?: number;
  /** Positions of XENOAWARE robots — suppress Resonant spawns within 500 units. */
  xenoawareRobotPositions?: Array<{ x: number; y: number; z: number }>;
}

// ── Constants ──────────────────────────────────────────────────────────────────

const DRIFTER_RADIUS = 600;
const RESONANT_RADIUS = 40;
const DRIFTER_SPEED = 12; // units/second
const RESONANT_SPEED = 25;
const RESONANT_WANDER = 8; // random wander added to velocity
const DRIFTER_EFFECT_RADIUS = 800; // drifter sensor disruption range
const RESONANT_EFFECT_RADIUS = 350; // resonant mining interference range
const RESONANT_GROUP_SIZE_MIN = 3;
const RESONANT_GROUP_SIZE_MAX = 8;
const ALIEN_FLEET_RADIUS = 3000; // ~3km, massive
const ALIEN_FLEET_SPEED = 6; // slow, deliberate approach
const ALIEN_FLEET_EFFECT_RADIUS = 2000; // sensor overwrite range

// Phase 4: first drifter after tick 28800 (~8 min at 60fps), resonants after ANALYZED
const DRIFTER_MIN_TICK = 28000;
const RESONANT_MIN_TICK = 12000;

// Respawn timers (ticks between spawn opportunities)
const DRIFTER_SPAWN_INTERVAL = 60 * 60 * 8; // ~8 minutes
const RESONANT_SPAWN_INTERVAL = 60 * 60 * 2; // ~2 minutes

let _entityIdCounter = 1;
let _groupIdCounter = 1;
let _rng = mulberry32(0xbadcafe);

function nextId(): number {
  return _entityIdCounter++;
}
function nextGroupId(): number {
  return _groupIdCounter++;
}

export class EntitySystem {
  private entities: Map<number, EntityState> = new Map();
  private drifterSpawnTimer = 0;
  private resonantSpawnTimer = 0;
  private totalDriftersEverSpawned = 0;

  /** Seed the internal RNG (called on init with world seed) */
  seed(worldSeed: number): void {
    _rng = mulberry32(worldSeed ^ 0xbadcafe);
    _entityIdCounter = 1;
    _groupIdCounter = 1;
  }

  get size(): number {
    return this.entities.size;
  }

  getAll(): EntityState[] {
    return Array.from(this.entities.values());
  }

  /**
   * Tick the entity system.
   * Returns proximity effects for the current tick.
   */
  tick(dt: number, params: EntitySystemParams): ProximityEffect[] {
    this.spawnTick(params);
    this.moveTick(dt);
    this.despawnTick(params);
    return this.computeProximityEffects(params);
  }

  // ── Spawning ───────────────────────────────────────────────────────────────

  private spawnTick(params: EntitySystemParams): void {
    const { tick, beltOuterRadius, analyzedAnomalyCount, robotCount, anomalyPositions } = params;

    // Drifters: rare, cap at 2 per game
    if (
      tick >= DRIFTER_MIN_TICK &&
      this.totalDriftersEverSpawned < 2 &&
      this.countType(ENTITY_TYPES.DRIFTER) === 0
    ) {
      this.drifterSpawnTimer++;
      if (this.drifterSpawnTimer >= DRIFTER_SPAWN_INTERVAL) {
        this.drifterSpawnTimer = 0;
        this.spawnDrifter(beltOuterRadius);
      }
    }

    // Alien fleet: spawn once when alien_arrived flag is set
    if (params.alienArrived && this.countType(ENTITY_TYPES.ALIEN_FLEET) === 0) {
      this.spawnAlienFleet(beltOuterRadius);
    }

    // Resonants: spawn near analyzed anomalies when player is active
    if (tick >= RESONANT_MIN_TICK && analyzedAnomalyCount > 0 && robotCount >= 3) {
      this.resonantSpawnTimer++;
      // Spawn rate scales with robot count (more activity = more attention)
      const baseRate = Math.max(1, RESONANT_SPAWN_INTERVAL - robotCount * 200);
      const spawnRate = Math.round(baseRate * (params.resonantSpawnMultiplier ?? 1));
      if (this.resonantSpawnTimer >= spawnRate) {
        this.resonantSpawnTimer = 0;
        if (anomalyPositions.length > 0) {
          // Pick a random analyzed anomaly as the spawn anchor
          const anchor = anomalyPositions[Math.floor(_rng() * anomalyPositions.length)];

          // XENOAWARE: suppress Resonant spawns within 500 units of any XENOAWARE robot
          const xenoPositions = params.xenoawareRobotPositions;
          let suppressed = false;
          if (xenoPositions && xenoPositions.length > 0) {
            const XENOAWARE_SUPPRESSION_RADIUS = 500;
            for (const rp of xenoPositions) {
              const dx = anchor.x - rp.x;
              const dy = anchor.y - rp.y;
              const dz = anchor.z - rp.z;
              if (dx * dx + dy * dy + dz * dz < XENOAWARE_SUPPRESSION_RADIUS * XENOAWARE_SUPPRESSION_RADIUS) {
                suppressed = true;
                break;
              }
            }
          }

          if (!suppressed) {
            this.spawnResonantGroup(anchor.x, anchor.y, anchor.z);
          }
        }
      }
    }
  }

  private spawnDrifter(beltOuterRadius: number): void {
    const angle = _rng() * Math.PI * 2;
    const spawnDist = beltOuterRadius * (0.9 + _rng() * 0.1);
    const x = Math.cos(angle) * spawnDist;
    const z = Math.sin(angle) * spawnDist;
    const y = (_rng() - 0.5) * 400;

    // Drift slowly inward, slightly off-center
    const inwardAngle = angle + Math.PI + (_rng() - 0.5) * 0.4;
    const vx = Math.cos(inwardAngle) * DRIFTER_SPEED;
    const vz = Math.sin(inwardAngle) * DRIFTER_SPEED;
    const vy = (_rng() - 0.5) * 2;

    const entity: EntityState = {
      id: nextId(),
      type: ENTITY_TYPES.DRIFTER,
      x,
      y,
      z,
      vx,
      vy,
      vz,
      radius: DRIFTER_RADIUS * (0.8 + _rng() * 0.4),
      groupId: 0,
      phase: _rng() * Math.PI * 2,
      lifetime: 60 * 60 * 20, // 20 minutes of travel before despawn
    };
    this.entities.set(entity.id, entity);
    this.totalDriftersEverSpawned++;
  }

  private spawnResonantGroup(anchorX: number, anchorY: number, anchorZ: number): void {
    const groupId = nextGroupId();
    const count =
      RESONANT_GROUP_SIZE_MIN +
      Math.floor(_rng() * (RESONANT_GROUP_SIZE_MAX - RESONANT_GROUP_SIZE_MIN + 1));
    const spawnRadius = 200 + _rng() * 300;

    for (let i = 0; i < count; i++) {
      const angle = _rng() * Math.PI * 2;
      const dist = spawnRadius * (0.5 + _rng() * 0.5);
      const x = anchorX + Math.cos(angle) * dist;
      const z = anchorZ + Math.sin(angle) * dist;
      const y = anchorY + (_rng() - 0.5) * 100;

      const vx = (_rng() - 0.5) * RESONANT_SPEED;
      const vy = (_rng() - 0.5) * 5;
      const vz = (_rng() - 0.5) * RESONANT_SPEED;

      const entity: EntityState = {
        id: nextId(),
        type: ENTITY_TYPES.RESONANT,
        x,
        y,
        z,
        vx,
        vy,
        vz,
        radius: RESONANT_RADIUS * (0.6 + _rng() * 0.8),
        groupId,
        phase: _rng() * Math.PI * 2,
        lifetime: 60 * 60 * 4, // 4 minutes before despawning
      };
      this.entities.set(entity.id, entity);
    }
  }

  private spawnAlienFleet(beltOuterRadius: number): void {
    const angle = _rng() * Math.PI * 2;
    const spawnDist = beltOuterRadius * 1.3; // spawn beyond belt edge
    const x = Math.cos(angle) * spawnDist;
    const z = Math.sin(angle) * spawnDist;
    const y = (_rng() - 0.5) * 200;

    // Approach toward center, deliberately
    const inwardAngle = angle + Math.PI;
    const vx = Math.cos(inwardAngle) * ALIEN_FLEET_SPEED;
    const vz = Math.sin(inwardAngle) * ALIEN_FLEET_SPEED;
    const vy = 0;

    const entity: EntityState = {
      id: nextId(),
      type: ENTITY_TYPES.ALIEN_FLEET,
      x,
      y,
      z,
      vx,
      vy,
      vz,
      radius: ALIEN_FLEET_RADIUS,
      groupId: 0,
      phase: 0,
      lifetime: -1, // permanent — the fleet doesn't leave
    };
    this.entities.set(entity.id, entity);
  }

  // ── Movement ───────────────────────────────────────────────────────────────

  private moveTick(dt: number): void {
    for (const e of this.entities.values()) {
      // Resonants: add wander to keep them from drifting too far
      if (e.type === ENTITY_TYPES.RESONANT) {
        e.vx += (_rng() - 0.5) * RESONANT_WANDER * dt;
        e.vy += (_rng() - 0.5) * 2 * dt;
        e.vz += (_rng() - 0.5) * RESONANT_WANDER * dt;
        // Clamp speed
        const speed = Math.sqrt(e.vx * e.vx + e.vy * e.vy + e.vz * e.vz);
        if (speed > RESONANT_SPEED) {
          const inv = RESONANT_SPEED / speed;
          e.vx *= inv;
          e.vy *= inv;
          e.vz *= inv;
        }
      }

      e.x += e.vx * dt;
      e.y += e.vy * dt;
      e.z += e.vz * dt;

      // Advance phase for visual pulsing
      const phaseRate = e.type === ENTITY_TYPES.DRIFTER ? 0.3 : e.type === ENTITY_TYPES.ALIEN_FLEET ? 0.15 : 1.2;
      e.phase += dt * phaseRate;
      if (e.lifetime > 0) e.lifetime--;
    }
  }

  // ── Despawning ─────────────────────────────────────────────────────────────

  private despawnTick(params: EntitySystemParams): void {
    const { beltOuterRadius } = params;
    const despawnDist = beltOuterRadius * 1.5;

    for (const [id, e] of this.entities) {
      const distSq = e.x * e.x + e.z * e.z;
      if (e.lifetime === 0 || distSq > despawnDist * despawnDist) {
        this.entities.delete(id);
      }
    }
  }

  // ── Proximity effects ──────────────────────────────────────────────────────

  private computeProximityEffects(params: EntitySystemParams): ProximityEffect[] {
    const effects: ProximityEffect[] = [];
    const { robotPositions } = params;

    for (const e of this.entities.values()) {
      const effectRadius =
        e.type === ENTITY_TYPES.DRIFTER ? DRIFTER_EFFECT_RADIUS
        : e.type === ENTITY_TYPES.ALIEN_FLEET ? ALIEN_FLEET_EFFECT_RADIUS
        : RESONANT_EFFECT_RADIUS;

      let minDist = Infinity;
      for (const rp of robotPositions) {
        const dx = rp.x - e.x;
        const dy = rp.y - e.y;
        const dz = rp.z - e.z;
        const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);
        if (dist < minDist) minDist = dist;
      }

      if (minDist < effectRadius) {
        effects.push({
          entityType: e.type,
          minRobotDist: minDist,
          x: e.x,
          y: e.y,
          z: e.z,
        });
      }
    }

    return effects;
  }

  // ── Helper ─────────────────────────────────────────────────────────────────

  private countType(type: EntityType): number {
    let count = 0;
    for (const e of this.entities.values()) {
      if (e.type === type) count++;
    }
    return count;
  }

  // ── Serialization ──────────────────────────────────────────────────────────

  serialize(): SerializedEntityState {
    return {
      entities: Array.from(this.entities.values()),
      drifterSpawnTimer: this.drifterSpawnTimer,
      resonantSpawnTimer: this.resonantSpawnTimer,
      totalDriftersEverSpawned: this.totalDriftersEverSpawned,
      entityIdCounter: _entityIdCounter,
      groupIdCounter: _groupIdCounter,
    };
  }

  deserialize(state: SerializedEntityState): void {
    this.entities.clear();
    for (const e of state.entities) {
      this.entities.set(e.id, { ...e });
    }
    this.drifterSpawnTimer = state.drifterSpawnTimer;
    this.resonantSpawnTimer = state.resonantSpawnTimer;
    this.totalDriftersEverSpawned = state.totalDriftersEverSpawned;
    _entityIdCounter = state.entityIdCounter;
    _groupIdCounter = state.groupIdCounter;
  }

  reset(): void {
    this.entities.clear();
    this.drifterSpawnTimer = 0;
    this.resonantSpawnTimer = 0;
    this.totalDriftersEverSpawned = 0;
    _entityIdCounter = 1;
    _groupIdCounter = 1;
  }
}

export interface SerializedEntityState {
  entities: EntityState[];
  drifterSpawnTimer: number;
  resonantSpawnTimer: number;
  totalDriftersEverSpawned: number;
  entityIdCounter: number;
  groupIdCounter: number;
}
