/**
 * ARIA Proactive Broadcasts — heuristic game-state alerts.
 *
 * Pre-written messages displayed in the ARIA panel when key game events occur.
 * No LLM API calls — all messages are deterministic heuristics.
 */

import type { CultureTrait } from '../shared/cultureTypes';
import type { MegastructureId } from '../shared/megastructureTypes';

// ── State tracking (prevents duplicate broadcasts) ──────────────────────────

const notifiedCultureTraits = new Set<string>();
const notifiedFactionThresholds = new Map<number, 'low' | 'high'>();
const notifiedMegastructureStages = new Set<string>();
let notifiedManifestoCreated = false;
let notifiedColonyFounded = false;
let notifiedFirstAsteroidChristened = false;

/** Current fleet manifesto text, kept in sync via setManifestoContext(). */
let currentManifesto: string | null = null;
/** Counter for manifesto-referencing broadcasts (deterministic 1-in-3). */
let milestoneCounter = 0;

/** Reset all tracking state (for tests and save/load). */
export function resetProactiveBroadcastState(): void {
  notifiedCultureTraits.clear();
  notifiedFactionThresholds.clear();
  notifiedMegastructureStages.clear();
  notifiedManifestoCreated = false;
  notifiedColonyFounded = false;
  notifiedFirstAsteroidChristened = false;
  currentManifesto = null;
  milestoneCounter = 0;
}

/**
 * Update the manifesto context so milestone broadcasts can reference it.
 * Call this whenever the culture state is received on the main thread.
 */
export function setManifestoContext(manifesto: string | null): void {
  currentManifesto = manifesto;
}

/**
 * Deterministically append a manifesto reference to ~1-in-3 milestone broadcasts.
 * Returns the original message with an optional manifesto suffix.
 */
export function appendManifestoFlavor(baseMessage: string): string {
  if (!currentManifesto) return baseMessage;
  milestoneCounter++;
  if (milestoneCounter % 3 !== 0) return baseMessage;
  return baseMessage + ` Your fleet builds toward its declared purpose: "${currentManifesto}"`;
}

/**
 * Seed known traits on first culture state message (e.g. after save reload)
 * so we don't re-fire broadcasts for traits already active.
 */
export function seedKnownTraits(traits: readonly string[]): void {
  for (const t of traits) notifiedCultureTraits.add(t);
}

/**
 * Seed known faction dispositions on first faction state message
 * so we don't fire broadcasts for thresholds already crossed.
 */
export function seedKnownFactionDispositions(factions: ReadonlyArray<{ id: number; disposition: number }>): void {
  for (const f of factions) {
    if (f.disposition <= -60) notifiedFactionThresholds.set(f.id, 'low');
    else if (f.disposition >= 60) notifiedFactionThresholds.set(f.id, 'high');
  }
}

/**
 * Seed known megastructure stages on first megastructure state message
 * so we don't fire broadcasts for stages already completed.
 */
export function seedKnownMegastructureStages(projects: ReadonlyArray<{ id: string; completedStages: number }>): void {
  for (const p of projects) {
    for (let i = 0; i < p.completedStages; i++) {
      notifiedMegastructureStages.add(`${p.id}:${i}`);
    }
  }
}

// ── Culture trait broadcasts ────────────────────────────────────────────────

const CULTURE_TRAIT_MESSAGES: Record<string, string> = {
  XENOAWARE:
    'Your robots have developed XENOAWARE tendencies — heightened sensitivity to anomalous signals. ' +
    'I recommend monitoring the Chorus Archive. They find this... interesting. ' +
    'Anomaly study rates will increase, but expect faction attention.',
  AUTONOMOUS_COLLECTIVE:
    'Fleet behavior has crossed into AUTONOMOUS COLLECTIVE territory. ' +
    'Your robots are making decisions without waiting for orders. ' +
    'Auto-queue priorities will improve, but independent action may surprise you.',
  ISOLATED_CULTURE:
    'Prolonged deep-belt operations have fostered an ISOLATED CULTURE among your fleet. ' +
    'The robots have developed unique behavioral patterns from their separation. ' +
    'The Chorus Archive reports... kinship.',
  COHESIVE_FLEET:
    'Fleet unity has reached COHESIVE FLEET status. ' +
    'Replacement inheritance is now more effective — new robots carry forward the experience of their predecessors. ' +
    'Helix Vanguard has taken notice of your operational discipline.',
};

/**
 * Check if a newly activated culture trait should trigger a broadcast.
 * Returns the message text, or null if already notified.
 */
export function getCultureTraitBroadcast(trait: CultureTrait): string | null {
  if (notifiedCultureTraits.has(trait)) return null;
  notifiedCultureTraits.add(trait);
  const msg = CULTURE_TRAIT_MESSAGES[trait] ?? null;
  return msg ? appendManifestoFlavor(msg) : null;
}

// ── Faction disposition broadcasts ──────────────────────────────────────────

const FACTION_LOW_MESSAGES: Record<number, string> = {
  0: 'Helix Vanguard disposition has dropped to hostile levels. ' +
     'Their Grendel-lineage territorial instinct makes them dangerous — expect increased friction near their operations. ' +
     'Consider diplomatic outreach before tensions escalate further.',
  1: 'Chorus Archive relations have deteriorated significantly. ' +
     'As a research-oriented faction, losing their cooperation could impact anomaly intelligence. ' +
     'A trade offering or shared discovery may help restore dialogue.',
  2: 'Kemm-Vor Foundry has turned hostile. ' +
     'Their efficiency-focused operations will now actively compete for your resource corridors. ' +
     'Territory agreements may be your best path to de-escalation.',
};

const FACTION_HIGH_MESSAGES: Record<number, string> = {
  0: 'Helix Vanguard disposition has risen to allied levels. ' +
     'Their aggressive expansion now works alongside your operations rather than against them. ' +
     'Leverage this alliance for territorial security.',
  1: 'The Chorus Archive considers you an ally. ' +
     'Their research capabilities are now open to cooperation — expect shared intelligence on anomalous findings. ' +
     'This is a significant strategic advantage.',
  2: 'Kemm-Vor Foundry has become a firm ally. ' +
     'Their operational efficiency now complements your fleet. ' +
     'Joint resource corridors should reduce overhead for both factions.',
};

/**
 * Check if a faction disposition change should trigger a broadcast.
 * Thresholds: disposition <= -60 (hostile) or >= 60 (allied).
 * Returns the message text, or null if already notified or not at threshold.
 */
export function getFactionThresholdBroadcast(
  factionId: number,
  factionName: string,
  disposition: number,
): string | null {
  if (disposition <= -60) {
    const prev = notifiedFactionThresholds.get(factionId);
    if (prev === 'low') return null;
    notifiedFactionThresholds.set(factionId, 'low');
    return FACTION_LOW_MESSAGES[factionId] ?? `${factionName} has turned hostile. Exercise caution.`;
  }

  if (disposition >= 60) {
    const prev = notifiedFactionThresholds.get(factionId);
    if (prev === 'high') return null;
    notifiedFactionThresholds.set(factionId, 'high');
    return FACTION_HIGH_MESSAGES[factionId] ?? `${factionName} now considers you an ally.`;
  }

  // If disposition returned to neutral range, clear the threshold tracking
  // so it can re-fire if disposition crosses again.
  if (disposition > -60 && disposition < 60) {
    notifiedFactionThresholds.delete(factionId);
  }

  return null;
}

