/**
 * Check if a megastructure stage completion should trigger a broadcast.
 * Returns the message text, or null if already notified.
 */
export function getMegastructureBroadcast(
  megaId: MegastructureId,
  completedStages: number,
): string | null {
  // completedStages is the total count; we want to announce the latest one
  const stageIndex = completedStages - 1;
  if (stageIndex < 0) return null;

  const key = `${megaId}:${stageIndex}`;
  if (notifiedMegastructureStages.has(key)) return null;
  notifiedMegastructureStages.add(key);

  const msg = MEGASTRUCTURE_MESSAGES[megaId]?.[stageIndex] ?? null;
  return msg ? appendManifestoFlavor(msg) : null;
}

// ── Fleet Manifesto broadcasts ──────────────────────────────────────────────

/**
 * Check if manifesto creation should trigger a broadcast.
 * Returns the message text, or null if already notified.
 */
export function getManifestoCreatedBroadcast(manifestoText: string): string | null {
  if (notifiedManifestoCreated) return null;
  notifiedManifestoCreated = true;
  return (
    'The fleet has declared its purpose. Every action from here forward carries meaning — ' +
    'your robots will build toward the vision you\'ve set. I\'ll reference your manifesto as milestones unfold.'
  );
}

/** Seed manifesto state on load (prevent re-broadcast). */
export function seedKnownManifesto(manifesto: string | null): void {
  if (manifesto) notifiedManifestoCreated = true;
  currentManifesto = manifesto;
}

/** Seed colony name state on load (prevent re-broadcast). */
export function seedKnownColonyName(colonyName: string | null, playerAsteroidCount: number): void {
  if (colonyName) notifiedColonyFounded = true;
  if (playerAsteroidCount > 0) notifiedFirstAsteroidChristened = true;
}

// ── Cultural Shift broadcast ─────────────────────────────────────────────────

/**
 * Generate a Cultural Shift broadcast when the player changes their manifesto.
 * Returns the message text, or null if the manifesto hasn't actually changed.
 */
export function getCulturalShiftBroadcast(newManifesto: string): string | null {
  if (!currentManifesto || currentManifesto === newManifesto) return null;
  return (
    'Your fleet has redefined its purpose. A Cultural Shift marks this moment — ' +
    `from this point forward, your colony builds toward a new vision: "${newManifesto}"`
  );
}

// ── Colony Founding broadcast ─────────────────────────────────────────────────

/**
 * Check if colony naming should trigger a broadcast.
 * Returns the message text, or null if already notified.
 */
export function getColonyFoundedBroadcast(colonyName: string): string | null {
  if (notifiedColonyFounded) return null;
  notifiedColonyFounded = true;
  return `Welcome to ${colonyName}, Commander. A name gives this place meaning — it's no longer just coordinates in the belt. It's home.`;
}

// ── Asteroid Christening broadcast ──────────────────────────────────────────

/**
 * Check if asteroid naming should trigger a first-christening broadcast.
 * Returns the message text, or null if already notified.
 */
export function getFirstAsteroidChristeningBroadcast(): string | null {
  if (notifiedFirstAsteroidChristened) return null;
  notifiedFirstAsteroidChristened = true;
  return 'You\'ve named your first asteroid. That\'s how civilizations begin — one named stone at a time.';
}
