/**
 * Shared DOM helper functions for dashboard tab renderers.
 */

import { safeHtml } from '../utils/safeHtml';

export function sectionHeader(title: string): HTMLDivElement {
  const el = document.createElement('div');
  el.style.cssText = `
    color: #7080b0;
    font-size: 10px;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    margin: 10px 0 6px;
    border-bottom: 1px solid rgba(100,120,200,0.25);
    padding-bottom: 3px;
  `;
  el.textContent = title;
  return el;
}

export function barRow(
  label: string,
  value: number,
  max: number,
  color: string,
  rightText: string,
): HTMLDivElement {
  const row = document.createElement('div');
  row.style.cssText = 'display:flex;align-items:center;gap:8px;margin-bottom:5px;';

  const labelEl = document.createElement('span');
  labelEl.style.cssText =
    'width:90px;flex-shrink:0;color:#8090b0;font-size:11px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;';
  labelEl.textContent = label;

  const track = document.createElement('div');
  track.style.cssText =
    'flex:1;height:10px;background:rgba(30,40,70,0.5);border-radius:2px;overflow:hidden;';

  const fill = document.createElement('div');
  const pct = max > 0 ? Math.min(100, (value / max) * 100) : 0;
  fill.style.cssText = `height:100%;width:${pct}%;background:${color};border-radius:2px;transition:width 0.3s;`;
  track.appendChild(fill);

  const valEl = document.createElement('span');
  valEl.style.cssText = `width:70px;text-align:right;color:${color};font-size:11px;flex-shrink:0;`;
  valEl.textContent = rightText;

  row.appendChild(labelEl);
  row.appendChild(track);
  row.appendChild(valEl);
  return row;
}

export function statRow(label: string, value: string): HTMLDivElement {
  const row = document.createElement('div');
  row.style.cssText = 'display:flex;justify-content:space-between;padding:3px 0;';
  row.innerHTML = safeHtml`<span style="color:#8090b0;">${label}</span><span style="color:#c0d0f0;">${value}</span>`;
  return row;
}

export function formatNum(n: number): string {
  if (n >= 1e6) return `${(n / 1e6).toFixed(1)}M`;
  if (n >= 1e3) return `${(n / 1e3).toFixed(1)}K`;
  return Math.floor(n).toString();
}

export function capitalize(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1);
}
